#!/usr/bin/env python3
"""Machi unified backend.

Single source of truth for the iOS App and the Web client.
PostgreSQL-backed in production, with SQLite for local development and
emergency rollback. JSON over HTTP. Native clients use Bearer sessions;
the Web client uses the same session token in an HttpOnly cookie.

The backend stays dependency-light and runnable with `python3 server.py`;
large data/helper sections are split into local modules. The schema is
designed so it can be lifted to Postgres / Aurora without changing the API shape.

API contract (all JSON, all snake_case unless noted):

    POST   /api/auth/register
    POST   /api/auth/login
    POST   /api/auth/logout
    GET    /api/auth/me
    PATCH  /api/auth/me
    DELETE /api/auth/me

    GET    /api/users/:id
    GET    /api/users/:id/posts
    GET    /api/users/:id/replies
    GET    /api/users/:id/media
    GET    /api/users/:id/likes
    GET    /api/users/:id/bookmarks
    POST   /api/users/:id/follow
    DELETE /api/users/:id/follow
    POST   /api/users/:id/block
    DELETE /api/users/:id/block
    POST   /api/users/:id/report

    GET    /api/feed                  ?mode=recommend|local|following|hot&country=&province=&city=&content_type=
    GET    /api/posts                 ?mode=recommend|local|following|hot&country=&province=&city=&content_type=
    POST   /api/posts
    GET    /api/posts/:id
    PATCH  /api/posts/:id
    DELETE /api/posts/:id
    POST   /api/posts/:id/like
    DELETE /api/posts/:id/like
    POST   /api/posts/:id/bookmark
    DELETE /api/posts/:id/bookmark
    POST   /api/posts/:id/repost
    DELETE /api/posts/:id/repost
    POST   /api/posts/:id/poll/vote  (body {option_index})
    POST   /api/posts/:id/view
    POST   /api/posts/:id/report
    POST   /api/posts/:id/comments
    GET    /api/posts/:id/comments
    DELETE /api/comments/:id
    POST   /api/comments/:id/like
    DELETE /api/comments/:id/like

    GET    /api/search                ?q=...&kind=post|user|topic
    GET    /api/trending
    GET    /api/topics
    GET    /api/topics/:tag

    GET    /api/notifications
    POST   /api/notifications/read    (body {ids:[...] or all:true, is_read?:bool})
    DELETE /api/notifications/:id

    GET    /api/conversations
    POST   /api/conversations         (body {peer_id})
    DELETE /api/conversations/:id
    GET    /api/conversations/:id/messages
    POST   /api/conversations/:id/messages
    DELETE /api/messages/:id
    POST   /api/conversations/:id/read (body {is_read?:bool})

    POST   /api/media/upload          (multipart)
    GET    /api/media/:id
    DELETE /api/media/:id

    GET    /api/settings
    PATCH  /api/settings
    POST   /api/cache/clear
    GET    /api/export
    POST   /api/feedback

    GET    /api/devices
    DELETE /api/devices/:id

    GET    /api/blocks
    GET    /api/drafts
    POST   /api/drafts
    DELETE /api/drafts/:id

    GET    /api/events                Server-Sent Events for realtime
"""

