def normalize_content_type(value: str | None) -> str:
    """Whitelist + default. Anything unrecognised collapses to
    'dynamic' so we never persist a junk discriminator."""
    if not value:
        return "dynamic"
    candidate = value.strip().lower()
    return candidate if candidate in CONTENT_TYPES else "dynamic"


def infer_content_type_from_content(content: str, raw_attributes: Any = None) -> str:
    """Best-effort fallback for quick posts.

    Users often just type "周六新宿约饭有人吗" or "租房避坑提醒" without
    choosing a post type. Keep the composer lightweight, but still route strong
    signals into the right channel. Explicit content_type always wins; this is
    only used for implicit dynamic posts.
    """
    bits = [str(content or "")]
    if isinstance(raw_attributes, dict):
        bits.extend(str(v or "") for v in raw_attributes.values())
    text = " ".join(bits).strip().lower()
    if not text:
        return ""
    warning_keys = ("避坑", "被骗", "诈骗", "骗子", "黑心", "危险", "踩雷", "注意", "小心", "warning", "scam")
    meetup_keys = ("约饭", "饭局", "约局", "搭子", "麻将", "剧本杀", "桌游", "citywalk", "语言交换", "一起", "有人去", "meetup")
    dining_keys = ("探店", "餐厅", "咖啡", "拉面", "居酒屋", "吃饭", "美食", "brunch", "dining")
    event_keys = ("活动", "展览", "演唱会", "音乐节", "市集", "运动", "羽毛球", "足球", "摄影", "event")
    guide_keys = ("攻略", "指南", "教程", "经验", "流程", "清单", "怎么申请", "如何办理", "guide")
    news_keys = ("停电", "停水", "地震", "台风", "交通", "通知", "公告", "新闻", "快讯")
    question_keys = ("?", "？", "请问", "求问", "想问", "有没有人知道", "怎么", "如何", "可以吗", "能不能")
    if any(k in text for k in warning_keys):
        return "warning"
    if any(k in text for k in meetup_keys):
        return "meetup"
    if any(k in text for k in dining_keys):
        return "dining"
    if any(k in text for k in event_keys):
        return "event"
    if any(k in text for k in guide_keys):
        return "guide"
    if any(k in text for k in news_keys):
        return "local_info"
    if any(k in text for k in question_keys):
        return "question"
    return ""


def normalize_post_attributes(content_type: str, raw: Any) -> str:
    """Validate `raw` against the per-type schema and return a JSON
    string ready to store in `posts.attributes`. Drops unknown keys,
    truncates long strings, casts numeric values, and forces a stable
    sorted-key serialisation so the same payload always produces the
    same string (useful for diffing / debugging)."""
    if raw is None or raw == "":
        return ""
    if isinstance(raw, str):
        try:
            raw = json.loads(raw)
        except json.JSONDecodeError:
            return ""
    if not isinstance(raw, dict):
        return ""
    schema = CONTENT_ATTR_SCHEMAS.get(content_type)
    if schema is None:
        # Untyped content (or a type without a schema yet): allow
        # plain string fields up to 600 chars and ignore the rest.
        out: dict[str, Any] = {}
        for k, v in raw.items():
            if not isinstance(k, str) or len(k) > 60:
                continue
            if isinstance(v, str):
                out[k] = v[:600]
            elif isinstance(v, (int, float, bool)):
                out[k] = v
        return json.dumps(out, ensure_ascii=False, sort_keys=True) if out else ""

    out = {}
    for key, (kind, cap) in schema.items():
        if key not in raw:
            continue
        v = raw[key]
        try:
            if content_type == "poll" and key == "options":
                options = normalize_poll_options(v)
                if options:
                    out[key] = json.dumps(options, ensure_ascii=False)
                continue
            if kind == _STR:
                s = str(v)
                if cap and len(s) > cap:
                    s = s[:cap]
                out[key] = s
            elif kind == _INT:
                out[key] = int(v)
            elif kind == _FLOAT:
                out[key] = float(v)
            elif kind == _BOOL:
                out[key] = bool(v)
        except (TypeError, ValueError):
            continue
    return json.dumps(out, ensure_ascii=False, sort_keys=True) if out else ""


def decode_post_attributes(raw: str | None) -> dict[str, Any]:
    """Inverse of normalize_post_attributes: stringified JSON → dict.
    Returns {} for empty / malformed inputs."""
    if not raw:
        return {}
    try:
        data = json.loads(raw)
        return data if isinstance(data, dict) else {}
    except (json.JSONDecodeError, TypeError):
        return {}


def normalize_poll_options(raw: Any) -> list[str]:
    """Return 2-6 clean poll options. Accepts a JSON array, a Python
    list, or a human-typed string split by newlines / slashes / semicolons.
    """
    value = raw
    if isinstance(value, str):
        stripped = value.strip()
        if stripped.startswith("["):
            try:
                parsed = json.loads(stripped)
                value = parsed
            except json.JSONDecodeError:
                value = stripped
    if isinstance(value, (list, tuple)):
        candidates = [str(item) for item in value]
    else:
        candidates = re.split(r"[\n/；;|]+", str(value or ""))
    options: list[str] = []
    seen: set[str] = set()
    for candidate in candidates:
        clean = re.sub(r"\s+", " ", candidate).strip()
        if not clean:
            continue
        clean = clean[:80]
        key = clean.lower()
        if key in seen:
            continue
        seen.add(key)
        options.append(clean)
        if len(options) >= 6:
            break
    return options if len(options) >= 2 else []


def poll_options_from_attributes(attrs: dict[str, Any]) -> list[str]:
    return normalize_poll_options(attrs.get("options"))


def poll_is_closed(expires_at: Any) -> bool:
    raw = str(expires_at or "").strip()
    if not raw:
        return False
    try:
        normalized = raw.replace("Z", "+00:00")
        dt = datetime.fromisoformat(normalized)
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=timezone.utc)
        return dt <= datetime.now(timezone.utc)
    except ValueError:
        return False


# Media mime helpers moved to server_media.py (imported at top, re-exported).
# The private-media encryption cluster below stays in server.py.

def _decode_urlsafe_base64(value: str, *, field: str) -> bytes:
    try:
        padded = value + ("=" * (-len(value) % 4))
        return base64.urlsafe_b64decode(padded.encode("ascii"))
    except Exception as exc:
        raise APIError(f"{field} 配置不合法", 500, "private_media_crypto_invalid") from exc


def private_media_key() -> bytes:
    if not PRIVATE_MEDIA_KEY_B64:
        raise APIError("私密媒体加密密钥未配置", 500, "private_media_key_missing")
    key = _decode_urlsafe_base64(PRIVATE_MEDIA_KEY_B64, field="KAIX_PRIVATE_MEDIA_KEY")
    if len(key) != 32:
        raise APIError("私密媒体加密密钥必须为 32 字节", 500, "private_media_key_invalid")
    return key


def private_media_encryptor(iv: bytes | None = None) -> tuple[Any, bytes]:
    try:
        from cryptography.hazmat.primitives.ciphers import Cipher, algorithms, modes
    except ImportError as exc:
        raise APIError("cryptography 未安装，无法保护私密媒体", 500, "private_media_crypto_missing") from exc
    nonce = iv or secrets.token_bytes(12)
    if len(nonce) != 12:
        raise APIError("私密媒体随机向量不合法", 500, "private_media_crypto_invalid")
    return Cipher(algorithms.AES(private_media_key()), modes.GCM(nonce)).encryptor(), nonce


def private_media_encryption_metadata(iv: bytes, tag: bytes) -> dict[str, Any]:
    return {
        "algorithm": PRIVATE_MEDIA_CIPHER,
        "version": PRIVATE_MEDIA_CIPHER_VERSION,
        "iv": base64.urlsafe_b64encode(iv).decode("ascii").rstrip("="),
        "tag": base64.urlsafe_b64encode(tag).decode("ascii").rstrip("="),
    }


def private_media_decryptor(metadata: dict[str, Any]) -> Any:
    encryption = metadata.get("encryption")
    if not isinstance(encryption, dict):
        raise APIError("私密媒体缺少加密信息", 503, "private_media_encryption_missing")
    if (
        encryption.get("algorithm") != PRIVATE_MEDIA_CIPHER
        or int(encryption.get("version") or 0) != PRIVATE_MEDIA_CIPHER_VERSION
    ):
        raise APIError("私密媒体加密格式不受支持", 503, "private_media_encryption_unsupported")
    iv = _decode_urlsafe_base64(str(encryption.get("iv") or ""), field="private media iv")
    tag = _decode_urlsafe_base64(str(encryption.get("tag") or ""), field="private media tag")
    if len(iv) != 12 or len(tag) != 16:
        raise APIError("私密媒体加密信息不完整", 503, "private_media_encryption_invalid")
    try:
        from cryptography.hazmat.primitives.ciphers import Cipher, algorithms, modes
    except ImportError as exc:
        raise APIError("cryptography 未安装，无法读取私密媒体", 500, "private_media_crypto_missing") from exc
    return Cipher(algorithms.AES(private_media_key()), modes.GCM(iv, tag)).decryptor()


# Media S3 / upload / thumbnail helpers moved to server_media.py (re-exported).
# Thumbnail-worker db()/DB_LOCK injected via server_media.configure(db, DB_LOCK) after db().

# PostgreSQL is the production backend, while SQLite remains the zero-cost
# local-development and emergency rollback backend. Keep the backend choice
# close to the lock because write coordination depends on it.
KAIX_DB_BACKEND = _env("KAIX_DB_BACKEND", "sqlite").strip().lower()
KAIX_PG_DSN = _env("KAIX_PG_DSN", "")


class _BackendAwareDBLock:
    """Serialize SQLite writes without throttling PostgreSQL.

    SQLite has a single writer, so the process-wide RLock is still valuable
    there. PostgreSQL provides its own row/index/transaction concurrency and
    must not be put behind the same process-wide bottleneck.
    """

    def __init__(self) -> None:
        self._lock = threading.RLock()

    @property
    def enabled(self) -> bool:
        return KAIX_DB_BACKEND != "postgres"

    def acquire(self, *args: Any, **kwargs: Any) -> bool:
        if not self.enabled:
            return True
        return self._lock.acquire(*args, **kwargs)

    def release(self) -> None:
        if self.enabled:
            self._lock.release()

    def __enter__(self) -> "_BackendAwareDBLock":
        self.acquire()
        return self

    def __exit__(self, *exc: Any) -> bool:
        self.release()
        return False


DB_LOCK = _BackendAwareDBLock()

# A write request that cannot acquire the global write lock within this many
# seconds fails fast with 503 instead of hanging the connection forever.
# Normal writes hold the lock for milliseconds — this is purely a safety
# valve so one stuck/slow holder can never wedge the whole backend again.
DB_WRITE_LOCK_TIMEOUT_SEC = float(_env("KAIX_DB_WRITE_LOCK_TIMEOUT_SEC", "20"))


class _DBLockReleased:
    """Temporarily drop the global write lock around slow I/O (e.g. a network
    crawl) so it doesn't block every other writer. Safe from a write handler
    that holds the lock; re-acquires on exit even if the body raises. No-op if
    the current thread doesn't hold the lock. The request's own connection is
    in autocommit mode, so no transaction spans the released window."""

    def __enter__(self) -> "_DBLockReleased":
        try:
            DB_LOCK.release()
            self._released = True
        except RuntimeError:
            self._released = False
        return self

    def __exit__(self, *exc: Any) -> bool:
        if getattr(self, "_released", False):
            DB_LOCK.acquire()
        return False

# ---------------------------------------------------------------------------
# session last-seen throttle and short-lived SSE token store.
# Both are in-memory only — they don't need to survive restarts.
# ---------------------------------------------------------------------------

# Map[token] -> monotonic timestamp of the last DB flush. We only write
# sessions.last_seen_at to the database when more than this many seconds
# have elapsed since the previous flush for the same token. Anything
# shorter is just kept in memory.
_LAST_SEEN_FLUSH_SEC = 60.0
_LAST_SEEN_LOCK = threading.Lock()
_LAST_SEEN: dict[str, float] = {}

# Short-lived tokens used exclusively for EventSource subscriptions.
# EventSource cannot attach an Authorization header, so the Web client
# trades its long-lived Bearer for a single-use SSE token via
# POST /api/events/token. The token is bound to a user id and expires
# in `_SSE_TOKEN_TTL` seconds. Keeping the long-lived token out of the
# URL stops it from leaking through nginx access logs / Referer headers.
_SSE_TOKEN_TTL = 300.0

# Hard ceiling on concurrent SSE streams. Each stream parks one handler
# thread for its whole lifetime — the dominant per-connection cost in this
# process — so without a cap a reconnect storm can exhaust thread/memory
# budget on a small host. A client that receives 503 keeps its normal
# polling behaviour and EventSource retries on its own schedule.
KAIX_SSE_MAX_CONNECTIONS = max(1, int(_env("KAIX_SSE_MAX_CONNECTIONS", "600")))
_SSE_ACTIVE_LOCK = threading.Lock()
_SSE_ACTIVE_COUNT = 0
_SSE_TOKEN_LOCK = threading.Lock()
_SSE_TOKENS: dict[str, tuple[str, float]] = {}


def _should_flush_last_seen(token: str) -> bool:
    now = time.monotonic()
    with _LAST_SEEN_LOCK:
        last = _LAST_SEEN.get(token)
        # First time we've seen this token in-process: always flush so
        # the DB row's last_seen_at gets bumped at least once per
        # process lifetime. Subsequent requests within the window are
        # coalesced.
        if last is not None and now - last < _LAST_SEEN_FLUSH_SEC:
            return False
        _LAST_SEEN[token] = now
        # Keep memory bounded — drop entries older than 1h.
        if len(_LAST_SEEN) > 10000:
            cutoff = now - 3600
            for k, v in list(_LAST_SEEN.items()):
                if v < cutoff:
                    _LAST_SEEN.pop(k, None)
    return True


def _mint_sse_token(user_id: str) -> str:
    token = secrets.token_urlsafe(24)
    now = time.monotonic()
    with _SSE_TOKEN_LOCK:
        _SSE_TOKENS[token] = (user_id, now + _SSE_TOKEN_TTL)
        # Lazy GC.
        if len(_SSE_TOKENS) > 5000:
            for k, (_, exp) in list(_SSE_TOKENS.items()):
                if exp < now:
                    _SSE_TOKENS.pop(k, None)
    return token


def _consume_sse_token(token: str) -> str | None:
    """Validate an SSE token. Returns the bound user id or None.
    The token is single-use: it's removed on first consumption."""
    if not token:
        return None
    now = time.monotonic()
    with _SSE_TOKEN_LOCK:
        entry = _SSE_TOKENS.pop(token, None)
    if not entry:
        return None
    user_id, expires_at = entry
    if expires_at < now:
        return None
    return user_id


# Generic TTL cache shared by hot feed / trending / admin stats — these
# endpoints are expensive but tolerate small staleness.
#
# Backed by server_shared_state.RankingCache: an in-process L1 (short absolute
# wall-clock TTL) fronting an optional redis L2 (SET EX + pub/sub invalidation)
# when KAIX_REDIS_URL is set, so the public rankings are shared across worker
# processes/hosts. Unconfigured/down redis degrades transparently to L1-only —
# reads never fail on a redis hiccup. Per-user/per-host keys (recprofile:/view:/
# media_size_bytes) are auto-routed L1-only inside RankingCache. The _cache_*
# helpers below keep their old signatures so no call site changes.

# Public ranking payload prefixes that 删帖 / admin下架 / hot_score edits must
# invalidate cluster-wide. topics:/discover:hot: were previously missing here
# (they could only self-heal on TTL); feed: covers feed:hot + feed:anon:.
_RANKING_INVAL_PREFIXES = (
    "feed:", "trending:", "explore:", "discover:hot:", "topics:",
)
# Public Guide payload prefixes. Guide content changes rarely but must go dark
# fast on 下架 (compliance), so guide write paths invalidate these cluster-wide
# instead of waiting out the 30–600s TTLs.
_GUIDE_INVAL_PREFIXES = (
    "guide_home:", "guide_jlpt:", "guide_journeys:", "guide_sitemap",
)

# Short TTL for the public Guide home payload (~8 read queries, no per-user
# data). Keeps /guide fast and the DB calm under traffic spikes; admin edits
# show up within this window. Override via env for tuning without a redeploy.
GUIDE_HOME_CACHE_TTL = float(os.environ.get("KAIX_GUIDE_HOME_CACHE_TTL", "30"))

# Public /api/guide/sitemap payload (slug + updated_at of every published
# school/company/article, for SEO sitemaps / client prefetch). Content changes
# rarely, so a longer window than guide-home is fine.
GUIDE_SITEMAP_CACHE_TTL = float(os.environ.get("KAIX_GUIDE_SITEMAP_CACHE_TTL", "600"))

# Anonymous feed pages are identical for every guest with the same filters —
# the landing surfaces (web /home, iOS guest mode, crawlers) hammer them the
# hardest. A short TTL collapses that fan-out to one DB hit per window
# without ever serving stale content to logged-in users (they bypass it).
ANON_FEED_CACHE_TTL = float(os.environ.get("KAIX_ANON_FEED_CACHE_TTL", "20"))
# Per-viewer interest profile (recommend feed): a 10-minute-stale profile is
# invisible to the user but turns repeated home opens from two engagement scans
# into a cache hit. Keeps the personalized first page cheap as DAU grows.
KAIX_RECPROFILE_TTL_SEC = float(os.environ.get("KAIX_RECPROFILE_TTL_SEC", "600"))


def _cache_get(key: str) -> Any | None:
    return shared_state.get_ranking_cache().get(key)


def _cache_put(key: str, value: Any, ttl_seconds: float) -> None:
    shared_state.get_ranking_cache().put(key, value, ttl_seconds)


def _cache_invalidate(prefix: str = "") -> None:
    shared_state.get_ranking_cache().invalidate_prefixes((prefix,) if prefix else ("",))


def invalidate_public_ranking_caches() -> None:
    shared_state.get_ranking_cache().invalidate_prefixes(_RANKING_INVAL_PREFIXES)


def invalidate_guide_caches() -> None:
    """Bust the public Guide payloads (home/jlpt/journeys/sitemap) cluster-wide.
    Called from guide content write paths so 下架/编辑 goes dark fast rather than
    waiting out the 30–600s TTLs."""
    shared_state.get_ranking_cache().invalidate_prefixes(_GUIDE_INVAL_PREFIXES)


# ---------------------------------------------------------------------------
# region payload validation.
#
# Region directory data and pure helpers live in server_regions.py.
# _normalize_region_payload stays here because it raises APIError envelopes.
# ---------------------------------------------------------------------------

def _normalize_region_payload(data: dict[str, Any]) -> tuple[str, str, str, str, str]:
    """Validate and normalize registration/profile region fields.

    Returns (country, province, city, region_code, city_label). Empty
    values are allowed so legacy clients can still register without a
    region, but partial/invalid regions are rejected.
    """
    country = str(data.get("country") or "").strip().lower()
    province = str(data.get("province") or "").strip().lower()
    city = str(data.get("city") or "").strip().lower()
    region_code = str(data.get("current_region_code") or data.get("region_code") or "").strip().lower()

    if region_code and not (country and city):
        country, province, city = _parse_region_code(region_code)
    if not (country or province or city or region_code):
        return "", "", "", "", ""

    spec = _country_lookup(country)
    if not spec:
        raise APIError("请选择有效国家", 400, "invalid_region")
    if spec.get("has_provinces"):
        allowed_provinces = {p["code"] for p in REGION_PROVINCES.get(country, [])}
        if not province or province not in allowed_provinces:
            raise APIError("请选择有效省份/都道府县", 400, "invalid_region")
    else:
        province = ""

    city_label = _resolve_region_label(country, province, city)
    if not city or not city_label:
        raise APIError("请选择有效城市", 400, "invalid_region")

    normalized_code = _resolve_region_code(country, province, city)
    if region_code and region_code != normalized_code:
        raise APIError("地区代码不匹配", 400, "invalid_region")
    return country, province, city, normalized_code, city_label


def _cached_media_size_bytes() -> int:
    """Sum of all files in MEDIA_DIR, cached for 5 minutes. The walk
    can be tens of seconds with many files and used to run inside the
    DB lock from admin-stats."""
    cached = _cache_get("media_size_bytes")
    if cached is not None:
        return int(cached)
    total = 0
    try:
        for p in MEDIA_DIR.glob("**/*"):
            if p.is_file():
                try:
                    total += p.stat().st_size
                except OSError:
                    pass
    except OSError:
        return 0
    _cache_put("media_size_bytes", total, ttl_seconds=300)
    return total


# ---------------------------------------------------------------------------
# rate limiter — token bucket per (ip, group), via server_shared_state so the
# buckets are shared across worker processes/hosts when KAIX_REDIS_URL is set
# (in-process and memory-bounded otherwise). See rate_check below.
# ---------------------------------------------------------------------------


def rate_check(ip: str, group: str) -> bool:
    """Returns True if the request may proceed, False if it should be 429'd.

    Delegates to the shared token-bucket limiter so per-IP limits hold ACROSS
    worker processes / hosts when KAIX_REDIS_URL is set (otherwise it's the same
    in-process bucket as before, so single-process behaviour is unchanged)."""
    capacity, per_minute = RATE_LIMITS.get(group, (200, 200))
    return shared_state.get_rate_limiter().allow(f"{ip or 'anon'}:{group}", capacity, per_minute)


def _rate_group_for(path: str, method: str) -> str:
    # Code-sending endpoints get the tightest bucket so an attacker can't
    # spray verification emails or probe which addresses exist.
    if path in ("/api/auth/email/send-code", "/api/auth/send-verification-code", "/api/auth/forgot-password", "/api/auth/login/start"):
        return "email"
    # Session probe is lenient (read-shaped, hit on every navigation); its
    # mutations (PATCH profile / DELETE account) fall through to the strict bucket.
    if path == "/api/auth/me" and method == "GET":
        return "auth_session"
    if path == "/api/auth/captcha":
        return "auth_captcha"
    if path.startswith("/api/auth/google/start") or path.startswith("/api/auth/google/url"):
        return "oauth_start"
    if path.startswith("/api/auth/"):
        return "auth"
    # Payment order creation + provider verification. Webhooks are
    # excluded: providers retry on non-2xx, so rate-limiting them would
    # cause dropped settlement callbacks.
    if (path.startswith("/api/payments/") and not path.startswith("/api/payments/webhook/")) \
            and method in ("POST", "PATCH", "PUT", "DELETE"):
        return "payment"
    if path.startswith("/api/wallet/topups/") and method in ("POST", "PATCH", "PUT", "DELETE"):
        return "payment"
    if path.startswith("/api/search"):
        return "search"
    if path.startswith("/api/uploads/local/"):
        return "upload_stream"
    if path.startswith("/api/uploads/"):
        return "upload"
    if path.startswith("/api/media/"):
        return "media"
    if method in ("POST", "PATCH", "PUT", "DELETE"):
        return "write"
    return "read"


# ---------------------------------------------------------------------------
# structured access log — one line per request, easy to grep / ship to a
# log aggregator (Loki, CloudWatch, BetterStack, whatever).
# ---------------------------------------------------------------------------

import logging
_log_handler = logging.StreamHandler()
_log_handler.setFormatter(logging.Formatter("%(asctime)s %(levelname)s %(message)s"))
ACCESS_LOG = logging.getLogger("kaix.access")
ACCESS_LOG.handlers = [_log_handler]
ACCESS_LOG.setLevel(logging.INFO if PRODUCTION else logging.DEBUG)
ACCESS_LOG.propagate = False
ERR_LOG = logging.getLogger("kaix.error")
ERR_LOG.handlers = [_log_handler]
ERR_LOG.setLevel(logging.WARNING)
ERR_LOG.propagate = False


# ---------------------------------------------------------------------------
# Sentry-lite error reporting. Set KAIX_SENTRY_DSN and every ERROR-level
# record on kaix.error (all 500s, migration/payment/worker failures) is
# forwarded to Sentry's envelope API — pure stdlib, async via a bounded
# queue + daemon thread, drops silently under backpressure, total no-op
# without a DSN. Replaces "users tell us when production breaks".
# ---------------------------------------------------------------------------

KAIX_SENTRY_DSN = _env("KAIX_SENTRY_DSN", "")


class _SentryLiteHandler(logging.Handler):
    def __init__(self, dsn: str) -> None:
        super().__init__(level=logging.ERROR)
        from urllib.parse import urlparse
        parsed = urlparse(dsn)
        self._key = parsed.username or ""
        project = (parsed.path or "/").rsplit("/", 1)[-1]
        self._endpoint = f"{parsed.scheme}://{parsed.hostname}/api/{project}/envelope/"
        self._queue: "queue.Queue[bytes]" = queue.Queue(maxsize=64)
        threading.Thread(target=self._drain, name="sentry-lite", daemon=True).start()

    def emit(self, record: logging.LogRecord) -> None:
        try:
            event: dict[str, Any] = {
                "event_id": uuid.uuid4().hex,
                "timestamp": datetime.now(timezone.utc).isoformat(),
                "platform": "python",
                "level": "error",
                "logger": record.name,
                "message": {"formatted": self.format(record)[:4000]},
                "environment": "production" if PRODUCTION else "development",
                "tags": {"service": "machi-backend"},
            }
            if record.exc_info and record.exc_info[0] is not None:
                import traceback
                exc_type, exc_value, tb = record.exc_info
                frames = [
                    {"filename": f.filename, "function": f.name, "lineno": f.lineno}
                    for f in traceback.extract_tb(tb)[-20:]
                ]
                event["exception"] = {"values": [{
                    "type": exc_type.__name__,
                    "value": str(exc_value)[:1000],
                    "stacktrace": {"frames": frames},
                }]}
            envelope = (
                json.dumps({"event_id": event["event_id"], "sent_at": event["timestamp"]}) + "\n"
                + json.dumps({"type": "event"}) + "\n"
                + json.dumps(event, ensure_ascii=False) + "\n"
            ).encode("utf-8")
            self._queue.put_nowait(envelope)
        except Exception:
            pass  # error reporting must never take the request down

    def _drain(self) -> None:
        from urllib.request import Request, urlopen
        while True:
            envelope = self._queue.get()
            try:
                req = Request(self._endpoint, data=envelope, method="POST")
                req.add_header("Content-Type", "application/x-sentry-envelope")
                req.add_header(
                    "X-Sentry-Auth",
                    f"Sentry sentry_version=7, sentry_client=machi-lite/1.0, sentry_key={self._key}",
                )
                with urlopen(req, timeout=5):
                    pass
            except Exception:
                pass  # network problems just drop the event


if KAIX_SENTRY_DSN:
    ERR_LOG.addHandler(_SentryLiteHandler(KAIX_SENTRY_DSN))
    ACCESS_LOG.info("sentry-lite error reporting enabled")


# ---------------------------------------------------------------------------
# Email error digest — the zero-account sibling of Sentry-lite. Set
# KAIX_ERROR_REPORT_EMAIL and every ERROR-level record is batched into a
# digest mail through the SAME SMTP transport that already sends
# verification codes. One mail per window at most (anti-storm), capped
# detail lines, drops silently when SMTP is down. Both channels can run
# side by side; either alone ends "users tell us when production breaks".
# ---------------------------------------------------------------------------

KAIX_ERROR_REPORT_EMAIL = _env("KAIX_ERROR_REPORT_EMAIL", "")
KAIX_ERROR_REPORT_WINDOW_SEC = max(60, int(_env("KAIX_ERROR_REPORT_WINDOW_SEC", "600")))


class _EmailDigestHandler(logging.Handler):
    _MAX_BUFFER = 200      # hard cap per window — beyond this we only count
    _MAX_DETAIL = 30       # full lines included in the mail body

    def __init__(self, to: str, window_sec: int) -> None:
        super().__init__(level=logging.ERROR)
        self._to = to
        self._window = window_sec
        self._lock = threading.Lock()
        self._buffer: list[str] = []
        self._dropped = 0
        threading.Thread(target=self._flush_loop, name="error-digest", daemon=True).start()

    def emit(self, record: logging.LogRecord) -> None:
        try:
            line = f"{datetime.now(timezone.utc).strftime('%H:%M:%SZ')} {self.format(record)[:600]}"
            with self._lock:
                if len(self._buffer) >= self._MAX_BUFFER:
                    self._dropped += 1
                else:
                    self._buffer.append(line)
        except Exception:
            pass  # error reporting must never take the request down

    def _flush_loop(self) -> None:
        while True:
            time.sleep(self._window)
            with self._lock:
                if not self._buffer:
                    continue
                lines, self._buffer = self._buffer, []
                dropped, self._dropped = self._dropped, 0
            total = len(lines) + dropped
            body_lines = [
                f"Machi backend reported {total} error(s) in the last {self._window // 60} minute(s).",
                "",
                *lines[: self._MAX_DETAIL],
            ]
            if len(lines) > self._MAX_DETAIL or dropped:
                body_lines.append(f"… and {len(lines) - self._MAX_DETAIL + dropped} more (see server logs)")
            body_lines += ["", "host: production" if PRODUCTION else "host: development",
                           "journal: journalctl -u kaix-backend --since '-1h'"]
            try:
                send_email(self._to, f"[Machi] 后端错误摘要 × {total}", "\n".join(body_lines))
            except Exception:
                pass  # SMTP being down must not loop into more errors


if KAIX_ERROR_REPORT_EMAIL:
    ERR_LOG.addHandler(_EmailDigestHandler(KAIX_ERROR_REPORT_EMAIL, KAIX_ERROR_REPORT_WINDOW_SEC))
    ACCESS_LOG.info("email error digest enabled (window=%ss)", KAIX_ERROR_REPORT_WINDOW_SEC)


# ---------------------------------------------------------------------------
# helpers


# now_iso / parse_iso moved to server_core.py (imported at top, re-exported).


def _visible_status_sql(alias: str = "p") -> str:
    return f"{alias}.status IN ('published', 'active')"


def _active_boost(row: dict[str, Any]) -> int:
    if not row.get("is_boosted"):
        return 0
    boosted_until = parse_iso(str(row.get("boosted_until") or ""))
    if boosted_until and boosted_until < datetime.now(timezone.utc):
        return 0
    return int(row.get("boost_weight") or 0)


def _time_decay(created_at: str | None) -> float:
    created = parse_iso(created_at)
    if not created:
        return 0
    age_hours = max(0.0, (datetime.now(timezone.utc) - created).total_seconds() / 3600.0)
    return max(0.0, 24.0 - age_hours)


# Recency component for the additive heat score. The old term hard-zeroed at 24h
# — a brand-new post lost ALL of its freshness advantage after a single day.
# Ramp down linearly over HEAT_RECENCY_WINDOW_H hours instead, keeping the same
# peak weight at h=0, so fresh posts retain a gentle edge for ~2 days. Pure
# +,-,*,/ so it stays portable across SQLite and Postgres (no exp/pow).
HEAT_RECENCY_WINDOW_H = 48.0
HEAT_RECENCY_PEAK = 24.0


def _heat_score_sql(alias: str = "p") -> str:
    # Reads the denormalized engagement counters on `posts` (migration v85)
    # instead of four correlated COUNT subqueries — the heat of every candidate
    # post is now plain arithmetic over the row, so ranking scans are O(N) index
    # reads rather than O(N × interactions). Recency/boost use time functions
    # that differ by backend, branched the same way as before.
    if KAIX_DB_BACKEND == "postgres":
        boost_cmp = f"{alias}.boosted_until > '{now_iso()}'"
        hours_since = f"EXTRACT(EPOCH FROM (now() - {alias}.created_at::timestamptz)) / 3600.0"
        max2 = "GREATEST"
    else:
        # boosted_until is stored as an ISO string ('T'-separated, +00:00 suffix
        # from datetime.isoformat()). SQLite's datetime('now') is SPACE-separated,
        # so a lexical compare put the 'T' (0x54) above the ' ' (0x20) at char 10
        # and the boost read as active forever. Compare against the SAME ISO shape
        # via a now_iso() literal (matches the Postgres branch) so it's correct.
        boost_cmp = f"{alias}.boosted_until > '{now_iso()}'"
        hours_since = f"(julianday('now') - julianday({alias}.created_at)) * 24.0"
        max2 = "MAX"
    recency_per_hour = HEAT_RECENCY_PEAK / HEAT_RECENCY_WINDOW_H
    # light_boost membership benefit: a verified member's post gets a gentle
    # ×1.05 on its heat. Correlated subquery on the author's is_verified_member
    # (portable on both backends); non-members / unknown authors get ×1.0.
    member_mult = (
        f"(CASE WHEN COALESCE((SELECT is_verified_member FROM users WHERE users.id = {alias}.author_id), 0) = 1 "
        f"THEN 1.05 ELSE 1.0 END)"
    )
    # Seed suppression (kept in lock-step with refresh_hot_scores): curated/seed
    # content rides at 0.6× so real UGC out-ranks it on heat-sorted surfaces.
    seed_mult = f"(CASE WHEN COALESCE({alias}.is_seed_content, 0) = 1 THEN {HOT_SCORE_SEED_MULT} ELSE 1.0 END)"
    return f"""
      ((COALESCE({alias}.like_count, 0) * 1
       + COALESCE({alias}.comment_count, 0) * 3
       + COALESCE({alias}.repost_count, 0) * 5
       + COALESCE({alias}.bookmark_count, 0) * 4
       - COALESCE({alias}.report_count, 0) * 10
       + CASE
           WHEN COALESCE({alias}.is_boosted, 0) = 1
             AND (COALESCE({alias}.boosted_until, '') = '' OR {boost_cmp})
           THEN COALESCE({alias}.boost_weight, 0)
           ELSE 0
         END
       + {max2}(0, {HEAT_RECENCY_WINDOW_H} - ({hours_since})) * {recency_per_hour})
       * {member_mult} * {seed_mult})
    """


# Denormalized engagement counters on `posts` (migration v85). Maintained
# incrementally at the interaction/comment write sites so ranking never needs a
# correlated COUNT subquery — the single biggest lever for scaling the feed /
# 热榜 / 热搜 reads as volume grows.
_POST_COUNTER_COLUMNS = {
    "like": "like_count",
    "bookmark": "bookmark_count",
    "repost": "repost_count",
    "comment": "comment_count",
}


def bump_post_counter(conn: sqlite3.Connection, post_id: str, column: str, delta: int) -> None:
    """Adjust one denormalized counter on a post by +1 / -1. Decrements clamp at
    0 via CASE (backend-agnostic — Postgres `MAX` is an aggregate, not the 2-arg
    function SQLite has). Best-effort: a counter drift never blocks the write."""
    if column not in {"like_count", "bookmark_count", "repost_count", "comment_count"} or delta == 0:
        return
    try:
        if delta > 0:
            conn.execute(f"UPDATE posts SET {column} = {column} + ? WHERE id = ?", (int(delta), post_id))
        else:
            n = abs(int(delta))
            conn.execute(
                f"UPDATE posts SET {column} = CASE WHEN {column} >= ? THEN {column} - ? ELSE 0 END WHERE id = ?",
                (n, n, post_id),
            )
    except Exception:
        ERR_LOG.warning("bump_post_counter failed post=%s col=%s delta=%s", post_id, column, delta)


def bump_post_counter_for_kind(conn: sqlite3.Connection, post_id: str, kind: str, delta: int) -> None:
    """Map an interaction `kind` (like/bookmark/repost/comment) to its counter
    column and bump it. Unknown kinds (e.g. meetup_join) are silently ignored."""
    column = _POST_COUNTER_COLUMNS.get(kind)
    if column:
        bump_post_counter(conn, post_id, column, delta)


def apply_review_to_aggregate(conn: sqlite3.Connection, product_id: str,
                              delta_count: int, delta_sum: int) -> None:
    """Incrementally maintain guide_products' denormalized review aggregate.

    Only 'published' reviews contribute. A review crossing INTO published adds
    (+1, +rating); crossing OUT of published subtracts (-1, -rating); a score
    change while staying published is (0, new-old). We never AVG the whole
    guide_reviews table on read — this CAS-friendly increment keeps rating_count
    / rating_sum authoritative and derives rating = sum/count in the same UPDATE.

    Both deltas are clamped at 0 via CASE (backend-agnostic — Postgres `MAX` is
    an aggregate, not the 2-arg function SQLite has), so a drift never produces a
    negative aggregate. Best-effort: a miss here is reconciled by
    reconcile_product_rating, it never blocks the review write."""
    if delta_count == 0 and delta_sum == 0:
        return
    dc, ds = int(delta_count), int(delta_sum)
    try:
        conn.execute(
            "UPDATE guide_products SET "
            "rating_count = CASE WHEN rating_count + ? < 0 THEN 0 ELSE rating_count + ? END, "
            "rating_sum = CASE WHEN rating_sum + ? < 0 THEN 0 ELSE rating_sum + ? END, "
            "rating = CASE WHEN (CASE WHEN rating_count + ? < 0 THEN 0 ELSE rating_count + ? END) > 0 "
            "  THEN CAST((CASE WHEN rating_sum + ? < 0 THEN 0 ELSE rating_sum + ? END) AS REAL) "
            "       / (CASE WHEN rating_count + ? < 0 THEN 0 ELSE rating_count + ? END) "
            "  ELSE 0 END, "
            "updated_at = ? WHERE id = ?",
            (dc, dc, ds, ds, dc, dc, ds, ds, dc, dc, now_iso(), product_id),
        )
    except Exception:
        ERR_LOG.warning("apply_review_to_aggregate failed product=%s dc=%s ds=%s", product_id, dc, ds)


def reconcile_product_rating(conn: sqlite3.Connection, product_id: str) -> dict[str, Any]:
    """Recompute a product's review aggregate from scratch (published rows only)
    and write it back. The audit/repair counterpart to the incremental
    apply_review_to_aggregate — run from admin or a nightly task to correct any
    drift. Returns the reconciled {count, sum, avg}."""
    row = conn.execute(
        "SELECT COUNT(*) AS c, COALESCE(SUM(rating), 0) AS s "
        "FROM guide_reviews WHERE product_id = ? AND status = 'published'",
        (product_id,)).fetchone()
    count = int(row["c"] or 0)
    total = int(row["s"] or 0)
    avg = (float(total) / count) if count > 0 else 0.0
    conn.execute(
        "UPDATE guide_products SET rating_count = ?, rating_sum = ?, rating = ?, updated_at = ? WHERE id = ?",
        (count, total, avg, now_iso(), product_id))
    return {"count": count, "sum": total, "avg": avg}


def maybe_autohide_guide_review(conn: sqlite3.Connection, review_id: str) -> bool:
    """Auto-hide a review once DISTINCT reports reach the threshold, pending human
    review — the guide-review analogue of maybe_autohide_post. If the review was
    'published' it is also withdrawn from the product's rating aggregate. CAS on
    status so concurrent reports don't double-subtract."""
    if REPORT_AUTOHIDE_THRESHOLD <= 0:
        return False
    row = conn.execute(
        "SELECT product_id, user_id, rating, status, report_count FROM guide_reviews WHERE id = ?",
        (review_id,)).fetchone()
    if not row:
        return False
    r = dict(row)
    if int(r.get("report_count") or 0) < REPORT_AUTOHIDE_THRESHOLD:
        return False
    if r.get("status") not in ("published", "pending"):
        return False  # already hidden / rejected / withdrawn
    was_published = r.get("status") == "published"
    cur = conn.execute(
        "UPDATE guide_reviews SET status = 'hidden', updated_at = ? WHERE id = ? AND status = ?",
        (now_iso(), review_id, r.get("status")))
    if cur.rowcount != 1:
        return False  # another writer moved it first
    if was_published:
        apply_review_to_aggregate(conn, r["product_id"], -1, -int(r.get("rating") or 0))
    record_moderation_action(conn, "", "guide_review", review_id, "auto_hide",
                             reason=f"reached {REPORT_AUTOHIDE_THRESHOLD} distinct reports")
    return True


def retire_reposts_of_deleted_post(conn: sqlite3.Connection, post_id: str) -> None:
    """Cascade a post deletion to its reposts.

    A pure repost (empty body) is just a pointer at the original, so once the
    original is gone it would otherwise linger in every feed rendering the
    now-deleted content, and its reposter could no longer undo it. Soft-delete
    those repost rows and drop the repost interactions so `reposted` state
    clears everywhere. Quote-reposts (non-empty body) are the reposter's own
    words — they survive, and their original preview resolves to null via
    fetch_posts_with_extras. Call this after the original has been soft-deleted.
    """
    conn.execute(
        """
        UPDATE posts
           SET status = 'deleted', deleted_at = ?, updated_at = ?
         WHERE repost_of_id = ? AND COALESCE(content, '') = '' AND deleted_at IS NULL
        """,
        (now_iso(), now_iso(), post_id),
    )
    conn.execute("DELETE FROM interactions WHERE target_id = ? AND kind = 'repost'", (post_id,))


def retire_reposts_of_deleted_posts_bulk(conn: sqlite3.Connection, where_sql: str, params: list[Any]) -> None:
    """Bulk variant of retire_reposts_of_deleted_post for paths that remove
    many originals at once (account scrub, seed clear). `where_sql` is a
    predicate over a `posts` alias `o` selecting the removed originals; pure
    reposts of any matched original are soft-deleted and their repost
    interactions dropped. Pure SQL, so it runs on SQLite and Postgres alike."""
    conn.execute(
        f"""
        UPDATE posts
           SET status = 'deleted', deleted_at = ?, updated_at = ?
         WHERE COALESCE(content, '') = '' AND deleted_at IS NULL
           AND repost_of_id IN (SELECT o.id FROM posts o WHERE {where_sql})
        """,
        (now_iso(), now_iso(), *params),
    )
    conn.execute(
        f"DELETE FROM interactions WHERE kind = 'repost' "
        f"AND target_id IN (SELECT o.id FROM posts o WHERE {where_sql})",
        tuple(params),
    )


def hash_password(password: str) -> str:
    salt = secrets.token_bytes(16)
    digest = hashlib.pbkdf2_hmac("sha256", password.encode("utf-8") + PASSWORD_PEPPER, salt, 120_000)
    return f"pbkdf2$120000${base64.b64encode(salt).decode()}${base64.b64encode(digest).decode()}"


def verify_password(password: str, stored: str) -> bool:
    try:
        algo, iters, salt_b64, digest_b64 = stored.split("$")
        if algo != "pbkdf2":
            return False
        salt = base64.b64decode(salt_b64)
        expected = base64.b64decode(digest_b64)
        actual = hashlib.pbkdf2_hmac("sha256", password.encode("utf-8") + PASSWORD_PEPPER, salt, int(iters))
        return hmac.compare_digest(expected, actual)
    except Exception:
        return False


def normalize_handle(value: str) -> str:
    return (value or "").strip().lstrip("@").lower()


HANDLE_RE = re.compile(r"^[a-z0-9_.]{3,20}$")
RESERVED_HANDLES = {
    "admin", "administrator", "root", "machi", "machicity", "kaix",
    "official", "support", "help", "news", "localdesk", "local_desk",
    "machi_editorial", "machi_news", "machi_support",
}
TAG_RE = re.compile(r"#([\w一-鿿]+)", re.UNICODE)


def extract_tags(content: str) -> list[str]:
    seen: list[str] = []
    for match in TAG_RE.findall(content or ""):
        tag = match.strip().lower()
        if tag and tag not in seen:
            seen.append(tag)
    return seen


# @mention parsing (B6). Handles are [a-z0-9_.] (see HANDLE_RE); we accept the
# same run of chars after '@', deduped and lowercased for a users.handle lookup.
# The 3..20 length bound mirrors HANDLE_RE so junk like "@a" isn't queried. The
# negative lookbehind rejects an '@' glued to a preceding word char (an email
# local part like "a@b.com" must not read as a mention of "b.com").
MENTION_RE = re.compile(r"(?<![A-Za-z0-9_.])@([A-Za-z0-9_.]{3,20})")


def extract_mentions(content: str) -> list[str]:
    """Unique lowercased handles mentioned in `content`, in first-seen order.
    Trailing dots (from sentence punctuation like "@alice.") are trimmed."""
    seen: list[str] = []
    for match in MENTION_RE.findall(content or ""):
        handle = match.strip().strip(".").lower()
        if len(handle) < 3:
            continue  # a bare "@a." collapses below the handle minimum
        if handle and handle not in seen:
            seen.append(handle)
    return seen


def notify_mentions(
    conn: sqlite3.Connection,
    content: str,
    *,
    actor_id: str,
    post_id: str,
    comment_id: str = "",
    already_notified: set[str] | None = None,
    now: str | None = None,
) -> int:
    """Best-effort: write a `mention` notification for every real @handle in
    `content`, excluding the actor themselves and any user id in
    `already_notified` (people who were already pinged via reply/comment for the
    same event, so they don't get two rows). Dedupes by resolved user id, so
    "@bob @bob" pings bob once. NEVER raises. Returns the number notified."""
    try:
        handles = extract_mentions(content)
        if not handles:
            return 0
        skip = set(already_notified or set())
        skip.add(actor_id)
        now = now or now_iso()
        notified = 0
        seen_uids: set[str] = set()
        for handle in handles:
            urow = conn.execute(
                "SELECT id FROM users WHERE handle = ? AND deleted_at IS NULL", (handle,)
            ).fetchone()
            if not urow:
                continue
            uid = urow["id"]
            if uid in skip or uid in seen_uids:
                continue
            seen_uids.add(uid)
            conn.execute(
                "INSERT INTO notifications (id, user_id, actor_id, type, target_post_id, target_comment_id, content, created_at) "
                "VALUES (?, ?, ?, 'mention', ?, ?, ?, ?)",
                (str(uuid.uuid4()), uid, actor_id, post_id, comment_id or None, (content or "")[:140], now),
            )
            HUB.publish(uid, {"type": "notification", "kind": "mention", "post_id": post_id,
                              **({"comment_id": comment_id} if comment_id else {})})
            server_apns.enqueue(uid, ntype="mention", actor_id=actor_id,
                                content=(content or "")[:140], post_id=post_id)
            notified += 1
        return notified
    except Exception as exc:  # pragma: no cover - defensive: must not break the write
        try:
            ERR_LOG.warning("notify_mentions failed post=%s comment=%s error=%s",
                            post_id, comment_id, exc)
        except Exception:
            pass
        return 0


