# Author diversity cap for ranked boards (热榜 / 正在发生 / trending): a single
# author may hold at most this many slots on one page, so a prolific poster can't
# monopolize a board. Applied as an in-memory filter over an over-fetched
# candidate pool, in rank order (an author keeps their highest-ranked posts).
EXPLORE_MAX_POSTS_PER_AUTHOR = 2


def cursor_encode(iso_value: str, item_id: str) -> str:
    raw = f"{iso_value}|{item_id}".encode("utf-8")
    return base64.urlsafe_b64encode(raw).decode().rstrip("=")


def cursor_decode(token: str | None) -> tuple[str, str] | None:
    if not token:
        return None
    try:
        padded = token + "=" * (-len(token) % 4)
        raw = base64.urlsafe_b64decode(padded.encode("utf-8")).decode("utf-8")
        iso_value, item_id = raw.split("|", 1)
        return iso_value, item_id
    except Exception:
        return None


def row_dict(row: sqlite3.Row | None) -> dict[str, Any] | None:
    return dict(row) if row else None


# ---------------------------------------------------------------------------
# database


# --- Optional PostgreSQL backend (Tier 2, step 2) ---------------------------
# The SQLite path below is unchanged and stays the default. When
# KAIX_DB_BACKEND=postgres, db() returns a thin adapter that mimics the
# sqlite3.Connection API the handlers use (885 conn.execute() calls, context
# manager, rows indexable by position AND name) and translates the dialect on
# the fly: ?->%s, literal % escaping, PRAGMA->no-op, LIKE->ILIKE (SQLite LIKE
# is case-insensitive for ASCII), INSERT OR IGNORE -> ON CONFLICT DO NOTHING.
# psycopg2 is imported lazily so the SQLite/production path never needs it.
# Remaining SQLite-only SQL (1 INSERT OR REPLACE, 3 strftime) is fixed per-site
# in following steps.
#
# The translation is a pure function of the SQL text, but it used to run its
# character-walk + regexes on EVERY conn.execute(). Handlers issue the same
# statement shapes over and over (IN(...) placeholder lists give a bounded
# family per endpoint), so an LRU keyed on (sql, has_params) turns the
# per-query translation cost into a dict hit.
@functools.lru_cache(maxsize=4096)
def _pg_xlate(sql: str, has_params: bool) -> str:
    import re
    if sql.lstrip()[:6].upper() == "PRAGMA":
        return "SELECT 1"
    # SQLite's BEGIN IMMEDIATE/EXCLUSIVE/DEFERRED are a syntax error on
    # PostgreSQL; the plain BEGIN gives the same all-or-nothing semantics
    # (autocommit connections start an explicit transaction here).
    if sql.strip().upper() in {"BEGIN IMMEDIATE", "BEGIN EXCLUSIVE", "BEGIN DEFERRED"}:
        return "BEGIN"

    def replace_like_operators(src: str) -> str:
        out: list[str] = []
        i = 0
        in_single = False
        while i < len(src):
            ch = src[i]
            if in_single:
                out.append(ch)
                if ch == "'":
                    if i + 1 < len(src) and src[i + 1] == "'":
                        out.append(src[i + 1])
                        i += 2
                        continue
                    in_single = False
                i += 1
                continue
            if ch == "'":
                in_single = True
                out.append(ch)
                i += 1
                continue
            token = src[i:i + 4]
            if token.lower() == "like":
                before = src[i - 1] if i > 0 else ""
                after = src[i + 4] if i + 4 < len(src) else ""
                if (not (before.isalnum() or before == "_")) and (not (after.isalnum() or after == "_")):
                    out.append("ILIKE")
                    i += 4
                    continue
            out.append(ch)
            i += 1
        return "".join(out)

    s = replace_like_operators(sql)
    # SQLite scalar MAX/MIN(a, b) -> Postgres GREATEST/LEAST. Only flat 2-arg
    # forms (no nested parens) match, so aggregate MAX(col) is left untouched.
    s = re.sub(r"(?i)\bMAX\s*\(([^()]+,[^()]+)\)", r"GREATEST(\1)", s)
    s = re.sub(r"(?i)\bMIN\s*\(([^()]+,[^()]+)\)", r"LEAST(\1)", s)
    m = re.match(r"(?is)\s*INSERT\s+OR\s+IGNORE\s+INTO\b(.*)$", s)
    if m:
        s = "INSERT INTO" + m.group(1)
        if "ON CONFLICT" not in s.upper() and "RETURNING" not in s.upper():
            s = s.rstrip().rstrip(";") + " ON CONFLICT DO NOTHING"
    if has_params:
        s = s.replace("%", "%%").replace("?", "%s")
    return s


# --- PostgreSQL connection pool ---------------------------------------------
# ThreadingHTTPServer services each request on its own thread, and db() used
# to open a brand-new psycopg2 connection per request: a TCP + auth handshake
# and a forked PostgreSQL backend process every time. Under load that both
# slows every request and (worse) races toward PG's max_connections, after
# which the whole API errors out. The pool keeps warm connections, bounds the
# total via a semaphore, health-checks on borrow, and fails fast with 503
# when saturated instead of queueing unboundedly.
KAIX_PG_POOL_MAX = max(1, int(_env("KAIX_PG_POOL_MAX", "20")))
KAIX_PG_POOL_ACQUIRE_TIMEOUT_SEC = float(_env("KAIX_PG_POOL_ACQUIRE_TIMEOUT_SEC", "5"))
# Bound any single query so a runaway statement frees its thread + pool slot
# instead of pinning them forever (the real "request timeout" for a DB-bound
# request). 0 disables. Generous default — only kills genuinely stuck queries.
KAIX_PG_STATEMENT_TIMEOUT_MS = max(0, int(_env("KAIX_PG_STATEMENT_TIMEOUT_MS", "15000")))


class _PgPool:
    def __init__(self, dsn: str, maxconn: int, acquire_timeout: float) -> None:
        self._dsn = dsn
        self._acquire_timeout = acquire_timeout
        self._lock = threading.Lock()
        self._idle: list[Any] = []
        self._sem = threading.BoundedSemaphore(maxconn)
        self._maxconn = maxconn
        self._in_use = 0      # gauge: connections currently checked out
        self._peak = 0        # high-water mark since boot (saturation signal)
        self._busy_rejects = 0  # times we shed load with 503

    def acquire(self) -> Any:
        import psycopg2
        if not self._sem.acquire(timeout=self._acquire_timeout):
            # Saturated: shed load instead of stacking blocked threads.
            with self._lock:
                self._busy_rejects += 1
            raise APIError("服务器繁忙，请稍后再试", 503, "server_busy")
        with self._lock:
            self._in_use += 1
            if self._in_use > self._peak:
                self._peak = self._in_use
        try:
            while True:
                with self._lock:
                    raw = self._idle.pop() if self._idle else None
                if raw is None:
                    break
                if self._ping(raw):
                    return raw
                try:
                    raw.close()
                except Exception:
                    pass
            raw = psycopg2.connect(self._dsn or "dbname=machi_dev")
            raw.autocommit = True  # mirror sqlite isolation_level=None
            if KAIX_PG_STATEMENT_TIMEOUT_MS > 0:
                try:
                    cur = raw.cursor()
                    cur.execute("SET statement_timeout = %s", (KAIX_PG_STATEMENT_TIMEOUT_MS,))
                    cur.close()
                except Exception:
                    pass
            return raw
        except BaseException:
            with self._lock:
                self._in_use -= 1
            self._sem.release()
            raise

    def stats(self) -> dict[str, int]:
        with self._lock:
            return {"in_use": self._in_use, "peak": self._peak, "idle": len(self._idle),
                    "max": self._maxconn, "busy_rejects": self._busy_rejects}

    @staticmethod
    def _ping(raw: Any) -> bool:
        """A pooled connection may have been severed (PG restart, idle
        timeout); one localhost round-trip on borrow is far cheaper than
        handing a dead connection to a request."""
        try:
            cur = raw.cursor()
            cur.execute("SELECT 1")
            cur.fetchone()
            cur.close()
            return True
        except Exception:
            return False

    def release(self, raw: Any, *, discard: bool = False) -> None:
        try:
            if raw is None:
                return
            if discard or getattr(raw, "closed", True):
                try:
                    raw.close()
                except Exception:
                    pass
                return
            try:
                # Clears any aborted-transaction state before reuse; a no-op
                # round trip is skipped by psycopg2 when the conn is idle.
                raw.rollback()
            except Exception:
                try:
                    raw.close()
                except Exception:
                    pass
                return
            with self._lock:
                self._idle.append(raw)
        finally:
            with self._lock:
                self._in_use -= 1
            self._sem.release()


_PG_POOL: "_PgPool | None" = None
_PG_POOL_INIT_LOCK = threading.Lock()


def _pg_pool() -> _PgPool:
    global _PG_POOL
    if _PG_POOL is None:
        with _PG_POOL_INIT_LOCK:
            if _PG_POOL is None:
                _PG_POOL = _PgPool(KAIX_PG_DSN, KAIX_PG_POOL_MAX, KAIX_PG_POOL_ACQUIRE_TIMEOUT_SEC)
    return _PG_POOL


# Requests slower than this get a WARN line (with pool stats) so slow endpoints
# surface in the logs without an external APM. 0 disables.
KAIX_SLOW_REQUEST_MS = max(0, int(_env("KAIX_SLOW_REQUEST_MS", "1500")))


def _pg_pool_stats() -> dict[str, int] | None:
    """Pool gauge for health/metrics; None on SQLite (no pool)."""
    if KAIX_DB_BACKEND != "postgres" or _PG_POOL is None:
        return None
    try:
        return _PG_POOL.stats()
    except Exception:
        return None


def _pg_pool_stat_suffix() -> str:
    s = _pg_pool_stats()
    return f" pool={s['in_use']}/{s['max']}" if s else ""


class _PgConn:
    """Minimal sqlite3.Connection-compatible adapter over psycopg2.
    DictCursor rows support both row[0] and row['col'].

    Connections come from the process-wide pool; close() (and the context
    manager exit, and finalization) give the underlying connection back
    instead of dropping it."""

    def __init__(self, dsn: str):
        import psycopg2
        import psycopg2.extras
        self._psycopg2 = psycopg2
        self._extras = psycopg2.extras
        self._pool = _pg_pool()
        self._c = self._pool.acquire()
        self._released = False
        self.row_factory = None     # accepted & ignored (DictCursor used)

    def _give_back(self, *, discard: bool = False) -> None:
        if self._released:
            return
        self._released = True
        raw, self._c = self._c, None
        self._pool.release(raw, discard=discard)

    def _raw(self):
        if self._c is None:
            raise sqlite3.ProgrammingError("Cannot operate on a closed database.")
        return self._c

    def execute(self, sql, params=None):
        cur = self._raw().cursor(cursor_factory=self._extras.DictCursor)
        try:
            if params is None:
                cur.execute(_pg_xlate(sql, False))
            else:
                cur.execute(_pg_xlate(sql, True), tuple(params))
        except self._psycopg2.IntegrityError as exc:
            raise sqlite3.IntegrityError(str(exc)) from exc
        except self._psycopg2.OperationalError as exc:
            raise sqlite3.OperationalError(str(exc)) from exc
        except self._psycopg2.DatabaseError as exc:
            raise sqlite3.DatabaseError(str(exc)) from exc
        return cur

    def executemany(self, sql, seq):
        cur = self._raw().cursor()
        try:
            cur.executemany(_pg_xlate(sql, True), [tuple(p) for p in seq])
        except self._psycopg2.IntegrityError as exc:
            raise sqlite3.IntegrityError(str(exc)) from exc
        except self._psycopg2.OperationalError as exc:
            raise sqlite3.OperationalError(str(exc)) from exc
        except self._psycopg2.DatabaseError as exc:
            raise sqlite3.DatabaseError(str(exc)) from exc
        return cur

    def executescript(self, sql):
        cur = self._raw().cursor()
        try:
            # psycopg2 accepts a semicolon-delimited command string. This path
            # is used only by the explicit PostgreSQL migration runner; normal
            # production startup still treats the migrated PG schema as the
            # source of truth.
            cur.execute(_pg_xlate(sql, False))
        except self._psycopg2.IntegrityError as exc:
            raise sqlite3.IntegrityError(str(exc)) from exc
        except self._psycopg2.OperationalError as exc:
            raise sqlite3.OperationalError(str(exc)) from exc
        except self._psycopg2.DatabaseError as exc:
            raise sqlite3.DatabaseError(str(exc)) from exc
        return cur

    def commit(self):
        self._raw().commit()

    def rollback(self):
        self._raw().rollback()

    def close(self):
        try:
            self._give_back()
        except Exception:
            pass

    def __enter__(self):
        return self

    def __exit__(self, exc_type, exc, tb):
        discard = False
        if self._c is not None:
            try:
                if exc_type is None:
                    self._c.commit()
                else:
                    self._c.rollback()
            except Exception:
                # The connection is in an unknown state — don't pool it.
                discard = True
        self._give_back(discard=discard)
        return False

    def __del__(self):
        # Callers that neither close() nor use the context manager still
        # return their connection when the wrapper is garbage-collected.
        try:
            self._give_back()
        except Exception:
            pass


def db() -> sqlite3.Connection:
    if KAIX_DB_BACKEND == "postgres":
        return _PgConn(KAIX_PG_DSN)  # type: ignore[return-value]
    conn = sqlite3.connect(DB_PATH, timeout=30, isolation_level=None)
    conn.row_factory = sqlite3.Row
    conn.execute("PRAGMA foreign_keys = ON")
    # WAL allows concurrent readers + a single writer — the right mode
    # for "many readers, few writers" web workloads.
    conn.execute("PRAGMA journal_mode = WAL")
    # NORMAL is safe under WAL (only risks losing the last tx on a power
    # cut) and meaningfully reduces fsync pressure under load.
    conn.execute("PRAGMA synchronous = NORMAL")
    # When SQLite hits a writer-held lock, retry-busy for up to 5s
    # instead of erroring instantly. Pairs with the 30s connect timeout.
    conn.execute("PRAGMA busy_timeout = 5000")
    # Hold ~16k pages (~64MB at 4KB pages) in per-connection cache.
    conn.execute("PRAGMA cache_size = -16384")
    # Memory-map up to 128MB of the DB file for cheap reads.
    conn.execute("PRAGMA mmap_size = 134217728")
    # Use the OS-managed temp store (avoids surprising disk pressure
    # from large GROUP BY / ORDER BY scratch space).
    conn.execute("PRAGMA temp_store = MEMORY")
    return conn


# ---------------------------------------------------------------------------
# database schema and migrations.
#
# The SQL definitions live in server_schema.py; imported names stay available
# here for scripts/tests that use server.SCHEMA and server.MIGRATIONS.
# ---------------------------------------------------------------------------

_MIGRATION_BACKEND_RE = re.compile(r"^\s*--\s*backend:\s*([a-z]+)", re.IGNORECASE)



# Wire the thumbnail worker's DB access now that db()/DB_LOCK exist.
server_media.configure(db, DB_LOCK)
def run_migrations(conn: sqlite3.Connection) -> None:
    """Apply pending migrations in version order.

    A migration whose SQL starts with a ``-- backend: postgres`` (or
    ``-- backend: sqlite``) marker only *executes* on that backend; on the
    other backend it is recorded as applied without running, so the version
    sequence stays linear everywhere.
    """
    applied_notes = {
        row["version"]: (row["note"] or "")
        for row in conn.execute("SELECT version, note FROM schema_migrations")
    }
    for version, note, sql in sorted(MIGRATIONS, key=lambda x: x[0]):
        marker = _MIGRATION_BACKEND_RE.match(sql)
        target_backend = marker.group(1).lower() if marker else None
        if version in applied_notes:
            skipped = re.search(r"\[skipped: ([a-z]+)-only\]$", applied_notes[version])
            # Self-heal: a snapshot migrated from the other backend carries
            # "skipped" records for migrations this backend should actually
            # run (e.g. an SQLite snapshot imported into PostgreSQL). Re-run
            # those here; everything else is genuinely applied.
            if not (skipped and skipped.group(1) == KAIX_DB_BACKEND):
                continue
            try:
                conn.executescript(sql)
                conn.execute(
                    "UPDATE schema_migrations SET applied_at = ?, note = ? WHERE version = ?",
                    (now_iso(), note, version),
                )
                ACCESS_LOG.info("migration re-applied on target backend version=%s note=%s", version, note)
            except Exception:
                ERR_LOG.exception("migration failed version=%s note=%s", version, note)
                raise
            continue
        if target_backend and target_backend != KAIX_DB_BACKEND:
            conn.execute(
                "INSERT INTO schema_migrations (version, applied_at, note) VALUES (?, ?, ?)",
                (version, now_iso(), f"{note} [skipped: {target_backend}-only]"),
            )
            ACCESS_LOG.info("migration recorded as no-op version=%s note=%s (backend=%s)", version, note, KAIX_DB_BACKEND)
            continue
        try:
            conn.executescript(sql)
            conn.execute(
                "INSERT INTO schema_migrations (version, applied_at, note) VALUES (?, ?, ?)",
                (version, now_iso(), note),
            )
            ACCESS_LOG.info("migration applied version=%s note=%s", version, note)
        except Exception as exc:
            ERR_LOG.exception("migration failed version=%s note=%s", version, note)
            raise


def _table_columns(conn: sqlite3.Connection, table: str) -> set[str]:
    if KAIX_DB_BACKEND == "postgres":
        rows = conn.execute(
            "SELECT column_name AS name FROM information_schema.columns WHERE table_name = ?",
            (table,),
        ).fetchall()
    else:
        rows = conn.execute(f"PRAGMA table_info({table})").fetchall()
    columns: set[str] = set()
    for row in rows:
        try:
            data = dict(row)
        except Exception:
            continue
        name = data.get("name")
        if name:
            columns.add(str(name))
    return columns


def _ensure_columns(conn: sqlite3.Connection, table: str, columns: dict[str, str]) -> None:
    existing = _table_columns(conn, table)
    for name, ddl in columns.items():
        if name not in existing:
            try:
                if KAIX_DB_BACKEND == "postgres":
                    conn.execute(f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS {name} {ddl}")
                else:
                    conn.execute(f"ALTER TABLE {table} ADD COLUMN {name} {ddl}")
            except Exception as exc:
                # When several backend processes boot at once (horizontal
                # scaling), another worker may have added the column between
                # our PRAGMA read and this ALTER. "duplicate column name" is
                # benign and means the migration already happened.
                message = str(exc).lower()
                if "duplicate column" not in message and "already exists" not in message:
                    raise


def ensure_moderation_schema(conn: sqlite3.Connection) -> None:
    """Idempotently upgrade existing DBs to the UGC-moderation schema (App Store
    1.2 / legal): the reports close-loop columns plus the moderation audit trail
    and blocked-media-hash tables. Fresh DBs already have these from SCHEMA; this
    covers existing SQLite dev DBs (the Postgres path is migration 78)."""
    _ensure_columns(conn, "reports", {
        "status": "TEXT NOT NULL DEFAULT 'open'",
        "action": "TEXT NOT NULL DEFAULT ''",
        "resolved_by": "TEXT NOT NULL DEFAULT ''",
        "resolved_note": "TEXT NOT NULL DEFAULT ''",
        "resolved_at": "TEXT",
    })
    conn.execute(
        "CREATE TABLE IF NOT EXISTS content_moderation_actions ("
        "id TEXT PRIMARY KEY, moderator_id TEXT NOT NULL DEFAULT '', target_kind TEXT NOT NULL, "
        "target_id TEXT NOT NULL, action TEXT NOT NULL, reason TEXT NOT NULL DEFAULT '', "
        "report_id TEXT NOT NULL DEFAULT '', created_at TEXT NOT NULL)"
    )
    conn.execute(
        "CREATE TABLE IF NOT EXISTS blocked_media_hashes ("
        "sha256 TEXT PRIMARY KEY, reason TEXT NOT NULL DEFAULT '', "
        "created_by TEXT NOT NULL DEFAULT '', created_at TEXT NOT NULL)"
    )
    conn.execute("CREATE INDEX IF NOT EXISTS idx_reports_status ON reports(status, created_at)")
    conn.execute(
        "CREATE INDEX IF NOT EXISTS idx_content_mod_actions_target "
        "ON content_moderation_actions(target_kind, target_id, created_at)"
    )


# A post flagged by this many DISTINCT reporters is auto-hidden (status ->
# 'under_review') pending human review, so community-flagged objectionable
# content drops out of public surfaces immediately (App Store 1.2). 0 disables it.
REPORT_AUTOHIDE_THRESHOLD = max(0, int(_env("KAIX_REPORT_AUTOHIDE_THRESHOLD", "3") or 3))

# Operator-imported known-bad media fingerprints (e.g. CSAM SHA-256 hashes),
# comma/space separated lowercase hex. Merged with the blocked_media_hashes table.
_BLOCKED_MEDIA_HASHES_ENV = frozenset(
    h.strip().lower() for h in re.split(r"[,\s]+", _env("KAIX_BLOCKED_MEDIA_SHA256", "")) if h.strip()
)

_MODERATION_HIDDEN_POST_STATUS = "under_review"
_MODERATION_REMOVED_POST_STATUS = "removed"


def media_hash_blocked(conn: sqlite3.Connection, sha256_hex: str) -> bool:
    """True if this content hash is on the known-bad blocklist (env or DB) — used
    to reject CSAM / known-illegal media at upload before it is ever stored."""
    h = (sha256_hex or "").strip().lower()
    if not h:
        return False
    if h in _BLOCKED_MEDIA_HASHES_ENV:
        return True
    try:
        return conn.execute(
            "SELECT 1 FROM blocked_media_hashes WHERE sha256 = ? LIMIT 1", (h,)
        ).fetchone() is not None
    except Exception:
        return False


def record_moderation_action(conn: sqlite3.Connection, moderator_id: str, target_kind: str,
                             target_id: str, action: str, reason: str = "", report_id: str = "") -> None:
    """Append an immutable moderation audit row (who hid/removed/restored what & why)."""
    conn.execute(
        "INSERT INTO content_moderation_actions "
        "(id, moderator_id, target_kind, target_id, action, reason, report_id, created_at) "
        "VALUES (?, ?, ?, ?, ?, ?, ?, ?)",
        (str(uuid.uuid4()), moderator_id or "", target_kind, target_id, action,
         reason or "", report_id or "", now_iso()),
    )


def set_content_hidden(conn: sqlite3.Connection, target_kind: str, target_id: str,
                       *, removed: bool = False) -> None:
    """Drop a reported piece of content from public surfaces. Posts use `status`
    (the public feed only shows 'published'/'active', so 'under_review'/'removed'
    fall out); comments use `deleted_at`. Other kinds are handled by their own
    flows and are a no-op here."""
    now = now_iso()
    if target_kind == "post":
        status = _MODERATION_REMOVED_POST_STATUS if removed else _MODERATION_HIDDEN_POST_STATUS
        conn.execute("UPDATE posts SET status = ?, updated_at = ? WHERE id = ?", (status, now, target_id))
        invalidate_public_ranking_caches()
    elif target_kind == "comment":
        conn.execute("UPDATE comments SET deleted_at = COALESCE(deleted_at, ?) WHERE id = ?", (now, target_id))
    elif target_kind == "guide_review":
        # hide → 'hidden' (community/temporary), remove → 'rejected' (admin final).
        # If the review was counting toward the product rating, retract it (CAS on
        # the published→other move so we subtract at most once).
        new_status = "rejected" if removed else "hidden"
        gr = conn.execute("SELECT product_id, rating, status FROM guide_reviews WHERE id = ?", (target_id,)).fetchone()
        if gr:
            cur = conn.execute(
                "UPDATE guide_reviews SET status = ?, updated_at = ? WHERE id = ? AND status != ?",
                (new_status, now, target_id, new_status))
            if cur.rowcount == 1 and gr["status"] == "published":
                apply_review_to_aggregate(conn, gr["product_id"], -1, -int(gr["rating"] or 0))


def restore_auto_hidden_content(conn: sqlite3.Connection, target_kind: str, target_id: str) -> None:
    """Re-publish content that was AUTO-hidden by reports when a moderator
    dismisses the report. Deliberately only un-hides the 'under_review' state —
    never resurrects content an admin explicitly removed."""
    if target_kind == "post":
        conn.execute(
            "UPDATE posts SET status = 'published', updated_at = ? WHERE id = ? AND status = ?",
            (now_iso(), target_id, _MODERATION_HIDDEN_POST_STATUS),
        )
        invalidate_public_ranking_caches()
    elif target_kind == "guide_review":
        # Only resurrect a review that was auto-hidden by reports ('hidden'), never
        # one an admin explicitly rejected. Re-publishing re-adds it to the rating.
        gr = conn.execute("SELECT product_id, rating, status FROM guide_reviews WHERE id = ?", (target_id,)).fetchone()
        if gr and gr["status"] == "hidden":
            cur = conn.execute(
                "UPDATE guide_reviews SET status = 'published', report_count = 0, updated_at = ? WHERE id = ? AND status = 'hidden'",
                (now_iso(), target_id))
            if cur.rowcount == 1:
                apply_review_to_aggregate(conn, gr["product_id"], 1, int(gr["rating"] or 0))


def maybe_autohide_post(conn: sqlite3.Connection, post_id: str) -> bool:
    """Auto-hide a still-visible post once DISTINCT reports reach the threshold,
    pending human review — the proactive 'filter objectionable content' control."""
    if REPORT_AUTOHIDE_THRESHOLD <= 0:
        return False
    row = conn.execute("SELECT status, report_count FROM posts WHERE id = ?", (post_id,)).fetchone()
    if not row:
        return False
    r = dict(row)
    if int(r.get("report_count") or 0) < REPORT_AUTOHIDE_THRESHOLD:
        return False
    if r.get("status") not in ("published", "active"):
        return False  # already hidden / removed
    set_content_hidden(conn, "post", post_id, removed=False)
    record_moderation_action(conn, "", "post", post_id, "auto_hide",
                             reason=f"reached {REPORT_AUTOHIDE_THRESHOLD} distinct reports")
    return True


