def ensure_draft_schema_extensions(conn: sqlite3.Connection) -> None:
    """Keep draft persistence aligned with the publish form schema.

    Drafts used to store only content/media/tags. Production clients now
    restore category, region, typed attributes and language from the server,
    so old SQLite databases need additive columns before the draft APIs run.
    PostgreSQL receives the same change through migration 54.
    """
    _ensure_columns(conn, "drafts", {
        "country": "TEXT NOT NULL DEFAULT ''",
        "province": "TEXT NOT NULL DEFAULT ''",
        "city": "TEXT NOT NULL DEFAULT ''",
        "region_code": "TEXT NOT NULL DEFAULT ''",
        "content_type": "TEXT NOT NULL DEFAULT 'dynamic'",
        "attributes": "TEXT NOT NULL DEFAULT ''",
        "language": "TEXT NOT NULL DEFAULT ''",
    })


def ensure_booking_schema(conn: sqlite3.Connection) -> None:
    """Reservation-calendar tables (slots + bookings) for existing SQLite DBs.
    Fresh DBs get these from SCHEMA, PostgreSQL from migration 56; existing
    SQLite needs an explicit create because executescript(SCHEMA) doesn't add
    tables appended after the DB was first built. Idempotent, no money."""
    conn.executescript(
        """
        CREATE TABLE IF NOT EXISTS listing_booking_slots (
            id TEXT PRIMARY KEY, listing_id TEXT NOT NULL, owner_id TEXT NOT NULL,
            start_at TEXT NOT NULL, end_at TEXT NOT NULL DEFAULT '', capacity INTEGER NOT NULL DEFAULT 1,
            booked_count INTEGER NOT NULL DEFAULT 0, note TEXT NOT NULL DEFAULT '',
            status TEXT NOT NULL DEFAULT 'open', created_at TEXT NOT NULL, deleted_at TEXT
        );
        CREATE INDEX IF NOT EXISTS idx_booking_slots_listing ON listing_booking_slots(listing_id, start_at);
        CREATE TABLE IF NOT EXISTS listing_bookings (
            id TEXT PRIMARY KEY, slot_id TEXT NOT NULL, listing_id TEXT NOT NULL, user_id TEXT NOT NULL,
            owner_id TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'confirmed', note TEXT NOT NULL DEFAULT '',
            created_at TEXT NOT NULL, updated_at TEXT NOT NULL DEFAULT ''
        );
        CREATE INDEX IF NOT EXISTS idx_listing_bookings_user ON listing_bookings(user_id, created_at);
        CREATE INDEX IF NOT EXISTS idx_listing_bookings_slot ON listing_bookings(slot_id);
        CREATE INDEX IF NOT EXISTS idx_listing_bookings_owner ON listing_bookings(owner_id, created_at);
        """
    )


# ---------------------------------------------------------------------------
# Saved-search alerts (N4). A user pins a (vertical, location, keyword, filter)
# query; when a matching listing publishes we drop an in-app notification (push
# is wired separately under N1, gated on APNs/VAPID creds). New table for
# existing SQLite DBs; PostgreSQL gets it via the migrate script / prod SQL.
# Money is never touched.
# ---------------------------------------------------------------------------
SAVED_SEARCH_CADENCES = ("instant", "daily", "off")
SAVED_SEARCH_MAX_PER_USER = 50


def ensure_saved_search_schema(conn: sqlite3.Connection) -> None:
    """Idempotent: create the saved_searches table + indexes."""
    conn.executescript(
        """
        CREATE TABLE IF NOT EXISTS saved_searches (
            id TEXT PRIMARY KEY,
            user_id TEXT NOT NULL,
            vertical TEXT NOT NULL DEFAULT '',
            city_slug TEXT NOT NULL DEFAULT '',
            region_code TEXT NOT NULL DEFAULT '',
            country_code TEXT NOT NULL DEFAULT '',
            keyword TEXT NOT NULL DEFAULT '',
            category TEXT NOT NULL DEFAULT '',
            filter_json TEXT NOT NULL DEFAULT '{}',
            label TEXT NOT NULL DEFAULT '',
            cadence TEXT NOT NULL DEFAULT 'instant',
            last_notified_at TEXT NOT NULL DEFAULT '',
            match_count INTEGER NOT NULL DEFAULT 0,
            created_at TEXT NOT NULL,
            updated_at TEXT NOT NULL DEFAULT ''
        );
        CREATE INDEX IF NOT EXISTS idx_saved_searches_user ON saved_searches(user_id, created_at);
        CREATE INDEX IF NOT EXISTS idx_saved_searches_match ON saved_searches(vertical, cadence);
        """
    )


def ensure_apns_push_ledger_schema(conn: sqlite3.Connection) -> None:
    """Idempotent: per-user / per-JST-day APNs send counter backing the daily
    cap on reminder-type pushes in server_apns. New table for existing SQLite
    DBs; PostgreSQL gets it via migration 90."""
    conn.executescript(
        """
        CREATE TABLE IF NOT EXISTS apns_push_ledger (
            user_id TEXT NOT NULL,
            jst_date TEXT NOT NULL,
            count INTEGER NOT NULL DEFAULT 0,
            PRIMARY KEY (user_id, jst_date)
        );
        """
    )


def serialize_saved_search(row: dict[str, Any]) -> dict[str, Any]:
    d = dict(row)
    try:
        filters = json.loads(d.get("filter_json") or "{}")
    except (TypeError, ValueError):
        filters = {}
    return {
        "id": d.get("id"),
        "vertical": d.get("vertical") or "",
        "listingType": d.get("vertical") or "",
        "citySlug": d.get("city_slug") or "", "city_slug": d.get("city_slug") or "",
        "regionCode": d.get("region_code") or "", "region_code": d.get("region_code") or "",
        "countryCode": d.get("country_code") or "", "country_code": d.get("country_code") or "",
        "keyword": d.get("keyword") or "",
        "category": d.get("category") or "",
        "filters": filters, "filterJson": d.get("filter_json") or "{}",
        "label": d.get("label") or "",
        "cadence": d.get("cadence") or "instant",
        "matchCount": int(d.get("match_count") or 0), "match_count": int(d.get("match_count") or 0),
        "lastNotifiedAt": d.get("last_notified_at") or "", "last_notified_at": d.get("last_notified_at") or "",
        "createdAt": d.get("created_at"), "created_at": d.get("created_at"),
        "updatedAt": d.get("updated_at") or "", "updated_at": d.get("updated_at") or "",
    }


def saved_search_auto_label(vertical: str, city_slug: str, region_code: str, keyword: str, category: str) -> str:
    bits: list[str] = []
    if keyword:
        bits.append(keyword)
    if category and category != keyword:
        bits.append(category)
    loc = city_slug or region_code
    if loc:
        bits.append(loc)
    if not bits and vertical:
        bits.append(vertical)
    label = " · ".join(b for b in bits if b)[:120]
    return label or "我的订阅"


def _saved_search_category_set(s: dict[str, Any]) -> set[str]:
    """Optional `categories` (comma-separated string or list) inside
    filter_json — used when a channel tab queries by a category SET (web
    homestay tab, services sections) instead of a single `category`. Empty
    set = no constraint."""
    try:
        filters = json.loads(s.get("filter_json") or "{}")
    except (TypeError, ValueError):
        return set()
    if not isinstance(filters, dict):
        return set()
    raw = filters.get("categories")
    if isinstance(raw, list):
        return {str(c).strip() for c in raw if str(c).strip()}
    return {c.strip() for c in str(raw or "").split(",") if c.strip()}


def notify_favorite_listing_change(
    conn: sqlite3.Connection,
    listing_id: str,
    *,
    author_id: str,
    title: str,
    kind: str,
    old_price: Any = None,
    new_price: Any = None,
) -> int:
    """Best-effort: notify everyone who favorited `listing_id` that it either
    dropped in price (kind='favorite_price_drop') or was taken down
    (kind='favorite_closed'). NEVER raises — a notification bug must not break
    the owner's edit. The author is always excluded (you don't get pinged about
    your own listing). Both are _TRANSACTIONAL_TYPES on the push side (low-freq,
    high-value). Returns the number of favoriters notified."""
    try:
        if kind not in ("favorite_price_drop", "favorite_closed"):
            return 0
        favoriters = [
            dict(r) for r in conn.execute(
                "SELECT user_id FROM listing_favorites WHERE listing_id = ?", (listing_id,)
            )
        ]
        if not favoriters:
            return 0
        title = (str(title or "").strip() or "你收藏的信息")[:140]
        if kind == "favorite_price_drop":
            # Show the concrete drop when both prices are clean numbers; otherwise
            # a generic "降价了" still tells the user to go look.
            try:
                content = f"「{title}」降价了：¥{int(float(new_price)):,} (原 ¥{int(float(old_price)):,})"[:140]
            except (TypeError, ValueError):
                content = f"「{title}」降价了"[:140]
        else:
            content = f"「{title}」已下架"[:140]
        now = now_iso()
        notified = 0
        for f in favoriters:
            uid = f.get("user_id")
            if not uid or uid == author_id:
                continue  # never notify the author about their own listing
            conn.execute(
                """
                INSERT INTO notifications (id, user_id, actor_id, type, target_listing_id, content, created_at)
                VALUES (?, ?, ?, ?, ?, ?, ?)
                """,
                (str(uuid.uuid4()), uid, author_id or uid, kind, listing_id, content, now),
            )
            HUB.publish(uid, {"type": "notification", "kind": kind, "listing_id": listing_id})
            server_apns.enqueue(uid, ntype=kind, actor_id="", content=content, listing_id=listing_id)
            notified += 1
        return notified
    except Exception as exc:  # pragma: no cover - defensive: must not break the edit
        try:
            ERR_LOG.warning("notify_favorite_listing_change failed listing=%s kind=%s error=%s",
                            listing_id, kind, exc)
        except Exception:
            pass
        return 0


def notify_saved_search_matches(conn: sqlite3.Connection, listing: dict[str, Any]) -> int:
    """Best-effort: notify every user whose saved search matches this freshly
    published listing. NEVER raises — a saved-search bug must not break listing
    publishing. Returns the number of users notified. Filter-level (attribute)
    matching is intentionally deferred to v2; v1 matches on vertical + location
    (metro-circle aware) + keyword + category (+ an optional `categories` set
    inside filter_json, used by the web homestay/services-section tabs)."""
    try:
        listing_id = listing.get("id")
        if not listing_id:
            return 0
        ltype = str(listing.get("type") or "").strip().lower()
        seller_id = listing.get("seller_user_id") or ""
        l_city = str(listing.get("city_slug") or "").strip().lower()
        l_region = str(listing.get("region_code") or "").strip().lower()
        l_country = str(listing.get("country_code") or "").strip().lower()
        l_category = str(listing.get("category") or "").strip()
        haystack = " ".join(
            str(listing.get(k) or "") for k in ("title", "description", "category")
        ).lower()
        # job/hiring are one family: the jobs channel on both clients merges
        # both streams, and historically Web subscribed 'job' while iOS
        # subscribed 'hiring' — either row must match either listing type.
        ltype_alias = {"job": "hiring", "hiring": "job"}.get(ltype, ltype)
        rows = list(conn.execute(
            """
            SELECT * FROM saved_searches
             WHERE cadence = 'instant'
               AND (vertical = '' OR vertical = ? OR vertical = ?)
             ORDER BY created_at DESC
             LIMIT 1000
            """,
            (ltype, ltype_alias),
        ))
        notified = 0
        now = now_iso()
        for r in rows:
            s = dict(r)
            uid = s.get("user_id")
            if not uid or uid == seller_id:
                continue
            s_city = str(s.get("city_slug") or "").strip().lower()
            s_region = str(s.get("region_code") or "").strip().lower()
            s_country = str(s.get("country_code") or "").strip().lower()
            if s_city:
                circle = {c.lower() for c in (metro_circle_city_slugs_for_city(l_country or "jp", s_city) or [])}
                circle.add(s_city)
                if l_city not in circle:
                    continue
            elif s_region:
                circle = {c.lower() for c in (metro_circle_region_codes(s_region) or [])}
                circle.add(s_region)
                if l_region not in circle:
                    continue
            elif s_country:
                if l_country != s_country:
                    continue
            kw = str(s.get("keyword") or "").strip().lower()
            if kw and kw not in haystack:
                continue
            cat = str(s.get("category") or "").strip()
            if cat and cat != l_category:
                continue
            cat_set = _saved_search_category_set(s)
            if cat_set and l_category not in cat_set:
                continue
            # Dedupe: at most one saved-search notification per (user, listing).
            if conn.execute(
                "SELECT 1 FROM notifications WHERE user_id = ? AND type = 'saved_search' "
                "AND target_listing_id = ? AND deleted_at IS NULL LIMIT 1",
                (uid, listing_id),
            ).fetchone():
                continue
            content = (str(listing.get("title") or "").strip() or "新的匹配信息")[:140]
            conn.execute(
                """
                INSERT INTO notifications (id, user_id, actor_id, type, target_listing_id, content, created_at)
                VALUES (?, ?, ?, 'saved_search', ?, ?, ?)
                """,
                (str(uuid.uuid4()), uid, seller_id or uid, listing_id, content, now),
            )
            conn.execute(
                "UPDATE saved_searches SET match_count = match_count + 1, last_notified_at = ?, "
                "updated_at = ? WHERE id = ?",
                (now, now, s.get("id")),
            )
            # Push banner (N1) — no-op until APNs is configured; never raises.
            server_apns.enqueue(uid, ntype="saved_search", actor_id=seller_id or "", content=content,
                                listing_id=listing_id)
            notified += 1
        return notified
    except Exception as exc:  # pragma: no cover - defensive: must not break publish
        try:
            ERR_LOG.warning("notify_saved_search_matches failed listing=%s error=%s",
                            listing.get("id"), exc)
        except Exception:
            pass
        return 0


def _saved_search_matches_listing(s: dict[str, Any], listing: dict[str, Any]) -> bool:
    """Shared predicate: does saved search row `s` match listing `listing`?
    Mirrors the per-listing logic in notify_saved_search_matches (vertical is
    assumed pre-filtered by the caller)."""
    l_city = str(listing.get("city_slug") or "").strip().lower()
    l_region = str(listing.get("region_code") or "").strip().lower()
    l_country = str(listing.get("country_code") or "").strip().lower()
    s_city = str(s.get("city_slug") or "").strip().lower()
    s_region = str(s.get("region_code") or "").strip().lower()
    s_country = str(s.get("country_code") or "").strip().lower()
    if s_city:
        circle = {c.lower() for c in (metro_circle_city_slugs_for_city(l_country or "jp", s_city) or [])}
        circle.add(s_city)
        if l_city not in circle:
            return False
    elif s_region:
        circle = {c.lower() for c in (metro_circle_region_codes(s_region) or [])}
        circle.add(s_region)
        if l_region not in circle:
            return False
    elif s_country:
        if l_country != s_country:
            return False
    kw = str(s.get("keyword") or "").strip().lower()
    if kw:
        haystack = " ".join(
            str(listing.get(k) or "") for k in ("title", "description", "category")
        ).lower()
        if kw not in haystack:
            return False
    cat = str(s.get("category") or "").strip()
    if cat and cat != str(listing.get("category") or "").strip():
        return False
    cat_set = _saved_search_category_set(s)
    if cat_set and str(listing.get("category") or "").strip() not in cat_set:
        return False
    return True


def run_saved_search_digests(conn: sqlite3.Connection) -> int:
    """Daily digest for saved searches with cadence='daily': batch every new
    matching listing published since the search's last digest into ONE
    notification, instead of an instant ping per match. Each daily search is
    digested at most once per ~20h (gated by last_notified_at) so the 6-hourly
    janitor that calls this never double-sends. Best-effort; never raises."""
    try:
        now = now_iso()
        due_cutoff = (datetime.now(timezone.utc) - timedelta(hours=20)).isoformat()
        default_since = (datetime.now(timezone.utc) - timedelta(days=7)).isoformat()
        rows = list(conn.execute(
            """
            SELECT * FROM saved_searches
             WHERE cadence = 'daily'
               AND (last_notified_at = '' OR last_notified_at < ?)
             ORDER BY updated_at ASC
             LIMIT 500
            """,
            (due_cutoff,),
        ))
        sent = 0
        for r in rows:
            s = dict(r)
            uid = s.get("user_id")
            if not uid:
                continue
            vertical = str(s.get("vertical") or "").strip().lower()
            since = s.get("last_notified_at") or default_since
            where = [
                "status = 'published'",
                "deleted_at IS NULL",
                "COALESCE(NULLIF(published_at, ''), created_at) > ?",
            ]
            params: list[Any] = [since]
            if vertical in ("job", "hiring"):
                # job/hiring are one family (jobs channel merges both streams).
                where.append("type IN ('job', 'hiring')")
            elif vertical:
                where.append("type = ?")
                params.append(vertical)
            cands = list(conn.execute(
                "SELECT id, title, description, category, type, city_slug, region_code, "
                "country_code, seller_user_id, "
                "COALESCE(NULLIF(published_at, ''), created_at) AS pub "
                "FROM city_listings WHERE " + " AND ".join(where) +
                " ORDER BY pub DESC LIMIT 200",
                params,
            ))
            matches = [
                dict(c) for c in cands
                if dict(c).get("seller_user_id") != uid
                and _saved_search_matches_listing(s, dict(c))
            ]
            # Always advance last_notified_at to reset the 20h window, even with
            # zero matches — otherwise an empty search re-scans every sweep.
            if not matches:
                conn.execute(
                    "UPDATE saved_searches SET last_notified_at = ?, updated_at = ? WHERE id = ?",
                    (now, now, s.get("id")),
                )
                continue
            count = len(matches)
            top = matches[0]
            label = str(s.get("label") or s.get("keyword") or vertical or "保存的搜索").strip()
            content = f"「{label}」有 {count} 条新匹配信息"[:140]
            conn.execute(
                """
                INSERT INTO notifications (id, user_id, actor_id, type, target_listing_id, content, created_at)
                VALUES (?, ?, ?, 'saved_search', ?, ?, ?)
                """,
                (str(uuid.uuid4()), uid, uid, top["id"], content, now),
            )
            conn.execute(
                "UPDATE saved_searches SET match_count = match_count + ?, last_notified_at = ?, "
                "updated_at = ? WHERE id = ?",
                (count, now, now, s.get("id")),
            )
            # Same deep-link target as the in-app row above: tapping the push
            # opens the digest's top match (instant path at
            # notify_saved_search_matches does the same).
            server_apns.enqueue(uid, ntype="saved_search", actor_id="", content=content,
                                listing_id=top["id"])
            sent += 1
        return sent
    except Exception as exc:  # pragma: no cover - defensive: must not break the janitor
        try:
            ERR_LOG.warning("run_saved_search_digests failed error=%s", exc)
        except Exception:
            pass
        return 0


# Digest cadence: at most one of each digest type per user per ~20h. Reuses the
# same "look at the last notification row of this type" gate as saved-search
# digests, so the 6-hourly janitor never double-sends even though it runs 4×/day.
_DIGEST_MIN_INTERVAL_HOURS = 20


def _digest_recently_sent(conn: sqlite3.Connection, user_id: str, ntype: str, cutoff_iso: str) -> bool:
    """True if a `ntype` notification was written to `user_id` since `cutoff_iso`
    — the once-per-day gate for the digest tasks."""
    return conn.execute(
        "SELECT 1 FROM notifications WHERE user_id = ? AND type = ? "
        "AND created_at >= ? AND deleted_at IS NULL LIMIT 1",
        (user_id, ntype, cutoff_iso),
    ).fetchone() is not None


def run_follow_digests(conn: sqlite3.Connection) -> int:
    """Daily "你关注的 N 人发布了新内容" summary (B6 #4 + #7). For each user who
    follows people and/or topics, count the DISTINCT authors they follow who
    posted in the last day, plus new posts under followed hashtags, and write ONE
    `follow_digest` notification (payload lands the 关注 tab — no postId). Gated to
    once/~20h per user. Best-effort; never raises."""
    try:
        now = now_iso()
        cutoff = (datetime.now(timezone.utc) - timedelta(hours=_DIGEST_MIN_INTERVAL_HOURS)).isoformat()
        since = (datetime.now(timezone.utc) - timedelta(days=1)).isoformat()
        # Everyone who follows at least one person OR at least one topic.
        followers = [
            dict(r) for r in conn.execute(
                """
                SELECT DISTINCT user_id FROM (
                    SELECT follower_id AS user_id FROM follows
                    UNION
                    SELECT user_id FROM topic_follows
                ) t
                LIMIT 5000
                """
            )
        ]
        sent = 0
        for f in followers:
            uid = f.get("user_id")
            if not uid:
                continue
            if _digest_recently_sent(conn, uid, "follow_digest", cutoff):
                continue
            # (a) distinct followed authors who posted in the last day.
            people_row = conn.execute(
                """
                SELECT COUNT(DISTINCT p.author_id) AS c
                  FROM follows fo
                  JOIN posts p ON p.author_id = fo.following_id
                 WHERE fo.follower_id = ?
                   AND p.created_at >= ?
                   AND p.status = 'active'
                   AND p.deleted_at IS NULL
                   AND p.author_id <> ?
                """,
                (uid, since, uid),
            ).fetchone()
            people = int(people_row["c"] if people_row else 0)
            # (b) new posts under any topic this user follows (last day).
            topic_row = conn.execute(
                """
                SELECT COUNT(DISTINCT pt.post_id) AS c
                  FROM topic_follows tf
                  JOIN post_tags pt ON pt.tag = tf.tag
                  JOIN posts p ON p.id = pt.post_id
                 WHERE tf.user_id = ?
                   AND p.created_at >= ?
                   AND p.status = 'active'
                   AND p.deleted_at IS NULL
                   AND p.author_id <> ?
                """,
                (uid, since, uid),
            ).fetchone()
            topics = int(topic_row["c"] if topic_row else 0)
            if people <= 0 and topics <= 0:
                continue
            frags: list[str] = []
            if people > 0:
                frags.append(f"你关注的 {people} 人发布了新内容")
            if topics > 0:
                frags.append(f"关注的话题有 {topics} 条新帖")
            content = "，".join(frags)[:140]
            conn.execute(
                """
                INSERT INTO notifications (id, user_id, actor_id, type, content, created_at)
                VALUES (?, ?, ?, 'follow_digest', ?, ?)
                """,
                (str(uuid.uuid4()), uid, uid, content, now),
            )
            # No postId — the client routes follow_digest to the 关注 tab.
            server_apns.enqueue(uid, ntype="follow_digest", actor_id="", content=content)
            sent += 1
        return sent
    except Exception as exc:  # pragma: no cover - defensive: must not break the janitor
        try:
            ERR_LOG.warning("run_follow_digests failed error=%s", exc)
        except Exception:
            pass
        return 0


def run_city_digests(conn: sqlite3.Connection) -> int:
    """Inactive-user recall (B6 #5). For users whose most-recent session was
    3..8 days ago (a light re-engagement window, not a firehose), count the
    NEW listings and hot posts in their region over the last week and, when
    there's something real to show, write ONE `city_digest` notification. Zero
    on both counts → no push (never nag with nothing). Gated once/~20h per user.
    The daily push cap (_CAPPED_TYPES) is the backstop against over-messaging.
    Best-effort; never raises."""
    try:
        now = now_iso()
        cutoff = (datetime.now(timezone.utc) - timedelta(hours=_DIGEST_MIN_INTERVAL_HOURS)).isoformat()
        window_start = (datetime.now(timezone.utc) - timedelta(days=7)).isoformat()
        inactive_lo = (datetime.now(timezone.utc) - timedelta(days=8)).isoformat()
        inactive_hi = (datetime.now(timezone.utc) - timedelta(days=3)).isoformat()
        # Users whose LATEST session activity falls in the [3d, 8d) window. We
        # use MAX(last_seen_at) per user so someone with an old session but a
        # fresh one isn't treated as inactive. (sessions has no revoked_at
        # column — see campaign_recipient_rows — so we don't filter on it.)
        candidates = [
            dict(r) for r in conn.execute(
                """
                SELECT u.id AS user_id, u.current_region_code AS region_code,
                       u.city AS city, u.country AS country
                  FROM users u
                  JOIN (
                      SELECT user_id, MAX(last_seen_at) AS seen
                        FROM sessions GROUP BY user_id
                  ) s ON s.user_id = u.id
                 WHERE u.deleted_at IS NULL
                   AND s.seen >= ?
                   AND s.seen < ?
                 LIMIT 5000
                """,
                (inactive_lo, inactive_hi),
            )
        ]
        sent = 0
        for c in candidates:
            uid = c.get("user_id")
            region = str(c.get("region_code") or "").strip().lower()
            country = str(c.get("country") or "").strip().lower()
            if not uid:
                continue
            if not region and not country:
                continue  # no region to summarise — skip rather than guess
            if _digest_recently_sent(conn, uid, "city_digest", cutoff):
                continue
            # New listings in the user's region over the last week (real count).
            if region:
                listing_row = conn.execute(
                    "SELECT COUNT(*) AS c FROM city_listings "
                    "WHERE region_code = ? AND status = 'published' AND deleted_at IS NULL "
                    "AND COALESCE(NULLIF(published_at, ''), created_at) >= ?",
                    (region, window_start),
                ).fetchone()
                post_row = conn.execute(
                    "SELECT COUNT(*) AS c FROM posts "
                    "WHERE region_code = ? AND status = 'active' AND deleted_at IS NULL "
                    "AND created_at >= ? AND weighted_interaction_score > 0",
                    (region, window_start),
                ).fetchone()
            else:
                listing_row = conn.execute(
                    "SELECT COUNT(*) AS c FROM city_listings "
                    "WHERE country_code = ? AND status = 'published' AND deleted_at IS NULL "
                    "AND COALESCE(NULLIF(published_at, ''), created_at) >= ?",
                    (country, window_start),
                ).fetchone()
                post_row = conn.execute(
                    "SELECT COUNT(*) AS c FROM posts "
                    "WHERE country = ? AND status = 'active' AND deleted_at IS NULL "
                    "AND created_at >= ? AND weighted_interaction_score > 0",
                    (country, window_start),
                ).fetchone()
            listings = int(listing_row["c"] if listing_row else 0)
            hot_posts = int(post_row["c"] if post_row else 0)
            if listings <= 0 and hot_posts <= 0:
                continue  # nothing real to say — don't nag
            frags: list[str] = []
            if listings > 0:
                frags.append(f"新增 {listings} 条房源/信息")
            if hot_posts > 0:
                frags.append(f"{hot_posts} 个热帖")
            content = ("你的城市" + "，".join(frags))[:140]
            conn.execute(
                """
                INSERT INTO notifications (id, user_id, actor_id, type, content, created_at)
                VALUES (?, ?, ?, 'city_digest', ?, ?)
                """,
                (str(uuid.uuid4()), uid, uid, content, now),
            )
            server_apns.enqueue(uid, ntype="city_digest", actor_id="", content=content)
            sent += 1
        return sent
    except Exception as exc:  # pragma: no cover - defensive: must not break the janitor
        try:
            ERR_LOG.warning("run_city_digests failed error=%s", exc)
        except Exception:
            pass
        return 0


# Orphan-media GC (B6 #8). Uploads that were presigned + completed but never
# attached to any content leak S3 objects + rows forever. This sweep is
# deliberately CONSERVATIVE: it only touches rows that are (a) status='ready',
# (b) older than 48h, (c) never attached to an entity (entity_type/entity_id
# both empty), (d) NOT a purpose that's referenced by URL instead of by an
# entity row (avatar / cover / logo — those live in users/businesses columns,
# not in a *_media table, so entity_type stays empty even when in use), and
# (e) confirmed absent from EVERY known reference table. Anything whose
# reference we can't establish is left alone. Bounded per pass to avoid a long
# write transaction.
KAIX_ORPHAN_MEDIA_MAX_PER_SWEEP = max(1, int(_env("KAIX_ORPHAN_MEDIA_MAX_PER_SWEEP", "200")))

# Purposes referenced by a URL/id column on users/businesses (avatar_url,
# cover_url, business logo/cover) rather than by a *_media / *_attachments row.
# entity_type is empty for these even when they're live, so the entity-based
# orphan test would false-positive — never sweep them here.
_ORPHAN_GC_SKIP_PURPOSES = {
    "avatar",
    "profile_cover",
    "business_logo",
    "business_cover",
}


def _uploaded_file_is_referenced(conn: sqlite3.Connection, file_id: str) -> bool:
    """True if `file_id` is used by any known content table. Mirrors the
    in-use check in api_upload_delete, extended with the guide-product and
    business-verification reference tables. Conservative: any hit (or any
    query error) means 'referenced', so the GC never deletes on doubt."""
    try:
        row = conn.execute(
            """
            SELECT
              (SELECT COUNT(*) FROM post_media WHERE media_id = ? OR uploaded_file_id = ?) +
              (SELECT COUNT(*) FROM message_media WHERE media_id = ?) +
              (SELECT COUNT(*) FROM message_attachments WHERE (uploaded_file_id = ? OR thumbnail_file_id = ?) AND deleted_at IS NULL) +
              (SELECT COUNT(*) FROM listing_media WHERE uploaded_file_id = ? OR id = ?) +
              (SELECT COUNT(*) FROM guide_product_files WHERE uploaded_file_id = ?) +
              (SELECT COUNT(*) FROM business_verification_documents WHERE uploaded_file_id = ?) AS c
            """,
            (file_id, file_id, file_id, file_id, file_id, file_id, file_id, file_id, file_id),
        ).fetchone()
        return int(row["c"] if row else 1) > 0
    except Exception:
        return True  # unknown → treat as referenced, never delete


def run_orphan_media_gc(conn: sqlite3.Connection) -> int:
    """Delete a bounded batch of orphaned uploads (S3 object + row). Returns the
    number of rows swept. Best-effort; never raises."""
    try:
        cutoff = (datetime.now(timezone.utc) - timedelta(hours=48)).isoformat()
        candidates = [
            dict(r) for r in conn.execute(
                """
                SELECT id, object_key, bucket, purpose
                  FROM uploaded_files
                 WHERE status = 'ready'
                   AND deleted_at IS NULL
                   AND created_at < ?
                   AND COALESCE(entity_type, '') = ''
                   AND COALESCE(entity_id, '') = ''
                 ORDER BY created_at ASC
                 LIMIT ?
                """,
                (cutoff, KAIX_ORPHAN_MEDIA_MAX_PER_SWEEP),
            )
        ]
        now = now_iso()
        swept = 0
        for d in candidates:
            if str(d.get("purpose") or "") in _ORPHAN_GC_SKIP_PURPOSES:
                continue
            if _uploaded_file_is_referenced(conn, d["id"]):
                continue
            # Best-effort object delete first; even if it fails we still soft-delete
            # the row so it stops being scanned (a leaked object is far cheaper than
            # re-scanning it every sweep, and admin temp-cleanup can reap it later).
            try:
                object_key = str(d.get("object_key") or "")
                if object_key:
                    if d.get("bucket") == "local-dev":
                        local_upload_path(object_key).unlink(missing_ok=True)
                    else:
                        _s3_delete_object(object_key)
            except Exception:
                pass
            conn.execute(
                "UPDATE uploaded_files SET status = 'deleted', deleted_at = ?, updated_at = ? WHERE id = ?",
                (now, now, d["id"]),
            )
            # Keep any mirror media row consistent (media.id == uploaded_files.id
            # on the current upload path).
            conn.execute("UPDATE media SET deleted_at = ? WHERE id = ? AND deleted_at IS NULL", (now, d["id"]))
            swept += 1
        return swept
    except Exception as exc:  # pragma: no cover - defensive: must not break the janitor
        try:
            ERR_LOG.warning("run_orphan_media_gc failed error=%s", exc)
        except Exception:
            pass
        return 0


def ensure_membership_plans(conn: sqlite3.Connection) -> None:
    """Seed editable monthly/yearly plans without overwriting admin changes."""
    now = now_iso()
    for seed in _membership_plan_seed_rows():
        existing = conn.execute(
            "SELECT id FROM membership_plans WHERE plan_key = ?", (seed["plan_key"],)
        ).fetchone()
        if existing:
            # Backfill new columns only when the old row is empty. Do not rewrite
            # price/currency/Stripe/IAP fields after an admin has edited them.
            conn.execute(
                """
                UPDATE membership_plans
                   SET name = COALESCE(NULLIF(name, ''), ?),
                       subtitle = COALESCE(NULLIF(subtitle, ''), ?),
                       description = COALESCE(NULLIF(description, ''), ?),
                       billing_period = COALESCE(NULLIF(billing_period, ''), COALESCE(NULLIF(billing_cycle, ''), ?)),
                       billing_cycle = COALESCE(NULLIF(billing_cycle, ''), ?),
                       interval_count = CASE WHEN interval_count <= 0 THEN ? ELSE interval_count END,
                       price = CASE WHEN price <= 0 THEN ? ELSE price END,
                       amount_cents = CASE WHEN amount_cents <= 0 THEN ? ELSE amount_cents END,
                       price_label = COALESCE(NULLIF(price_label, ''), ?),
                       ios_iap_product_id = COALESCE(NULLIF(ios_iap_product_id, ''), ?),
                       apple_product_id = COALESCE(NULLIF(apple_product_id, ''), ?),
                       benefits = CASE WHEN benefits = '' OR benefits = '[]' THEN ? ELSE benefits END,
                       updated_at = updated_at
                 WHERE plan_key = ?
                """,
                (
                    seed["name"], seed["subtitle"], seed["description"], seed["billing_period"],
                    seed["billing_period"], seed["interval_count"], seed["price"], seed["amount_cents"],
                    seed["price_label"], seed["ios_iap_product_id"], seed["apple_product_id"],
                    seed["benefits"], seed["plan_key"],
                ),
            )
            continue
        row = {
            "id": str(uuid.uuid4()),
            **seed,
            "billing_cycle": seed["billing_period"],
            "is_active": 1,
            "created_at": now,
            "updated_at": now,
        }
        conn.execute(
            f"INSERT INTO membership_plans ({', '.join(row.keys())}) VALUES ({', '.join(['?'] * len(row))})",
            tuple(row.values()),
        )
    # Keep the historical cny_10 key readable for existing rows, but do not
    # expose it as the default card when a fresh DB uses the new keys.
    if MEMBERSHIP_LEGACY_PLAN_KEY != MEMBERSHIP_PLAN_MONTHLY_KEY and not conn.execute(
        "SELECT id FROM membership_plans WHERE plan_key = ?", (MEMBERSHIP_LEGACY_PLAN_KEY,)
    ).fetchone():
        seed = _membership_plan_seed_rows()[0].copy()
        seed["plan_key"] = MEMBERSHIP_LEGACY_PLAN_KEY
        seed["is_default"] = 0
        seed["sort_order"] = 99
        row = {"id": str(uuid.uuid4()), **seed, "billing_cycle": seed["billing_period"],
               "is_active": 1, "created_at": now, "updated_at": now}
        conn.execute(
            f"INSERT INTO membership_plans ({', '.join(row.keys())}) VALUES ({', '.join(['?'] * len(row))})",
            tuple(row.values()),
        )
    # Copy-only migration for old production rows: remove subscription wording
    # without touching admin-edited prices, currencies, IAP IDs or benefits.
    conn.execute(
        "UPDATE membership_plans SET subtitle = ?, updated_at = ? "
        "WHERE plan_key IN (?, ?) AND subtitle = ?",
        (
            "按月购买，到期前可再次续购",
            now,
            MEMBERSHIP_PLAN_MONTHLY_KEY,
            MEMBERSHIP_LEGACY_PLAN_KEY,
            "按月订阅，随时管理",
        ),
    )
    conn.execute(
        "UPDATE membership_plans SET description = ?, updated_at = ? "
        "WHERE plan_key = ? AND description = ?",
        (
            "一次购买一年，同步获得 Machi 认证会员全部权益。",
            now,
            MEMBERSHIP_PLAN_YEARLY_KEY,
            "包年订阅，同步获得 Machi 认证会员全部权益。",
        ),
    )
    # Membership is now denominated in JPY (Japan-facing). Rewrite old
    # seeded/production rows that still carry a historical CNY price to the new
    # JPY figures: ¥600 / 30天 and ¥4,800 / 365天. Storage stays value×100
    # (amount_cents), and the Stripe edge divides by 100 for JPY (zero-decimal),
    # so amount_cents=60000 charges 600 minor units = ¥600. Only migrate rows
    # still carrying a known-old value; if an operator has already set the JPY
    # price in Admin (600 / 4800) the WHERE clause skips them, preserving edits.
    # (Guard on currency='CNY' too so an already-migrated JPY 600 row is left
    # intact even though 600 appears in the monthly value list.)
    conn.execute(
        """
        UPDATE membership_plans
           SET price = 600,
               amount_cents = 60000,
               currency = 'JPY',
               price_label = '¥600 / 30天',
               ios_iap_product_id = ?,
               apple_product_id = ?,
               updated_at = ?
         WHERE plan_key = ?
           AND currency = 'CNY'
           AND price IN (0, 10, 18, 600)
        """,
        (APPLE_IAP_PRODUCT_ID, APPLE_IAP_PRODUCT_ID, now, MEMBERSHIP_PLAN_MONTHLY_KEY),
    )
    conn.execute(
        """
        UPDATE membership_plans
           SET price = 4800,
               amount_cents = 480000,
               currency = 'JPY',
               price_label = '¥4,800 / 365天',
               original_price = 7200,
               discount_label = '约省 1 个月',
               ios_iap_product_id = ?,
               apple_product_id = ?,
               updated_at = ?
         WHERE plan_key = ?
           AND currency = 'CNY'
           AND price IN (0, 98, 138, 198, 4800)
        """,
        (APPLE_IAP_PRODUCT_ID_YEARLY, APPLE_IAP_PRODUCT_ID_YEARLY, now, MEMBERSHIP_PLAN_YEARLY_KEY),
    )


