def _guide_bool_value(raw: Any, default: bool = False) -> bool:
    if raw is None or raw == "":
        return default
    if isinstance(raw, bool):
        return raw
    if isinstance(raw, (int, float)):
        return bool(raw)
    return str(raw).strip().lower() in {"1", "true", "yes", "y", "是", "需要", "on"}


GUIDE_ARRIVAL_STAGES = ("pre_arrival", "just_arrived", "first_year", "long_term")


def _guide_arrival_stage_value(raw: Any) -> str:
    # Whitelisted 来日阶段 enum; anything else is treated as unset ('') in the
    # handler's usual coerce-don't-400 style.
    text = str(raw or "").strip().lower()
    return text if text in GUIDE_ARRIVAL_STAGES else ""


def _guide_date_value(raw: Any) -> str | None:
    text = str(raw or "").strip()
    if not text:
        return None
    # Keep API date/datetime strings stable and permissive. The UI only needs
    # sortable ISO-ish values; exact timezone handling can remain client-side.
    return text[:32]


def _guide_today_date() -> datetime:
    # The workbench (todos/calendar/finance) is a Japan-life tool: "today" must
    # mean today in JST, not UTC — with UTC every user between 00:00 and 09:00
    # JST saw yesterday as "today" (todo grouping, overdue, calendar highlight).
    return datetime.now(timezone(timedelta(hours=9)))


def _guide_date_add(days: int, base: datetime | None = None) -> str:
    return ((base or _guide_today_date()) + timedelta(days=days)).date().isoformat()


def _guide_date_minus(raw: Any, days: int) -> str | None:
    text = str(raw or "").strip()
    if not text:
        return None
    try:
        parsed = datetime.fromisoformat(text[:10])
    except ValueError:
        return None
    return (parsed - timedelta(days=max(0, days))).date().isoformat()


def _guide_quick_todo_date_from_text(text: str) -> str | None:
    """Best-effort date extraction for one-line todo entry.

    This is intentionally conservative: it recognizes common "今天 / 明天 /
    下周 / 7/25 / 2026-07-25" style input, then stores the normalized date on
    the server. It is a helper, not a natural-language parser.
    """
    raw = (text or "").strip()
    if not raw:
        return None
    today = _guide_today_date().date()
    lowered = raw.lower()
    keyword_offsets = (
        (("今天", "今日", "today"), 0),
        (("明天", "明日", "tomorrow"), 1),
        (("后天", "後天"), 2),
        (("下周", "来週", "next week"), 7),
    )
    for keys, offset in keyword_offsets:
        if any(k in lowered or k in raw for k in keys):
            return (today + timedelta(days=offset)).isoformat()
    if "周末" in raw or "週末" in raw or "weekend" in lowered:
        days = (5 - today.weekday()) % 7
        return (today + timedelta(days=days or 7)).isoformat()

    explicit = re.search(r"(20\d{2})[./\-年](\d{1,2})[./\-月](\d{1,2})", raw)
    if explicit:
        try:
            return datetime(int(explicit.group(1)), int(explicit.group(2)), int(explicit.group(3))).date().isoformat()
        except ValueError:
            return None
    md = re.search(r"(?<!\d)(\d{1,2})[./\-月](\d{1,2})(?:日)?(?!\d)", raw)
    if md:
        try:
            candidate = datetime(today.year, int(md.group(1)), int(md.group(2))).date()
            if candidate < today:
                candidate = datetime(today.year + 1, int(md.group(1)), int(md.group(2))).date()
            return candidate.isoformat()
        except ValueError:
            return None
    return None


