def _guide_template_key(app_type: str, career_track: str = "") -> str:
    if app_type == "school":
        return "school"
    if app_type in ("jlpt", "exam"):
        return "jlpt"
    if (career_track or "").strip().lower() in {"tenshoku", "mid_career", "midcareer", "社会人"}:
        return "company:tenshoku"
    return "company:shinsotsu"


