def _guide_funnel_log(event: str, user_id: str = "", **extra: Any) -> None:
    """Lightweight Guide funnel analytics (spec P2): one structured ACCESS_LOG
    line per conversion step (journeys_viewed → plan_started → todo_completed →
    study_plan_created) so the funnel is grep-able without a new table."""
    try:
        parts = " ".join(f"{k}={v}" for k, v in extra.items() if v not in (None, ""))
        ACCESS_LOG.info("guide_funnel event=%s user=%s %s", event, (user_id or "guest")[:12], parts)
    except Exception:
        pass


# Generic product funnel (B6 #6). Whitelisted client events for the discovery /
# listing / compose / purchase funnels, logged as structured ACCESS_LOG lines
# (no table) so they're grep-able / shippable to a log aggregator like the guide
# funnel above. Unknown events are rejected so the log stays clean.
FUNNEL_EVENTS = {
    "listing_impression",
    "listing_detail",
    "listing_contact",
    "compose_open",
    "compose_submit",
    "purchase_step",
}


def _funnel_log(event: str, user_id: str = "", entity_type: str = "", entity_id: str = "") -> None:
    """One structured ACCESS_LOG line per funnel event; mirrors _guide_funnel_log."""
    try:
        parts = " ".join(
            f"{k}={v}" for k, v in
            (("entityType", entity_type), ("entityId", entity_id)) if v not in (None, "")
        )
        ACCESS_LOG.info("funnel event=%s user=%s %s", event, (user_id or "guest")[:12], parts)
    except Exception:
        pass


def _guide_reminder_tier_dates(due_at: str, reminder_at: str | None, multi_tier: bool) -> list[str]:
    """All reminder dates for a todo (sorted, de-duped). High-value todos get a
    T-7/T-3/T-1 ladder off the due date; everything else just `reminder_at`."""
    dates: list[str] = []
    if multi_tier and due_at:
        for tier in (7, 3, 1):
            d = _guide_date_minus(due_at, tier)
            if d:
                dates.append(d)
    if reminder_at:
        dates.append(reminder_at)
    return sorted({d for d in dates if d})

# Life-bill presets (spec P1): each type carries a default recurrence + how many
# days ahead to remind, so the editor pre-fills smart defaults. (type, zh, ja,
# en, icon, recurrence, reminderDaysBefore, kind). kind: payment | contract |
# visa | procedure. monthly bills default to a 3-day heads-up; annual/visa
