def _guide_life_preset_label(preset: dict, language: str) -> str:
    if language.startswith("ja"):
        return preset.get("ja") or preset.get("zh") or preset["type"]
    if language.startswith("en"):
        return preset.get("en") or preset.get("zh") or preset["type"]
    return preset.get("zh") or preset["type"]


def _guide_identity_journey_order(identity_type: str, available_keys: list[str]) -> list[str]:
    """Order available journey keys by the user's identity; unmapped journeys
    fall back to the default order, then any remaining keys preserve their order."""
    pref = GUIDE_IDENTITY_JOURNEY_ORDER.get((identity_type or "").strip()) or GUIDE_DEFAULT_JOURNEY_ORDER
    avail = set(available_keys)
    ordered = [k for k in pref if k in avail]
    ordered += [k for k in available_keys if k not in ordered]
    return ordered


def _guide_identity_default_journey(identity_type: str, available_keys: list[str]) -> str:
    pick = GUIDE_IDENTITY_DEFAULT_JOURNEY.get((identity_type or "").strip())
    if pick and pick in available_keys:
        return pick
    ordered = _guide_identity_journey_order(identity_type, available_keys)
    return ordered[0] if ordered else "arrival"


def _guide_seed_plan_templates(conn: sqlite3.Connection) -> int:
    """Idempotently seed guide_plan_templates from the code defaults — only for
    template_keys that have no rows yet, so admin edits are never overwritten."""
    seeded = 0
    now = now_iso()
    for key, rows in _GUIDE_TEMPLATE_DEFAULTS.items():
        try:
            existing = conn.execute("SELECT COUNT(*) AS c FROM guide_plan_templates WHERE template_key = ?", (key,)).fetchone()
            if existing and int(existing["c"]) > 0:
                continue
            for idx, (offset, title, summary, todo_type, products, services) in enumerate(rows):
                conn.execute(
                    "INSERT INTO guide_plan_templates (id, template_key, offset_days, title, summary, todo_type, product_slugs, service_slugs, sort_order, status, created_at, updated_at) "
                    "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 'published', ?, ?)",
                    (str(uuid.uuid4()), key, int(offset), title, summary, todo_type, products, services, idx, now, now),
                )
                seeded += 1
        except Exception:
            continue
    return seeded


