def _guide_seed_product_relations(conn: sqlite3.Connection) -> int:
    """Idempotently seed guide_product_relations by journey from the code map —
    only for journey_keys with no rows yet, so admin curation is never lost.
    Slugs without a matching published product are skipped silently."""
    seeded = 0
    now = now_iso()
    for jkey, slugs in _GUIDE_PRODUCT_RELATION_DEFAULTS.items():
        try:
            existing = conn.execute("SELECT COUNT(*) AS c FROM guide_product_relations WHERE journey_key = ?", (jkey,)).fetchone()
            if existing and int(existing["c"]) > 0:
                continue
            for idx, slug in enumerate(slugs):
                prow = conn.execute("SELECT id FROM guide_products WHERE slug = ? LIMIT 1", (slug,)).fetchone()
                if not prow:
                    continue
                conn.execute(
                    "INSERT INTO guide_product_relations (id, product_id, plan_type, todo_type, journey_key, step_key, priority, created_at) "
                    "VALUES (?, ?, '', '', ?, '', ?, ?)",
                    (str(uuid.uuid4()), prow["id"], jkey, len(slugs) - idx, now),
                )
                seeded += 1
        except Exception:
            continue
    return seeded


def _guide_next_monthly_due(day: int) -> str | None:
    if day <= 0:
        return None
    today = _guide_today_date().date()
    safe_day = min(max(day, 1), 28)
    candidate = today.replace(day=safe_day)
    if candidate < today:
        month = today.month + 1
        year = today.year
        if month > 12:
            month = 1
            year += 1
        candidate = candidate.replace(year=year, month=month)
    return candidate.isoformat()


def ensure_guide_seed(conn: sqlite3.Connection) -> dict[str, int]:
    """Idempotently seed the Guide taxonomy + starter editorial content.

    Categories/tags/faq are config-driven and refreshed each boot. Articles /
    products / companies are inserted only when their slug is missing, so admin
    or user edits are never overwritten. No crawler data, no fake user content:
    company review tables are left empty until real users submit and pass review.
    """
    now = now_iso()
    result = {
        "categories": 0, "articles": 0, "products": 0, "schools": 0, "companies": 0,
        "faq": 0, "tags": 0, "topics": 0, "homeModules": 0,
    }
    country = GUIDE_DEFAULT_COUNTRY

    # --- categories (top-level + children) ---
    order = 0
    for cat in GUIDE_CATEGORY_SEED:
        order += 1
        _guide_upsert_category(conn, cat["key"], "", cat["title"], cat.get("subtitle", ""),
                               cat.get("description", ""), cat.get("icon", ""), cat.get("color", ""),
                               country, order, now, result)
        child_order = 0
        for child_key, child_title in cat.get("children", []):
            child_order += 1
            child_desc = f"围绕{child_title}的步骤、材料、时间线、费用和常见风险，持续补充文章、清单与相关服务。"
            _guide_upsert_category(conn, child_key, cat["key"], child_title, "", child_desc, cat.get("icon", ""),
                                   cat.get("color", ""), country, child_order, now, result)

    # --- tags ---
    tag_order = 0
    for name, key, cat_key in GUIDE_TAG_SEED:
        tag_order += 1
        exists = conn.execute("SELECT id FROM guide_tags WHERE key = ? AND country = ?", (key, country)).fetchone()
        if not exists:
            conn.execute(
                "INSERT INTO guide_tags (id, name, key, description, category_key, country, language, sort_order, is_active, created_at, updated_at) "
                "VALUES (?, ?, ?, '', ?, ?, 'zh-CN', ?, 1, ?, ?)",
                (str(uuid.uuid4()), name, key, cat_key, country, tag_order, now, now),
            )
            result["tags"] += 1

    # --- topics / themed paths ---
    for topic in GUIDE_TOPIC_SEED:
        exists = conn.execute(
            "SELECT id FROM guide_topics WHERE slug = ? AND country = ?", (topic["slug"], country)
        ).fetchone()
        if exists:
            continue
        status = str(topic.get("status") or "draft")
        conn.execute(
            "INSERT INTO guide_topics (id, title, slug, description, category_key, tags, article_slugs, product_slugs, "
            "cover_image, country, language, sort_order, status, created_at, updated_at, published_at) "
            "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'zh-CN', ?, ?, ?, ?, ?)",
            (
                str(uuid.uuid4()), topic["title"], topic["slug"], topic.get("description", ""),
                topic.get("categoryKey", ""), _guide_csv(topic.get("tags", [])),
                _guide_csv(topic.get("articleSlugs", [])), _guide_csv(topic.get("productSlugs", [])),
                topic.get("coverImage", ""), country, _guide_int(topic.get("sortOrder"), 0),
                status, now, now, now if status == "published" else None,
            ),
        )
        result["topics"] += 1

    # --- home modules ---
    for module in GUIDE_HOME_MODULE_SEED:
        key = str(module["moduleKey"])
        exists = conn.execute(
            "SELECT id FROM guide_home_modules WHERE module_key = ? AND country = ? AND language = 'zh-CN'",
            (key, country),
        ).fetchone()
        if exists:
            continue
        conn.execute(
            "INSERT INTO guide_home_modules (id, module_key, title, subtitle, content_json, country, language, "
            "sort_order, is_active, status, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, 'zh-CN', ?, 1, 'published', ?, ?)",
            (
                str(uuid.uuid4()), key, module.get("title", ""), module.get("subtitle", ""),
                json.dumps(module.get("content") or {}, ensure_ascii=False), country,
                _guide_int(module.get("sortOrder"), 0), now, now,
            ),
        )
        result["homeModules"] += 1

    # --- faq (三语:zh-CN 原文 + ja/en 译文,每语言一行,各自幂等) ---
    faq_order = 0
    for faq in GUIDE_FAQ_SEED:
        faq_order += 1
        cat = faq.get("category_key", "")
        # (language, question, answer) 三元组:zh-CN 恒有,ja/en 有译文才插。
        variants = [("zh-CN", faq["q"], faq["a"])]
        for lang in ("ja", "en"):
            loc = GUIDE_FAQ_I18N.get(faq["q"], {}).get(lang)
            if loc and loc.get("q") and loc.get("a"):
                variants.append((lang, loc["q"], loc["a"]))
        for lang, question, answer in variants:
            exists = conn.execute(
                "SELECT id FROM guide_faq WHERE question = ? AND country = ? AND language = ?",
                (question, country, lang),
            ).fetchone()
            if exists:
                continue
            conn.execute(
                "INSERT INTO guide_faq (id, question, answer, category_key, country, language, sort_order, status, created_at, updated_at) "
                "VALUES (?, ?, ?, ?, ?, ?, ?, 'published', ?, ?)",
                (str(uuid.uuid4()), question, answer, cat, country, lang, faq_order, now, now),
            )
            result["faq"] += 1

    # --- articles ---
    art_order = 0
    for art in GUIDE_ARTICLE_SEED:
        art_order += 1
        exists = conn.execute(
            "SELECT id FROM guide_articles WHERE slug = ? AND country = ?", (art["slug"], country)
        ).fetchone()
        if exists:
            continue
        # 信任字段:政策类文章带官方 source_url + 90 天复核窗口,其余原创整理 180 天。
        src_url, src_label, verified_at, stale_days = guide_article_source_meta(art["slug"])
        related_slugs = _guide_csv(guide_article_related_slugs(art["slug"]))
        conn.execute(
            "INSERT INTO guide_articles (id, title, slug, summary, body, category_key, sub_category_key, "
            "content_type, country, city, language, cover_image, seo_title, seo_description, tags, related_article_slugs, "
            "author_type, author_name, is_featured, "
            "is_free, is_paid, status, source_url, source_label, verified_at, stale_after_days, "
            "view_count, save_count, sort_order, created_at, updated_at, published_at) "
            "VALUES (?, ?, ?, ?, ?, ?, ?, 'guide', ?, '', 'zh-CN', '', ?, ?, ?, ?, 'editorial', ?, ?, 1, 0, 'published', ?, ?, ?, ?, 0, 0, ?, ?, ?, ?)",
            (str(uuid.uuid4()), art["title"], art["slug"], art.get("summary", ""), art.get("body", ""),
             art["category"], art.get("sub", ""), country, art.get("seo_title", art["title"]),
             art.get("seo_description", art.get("summary", "")), ",".join(art.get("tags", [])), related_slugs,
             art.get("author", "Machi 日本指南编辑部"), 1 if art.get("featured") else 0,
             src_url, src_label, verified_at, stale_days,
             art_order, now, now, now),
        )
        result["articles"] += 1
    conn.execute(
        "UPDATE guide_articles SET seo_title = title WHERE country = ? AND (seo_title IS NULL OR seo_title = '')",
        (country,),
    )
    conn.execute(
        "UPDATE guide_articles SET seo_description = summary WHERE country = ? AND (seo_description IS NULL OR seo_description = '')",
        (country,),
    )

    # --- products ---
    prod_order = 0
    for prod in GUIDE_PRODUCT_SEED:
        prod_order += 1
        exists = conn.execute(
            "SELECT id FROM guide_products WHERE slug = ? AND country = ?", (prod["slug"], country)
        ).fetchone()
        if exists:
            continue
        is_free = int(prod.get("is_free", 0))
        coming = 0 if is_free else (1 if prod.get("coming_soon", True) else 0)
        status = "coming_soon" if coming else "published"
        is_paid = 0 if is_free else 1
        row = {
            "id": str(uuid.uuid4()),
            "title": prod["title"], "slug": prod["slug"], "subtitle": prod.get("subtitle", ""),
            "description": prod.get("description", ""), "category_key": prod["category"],
            "sub_category_key": prod.get("sub", ""), "product_type": prod["product_type"],
            "price": int(prod.get("price", 0)), "currency": prod.get("currency", "CNY"),
            "price_label": prod.get("price_label", ""), "cover_image": prod.get("cover_image", ""),
            "tags": _guide_csv(prod.get("tags", [])), "target_audience": prod.get("target", ""),
            "delivery_method": prod.get("delivery", ""), "preview_content": prod.get("preview", ""),
            "purchase_content": prod.get("purchase", ""), "file_url": prod.get("file_url", ""),
            "file_name": prod.get("file_name", ""), "file_type": prod.get("file_type", ""),
            "file_size": int(prod.get("file_size", 0)), "country": country, "language": "zh-CN",
            "is_digital": 0 if prod.get("is_service") else 1, "is_service": int(prod.get("is_service", 0)),
            "is_free": is_free, "is_paid": is_paid,
            "is_member_included": 1 if prod.get("member_included") and not prod.get("is_service") else 0,
            "is_member_discount": 1 if prod.get("member_discount") else 0,
            "member_price": int(prod.get("member_price", 0) or 0),
            "is_coming_soon": coming, "status": status, "purchase_count": 0, "rating": 0,
            "sort_order": prod_order, "is_featured": int(prod.get("is_featured", 0)),
            "refund_policy": prod.get("refund_policy", ""), "notes": prod.get("notes", ""),
            "created_at": now, "updated_at": now, "published_at": now if status == "published" else None,
        }
        conn.execute(
            f"INSERT INTO guide_products ({', '.join(row.keys())}) VALUES ({', '.join(['?'] * len(row))})",
            tuple(row.values()),
        )
        result["products"] += 1

    # --- schools (example starter database, source-backed fields only) ---
    for idx, school in enumerate(GUIDE_SCHOOL_SEED, start=1):
        exists = conn.execute(
            "SELECT id FROM guide_schools WHERE slug = ? AND country = ?", (school["slug"], country)
        ).fetchone()
        source_url = school.get("source_url") or school.get("international_admission_url") or school.get("website", "")
        source_type = school.get("source_type") or ("official" if school.get("website") else "public_reference")
        source_name = school.get("source_name") or school.get("school_name_en") or school["school_name"]
        verification_status = school.get("verification_status") or "needs_review"
        international_admission_url = school.get("international_admission_url") or school.get("admission_url") or school.get("website", "")
        school_fields = school.get("fields_of_study", [])
        school_tags = school.get("tags") or [
            school.get("school_type", ""),
            school.get("prefecture", ""),
            school.get("city", ""),
            *school_fields,
        ]
        accepts_international = _guide_payload_bool(
            school, "is_accepting_international_students", default=1 if international_admission_url else -1
        )
        has_english_program = _guide_payload_bool(school, "has_english_program", default=-1)
        has_japanese_program = _guide_payload_bool(school, "has_japanese_program", default=-1)
        has_scholarship = _guide_payload_bool(school, "has_scholarship", default=-1)
        has_dormitory = _guide_payload_bool(school, "has_dormitory", default=-1)
        has_career_support = _guide_payload_bool(school, "has_career_support", default=-1)
        has_language_support = _guide_payload_bool(school, "has_language_support", default=-1)
        short = school.get("short_description") or "示例学校档案，后续由管理员根据官方资料继续补充申请信息。"
        desc = school.get("description") or (
            f"{school['school_name']} 的基础资料档案。当前仅录入学校名称、类型、地区和官方链接；"
            "详细申请要求请以学校官网与招生简章为准。"
        )
        if exists:
            conn.execute(
                "UPDATE guide_schools SET school_name = ?, school_name_jp = ?, school_name_en = ?, school_type = ?, "
                "prefecture = ?, city = ?, website = ?, international_admission_url = ?, short_description = ?, "
                "description = ?, is_accepting_international_students = ?, has_english_program = ?, has_japanese_program = ?, "
                "has_scholarship = ?, has_dormitory = ?, has_career_support = ?, has_language_support = ?, application_periods = ?, "
                "admission_months = ?, required_japanese_level = ?, required_english_level = ?, fields_of_study = ?, tags = ?, "
                "source_type = ?, source_name = ?, source_url = ?, verification_status = ?, data_quality_score = ?, "
                "is_featured = ?, updated_at = ? WHERE id = ?",
                (school["school_name"], school.get("school_name_jp", ""), school.get("school_name_en", ""),
                 school.get("school_type", "other"), school.get("prefecture", ""), school.get("city", ""),
                 school.get("website", ""), international_admission_url, short, desc,
                 accepts_international, has_english_program, has_japanese_program, has_scholarship, has_dormitory,
                 has_career_support, has_language_support, school.get("application_periods", ""),
                 school.get("admission_months", ""), school.get("required_japanese_level", "unknown"),
                 school.get("required_english_level", "unknown"), _guide_csv(school_fields), _guide_csv(school_tags),
                 source_type, source_name, source_url, verification_status, _guide_school_quality(school),
                 int(school.get("is_featured", 0)), now, exists["id"]),
            )
            continue
        conn.execute(
            "INSERT INTO guide_schools (id, slug, school_name, school_name_jp, school_name_en, school_type, country, "
            "prefecture, city, website, international_admission_url, description, short_description, "
            "is_accepting_international_students, has_english_program, has_japanese_program, has_scholarship, "
            "has_dormitory, has_career_support, has_language_support, tuition_min, tuition_max, currency, "
            "application_periods, admission_months, required_japanese_level, required_english_level, fields_of_study, tags, "
            "source_type, source_name, source_url, verification_status, data_quality_score, is_featured, status, created_at, updated_at) "
            "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 0, 0, 'JPY', ?, ?, ?, ?, ?, ?, "
            "?, ?, ?, ?, ?, ?, 'published', ?, ?)",
            (str(uuid.uuid4()), school["slug"], school["school_name"], school.get("school_name_jp", ""),
             school.get("school_name_en", ""), school.get("school_type", "other"), country,
             school.get("prefecture", ""), school.get("city", ""), school.get("website", ""),
             international_admission_url, desc, short,
             accepts_international, has_english_program, has_japanese_program, has_scholarship, has_dormitory,
             has_career_support, has_language_support, school.get("application_periods", ""),
             school.get("admission_months", ""), school.get("required_japanese_level", "unknown"),
             school.get("required_english_level", "unknown"), _guide_csv(school_fields), _guide_csv(school_tags),
             source_type, source_name, source_url, verification_status, _guide_school_quality(school),
             int(school.get("is_featured", 0)), now, now),
        )
        result["schools"] += 1

    # --- companies (public factual metadata only; scores stay 0 / no fake reviews) ---
    for comp in GUIDE_COMPANY_SEED:
        exists = conn.execute(
            "SELECT id FROM guide_companies WHERE slug = ? AND country = ?", (comp["slug"], country)
        ).fetchone()
        comp_tags = comp.get("tags", [])
        comp_employment = comp.get("employment_types") or (["new_graduate", "mid_career"] if comp.get("career_url") else [])
        is_foreigner_friendly = _guide_payload_bool(comp, "is_foreigner_friendly", default=-1)
        accepts_foreign = _guide_payload_bool(comp, "accepts_foreign_applicants", default=-1)
        supports_work_visa = _guide_payload_bool(comp, "supports_work_visa", default=-1)
        supports_new_graduate = _guide_payload_bool(comp, "supports_new_graduate", default=1 if "new_graduate" in comp_employment else -1)
        supports_mid_career = _guide_payload_bool(comp, "supports_mid_career", default=1 if "mid_career" in comp_employment else -1)
        has_english_positions = _guide_payload_bool(comp, "has_english_positions", default=-1)
        has_global_roles = _guide_payload_bool(comp, "has_global_roles", default=-1)
        has_foreign_employees = _guide_payload_bool(comp, "has_foreign_employees", default=-1)
        if exists:
            source_url = comp.get("source_url") or comp.get("career_url") or comp.get("website", "")
            source_type = comp.get("source_type") or ("official" if comp.get("website") else "public_reference")
            source_name = comp.get("source_name") or comp.get("name_en") or comp["name"]
            verification_status = comp.get("verification_status") or "needs_review"
            conn.execute(
                "UPDATE guide_companies SET company_name = ?, company_name_jp = ?, company_name_en = ?, industry = ?, "
                "country = ?, prefecture = ?, city = ?, website = ?, career_url = ?, size = ?, company_size = ?, "
                "founded_year = ?, short_description = ?, description = ?, source_type = ?, source_name = ?, "
                "source_url = ?, verification_status = ?, data_quality_score = ?, is_featured = ?, is_foreigner_friendly = ?, "
                "accepts_foreign_applicants = ?, supports_work_visa = ?, supports_new_graduate = ?, supports_mid_career = ?, "
                "has_english_positions = ?, has_global_roles = ?, has_foreign_employees = ?, japanese_level_required = ?, "
                "english_level_required = ?, employment_types = ?, tags = ?, updated_at = ? WHERE id = ?",
                (comp["name"], comp.get("name_jp", ""), comp.get("name_en", ""), comp.get("industry", ""),
                 country, comp.get("prefecture", ""), comp.get("city", ""), comp.get("website", ""),
                 comp.get("career_url", ""), comp.get("company_size", comp.get("size", "")),
                 comp.get("company_size", comp.get("size", "")), int(comp.get("founded", 0)),
                 comp.get("short_description", "示例公司档案，评分与评论需等待真实用户提交并审核。"),
                 comp.get("description", "公开基础信息档案。公司详情、招聘岗位和制度请以公司官网与招聘页面为准。"),
                 source_type, source_name, source_url, verification_status, _guide_company_quality(comp),
                 int(comp.get("is_featured", 0)), is_foreigner_friendly, accepts_foreign, supports_work_visa,
                 supports_new_graduate, supports_mid_career, has_english_positions, has_global_roles,
                 has_foreign_employees, comp.get("japanese_level_required", "unknown"),
                 comp.get("english_level_required", "unknown"), _guide_csv(comp_employment), _guide_csv(comp_tags),
                 now, exists["id"]),
            )
            continue
        source_url = comp.get("source_url") or comp.get("career_url") or comp.get("website", "")
        source_type = comp.get("source_type") or ("official" if comp.get("website") else "public_reference")
        source_name = comp.get("source_name") or comp.get("name_en") or comp["name"]
        verification_status = comp.get("verification_status") or "needs_review"
        conn.execute(
            "INSERT INTO guide_companies (id, company_name, company_name_jp, company_name_en, slug, industry, country, "
            "prefecture, city, website, career_url, size, company_size, founded_year, short_description, description, "
            "is_foreigner_friendly, accepts_foreign_applicants, supports_work_visa, has_english_positions, "
            "supports_new_graduate, supports_mid_career, has_global_roles, has_foreign_employees, "
            "japanese_level_required, english_level_required, employment_types, tags, "
            "foreigner_friendly_score, visa_support_score, interview_difficulty_score, overtime_score, "
            "salary_benefit_score, work_life_balance_score, career_growth_score, review_count, interview_review_count, "
            "source_type, source_name, source_url, verification_status, data_quality_score, is_featured, status, created_at, updated_at) "
            "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 0, 0, 0, 0, 0, 0, 0, 0, 0, "
            "?, ?, ?, ?, ?, ?, 'published', ?, ?)",
            (str(uuid.uuid4()), comp["name"], comp.get("name_jp", ""), comp.get("name_en", ""), comp["slug"],
             comp.get("industry", ""), country, comp.get("prefecture", ""), comp.get("city", ""),
             comp.get("website", ""), comp.get("career_url", ""), comp.get("company_size", comp.get("size", "")),
             comp.get("company_size", comp.get("size", "")), int(comp.get("founded", 0)),
             comp.get("short_description", "示例公司档案，评分与评论需等待真实用户提交并审核。"),
             comp.get("description", "公开基础信息档案。公司详情、招聘岗位和制度请以公司官网与招聘页面为准。"),
             is_foreigner_friendly, accepts_foreign, supports_work_visa, has_english_positions,
             supports_new_graduate, supports_mid_career, has_global_roles, has_foreign_employees,
             comp.get("japanese_level_required", "unknown"), comp.get("english_level_required", "unknown"),
             _guide_csv(comp_employment), _guide_csv(comp_tags),
             source_type, source_name, source_url, verification_status, _guide_company_quality(comp),
             int(comp.get("is_featured", 0)), now, now),
        )
        result["companies"] += 1

    # --- journeys + steps (situation -> ordered action path) ---
    result["journeys"] = 0
    result["journeySteps"] = 0
    for journey in GUIDE_JOURNEY_SEED:
        jkey = journey["key"]
        exists = conn.execute(
            "SELECT id FROM guide_journeys WHERE journey_key = ? AND country = ? AND language = 'zh-CN'",
            (jkey, country),
        ).fetchone()
        if not exists:
            conn.execute(
                "INSERT INTO guide_journeys (id, journey_key, country, language, title, subtitle, audience, icon, color, "
                "hero_title, hero_subtitle, estimated_days, sort_order, status, created_at, updated_at) "
                "VALUES (?, ?, ?, 'zh-CN', ?, ?, ?, ?, ?, ?, ?, ?, ?, 'published', ?, ?)",
                (
                    str(uuid.uuid4()), jkey, country, journey["title"], journey.get("subtitle", ""),
                    journey.get("audience", ""), journey.get("icon", ""), journey.get("color", ""),
                    journey.get("heroTitle", ""), journey.get("heroSubtitle", ""),
                    _guide_int(journey.get("estimatedDays"), 0), _guide_int(journey.get("sortOrder"), 0), now, now,
                ),
            )
            result["journeys"] += 1
        step_order = 0
        for step in journey.get("steps", []):
            step_order += 1
            step_exists = conn.execute(
                "SELECT id FROM guide_journey_steps WHERE journey_key = ? AND step_key = ? AND country = ? AND language = 'zh-CN'",
                (jkey, step["key"], country),
            ).fetchone()
            if step_exists:
                # Step already seeded — refresh only the curated article_slugs
                # (spec P2: step-precise reading) so re-seed pushes the editorial
                # links to existing rows without clobbering other admin edits.
                seed_article_slugs = _guide_csv(step.get("articleSlugs", []))
                if seed_article_slugs:
                    conn.execute(
                        "UPDATE guide_journey_steps SET article_slugs = ?, updated_at = ? WHERE id = ?",
                        (seed_article_slugs, now, step_exists["id"]),
                    )
                continue
            conn.execute(
                "INSERT INTO guide_journey_steps (id, journey_key, step_key, country, language, title, summary, body, "
                "action_label, action_type, action_target, category_key, article_slugs, product_slugs, school_filters, "
                "company_filters, required, estimated_minutes, deadline_hint, sort_order, status, created_at, updated_at) "
                "VALUES (?, ?, ?, ?, 'zh-CN', ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'published', ?, ?)",
                (
                    str(uuid.uuid4()), jkey, step["key"], country, step["title"], step.get("summary", ""),
                    step.get("body", ""), step.get("actionLabel", ""), step.get("actionType", ""),
                    step.get("actionTarget", ""), step.get("categoryKey", journey.get("categoryKey", "")),
                    _guide_csv(step.get("articleSlugs", [])), _guide_csv(step.get("productSlugs", [])),
                    json.dumps(step.get("schoolFilters") or {}, ensure_ascii=False),
                    json.dumps(step.get("companyFilters") or {}, ensure_ascii=False),
                    1 if step.get("required", True) else 0, _guide_int(step.get("estimatedMinutes"), 0),
                    step.get("deadlineHint", ""), step_order, now, now,
                ),
            )
            result["journeySteps"] += 1

    result["planTemplates"] = _guide_seed_plan_templates(conn)
    result["productRelations"] = _guide_seed_product_relations(conn)

    # --- B4 幂等回填:线上库已有行不会被上面的 INSERT 更新,这里对现有行做一次性
    # 幂等 UPDATE(每次启动都跑,只改仍为空/仍需迁移的行,重复运行无副作用)。 ---
    _guide_backfill_existing_rows(conn, country)
    return result


def _guide_backfill_existing_rows(conn: sqlite3.Connection, country: str) -> None:
    """对已存在的 guide_articles / guide_products 行做 B4 幂等回填:
    ① 信任字段(verified_at/source_label/source_url/stale_after_days)
    ② 孤儿子分类归位  ③ related_article_slugs  ④ 资料币种 CNY→JPY。
    全部用参数化 UPDATE,PG/SQLite 双方言安全;仅命中需要修的行。"""
    # ① 信任字段:先给所有 author_type='editorial' 且 verified_at 为空的行铺默认
    # (label + 发布日 + 默认 180 天),再按 source-meta 覆盖政策类文章的 url/stale。
    conn.execute(
        "UPDATE guide_articles SET source_label = ?, verified_at = ?, stale_after_days = ? "
        "WHERE country = ? AND author_type = 'editorial' AND (verified_at IS NULL OR verified_at = '')",
        (GUIDE_ARTICLE_SOURCE_LABEL, GUIDE_ARTICLE_SEED_VERIFIED_AT, 180, country),
    )
    for art in GUIDE_ARTICLE_SEED:
        src_url, src_label, verified_at, stale_days = guide_article_source_meta(art["slug"])
        # 只对政策类(有 source_url 或非默认 stale)且当前还没填 source_url 的行覆盖,
        # 避免反复覆写管理员后台手动改过的值。
        if not src_url and stale_days == 180:
            continue
        conn.execute(
            "UPDATE guide_articles SET source_url = ?, source_label = ?, stale_after_days = ? "
            "WHERE country = ? AND slug = ? AND author_type = 'editorial' "
            "AND (source_url IS NULL OR source_url = '')",
            (src_url, src_label, stale_days, country, art["slug"]),
        )

    # ①b B5 旗舰文章正文升级:种子只插不改,所以线上已存在的这 12 篇不会被上面的
    # INSERT 更新。这里对它们做一次幂等 body/summary/verified_at 升级。安全条件:
    # 只更新「正文仍为种子时代原文」的行——用旧正文前 64 字符做指纹(SUBSTR 在
    # SQLite/PG 都按字符计,双方言一致);不匹配说明管理员在后台手改过正文,跳过
    # 并记日志,绝不覆盖人工内容。SET 已升级则命中 0 行(幂等),重复启动无副作用。
    _flagship_now = now_iso()
    for slug, old_prefix, new_body, new_summary, verified_at in guide_flagship_upgrade_rows():
        cur = conn.execute(
            "UPDATE guide_articles SET body = ?, summary = ?, verified_at = ?, updated_at = ? "
            "WHERE country = ? AND slug = ? AND author_type = 'editorial' "
            "AND SUBSTR(body, 1, ?) = ?",
            (new_body, new_summary, verified_at, _flagship_now,
             country, slug, len(old_prefix), old_prefix),
        )
        # rowcount==0 既可能是「已升级过」(幂等再跑),也可能是「正文被手改/不存在」。
        # 只在确实存在该 slug 且正文既不是旧指纹、也不是新正文时,才判定为人工改动并记日志。
        if getattr(cur, "rowcount", -1) == 0:
            row = conn.execute(
                "SELECT SUBSTR(body, 1, ?) AS head FROM guide_articles "
                "WHERE country = ? AND slug = ? AND author_type = 'editorial'",
                (len(old_prefix), country, slug),
            ).fetchone()
            if row is not None and row["head"] != old_prefix and row["head"] != new_body[:len(old_prefix)]:
                ACCESS_LOG.info(
                    "guide flagship upgrade skipped (admin-edited body) country=%s slug=%s",
                    country, slug,
                )

    # ② 孤儿子分类归位:线上行 sub_category_key 若仍是旧的孤儿键,改成规范子分类。
    _orphan_sub_remap = {
        ("life_japan", "housing"): "renting", ("life_japan", "banking"): "bank_account",
        ("life_japan", "bank_account_japan"): "bank_account", ("life_japan", "mobile_internet"): "mobile_sim",
        ("life_japan", "mobile_plan_japan"): "mobile_sim", ("life_japan", "points_and_switching"): "mobile_sim",
        ("life_japan", "daily_life"): "life_tips", ("life_japan", "safety"): "life_tips",
        ("life_japan", "driving"): "transportation", ("life_japan", "national_health_insurance"): "health_insurance",
        ("life_japan", "national_pension"): "pension", ("career_japan", "job_change"): "job_hunting_flow",
        ("career_japan", "new_grad"): "job_hunting_flow", ("career_japan", "job_offer"): "job_hunting_flow",
        ("career_japan", "it_career"): "industry_guides", ("career_japan", "interview"): "job_interview",
        ("career_japan", "visa"): "work_visa", ("study_japan", "interview"): "admission_interview",
        ("study_abroad_japan", "visa"): "student_visa", ("jlpt", "n1"): "jlpt_n1",
    }
    for (cat, old_sub), new_sub in _orphan_sub_remap.items():
        conn.execute(
            "UPDATE guide_articles SET sub_category_key = ? "
            "WHERE country = ? AND category_key = ? AND sub_category_key = ?",
            (new_sub, country, cat, old_sub),
        )

    # ③ related_article_slugs:仅对当前为空的行回填种子关联。
    for art in GUIDE_ARTICLE_SEED:
        related = _guide_csv(guide_article_related_slugs(art["slug"]))
        if not related:
            continue
        conn.execute(
            "UPDATE guide_articles SET related_article_slugs = ? "
            "WHERE country = ? AND slug = ? AND (related_article_slugs IS NULL OR related_article_slugs = '')",
            (related, country, art["slug"]),
        )

    # ④ 资料币种 JPY:仅对仍是 CNY 的行,按 seed 里对应 slug 的新价/币种/标签回写。
    for prod in GUIDE_PRODUCT_SEED:
        if prod.get("currency") != "JPY":
            continue
        conn.execute(
            "UPDATE guide_products SET currency = 'JPY', price = ?, price_label = ?, member_price = ? "
            "WHERE country = ? AND slug = ? AND currency = 'CNY'",
            (int(prod.get("price", 0)), prod.get("price_label", ""),
             int(prod.get("member_price", 0) or 0), country, prod["slug"]),
        )


def _guide_upsert_category(conn: sqlite3.Connection, key: str, parent_key: str, title: str, subtitle: str,
                           description: str, icon: str, color: str, country: str, sort_order: int,
                           now: str, result: dict[str, int]) -> None:
    existing = conn.execute(
        "SELECT id FROM guide_categories WHERE key = ? AND country = ?", (key, country)
    ).fetchone()
    if existing:
        conn.execute(
            "UPDATE guide_categories SET parent_key = ?, title = ?, subtitle = ?, description = ?, icon = ?, "
            "color = ?, sort_order = ?, is_active = 1, updated_at = ? WHERE id = ?",
            (parent_key, title, subtitle, description, icon, color, sort_order, now, existing["id"]),
        )
        return
    conn.execute(
        "INSERT INTO guide_categories (id, key, parent_key, title, subtitle, description, icon, color, country, "
        "language, sort_order, is_active, created_at, updated_at) "
        "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 'zh-CN', ?, 1, ?, ?)",
        (str(uuid.uuid4()), key, parent_key, title, subtitle, description, icon, color, country, sort_order, now, now),
    )
    result["categories"] += 1


def ensure_city_listing_seed(conn: sqlite3.Connection) -> None:
    """Seed a compact public listing set for local verification.

    The seed is idempotent and fills missing starter channels in development.
    It never migrates old posts into listings automatically because
    moderation/state for classifieds must be explicit. In production, preserve
    the historical behavior: seed only when the structured table is empty.
    """
    try:
        existing = conn.execute("SELECT COUNT(*) AS c FROM city_listings").fetchone()["c"]
    except sqlite3.OperationalError:
        return
    if PRODUCTION and int(existing or 0) > 0:
        return
    seller = conn.execute("SELECT * FROM users WHERE handle = 'kaizi' LIMIT 1").fetchone()
    if not seller:
        seller = conn.execute("SELECT * FROM users ORDER BY created_at ASC LIMIT 1").fetchone()
    if not seller:
        return
    seller_id = seller["id"]
    now = now_iso()

