def user_social_counts(conn: sqlite3.Connection, user_id: str) -> dict[str, int]:
    """Real follower/following/post counts for one user.

    serialize_user only passes counts through when the caller's row already
    carries them; every "current user" endpoint that skipped this returned
    hard zeros, which clients then cached over the real values (the
    follower-count-randomly-resets-to-0 bug). Single-user payloads must
    always attach these.
    """
    followers = conn.execute(
        "SELECT COUNT(*) AS c FROM follows WHERE following_id = ?", (user_id,)
    ).fetchone()["c"]
    following = conn.execute(
        "SELECT COUNT(*) AS c FROM follows WHERE follower_id = ?", (user_id,)
    ).fetchone()["c"]
    posts_count = conn.execute(
        "SELECT COUNT(*) AS c FROM posts WHERE author_id = ? AND deleted_at IS NULL AND status IN ('published', 'active')",
        (user_id,),
    ).fetchone()["c"]
    return {
        "follower_count": int(followers), "followerCount": int(followers),
        "following_count": int(following), "followingCount": int(following),
        "post_count": int(posts_count), "postCount": int(posts_count),
    }


def user_listing_counts(conn: sqlite3.Connection, user_id: str) -> dict[str, int]:
    """Published city-listing counts per type for one seller (二手/租房/招聘/服务…),
    powering the profile's tappable count tags ("出售二手 5" → that user's items)."""
    if not user_id:
        return {}
    placeholders = ",".join(["?"] * len(PUBLIC_LISTING_STATUSES))
    rows = conn.execute(
        f"""
        SELECT type, COUNT(*) AS c FROM city_listings
         WHERE seller_user_id = ? AND deleted_at IS NULL AND status IN ({placeholders})
         GROUP BY type
        """,
        (user_id, *PUBLIC_LISTING_STATUSES),
    ).fetchall()
    return {str(dict(r)["type"]): int(dict(r)["c"]) for r in rows if int(dict(r)["c"]) > 0}


def serialize_user_with_counts(conn: sqlite3.Connection, row: dict[str, Any]) -> dict[str, Any]:
    payload = serialize_user(row)
    uid = str(dict(row).get("id") or "")
    payload.update(user_social_counts(conn, uid))
    counts = user_listing_counts(conn, uid)
    payload["listing_counts"] = counts
    payload["listingCounts"] = counts
    return payload


def serialize_post(row: dict[str, Any], extras: dict[str, Any] | None = None) -> dict[str, Any]:
    extras = extras or {}
    like_count = int(extras.get("like_count") or 0)
    repost_count = int(extras.get("repost_count") or 0)
    bookmark_count = int(extras.get("bookmark_count") or 0)
    comment_count = int(extras.get("comment_count") or 0)
    view_count = int(row.get("view_count") or 0)
    report_count = int(row.get("report_count") or 0)
    heat = int(round(
        like_count
        + comment_count * 3
        + repost_count * 5
        + bookmark_count * 4
        - report_count * 10
        + _active_boost(row)
        + _time_decay(row.get("created_at")),
    ))
    media = extras.get("media") or []
    content_type = row.get("content_type", "") or "dynamic"
    attributes = decode_post_attributes(row.get("attributes"))
    viewer = extras.get("viewer") if isinstance(extras.get("viewer"), dict) else None
    viewer_id = (viewer or {}).get("id")
    can_manage = bool(viewer_id and viewer_id == row.get("author_id") and not row.get("deleted_at"))
    is_anonymous = content_type == "anonymous" or attributes.get("anonymous") is True
    public_author_id = row["author_id"] if not is_anonymous or can_manage else ""
    public_author = extras.get("author")
    if is_anonymous and not can_manage:
        public_author = {
            "id": "anonymous",
            "remote_id": "anonymous",
            "handle": "anonymous",
            "username": "anonymous",
            "display_name": "匿名用户",
            "displayName": "匿名用户",
            "bio": "",
            "location": "",
            "avatar_symbol": "person.fill",
            "avatar_color": "slate",
            "avatar_url": "",
            "avatarUrl": "",
            "cover_url": "",
            "membership_tier": "free",
            "is_verified": False,
            "is_verified_member": False,
            "isOfficial": False,
            "is_official": False,
            "role": "anonymous",
            "country": "",
            "province": "",
            "city": "",
            "current_region_code": "",
            "recent_region_codes": [],
            "follower_count": 0,
            "following_count": 0,
            "post_count": 0,
            "can_message": False,
            "canMessage": False,
        }
    payload = {
        "id": row["id"],
        "remote_id": row["id"],
        "author_id": public_author_id,
        "content": row["content"],
        "created_at": row["created_at"],
        "createdAt": row["created_at"],
        "updated_at": row["updated_at"],
        "updatedAt": row["updated_at"],
        # last_activity_at = own creation OR latest live comment. The 正在发生 radar
        # revives older posts on it; the client renders "N 分钟前有新讨论" when it's
        # newer than created_at. Falls back to created_at so it's never null.
        "last_activity_at": row.get("last_activity_at") or row.get("created_at") or "",
        "lastActivityAt": row.get("last_activity_at") or row.get("created_at") or "",
        "deleted_at": row.get("deleted_at"),
        "repost_of_id": row.get("repost_of_id"),
        "view_count": view_count,
        "viewCount": view_count,
        "like_count": like_count,
        "likeCount": like_count,
        "repost_count": repost_count,
        "repostCount": repost_count,
        "bookmark_count": bookmark_count,
        "bookmarkCount": bookmark_count,
        "save_count": bookmark_count,
        "saveCount": bookmark_count,
        "comment_count": comment_count,
        "commentCount": comment_count,
        "share_count": 0,
        "shareCount": 0,
        "heat_score": heat,
        "heatScore": heat,
        "report_count": report_count,
        "is_boosted": bool(row.get("is_boosted", 0)),
        "boost_weight": int(row.get("boost_weight") or 0),
        "boosted_until": row.get("boosted_until", "") or "",
        "liked": bool(extras.get("liked")),
        "isLiked": bool(extras.get("liked")),
        "bookmarked": bool(extras.get("bookmarked")),
        "saved": bool(extras.get("bookmarked")),
        "isSaved": bool(extras.get("bookmarked")),
        "meetupGoing": int(extras.get("meetup_going") or 0),
        "meetup_going": int(extras.get("meetup_going") or 0),
        "meetupJoined": bool(extras.get("meetup_joined")),
        "meetup_joined": bool(extras.get("meetup_joined")),
        "reposted": bool(extras.get("reposted")),
        "isReposted": bool(extras.get("reposted")),
        "canEdit": can_manage,
        "can_edit": can_manage,
        "canDelete": can_manage,
        "can_delete": can_manage,
        "canInteract": bool(extras.get("can_interact")),
        "can_interact": bool(extras.get("can_interact")),
        "viewer": extras.get("viewer"),
        "tags": extras.get("tags") or [],
        "media": media,
        "images": [m.get("url", "") for m in media if m.get("type") == "image" and m.get("url")],
        "videoUrl": next((m.get("url", "") for m in media if m.get("type") == "video" and m.get("url")), ""),
        "video_url": next((m.get("url", "") for m in media if m.get("type") == "video" and m.get("url")), ""),
        "author": public_author,
        "original_post": extras.get("original_post"),
        "status": row.get("status", "published"),
        # Region (phase 1). Empty strings when the post predates the
        # region pivot or the author didn't pick a city.
        "country":     row.get("country", "") or "",
        "province":    row.get("province", "") or "",
        "city":        row.get("city", "") or "",
        "region_code": row.get("region_code", "") or "",
        "cityPath": row.get("region_code", "") or "",
        "city_path": row.get("region_code", "") or "",
        # Content type discriminator + typed attributes (phase 2).
        # `content_type` defaults to 'dynamic' for posts created before
        # this column existed; `attributes` is a decoded dict (already
        # validated against the per-type schema on write).
        "content_type": content_type,
        "contentType": content_type,
        "category": content_type,
        "attributes": attributes,
        "isAnonymous": is_anonymous,
        "is_anonymous": is_anonymous,
        "requiresMembership": requires_verified_membership(content_type),
        "requires_membership": requires_verified_membership(content_type),
        "sourceType": "city_seed" if bool(row.get("is_seed_content", 0)) else "user",
        "source_type": "city_seed" if bool(row.get("is_seed_content", 0)) else "user",
        # City Seed Bot (城市内容助手). When true the client renders an official
        # identity + a light "城市助手/编辑部" chip and an official avatar — never
        # a real-person identity. `seed_author_type` is one of the official
        # assistant/editorial desk identities managed by ensure_seed_bot_account().
        "is_seed_content": bool(row.get("is_seed_content", 0)),
        "seed_author_type": row.get("generated_by", "") or "",
        "seed_source": row.get("seed_source", "") or "",
        "poll": extras.get("poll"),
    }
    return payload




def serialize_media(row: dict[str, Any]) -> dict[str, Any]:
    media = normalize_media_dto(row)
    media.update({
        "id": row["id"],
        "remote_id": row["id"],
        "remoteId": row["id"],
        "owner_id": row.get("owner_id") or "",
        "ownerId": row.get("owner_id") or "",
        "type": _media_type_from(row.get("mime") or "", row.get("type") or ""),
        "url": media["url"] or row.get("url", ""),
        "cdnUrl": media["cdnUrl"] or row.get("url", ""),
        "publicUrl": media["publicUrl"] or row.get("url", ""),
        "mime": row.get("mime") or "",
        "contentType": row.get("mime") or media.get("contentType") or "",
        "content_type": row.get("mime") or media.get("content_type") or "",
        "width": int(row.get("width") or 0),
        "height": int(row.get("height") or 0),
        "duration": float(row.get("duration") or 0),
        "durationSeconds": float(row.get("duration") or 0),
        "duration_seconds": float(row.get("duration") or 0),
        "byte_size": int(row.get("byte_size") or 0),
        "fileSize": int(row.get("byte_size") or 0),
        "file_size": int(row.get("byte_size") or 0),
        "created_at": row.get("created_at") or "",
        "createdAt": row.get("created_at") or "",
    })
    if media["type"] == "video" and media.get("thumb_url") == media.get("url"):
        media["thumb_url"] = ""
        media["thumbUrl"] = ""
        media["thumbnailUrl"] = ""
        media["thumbnail_url"] = ""
    return media


def canonical_post_media_type(media_type: str, mime: str, linked_type: str) -> str:
    """Prefer the stored object's MIME/type over legacy post-link defaults."""
    normalized_mime = (mime or "").lower()
    normalized_media = (media_type or "").lower()
    normalized_link = (linked_type or "").lower()
    if normalized_mime.startswith("video/") or normalized_media == "video":
        return "video"
    if normalized_mime.startswith("image/") or normalized_media == "image":
        return "image"
    return normalized_link or normalized_media or "file"
















