def _taxonomy_i18n(label: str) -> tuple[str, str]:
    """Return (label_ja, label_en) for a default taxonomy label, falling back
    to the Chinese label so a missing translation never blanks the column."""
    ja, en = _TAXONOMY_LABEL_I18N.get(label, (label, label))
    return ja or label, en or label


def ensure_listing_taxonomy_defaults(conn: sqlite3.Connection, listing_type: str) -> None:
    listing_type = normalize_listing_type(listing_type)
    conn.execute("""
        CREATE TABLE IF NOT EXISTS listing_taxonomy_meta (
            listing_type TEXT PRIMARY KEY,
            initialized_at TEXT NOT NULL
        )
    """)
    existing = conn.execute(
        "SELECT 1 FROM listing_taxonomy_categories WHERE listing_type = ? LIMIT 1",
        (listing_type,),
    ).fetchone()
    initialized = conn.execute(
        "SELECT 1 FROM listing_taxonomy_meta WHERE listing_type = ? LIMIT 1",
        (listing_type,),
    ).fetchone()
    if existing:
        if not initialized:
            conn.execute(
                "INSERT OR IGNORE INTO listing_taxonomy_meta (listing_type, initialized_at) VALUES (?, ?)",
                (listing_type, now_iso()),
            )
        return
    if initialized:
        return
    spec = LISTING_TAXONOMY_DEFAULTS.get(listing_type) or LISTING_TAXONOMY_DEFAULTS["secondhand"]
    now = now_iso()
    for idx, label in enumerate(spec.get("categories", [])):
        cat_ja, cat_en = _taxonomy_i18n(label)
        conn.execute(
            """
            INSERT OR IGNORE INTO listing_taxonomy_categories (
                id, listing_type, category_key, label, label_ja, label_en, sort_order, created_at, updated_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (str(uuid.uuid4()), listing_type, label, label, cat_ja, cat_en, idx * 10, now, now),
        )
    for idx, entry in enumerate(spec.get("fields", [])):
        category_key, field_key, label, field_kind, options, required, placeholder = entry
        field_ja, field_en = _taxonomy_i18n(label)
        conn.execute(
            """
            INSERT OR IGNORE INTO listing_taxonomy_fields (
                id, listing_type, category_key, field_key, label, label_ja, label_en, field_kind, options_json,
                required, placeholder, sort_order, created_at, updated_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                str(uuid.uuid4()), listing_type, category_key, field_key, label, field_ja, field_en, field_kind,
                json.dumps(options or [], ensure_ascii=False), 1 if required else 0,
                placeholder or "", idx * 10, now, now,
            ),
        )
    conn.execute(
        "INSERT OR IGNORE INTO listing_taxonomy_meta (listing_type, initialized_at) VALUES (?, ?)",
        (listing_type, now),
    )






def listing_taxonomy_payload(conn: sqlite3.Connection, listing_type: str, include_inactive: bool = False) -> dict[str, Any]:
    listing_type = normalize_listing_type(listing_type)
    ensure_listing_taxonomy_defaults(conn, listing_type)
    cat_where = "listing_type = ?" + ("" if include_inactive else " AND is_active = 1")
    field_where = "listing_type = ?" + ("" if include_inactive else " AND is_active = 1")
    categories = [
        serialize_listing_taxonomy_category(dict(r))
        for r in conn.execute(
            f"SELECT * FROM listing_taxonomy_categories WHERE {cat_where} ORDER BY sort_order ASC, label ASC",
            (listing_type,),
        )
    ]
    fields = [
        serialize_listing_taxonomy_field(dict(r))
        for r in conn.execute(
            f"SELECT * FROM listing_taxonomy_fields WHERE {field_where} ORDER BY category_key ASC, sort_order ASC, label ASC",
            (listing_type,),
        )
    ]
    return {"listing_type": listing_type, "listingType": listing_type, "categories": categories, "fields": fields}


def normalize_listing_promotion_type(value: Any, fallback: str = "top") -> str:
    raw = str(value or "").strip().lower()
    aliases = {
        "pinned": "top",
        "pin": "top",
        "boost": "featured",
        "homepage": "city_home",
        "city_home_recommend": "city_home",
        "category": "category_featured",
        "urgent": "urgent_hiring",
        "rental": "recommended_rental",
        "service": "recommended_service",
    }
    raw = aliases.get(raw, raw)
    return raw if raw in LISTING_PROMOTION_TYPES else fallback


def normalize_listing_verification_type(value: Any, fallback: str = "seller") -> str:
    raw = str(value or "").strip().lower()
    aliases = {
        "recruiter_verified": "recruiter",
        "rental": "rental_provider",
        "service": "service_provider",
        "merchant": "business",
    }
    raw = aliases.get(raw, raw)
    return raw if raw in LISTING_VERIFICATION_TYPES else fallback


def listing_value_type(value: Any) -> str:
    if isinstance(value, bool):
        return "bool"
    if isinstance(value, int) and not isinstance(value, bool):
        return "int"
    if isinstance(value, float):
        return "float"
    if isinstance(value, (list, dict)):
        return "json"
    return "string"


def listing_value_to_text(value: Any) -> str:
    if value is None:
        return ""
    if isinstance(value, bool):
        return "true" if value else "false"
    if isinstance(value, (int, float)):
        return str(value)
    if isinstance(value, (list, dict)):
        # Structured attributes (菜单 / 团购套餐). Serialize compactly; cap big
        # so a full restaurant menu survives but a payload can't run away.
        try:
            return json.dumps(value, ensure_ascii=False, separators=(",", ":"))[:16000]
        except Exception:
            return ""
    return str(value).strip()[:1000]


def listing_text_to_value(value: str, value_type: str) -> Any:
    if value_type == "bool":
        return str(value).lower() in {"1", "true", "yes", "y", "on"}
    if value_type == "int":
        try:
            return int(float(value))
        except Exception:
            return 0
    if value_type == "float":
        try:
            return float(value)
        except Exception:
            return 0.0
    if value_type == "json":
        try:
            return json.loads(value)
        except Exception:
            return None
    return value


def infer_service_vertical(category: Any, attrs: dict[str, Any]) -> str:
    category_text = str(category or "").strip()
    if category_text in SERVICE_VERTICAL_BY_CATEGORY:
        return SERVICE_VERTICAL_BY_CATEGORY[category_text]
    service_type = str(attrs.get("service_type") or "").strip()
    if service_type in SERVICE_VERTICAL_BY_CATEGORY:
        return SERVICE_VERTICAL_BY_CATEGORY[service_type]
    explicit = str(attrs.get("service_vertical") or "").strip()
    if explicit in SERVICE_VERTICAL_ATTRIBUTE_KEYS:
        return explicit
    if attrs.get("menu") or attrs.get("packages"):
        return "food_restaurant"
    if attrs.get("room_type") or attrs.get("max_guests") or attrs.get("check_in_time"):
        return "lodging"
    if attrs.get("airport_route") or attrs.get("vehicle_type") or attrs.get("flight_info_note"):
        return "airport_transfer"
    if attrs.get("document_type") or attrs.get("no_result_guarantee"):
        return "paperwork_translation"
    if attrs.get("property_size") or attrs.get("item_volume") or attrs.get("vehicle_staff"):
        return "moving_cleaning"
    if attrs.get("setup_type") or attrs.get("cannot_guarantee"):
        return "life_setup"
    if attrs.get("beauty_service") or attrs.get("medical_disclaimer"):
        return "beauty_health"
    if attrs.get("service_target"):
        return "pet_family"
    if attrs.get("required_materials") or attrs.get("delivery_time"):
        return "paperwork_translation"
    if attrs.get("ticket_type") and attrs.get("meeting_point"):
        return "day_tour" if attrs.get("pickup_service") else "attraction_ticket"
    return ""


def normalize_listing_attributes(listing_type: str, raw: Any, category: Any = "") -> dict[str, tuple[str, str]]:
    if not isinstance(raw, dict):
        return {}
    raw_attrs = dict(raw)
    allowed = LISTING_ATTRIBUTE_KEYS.get(listing_type, set())
    if listing_type == "local_service":
        vertical = infer_service_vertical(category, raw_attrs)
        if vertical:
            raw_attrs["service_vertical"] = vertical
            if not str(raw_attrs.get("service_type") or "").strip() and str(category or "").strip():
                raw_attrs["service_type"] = str(category or "").strip()
            allowed = SERVICE_VERTICAL_COMMON_ATTRS | SERVICE_VERTICAL_ATTRIBUTE_KEYS.get(vertical, set())
        else:
            allowed = SERVICE_VERTICAL_COMMON_ATTRS
    out: dict[str, tuple[str, str]] = {}
    for key, value in raw_attrs.items():
        k = str(key or "").strip()
        if not k or (allowed and k not in allowed):
            continue
        # menu / packages: web sends arrays; iOS sends a JSON string (its
        # attributes map is string-only). Parse the string back to a list so
        # both clients land the same structured json attribute.
        if k in {"menu", "packages"} and isinstance(value, str):
            stripped = value.strip()
            if stripped.startswith("["):
                try:
                    parsed = json.loads(stripped)
                    if isinstance(parsed, list):
                        value = parsed
                except Exception:
                    pass
        text = listing_value_to_text(value)
        if text == "":
            continue
        out[k] = (text, listing_value_type(value))
    return out


def public_listing_title(title: Any) -> str:
    text = str(title or "")
    return (
        text
        .replace("，外国人可咨询", "，可预约看房")
        .replace("外国人可咨询", "可预约看房")
        .replace("，外国人可", "")
        .replace("外国人可", "")
        .strip()
    )


def public_listing_attributes(listing_type: str, attrs: Any) -> dict[str, Any]:
    if not isinstance(attrs, dict):
        return {}
    # Drop internal markers (e.g. __content_pack, __partner, __partner_ext_id):
    # they are bookkeeping only and must never reach the client payload.
    cleaned = {k: v for k, v in attrs.items() if not str(k).startswith("__")}
    if listing_type == "rental":
        cleaned.pop("foreigners_allowed", None)
    return cleaned


