# ── listing reviews (local-service star ratings) ───────────────────────────
# One review per user per listing, upsert-able. Aggregates are denormalized
# onto city_listings (rating_avg / rating_count) so list pages never join.
LISTING_REVIEW_STATUSES: set[str] = {"published", "hidden", "deleted"}
# Star reviews only make sense where a merchant serves many customers; C2C
# verticals (secondhand/rental/job) keep the inquiry/reputation loop instead.
LISTING_REVIEWABLE_TYPES: set[str] = {"local_service", "discount", "event"}


def recompute_listing_rating(conn: sqlite3.Connection, listing_id: str) -> tuple[float, int]:
    row = conn.execute(
        "SELECT COUNT(*) AS c, COALESCE(AVG(rating), 0) AS a FROM listing_reviews WHERE listing_id = ? AND status = 'published'",
        (listing_id,),
    ).fetchone()
    count = int(row["c"] or 0)
    avg = round(float(row["a"] or 0), 2) if count else 0.0
    conn.execute(
        "UPDATE city_listings SET rating_avg = ?, rating_count = ? WHERE id = ?",
        (avg, count, listing_id),
    )
    return avg, count


def listing_review_histogram(conn: sqlite3.Connection, listing_id: str) -> dict[str, int]:
    histogram = {str(star): 0 for star in range(1, 6)}
    for row in conn.execute(
        "SELECT rating, COUNT(*) AS c FROM listing_reviews WHERE listing_id = ? AND status = 'published' GROUP BY rating",
        (listing_id,),
    ):
        star = str(int(row["rating"] or 0))
        if star in histogram:
            histogram[star] = int(row["c"] or 0)
    return histogram




def fetch_listing_reviews_with_authors(conn: sqlite3.Connection, rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    author_ids = list({r.get("user_id") for r in rows if r.get("user_id")})
    authors = fetch_users_by_ids(conn, author_ids)
    return [serialize_listing_review(r, authors.get(r.get("user_id", ""))) for r in rows]


def hydrate_listing_extras(conn: sqlite3.Connection, listing_ids: list[str], current_user_id: str | None) -> dict[str, dict[str, Any]]:
    if not listing_ids:
        return {}
    placeholders = ",".join("?" * len(listing_ids))
    extras: dict[str, dict[str, Any]] = {lid: {"media": [], "attributes": {}} for lid in listing_ids}
    for row in conn.execute(
        f"""
        SELECT
            lm.id AS lm_id,
            lm.listing_id,
            lm.media_type,
            lm.url AS lm_url,
            lm.thumbnail_url AS lm_thumbnail_url,
            lm.sort_order,
            lm.is_cover,
            lm.created_at AS lm_created_at,
            lm.uploaded_file_id,
            uf.id AS uf_id,
            uf.user_id AS uf_user_id,
            uf.object_key AS uf_object_key,
            uf.public_url AS uf_public_url,
            uf.cdn_url AS uf_cdn_url,
            uf.content_type AS uf_content_type,
            uf.file_size AS uf_file_size,
            uf.file_type AS uf_file_type,
            uf.purpose AS uf_purpose,
            uf.status AS uf_status,
            uf.width AS uf_width,
            uf.height AS uf_height,
            uf.duration AS uf_duration,
            uf.metadata AS uf_metadata,
            uf.created_at AS uf_created_at
        FROM listing_media lm
        LEFT JOIN uploaded_files uf ON uf.id = lm.uploaded_file_id AND uf.deleted_at IS NULL
        WHERE lm.listing_id IN ({placeholders})
        ORDER BY lm.sort_order ASC, lm.created_at ASC
        """,
        listing_ids,
    ):
        item = dict(row)
        media_source = {
            "id": item.get("uf_id") or item.get("lm_id"),
            "owner_id": item.get("uf_user_id") or "",
            "type": item.get("media_type") or item.get("uf_file_type") or "image",
            "media_type": item.get("media_type") or item.get("uf_file_type") or "image",
            "url": item.get("uf_cdn_url") or item.get("uf_public_url") or public_listing_media_url(item.get("lm_url")),
            "thumb_url": public_listing_media_url(item.get("lm_thumbnail_url")),
            "thumbnail_url": public_listing_media_url(item.get("lm_thumbnail_url")),
            "object_key": item.get("uf_object_key") or "",
            "content_type": item.get("uf_content_type") or "",
            "file_size": item.get("uf_file_size") or 0,
            "file_type": item.get("uf_file_type") or "",
            "purpose": item.get("uf_purpose") or "",
            "status": item.get("uf_status") or "ready",
            "width": item.get("uf_width") or 0,
            "height": item.get("uf_height") or 0,
            "duration": item.get("uf_duration") or 0,
            "metadata": item.get("uf_metadata") or "{}",
            "created_at": item.get("uf_created_at") or item.get("lm_created_at") or "",
        }
        media_payload = normalize_media_dto(media_source, fallback_id=item.get("lm_id") or "")
        media_payload.update({
            "id": item.get("lm_id"),
            "uploadedFileId": item.get("uploaded_file_id") or item.get("uf_id") or "",
            "uploaded_file_id": item.get("uploaded_file_id") or item.get("uf_id") or "",
            "listing_id": item["listing_id"],
            "listingId": item["listing_id"],
            "media_type": media_payload.get("type") or item.get("media_type", "image"),
            "mediaType": media_payload.get("type") or item.get("media_type", "image"),
            "sort_order": int(item.get("sort_order") or 0),
            "sortOrder": int(item.get("sort_order") or 0),
            "is_cover": bool(item.get("is_cover", 0)),
            "isCover": bool(item.get("is_cover", 0)),
        })
        if not media_payload.get("url"):
            fallback_url = public_listing_media_url(item.get("lm_url"))
            media_payload["url"] = fallback_url
            media_payload["cdnUrl"] = fallback_url
            media_payload["publicUrl"] = fallback_url
        if not media_payload.get("thumbnailUrl") and media_payload.get("type") == "image":
            fallback_thumb = public_listing_media_url(item.get("lm_thumbnail_url") or item.get("lm_url"))
            media_payload["thumbnailUrl"] = fallback_thumb
            media_payload["thumbnail_url"] = fallback_thumb
            media_payload["thumb_url"] = fallback_thumb
            media_payload["thumbUrl"] = fallback_thumb
        extras.setdefault(item["listing_id"], {}).setdefault("media", []).append(media_payload)
    for row in conn.execute(
        f"SELECT listing_id, key, value, value_type FROM listing_attributes WHERE listing_id IN ({placeholders})",
        listing_ids,
    ):
        item = dict(row)
        attrs = extras.setdefault(item["listing_id"], {}).setdefault("attributes", {})
        attrs[item["key"]] = listing_text_to_value(item["value"], item.get("value_type", "string"))
    if current_user_id:
        for row in conn.execute(
            f"SELECT listing_id FROM listing_favorites WHERE user_id = ? AND listing_id IN ({placeholders})",
            [current_user_id] + listing_ids,
        ):
            extras.setdefault(row["listing_id"], {})["favorited"] = True
    for row in conn.execute(
        f"SELECT listing_id, COUNT(*) AS c FROM listing_reports WHERE status = 'open' AND listing_id IN ({placeholders}) GROUP BY listing_id",
        listing_ids,
    ):
        extras.setdefault(row["listing_id"], {})["open_report_count"] = int(row["c"] or 0)
    return extras


def fetch_listings_with_extras(conn: sqlite3.Connection, rows: list[dict[str, Any]], current_user_id: str | None) -> list[dict[str, Any]]:
    if not rows:
        return []
    ids = [r["id"] for r in rows]
    extras = hydrate_listing_extras(conn, ids, current_user_id)
    seller_ids = list({r.get("seller_user_id") for r in rows if r.get("seller_user_id")})
    sellers = fetch_users_by_ids(conn, seller_ids)
    out: list[dict[str, Any]] = []
    for row in rows:
        item = dict(row)
        item_extra = dict(extras.get(item["id"], {}))
        item_extra["seller"] = sellers.get(item.get("seller_user_id", ""))
        item_extra["can_manage"] = bool(current_user_id and (current_user_id == item.get("seller_user_id")))
        out.append(serialize_listing(item, item_extra))
    return out


