# APIError moved to server_errors.py (imported at top, re-exported for compat).


def dm_privacy_allows(conn: sqlite3.Connection, sender_id: str, recipient_id: str) -> bool:
    """Whether the recipient's dm_privacy setting lets sender DM them.

    'everyone' (default) → yes; 'following' → only people the recipient
    follows; 'none' → nobody. Mutual blocks and reputation gates are
    enforced separately by the callers; listing-inquiry business threads
    bypass this on purpose (the contact flow is the product)."""
    if sender_id == recipient_id:
        return True
    row = conn.execute("SELECT dm_privacy FROM users WHERE id = ?", (recipient_id,)).fetchone()
    privacy = ((row["dm_privacy"] if row else "") or "everyone").strip().lower()
    if privacy == "none":
        return False
    if privacy == "following":
        return conn.execute(
            "SELECT 1 FROM follows WHERE follower_id = ? AND following_id = ?",
            (recipient_id, sender_id),
        ).fetchone() is not None
    return True


# ---------------------------------------------------------------------------
# account security: email/password helpers
#
# All of the secret-handling rules live here:
#   - passwords are hashed with PBKDF2-HMAC-SHA256 + pepper (see
#     hash_password); never stored or logged in plaintext.
#   - verification / reset codes are stored only as keyed HMAC hashes and
#     are never logged or returned by any API.
#   - emails are masked before they ever touch a log line.
# ---------------------------------------------------------------------------

EMAIL_RE = re.compile(r"^[^@\s]+@[^@\s]+\.[^@\s]+$")


def is_valid_email(email: str) -> bool:
    email = (email or "").strip()
    return bool(EMAIL_RE.match(email)) and len(email) <= 254


def mask_email(email: str) -> str:
    """Mask an address for safe logging: ``a***z@example.com``."""
    email = (email or "").strip()
    if "@" not in email:
        return "***"
    local, _, domain = email.partition("@")
    if len(local) <= 2:
        masked = (local[:1] or "*") + "*"
    else:
        masked = local[0] + "***" + local[-1]
    return f"{masked}@{domain}"


def validate_password_strength(password: Any) -> None:
    """Policy for NEW passwords: >= 8 chars, at least one letter + one digit.

    Login keeps verifying legacy (shorter) passwords so existing accounts are
    never locked out; only password *creation* paths call this.
    """
    if not isinstance(password, str) or len(password) < 8:
        raise APIError("密码至少 8 位", 400, "weak_password")
    if len(password) > 256:
        raise APIError("密码过长", 400, "invalid_password")
    if not re.search(r"[A-Za-z]", password) or not re.search(r"\d", password):
        raise APIError("密码需同时包含字母和数字", 400, "weak_password")


def generate_numeric_code(length: int = EMAIL_CODE_LENGTH) -> str:
    return "".join(str(secrets.randbelow(10)) for _ in range(length))


def hash_auth_code(code: str, email: str = "", purpose: str = "") -> str:
    """Keyed HMAC of a verification code. The plaintext code only ever
    exists in the email we send; the DB stores this digest."""
    msg = f"{purpose}\x1f{(email or '').lower()}\x1f{code}".encode("utf-8")
    return hmac.new(EMAIL_CODE_PEPPER, msg, hashlib.sha256).hexdigest()


def hash_ip(ip: str) -> str:
    return hashlib.sha256(b"machi-ip\x1f" + PASSWORD_PEPPER + (ip or "").encode("utf-8")).hexdigest()[:32]


# ---- content policy (H4) ---------------------------------------------------
# A configurable deny-list applied to user-authored text on the create paths
# (posts, comments, DMs, listings, profile bio). The MECHANISM is the product;
# the actual word lists are Trust & Safety DATA that varies per locale and is
# supplied via env (KAIX_BANNED_WORDS, comma-separated, case-insensitive). We
# ship only a tiny, high-signal seed of scam / illegal-goods solicitation
# patterns so the gate is live out of the box without embedding slur lists in
# source. Tune/extend in prod via env without a code change.
_BANNED_WORDS_SEED = [
    "代开发票", "办理证件", "出售银行卡", "枪支弹药", "child porn", "childporn",
]
_POLICY_STRIP_CODEPOINTS = dict.fromkeys(
    [0x200B, 0x200C, 0x200D, 0x2060, 0xFEFF,
     0x200E, 0x200F, 0x202A, 0x202B, 0x202C, 0x202D, 0x202E],
    None,
)


def _policy_fold(text: str) -> str:
    """Aggressively normalise text for deny-list matching so trivial obfuscation
    can't slip a banned term past it: NFKC-fold full-width / compatibility forms,
    drop zero-width + bidi controls, strip combining marks (accents), lowercase,
    then remove ALL separators/punctuation so spaced-out or punctuated evasions
    collapse onto the same tight form as the seed term. Never logged."""
    if not text:
        return ""
    t = unicodedata.normalize("NFKC", text).translate(_POLICY_STRIP_CODEPOINTS)
    t = "".join(ch for ch in unicodedata.normalize("NFKD", t)
                if not unicodedata.combining(ch))
    return re.sub(r"[\s\W_]+", "", t.lower(), flags=re.UNICODE)


BANNED_WORDS = {
    folded
    for raw in (_BANNED_WORDS_SEED + _env("KAIX_BANNED_WORDS", "").split(","))
    if (folded := _policy_fold(raw))
}


def content_policy_reason(*texts: str) -> str:
    """Return a non-empty violation code if any banned term appears in the
    concatenated user text, else ''. Both text and the deny-list pass through
    _policy_fold (NFKC + accent/zero-width strip + separator removal) so
    full-width/spaced-out/accented/punctuated evasions still match."""
    if not BANNED_WORDS:
        return ""
    blob = _policy_fold(" ".join(t for t in texts if t))
    if not blob:
        return ""
    for term in BANNED_WORDS:
        if term and term in blob:
            return "content_policy_violation"
    return ""


def enforce_content_policy(*texts: str) -> None:
    """Raise a 400 policy violation if user text trips the deny-list. Applied on
    create so objectionable content (slurs/scam/illegal, configured via env) is
    rejected before it is ever stored or served."""
    if content_policy_reason(*texts):
        raise APIError("内容包含违规信息，无法发布。如有疑问请联系客服。", 400, "content_policy_violation")


# ===========================================================================
# Machi Verified — membership + payment service layer
#
# Security invariants (the spec hammers on these — keep them true):
#   * The charge is ALWAYS recomputed from the plan server-side; a
#     client-supplied amount is never trusted.
#   * Membership is only opened/extended from a *server-confirmed* payment
#     — a verified webhook, a verified Apple transaction, or an admin
#     grant — NEVER from a client "success" callback.
#   * Settlement is idempotent: a duplicate provider callback for an
#     already-paid order is a no-op (no double extension).
#   * No payment secret (api key, private key, signature, full receipt)
#     is ever logged or returned by any API.
# ===========================================================================

# 'grace_period' removed — no code path ever writes it (one-time purchase model
# has no dunning/grace state), so it was a dead status that could never match.
MEMBERSHIP_ACTIVE_STATUSES = {"active", "trialing"}
_PROVIDER_SOURCE = {
    "wechat_pay": "wechat_pay",
    "alipay": "alipay",
    "stripe": "stripe",
    "apple_iap": "ios_iap",
    "admin": "admin_grant",
}


def _aware(dt: datetime | None) -> datetime | None:
    if dt is None:
        return None
    return dt if dt.tzinfo else dt.replace(tzinfo=timezone.utc)


def _add_one_month(dt: datetime) -> datetime:
    """Calendar-month add with day clamping (Jan 31 -> Feb 28/29) so the
    renewal anchor doesn't drift like a flat 30-day add would."""
    import calendar
    year = dt.year + (1 if dt.month == 12 else 0)
    month = 1 if dt.month == 12 else dt.month + 1
    last = calendar.monthrange(year, month)[1]
    return dt.replace(year=year, month=month, day=min(dt.day, last))


def _add_plan_period(dt: datetime, plan: dict[str, Any] | None, periods: int = 1) -> datetime:
    billing = (plan or {}).get("billing_period") or (plan or {}).get("billing_cycle") or "monthly"
    count = max(1, int((plan or {}).get("interval_count") or 1))
    months = 12 if billing == "yearly" else 1
    out = dt
    for _ in range(max(1, int(periods or 1)) * count * months):
        out = _add_one_month(out)
    return out


def requires_verified_membership(content_type: str | None) -> bool:
    return (content_type or "").strip().lower() in REQUIRES_VERIFIED_MEMBERSHIP


