def _plan_benefits(plan: dict[str, Any] | None) -> list[dict[str, Any]]:
    raw = (plan or {}).get("benefits") or ""
    try:
        parsed = json.loads(raw) if raw else []
    except Exception:
        parsed = []
    if not isinstance(parsed, list) or not parsed:
        parsed = default_membership_benefits()
    out: list[dict[str, Any]] = []
    for idx, item in enumerate(parsed):
        if not isinstance(item, dict):
            continue
        enabled = item.get("is_enabled", item.get("isEnabled", True))
        if enabled is False or str(enabled).lower() in {"0", "false", "no"}:
            continue
        title = str(item.get("benefit_title") or item.get("title") or "").strip()
        if not title:
            continue
        key = str(item.get("key") or f"benefit_{idx + 1}")
        localized = MEMBERSHIP_BENEFIT_I18N.get(key, {})
        payload = {
            "key": key,
            "benefit_title": title,
            "title": title,
            "benefit_description": str(item.get("benefit_description") or item.get("description") or ""),
            "description": str(item.get("benefit_description") or item.get("description") or ""),
            "benefit_icon": str(item.get("benefit_icon") or item.get("icon") or "checkmark.circle"),
            "icon": str(item.get("benefit_icon") or item.get("icon") or "checkmark.circle"),
            "is_enabled": True,
            "sort_order": int(item.get("sort_order") or item.get("sortOrder") or idx + 1),
        }
        for code, names in localized.items():
            payload[f"title_{code}"] = names[0]
            payload[f"description_{code}"] = names[1]
        out.append(payload)
    return sorted(out, key=lambda x: int(x.get("sort_order") or 0))


def plan_price_value(plan: dict[str, Any]) -> float:
    price = float(plan.get("price") or 0)
    if price > 0:
        return price
    return round(int(plan.get("amount_cents") or 0) / 100, 2)


def serialize_plan(plan: dict[str, Any]) -> dict[str, Any]:
    amount = plan_price_value(plan)
    cents = int(plan.get("amount_cents") or round(amount * 100))
    currency = normalize_currency(plan.get("currency", MEMBERSHIP_CURRENCY))
    billing_period = plan.get("billing_period") or plan.get("billing_cycle") or MEMBERSHIP_BILLING_CYCLE
    # Membership is a one-time, non-renewing pass. Expose the access duration in
    # days so clients can render "N-day pass" instead of implying recurring billing.
    term_days = 365 if billing_period == "yearly" else 30 * max(1, int(plan.get("interval_count") or 1))
    price_label = str(plan.get("price_label") or "").strip()
    if not price_label:
        suffix = "/ 365天" if billing_period == "yearly" else "/ 30天" if billing_period == "monthly" else ""
        price_label = f"{format_price_value(amount, currency)} {suffix}".strip()
    return {
        "plan_key": plan["plan_key"],
        "planKey": plan["plan_key"],
        "name": plan.get("name") or plan.get("name_zh", ""),
        "subtitle": plan.get("subtitle", ""),
        "description": plan.get("description", ""),
        "name_zh": plan.get("name_zh", "") or plan.get("name", ""),
        "name_en": plan.get("name_en", ""),
        "name_ja": plan.get("name_ja", ""),
        "amount": amount,
        "amount_cents": cents,
        "price": amount,
        "currency": currency,
        "price_label": price_label,
        "priceLabel": price_label,
        "original_price": float(plan.get("original_price") or 0),
        "originalPrice": float(plan.get("original_price") or 0),
        "discount_label": plan.get("discount_label") or "",
        "discountLabel": plan.get("discount_label") or "",
        "billing_cycle": billing_period,
        "billingCycle": billing_period,
        "billing_period": billing_period,
        "billingPeriod": billing_period,
        "interval_count": int(plan.get("interval_count") or 1),
        "intervalCount": int(plan.get("interval_count") or 1),
        "term_days": term_days,
        "termDays": term_days,
        "one_time": True,
        "oneTime": True,
        "stripe_product_id": plan.get("stripe_product_id") or "",
        "stripeProductId": plan.get("stripe_product_id") or "",
        "stripe_price_id": plan.get("stripe_price_id") or "",
        "stripePriceId": plan.get("stripe_price_id") or "",
        "ios_iap_product_id": plan.get("ios_iap_product_id") or "",
        "iosIapProductId": plan.get("ios_iap_product_id") or "",
        "apple_product_id": plan.get("apple_product_id") or "",
        "appleProductId": plan.get("apple_product_id") or "",
        "is_active": bool(plan.get("is_active", 1)),
        "isActive": bool(plan.get("is_active", 1)),
        "is_recommended": bool(plan.get("is_recommended")),
        "isRecommended": bool(plan.get("is_recommended")),
        "is_default": bool(plan.get("is_default")),
        "isDefault": bool(plan.get("is_default")),
        "is_featured": bool(plan.get("is_featured")),
        "isFeatured": bool(plan.get("is_featured")),
        "sort_order": int(plan.get("sort_order") or 0),
        "sortOrder": int(plan.get("sort_order") or 0),
        "benefits": _plan_benefits(plan),
        "created_at": plan.get("created_at"),
        "updated_at": plan.get("updated_at"),
    }


def _current_membership_row(conn: sqlite3.Connection, user_id: str) -> dict[str, Any] | None:
    row = conn.execute(
        "SELECT * FROM user_memberships WHERE user_id = ? "
        "ORDER BY current_period_end DESC, updated_at DESC LIMIT 1",
        (user_id,),
    ).fetchone()
    return dict(row) if row else None


def _membership_is_live(row: dict[str, Any] | None) -> bool:
    if not row or row.get("status") not in MEMBERSHIP_ACTIVE_STATUSES:
        return False
    end = _aware(parse_iso(row.get("current_period_end")))
    return bool(end and end > datetime.now(timezone.utc))


def record_entitlement_event(conn: sqlite3.Connection, user_id: str, membership_id: str,
                             event_type: str, source: str, metadata: dict | None = None) -> None:
    conn.execute(
        "INSERT INTO entitlement_events (id, user_id, membership_id, event_type, source, metadata_json, created_at) "
        "VALUES (?, ?, ?, ?, ?, ?, ?)",
        (str(uuid.uuid4()), user_id, membership_id or "", event_type, source or "",
         json.dumps(metadata or {}, ensure_ascii=False), now_iso()),
    )


def write_security_log(conn: sqlite3.Connection, user_id: str, action: str,
                       metadata: dict[str, Any] | None = None,
                       ip: str = "", user_agent: str = "") -> None:
    safe_metadata = dict(metadata or {})
    for key in ("password", "current_password", "old_password", "new_password", "code", "old_code", "new_code"):
        safe_metadata.pop(key, None)
    conn.execute(
        "INSERT INTO security_logs (id, user_id, action, ip, user_agent, metadata, created_at) VALUES (?, ?, ?, ?, ?, ?, ?)",
        (
            str(uuid.uuid4()),
            user_id or "",
            action or "",
            (ip or "")[:64],
            (user_agent or "")[:300],
            json.dumps(safe_metadata, ensure_ascii=False, sort_keys=True),
            now_iso(),
        ),
    )


def sync_user_membership_cache(conn: sqlite3.Connection, user_id: str) -> dict[str, Any]:
    """Recompute the users.* cache columns from the membership rows. The
    cache is a read accelerator only — every entitlement change calls
    this, and the expiry sweep does too."""
    row = _current_membership_row(conn, user_id)
    live = _membership_is_live(row)
    status = (row.get("status") if row else "inactive") or "inactive"
    until = (row.get("current_period_end") if (row and live) else "") or ""
    plan_key = (row.get("plan_key") if row else "") or ""
    conn.execute(
        "UPDATE users SET is_verified_member = ?, verified_member_until = ?, membership_status = ?, "
        "membership_plan_key = ?, verified_badge_type = ?, updated_at = ? WHERE id = ?",
        (1 if live else 0, until, status, plan_key, "member" if live else "", now_iso(), user_id),
    )
    return {"is_verified_member": live, "verified_member_until": until, "membership_status": status}


def _expire_membership_row(conn: sqlite3.Connection, row: dict[str, Any]) -> None:
    conn.execute(
        "UPDATE user_memberships SET status = 'expired', expired_at = ?, updated_at = ? "
        "WHERE id = ? AND status = 'active'",
        (now_iso(), now_iso(), row["id"]),
    )
    record_entitlement_event(conn, row["user_id"], row["id"], "membership_expired", row.get("source") or "", {})
    sync_user_membership_cache(conn, row["user_id"])


def get_user_membership_status(conn: sqlite3.Connection, user_id: str) -> dict[str, Any]:
    """Authoritative membership snapshot. Lazily flips a lapsed period to
    'expired' (and re-syncs the cache) so a stale row never reads active."""
    row = _current_membership_row(conn, user_id)
    if row and row.get("status") in MEMBERSHIP_ACTIVE_STATUSES and not _membership_is_live(row):
        _expire_membership_row(conn, row)
        row = _current_membership_row(conn, user_id)
    banned_row = conn.execute("SELECT deleted_at FROM users WHERE id = ?", (user_id,)).fetchone()
    banned = bool(banned_row and banned_row["deleted_at"])
    is_active = (not banned) and _membership_is_live(row)
    plan_key = (row.get("plan_key") if row else "") or ""
    plan = get_plan(conn, plan_key) if plan_key else None
    plan_payload = serialize_plan(plan) if plan else None
    current_period_end = (row.get("current_period_end") if row else "") or ""
    status = (row.get("status") if row else "inactive") or "inactive"
    source = (row.get("source") if row else "") or ""
    return {
        "user_id": user_id,
        "userId": user_id,
        "is_active": is_active,
        "isActive": is_active,
        "status": status,
        "plan_key": plan_key,
        "planKey": plan_key,
        "current_period_end": current_period_end,
        "expires_at": current_period_end,
        "expiresAt": current_period_end,
        "started_at": (row.get("started_at") if row else "") or "",
        "startedAt": (row.get("started_at") if row else "") or "",
        "source": source,
        "provider": source,
        "price": float((plan_payload or {}).get("amount") or 0),
        "currency": (plan_payload or {}).get("currency") or MEMBERSHIP_CURRENCY,
        "benefits": _plan_benefits(plan) if is_active and plan else [],
        "verified_badge_type": "member" if is_active else "",
        "verifiedBadgeType": "member" if is_active else "",
        "can_post_high_trust_content": is_active,
        "canPostHighTrustContent": is_active,
        "can_access_exclusive_page": is_active,
        "canAccessExclusivePage": is_active,
        "daily_post_limit": MEMBERSHIP_DAILY_LIMIT_VERIFIED if is_active and MEMBERSHIP_DAILY_LIMIT_VERIFIED > 0 else MEMBERSHIP_DAILY_LIMIT_FREE,
        "dailyPostLimit": MEMBERSHIP_DAILY_LIMIT_VERIFIED if is_active and MEMBERSHIP_DAILY_LIMIT_VERIFIED > 0 else MEMBERSHIP_DAILY_LIMIT_FREE,
        # priority_review removed — it was never a real benefit (no code path
        # gives a member's content faster review). light_boost IS real now (see
        # refresh_hot_scores / _heat_score_sql ×1.05 for verified-member authors).
        "light_boost": is_active,
        "lightBoost": is_active,
        "cancel_at_period_end": bool(row.get("cancel_at_period_end")) if row else False,
        "cancelAtPeriodEnd": bool(row.get("cancel_at_period_end")) if row else False,
        "membership_id": (row.get("id") if row else "") or "",
    }


def has_active_membership(conn: sqlite3.Connection, user_id: str) -> bool:
    return get_user_membership_status(conn, user_id)["is_active"]


# ---------------------------------------------------------------------------
# Machi AI — original in-app assistant (日本生活 / 升学 / 就职 / Machi 使用).
#
# Everything the user ever sees is "Machi AI". The underlying LLM provider and
# model are an INTERNAL server-side detail (seed_llm.machi_ai_chat_completion)
# and are never returned to clients, logged in the access log, or named in any
# user-visible string. These helpers handle the JST usage day, lightweight
# Guide retrieval (keyword/LIKE — never a vector store), the brand system
# prompt, the starter suggestions, and quota bookkeeping. Retrieval is
# best-effort and never raises into the chat path.
# ---------------------------------------------------------------------------

_MACHI_AI_JST = timezone(timedelta(hours=9))  # Asia/Tokyo, no DST


def machi_ai_usage_date() -> str:
    """Current calendar date in Japan time (YYYY-MM-DD) — the daily quota key."""
    return datetime.now(_MACHI_AI_JST).date().isoformat()


def machi_ai_lang_key(language: str) -> str:
    low = (language or "").strip().lower()
    if low.startswith("ja") or low == "jp":
        return "ja"
    if low.startswith("en"):
        return "en"
    return "zh"


def machi_ai_text(language: str, zh: str, ja: str, en: str) -> str:
    return {"ja": ja, "en": en}.get(machi_ai_lang_key(language), zh)


def machi_ai_usage_count(conn: sqlite3.Connection, user_id: str, usage_date: str) -> int:
    row = conn.execute(
        "SELECT total_count FROM guide_ai_usage WHERE user_id = ? AND usage_date = ?",
        (user_id, usage_date),
    ).fetchone()
    return int(row["total_count"]) if row else 0


def machi_ai_daily_limit(user: dict[str, Any] | None, is_member: bool) -> int:
    """Tiered daily quota: member > newly registered > free > guest.

    `user` is the users row (created_at decides the new-user taster window);
    None means a signed-out guest identified via X-Machi-Guest-Id."""
    if user is None:
        return MACHI_AI_GUEST_DAILY_LIMIT
    if is_member:
        return MACHI_AI_MEMBER_DAILY_LIMIT
    created = parse_iso(str(user.get("created_at") or ""))
    if created is not None:
        if created.tzinfo is None:
            created = created.replace(tzinfo=timezone.utc)
        age_days = (datetime.now(timezone.utc) - created.astimezone(timezone.utc)).days
        if 0 <= age_days < MACHI_AI_NEW_USER_WINDOW_DAYS:
            return MACHI_AI_NEW_USER_DAILY_LIMIT
    return MACHI_AI_FREE_DAILY_LIMIT


def machi_ai_guest_key(raw_guest_id: str | None) -> str | None:
    """Usage-ledger identity for a signed-out caller.

    Contract: the client sends its stable UUID in X-Machi-Guest-Id; the ledger
    key is 'guest:' + sha256(uuid)[:16], so the raw device id is never stored
    (guide_ai_usage.user_id has no FK). Missing/oversized header → None → the
    caller falls back to the ordinary 401."""
    raw = (raw_guest_id or "").strip()
    if not raw or len(raw) > 64:
        return None
    return "guest:" + hashlib.sha256(raw.encode("utf-8")).hexdigest()[:16]


def _machi_ai_title_from_message(message: str) -> str:
    """Conversation title = the question's first ~24 chars, newlines stripped."""
    text = " ".join((message or "").split()).strip()
    if len(text) > 24:
        text = text[:24]
    return text or "Machi AI"


