def require_verified_membership(conn: sqlite3.Connection, user_id: str, content_type: str | None) -> None:
    """403 MEMBERSHIP_REQUIRED if the content type is gated and the user
    isn't an active verified member. Same rule for every client."""
    if not requires_verified_membership(content_type):
        return
    if not has_active_membership(conn, user_id):
        raise APIError("发布该类型内容需要开通 Machi 认证会员。", 403, "MEMBERSHIP_REQUIRED")


_money_tx_depth = threading.local()


def money_atomic(fn):
    """Run a money-mutating function's writes as ONE all-or-nothing transaction.

    Composite money operations (flip an order pending->paid, THEN append the
    ledger / grant the entitlement) previously ran on the autocommit connection,
    so a crash between the steps could leave a 'paid' order with no credit that
    per-step idempotency then refused to repair on retry — a "charged real money,
    received nothing, unrecoverable" window. This wraps the whole call in a
    BEGIN IMMEDIATE / COMMIT (plain BEGIN on Postgres, see _pg_xlate) and ROLLS
    BACK on any exception.

    Reentrant: only the OUTERMOST decorated call opens/commits the transaction;
    nested decorated calls (e.g. wallet_credit_topup -> wallet_post_ledger) just
    join it, so there is no illegal nested BEGIN and the whole composite stays a
    single atomic unit. All decorated functions run under DB_LOCK (one writer per
    process), so the BEGIN IMMEDIATE never contends within a process. Functions
    that internally catch-and-continue on IntegrityError (which would poison a
    Postgres transaction) are deliberately left undecorated."""
    @functools.wraps(fn)
    def wrapper(conn, *args, **kwargs):
        if getattr(_money_tx_depth, "value", 0) > 0:
            return fn(conn, *args, **kwargs)  # already inside an outer money_tx
        _money_tx_depth.value = 1
        conn.execute("BEGIN IMMEDIATE")
        try:
            result = fn(conn, *args, **kwargs)
            conn.execute("COMMIT")
            return result
        except BaseException:
            try:
                conn.execute("ROLLBACK")
            except Exception:
                pass
            raise
        finally:
            _money_tx_depth.value = 0
    return wrapper


@money_atomic
def activate_or_extend_membership(conn: sqlite3.Connection, user_id: str, plan_key: str,
                                  source: str, periods: int = 1) -> dict[str, Any]:
    """Open a new membership or extend the live one by `periods` plan periods.
    Callers own idempotency — this always adds `periods` when invoked."""
    now = datetime.now(timezone.utc)
    periods = max(1, int(periods or 1))
    plan = get_plan(conn, plan_key)
    row = _current_membership_row(conn, user_id)
    if _membership_is_live(row):
        end = _aware(parse_iso(row.get("current_period_end"))) or now
        end = _add_plan_period(end, plan, periods)
        conn.execute(
            # Clear cancel_at_period_end / canceled_at: a member who was scheduled
            # to lapse but pays again is now genuinely active — otherwise they'd be
            # flagged 'canceling' and wrongly expired at period end despite paying.
            "UPDATE user_memberships SET status = 'active', plan_key = ?, current_period_end = ?, "
            "expires_at = ?, billing_period = ?, price = ?, currency = ?, provider = ?, source = ?, "
            "cancel_at_period_end = 0, canceled_at = NULL, expired_at = NULL, updated_at = ? WHERE id = ?",
            (plan_key, end.isoformat(), end.isoformat(), (plan or {}).get("billing_period") or (plan or {}).get("billing_cycle") or "",
             plan_price_value(plan) if plan else 0, (plan or {}).get("currency") or "", source, source, now_iso(), row["id"]),
        )
        membership_id = row["id"]
        record_entitlement_event(conn, user_id, membership_id, "membership_renewed", source, {"plan_key": plan_key})
    else:
        end = _add_plan_period(now, plan, periods)
        membership_id = str(uuid.uuid4())
        conn.execute(
            "INSERT INTO user_memberships (id, user_id, plan_key, status, started_at, current_period_start, "
            "current_period_end, expires_at, billing_period, price, currency, provider, source, created_at, updated_at) VALUES (?, ?, ?, 'active', ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
            (membership_id, user_id, plan_key, now.isoformat(), now.isoformat(), end.isoformat(),
             end.isoformat(), (plan or {}).get("billing_period") or (plan or {}).get("billing_cycle") or "",
             plan_price_value(plan) if plan else 0, (plan or {}).get("currency") or "",
             source, source, now_iso(), now_iso()),
        )
        record_entitlement_event(conn, user_id, membership_id, "membership_started", source, {"plan_key": plan_key})
    sync_user_membership_cache(conn, user_id)
    return get_user_membership_status(conn, user_id)


def sync_apple_membership_expiry(conn: sqlite3.Connection, user_id: str, plan_key: str,
                                 expires_at_iso: str, original_transaction_id: str = "",
                                 product_id: str = "", event_type: str = "apple_sync",
                                 minimum_until_iso: str = "") -> dict[str, Any]:
    """Align membership to Apple's authoritative subscription expiry.

    `mark_order_paid` grants by local plan period so Web/Stripe/Alipay/WeChat
    share one settlement path. Auto-renewable IAP also carries an exact
    `expiresDate`; use that exact date afterward so restore/notification flows
    never accidentally over-extend from "now" when replaying an older
    transaction.
    """
    expiry = _aware(parse_iso(expires_at_iso))
    if not expiry:
        return get_user_membership_status(conn, user_id)
    floor = _aware(parse_iso(minimum_until_iso))
    target = floor if floor and floor > expiry else expiry
    now = datetime.now(timezone.utc)
    plan = get_plan(conn, plan_key)
    row = _current_membership_row(conn, user_id)
    # For App Store Server Notifications, events can arrive out of order.
    # Preserve a newer already-synced expiry unless the caller supplied an
    # explicit pre-settlement floor (client verify uses that to undo the local
    # plan-period provisional grant and align to Apple's exact expiresDate).
    if row and not minimum_until_iso:
        row_end = _aware(parse_iso(row.get("current_period_end")))
        if row_end and row_end > target:
            target = row_end
    status = "active" if target > now else "expired"
    membership_id = ""
    if row:
        membership_id = row["id"]
        conn.execute(
            "UPDATE user_memberships SET status = ?, plan_key = ?, current_period_end = ?, expires_at = ?, "
            "billing_period = ?, price = ?, currency = ?, provider = 'ios_iap', source = 'ios_iap', "
            "provider_subscription_id = COALESCE(NULLIF(?, ''), provider_subscription_id), "
            "provider_price_id = COALESCE(NULLIF(?, ''), provider_price_id), "
            "expired_at = CASE WHEN ? = 'expired' THEN ? ELSE NULL END, updated_at = ? WHERE id = ?",
            (
                status, plan_key, target.isoformat(), target.isoformat(),
                (plan or {}).get("billing_period") or (plan or {}).get("billing_cycle") or "",
                plan_price_value(plan) if plan else 0, (plan or {}).get("currency") or "",
                original_transaction_id or "", product_id or "", status, now_iso(), now_iso(), row["id"],
            ),
        )
    else:
        membership_id = str(uuid.uuid4())
        conn.execute(
            "INSERT INTO user_memberships (id, user_id, plan_key, status, started_at, current_period_start, "
            "current_period_end, expires_at, billing_period, price, currency, provider, source, "
            "provider_subscription_id, provider_price_id, expired_at, created_at, updated_at) "
            "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'ios_iap', 'ios_iap', ?, ?, ?, ?, ?)",
            (
                membership_id, user_id, plan_key, status, now.isoformat(), now.isoformat(),
                target.isoformat(), target.isoformat(),
                (plan or {}).get("billing_period") or (plan or {}).get("billing_cycle") or "",
                plan_price_value(plan) if plan else 0, (plan or {}).get("currency") or "",
                original_transaction_id or "", product_id or "",
                now_iso() if status == "expired" else None, now_iso(), now_iso(),
            ),
        )
    record_entitlement_event(conn, user_id, membership_id, event_type, "ios_iap", {
        "plan_key": plan_key,
        "expires_at": target.isoformat(),
        "original_transaction_id": original_transaction_id,
        "product_id": product_id,
    })
    sync_user_membership_cache(conn, user_id)
    return get_user_membership_status(conn, user_id)


def cancel_membership(conn: sqlite3.Connection, user_id: str, immediate: bool = False,
                      source: str = "admin") -> dict[str, Any]:
    """Stop access at the current period end (default) or revoke
    immediately. Already-published content is never deleted."""
    row = _current_membership_row(conn, user_id)
    if not row:
        raise APIError("用户没有会员记录", 404, "membership_not_found")
    if immediate:
        conn.execute(
            "UPDATE user_memberships SET status = 'canceled', cancel_at_period_end = 1, canceled_at = ?, "
            "current_period_end = ?, expired_at = ?, updated_at = ? WHERE id = ?",
            (now_iso(), now_iso(), now_iso(), now_iso(), row["id"]),
        )
    else:
        conn.execute(
            "UPDATE user_memberships SET cancel_at_period_end = 1, canceled_at = ?, updated_at = ? WHERE id = ?",
            (now_iso(), now_iso(), row["id"]),
        )
    record_entitlement_event(conn, user_id, row["id"], "membership_canceled", source, {"immediate": immediate})
    sync_user_membership_cache(conn, user_id)
    return get_user_membership_status(conn, user_id)


def expire_due_memberships(conn: sqlite3.Connection) -> int:
    rows = list(conn.execute(
        "SELECT * FROM user_memberships WHERE status = 'active' "
        "AND current_period_end IS NOT NULL AND current_period_end < ?",
        (now_iso(),),
    ))
    for r in rows:
        _expire_membership_row(conn, dict(r))
    return len(rows)


# ---------------------------------------------------------------------------
# payment orders + providers
# ---------------------------------------------------------------------------

def generate_order_no() -> str:
    """Unique, time-ordered, unguessable order number."""
    ts = datetime.now(timezone.utc).strftime("%Y%m%d%H%M%S")
    return f"MV{ts}{secrets.token_hex(6).upper()}"


def serialize_order(row: dict[str, Any]) -> dict[str, Any]:
    cents = int(row.get("amount_cents") or 0)
    provider = row.get("payment_provider", "")
    platform = row.get("client_type", "") or ("ios" if provider == "apple_iap" else "web")
    return {
        "id": row.get("id", ""),
        "user_id": row.get("user_id", ""),
        "userId": row.get("user_id", ""),
        "order_no": row["order_no"],
        "orderNo": row["order_no"],
        "plan_key": row.get("plan_key", ""),
        "planKey": row.get("plan_key", ""),
        "amount": round(cents / 100, 2),
        "price": round(cents / 100, 2),
        "amount_cents": cents,
        "currency": row.get("currency", MEMBERSHIP_CURRENCY),
        "status": row.get("status", "pending"),
        "provider": provider,
        "payment_provider": provider,
        "platform": platform,
        "client_type": row.get("client_type", ""),
        "created_at": row.get("created_at"),
        "createdAt": row.get("created_at"),
        "expires_at": row.get("expires_at"),
        "expiresAt": row.get("expires_at"),
        "paid_at": row.get("paid_at"),
        "paidAt": row.get("paid_at"),
        "transaction_id": row.get("provider_trade_no", "") or "",
        "transactionId": row.get("provider_trade_no", "") or "",
        "error_message": row.get("error_message", "") or "",
        "errorMessage": row.get("error_message", "") or "",
    }


def _stripe_minor_units(amount_cents: int, currency: str) -> int:
    """Convert our value×100 storage into Stripe minor units for the given
    currency (zero-decimal currencies divide by 100)."""
    if (currency or "").lower() in STRIPE_ZERO_DECIMAL:
        return int(amount_cents) // 100
    return int(amount_cents)


def _order_charge_for_provider(plan: dict[str, Any], provider: str) -> tuple[int, str]:
    """The amount + currency to charge, chosen server-side per provider.
    A client-supplied amount is never used. Orders store the app's normal
    value×100 amount for every provider; provider-specific minor-unit
    conversion happens only at the edge when creating/verifying a charge."""
    amount = int(plan.get("amount_cents") or round(plan_price_value(plan) * 100))
    return amount, normalize_currency(plan.get("currency") or MEMBERSHIP_CURRENCY)


def create_payment_order(conn: sqlite3.Connection, user_id: str, plan_key: str,
                         provider: str, client_type: str) -> dict[str, Any]:
    plan = get_plan(conn, plan_key)
    if not plan:
        raise APIError("会员计划不存在", 404, "plan_not_found")
    amount_cents, currency = _order_charge_for_provider(plan, provider)
    provider_price_id = ""
    if provider == "apple_iap":
        provider_price_id = str(plan.get("apple_product_id") or plan.get("ios_iap_product_id") or "")
    order_no = generate_order_no()
    expires_at = (datetime.now(timezone.utc) + timedelta(seconds=PAYMENT_ORDER_TTL_SEC)).isoformat()
    conn.execute(
        "INSERT INTO payment_orders (id, order_no, user_id, plan_key, amount_cents, currency, status, "
        "payment_provider, provider_price_id, client_type, expires_at, created_at, updated_at) "
        "VALUES (?, ?, ?, ?, ?, ?, 'pending', ?, ?, ?, ?, ?, ?)",
        (str(uuid.uuid4()), order_no, user_id, plan_key, amount_cents, currency,
         provider, provider_price_id, client_type, expires_at, now_iso(), now_iso()),
    )
    return dict(conn.execute("SELECT * FROM payment_orders WHERE order_no = ?", (order_no,)).fetchone())


def _order_is_expired(order: dict[str, Any]) -> bool:
    exp = _aware(parse_iso(order.get("expires_at")))
    return bool(exp and exp < datetime.now(timezone.utc))


@money_atomic
def mark_order_paid(conn: sqlite3.Connection, order_no: str, provider_trade_no: str = "",
                    provider_user_id: str = "", expected_provider: str | None = None,
                    paid_amount_cents: int | None = None,
                    provider_subscription_id: str = "",
                    provider_price_id: str = "",
                    notify_email: bool = True) -> dict[str, Any]:
    """Idempotent settlement. A pending order transitions to paid exactly
    once and opens/extends membership. Re-invoked for an already-paid
    order → returns existing state without double-extending.
    notify_email=False settles without the "payment succeeded" email —
    Apple Sandbox/TestFlight/Xcode transactions are test traffic, not money."""
    row = conn.execute("SELECT * FROM payment_orders WHERE order_no = ?", (order_no,)).fetchone()
    if not row:
        raise APIError("订单不存在", 404, "order_not_found")
    order = dict(row)
    if expected_provider and order.get("payment_provider") != expected_provider:
        raise APIError("订单支付方式不匹配", 400, "provider_mismatch")
    expected_paid_amount = int(order["amount_cents"])
    if order.get("payment_provider") == "stripe":
        expected_paid_amount = _stripe_minor_units(expected_paid_amount, order.get("currency") or MEMBERSHIP_CURRENCY)
    if paid_amount_cents is not None and int(paid_amount_cents) != expected_paid_amount:
        # Amount tampering — never settle. The charge is defined by the plan.
        raise APIError("支付金额与订单不一致", 400, "amount_mismatch")
    if order["status"] == "paid":
        return order  # idempotent
    # 'closed' = auto-expired-but-unpaid (the 20-min janitor). A genuine payment
    # can still arrive after that (the Stripe session outlives our order TTL), so
    # accept closed→paid too — real money always wins. Only truly terminal states
    # (refunded, etc.) are rejected.
    if order["status"] not in ("pending", "closed"):
        raise APIError("订单状态不允许支付", 409, "order_not_payable")
    cur = conn.execute(
        "UPDATE payment_orders SET status = 'paid', provider_trade_no = ?, provider_user_id = ?, "
        "provider_subscription_id = COALESCE(NULLIF(?, ''), provider_subscription_id), "
        "provider_price_id = COALESCE(NULLIF(?, ''), provider_price_id), paid_at = ?, updated_at = ? "
        "WHERE order_no = ? AND status IN ('pending', 'closed')",
        (provider_trade_no or "", provider_user_id or "", provider_subscription_id or "",
         provider_price_id or "", now_iso(), now_iso(), order_no),
    )
    fresh = dict(conn.execute("SELECT * FROM payment_orders WHERE order_no = ?", (order_no,)).fetchone())
    # Gate the grant on actually WINNING the pending→paid transition. A re-read of
    # `fresh` can't distinguish "I settled it" from "a concurrent caller settled
    # it" (both see 'paid'); the conditional UPDATE's rowcount can. SQLite
    # serializes writers, so exactly one caller gets rowcount==1 and grants — two
    # different webhook events for the same order never double-extend membership.
    if cur.rowcount != 1:
        return fresh  # already settled by a concurrent caller — never double-grant
    source = _PROVIDER_SOURCE.get(order["payment_provider"], order["payment_provider"] or "manual")
    status = activate_or_extend_membership(conn, order["user_id"], order["plan_key"], source, periods=1)
    if provider_subscription_id or provider_price_id:
        conn.execute(
            "UPDATE user_memberships SET provider_subscription_id = COALESCE(NULLIF(?, ''), provider_subscription_id), "
            "provider_price_id = COALESCE(NULLIF(?, ''), provider_price_id), provider = ?, updated_at = ? WHERE id = ?",
            (provider_subscription_id or "", provider_price_id or "", source, now_iso(), status.get("membership_id") or ""),
        )
    if notify_email:
        queue_membership_payment_email(conn, fresh)
    return fresh


@money_atomic
def refund_order(conn: sqlite3.Connection, order_no: str) -> None:
    """MS-6: refund a membership order — mark refunded, record the event, AND
    revoke the membership so a refunded user loses access (idempotent). The
    three dependent writes commit as one transaction so a crash can't leave an
    order flagged refunded with the membership still active (or vice versa)."""
    order = conn.execute("SELECT * FROM payment_orders WHERE order_no = ?", (order_no,)).fetchone()
    if not order:
        return
    order = dict(order)
    if order.get("status") == "refunded":
        return
    conn.execute(
        "UPDATE payment_orders SET status = 'refunded', refunded_at = ?, updated_at = ? WHERE order_no = ? AND status != 'refunded'",
        (now_iso(), now_iso(), order_no),
    )
    record_entitlement_event(conn, order["user_id"], "", "membership_refunded",
                             order["payment_provider"], {"order_no": order_no})
    cancel_membership(conn, order["user_id"], immediate=True, source="refund")


def record_payment_webhook(conn: sqlite3.Connection, provider: str, event_type: str, event_id: str,
                           order_no: str, raw: str, signature_valid: bool) -> bool:
    """Audit-log a provider callback. Returns False if this exact event
    was already recorded (dedup on provider+event_id) so the caller can
    skip re-processing."""
    if event_id:
        dupe = conn.execute(
            "SELECT 1 FROM payment_webhooks WHERE provider = ? AND event_id = ?", (provider, event_id)
        ).fetchone()
        if dupe:
            return False
    conn.execute(
        "INSERT INTO payment_webhooks (id, provider, event_type, event_id, order_no, raw_payload, "
        "signature_valid, processed_at, created_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)",
        (str(uuid.uuid4()), provider, event_type or "", event_id or "", order_no or "",
         (raw or "")[:8000], 1 if signature_valid else 0, now_iso(), now_iso()),
    )
    return True


def _payment_webhook_seen(conn: sqlite3.Connection, provider: str, event_id: str) -> bool:
    """True if this provider event was already durably recorded (dedup)."""
    if not event_id:
        return False
    return conn.execute(
        "SELECT 1 FROM payment_webhooks WHERE provider = ? AND event_id = ?", (provider, event_id)
    ).fetchone() is not None


@money_atomic
def _settle_and_record_webhook(conn: sqlite3.Connection, provider: str, event_type: str,
                               event_id: str, order_no: str, raw: str, settle) -> bool:
    """Grant the entitlement AND write the dedup row as ONE atomic unit that
    commits together. Closes the record-then-settle window: the dedup INSERT
    used to commit on its own BEFORE settle ran, so a crash in between left the
    event marked processed while nothing was granted, and the provider's retry
    was then skipped (first=False) — the "charged real money, received nothing,
    unrecoverable" hole. Now a crash rolls back BOTH, so the retry re-processes."""
    settle(conn)
    record_payment_webhook(conn, provider, event_type, event_id, order_no, raw, True)
    return True


def process_payment_webhook(conn: sqlite3.Connection, provider: str, event_type: str,
                            event_id: str, order_no: str, raw: str, settle) -> bool:
    """Idempotently settle a verified provider callback. `settle(conn)` performs
    the grant and MUST raise APIError for a PERMANENT business rejection (amount
    mismatch / wrong provider / not payable) — those are recorded as seen WITHOUT
    granting, so the provider stops retrying a non-settleable event. Any OTHER
    exception (a transient crash / DB error) propagates after the transaction
    rolls back, leaving no dedup row, so the provider retry re-processes it
    cleanly. Returns True iff this call performed the first settlement."""
    if _payment_webhook_seen(conn, provider, event_id):
        return False
    try:
        return _settle_and_record_webhook(conn, provider, event_type, event_id, order_no, raw, settle)
    except APIError as exc:
        ACCESS_LOG.warning("%s webhook settle rejected order=%s code=%s",
                           provider, order_no, getattr(exc, "code", ""))
        try:
            record_payment_webhook(conn, provider, event_type, event_id, order_no, raw, True)
        except Exception:
            pass
        return False


# ---------------------------------------------------------------------------
# Machi Points wallet — internal points scrip (NOT cash).
#
# Hard product rules (mirror Apple's IAP guidance, last reviewed 2026-06):
#   * Points are bought with real money (Stripe on Web, App Store IAP on iOS,
#     Google Play Billing on Android global) and spent ONLY on Machi's own
#     digital goods/services.
#   * Points NEVER expire — IAP-purchased "currency" must not expire.
#   * No withdrawal, no transfer, no cash conversion.
#   * Every credit/debit is an immutable ledger row; the balance is just the
#     running sum and can be rebuilt from the ledger. Each provider settlement
#     is idempotent on a stable key (and gated on a pending→paid order-state
#     transition) so a webhook + a client confirm can't double-credit.
# ---------------------------------------------------------------------------

WALLET_POINTS_NAME = "Machi Coins"
WALLET_POINTS_NAME_ZH = "Machi 币"
WALLET_POINTS_UNIT = "币"
WALLET_DISCLAIMER = (
    "Machi 币仅可用于 Machi 内的数字资料、模板与平台服务，"
    "不可提现、不可转让、不可兑换现金，且不会过期。"
)

# Client capability handshake. Clients read /api/meta/client-config on launch to
# decide what to show. The single most important signal is simply that this
# endpoint EXISTS and returns features.wallet=true — an older backend (no wallet
# routes) returns 404 here, so the client knows not to render a topup card that
# would 404 on /api/wallet/me. Bump CLIENT_CONFIG_API_VERSION when the
# client-visible contract changes.
CLIENT_CONFIG_API_VERSION = 1
SERVER_BUILD_SHA = _env("KAIX_BUILD_SHA", "") or _env("RENDER_GIT_COMMIT", "") or "dev"
# Minimum client versions the server still supports. Empty = no floor enforced.
MIN_CLIENT_VERSION_IOS = _env("MIN_CLIENT_VERSION_IOS", "")
MIN_CLIENT_VERSION_ANDROID = _env("MIN_CLIENT_VERSION_ANDROID", "")


def client_config_payload() -> dict[str, Any]:
    """Capability/feature handshake, computed from real server config so a
    client never offers a payment path the backend can't actually settle.
    Public, unauthenticated, no DB — safe to hit on every cold launch."""
    stripe_ready = bool(STRIPE_SECRET_KEY and STRIPE_WEBHOOK_SECRET)
    apple_ready = bool(APPLE_IAP_SHARED_SECRET or APPLE_IAP_PRIVATE_KEY)
    google_ready = google_play_configured()
    return {
        "apiVersion": CLIENT_CONFIG_API_VERSION,
        "serverVersion": SERVER_BUILD_SHA,
        "buildSha": SERVER_BUILD_SHA,
        "environment": "production" if PRODUCTION else "development",
        "features": {
            "wallet": True,
            "guideCommerce": True,
            "membership": True,
            "points": True,
        },
        # Which providers are usable *and configured* per platform. "machi_points"
        # means "spend the in-app wallet" and is always available once funded.
        "paymentProviders": {
            "web": (["stripe"] if stripe_ready else []) + ["machi_points"],
            "ios": ["apple_iap", "machi_points"],
            "androidGlobal": (["google_play"] if google_ready else []) + ["machi_points"],
            # China/OEM channels have no compliant in-app topup yet.
            "androidChina": [],
        },
        "providersConfigured": {
            "stripe": stripe_ready,
            "appleIap": apple_ready,
            "googlePlay": google_ready,
        },
        "wallet": {
            "pointsName": WALLET_POINTS_NAME,
            "pointsNameZh": WALLET_POINTS_NAME_ZH,
            "pointsUnit": WALLET_POINTS_UNIT,
            "disclaimer": WALLET_DISCLAIMER,
        },
        "walletDisclaimer": WALLET_DISCLAIMER,
        "minClientVersion": {
            "ios": MIN_CLIENT_VERSION_IOS,
            "android": MIN_CLIENT_VERSION_ANDROID,
        },
        "ts": now_iso(),
    }

