def _wallet_topup_order_no() -> str:
    """Wallet top-up order number. The 'WT' prefix lets the shared Stripe
    webhook route the settlement to wallet_topup_orders (vs membership /
    guide_orders)."""
    return "WT" + now_iso()[:10].replace("-", "") + uuid.uuid4().hex[:8].upper()


def _wallet_order_no() -> str:
    """Order number for a points-paid guide purchase. 'GW' = guide wallet; it
    never reaches a payment provider (the order is born fulfilled)."""
    return "GW" + now_iso()[:10].replace("-", "") + uuid.uuid4().hex[:8].upper()


def _points_display(points: int) -> str:
    return f"{int(points or 0):,} {WALLET_POINTS_UNIT}"


def ensure_wallet_account(conn: sqlite3.Connection, user_id: str) -> dict[str, Any]:
    """Return the user's wallet, creating a zero-balance account on first use."""
    row = conn.execute("SELECT * FROM wallet_accounts WHERE user_id = ?", (user_id,)).fetchone()
    if row:
        return dict(row)
    now = now_iso()
    try:
        conn.execute(
            "INSERT INTO wallet_accounts (id, user_id, balance_points, lifetime_purchased_points, "
            "lifetime_bonus_points, lifetime_spent_points, status, created_at, updated_at) "
            "VALUES (?, ?, 0, 0, 0, 0, 'active', ?, ?)",
            (str(uuid.uuid4()), user_id, now, now),
        )
    except sqlite3.IntegrityError:
        # Concurrent create won the user_id UNIQUE race — fall through to re-read.
        pass
    return dict(conn.execute("SELECT * FROM wallet_accounts WHERE user_id = ?", (user_id,)).fetchone())


def serialize_wallet_account(row: sqlite3.Row | dict[str, Any]) -> dict[str, Any]:
    d = dict(row)
    bal = int(d.get("balance_points") or 0)
    return {
        "balancePoints": bal, "balance_points": bal,
        "status": d.get("status") or "active",
        "lifetimePurchasedPoints": int(d.get("lifetime_purchased_points") or 0),
        "lifetimeBonusPoints": int(d.get("lifetime_bonus_points") or 0),
        "lifetimeSpentPoints": int(d.get("lifetime_spent_points") or 0),
        "pointsName": WALLET_POINTS_NAME,
        "pointsNameZh": WALLET_POINTS_NAME_ZH,
        "displayBalance": _points_display(bal),
        "disclaimer": WALLET_DISCLAIMER,
    }


def get_wallet_snapshot(conn: sqlite3.Connection, user_id: str) -> dict[str, Any]:
    return serialize_wallet_account(ensure_wallet_account(conn, user_id))




def serialize_wallet_topup_product(row: sqlite3.Row | dict[str, Any]) -> dict[str, Any]:
    d = dict(row)
    points = int(d.get("points") or 0)
    bonus = int(d.get("bonus_points") or 0)
    amount = int(d.get("amount_cents") or 0)
    currency = normalize_currency(d.get("currency") or "CNY")
    return {
        "id": d.get("id"), "packKey": d.get("pack_key"), "pack_key": d.get("pack_key"),
        "title": d.get("title") or "", "subtitle": d.get("subtitle") or "",
        "points": points, "bonusPoints": bonus, "bonus_points": bonus,
        "totalPoints": points + bonus, "total_points": points + bonus,
        "amountCents": amount, "amount_cents": amount, "currency": currency,
        "priceLabel": format_price_value(amount / 100.0, currency),
        "displayPoints": _points_display(points + bonus),
        "appleProductId": d.get("apple_product_id") or d.get("ios_iap_product_id") or "",
        "iosIapProductId": d.get("ios_iap_product_id") or d.get("apple_product_id") or "",
        "googleProductId": d.get("google_product_id") or "",
        "huaweiProductId": d.get("huawei_product_id") or "",
        "sortOrder": int(d.get("sort_order") or 0),
        "isActive": bool(d.get("is_active", 1)),
    }




def get_topup_product(conn: sqlite3.Connection, pack_key: str) -> dict[str, Any] | None:
    row = conn.execute(
        "SELECT * FROM wallet_topup_products WHERE pack_key = ? AND is_active = 1", (pack_key,)
    ).fetchone()
    return dict(row) if row else None


def list_topup_products(conn: sqlite3.Connection) -> list[dict[str, Any]]:
    rows = conn.execute(
        "SELECT * FROM wallet_topup_products WHERE is_active = 1 ORDER BY sort_order, amount_cents"
    ).fetchall()
    return [dict(r) for r in rows]


@money_atomic
def wallet_post_ledger(conn: sqlite3.Connection, user_id: str, entry_type: str, points_delta: int, *,
                       source_type: str = "", source_order_id: str = "", source_transaction_id: str = "",
                       idempotency_key: str = "", product_id: str = "", metadata: dict | None = None,
                       created_by: str = "") -> dict[str, Any]:
    """Apply ONE balance movement and append its immutable audit row.

    points_delta > 0 credits, < 0 debits, 0 is a no-op audit note. Returns a
    result dict: {entry, wallet, applied, duplicate, insufficient}. Idempotent
    on (user_id, idempotency_key) — a repeat returns the prior row untouched.
    A debit is a single conditional UPDATE (never goes below zero, safe across
    processes); the rowcount tells us whether it landed."""
    account = ensure_wallet_account(conn, user_id)
    points_delta = int(points_delta)
    if idempotency_key:
        existing = conn.execute(
            "SELECT * FROM wallet_ledger_entries WHERE user_id = ? AND idempotency_key = ? LIMIT 1",
            (user_id, idempotency_key),
        ).fetchone()
        if existing:
            return {"entry": serialize_wallet_ledger_entry(existing),
                    "wallet": get_wallet_snapshot(conn, user_id),
                    "applied": False, "duplicate": True, "insufficient": False}
    now = now_iso()
    if points_delta < 0:
        spend = -points_delta
        cur = conn.execute(
            "UPDATE wallet_accounts SET balance_points = balance_points - ?, "
            "lifetime_spent_points = lifetime_spent_points + ?, updated_at = ? "
            "WHERE user_id = ? AND status = 'active' AND balance_points >= ?",
            (spend, spend, now, user_id, spend),
        )
        if cur.rowcount != 1:
            return {"entry": None, "wallet": get_wallet_snapshot(conn, user_id),
                    "applied": False, "duplicate": False, "insufficient": True}
    elif points_delta > 0:
        purchased_inc = points_delta if entry_type == "topup" else 0
        bonus_inc = points_delta if entry_type in ("bonus", "membership_bonus", "referral_bonus") else 0
        conn.execute(
            "UPDATE wallet_accounts SET balance_points = balance_points + ?, "
            "lifetime_purchased_points = lifetime_purchased_points + ?, "
            "lifetime_bonus_points = lifetime_bonus_points + ?, updated_at = ? WHERE user_id = ?",
            (points_delta, purchased_inc, bonus_inc, now, user_id),
        )
    balance_after = int(dict(conn.execute(
        "SELECT balance_points FROM wallet_accounts WHERE user_id = ?", (user_id,)).fetchone()).get("balance_points") or 0)
    entry_id = str(uuid.uuid4())
    conn.execute(
        "INSERT INTO wallet_ledger_entries (id, user_id, account_id, entry_type, points_delta, balance_after, "
        "source_type, source_order_id, source_transaction_id, idempotency_key, product_id, metadata_json, "
        "created_at, created_by) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
        (entry_id, user_id, account["id"], entry_type, points_delta, balance_after,
         source_type or "", source_order_id or "", source_transaction_id or "", idempotency_key or "",
         product_id or "", json.dumps(metadata or {}, ensure_ascii=False), now, created_by or ""),
    )
    entry = conn.execute("SELECT * FROM wallet_ledger_entries WHERE id = ?", (entry_id,)).fetchone()
    return {"entry": serialize_wallet_ledger_entry(entry),
            "wallet": get_wallet_snapshot(conn, user_id),
            "applied": True, "duplicate": False, "insufficient": False}


@money_atomic
def qualify_referral_atomic(conn: sqlite3.Connection, invitee_id: str) -> dict[str, Any]:
    """@money_atomic boundary for referral.qualify_referral: the CAS on the
    referral status plus BOTH ledger writes commit as one transaction (or roll
    back together). The pure logic lives in server_referral.py; we inject the
    wallet ledger so that module never imports server. Nested money_atomic calls
    (wallet_post_ledger is itself decorated) just join this outer tx."""
    return referral.qualify_referral(conn, invitee_id, post_ledger=wallet_post_ledger, now=now_iso())


@money_atomic
def admin_review_referral_atomic(conn: sqlite3.Connection, referral_id: str, action: str) -> dict[str, Any]:
    """@money_atomic boundary for admin approve/reject of a held referral."""
    return referral.admin_review_referral(conn, referral_id, action,
                                          post_ledger=wallet_post_ledger, now=now_iso())


def create_wallet_topup_order(conn: sqlite3.Connection, user_id: str, pack: dict[str, Any], provider: str,
                              client_type: str = "", provider_product_id: str = "",
                              provider_trade_no: str = "") -> dict[str, Any]:
    """Create a pending top-up order. Amount + points always come from the pack
    row server-side — the client never sends a price or a points amount. For IAP
    flows pass provider_trade_no (the store transaction id): the UNIQUE
    (payment_provider, provider_trade_no) index then makes one order per
    transaction, so a re-verify can't create a second order to double-credit."""
    points = int(pack.get("points") or 0)
    bonus = int(pack.get("bonus_points") or 0)
    now = now_iso()
    order_id = str(uuid.uuid4())
    order_no = _wallet_topup_order_no()
    conn.execute(
        "INSERT INTO wallet_topup_orders (id, order_no, user_id, pack_key, points, bonus_points, total_points, "
        "amount_cents, currency, status, payment_provider, provider_product_id, provider_trade_no, client_type, "
        "created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 'pending', ?, ?, ?, ?, ?, ?)",
        (order_id, order_no, user_id, pack.get("pack_key"), points, bonus, points + bonus,
         int(pack.get("amount_cents") or 0), pack.get("currency") or "CNY", provider,
         provider_product_id or "", provider_trade_no or "", client_type or "", now, now),
    )
    return dict(conn.execute("SELECT * FROM wallet_topup_orders WHERE id = ?", (order_id,)).fetchone())


def get_topup_product_by_apple(conn: sqlite3.Connection, product_id: str) -> dict[str, Any] | None:
    row = conn.execute(
        "SELECT * FROM wallet_topup_products WHERE is_active = 1 AND ? <> '' "
        "AND (apple_product_id = ? OR ios_iap_product_id = ?) LIMIT 1",
        (product_id, product_id, product_id),
    ).fetchone()
    return dict(row) if row else None


def get_topup_product_by_google(conn: sqlite3.Connection, product_id: str) -> dict[str, Any] | None:
    row = conn.execute(
        "SELECT * FROM wallet_topup_products WHERE is_active = 1 AND ? <> '' AND google_product_id = ? LIMIT 1",
        (product_id, product_id),
    ).fetchone()
    return dict(row) if row else None


def wallet_credit_iap_topup(conn: sqlite3.Connection, user_id: str, pack: dict[str, Any], provider: str,
                            client_type: str, provider_trade_no: str, provider_product_id: str = "",
                            provider_user_id: str = "") -> dict[str, Any]:
    """Credit an IAP (Apple/Google) top-up exactly once, keyed on the store
    transaction id. Creates the audit order keyed by provider_trade_no (UNIQUE),
    then settles it via wallet_credit_topup. Safe to call repeatedly for the same
    transaction (restore / retry) — never double-credits."""
    existing = conn.execute(
        "SELECT order_no FROM wallet_topup_orders WHERE payment_provider = ? AND provider_trade_no = ? LIMIT 1",
        (provider, provider_trade_no),
    ).fetchone()
    if existing:
        order_no = existing["order_no"]
    else:
        try:
            order = create_wallet_topup_order(conn, user_id, pack, provider, client_type,
                                              provider_product_id=provider_product_id,
                                              provider_trade_no=provider_trade_no)
            order_no = order["order_no"]
        except sqlite3.IntegrityError:
            # Concurrent verify created the order first — settle that one.
            row = conn.execute(
                "SELECT order_no FROM wallet_topup_orders WHERE payment_provider = ? AND provider_trade_no = ? LIMIT 1",
                (provider, provider_trade_no),
            ).fetchone()
            order_no = row["order_no"] if row else ""
    if not order_no:
        return {"applied": False, "wallet": get_wallet_snapshot(conn, user_id), "grantedPoints": 0}
    return wallet_credit_topup(conn, order_no, provider_trade_no=provider_trade_no,
                               provider_user_id=provider_user_id, source_type=provider)


@money_atomic
def wallet_credit_topup(conn: sqlite3.Connection, order_no: str, *, provider_trade_no: str = "",
                        provider_user_id: str = "", source_type: str = "") -> dict[str, Any]:
    """Settle a top-up order and credit its points EXACTLY ONCE. The grant is
    gated on winning the pending→paid transition (rowcount==1), so a webhook
    and a client-side confirm racing on the same order never double-credit."""
    row = conn.execute("SELECT * FROM wallet_topup_orders WHERE order_no = ?", (order_no,)).fetchone()
    if not row:
        return {"applied": False, "duplicate": False, "reason": "order_not_found", "order": None, "wallet": None}
    order = dict(row)
    if order["status"] in ("paid", "fulfilled"):
        return {"applied": False, "duplicate": True, "order": serialize_wallet_topup_order(order),
                "wallet": get_wallet_snapshot(conn, order["user_id"]),
                "grantedPoints": int(order["total_points"] or 0)}
    # 'closed' = auto-expired-but-unpaid (20-min janitor). A real top-up payment
    # that lands afterwards must still credit, so accept closed→paid as well.
    if order["status"] not in ("pending", "closed"):
        return {"applied": False, "duplicate": False, "reason": "order_not_payable",
                "order": serialize_wallet_topup_order(order),
                "wallet": get_wallet_snapshot(conn, order["user_id"])}
    now = now_iso()
    cur = conn.execute(
        "UPDATE wallet_topup_orders SET status = 'paid', "
        "provider_trade_no = COALESCE(NULLIF(?, ''), provider_trade_no), "
        "provider_user_id = COALESCE(NULLIF(?, ''), provider_user_id), "
        "paid_at = ?, fulfilled_at = ?, updated_at = ? WHERE order_no = ? AND status IN ('pending', 'closed')",
        (provider_trade_no or "", provider_user_id or "", now, now, now, order_no),
    )
    if cur.rowcount != 1:
        fresh = dict(conn.execute("SELECT * FROM wallet_topup_orders WHERE order_no = ?", (order_no,)).fetchone())
        return {"applied": False, "duplicate": True, "order": serialize_wallet_topup_order(fresh),
                "wallet": get_wallet_snapshot(conn, order["user_id"]),
                "grantedPoints": int(order["total_points"] or 0)}
    src = source_type or order["payment_provider"] or "topup"
    idem = f"topup:{order_no}"
    wallet_post_ledger(conn, order["user_id"], "topup", int(order["points"] or 0), source_type=src,
                       source_order_id=order_no, source_transaction_id=provider_trade_no or "",
                       idempotency_key=idem, metadata={"packKey": order["pack_key"]})
    bonus = int(order["bonus_points"] or 0)
    if bonus > 0:
        wallet_post_ledger(conn, order["user_id"], "bonus", bonus, source_type=src,
                           source_order_id=order_no, idempotency_key=idem + ":bonus",
                           metadata={"packKey": order["pack_key"]})
    fresh = dict(conn.execute("SELECT * FROM wallet_topup_orders WHERE order_no = ?", (order_no,)).fetchone())
    return {"applied": True, "duplicate": False, "order": serialize_wallet_topup_order(fresh),
            "wallet": get_wallet_snapshot(conn, order["user_id"]),
            "grantedPoints": int(order["total_points"] or 0)}


@money_atomic
def wallet_refund_topup(conn: sqlite3.Connection, order_no: str, *, reason: str = "", entry_type: str = "chargeback_debit") -> dict[str, Any]:
    """Reverse a settled top-up (Stripe refund / chargeback). Claws back the
    granted points. If the user already spent some, we never force the live
    balance negative — we debit what's left and put the wallet into 'restricted'
    with the residual debt recorded in metadata for manual follow-up."""
    row = conn.execute("SELECT * FROM wallet_topup_orders WHERE order_no = ?", (order_no,)).fetchone()
    if not row:
        return {"applied": False, "reason": "order_not_found"}
    order = dict(row)
    if order["status"] in ("refunded", "chargeback"):
        return {"applied": False, "duplicate": True}
    user_id = order["user_id"]
    granted = int(order["total_points"] or 0)
    now = now_iso()
    new_status = "chargeback" if entry_type == "chargeback_debit" else "refunded"
    cur = conn.execute(
        "UPDATE wallet_topup_orders SET status = ?, refunded_at = ?, updated_at = ? "
        "WHERE order_no = ? AND status IN ('paid','fulfilled')",
        (new_status, now, now, order_no))
    if cur.rowcount != 1:
        return {"applied": False, "duplicate": True}
    balance = int(dict(conn.execute("SELECT balance_points FROM wallet_accounts WHERE user_id = ?", (user_id,)).fetchone() or {"balance_points": 0}).get("balance_points") or 0)
    debit = min(balance, granted)
    if debit > 0:
        wallet_post_ledger(conn, user_id, entry_type, -debit, source_type="refund", source_order_id=order_no,
                           idempotency_key=f"refund:{order_no}", metadata={"reason": reason, "granted": granted})
    debt = granted - debit
    if debt > 0:
        # Restrict the wallet until the residual debt is resolved; no negative balance.
        conn.execute("UPDATE wallet_accounts SET status = 'restricted', updated_at = ? WHERE user_id = ?", (now, user_id))
        wallet_post_ledger(conn, user_id, "reversal", 0, source_type="refund", source_order_id=order_no,
                           idempotency_key=f"refund-debt:{order_no}",
                           metadata={"reason": reason, "debtPoints": debt, "note": "wallet restricted pending resolution"})
    return {"applied": True, "clawedBack": debit, "debtPoints": debt, "wallet": get_wallet_snapshot(conn, user_id)}


@money_atomic
def refund_guide_points_order(conn: sqlite3.Connection, order_id_or_no: str, *, reason: str = "") -> dict[str, Any]:
    """Refund a guide purchase: revoke the entitlement and (for points-paid
    orders) credit the points back. Works for any provider — a money-paid
    (Stripe) order has price_points=0 so only the entitlement is revoked (the
    money refund is the provider's job). Idempotent on the refunded state."""
    row = conn.execute(
        "SELECT * FROM guide_orders WHERE (id = ? OR order_no = ?)",
        (order_id_or_no, order_id_or_no)).fetchone()
    if not row:
        return {"applied": False, "reason": "order_not_found"}
    order = dict(row)
    if order["status"] == "refunded":
        return {"applied": False, "duplicate": True}
    now = now_iso()
    cur = conn.execute(
        "UPDATE guide_orders SET status = 'refunded', refunded_at = ?, fulfilled_at = fulfilled_at WHERE id = ? AND status != 'refunded'",
        (now, order["id"]))
    if cur.rowcount != 1:
        return {"applied": False, "duplicate": True}
    prod = conn.execute("SELECT * FROM guide_products WHERE id = ?", (order["product_id"],)).fetchone()
    resource_type = _guide_product_resource_type(dict(prod)) if prod else "guide_product"
    revoke_user_entitlement(conn, order["user_id"], resource_type, order["product_id"], reason=reason or "refund")
    # BE4: a refunded buyer no longer stands behind the product — retract their
    # published review from the aggregate (score no longer counts) and mark it
    # withdrawn so it drops off the product page. CAS so a double refund callback
    # subtracts at most once. Non-published reviews just get marked, no aggregate
    # touch. Best-effort — a review-reclaim miss never blocks the money refund.
    try:
        rev = conn.execute(
            "SELECT id, rating, status FROM guide_reviews WHERE user_id = ? AND product_id = ?",
            (order["user_id"], order["product_id"])).fetchone()
        if rev and rev["status"] not in ("withdrawn", "rejected"):
            cur2 = conn.execute(
                "UPDATE guide_reviews SET status = 'withdrawn', updated_at = ? WHERE id = ? AND status != 'withdrawn'",
                (now, rev["id"]))
            if cur2.rowcount == 1 and rev["status"] == "published":
                apply_review_to_aggregate(conn, order["product_id"], -1, -int(rev["rating"] or 0))
    except Exception:
        ERR_LOG.warning("refund review reclaim failed order=%s", order.get("id"))
    points = int(order["price_points"] or 0)
    if points > 0:
        wallet_post_ledger(conn, order["user_id"], "refund_credit", points, source_type="refund",
                           source_order_id=order["id"], product_id=order["product_id"],
                           idempotency_key=f"guide-refund:{order['id']}", metadata={"reason": reason})
    return {"applied": True, "refundedPoints": points, "wallet": get_wallet_snapshot(conn, order["user_id"])}


# ---- generic entitlements (own a guide product / file / member resource …) ----

def user_has_entitlement(conn: sqlite3.Connection, user_id: str, resource_type: str, resource_id: str) -> bool:
    return conn.execute(
        "SELECT 1 FROM user_entitlements WHERE user_id = ? AND resource_type = ? AND resource_id = ? "
        "AND status = 'active' LIMIT 1",
        (user_id, resource_type, resource_id),
    ).fetchone() is not None


def grant_user_entitlement(conn: sqlite3.Connection, user_id: str, resource_type: str, resource_id: str, *,
                           entitlement_type: str = "own", source_type: str = "", source_order_id: str = "",
                           source_ledger_id: str = "", metadata: dict | None = None) -> dict[str, Any]:
    existing = conn.execute(
        "SELECT * FROM user_entitlements WHERE user_id = ? AND resource_type = ? AND resource_id = ? "
        "AND entitlement_type = ? AND status = 'active' LIMIT 1",
        (user_id, resource_type, resource_id, entitlement_type),
    ).fetchone()
    if existing:
        return dict(existing)
    now = now_iso()
    ent_id = str(uuid.uuid4())
    try:
        conn.execute(
            "INSERT INTO user_entitlements (id, user_id, resource_type, resource_id, entitlement_type, status, "
            "source_type, source_order_id, source_ledger_id, granted_at, metadata_json, created_at, updated_at) "
            "VALUES (?, ?, ?, ?, ?, 'active', ?, ?, ?, ?, ?, ?, ?)",
            (ent_id, user_id, resource_type, resource_id, entitlement_type, source_type or "",
             source_order_id or "", source_ledger_id or "", now,
             json.dumps(metadata or {}, ensure_ascii=False), now, now),
        )
    except sqlite3.IntegrityError:
        # Concurrent grant won the unique-active race — return the live row.
        row = conn.execute(
            "SELECT * FROM user_entitlements WHERE user_id = ? AND resource_type = ? AND resource_id = ? "
            "AND entitlement_type = ? AND status = 'active' LIMIT 1",
            (user_id, resource_type, resource_id, entitlement_type),
        ).fetchone()
        return dict(row) if row else {}
    return dict(conn.execute("SELECT * FROM user_entitlements WHERE id = ?", (ent_id,)).fetchone())


def revoke_user_entitlement(conn: sqlite3.Connection, user_id: str, resource_type: str, resource_id: str, *,
                            entitlement_type: str = "own", reason: str = "") -> None:
    now = now_iso()
    conn.execute(
        "UPDATE user_entitlements SET status = 'revoked', revoked_at = ?, "
        "metadata_json = ?, updated_at = ? "
        "WHERE user_id = ? AND resource_type = ? AND resource_id = ? AND entitlement_type = ? AND status = 'active'",
        (now, json.dumps({"reason": reason}, ensure_ascii=False), now,
         user_id, resource_type, resource_id, entitlement_type),
    )


def compute_product_points_price(conn: sqlite3.Connection, user_id: str, product_row: dict[str, Any]) -> int:
    """The points price for THIS user (member price when they hold an active
    membership and a member points price is set). Always server-side."""
    d = dict(product_row)
    base = int(d.get("wallet_price_points") or 0)
    member = int(d.get("member_wallet_price_points") or 0)
    if member > 0 and has_active_membership(conn, user_id):
        return member
    return base


def _guide_product_resource_type(product_row: dict[str, Any]) -> str:
    return str(dict(product_row).get("entitlement_type") or "guide_product")


@money_atomic
def wallet_debit_for_product(conn: sqlite3.Connection, user_id: str, product_row: dict[str, Any], *,
                             idempotency_key: str = "") -> dict[str, Any]:
    """Spend Machi Points on a guide product: debit the wallet, create a
    fulfilled guide_order, grant the entitlement. Returns a status dict with
    one of: already_owned / insufficient / fulfilled. The whole debit→order→
    grant runs as ONE transaction (@money_atomic) so a crash mid-sequence can't
    leave points spent with no entitlement; never overdraws; if a concurrent
    purchase wins the entitlement race the points are refunded so the user is
    never charged for nothing."""
    d = dict(product_row)
    resource_type = _guide_product_resource_type(d)
    resource_id = str(d.get("id"))
    price = compute_product_points_price(conn, user_id, d)

    if user_has_entitlement(conn, user_id, resource_type, resource_id):
        snap = get_wallet_snapshot(conn, user_id)
        return {"status": "already_owned", "wallet": snap, "order": None, "entitlement": None,
                "requiredPoints": price, "currentBalance": snap["balancePoints"]}

    ledger_entry_id = ""
    if price > 0:
        # ALWAYS namespace the spend key by user + product. Using the raw
        # client-supplied idempotency_key directly let an attacker reuse one key
        # across DIFFERENT products: the 2nd debit deduped (no points removed) yet
        # the 2nd product's entitlement was still granted = free purchase. Scoping
        # by resource_id keeps genuine same-product retries idempotent while making
        # cross-product key reuse harmless.
        client_key = (idempotency_key or "").strip()
        spend_key = f"spend:{user_id}:{resource_id}:" + (client_key or uuid.uuid4().hex[:10])
        result = wallet_post_ledger(conn, user_id, "spend", -price, source_type="wallet_purchase",
                                    product_id=resource_id, idempotency_key=spend_key,
                                    metadata={"productTitle": d.get("title")})
        if result.get("insufficient"):
            snap = result["wallet"]
            return {"status": "insufficient", "wallet": snap, "order": None, "entitlement": None,
                    "requiredPoints": price, "currentBalance": snap["balancePoints"]}
        ledger_entry_id = (result.get("entry") or {}).get("id") or ""

    now = now_iso()
    order_id = str(uuid.uuid4())
    order_no = _wallet_order_no()
    currency = d.get("currency") or "CNY"
    conn.execute(
        "INSERT INTO guide_orders (id, user_id, product_id, order_no, price, currency, status, payment_provider, "
        "payment_method, price_points, wallet_ledger_entry_id, created_at, paid_at, fulfilled_at) "
        "VALUES (?, ?, ?, ?, 0, ?, 'fulfilled', 'wallet', 'wallet_points', ?, ?, ?, ?, ?)",
        (order_id, user_id, resource_id, order_no, currency, price, ledger_entry_id, now, now, now),
    )
    ent = grant_user_entitlement(conn, user_id, resource_type, resource_id, source_type="wallet_order",
                                 source_order_id=order_id, source_ledger_id=ledger_entry_id,
                                 metadata={"orderNo": order_no, "pricePoints": price})
    # If the returned entitlement was granted by a DIFFERENT order, a concurrent
    # purchase of the same product won the unique-active race. We already
    # debited, so refund those points and void this order — never charge twice.
    if price > 0 and ent and ent.get("source_order_id") and ent.get("source_order_id") != order_id:
        wallet_post_ledger(conn, user_id, "refund_credit", price, source_type="refund",
                           source_order_id=order_id, product_id=resource_id,
                           idempotency_key=f"dup-refund:{order_id}", metadata={"reason": "duplicate_purchase"})
        conn.execute("UPDATE guide_orders SET status = 'refunded', refunded_at = ? WHERE id = ?", (now, order_id))
        snap = get_wallet_snapshot(conn, user_id)
        return {"status": "already_owned", "wallet": snap, "order": None, "entitlement": None,
                "requiredPoints": price, "currentBalance": snap["balancePoints"]}
    conn.execute("UPDATE guide_orders SET entitlement_id = ? WHERE id = ?", (ent.get("id") or "", order_id))
    conn.execute("UPDATE guide_products SET purchase_count = purchase_count + 1 WHERE id = ?", (resource_id,))
    order_row = dict(conn.execute("SELECT * FROM guide_orders WHERE id = ?", (order_id,)).fetchone())
    snap = get_wallet_snapshot(conn, user_id)
    return {"status": "fulfilled", "wallet": snap, "order": order_row, "orderId": order_id,
            "orderNo": order_no, "entitlement": ent, "ledgerEntryId": ledger_entry_id,
            "requiredPoints": price, "currentBalance": snap["balancePoints"]}


def ensure_wallet_schema(conn: sqlite3.Connection) -> None:
    """Idempotently seed the default Machi Points top-up packs. The tables
    themselves come from SCHEMA (fresh SQLite, run every boot) and migration 73
    (PostgreSQL); this only inserts the packs that don't exist yet."""
    now = now_iso()
    for idx, (pack_key, title, subtitle, points, bonus, amount_cents, currency) in enumerate(WALLET_TOPUP_SEED):
        if conn.execute("SELECT 1 FROM wallet_topup_products WHERE pack_key = ?", (pack_key,)).fetchone():
            continue
        conn.execute(
            "INSERT INTO wallet_topup_products (id, pack_key, title, subtitle, points, bonus_points, amount_cents, "
            "currency, apple_product_id, ios_iap_product_id, google_product_id, sort_order, is_active, created_at, "
            "updated_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 1, ?, ?)",
            (str(uuid.uuid4()), pack_key, title, subtitle, points, bonus, amount_cents, currency,
             pack_key, pack_key, pack_key, idx, now, now),
        )


# ---- provider client params (what the client needs to start paying) ----

def _mock_pay_url(order_no: str) -> str:
    # A dev-only link the Web mock-confirm button can call. Only created
    # when PAYMENT_MOCK_ENABLED and not in production.
    return f"/api/payments/mock/confirm?order_no={order_no}"


def wechat_miniapp_configured() -> bool:
    return bool(WECHAT_MINIAPP_APPID and WECHAT_MINIAPP_SECRET)


def wechat_code2session(code: str) -> dict[str, Any]:
    """Exchange a wx.login() code for {openid, unionid, session_key} via the
    WeChat sns/jscode2session endpoint. Server-side only — the appsecret never
    leaves the backend. Raises APIError on any failure with a stable code so
    the mini-program can branch on it. The session_key is returned to the
    caller for the duration of the request but is never persisted or logged."""
    if not wechat_miniapp_configured():
        raise APIError("微信登录尚未开放", 503, "wechat_login_unconfigured")
    code = (code or "").strip()
    if not code:
        raise APIError("缺少微信登录凭证", 400, "wechat_code_missing")
    params = urllib.parse.urlencode({
        "appid": WECHAT_MINIAPP_APPID,
        "secret": WECHAT_MINIAPP_SECRET,
        "js_code": code,
        "grant_type": "authorization_code",
    })
    url = f"https://api.weixin.qq.com/sns/jscode2session?{params}"
    try:
        req = urllib.request.Request(url, method="GET")
        with urllib.request.urlopen(req, timeout=8) as resp:
            payload = json.loads(resp.read().decode("utf-8") or "{}")
    except urllib.error.URLError:
        raise APIError("无法连接微信登录服务，请稍后重试", 503, "wechat_login_unavailable")
    except (ValueError, TimeoutError):
        raise APIError("微信登录服务响应异常，请稍后重试", 502, "wechat_login_bad_response")
    errcode = int(payload.get("errcode") or 0)
    if errcode != 0 or not payload.get("openid"):
        # Do NOT surface WeChat's raw errmsg to clients (may leak internals);
        # log the code server-side only.
        ERR_LOG.warning("wechat code2session failed errcode=%s", errcode)
        raise APIError("微信登录失败，请重新进入小程序", 401, "wechat_login_rejected")
    return {
        "openid": str(payload.get("openid") or ""),
        "unionid": str(payload.get("unionid") or ""),
        "session_key": str(payload.get("session_key") or ""),
    }


# --- WeChat content security (内容安全) for mini-program-submitted UGC ---
# Required for a UGC mini-program to pass review. We cache a single
# access_token (~2h TTL) and call wxa/msg_sec_check v2 (synchronous, text).
# Image check (media_check_async) is asynchronous via message-push callback;
# we expose a hook but leave the callback wiring to deployment (needs the
# message-push URL + token configured in mp.weixin.qq.com).
_WECHAT_TOKEN_LOCK = threading.Lock()
_WECHAT_TOKEN_CACHE: dict[str, Any] = {"token": "", "expires_at": 0.0}


def _wechat_access_token() -> str:
    """Fetch + cache the mini-program access_token. Returns '' if unconfigured."""
    if not wechat_miniapp_configured():
        return ""
    now = time.time()
    with _WECHAT_TOKEN_LOCK:
        if _WECHAT_TOKEN_CACHE["token"] and _WECHAT_TOKEN_CACHE["expires_at"] > now + 60:
            return str(_WECHAT_TOKEN_CACHE["token"])
    params = urllib.parse.urlencode({
        "grant_type": "client_credential",
        "appid": WECHAT_MINIAPP_APPID,
        "secret": WECHAT_MINIAPP_SECRET,
    })
    try:
        req = urllib.request.Request(f"https://api.weixin.qq.com/cgi-bin/token?{params}", method="GET")
        with urllib.request.urlopen(req, timeout=8) as resp:
            data = json.loads(resp.read().decode("utf-8") or "{}")
    except Exception:
        ERR_LOG.warning("wechat access_token fetch failed")
        return ""
    token = str(data.get("access_token") or "")
    if token:
        with _WECHAT_TOKEN_LOCK:
            _WECHAT_TOKEN_CACHE["token"] = token
            _WECHAT_TOKEN_CACHE["expires_at"] = now + float(data.get("expires_in") or 7200)
    return token


def wechat_text_sec_check(text: str, openid: str) -> bool:
    """Return True if the text is safe (or check unavailable/unconfigured —
    fail-open so the existing human moderation remains the backstop and a
    WeChat outage never blocks all posting). Returns False only on an explicit
    risky verdict (label != 100 / suggest == 'risky')."""
    text = (text or "").strip()
    if not text or not openid:
        return True
    token = _wechat_access_token()
    if not token:
        return True
    body = json.dumps({
        "version": 2,
        "scene": 2,  # 2 = 评论/发帖类
        "openid": openid,
        "content": text[:2500],
    }, ensure_ascii=False).encode("utf-8")
    try:
        req = urllib.request.Request(
            f"https://api.weixin.qq.com/wxa/msg_sec_check?access_token={token}",
            data=body, method="POST", headers={"Content-Type": "application/json"},
        )
        with urllib.request.urlopen(req, timeout=8) as resp:
            data = json.loads(resp.read().decode("utf-8") or "{}")
    except Exception:
        ERR_LOG.warning("wechat msg_sec_check unavailable")
        return True
    errcode = int(data.get("errcode") or 0)
    if errcode != 0:
        # 87014 = risky content detected
        if errcode == 87014:
            return False
        return True  # other errors (token/quota) — don't hard-block
    result = data.get("result") or {}
    return str(result.get("suggest") or "pass") != "risky"


def wechat_user_openid(conn: sqlite3.Connection, user_id: str) -> str:
    row = conn.execute(
        "SELECT openid FROM miniapp_openid_bindings WHERE user_id = ? AND platform = 'wechat' ORDER BY last_login_at DESC LIMIT 1",
        (user_id,),
    ).fetchone()
    return str(row["openid"]) if row else ""


def build_wechat_payment(conn: sqlite3.Connection, order: dict[str, Any]) -> dict[str, Any]:
    """Return the params a Web client needs to pay an order via WeChat
    (Native = a QR code). When merchant creds are present the real v3
    Native API is called; otherwise dev mock, else a clear config error."""
    if not ENABLE_CN_WEB_PAY:
        raise APIError("当前不支持该支付方式", 503, "provider_unconfigured")
    if WECHAT_PAY_MCH_ID and WECHAT_PAY_APP_ID and WECHAT_PAY_PRIVATE_KEY and WECHAT_PAY_API_V3_KEY:
        code_url = _wechat_native_prepay(order)  # real server-to-server call
        return {"qr_code_url": code_url}
    if PAYMENT_MOCK_ENABLED:
        return {"qr_code_url": _mock_pay_url(order["order_no"]), "mock": True}
    raise APIError("微信支付尚未完成商户配置", 503, "provider_unconfigured")


def build_alipay_payment(conn: sqlite3.Connection, order: dict[str, Any]) -> dict[str, Any]:
    """Return the params a Web client needs to pay via Alipay (a signed
    redirect URL to the Alipay gateway — page/wap pay needs no S2S call)."""
    if not ENABLE_CN_WEB_PAY:
        raise APIError("当前不支持该支付方式", 503, "provider_unconfigured")
    if ALIPAY_APP_ID and ALIPAY_PRIVATE_KEY:
        return {"pay_url": _alipay_page_pay_url(order)}
    if PAYMENT_MOCK_ENABLED:
        return {"pay_url": _mock_pay_url(order["order_no"]), "mock": True}
    raise APIError("支付宝尚未完成商户配置", 503, "provider_unconfigured")


def wechat_pay_configured() -> bool:
    return bool(WECHAT_PAY_MCH_ID and WECHAT_PAY_APP_ID and WECHAT_PAY_PRIVATE_KEY and WECHAT_PAY_API_V3_KEY)


def alipay_configured() -> bool:
    return bool(ALIPAY_APP_ID and ALIPAY_PRIVATE_KEY)


def stripe_configured() -> bool:
    return bool(STRIPE_SECRET_KEY)


def available_payment_providers() -> list[str]:
    """Which Web providers the client should offer. A provider is shown if
    its real credentials are present, or if dev mock mode is on. Lets the
    membership page hide WeChat until the 服务号 appid + APIv3 key land."""
    out: list[str] = []
    # CN card rails are hidden unless explicitly enabled (iOS-first launch).
    if ENABLE_CN_WEB_PAY and (wechat_pay_configured() or PAYMENT_MOCK_ENABLED):
        out.append("wechat_pay")
    if ENABLE_CN_WEB_PAY and (alipay_configured() or PAYMENT_MOCK_ENABLED):
        out.append("alipay")
    if stripe_configured() or PAYMENT_MOCK_ENABLED:
        out.append("stripe")
    return out


def build_stripe_payment(conn: sqlite3.Connection, order: dict[str, Any]) -> dict[str, Any]:
    """Create a Stripe hosted Checkout Session (one-time payment) and
    return its redirect URL. Stripe-hosted page handles payment UI / PCI.
    Membership opens later from a server-verified Checkout Session/webhook,
    never from a client-only success redirect."""
    plan = get_plan(conn, order.get("plan_key") or "")
    if STRIPE_SECRET_KEY:
        return {"pay_url": _stripe_checkout_url(order, plan)}
    if PAYMENT_MOCK_ENABLED:
        return {"pay_url": _mock_pay_url(order["order_no"]), "mock": True}
    raise APIError("Stripe 尚未完成配置", 503, "provider_unconfigured")


def _stripe_checkout_url(order: dict[str, Any], plan: dict[str, Any] | None = None) -> str:
    """POST to Stripe /v1/checkout/sessions (form-encoded, Bearer secret).
    No SDK needed. Returns the hosted Checkout URL. The success_url carries
    the Checkout session id so the client can confirm the payment on return
    (works with just the secret key — no webhook required)."""
    from urllib.parse import urlencode
    from urllib.request import Request, urlopen
    sep = "&" if "?" in STRIPE_SUCCESS_URL else "?"
    success_url = f"{STRIPE_SUCCESS_URL}{sep}stripe_session={{CHECKOUT_SESSION_ID}}"
    plan_name = (plan or {}).get("name") or (plan or {}).get("name_zh") or "Machi Verified"
    fields = {
        "mode": "payment",
        "success_url": success_url,
        "cancel_url": STRIPE_CANCEL_URL,
        "client_reference_id": order["order_no"],
        "metadata[order_no]": order["order_no"],
        "metadata[plan_key]": order.get("plan_key") or "",
        "metadata[kind]": "membership_purchase",
        "line_items[0][quantity]": "1",
        "line_items[0][price_data][currency]": str(order["currency"]).lower(),
        "line_items[0][price_data][unit_amount]": str(_stripe_minor_units(int(order["amount_cents"]), order["currency"])),
        "line_items[0][price_data][product_data][name]": str(plan_name),
    }
    data = urlencode(fields).encode("utf-8")
    req = Request("https://api.stripe.com/v1/checkout/sessions", data=data, method="POST")
    req.add_header("Authorization", "Bearer " + STRIPE_SECRET_KEY)
    req.add_header("Content-Type", "application/x-www-form-urlencoded")
    try:
        with urlopen(req, timeout=10) as resp:
            session = json.loads(resp.read().decode("utf-8"))
        return session["url"]
    except Exception as exc:
        ERR_LOG.warning("stripe checkout create failed: %s", type(exc).__name__)
        raise APIError("Stripe 下单失败", 502, "provider_error")


