def send_verification_email(to: str, code: str, purpose: str, locale: str = "zh") -> bool:
    locale = locale if locale in ("zh", "en", "ja") else "zh"
    templates = _CODE_EMAIL_TEMPLATES.get(purpose) or _CODE_EMAIL_TEMPLATES["register"]
    subject, body_tpl = templates.get(locale) or templates["zh"]
    body = body_tpl.format(code=code, ttl=max(1, EMAIL_CODE_TTL_SEC // 60))
    return send_email(to, subject, body)


# ---- verification code lifecycle (stored hashed, single-use, capped) ----

def _auth_code_recent(conn: sqlite3.Connection, purpose: str, email: str, user_id: str | None) -> sqlite3.Row | None:
    if user_id:
        return conn.execute(
            "SELECT * FROM auth_codes WHERE purpose = ? AND user_id = ? ORDER BY created_at DESC LIMIT 1",
            (purpose, user_id),
        ).fetchone()
    return conn.execute(
        "SELECT * FROM auth_codes WHERE purpose = ? AND email = ? ORDER BY created_at DESC LIMIT 1",
        (purpose, (email or "").lower()),
    ).fetchone()


def issue_auth_code(conn: sqlite3.Connection, *, purpose: str, email: str, ip: str,
                    user_id: str | None = None, locale: str = "zh") -> dict[str, Any]:
    """Generate + store (hashed) + email a fresh code. Enforces a resend
    cooldown and invalidates any prior unconsumed code for the same target.
    Returns metadata only — NEVER the code itself."""
    email_norm = (email or "").lower().strip()
    recent = _auth_code_recent(conn, purpose, email_norm, user_id)
    if recent and not recent["consumed_at"]:
        created = parse_iso(recent["created_at"])
        if created and (datetime.now(timezone.utc) - created).total_seconds() < EMAIL_CODE_RESEND_COOLDOWN_SEC:
            raise APIError("验证码发送过于频繁，请稍后再试", 429, "code_cooldown")
    # Retire older unconsumed codes so only the newest one is valid.
    if user_id:
        conn.execute("UPDATE auth_codes SET consumed_at = ? WHERE purpose = ? AND user_id = ? AND consumed_at IS NULL",
                     (now_iso(), purpose, user_id))
    else:
        conn.execute("UPDATE auth_codes SET consumed_at = ? WHERE purpose = ? AND email = ? AND consumed_at IS NULL",
                     (now_iso(), purpose, email_norm))
    code = generate_numeric_code()
    code_id = str(uuid.uuid4())
    expires = (datetime.now(timezone.utc) + timedelta(seconds=EMAIL_CODE_TTL_SEC)).isoformat()
    conn.execute(
        "INSERT INTO auth_codes (id, purpose, email, user_id, code_hash, created_at, expires_at, attempts, ip) "
        "VALUES (?, ?, ?, ?, ?, ?, ?, 0, ?)",
        (code_id, purpose, email_norm, user_id, hash_auth_code(code, email_norm, purpose),
         now_iso(), expires, (ip or "")[:64]),
    )
    # Send the email WITHOUT holding the global write lock. With a real
    # SMTP / HTTP transport this network call can take seconds; holding
    # DB_LOCK across it would stall every other writer. The verification
    # row is already persisted above (autocommit), so dropping the lock
    # here is safe. No-op release if the caller isn't under the lock.
    with _DBLockReleased():
        sent = send_verification_email(email_norm, code, purpose, locale)
    # `code` goes out of scope here and is never logged or returned.
    return {"challenge_id": code_id, "sent": bool(sent), "expires_in": EMAIL_CODE_TTL_SEC}


def consume_auth_code(conn: sqlite3.Connection, *, purpose: str, email: str = "", code: str = "",
                      challenge_id: str = "", user_id: str | None = None) -> sqlite3.Row:
    """Validate a submitted code in constant time, capping attempts and
    marking the row consumed on success. Raises APIError otherwise."""
    code = (code or "").strip()
    if not code:
        raise APIError("请输入验证码", 400, "invalid_code")
    email_norm = (email or "").lower().strip()
    if challenge_id:
        row = conn.execute("SELECT * FROM auth_codes WHERE id = ? AND purpose = ?", (challenge_id, purpose)).fetchone()
    elif user_id:
        row = conn.execute(
            "SELECT * FROM auth_codes WHERE purpose = ? AND user_id = ? AND consumed_at IS NULL ORDER BY created_at DESC LIMIT 1",
            (purpose, user_id),
        ).fetchone()
    else:
        row = conn.execute(
            "SELECT * FROM auth_codes WHERE purpose = ? AND email = ? AND consumed_at IS NULL ORDER BY created_at DESC LIMIT 1",
            (purpose, email_norm),
        ).fetchone()
    if not row or row["consumed_at"]:
        raise APIError("验证码无效或已过期", 400, "invalid_code")
    expires = parse_iso(row["expires_at"])
    if expires and expires < datetime.now(timezone.utc):
        raise APIError("验证码已过期", 400, "code_expired")
    if int(row["attempts"] or 0) >= EMAIL_CODE_MAX_ATTEMPTS:
        raise APIError("尝试次数过多，请重新获取验证码", 429, "too_many_attempts")
    expected = row["code_hash"]
    actual = hash_auth_code(code, row["email"], purpose)
    if not hmac.compare_digest(expected, actual):
        conn.execute("UPDATE auth_codes SET attempts = attempts + 1 WHERE id = ?", (row["id"],))
        raise APIError("验证码不正确", 400, "invalid_code")
    conn.execute("UPDATE auth_codes SET consumed_at = ? WHERE id = ?", (now_iso(), row["id"]))
    # Return the post-update row so callers see consumed_at set (the row
    # fetched above predates the UPDATE and would still read NULL).
    fresh = conn.execute("SELECT * FROM auth_codes WHERE id = ?", (row["id"],)).fetchone()
    return fresh or row


# ---- image CAPTCHA lifecycle (anonymous-auth bot guard) -------------------
#
# Challenges live in the existing `auth_codes` table under purpose='captcha'
# (hashed answer, TTL, single-use) so both DB backends work with no schema
# migration. One image = exactly one guess: the row is burned on submission
# BEFORE the answer is compared, so a wrong guess can never be retried
# against the same image and the answer can't be brute-forced.

try:
    from PIL import Image as _PILImage, ImageDraw as _PILImageDraw, ImageFont as _PILImageFont, ImageFilter as _PILImageFilter
    CAPTCHA_AVAILABLE = True
except Exception:  # Pillow missing — captcha enforcement degrades to off.
    CAPTCHA_AVAILABLE = False

# Every glyph must survive rotation + noise unambiguously, so confusable
# pairs are dropped entirely: 0/O/Q, 1/I/L, 2/Z, 5/S, 6/G, 8/B.
CAPTCHA_CHARS = "23456789ACDEFHJKMNPRTUVWXY"


# Failed-login tracker backing the "adaptive" login-captcha mode. Process-
# local like the rate limiter (single-process deployment); keys are both
# the client IP and the attempted handle so a bot rotating handles from
# one IP and one targeting a single account from many IPs both trip it.
def _login_failure_keys(ip: str, handle: str = "") -> list[str]:
    keys = []
    if ip:
        keys.append(f"ip:{ip}")
    if handle:
        keys.append(f"handle:{handle}")
    return keys


def record_login_failure(ip: str, handle: str = "") -> None:
    # Backed by the shared FailureTracker so counts hold across workers/hosts
    # (in-process by default; redis when KAIX_REDIS_URL is set).
    tracker = shared_state.get_failure_tracker()
    ttl = max(CAPTCHA_LOGIN_FAIL_WINDOW_SEC, LOGIN_LOCKOUT_WINDOW_SEC)
    for key in _login_failure_keys(ip, handle):
        tracker.record(key, ttl=ttl)


def clear_login_failures(ip: str, handle: str = "") -> None:
    tracker = shared_state.get_failure_tracker()
    for key in _login_failure_keys(ip, handle):
        tracker.clear(key)


def reset_login_failures() -> None:
    """Clear all tracked login-failure state (used by tests)."""
    shared_state.get_failure_tracker().clear_all()


def login_locked_out(ip: str, handle: str = "") -> bool:
    """Hard lockout on top of the adaptive captcha: once an account or IP racks
    up LOGIN_LOCKOUT_THRESHOLD failures inside the window, refuse login outright
    to blunt distributed credential stuffing. 0 disables."""
    if LOGIN_LOCKOUT_THRESHOLD <= 0:
        return False
    tracker = shared_state.get_failure_tracker()
    for key in _login_failure_keys(ip, handle):
        if tracker.count(key, LOGIN_LOCKOUT_WINDOW_SEC) >= LOGIN_LOCKOUT_THRESHOLD:
            return True
    return False


def login_failures_exceeded(ip: str, handle: str = "") -> bool:
    tracker = shared_state.get_failure_tracker()
    for key in _login_failure_keys(ip, handle):
        if tracker.count(key, CAPTCHA_LOGIN_FAIL_WINDOW_SEC) >= CAPTCHA_LOGIN_FAIL_THRESHOLD:
            return True
    return False


def captcha_required_for(scene: str, *, ip: str = "", handle: str = "") -> bool:
    """Whether the given auth scene must present a solved captcha."""
    if not (CAPTCHA_ENABLED and CAPTCHA_AVAILABLE):
        return False
    if scene == "login":
        if CAPTCHA_LOGIN_MODE == "1":
            return True
        if CAPTCHA_LOGIN_MODE == "0":
            return False
        return login_failures_exceeded(ip, handle)
    return True


def _captcha_font(size: int):
    for path in (
        "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf",
        "/usr/share/fonts/dejavu-sans-fonts/DejaVuSans-Bold.ttf",
        "/Library/Fonts/Arial Bold.ttf",
        "/System/Library/Fonts/Supplemental/Arial Bold.ttf",
    ):
        try:
            return _PILImageFont.truetype(path, size)
        except Exception:
            continue
    try:
        # Pillow ≥10.1 bundles a scalable fallback font for load_default(size).
        return _PILImageFont.load_default(size)
    except Exception:
        return _PILImageFont.load_default()


def render_captcha_png(text: str) -> bytes:
    """Distorted-text PNG: per-glyph rotation/jitter + arc and dot noise.
    Rendered at 2x (clients display ~half size) so it stays crisp on
    retina/mobile screens. Solid light background so the image reads fine
    in dark-mode UIs too."""
    s = 2  # supersampling scale
    width, height = (44 * len(text) + 24) * s, 56 * s
    rng = secrets.SystemRandom()
    img = _PILImage.new("RGB", (width, height), (246, 247, 250))
    draw = _PILImageDraw.Draw(img)
    palette = [(31, 41, 75), (88, 28, 96), (12, 74, 110), (124, 45, 18), (6, 78, 59)]
    # Background interference first so glyphs land on top of it.
    for _ in range(4):
        x1, y1 = rng.randint(-20 * s, width), rng.randint(0, height)
        x2, y2 = rng.randint(0, width + 20 * s), rng.randint(0, height)
        draw.arc((min(x1, x2), min(y1, y2) - 20 * s, max(x1, x2) + 30 * s, max(y1, y2) + 20 * s),
                 rng.randint(0, 180), rng.randint(180, 360),
                 fill=rng.choice(palette), width=2 * s)
    for _ in range(width * height // (28 * s)):
        draw.point((rng.randint(0, width - 1), rng.randint(0, height - 1)),
                   fill=(rng.randint(120, 200),) * 3)
    font = _captcha_font(38 * s)
    for i, ch in enumerate(text):
        tile = _PILImage.new("RGBA", (46 * s, 54 * s), (0, 0, 0, 0))
        _PILImageDraw.Draw(tile).text((4 * s, 2 * s), ch, font=font, fill=rng.choice(palette))
        tile = tile.rotate(rng.uniform(-28, 28), expand=True, resample=_PILImage.BICUBIC)
        img.paste(tile, ((10 + i * 44 + rng.randint(-4, 4)) * s, rng.randint(-6, 4) * s), tile)
    img = img.filter(_PILImageFilter.SMOOTH)
    buf = io.BytesIO()
    img.save(buf, format="PNG", optimize=True)
    return buf.getvalue()


def issue_captcha(conn: sqlite3.Connection, ip: str) -> dict[str, Any]:
    """Create a captcha challenge; returns the id + inline PNG data URI.
    The answer is stored hashed only — never logged, never returned."""
    answer = "".join(secrets.choice(CAPTCHA_CHARS) for _ in range(CAPTCHA_LENGTH))
    captcha_id = str(uuid.uuid4())
    now = datetime.now(timezone.utc)
    # Opportunistic purge so abandoned challenges can't bloat the table.
    conn.execute("DELETE FROM auth_codes WHERE purpose = 'captcha' AND expires_at < ?",
                 ((now - timedelta(hours=1)).isoformat(),))
    conn.execute(
        "INSERT INTO auth_codes (id, purpose, email, user_id, code_hash, created_at, expires_at, attempts, ip) "
        "VALUES (?, 'captcha', '', NULL, ?, ?, ?, 0, ?)",
        (captcha_id, hash_auth_code(answer, "", "captcha"), now_iso(),
         (now + timedelta(seconds=CAPTCHA_TTL_SEC)).isoformat(), (ip or "")[:64]),
    )
    png = render_captcha_png(answer)
    return {
        "captcha_id": captcha_id,
        "image": "data:image/png;base64," + base64.b64encode(png).decode("ascii"),
        "expires_in": CAPTCHA_TTL_SEC,
    }


def verify_captcha_or_raise(conn: sqlite3.Connection, *, captcha_id: str, answer: str) -> None:
    """One-shot check. Case-insensitive; consumes the challenge regardless
    of outcome so every retry needs a fresh image."""
    captcha_id = (captcha_id or "").strip()
    answer = (answer or "").strip().upper()
    if not captcha_id or not answer:
        raise APIError("请输入图形验证码", 400, "captcha_required")
    row = conn.execute("SELECT * FROM auth_codes WHERE id = ? AND purpose = 'captcha'",
                       (captcha_id,)).fetchone()
    if not row or row["consumed_at"]:
        raise APIError("图形验证码已失效，请点击图片刷新后重试", 400, "invalid_captcha")
    conn.execute("UPDATE auth_codes SET consumed_at = ?, attempts = attempts + 1 WHERE id = ?",
                 (now_iso(), row["id"]))
    expires = parse_iso(row["expires_at"])
    if expires and expires < datetime.now(timezone.utc):
        raise APIError("图形验证码已过期，请点击图片刷新后重试", 400, "captcha_expired")
    if not hmac.compare_digest(row["code_hash"], hash_auth_code(answer, "", "captcha")):
        raise APIError("图形验证码不正确", 400, "invalid_captcha")


# ---------------------------------------------------------------------------
# visitor analytics: GeoIP resolver + async write path
#
# Logging happens entirely off the request thread via a bounded queue and a
# single background writer, so it never adds latency or DB-lock contention to
# real requests (the codebase deliberately avoids "writes inside a GET").
# ---------------------------------------------------------------------------

_GEO_CACHE: dict[str, tuple[float, dict[str, str]]] = {}
_GEO_LOCK = threading.Lock()
_GEO_TTL = 86400.0
_GEO_EMPTY = {"country": "", "region": "", "city": "", "org": "", "state": "none"}


def _is_public_ip(ip: str) -> bool:
    try:
        addr = ipaddress.ip_address(ip)
    except ValueError:
        return False
    return not (addr.is_private or addr.is_loopback or addr.is_link_local
                or addr.is_reserved or addr.is_multicast or addr.is_unspecified)


def _geo_via_ipapi(ip: str) -> dict[str, str]:
    url = f"http://ip-api.com/json/{ip}?fields=status,country,regionName,city,org"
    req = urllib.request.Request(url, headers={"User-Agent": "machi-backend/1.0"})
    with urllib.request.urlopen(req, timeout=4) as resp:  # noqa: S310
        data = json.loads(resp.read().decode("utf-8"))
    if data.get("status") != "success":
        return {**_GEO_EMPTY, "state": "error"}
    return {
        "country": str(data.get("country") or "")[:80],
        "region": str(data.get("regionName") or "")[:80],
        "city": str(data.get("city") or "")[:80],
        "org": str(data.get("org") or "")[:120],
        "state": "ok",
    }


def _geo_via_maxmind(ip: str) -> dict[str, str]:
    try:
        import geoip2.database  # type: ignore
    except ImportError:
        return {**_GEO_EMPTY, "state": "error"}
    if not GEOIP_MAXMIND_DB:
        return {**_GEO_EMPTY, "state": "error"}
    with geoip2.database.Reader(GEOIP_MAXMIND_DB) as reader:
        resp = reader.city(ip)
        return {
            "country": (resp.country.name or "")[:80],
            "region": (resp.subdivisions.most_specific.name or "")[:80] if resp.subdivisions else "",
            "city": (resp.city.name or "")[:80],
            "org": "",
            "state": "ok",
        }


def resolve_geo(ip: str) -> dict[str, str]:
    if not ip or not _is_public_ip(ip):
        return {**_GEO_EMPTY, "state": "local"}
    now = time.monotonic()
    with _GEO_LOCK:
        hit = _GEO_CACHE.get(ip)
        if hit and (now - hit[0]) < _GEO_TTL:
            return hit[1]
    result = dict(_GEO_EMPTY)
    try:
        if GEOIP_TRANSPORT == "ipapi":
            result = _geo_via_ipapi(ip)
        elif GEOIP_TRANSPORT == "maxmind":
            result = _geo_via_maxmind(ip)
    except Exception:
        result = {**_GEO_EMPTY, "state": "error"}
    with _GEO_LOCK:
        if len(_GEO_CACHE) > 20000:
            _GEO_CACHE.clear()
        _GEO_CACHE[ip] = (now, result)
    return result


_VISIT_QUEUE: "queue.Queue[dict]" = queue.Queue(maxsize=5000)
_VISIT_LAST_SEEN: dict[str, float] = {}
_VISIT_LOCK = threading.Lock()
_VISIT_WRITER_STARTED = False
# Static-asset extensions we never bother logging as "visits".
_VISIT_SKIP_EXT = (".js", ".css", ".map", ".png", ".jpg", ".jpeg", ".gif", ".webp",
                   ".svg", ".ico", ".woff", ".woff2", ".ttf", ".mp4", ".webm", ".txt")


def enqueue_visitor_log(record: dict[str, Any]) -> None:
    """Record one visit (best-effort, non-blocking). Repeated hits from the
    same client inside VISITOR_LOG_DEDUP_SEC collapse to a single row unless
    ``force`` is set (security events always log)."""
    if not VISITOR_LOG_ENABLED:
        return
    ip = record.get("ip") or ""
    now = time.monotonic()
    with _VISIT_LOCK:
        if not record.get("force"):
            last = _VISIT_LAST_SEEN.get(ip, 0.0)
            if (now - last) < VISITOR_LOG_DEDUP_SEC:
                return
        _VISIT_LAST_SEEN[ip] = now
        if len(_VISIT_LAST_SEEN) > 50000:
            cutoff = now - max(VISITOR_LOG_DEDUP_SEC, 600)
            for k, t in list(_VISIT_LAST_SEEN.items()):
                if t < cutoff:
                    _VISIT_LAST_SEEN.pop(k, None)
    try:
        _VISIT_QUEUE.put_nowait(record)
    except queue.Full:
        pass  # analytics are best-effort; never block or buffer unboundedly


def _visitor_writer_loop() -> None:
    while True:
        try:
            first = _VISIT_QUEUE.get()
        except Exception:
            continue
        batch = [first]
        for _ in range(199):
            try:
                batch.append(_VISIT_QUEUE.get_nowait())
            except queue.Empty:
                break
        rows: list[tuple] = []
        for r in batch:
            country = region = city = org = ""
            geo_state = "none"
            if GEOIP_TRANSPORT != "none":
                g = resolve_geo(r.get("ip", ""))
                country, region, city, org, geo_state = g["country"], g["region"], g["city"], g["org"], g["state"]
            rows.append((
                str(uuid.uuid4()), r.get("created_at") or now_iso(), (r.get("ip") or "")[:64],
                (r.get("ip_hash") or "")[:64], (r.get("method") or "")[:8], (r.get("path") or "")[:300],
                int(r.get("status") or 0), r.get("user_id"), (r.get("user_agent") or "")[:300],
                (r.get("referer") or "")[:300], country[:80], region[:80], city[:80], org[:120], geo_state[:16],
            ))
        try:
            with DB_LOCK:
                wconn = db()
                try:
                    wconn.executemany(
                        "INSERT INTO visitor_logs (id, created_at, ip, ip_hash, method, path, status, user_id, "
                        "user_agent, referer, country, region, city, org, geo_state) "
                        "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
                        rows,
                    )
                finally:
                    wconn.close()
        except Exception:
            ERR_LOG.warning("visitor log batch insert failed (%d rows dropped)", len(rows))


def start_visitor_writer() -> None:
    global _VISIT_WRITER_STARTED
    if _VISIT_WRITER_STARTED or not VISITOR_LOG_ENABLED:
        return
    _VISIT_WRITER_STARTED = True
    threading.Thread(target=_visitor_writer_loop, name="visitor-writer", daemon=True).start()


def cleanup_visitor_logs(conn: sqlite3.Connection, days: int) -> int:
    cutoff = (datetime.now(timezone.utc) - timedelta(days=max(0, days))).isoformat()
    cur = conn.execute("DELETE FROM visitor_logs WHERE created_at < ?", (cutoff,))
    return cur.rowcount if cur.rowcount is not None else 0


# ---------------------------------------------------------------------------
# retention janitor.
#
# Three tables only ever grew: visitor_logs had a cleanup function that was
# never scheduled, expired sessions were deleted solely on explicit logout,
# and idempotency_keys replay records (which embed full response bodies)
# were kept forever. At real traffic that is unbounded disk growth plus
# ever-slower scans. One daemon thread sweeps all three on a fixed cadence;
# like the crawler scheduler it is a singleton job, gated by
# KAIX_ENABLE_SCHEDULERS so multi-process deploys run exactly one janitor.
# ---------------------------------------------------------------------------

KAIX_VISITOR_LOG_RETENTION_DAYS = max(1, int(_env("KAIX_VISITOR_LOG_RETENTION_DAYS", "90")))
KAIX_IDEMPOTENCY_TTL_HOURS = max(1, int(_env("KAIX_IDEMPOTENCY_TTL_HOURS", "48")))
KAIX_JANITOR_INTERVAL_SEC = max(300, int(_env("KAIX_JANITOR_INTERVAL_SEC", str(6 * 3600))))
_JANITOR_STARTED = False


def close_expired_unpaid_orders(conn: sqlite3.Connection) -> int:
    """Auto-close abandoned unpaid orders across all three order tables so they
    don't linger in a user's order list. A genuine payment that arrives after an
    order is closed still settles (mark_order_paid / settle_topup tolerate the
    closed state; settle_guide_order ignores non-terminal states) — real money
    always wins. Returns the number of orders closed."""
    now = now_iso()
    created_cutoff = (datetime.now(timezone.utc) - timedelta(seconds=PAYMENT_ORDER_TTL_SEC)).isoformat()
    closed = 0
    # Membership orders carry an explicit expires_at (mirror the existing lazy
    # close in api_order_status, just done proactively here).
    cur = conn.execute(
        "UPDATE payment_orders SET status = 'closed', closed_at = ?, updated_at = ? "
        "WHERE status = 'pending' AND expires_at IS NOT NULL AND expires_at <> '' AND expires_at < ?",
        (now, now, now),
    )
    closed += cur.rowcount or 0
    # Wallet top-up orders have no expires_at column — fall back to created_at + TTL.
    cur = conn.execute(
        "UPDATE wallet_topup_orders SET status = 'closed', updated_at = ? "
        "WHERE status = 'pending' AND created_at < ?",
        (now, created_cutoff),
    )
    closed += cur.rowcount or 0
    # Guide product orders: reuse the existing cancelled state + cancelled_at
    # column (guide_orders has no updated_at column).
    cur = conn.execute(
        "UPDATE guide_orders SET status = 'cancelled', cancelled_at = ? "
        "WHERE status = 'pending' AND created_at < ?",
        (now, created_cutoff),
    )
    closed += cur.rowcount or 0
    return closed


def run_retention_sweep() -> dict[str, int]:
    """One pass of the retention sweeps. Returns per-table delete counts."""
    counts = {"visitor_logs": 0, "sessions": 0, "idempotency_keys": 0, "expired_orders": 0, "saved_search_digests": 0, "post_counters": 0, "follow_digests": 0, "city_digests": 0, "orphan_media": 0}
    with DB_LOCK:
        conn = db()
        try:
            counts["visitor_logs"] = cleanup_visitor_logs(conn, KAIX_VISITOR_LOG_RETENTION_DAYS)
            cur = conn.execute("DELETE FROM sessions WHERE expires_at < ?", (now_iso(),))
            counts["sessions"] = cur.rowcount if cur.rowcount is not None else 0
            idem_cutoff = int(time.time()) - KAIX_IDEMPOTENCY_TTL_HOURS * 3600
            cur = conn.execute(
                "DELETE FROM idempotency_keys WHERE created_epoch > 0 AND created_epoch < ?",
                (idem_cutoff,),
            )
            counts["idempotency_keys"] = cur.rowcount if cur.rowcount is not None else 0
            counts["expired_orders"] = close_expired_unpaid_orders(conn)
            # Daily saved-search digests (cadence='daily'); self-gated to once/~20h per search.
            counts["saved_search_digests"] = run_saved_search_digests(conn)
            # Daily follow / topic digest + inactive-user city recall (B6);
            # each self-gated to once/~20h per user.
            counts["follow_digests"] = run_follow_digests(conn)
            counts["city_digests"] = run_city_digests(conn)
            # Orphan-media GC (B6): bounded batch of never-attached uploads.
            counts["orphan_media"] = run_orphan_media_gc(conn)
            # Self-heal the denormalized post counters from the source tables for
            # the active window. The write sites keep them exact on the common
            # paths; this catches drift from rare bulk operations (e.g. account
            # deletion soft-deleting a user's comments) so ranking never skews.
            counts["post_counters"] = reconcile_post_counters(conn)
            conn.commit()
        finally:
            conn.close()
    return counts


def start_retention_janitor() -> None:
    global _JANITOR_STARTED
    if _JANITOR_STARTED:
        return
    _JANITOR_STARTED = True

    def _loop() -> None:
        # First pass shortly after boot (give migrations/seeds time to
        # settle), then on the configured cadence.
        time.sleep(300)
        while True:
            try:
                counts = run_retention_sweep()
                if any(counts.values()):
                    ACCESS_LOG.info(
                        "retention sweep: visitor_logs=%d sessions=%d idempotency_keys=%d expired_orders=%d "
                        "saved_search_digests=%d follow_digests=%d city_digests=%d orphan_media=%d",
                        counts["visitor_logs"], counts["sessions"], counts["idempotency_keys"],
                        counts.get("expired_orders", 0), counts.get("saved_search_digests", 0),
                        counts.get("follow_digests", 0), counts.get("city_digests", 0),
                        counts.get("orphan_media", 0),
                    )
            except Exception:
                ERR_LOG.exception("retention sweep failed")
            time.sleep(KAIX_JANITOR_INTERVAL_SEC)

    threading.Thread(target=_loop, name="retention-janitor", daemon=True).start()


# ---------------------------------------------------------------------------
# Hot-score refresher — the scalability core of the ranking system.
#
# A single bounded background pass recomputes posts.hot_score for the active
# window so trending / 热搜 read an indexed precomputed column instead of
# sorting a live time-dependent expression. This is what keeps read cost flat
# as QPS grows: the expensive part runs once per minute on ONE worker, not on
# every request. Gated by KAIX_ENABLE_SCHEDULERS so multi-process deploys run
# it exactly once. Pairs with the denormalized counters (migration v85) — those
# removed the per-read COUNT subqueries; this removes the per-read time sort.
# ---------------------------------------------------------------------------
KAIX_HOT_SCORE_INTERVAL_SEC = max(30, int(_env("KAIX_HOT_SCORE_INTERVAL_SEC", "60")))
KAIX_HOT_SCORE_WINDOW_DAYS = max(1, int(_env("KAIX_HOT_SCORE_WINDOW_DAYS", "10")))
HOT_SCORE_DECAY_H = 48.0          # engagement value halves ~every 48h of age
HOT_SCORE_FRESH_WINDOW_H = 12.0   # new-post visibility bonus fades over 12h
HOT_SCORE_FRESH_PEAK = 30.0       # peak freshness bonus (~30 like-points) for a brand-new post
HOT_SCORE_REPORT_PENALTY_CAP = 30.0  # max heat a report barrage can subtract (≈3 reports)
HOT_SCORE_SEED_MULT = 0.6         # seed/simulated content rides below genuine UGC
# 正在发生: a revival counts as "live" (uncapped recency) only while its reviving
# comment is this fresh; past it the revived post's recency is capped at 70 so a
# stale late comment can't pin an ancient thread to the top (see _happening_score_sql).
HAPPENING_LIVE_WINDOW_H = 6.0
_HOT_SCORE_STARTED = False


def refresh_hot_scores(conn: sqlite3.Connection) -> int:
    """Recompute posts.hot_score for the active window in one bounded UPDATE:

        hot_score = engagement * (DECAY / (age_h + DECAY))     # rational decay
                    + FRESH_PEAK * max(0, FRESH_WINDOW - age_h) / FRESH_WINDOW

    The rational decay keeps an engaged post ranking while gently fading with
    age; the freshness term gives a brand-new, zero-engagement post real
    visibility for its first hours (then fades) — that is the lever that lets
    newly-posted content be seen. Portable arithmetic only (no exp/pow), backend
    -branched exactly like the heat SQL. Returns rows touched."""
    now = datetime.now(timezone.utc)
    cutoff = (now - timedelta(days=KAIX_HOT_SCORE_WINDOW_DAYS)).isoformat()
    # Rows created more than ~13h ago no longer have a freshness bonus to update
    # (the bonus fades to 0 over FRESH_WINDOW = 12h); a 1h margin covers the
    # refresh interval so a post crossing 12h still gets its final bonus tick.
    fresh_cutoff = (now - timedelta(hours=HOT_SCORE_FRESH_WINDOW_H + 1.0)).isoformat()
    if KAIX_DB_BACKEND == "postgres":
        boost_cmp = f"boosted_until > '{now_iso()}'"
        hours_since = "EXTRACT(EPOCH FROM (now() - created_at::timestamptz)) / 3600.0"
        max2 = "GREATEST"
        min2 = "LEAST"
    else:
        # See _heat_score_sql: compare boosted_until (ISO 'T' string) against a
        # now_iso() literal, NOT datetime('now') (space-separated), or the lexical
        # compare mis-reads every boost as still active.
        boost_cmp = f"boosted_until > '{now_iso()}'"
        hours_since = "(julianday('now') - julianday(created_at)) * 24.0"
        max2 = "MAX"
        min2 = "MIN"
    # light_boost membership benefit (made real): a verified member's post gets a
    # gentle ×1.05 on its final hot_score. Correlated subquery on the author's
    # is_verified_member — same portable pattern used elsewhere (e.g. the region
    # backfill). Non-members and unknown authors get ×1.0 (no change).
    member_mult = (
        f"(CASE WHEN COALESCE((SELECT is_verified_member FROM users WHERE users.id = posts.author_id), 0) = 1 "
        f"THEN 1.05 ELSE 1.0 END)"
    )
    # Per-author freshness decay: the free "曝光分" (freshness bonus) that lets a
    # brand-new post be seen is halved for each *fresher* post the same author
    # already has inside the freshness window — so an author flooding the feed
    # can't stack full-strength exposure bonuses on every post. n-1 = the count
    # of that author's newer, still-fresh, live posts; the multiplier is
    # 0.5^(n-1). Expressed as a portable CASE ladder (SQLite has no POWER()),
    # saturating near-zero past the 5th concurrent fresh post.
    fresh_newer_by_author = (
        f"(SELECT COUNT(*) FROM posts pp "
        f" WHERE pp.author_id = posts.author_id AND pp.deleted_at IS NULL "
        f"   AND pp.status IN ('published', 'active') "
        f"   AND pp.created_at > posts.created_at AND pp.created_at >= ?)"
    )
    fresh_author_mult = (
        f"(CASE {fresh_newer_by_author} "
        f"WHEN 0 THEN 1.0 WHEN 1 THEN 0.5 WHEN 2 THEN 0.25 "
        f"WHEN 3 THEN 0.125 WHEN 4 THEN 0.0625 ELSE 0.03125 END)"
    )
    # Seed suppression: curated/simulated seed content (is_seed_content=1) rides
    # at 0.6× so genuine UGC out-ranks it on the boards over time. Kept in sync
    # with the same multiplier in _heat_score_sql (the live explore path).
    seed_mult = f"(CASE WHEN COALESCE(is_seed_content, 0) = 1 THEN {HOT_SCORE_SEED_MULT} ELSE 1.0 END)"
    # Engagement-only heat (× decay), WITHOUT the freshness "曝光分". This is what
    # tag heat (热搜) sums, so a flood of brand-new posts under a tag can't inflate
    # it on freshness alone. hot_score adds the freshness term on top; both share
    # this bracket and the member/seed multipliers so they stay consistent.
    #
    # Like/repost/bookmark heat rides weighted_interaction_score (item B3.7), NOT
    # the raw counts: reconcile_post_counters bakes the same kind weights
    # (like×1 + repost×5 + bookmark×4) into that column but with 互刷 marginal
    # decay + a new-account penalty, so a like-ring can't linearly pump the board.
    # The raw counts stay real for DISPLAY. Comments (own table, not the 互刷-prone
    # interactions table) keep their true-count ×3 weight. On a brand-new post the
    # column is 0 until the first reconcile pass — that's fine, the freshness term
    # gives it visibility meanwhile and comments still count immediately.
    engaged_decayed = (
        f"((COALESCE(weighted_interaction_score, 0) * 1.0"
        f" + COALESCE(comment_count, 0) * 3.0"
        f" - {min2}({HOT_SCORE_REPORT_PENALTY_CAP}, COALESCE(report_count, 0) * 10.0)"
        f" + CASE WHEN COALESCE(is_boosted, 0) = 1"
        f"          AND (COALESCE(boosted_until, '') = '' OR {boost_cmp})"
        f"         THEN COALESCE(boost_weight, 0) ELSE 0 END)"
        f" * ({HOT_SCORE_DECAY_H} / ({max2}(0.0, {hours_since}) + {HOT_SCORE_DECAY_H})))"
    )
    freshness_term = (
        f"({HOT_SCORE_FRESH_PEAK} * {max2}(0.0, {HOT_SCORE_FRESH_WINDOW_H} - ({hours_since}))"
        f" / {HOT_SCORE_FRESH_WINDOW_H} * {fresh_author_mult})"
    )
    sql = f"""
        UPDATE posts SET
            hot_score = ({engaged_decayed} + {freshness_term}) * {member_mult} * {seed_mult},
            hot_score_engaged = {engaged_decayed} * {member_mult} * {seed_mult}
        WHERE deleted_at IS NULL
          AND status IN ('published', 'active')
          AND created_at >= ?
          -- Write reduction: only recompute rows whose score can still MOVE this
          -- pass. A row with no engagement, no active freshness bonus, and an
          -- already-negligible hot_score would just be re-written to (nearly) the
          -- same value every minute — pure write amplification on a growing table.
          -- Skip those; they stay at their last value until something engages them.
          AND (COALESCE(like_count, 0) + COALESCE(comment_count, 0)
               + COALESCE(repost_count, 0) + COALESCE(bookmark_count, 0)
               + COALESCE(report_count, 0) > 0
               OR created_at >= ?
               OR COALESCE(hot_score, 0) > 0.1)
    """
    # Param order follows textual position: the fresh-author-rank subquery in the
    # SET clause (fresh_cutoff) precedes the two WHERE bounds (cutoff, fresh_cutoff).
    cur = conn.execute(sql, (fresh_cutoff, cutoff, fresh_cutoff))
    return cur.rowcount or 0


# ---------------------------------------------------------------------------
# 热搜/热榜 rank snapshots (topic_rank_snapshots). Written by the hot-score
# refresher on a ~10 min cadence so rankDelta (this rank vs the previous
# snapshot's) and velocity (this window's heat vs the previous equal-length
# window's) are real instead of hard-coded 0. All queries double-quote the
# reserved-word columns "window" and "rank" (see migration 96).
# ---------------------------------------------------------------------------
KAIX_TOPIC_SNAPSHOT_INTERVAL_SEC = max(60, int(_env("KAIX_TOPIC_SNAPSHOT_INTERVAL_SEC", "600")))
KAIX_TOPIC_SNAPSHOT_RETAIN_DAYS = 7
_TOPIC_SNAPSHOT_WINDOWS = {"2h": 2, "24h": 24, "3d": 72, "7d": 168}
_LAST_TOPIC_SNAPSHOT_AT = 0.0


def _topic_snapshot_scope_key(scope: str, region_key: str) -> str:
    """Composite identity for a board so a snapshot lookup matches the exact
    board a user is viewing. region_key is a region_code / country / 'all'."""
    return f"{scope}:{region_key or 'all'}"


def _capture_topic_rank_for_scope(
    conn: sqlite3.Connection,
    *,
    scope_key: str,
    window: str,
    hours: int,
    country: str,
    captured_at: str,
) -> None:
    """Compute the top-50 tags for one board (national/country level) and append
    them as a snapshot. Same heat definition as api_discover_hot / api_trending
    (SUM(hot_score_engaged), last_activity_at keeps a discussed-now post alive,
    blocklist drops filler tags) so the recorded ranks line up with what those
    endpoints display. Best-effort — a snapshot failure never blocks the refresh."""
    now = datetime.now(timezone.utc)
    cutoff = (now - timedelta(hours=hours)).isoformat()
    block_tags = sorted(HOT_BOARD_TAG_BLOCKLIST)
    block_clause = ("AND t.tag NOT IN (%s)" % ",".join("?" * len(block_tags))) if block_tags else ""
    country_clause = "AND p.country = ?" if country else ""
    params: list[Any] = [cutoff, cutoff]
    if country:
        params.append(country)
    params.extend(block_tags)
    try:
        rows = list(conn.execute(
            f"""
            SELECT t.tag AS tag,
                   CAST(SUM(COALESCE(p.hot_score_engaged, 0)) AS INTEGER) AS heat,
                   COUNT(DISTINCT p.author_id) AS authors
              FROM post_tags t
              JOIN posts p ON p.id = t.post_id
             WHERE p.deleted_at IS NULL AND p.status IN ('published', 'active')
               AND (p.created_at >= ?
                    OR COALESCE(NULLIF(p.last_activity_at, ''), p.created_at) >= ?)
               {country_clause}
               {block_clause}
             GROUP BY t.tag
             ORDER BY heat DESC, authors DESC
             LIMIT 50
            """,
            params,
        ))
    except Exception as exc:
        ERR_LOG.warning("topic snapshot query degraded scope=%s window=%s error=%s", scope_key, window, exc)
        return
    for rank, r in enumerate(rows, 1):
        tag = (r["tag"] or "").strip()
        if not tag:
            continue
        conn.execute(
            'INSERT INTO topic_rank_snapshots (scope, "window", tag, "rank", heat, captured_at) '
            "VALUES (?, ?, ?, ?, ?, ?)",
            (scope_key, window, tag, rank, max(0, int(r["heat"] or 0)), captured_at),
        )


def capture_topic_rank_snapshots(conn: sqlite3.Connection) -> int:
    """One snapshot pass: record the top-50 tags per (scope, window) for the
    national boards that api_trending / api_discover_hot serve at country + 'all'
    granularity, then prune rows older than the retention window. Region-specific
    boards additionally self-snapshot on read (see _record_board_snapshot) so a
    delta exists for exactly the regions people actually view — this refresher
    pass guarantees the always-visible national/global boards have history.
    Returns the number of (scope, window) boards captured."""
    captured_at = now_iso()
    # Countries with live content in the hot window — bounded (a handful), not
    # every possible region. 'all' is the global board api_trending uses when the
    # viewer has no country. Each becomes a national-scope snapshot.
    try:
        countries = [
            (r["country"] or "").strip().lower()
            for r in conn.execute(
                "SELECT DISTINCT country FROM posts "
                "WHERE deleted_at IS NULL AND status IN ('published','active') "
                "AND created_at >= ? AND COALESCE(country,'') <> ''",
                ((datetime.now(timezone.utc) - timedelta(days=7)).isoformat(),),
            )
        ]
    except Exception:
        countries = []
    boards = 0
    scope_targets = [("national", "", "")]  # (scope, region_key, country) for the global board
    for c in countries:
        if c:
            scope_targets.append(("national", c, c))
    for scope, region_key, country in scope_targets:
        scope_key = _topic_snapshot_scope_key(scope, region_key)
        for window, hours in _TOPIC_SNAPSHOT_WINDOWS.items():
            _capture_topic_rank_for_scope(
                conn, scope_key=scope_key, window=window, hours=hours,
                country=country, captured_at=captured_at,
            )
            boards += 1
    # Retention: drop snapshots older than the retention window in the same pass.
    floor = (datetime.now(timezone.utc) - timedelta(days=KAIX_TOPIC_SNAPSHOT_RETAIN_DAYS)).isoformat()
    try:
        conn.execute("DELETE FROM topic_rank_snapshots WHERE captured_at < ?", (floor,))
    except Exception:
        pass
    return boards


def _previous_topic_ranks(conn: sqlite3.Connection, scope_key: str, window: str) -> dict[str, dict[str, int]]:
    """The most recent PRIOR snapshot for a board as {tag: {"rank", "heat"}}.
    'Prior' = the latest single captured_at for this (scope, window). Used to
    compute rankDelta (prev_rank - current_rank) and heat velocity. Returns {}
    when no snapshot exists yet (first run) so callers degrade to delta 0."""
    try:
        last = conn.execute(
            'SELECT MAX(captured_at) AS c FROM topic_rank_snapshots WHERE scope = ? AND "window" = ?',
            (scope_key, window),
        ).fetchone()
    except Exception:
        return {}
    if not last or not last["c"]:
        return {}
    out: dict[str, dict[str, int]] = {}
    for r in conn.execute(
        'SELECT tag, "rank" AS rnk, heat FROM topic_rank_snapshots '
        'WHERE scope = ? AND "window" = ? AND captured_at = ?',
        (scope_key, window, last["c"]),
    ):
        out[r["tag"]] = {"rank": int(r["rnk"] or 0), "heat": int(r["heat"] or 0)}
    return out


def run_topic_rank_snapshot() -> int:
    with DB_LOCK:
        conn = db()
        try:
            n = capture_topic_rank_snapshots(conn)
            conn.commit()
            return n
        finally:
            conn.close()


def reconcile_post_counters(conn: sqlite3.Connection) -> int:
    """Recompute the denormalized engagement counters from the source tables for
    posts in the active window. Cheap to run on a slow cadence (piggybacks the
    retention sweep); keeps the counters honest against drift from rare bulk
    paths. Returns the window size touched (best-effort)."""
    cutoff = (datetime.now(timezone.utc) - timedelta(days=KAIX_HOT_SCORE_WINDOW_DAYS)).isoformat()
    # Exclude self-interactions (i.user_id = posts.author_id) from the three
    # interaction-derived counters — the incremental write path (api_post_interaction)
    # already skips the bump for a self like/收藏/repost, so the reconcile MUST use
    # the same rule or it would silently drift the count back up on every pass.
    conn.execute(
        "UPDATE posts SET like_count = (SELECT COUNT(*) FROM interactions i WHERE i.target_id = posts.id AND i.kind = 'like' AND i.user_id <> posts.author_id) WHERE created_at >= ?",
        (cutoff,),
    )
    conn.execute(
        "UPDATE posts SET repost_count = (SELECT COUNT(*) FROM interactions i WHERE i.target_id = posts.id AND i.kind = 'repost' AND i.user_id <> posts.author_id) WHERE created_at >= ?",
        (cutoff,),
    )
    conn.execute(
        "UPDATE posts SET bookmark_count = (SELECT COUNT(*) FROM interactions i WHERE i.target_id = posts.id AND i.kind = 'bookmark' AND i.user_id <> posts.author_id) WHERE created_at >= ?",
        (cutoff,),
    )
    cur = conn.execute(
        "UPDATE posts SET comment_count = (SELECT COUNT(*) FROM comments c WHERE c.post_id = posts.id AND c.deleted_at IS NULL) WHERE created_at >= ?",
        (cutoff,),
    )
    # Recompute last_activity_at to the latest live comment time, falling back to
    # the post's own created_at when it has no comments (NOT ''). Keeping the
    # column always-populated lets the 正在发生 radar filter+sort on the bare
    # column with an index instead of a per-row COALESCE(NULLIF(...)) expression.
    # Heals drift from comment deletions that left the value pointing at a
    # now-removed comment.
    conn.execute(
        "UPDATE posts SET last_activity_at = COALESCE((SELECT MAX(c.created_at) FROM comments c WHERE c.post_id = posts.id AND c.deleted_at IS NULL), created_at) WHERE created_at >= ?",
        (cutoff,),
    )
    _reconcile_weighted_interaction_score(conn, cutoff)
    return cur.rowcount or 0


def _reconcile_weighted_interaction_score(conn: sqlite3.Connection, window_cutoff: str) -> None:
    """互刷边际递减 (item B3.7): recompute posts.weighted_interaction_score — the
    de-inflated engagement figure hot_score reads for its like/repost/bookmark
    heat. The DISPLAY counters (like_count etc.) stay exact real counts; only the
    heat input is weighted, so a ring of accounts liking each other can't linearly
    pump the board.

    Each non-self like/repost/bookmark contributes:
        kind_heat (like=1, repost=5, bookmark=4)
        × marginal_decay   — the Nth interaction from the SAME user to the SAME
                             author within 30 days: 1.0, 0.5, 0.25, 0.125, then
                             0.0625 (ROW_NUMBER over (user_id, author_id))
        × account_factor   — 0.3 if the interacting account was <48h old at the
                             time of the interaction (fresh sockpuppet), else 1.0

    Interactions are already self-excluded upstream; this stacks cleanly on that
    (the SQL also filters user_id <> author_id). Computed with a window function
    over the last 30 days, aggregated per post in Python for backend portability
    (SQLite + Postgres differ on UPDATE..FROM + window semantics), then written
    back for the posts in the active hot window. Best-effort: any failure leaves
    the last good weights in place (hot_score just uses slightly stale weights)."""
    pair_cutoff = (datetime.now(timezone.utc) - timedelta(days=30)).isoformat()
    if KAIX_DB_BACKEND == "postgres":
        # Account age at interaction time, in hours.
        age_h = "EXTRACT(EPOCH FROM (i.created_at::timestamptz - u.created_at::timestamptz)) / 3600.0"
    else:
        age_h = "(julianday(i.created_at) - julianday(u.created_at)) * 24.0"
    kind_heat = "CASE i.kind WHEN 'like' THEN 1.0 WHEN 'repost' THEN 5.0 WHEN 'bookmark' THEN 4.0 ELSE 0.0 END"
    marginal = (
        "CASE ROW_NUMBER() OVER (PARTITION BY i.user_id, p.author_id ORDER BY i.created_at) "
        "WHEN 1 THEN 1.0 WHEN 2 THEN 0.5 WHEN 3 THEN 0.25 WHEN 4 THEN 0.125 ELSE 0.0625 END"
    )
    # <48h means account age is between 0 and 48h at interaction time; a negative
    # age (clock skew / bad data) is treated as normal (1.0) rather than penalized.
    account_factor = f"CASE WHEN ({age_h}) >= 0 AND ({age_h}) < 48.0 THEN 0.3 ELSE 1.0 END"
    try:
        rows = list(conn.execute(
            f"""
            SELECT pid, COALESCE(SUM(w), 0.0) AS total FROM (
                SELECT i.target_id AS pid,
                       ({kind_heat}) * ({marginal}) * ({account_factor}) AS w
                  FROM interactions i
                  JOIN posts p ON p.id = i.target_id
                  JOIN users u ON u.id = i.user_id
                 WHERE i.kind IN ('like', 'repost', 'bookmark')
                   AND i.user_id <> p.author_id
                   AND i.created_at >= ?
                   AND p.created_at >= ?
            ) sub
            GROUP BY pid
            """,
            (pair_cutoff, window_cutoff),
        ))
    except Exception as exc:
        ERR_LOG.warning("weighted interaction reconcile degraded error=%s", exc)
        return
    # Reset in-window posts to 0 first so a post that lost all its interactions
    # (e.g. un-likes) drops to 0 instead of keeping a stale positive weight, then
    # apply the computed sums. Both statements bounded to the hot window.
    conn.execute(
        "UPDATE posts SET weighted_interaction_score = 0 WHERE created_at >= ?",
        (window_cutoff,),
    )
    for r in rows:
        conn.execute(
            "UPDATE posts SET weighted_interaction_score = ? WHERE id = ?",
            (float(r["total"] or 0.0), r["pid"]),
        )


def run_hot_score_refresh() -> int:
    with DB_LOCK:
        conn = db()
        try:
            n = refresh_hot_scores(conn)
            conn.commit()
            return n
        finally:
            conn.close()


def start_hot_score_refresher() -> None:
    global _HOT_SCORE_STARTED
    if _HOT_SCORE_STARTED:
        return
    _HOT_SCORE_STARTED = True

    def _loop() -> None:
        global _LAST_TOPIC_SNAPSHOT_AT
        # First pass quickly after boot so the board reflects live recency decay
        # within ~15s of a deploy. The migration seeds an engagement-only
        # baseline meanwhile, so the board is never empty in between.
        time.sleep(15)
        while True:
            try:
                run_hot_score_refresh()
                # New hot_scores (incl. recency decay) just landed — bust the
                # public ranking caches so they surface within the refresh
                # cadence instead of an extra ~30s TTL. On redis this is one
                # pub/sub broadcast that refreshes every worker's board at once;
                # in-process it just clears this (scheduler) instance's L1.
                invalidate_public_ranking_caches()
            except Exception:
                ERR_LOG.exception("hot_score refresh failed")
            # Piggyback the 热搜/热榜 rank snapshot on the refresher, but on its own
            # slower cadence (~10 min) — the ranks only need to be sampled often
            # enough for a meaningful delta, not every minute. Runs right after the
            # score refresh so the snapshot reflects the just-updated hot_score.
            now_mono = time.monotonic()
            if now_mono - _LAST_TOPIC_SNAPSHOT_AT >= KAIX_TOPIC_SNAPSHOT_INTERVAL_SEC:
                _LAST_TOPIC_SNAPSHOT_AT = now_mono
                try:
                    run_topic_rank_snapshot()
                except Exception:
                    ERR_LOG.exception("topic rank snapshot failed")
            time.sleep(KAIX_HOT_SCORE_INTERVAL_SEC)

    threading.Thread(target=_loop, name="hot-score-refresher", daemon=True).start()


KAIX_GUIDE_REMINDER_INTERVAL_SEC = max(120, int(_env("KAIX_GUIDE_REMINDER_INTERVAL_SEC", "600")))
_GUIDE_REMINDER_STARTED = False


def run_guide_reminder_dispatch() -> int:
    """One pass of guide reminders: push an APNs alert for every Guide todo whose
    reminder_at has come due (房租到期 / 出愿截止 / 面试 / 考试报名…) and hasn't been
    sent yet. The guide_reminders row (UNIQUE per user+todo) is the sent-ledger,
    so a reminder never fires twice. Only fires reminders from the last 7 days to
    avoid resurrecting ancient ones after a deploy. Best-effort per row."""
    now = now_iso()
    floor = _guide_date_minus(now[:10], 7) or ""
    sent = 0
    with DB_LOCK:
        conn = db()
        try:
            # Driven by guide_reminders rows (one per T-7/T-3/T-1 tier), joined to
            # the todo for its live title/status/due date. status='active' is the
            # not-yet-sent flag, so a tier never fires twice.
            rows = conn.execute(
                "SELECT r.id AS reminder_id, r.user_id, r.plan_id, r.reminder_at, "
                "t.id AS todo_id, t.title, t.due_at, t.todo_type "
                "FROM guide_reminders r JOIN guide_todos t ON t.id = r.todo_id "
                "WHERE r.status = 'active' AND r.reminder_at <> '' AND r.reminder_at <= ? AND r.reminder_at >= ? "
                "AND t.status NOT IN ('done','skipped') "
                "ORDER BY r.reminder_at LIMIT 300",
                (now, floor),
            ).fetchall()
            for r in rows:
                d = dict(r)
                title = (d.get("title") or "Guide 提醒").strip()
                due = (d.get("due_at") or "")[:10]
                days_left = None
                if due:
                    try:
                        days_left = (datetime.fromisoformat(due) - datetime.fromisoformat(now[:10])).days
                    except ValueError:
                        days_left = None
                tier = ""
                if days_left is not None and days_left >= 0:
                    tier = f"还有 {days_left} 天 · " if days_left > 0 else "今天截止 · "
                content = f"⏰ {tier}{title}"
                if due and days_left is None:
                    content += f"（{due} 截止）"
                try:
                    # Dedicated ntype: a deadline alert is fire-once (the
                    # guide_reminders row rolls forward regardless of delivery),
                    # so it must not compete with saved_search/system for the
                    # shared daily push cap. Still quiet-hours muted.
                    server_apns.enqueue(d["user_id"], ntype="guide_reminder", content=content)
                    HUB.publish(d["user_id"], {"type": "notification", "kind": "guide_reminder", "todoId": d["todo_id"]})
                except Exception:
                    pass
                # In-app notification center entry (spec P1).
                try:
                    conn.execute(
                        "INSERT INTO notifications (id, user_id, actor_id, type, content, created_at) "
                        "VALUES (?, ?, ?, 'system', ?, ?)",
                        (str(uuid.uuid4()), d["user_id"], d["user_id"], content, now),
                    )
                except Exception:
                    pass
                # Roll the single reminder row forward to the next tier (T-7 → T-3
                # → T-1); when no later tier remains, mark it sent. (spec P1)
                tiers = _guide_reminder_tier_dates(
                    due, None, (d.get("todo_type") or "") in _GUIDE_MULTI_TIER_TODO_TYPES)
                later = [t for t in tiers if t > (d.get("reminder_at") or "")]
                if later:
                    conn.execute(
                        "UPDATE guide_reminders SET reminder_at = ?, status = 'active', updated_at = ? WHERE id = ?",
                        (later[0], now, d["reminder_id"]),
                    )
                else:
                    conn.execute(
                        "UPDATE guide_reminders SET status = 'sent', updated_at = ? WHERE id = ?",
                        (now, d["reminder_id"]),
                    )
                sent += 1
        finally:
            conn.close()
    return sent


def start_guide_reminder_dispatcher() -> None:
    global _GUIDE_REMINDER_STARTED
    if _GUIDE_REMINDER_STARTED:
        return
    _GUIDE_REMINDER_STARTED = True

    def _loop() -> None:
        time.sleep(120)
        while True:
            try:
                n = run_guide_reminder_dispatch()
                if n:
                    ACCESS_LOG.info("guide reminders dispatched: %d", n)
            except Exception:
                ERR_LOG.exception("guide reminder dispatch failed")
            time.sleep(KAIX_GUIDE_REMINDER_INTERVAL_SEC)

    threading.Thread(target=_loop, name="guide-reminders", daemon=True).start()


# ---------------------------------------------------------------------------
# engagement simulation — seed personas gradually like / 收藏 / comment / follow
# seed content over its first few days, with per-post/per-user randomized
# ceilings and a front-loaded growth curve, so 推荐/热搜/feed look organically
# alive. Counts are live-computed, so inserting raw rows is sufficient. Tunable
# from the admin backend (site_settings engagement_sim_*). Scheduler-gated so it
# runs on exactly one worker.
# ---------------------------------------------------------------------------

KAIX_ENGAGEMENT_SIM_INTERVAL_SEC = max(60, int(_env("KAIX_ENGAGEMENT_SIM_INTERVAL_SEC", "600")))
_ENGAGEMENT_SIM_STARTED = False


def _eng_hash01(*parts: Any) -> float:
    """Stable float in [0,1) from the given parts (deterministic per id)."""
    h = hashlib.sha256("|".join(str(p) for p in parts).encode("utf-8")).hexdigest()
    return int(h[:12], 16) / float(0x1000000000000)


def _eng_range(lo: float, hi: float, *parts: Any) -> float:
    return lo + (hi - lo) * _eng_hash01(*parts)


# A small immediate floor so even brand-new posts show a few likes right away
# (real posts get early traction too); the rest grows over the window.
ENG_BASELINE_FRAC = 0.06
# Max posts that get fresh DeepSeek-generated comments per tick (bounds cost +
# keeps the in-band manual run well under the request timeout).
ENG_AI_COMMENT_POSTS_PER_TICK = 6


def _eng_frac(age_h: float, halflife: float) -> float:
    g = 1.0 - 0.5 ** (age_h / halflife)
    return ENG_BASELINE_FRAC + (1.0 - ENG_BASELINE_FRAC) * g


def _engagement_settings(conn: sqlite3.Connection) -> dict[str, Any]:
    s = _site_settings(conn)

    def _i(k: str, d: int) -> int:
        try:
            return int(float(s.get(k) or d))
        except (TypeError, ValueError):
            return d

    def _f(k: str, d: float) -> float:
        try:
            return float(s.get(k) or d)
        except (TypeError, ValueError):
            return d

    return {
        "enabled": (s.get("engagement_sim_enabled", "1") == "1"),
        "max_days": max(1, _i("engagement_sim_max_days", 3)),
        "like_min": max(0, _i("engagement_sim_like_min", 20)),
        "like_max": max(1, _i("engagement_sim_like_max", 30)),
        "bookmark_ratio": max(0.0, _f("engagement_sim_bookmark_ratio", 0.25)),
        "comment_max": max(0, _i("engagement_sim_comment_max", 12)),
        "comment_ai": (s.get("engagement_sim_comment_ai", "1") == "1"),
        "follow_max": max(0, _i("engagement_sim_follow_max", 1000)),
        "halflife": max(1.0, _f("engagement_sim_halflife_hours", 18.0)),
        "mutual": 0.35,
    }


def _eng_spread_ts(start: datetime, end: datetime, rng: Any) -> str:
    """A timestamp uniformly between start and end (so growth looks gradual)."""
    if end <= start:
        return start.isoformat()
    return (start + timedelta(seconds=rng.random() * (end - start).total_seconds())).isoformat()


def _engagement_pass(conn: sqlite3.Connection, s: dict[str, Any], out: dict[str, int]) -> None:
    rng = secrets.SystemRandom()
    POST_LIMIT = 400
    budget = 1600
    personas = seed_user_ids(conn)
    if len(personas) < 5:
        return
    persona_set = set(personas)
    gmap = _persona_gender_map(conn)  # user_id -> 'male'/'female'/''
    now = datetime.now(timezone.utc)
    window = s["max_days"] * 24.0
    cutoff = (now - timedelta(days=s["max_days"])).isoformat()

    # Heal: older seed posts authored by an official seed-bot (before personas
    # existed) should belong to real personas, so the feed never shows them all
    # as "编辑部". Reassign a bounded batch each tick.
    bot_ids = [r["id"] for r in conn.execute("SELECT id FROM users WHERE COALESCE(is_official, 0) = 1")]
    if bot_ids:
        ph = ",".join("?" * len(bot_ids))
        stale = conn.execute(
            f"SELECT id FROM posts WHERE is_seed_content = 1 AND deleted_at IS NULL AND author_id IN ({ph}) LIMIT 800",
            bot_ids,
        ).fetchall()
        for r in stale:
            conn.execute("UPDATE posts SET author_id = ? WHERE id = ?", (secrets.choice(personas), r["id"]))
        if stale:
            out["reassigned"] = out.get("reassigned", 0) + len(stale)

    posts = conn.execute(
        "SELECT id, author_id, created_at, content_type, content, language FROM posts "
        "WHERE is_seed_content = 1 AND deleted_at IS NULL AND status IN ('published', 'active') "
        "AND created_at >= ? ORDER BY created_at DESC LIMIT ?",
        (cutoff, POST_LIMIT),
    ).fetchall()
    ai_left = ENG_AI_COMMENT_POSTS_PER_TICK if s.get("comment_ai") else 0
    for p in posts:
        if budget <= 0:
            break
        pid = p["id"]
        author_id = p["author_id"]
        created = parse_iso(p["created_at"]) or now
        age_h = min(max(0.0, (now - created).total_seconds() / 3600.0), window)
        if age_h <= 0:
            continue
        frac = _eng_frac(age_h, s["halflife"])
        like_cap = min(len(personas), int(_eng_range(s["like_min"], s["like_max"], pid, "like")))
        bm_cap = int(like_cap * s["bookmark_ratio"] * _eng_range(0.6, 1.4, pid, "bm"))
        guide_bonus = 1.6 if p["content_type"] == "guide" else 1.0
        cm_cap = min(s["comment_max"], int(round(like_cap * _eng_range(0.02, 0.09, pid, "cm") * guide_bonus)))

        for kind, target, key in (("like", int(round(like_cap * frac)), "likes"),
                                  ("bookmark", int(round(bm_cap * frac)), "bookmarks")):
            if budget <= 0:
                break
            done = {r["user_id"] for r in conn.execute(
                "SELECT user_id FROM interactions WHERE target_id = ? AND kind = ?", (pid, kind))}
            delta = min(target - len(done), 60, budget)
            if delta <= 0:
                continue
            # Exclude the post's own author from the sample: a persona liking a
            # seed post it was reassigned to would be a self-interaction, which
            # reconcile_post_counters drops — so counting it here would drift.
            avail = [u for u in personas if u not in done and u != author_id]
            inserted = 0
            for uid in rng.sample(avail, min(delta, len(avail))):
                # OR IGNORE against the UNIQUE(target_id,user_id,kind) index: the
                # `done` set already excludes existing rows, but a concurrent tick
                # / real interaction could have landed one; the guard keeps the
                # `inserted` tally (used to bump the counter) exactly true.
                cur = conn.execute(
                    "INSERT OR IGNORE INTO interactions (id, target_id, user_id, kind, created_at) VALUES (?, ?, ?, ?, ?)",
                    (str(uuid.uuid4()), pid, uid, kind, _eng_spread_ts(created, now, rng)),
                )
                if (cur.rowcount or 0) > 0:
                    out[key] += 1
                    inserted += 1
                budget -= 1
            # Keep the denormalized counters (the ONLY thing ranking reads) in
            # step with the rows we just wrote — otherwise simulated engagement
            # was invisible to hot_score until reconcile_post_counters ran up to
            # 6h later. Non-author samples only (see above), so reconcile and the
            # incremental bump stay in lock-step.
            if inserted:
                bump_post_counter_for_kind(conn, pid, kind, inserted)

        if budget > 0 and cm_cap > 0:
            rows = conn.execute(
                "SELECT author_id, content FROM comments WHERE post_id = ? AND deleted_at IS NULL", (pid,)).fetchall()
            commenters = {r["author_id"] for r in rows}
            used_lines = {r["content"] for r in rows}
            delta = min(int(round(cm_cap * frac)) - len(rows), 6, budget)
            if delta > 0:
                # Prefer fresh DeepSeek comments (gender-tagged, contextual to the
                # post); fall back to the static pool when AI is off/unavailable.
                comment_items: list[dict[str, str]] | None = None
                if s.get("comment_ai") and ai_left > 0:
                    ai_left -= 1
                    try:
                        comment_items = seed_llm.generate_comments(p["content"], delta, language=(p["language"] or "zh"))
                    except Exception:
                        comment_items = None
                if not comment_items:
                    pool = [c for c in SEED_COMMENTS if c not in used_lines]
                    rng.shuffle(pool)
                    comment_items = [{"text": c, "gender": ""} for c in pool[:delta]]
                # Commenters available, split by gender so a male-voiced comment is
                # posted by a male persona (and vice versa).
                avail = [u for u in personas if u not in commenters]
                rng.shuffle(avail)
                avail_by_g = {"male": [u for u in avail if gmap.get(u) == "male"],
                              "female": [u for u in avail if gmap.get(u) == "female"]}
                cm_inserted = 0
                latest_ts = ""
                for ci in comment_items:
                    if budget <= 0:
                        break
                    line = ci.get("text", "")
                    if not line or line in used_lines:
                        continue
                    g = ci.get("gender") or ""
                    picks = avail_by_g.get(g) if avail_by_g.get(g) else avail
                    if not picks:
                        break
                    uid = picks.pop()
                    for lst in (avail, avail_by_g.get("male"), avail_by_g.get("female")):
                        if lst and uid in lst:
                            lst.remove(uid)
                    used_lines.add(line)
                    ts = _eng_spread_ts(created, now, rng)
                    conn.execute(
                        "INSERT INTO comments (id, post_id, author_id, content, parent_comment_id, reply_to_user_id, created_at, updated_at) "
                        "VALUES (?, ?, ?, ?, NULL, NULL, ?, ?)",
                        (str(uuid.uuid4()), pid, uid, line, ts, ts),
                    )
                    out["comments"] += 1
                    cm_inserted += 1
                    if ts > latest_ts:
                        latest_ts = ts
                    budget -= 1
                # Denormalized comment_count + activity radar in step with the
                # rows written (see the like/收藏 note above). last_activity_at
                # only advances if the newest simulated comment is more recent
                # than what's stored, so the 正在发生 radar reflects it without a
                # 6h reconcile lag.
                if cm_inserted:
                    bump_post_counter(conn, pid, "comment_count", cm_inserted)
                    if latest_ts:
                        conn.execute(
                            "UPDATE posts SET last_activity_at = ? WHERE id = ? "
                            "AND (last_activity_at = '' OR last_activity_at < ?)",
                            (latest_ts, pid, latest_ts),
                        )

    # follows among personas — each persona gains followers over its window,
    # with occasional mutual follow-backs (互关).
    follow_budget = min(400, budget)
    young = conn.execute(
        "SELECT u.id, u.created_at FROM content_pack_users cpu JOIN users u ON u.id = cpu.user_id "
        "WHERE u.deleted_at IS NULL AND u.created_at >= ? ORDER BY u.created_at DESC LIMIT 200",
        (cutoff,),
    ).fetchall()
    rng.shuffle(young)
    for u in young:
        if follow_budget <= 0:
            break
        uid = u["id"]
        created = parse_iso(u["created_at"]) or now
        age_h = min(max(0.0, (now - created).total_seconds() / 3600.0), window)
        if age_h <= 0:
            continue
        frac = _eng_frac(age_h, s["halflife"])
        cap = int(_eng_range(2, max(3, s["follow_max"]), uid, "fol"))
        followers = {r["follower_id"] for r in conn.execute(
            "SELECT follower_id FROM follows WHERE following_id = ?", (uid,))}
        delta = min(int(round(cap * frac)) - len(followers & persona_set), 40, follow_budget)
        if delta <= 0:
            continue
        avail = [x for x in personas if x != uid and x not in followers]
        for fid in rng.sample(avail, min(delta, len(avail))):
            conn.execute(
                "INSERT INTO follows (id, follower_id, following_id, created_at) VALUES (?, ?, ?, ?)",
                (str(uuid.uuid4()), fid, uid, _eng_spread_ts(created, now, rng)),
            )
            out["follows"] += 1
            follow_budget -= 1
            if rng.random() < s["mutual"] and not conn.execute(
                "SELECT 1 FROM follows WHERE follower_id = ? AND following_id = ?", (uid, fid)).fetchone():
                conn.execute(
                    "INSERT INTO follows (id, follower_id, following_id, created_at) VALUES (?, ?, ?, ?)",
                    (str(uuid.uuid4()), uid, fid, _eng_spread_ts(created, now, rng)),
                )
                out["follows"] += 1


def run_engagement_simulation_tick(conn: sqlite3.Connection | None = None) -> dict[str, int]:
    """One pass of engagement growth. Pass a conn to run in-band (admin trigger);
    omit it to acquire the write lock + a fresh connection (background daemon)."""
    out = {"likes": 0, "bookmarks": 0, "comments": 0, "follows": 0}
    if conn is not None:
        s = _engagement_settings(conn)
        if s["enabled"]:
            _engagement_pass(conn, s, out)
    else:
        with DB_LOCK:
            c = db()
            try:
                s = _engagement_settings(c)
                if s["enabled"]:
                    _engagement_pass(c, s, out)
                c.commit()
            finally:
                c.close()
    if any(out.values()):
        invalidate_public_ranking_caches()
    return out


def start_engagement_simulator() -> None:
    global _ENGAGEMENT_SIM_STARTED
    if _ENGAGEMENT_SIM_STARTED:
        return
    _ENGAGEMENT_SIM_STARTED = True

    def _loop() -> None:
        time.sleep(150)
        while True:
            try:
                n = run_engagement_simulation_tick()
                if any(n.values()):
                    ACCESS_LOG.info("engagement sim: +%d likes +%d 收藏 +%d comments +%d follows",
                                    n["likes"], n["bookmarks"], n["comments"], n["follows"])
            except Exception:
                ERR_LOG.exception("engagement sim tick failed")
            time.sleep(KAIX_ENGAGEMENT_SIM_INTERVAL_SEC)

    threading.Thread(target=_loop, name="engagement-sim", daemon=True).start()


