    def api_admin_engagement_status(self, conn: sqlite3.Connection) -> None:
        self.require_admin(conn)
        s = _site_settings(conn)
        keys = [k for k in sorted(SITE_SETTING_KEYS) if k.startswith("engagement_sim_")] + ["seed_post_image_ratio"]
        settings = {k: s.get(k) for k in keys}
        _ensure_content_pack_users_table(conn)
        q = lambda sql: int(conn.execute(sql).fetchone()[0])
        stats = {
            "seed_posts": q("SELECT COUNT(*) FROM posts WHERE is_seed_content = 1 AND deleted_at IS NULL"),
            "seed_likes": q("SELECT COUNT(*) FROM interactions WHERE kind='like' AND target_id IN (SELECT id FROM posts WHERE is_seed_content=1)"),
            "seed_bookmarks": q("SELECT COUNT(*) FROM interactions WHERE kind='bookmark' AND target_id IN (SELECT id FROM posts WHERE is_seed_content=1)"),
            "seed_comments": q("SELECT COUNT(*) FROM comments WHERE deleted_at IS NULL AND post_id IN (SELECT id FROM posts WHERE is_seed_content=1)"),
            "persona_follows": q("SELECT COUNT(*) FROM follows WHERE following_id IN (SELECT user_id FROM content_pack_users)"),
        }
        self.send_json({"settings": settings, "stats": stats})

    def api_admin_engagement_run(self, conn: sqlite3.Connection) -> None:
        admin = self.require_admin(conn)
        result = run_engagement_simulation_tick(conn)
        log_seed_action(conn, admin_id=admin["id"], action="engagement_run", country="jp",
                        language="zh", content_type="engagement", count=int(sum(result.values())), metadata=result)
        self.send_json({"ok": True, "result": result})

    # ---- Local News Desk / 本地资讯台 ----

    def _guide_country(self, query: dict[str, str]) -> str:
        raw = (query.get("country") or "").strip()
        return _normalize_country_code(raw) if raw else GUIDE_DEFAULT_COUNTRY

    def _guide_is_open(self, country: str) -> bool:
        return country in GUIDE_OPEN_COUNTRIES

    def _guide_coming_soon_payload(self, country: str, language: str = "zh-CN", **extra: Any) -> dict[str, Any]:
        base = {"status": "coming_soon", "country": country, "emptyState": _guide_localized_ui("empty", language, GUIDE_EMPTY_STATE)}
        base.update(extra)
        return base

    def _guide_content_counts(self, conn: sqlite3.Connection, country: str, category_key: str, sub_key: str = "") -> dict[str, int]:
        article_where = ["country = ?", "status = 'published'"]
        product_where = ["country = ?", "status IN ('published','coming_soon')"]
        article_params: list[Any] = [country]
        product_params: list[Any] = [country]
        if sub_key:
            article_where.extend(["category_key = ?", "sub_category_key = ?"])
            product_where.extend(["category_key = ?", "sub_category_key = ?"])
            article_params.extend([category_key, sub_key])
            product_params.extend([category_key, sub_key])
        else:
            article_where.append("category_key = ?")
            product_where.append("category_key = ?")
            article_params.append(category_key)
            product_params.append(category_key)
        article_count = conn.execute(
            f"SELECT COUNT(*) AS c FROM guide_articles WHERE {' AND '.join(article_where)}",
            article_params,
        ).fetchone()["c"]
        product_count = conn.execute(
            f"SELECT COUNT(*) AS c FROM guide_products WHERE {' AND '.join(product_where)}",
            product_params,
        ).fetchone()["c"]
        return {"articleCount": int(article_count), "productCount": int(product_count)}

    def _guide_categories_payload(self, conn: sqlite3.Connection, country: str, language: str = "zh-CN") -> list[dict[str, Any]]:
        tops = conn.execute(
            "SELECT * FROM guide_categories WHERE country = ? AND parent_key = '' AND is_active = 1 ORDER BY sort_order",
            (country,),
        ).fetchall()
        out: list[dict[str, Any]] = []
        for top in tops:
            kids = conn.execute(
                "SELECT * FROM guide_categories WHERE country = ? AND parent_key = ? AND is_active = 1 ORDER BY sort_order",
                (country, top["key"]),
            ).fetchall()
            child_items = []
            for k in kids:
                child = serialize_guide_category(k)
                child.update(self._guide_content_counts(conn, country, top["key"], child["key"]))
                child_items.append(child)
            item = serialize_guide_category(top, child_items)
            item.update(self._guide_content_counts(conn, country, item["key"]))
            out.append(localize_guide_category_payload(item, language))
        return out

    def _guide_home_modules_payload(self, conn: sqlite3.Connection, country: str, language: str) -> list[dict[str, Any]]:
        rows = conn.execute(
            "SELECT * FROM guide_home_modules WHERE country = ? AND language IN (?, 'zh-CN') "
            "ORDER BY CASE WHEN language = ? THEN 0 ELSE 1 END, sort_order",
            (country, language, language),
        ).fetchall()
        seen: set[str] = set()
        modules: list[dict[str, Any]] = []
        for row in rows:
            key = row["module_key"]
            if key in seen:
                continue
            seen.add(key)
            modules.append(serialize_guide_home_module(row))
        return modules

    def _guide_module_enabled(self, modules: list[dict[str, Any]], key: str) -> bool:
        for module in modules:
            if module.get("moduleKey") == key:
                return bool(module.get("isActive")) and str(module.get("status") or "published") == "published"
        return True

    def _guide_faq_rows(self, conn: sqlite3.Connection, country: str, language: Any,
                        *, category_key: str | None = None, limit: int = 8) -> list[Any]:
        """FAQ rows in the requested language, falling back to zh-CN when the
        localized rows are missing. Keeps guide-home / JLPT / search FAQ口径一致."""
        lang = _normalize_language_tag(language)
        base = "SELECT * FROM guide_faq WHERE country = ? AND status = 'published'"
        params: list[Any] = [country]
        if category_key:
            base += " AND category_key = ?"
            params.append(category_key)
        rows = conn.execute(
            f"{base} AND language = ? ORDER BY sort_order LIMIT ?",
            [*params, lang, limit],
        ).fetchall()
        if not rows and lang != "zh-CN":
            rows = conn.execute(
                f"{base} AND language = 'zh-CN' ORDER BY sort_order LIMIT ?",
                [*params, limit],
            ).fetchall()
        return rows

    def api_guide_home(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        country = self._guide_country(query)
        language = (query.get("language") or "zh-CN").strip() or "zh-CN"
        if not self._guide_is_open(country):
            return self.send_json(self._guide_coming_soon_payload(
                country, language, hero=_guide_localized_ui("hero", language, GUIDE_HERO), categories=[], goals={"title": _guide_localized_ui("goalTitle", language, GUIDE_GOAL_TITLE), "entries": []},
                goalEntries=[], featuredArticles=[], featuredProducts=[], featuredServices=[],
                resourceEntries=[], featuredSchools=[], companyHighlights=[], latestArticles=[], faq=[],
            ))
        # This payload is fully public (no per-user data) and runs ~8 read
        # queries. Under a traffic spike that's the single biggest source of
        # DB load and the "/guide stuck loading" symptom, so serve it from a
        # short-TTL in-memory cache: only one request per window per country
        # actually touches the DB. Admin guide edits become visible within
        # GUIDE_HOME_CACHE_TTL seconds.
        cache_key = f"guide_home:{country}:{language}"
        cached_payload = _cache_get(cache_key)
        if cached_payload is not None:
            return self.send_json(cached_payload)
        home_modules = self._guide_home_modules_payload(conn, country, language)
        hero = _guide_localized_ui("hero", language, GUIDE_HERO)
        hero_module = next((m for m in home_modules if m.get("moduleKey") == "hero" and m.get("isActive")), None)
        if hero_module and isinstance(hero_module.get("content"), dict):
            hero = {**hero, **{k: v for k, v in hero_module["content"].items() if v not in ("", None, [])}}
        module_on = lambda key: self._guide_module_enabled(home_modules, key)
        featured_articles = [localize_guide_article_payload(serialize_guide_article(r), language) for r in conn.execute(
            "SELECT * FROM guide_articles WHERE country = ? AND status = 'published' AND is_featured = 1 "
            "ORDER BY sort_order, published_at DESC LIMIT 6", (country,)).fetchall()] if module_on("featuredArticles") else []
        latest_articles = [localize_guide_article_payload(serialize_guide_article(r), language) for r in conn.execute(
            "SELECT * FROM guide_articles WHERE country = ? AND status = 'published' "
            "ORDER BY published_at DESC, created_at DESC LIMIT 8", (country,)).fetchall()] if module_on("latestArticles") else []
        featured_products = [localize_guide_product_payload(serialize_guide_product(r), language) for r in conn.execute(
            "SELECT * FROM guide_products WHERE country = ? AND is_service = 0 AND status IN ('published','coming_soon') "
            "ORDER BY is_coming_soon ASC, sort_order LIMIT 6", (country,)).fetchall()] if module_on("commerce") else []
        _svc_status = "status = 'published'" if GUIDE_HIDE_EMPTY_SERVICES else "status IN ('published','coming_soon')"
        featured_services = [localize_guide_product_payload(serialize_guide_product(r), language) for r in conn.execute(
            f"SELECT * FROM guide_products WHERE country = ? AND is_service = 1 AND {_svc_status} "
            "ORDER BY is_coming_soon ASC, sort_order LIMIT 6", (country,)).fetchall()] if module_on("commerce") else []
        featured_schools = [localize_guide_school_payload(serialize_guide_school(r), language) for r in conn.execute(
            "SELECT * FROM guide_schools WHERE country = ? AND status = 'published' "
            "ORDER BY is_featured DESC, data_quality_score DESC, updated_at DESC LIMIT 6", (country,)).fetchall()] if module_on("featuredSchools") else []
        companies = [localize_guide_company_payload(serialize_guide_company(r), language) for r in conn.execute(
            "SELECT * FROM guide_companies WHERE country = ? AND status = 'published' AND (website <> '' OR career_url <> '' OR global_career_url <> '') AND data_quality_score >= 15 "
            "ORDER BY is_featured DESC, data_quality_score DESC, review_count DESC, created_at DESC LIMIT 6", (country,)).fetchall()] if module_on("companyHighlights") else []
        faqs = [serialize_guide_faq(r) for r in self._guide_faq_rows(conn, country, language)] if module_on("faq") else []
        categories = self._guide_categories_payload(conn, country, language) if module_on("categories") else []
        resource_entries = [localize_guide_resource(r, language) for r in GUIDE_RESOURCE_ENTRIES] if module_on("resources") else []
        goal_entries = [localize_guide_goal(g, language) for g in GUIDE_GOAL_SEED] if module_on("goals") else []
        journeys = self._guide_journeys_payload(conn, country, language) if module_on("journeys") else []
        payload = {
            "status": "ok", "country": country, "language": language,
            "hero": hero,
            "categories": categories,
            "homeModules": home_modules,
            "resourceEntries": resource_entries,
            "goals": {"title": _guide_localized_ui("goalTitle", language, GUIDE_GOAL_TITLE), "entries": goal_entries},
            "goalEntries": goal_entries,
            "journeys": journeys,
            "universalSearchScopes": GUIDE_SEARCH_SCOPES,
            "featuredArticles": featured_articles,
            "featuredProducts": featured_products,
            "featuredServices": featured_services,
            "featuredSchools": featured_schools,
            "companyHighlights": companies,
            "latestArticles": latest_articles,
            "faq": faqs,
            "reviewDisclaimer": _guide_localized_ui("reviewDisclaimer", language, GUIDE_REVIEW_DISCLAIMER),
            "schoolDisclaimer": _guide_localized_ui("schoolDisclaimer", language, GUIDE_SCHOOL_DISCLAIMER),
            "companyDisclaimer": _guide_localized_ui("companyDisclaimer", language, GUIDE_COMPANY_DISCLAIMER),
        }
        _cache_put(cache_key, payload, GUIDE_HOME_CACHE_TTL)
        self.send_json(payload)

    def api_guide_sitemap(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        """公开站点地图: 已发布学校/公司/文章的 slug + updated_at(SEO 站点地图 /
        客户端预取用)。全公开、无个人数据,同 guide-home 一样走进程内 TTL 缓存。"""
        cached = _cache_get("guide_sitemap")
        if cached is not None:
            return self.send_json(cached)

        def _entries(table: str) -> list[dict[str, str]]:
            return [
                {"slug": r["slug"], "updated_at": r["updated_at"]}
                for r in conn.execute(
                    f"SELECT slug, updated_at FROM {table} WHERE status = 'published' ORDER BY updated_at DESC"
                ).fetchall()
            ]

        payload = {"ok": True, "data": {
            "schools": _entries("guide_schools"),
            "companies": _entries("guide_companies"),
            "articles": _entries("guide_articles"),
        }}
        _cache_put("guide_sitemap", payload, GUIDE_SITEMAP_CACHE_TTL)
        self.send_json(payload)

    def api_guide_jlpt_zone(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        """JLPT 备考专区: a curated public prep hub aggregating JLPT roadmap
        articles, resources (free/member/paid), FAQ, an N5–N1 level structure and
        a study-plan CTA. Doubles as a membership hook (member-priced resources).
        Fully public, cached like guide-home."""
        country = self._guide_country(query)
        language = (query.get("language") or "zh-CN").strip() or "zh-CN"
        if not self._guide_is_open(country):
            return self.send_json({
                "status": "coming_soon", "country": country,
                "hero": {}, "levels": [], "articles": [], "resources": [], "faq": [], "studyPlan": {},
            })
        cache_key = f"guide_jlpt:{country}:{language}"
        cached = _cache_get(cache_key)
        if cached is not None:
            return self.send_json(self._jlpt_zone_with_dynamic(conn, dict(cached)))
        articles = [localize_guide_article_payload(serialize_guide_article(r), language) for r in conn.execute(
            "SELECT * FROM guide_articles WHERE country = ? AND status = 'published' AND category_key = 'jlpt' "
            "ORDER BY is_featured DESC, sort_order, published_at DESC LIMIT 12", (country,)).fetchall()]
        # JLPT resources are content packs (not human services), so keep
        # coming_soon ones visible — they show 即将开放 and keep the roadmap whole.
        # Member-included packs sort first as the concrete membership payoff.
        resources = [localize_guide_product_payload(serialize_guide_product(r), language) for r in conn.execute(
            "SELECT * FROM guide_products WHERE country = ? AND category_key = 'jlpt' "
            "AND status IN ('published','coming_soon') "
            "ORDER BY is_coming_soon ASC, is_member_included DESC, sort_order LIMIT 24", (country,)).fetchall()]
        faq = [serialize_guide_faq(r) for r in self._guide_faq_rows(conn, country, language, category_key="jlpt")]
        levels = [
            {"key": "n5", "label": "N5", "summary": machi_ai_text(language, "入门:基础词汇语法与生活场景。", "入門:基礎の語彙・文法と日常場面。", "Beginner: core vocabulary, grammar, everyday scenes.")},
            {"key": "n4", "label": "N4", "summary": machi_ai_text(language, "初级:扩展词汇与日常表达。", "初級:語彙拡張と日常表現。", "Elementary: broader vocabulary and daily expression.")},
            {"key": "n3", "label": "N3", "summary": machi_ai_text(language, "过渡:承上启下,读解听力提速。", "橋渡し:読解・聴解のスピードアップ。", "Bridge: faster reading and listening.")},
            {"key": "n2", "label": "N2", "summary": machi_ai_text(language, "就职常见门槛:语法读解强化。", "就職でよく求められる:文法・読解の強化。", "Common job threshold: stronger grammar and reading.")},
            {"key": "n1", "label": "N1", "summary": machi_ai_text(language, "高级:综合岗位与升学的敲门砖。", "上級:総合職・進学の関門。", "Advanced: gateway for careers and grad school.")},
        ]
        payload = {
            "status": "ok",
            "country": country,
            "hero": {
                "title": machi_ai_text(language, "JLPT 备考专区", "JLPT 対策センター", "JLPT Prep Center"),
                "subtitle": machi_ai_text(
                    language,
                    "N5–N1 备考路线、题型趋势、高频词汇与模拟题,配合官方过去问一起用。",
                    "N5〜N1 の学習ロードマップ、出題傾向、頻出語彙、模擬問題。公式過去問と併用。",
                    "N5–N1 roadmaps, question trends, high-frequency vocabulary, and mock tests."),
            },
            "levels": levels,
            "articles": articles,
            "resources": resources,
            "faq": faq,
            "studyPlan": {
                "title": machi_ai_text(language, "制定我的 JLPT 学习计划", "JLPT 学習計画を作る", "Build my JLPT study plan"),
                "subtitle": machi_ai_text(language, "按考试日期和每日时间自动排期。", "試験日と学習時間から自動で予定化。", "Auto-schedule from your exam date and daily time."),
                "route": "guidePlan",
            },
            "disclaimer": machi_ai_text(
                language,
                "Machi 的 JLPT 资料为原创整理,不含未授权真题原文;请以 JLPT 官方最新公告为准。",
                "Machi の JLPT 資料はオリジナル整理で、無断の過去問原文は含みません。最新は JLPT 公式でご確認ください。",
                "Machi's JLPT materials are original summaries (no unauthorized past-paper text). Verify with official JLPT announcements."),
        }
        _cache_put(cache_key, payload, GUIDE_HOME_CACHE_TTL)
        self.send_json(self._jlpt_zone_with_dynamic(conn, dict(payload)))

    def _jlpt_zone_with_dynamic(self, conn: sqlite3.Connection, payload: dict[str, Any]) -> dict[str, Any]:
        """Overlay the JLPT core (BE6) dynamic fields onto the cached zone
        payload: hasPractice/hasPlacement/hasVocab/hasExams + examCountdown are
        cheap counts; streak is per-user (only when signed in), so it stays out
        of the cache key. Best-effort — never breaks the zone landing page."""
        try:
            viewer = self.current_session(conn)
            uid = viewer["user_id"] if viewer else None
            payload["jlptCore"] = jlpt.zone_dynamic_fields(conn, user_id=uid, region="jp", now=now_iso())
        except Exception:
            payload.setdefault("jlptCore", {
                "hasPractice": False, "hasPlacement": False, "hasVocab": False,
                "hasExams": False, "examCountdown": None,
            })
        return payload

    # ========================================================================
    # JLPT 备考核心 (BE6) — 题库 / 定级 / 打卡 / 单词 / 在线考试 / 考试日历.
    # Thin handlers: auth + membership + envelopes here; the pure logic lives in
    # server_jlpt.py. Compliance: study content is original/imported, never
    # unauthorized past-paper text; the AI 讲解 prompt forbids claiming真题.
    # ========================================================================

    _JLPT_DISCLAIMER = (
        "Machi 的 JLPT 题库为原创/授权导入内容，不含未授权官方历年真题原文；"
        "请以 JLPT 官方最新公告为准。"
    )

    def _jlpt_optional_user(self, conn: sqlite3.Connection) -> dict[str, Any] | None:
        """Resolve the signed-in user without raising (JLPT practice allows a
        signed-out taster for free questions)."""
        session = self.current_session(conn)
        if not session:
            return None
        row = conn.execute(
            "SELECT * FROM users WHERE id = ? AND deleted_at IS NULL", (session["user_id"],)
        ).fetchone()
        return dict(row) if row else None

    def api_guide_jlpt_practice(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        """Sample practice questions. Signed-out callers get free questions only;
        members additionally see is_member_only questions."""
        user = self._jlpt_optional_user(conn)
        is_member = bool(user) and has_active_membership(conn, user["id"])
        level = jlpt.normalize_level(query.get("level"), default="N5")
        section = jlpt.normalize_section(query.get("section"))
        count = query.get("count")
        questions = jlpt.pick_practice_questions(
            conn, level=level, section=section, count=count,
            user_id=(user["id"] if user else None), is_member=is_member, now=now_iso(),
        )
        self.send_json({
            "status": "ok", "level": level, "section": section or "all",
            "membershipActive": is_member, "questions": questions,
            "disclaimer": self._JLPT_DISCLAIMER,
        })

    def api_guide_jlpt_attempt(self, conn: sqlite3.Connection) -> None:
        """Grade + record one answer. Requires auth (attempts are per-user)."""
        user = self.require_user(conn)
        body = self.read_json()
        question_id = str(body.get("questionId") or body.get("question_id") or "").strip()
        if not question_id:
            return self.send_error_json("questionId required", 400, "invalid_body")
        question = jlpt.get_question(conn, question_id)
        if not question:
            return self.send_error_json("question not found", 404, "not_found")
        try:
            selected = int(body.get("selectedIndex", body.get("selected_index", -1)))
        except (TypeError, ValueError):
            return self.send_error_json("selectedIndex required", 400, "invalid_body")
        result = jlpt.record_attempt(
            conn, user_id=user["id"], question=question, selected_index=selected,
            session_id=str(body.get("sessionId") or body.get("session_id") or ""),
            source_kind=str(body.get("sourceKind") or body.get("source_kind") or "practice"),
            now=now_iso(),
        )
        conn.commit()
        self.send_json({"status": "ok", **result})

    def api_guide_jlpt_review(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        """错题本 — questions whose latest attempt was wrong."""
        user = self.require_user(conn)
        level = query.get("level") or ""
        count = query.get("count")
        questions = jlpt.review_questions(
            conn, user_id=user["id"], level=level, count=count if count is not None else 20,
        )
        self.send_json({"status": "ok", "questions": questions, "disclaimer": self._JLPT_DISCLAIMER})

    def api_guide_jlpt_stats(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        user = self.require_user(conn)
        self.send_json({"status": "ok", **jlpt.stats(conn, user_id=user["id"], level=query.get("level") or "")})

    def api_guide_jlpt_streak(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        user = self.require_user(conn)
        self.send_json({"status": "ok", **jlpt.streak(conn, user_id=user["id"], now=now_iso())})

    def api_guide_jlpt_exam_dates(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        region = (query.get("region") or "jp").strip().lower() or "jp"
        self.send_json({
            "status": "ok", "region": region,
            "examDates": jlpt.exam_dates(conn, region=region),
            "countdown": jlpt.next_exam_countdown(conn, region=region, now=now_iso()),
        })

    # ---- placement (定级) --------------------------------------------------
    def api_guide_jlpt_placement_start(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        user = self._jlpt_optional_user(conn)
        is_member = bool(user) and has_active_membership(conn, user["id"])
        questions = jlpt.placement_questions(conn, is_member=is_member)
        self.send_json({
            "status": "ok", "questions": questions,
            "note": machi_ai_text("zh-CN",
                                  "根据作答自动推荐适合的备考等级，仅供参考。",
                                  "回答からおすすめの学習レベルを提案します（参考）。",
                                  "We recommend a level from your answers (guidance only)."),
        })

    def api_guide_jlpt_placement_submit(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        body = self.read_json()
        answers = body.get("answers")
        if not isinstance(answers, list):
            return self.send_error_json("answers array required", 400, "invalid_body")
        # Record the placement answers as attempts too (so定级 counts for streak).
        now = now_iso()
        for a in answers:
            if not isinstance(a, dict):
                continue
            qid = str(a.get("questionId") or a.get("question_id") or "").strip()
            q = jlpt.get_question(conn, qid) if qid else None
            if not q:
                continue
            try:
                sel = int(a.get("selectedIndex", a.get("selected_index", -1)))
            except (TypeError, ValueError):
                sel = -1
            jlpt.record_attempt(conn, user_id=user["id"], question=q, selected_index=sel,
                                source_kind="placement", now=now)
        result = jlpt.score_placement(conn, answers)
        conn.commit()
        self.send_json({
            "status": "ok", **result,
            "studyPlanRoute": "guidePlan",
            "studyPlanPrefill": {"targetLevel": result["recommendedLevel"],
                                 "dailyMinutes": result["suggestedDailyMinutes"]},
        })

