    # --- Guide Journeys -----------------------------------------------------
    def _guide_journeys_payload(self, conn: sqlite3.Connection, country: str, language: str) -> list[dict[str, Any]]:
        rows = conn.execute(
            "SELECT * FROM guide_journeys WHERE country = ? AND language = 'zh-CN' AND status = 'published' ORDER BY sort_order",
            (country,),
        ).fetchall()
        journeys: list[dict[str, Any]] = []
        for row in rows:
            count = conn.execute(
                "SELECT COUNT(*) AS c FROM guide_journey_steps WHERE journey_key = ? AND country = ? AND status = 'published'",
                (row["journey_key"], country),
            ).fetchone()["c"]
            journeys.append(serialize_guide_journey(row, step_count=int(count)))
        return journeys

    def api_guide_journeys(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        country = self._guide_country(query)
        language = (query.get("language") or "zh-CN").strip() or "zh-CN"
        if not self._guide_is_open(country):
            return self.send_json(self._guide_coming_soon_payload(country, language, journeys=[]))
        cache_key = f"guide_journeys:{country}"
        cached = _cache_get(cache_key)
        if cached is None:
            cached = {"status": "ok", "country": country, "language": language,
                      "journeys": self._guide_journeys_payload(conn, country, language)}
            _cache_put(cache_key, cached, GUIDE_HOME_CACHE_TTL)
        _guide_funnel_log("journeys_viewed", country=country)
        self.send_json(cached)

    def _guide_step_related(self, conn: sqlite3.Connection, step: sqlite3.Row | dict[str, Any],
                            country: str, language: str) -> dict[str, Any]:
        # Resolve each step's recommended content from existing tables. Explicit
        # slugs win; otherwise fall back to top articles in the step category.
        # Wrapped so a column/query mismatch can never 500 the whole journey.
        d = dict(step)
        articles: list[dict[str, Any]] = []
        products: list[dict[str, Any]] = []
        try:
            slugs = _guide_split_tags(d.get("article_slugs"))
            if slugs:
                placeholders = ",".join("?" * len(slugs))
                rows = conn.execute(
                    f"SELECT * FROM guide_articles WHERE country = ? AND status = 'published' AND slug IN ({placeholders})",
                    (country, *slugs),
                ).fetchall()
                articles = [localize_guide_article_payload(serialize_guide_article(r), language) for r in rows]
            elif d.get("category_key"):
                rows = conn.execute(
                    "SELECT * FROM guide_articles WHERE country = ? AND status = 'published' AND category_key = ? "
                    "ORDER BY is_featured DESC, published_at DESC LIMIT 18",
                    (country, d.get("category_key")),
                ).fetchall()
                if rows:
                    # Distribute the category's articles across the journey's
                    # steps by the step order, so each step surfaces *different*
                    # reading instead of every step repeating the same top 3
                    # (the arrival journey's visible duplication). Wraps around
                    # when the category has fewer articles than steps × 3.
                    try:
                        # Stride 2 (not 3) so 6 steps over ~12 category articles
                        # yield distinct 3-article windows for every step instead
                        # of the first four — minimises cross-step repetition.
                        offset = (int(d.get("sort_order") or 0) * 2) % len(rows)
                    except (TypeError, ValueError):
                        offset = 0
                    seen: set[str] = set()
                    picked: list[Any] = []
                    for i in range(len(rows)):
                        r = rows[(offset + i) % len(rows)]
                        if r["id"] in seen:
                            continue
                        seen.add(r["id"])
                        picked.append(r)
                        if len(picked) >= 3:
                            break
                    articles = [localize_guide_article_payload(serialize_guide_article(r), language) for r in picked]
        except Exception:
            articles = []
        try:
            pslugs = _guide_split_tags(d.get("product_slugs"))
            if pslugs:
                placeholders = ",".join("?" * len(pslugs))
                rows = conn.execute(
                    f"SELECT * FROM guide_products WHERE country = ? AND status IN ('published','coming_soon') AND slug IN ({placeholders})",
                    (country, *pslugs),
                ).fetchall()
                products = [localize_guide_product_payload(serialize_guide_product(r), language) for r in rows]
        except Exception:
            products = []
        return {"articles": articles, "products": products}

    def api_guide_recommendations(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        # Materials + services to surface next to a task ("tools to finish this
        # step"). Works for guests; if a todo is referenced and owned by the
        # viewer it inherits that todo's scope + explicit product slugs. Every
        # sub-query is guarded so a single failure can never 500 the page.
        viewer = self.current_session(conn)
        language = (query.get("language") or "zh-CN").strip() or "zh-CN"
        country = self._guide_country(query)
        plan_type = (query.get("planType") or query.get("plan_type") or "").strip()
        todo_type = (query.get("todoType") or query.get("todo_type") or "").strip()
        journey_key = (query.get("journeyKey") or query.get("journey_key") or "").strip()
        step_key = (query.get("stepKey") or query.get("step_key") or "").strip()
        product_slugs: list[str] = []
        todo_id = (query.get("todoId") or query.get("todo_id") or "").strip()
        if todo_id and viewer:
            try:
                trow = conn.execute("SELECT * FROM guide_todos WHERE id = ? AND user_id = ?", (todo_id, viewer["user_id"])).fetchone()
                if trow:
                    t = dict(trow)
                    todo_type = todo_type or (t.get("todo_type") or "")
                    journey_key = journey_key or (t.get("journey_key") or "")
                    step_key = step_key or (t.get("step_key") or "")
                    product_slugs += _guide_split_tags(t.get("related_product_slugs"))
            except Exception:
                pass
        related_ids: list[str] = []
        try:
            clauses: list[str] = []
            params: list[Any] = []
            for col, val in (("plan_type", plan_type), ("todo_type", todo_type), ("journey_key", journey_key), ("step_key", step_key)):
                if val:
                    clauses.append(f"{col} = ?")
                    params.append(val)
            if clauses:
                for r in conn.execute(
                    f"SELECT product_id FROM guide_product_relations WHERE {' OR '.join(clauses)} ORDER BY priority DESC LIMIT 24",
                    tuple(params),
                ).fetchall():
                    related_ids.append(r["product_id"])
        except Exception:
            related_ids = []

        # Fallback: guide_product_relations is admin-curated and often empty, so a
        # journey/step query would otherwise return nothing. Derive the slugs from
        # the journey's own steps (which are seeded with product_slugs) so the
        # "tools to finish this" rail is never empty for a real journey/step.
        if not product_slugs and not related_ids and journey_key:
            try:
                if step_key:
                    srows = conn.execute(
                        "SELECT product_slugs FROM guide_journey_steps WHERE journey_key = ? AND step_key = ? AND country = ? AND status = 'published'",
                        (journey_key, step_key, country),
                    ).fetchall()
                else:
                    srows = conn.execute(
                        "SELECT product_slugs FROM guide_journey_steps WHERE journey_key = ? AND country = ? AND status = 'published' ORDER BY sort_order LIMIT 12",
                        (journey_key, country),
                    ).fetchall()
                derived: list[str] = []
                for sr in srows:
                    for sl in _guide_split_tags(sr["product_slugs"]):
                        if sl and sl not in derived:
                            derived.append(sl)
                product_slugs = derived[:18]
            except Exception:
                pass

        materials: list[dict[str, Any]] = []
        services: list[dict[str, Any]] = []
        seen: set[str] = set()

        def _append(row: sqlite3.Row) -> None:
            d = dict(row)
            if d["id"] in seen:
                return
            seen.add(d["id"])
            payload = localize_guide_product_payload(serialize_guide_product(row), language)
            if int(d.get("is_service") or 0) == 1 or d.get("product_type") == "service":
                services.append(payload)
            else:
                materials.append(payload)

        try:
            if product_slugs:
                ph = ",".join("?" * len(product_slugs))
                for r in conn.execute(
                    f"SELECT * FROM guide_products WHERE country = ? AND status IN ('published','coming_soon') AND slug IN ({ph})",
                    (country, *product_slugs),
                ).fetchall():
                    _append(r)
        except Exception:
            pass
        try:
            if related_ids:
                ph = ",".join("?" * len(related_ids))
                for r in conn.execute(
                    f"SELECT * FROM guide_products WHERE id IN ({ph}) AND status IN ('published','coming_soon')",
                    tuple(related_ids),
                ).fetchall():
                    _append(r)
        except Exception:
            pass

        self.send_json({
            "status": "ok",
            "materials": materials[:12],
            "services": services[:12],
            "products": (materials + services)[:18],
        })

    def api_guide_journey_detail(self, conn: sqlite3.Connection, key: str, query: dict[str, str]) -> None:
        country = self._guide_country(query)
        language = (query.get("language") or "zh-CN").strip() or "zh-CN"
        if not self._guide_is_open(country):
            return self.send_json(self._guide_coming_soon_payload(country, language, journey=None, steps=[]))
        row = conn.execute(
            "SELECT * FROM guide_journeys WHERE journey_key = ? AND country = ? AND language = 'zh-CN' AND status = 'published'",
            (key, country),
        ).fetchone()
        if not row:
            return self.send_error_json("journey not found", 404, "not_found")
        step_rows = conn.execute(
            "SELECT * FROM guide_journey_steps WHERE journey_key = ? AND country = ? AND status = 'published' ORDER BY sort_order",
            (key, country),
        ).fetchall()
        steps = [serialize_guide_journey_step(s, include_body=True, related=self._guide_step_related(conn, s, country, language)) for s in step_rows]
        # Optional per-viewer progress so a logged-in client renders completion
        # in one round trip; guests just get an empty map.
        progress: dict[str, Any] = {}
        viewer = self.current_session(conn)
        if viewer:
            progress_cols = _table_columns(conn, "guide_user_progress")
            select_cols = ["step_key", "status", "completed_at", "reminder_at"]
            for col in ("planned_date", "due_at", "priority", "notify_enabled", "calendar_note"):
                if col in progress_cols:
                    select_cols.append(col)
            for p in conn.execute(
                f"SELECT {', '.join(select_cols)} FROM guide_user_progress WHERE user_id = ? AND journey_key = ?",
                (viewer["user_id"], key),
            ).fetchall():
                d = dict(p)
                progress[d.get("step_key") or "__journey__"] = {
                    "status": d.get("status") or "in_progress",
                    "completedAt": d.get("completed_at"),
                    "reminderAt": d.get("reminder_at"),
                    "plannedDate": d.get("planned_date"),
                    "dueAt": d.get("due_at"),
                    "priority": d.get("priority") or "normal",
                    "notifyEnabled": bool(d.get("notify_enabled") or 0),
                    "calendarNote": d.get("calendar_note") or "",
                }
        active_plan_id = ""
        if viewer:
            plan_row = conn.execute(
                "SELECT id FROM guide_plans WHERE user_id = ? AND source_journey_key = ? AND status = 'active' "
                "ORDER BY updated_at DESC LIMIT 1",
                (viewer["user_id"], key),
            ).fetchone()
            if plan_row:
                active_plan_id = plan_row["id"]
        self.send_json({
            "status": "ok", "country": country, "language": language,
            "journey": serialize_guide_journey(row, step_count=len(steps)),
            "steps": steps, "progress": progress,
            "hasPlan": bool(active_plan_id), "planId": active_plan_id,
            "createdAt": row["created_at"], "updatedAt": row["updated_at"],
            "disclaimer": _guide_localized_ui("journeyDisclaimer", language, GUIDE_JOURNEY_DISCLAIMER),
        })

    # --- Unified Guide search (articles + schools + companies + products + faq + journeys) ---
    def api_guide_search(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        country = self._guide_country(query)
        language = (query.get("language") or "zh-CN").strip() or "zh-CN"
        keyword = (query.get("q") or query.get("keyword") or "").strip()
        scope = (query.get("scope") or "all").strip() or "all"
        if not self._guide_is_open(country) or not keyword:
            return self.send_json({"status": "ok", "country": country, "query": keyword,
                                   "scopes": GUIDE_SEARCH_SCOPES, "groups": {}})
        like = f"%{keyword}%"
        want = lambda s: scope in ("all", s)
        groups: dict[str, list[dict[str, Any]]] = {}

        def _safe(fn):
            try:
                return fn()
            except Exception:
                return []

        if want("articles"):
            groups["articles"] = _safe(lambda: [
                localize_guide_article_payload(serialize_guide_article(r), language) for r in conn.execute(
                    "SELECT * FROM guide_articles WHERE country = ? AND status = 'published' "
                    "AND (title LIKE ? OR summary LIKE ? OR body LIKE ? OR tags LIKE ? OR category_key LIKE ? OR sub_category_key LIKE ?) "
                    "ORDER BY is_featured DESC, published_at DESC LIMIT 10",
                    (country, like, like, like, like, like, like)).fetchall()])
        if want("schools"):
            groups["schools"] = _safe(lambda: [
                localize_guide_school_payload(serialize_guide_school(r), language) for r in conn.execute(
                    "SELECT * FROM guide_schools WHERE country = ? AND status = 'published' "
                    "AND (school_name LIKE ? OR school_name_jp LIKE ? OR school_name_en LIKE ? OR school_type LIKE ? "
                    "OR prefecture LIKE ? OR city LIKE ? OR fields_of_study LIKE ? OR departments LIKE ? "
                    "OR faculties LIKE ? OR graduate_schools LIKE ? OR tags LIKE ?) "
                    "ORDER BY is_featured DESC, data_quality_score DESC, updated_at DESC LIMIT 8",
                    (country, like, like, like, like, like, like, like, like, like, like, like)).fetchall()])
        if want("companies"):
            groups["companies"] = _safe(lambda: [
                localize_guide_company_payload(serialize_guide_company(r), language) for r in conn.execute(
                    "SELECT * FROM guide_companies WHERE country = ? AND status = 'published' "
                    "AND (company_name LIKE ? OR company_name_jp LIKE ? OR company_name_en LIKE ? OR industry LIKE ? "
                    "OR sub_industry LIKE ? OR prefecture LIKE ? OR city LIKE ? OR description LIKE ? "
                    "OR short_description LIKE ? OR tags LIKE ? OR japanese_level_required LIKE ? OR english_level_required LIKE ?) "
                    "ORDER BY is_featured DESC, data_quality_score DESC, review_count DESC, updated_at DESC LIMIT 8",
                    (country, like, like, like, like, like, like, like, like, like, like, like, like)).fetchall()])
        if want("products"):
            groups["products"] = _safe(lambda: [
                localize_guide_product_payload(serialize_guide_product(r), language) for r in conn.execute(
                    "SELECT * FROM guide_products WHERE country = ? AND status IN ('published','coming_soon') "
                    "AND (title LIKE ? OR subtitle LIKE ? OR description LIKE ? OR tags LIKE ? "
                    "OR target_audience LIKE ? OR product_type LIKE ? OR category_key LIKE ? OR sub_category_key LIKE ?) "
                    "ORDER BY is_coming_soon ASC, sort_order LIMIT 8",
                    (country, like, like, like, like, like, like, like, like)).fetchall()])
        if want("faq"):
            def _faq_search_rows() -> list[Any]:
                # Match guide-home口径: localized rows first, zh-CN fallback when
                # the requested language has no seeded FAQ yet.
                faq_lang = _normalize_language_tag(language)
                sql = ("SELECT * FROM guide_faq WHERE country = ? AND status = 'published' AND language = ? "
                       "AND (question LIKE ? OR answer LIKE ? OR category_key LIKE ?) ORDER BY sort_order LIMIT 8")
                rows = conn.execute(sql, (country, faq_lang, like, like, like)).fetchall()
                if not rows and faq_lang != "zh-CN":
                    rows = conn.execute(sql, (country, "zh-CN", like, like, like)).fetchall()
                return rows
            groups["faq"] = _safe(lambda: [serialize_guide_faq(r) for r in _faq_search_rows()])
        if want("journeys"):
            groups["journeys"] = _safe(lambda: [
                serialize_guide_journey(r) for r in conn.execute(
                    "SELECT * FROM guide_journeys WHERE country = ? AND language = ? AND status = 'published' "
                    "AND (title LIKE ? OR subtitle LIKE ? OR audience LIKE ? OR hero_title LIKE ? OR hero_subtitle LIKE ?) "
                    "ORDER BY sort_order LIMIT 8", (country, language, like, like, like, like, like)).fetchall()])
        self.send_json({"status": "ok", "country": country, "query": keyword,
                        "scopes": GUIDE_SEARCH_SCOPES, "groups": groups})

    # --- Machi AI (原创 in-app assistant) -----------------------------------
    # The user only ever sees "Machi AI". The underlying provider/model never
    # appears in any response, error, or log. Daily limits are enforced here on
    # the server, so a tampered client can't exceed them, and the member limit
    # number is never echoed back to members.

    def _guide_ai_conversation_dto(self, row: Any) -> dict[str, Any]:
        r = dict(row)
        return {
            "id": r.get("id"),
            "title": r.get("title") or "",
            "lastMessagePreview": r.get("last_message_preview") or "",
            "messageCount": int(r.get("message_count") or 0),
            "country": r.get("country") or "jp",
            "language": r.get("language") or "zh-CN",
            "createdAt": r.get("created_at"),
            "updatedAt": r.get("updated_at"),
        }

    def _guide_ai_message_dto(self, row: Any) -> dict[str, Any]:
        r = dict(row)
        out: dict[str, Any] = {
            "id": r.get("id"),
            "role": r.get("role"),
            "content": r.get("content") or "",
            "createdAt": r.get("created_at"),
        }
        # Only assistant turns carry Guide reference sources. model_internal /
        # token counts / finish_reason are intentionally NOT exposed.
        if r.get("role") == "assistant":
            sources: list[Any] = []
            raw = (r.get("sources_json") or "").strip()
            if raw:
                try:
                    parsed = json.loads(raw)
                    if isinstance(parsed, list):
                        sources = parsed
                except Exception:
                    sources = []
            out["sources"] = sources
        return out

    def api_guide_ai_bootstrap(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        # Signed-out guests with a stable X-Machi-Guest-Id get a legal
        # bootstrap too — same payload, remaining computed from the guest cap.
        user: dict[str, Any] | None
        guest_key: str | None = None
        try:
            user = self.require_user(conn)
        except APIError:
            guest_key = machi_ai_guest_key(self.headers.get("X-Machi-Guest-Id"))
            if not guest_key:
                raise
            user = None
        country = self._guide_country(query)
        language = (query.get("language") or "zh-CN").strip() or "zh-CN"
        is_member = bool(user) and has_active_membership(conn, user["id"])
        used = machi_ai_usage_count(conn, user["id"] if user else guest_key, machi_ai_usage_date())
        # Members don't get a number; free users (and guests) see how many
        # remain today under their tier (member / new user / free / guest).
        remaining = None if is_member else max(0, machi_ai_daily_limit(user, is_member) - used)
        self.send_json({
            "status": "ok",
            "membershipActive": is_member,
            "remainingFreeUses": remaining,
            "suggestions": machi_ai_suggestions(language),
            "abilities": machi_ai_abilities_dto(language),
            "disclaimer": machi_ai_text(
                language,
                "Machi AI 可以帮你整理步骤和注意事项，重要决定请以官方与专业意见为准。",
                "Machi AI は手順や注意点の整理をお手伝いします。重要な判断は必ず公式・専門家の意見をご確認ください。",
                "Machi AI helps you organize steps and things to watch for. For important decisions, rely on official and professional advice.",
            ),
        })

    def api_guide_ai_conversations(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        user = self.require_user(conn)
        try:
            limit = int(query.get("limit") or 30)
        except (TypeError, ValueError):
            limit = 30
        limit = max(1, min(limit, 50))
        rows = conn.execute(
            "SELECT * FROM guide_ai_conversations WHERE user_id = ? AND deleted_at = '' "
            "ORDER BY updated_at DESC LIMIT ?",
            (user["id"], limit),
        ).fetchall()
        self.send_json({"status": "ok", "items": [self._guide_ai_conversation_dto(r) for r in rows]})

    def api_guide_ai_messages(self, conn: sqlite3.Connection, conversation_id: str) -> None:
        user = self.require_user(conn)
        conversation_id = (conversation_id or "").strip()
        # Ownership is enforced in the WHERE clause: another user's id never
        # matches, so they get a 404 (can't read someone else's conversation).
        conv = conn.execute(
            "SELECT * FROM guide_ai_conversations WHERE id = ? AND user_id = ? AND deleted_at = ''",
            (conversation_id, user["id"]),
        ).fetchone()
        if not conv:
            return self.send_error_json("conversation not found", 404, "not_found")
        rows = conn.execute(
            "SELECT * FROM guide_ai_messages WHERE conversation_id = ? ORDER BY created_at ASC LIMIT 200",
            (conversation_id,),
        ).fetchall()
        self.send_json({
            "status": "ok",
            "conversation": self._guide_ai_conversation_dto(conv),
            "items": [self._guide_ai_message_dto(r) for r in rows],
        })

    def _guide_ai_quota_response(self, language: str, is_member: bool, *,
                                 is_guest: bool = False) -> None:
        # Free users learn it's a daily free cap (and may upgrade). Members are
        # only told "that's all for today" — never the internal number. Guests
        # are nudged to register (still no number).
        if is_guest:
            msg = machi_ai_text(
                language,
                "今天的体验次数已用完，注册登录后每天可以使用更多次。",
                "本日のお試し回数を使い切りました。登録・ログインすると毎日もっとご利用いただけます。",
                "You've used today's trial question. Sign up or log in to ask more every day.",
            )
        elif is_member:
            msg = machi_ai_text(
                language,
                "今天的 Machi AI 使用次数已用完，明天可以继续咨询。",
                "本日の Machi AI のご利用回数の上限に達しました。明日また利用できます。",
                "You've reached today's Machi AI limit. Please come back tomorrow.",
            )
        else:
            msg = machi_ai_text(
                language,
                "今日免费次数已用完，明天可以继续使用 Machi AI。",
                "本日の無料回数を使い切りました。明日また Machi AI をご利用いただけます。",
                "You've used today's free questions. Machi AI is available again tomorrow.",
            )
        envelope = self._error_envelope("AI_QUOTA_EXCEEDED", msg)
        envelope["upgradeSuggested"] = not is_member
        envelope["usage"] = {
            "membershipActive": is_member,
            "remainingFreeUses": None if is_member else 0,
            "upgradeSuggested": not is_member,
        }
        self.send_json(envelope, 429)

    def _guide_ai_member_ability_response(self, language: str, ability: dict[str, Any]) -> None:
        """403 upgrade prompt when a non-member requests a members-only ability.
        No quota is touched and no upstream call is made."""
        title = ability["title"][{"ja": 1, "en": 2}.get(machi_ai_lang_key(language), 0)]
        msg = machi_ai_text(
            language,
            f"「{title}」是 Machi 会员专属能力。开通会员即可使用，还包含更高每日额度与 Pro 深度模型。",
            f"「{title}」は Machi メンバー限定機能です。メンバーになると利用でき、1日の上限アップと Pro モデルも含まれます。",
            f"“{title}” is a Machi members-only ability. Become a member to use it, plus a higher daily limit and the Pro model.",
        )
        envelope = self._error_envelope("AI_MEMBER_ABILITY_REQUIRED", msg)
        envelope["upgradeSuggested"] = True
        envelope["usage"] = {"membershipActive": False, "remainingFreeUses": None, "upgradeSuggested": True}
        self.send_json(envelope, 403)

    def _machi_ai_reserve_usage(self, conn: sqlite3.Connection, user_id: str,
                                usage_date: str, is_member: bool) -> int:
        """Atomically claim one daily quota slot; return the new running total.

        A single UPSERT increments total_count (and the per-tier counter) and
        RETURNs the post-increment value, so N concurrent callers receive N
        distinct totals. This closes the check-then-increment race where every
        request read the same stale count, passed the gate, and burned a paid
        upstream call. The caller compares the returned count to the daily limit
        and refunds via _machi_ai_refund_usage if it over-claimed. Correct on
        SQLite (single writer) and Postgres (the conflicting row is locked for
        the duration of each INSERT ... ON CONFLICT DO UPDATE)."""
        now = now_iso()
        free_delta = 0 if is_member else 1
        member_delta = 1 if is_member else 0
        row = conn.execute(
            "INSERT INTO guide_ai_usage (id, user_id, usage_date, free_count, member_count, "
            "total_count, prompt_tokens, completion_tokens, updated_at) "
            "VALUES (?, ?, ?, ?, ?, 1, 0, 0, ?) "
            "ON CONFLICT(user_id, usage_date) DO UPDATE SET "
            "total_count = guide_ai_usage.total_count + 1, "
            "free_count = guide_ai_usage.free_count + ?, "
            "member_count = guide_ai_usage.member_count + ?, "
            "updated_at = ? "
            "RETURNING total_count",
            (str(uuid.uuid4()), user_id, usage_date, free_delta, member_delta, now,
             free_delta, member_delta, now),
        ).fetchone()
        return int(row["total_count"]) if row else 0

    def _machi_ai_refund_usage(self, conn: sqlite3.Connection, user_id: str,
                               usage_date: str, is_member: bool) -> None:
        """Give back a slot reserved by _machi_ai_reserve_usage.

        Used when the reservation over-shot the cap (lost the concurrent race)
        or the AI call produced no answer, so quota is only ever spent on a real
        response. Counts are clamped at zero defensively — paired reserve/refund
        can't underflow, but a stray refund must never push a counter negative."""
        free_delta = 0 if is_member else 1
        member_delta = 1 if is_member else 0
        conn.execute(
            "UPDATE guide_ai_usage SET "
            "total_count = MAX(total_count - 1, 0), "
            "free_count = MAX(free_count - ?, 0), "
            "member_count = MAX(member_count - ?, 0), "
            "updated_at = ? WHERE user_id = ? AND usage_date = ?",
            (free_delta, member_delta, now_iso(), user_id, usage_date),
        )

    def _machi_ai_record_usage_tokens(self, conn: sqlite3.Connection, user_id: str,
                                      usage_date: str, usage: dict[str, Any]) -> None:
        """Add the upstream token tallies to today's row after a successful call.

        The quota slot itself was already claimed by _machi_ai_reserve_usage, so
        this only updates the diagnostic token columns and never the counters."""
        prompt = int((usage or {}).get("prompt_tokens") or 0)
        completion = int((usage or {}).get("completion_tokens") or 0)
        if not prompt and not completion:
            return
        conn.execute(
            "UPDATE guide_ai_usage SET prompt_tokens = prompt_tokens + ?, "
            "completion_tokens = completion_tokens + ?, updated_at = ? "
            "WHERE user_id = ? AND usage_date = ?",
            (prompt, completion, now_iso(), user_id, usage_date),
        )

    def api_guide_ai_chat(self, conn: sqlite3.Connection) -> None:
        # Signed-out taster: a stable client UUID in X-Machi-Guest-Id buys the
        # (tiny) guest daily quota; without the header the original 401 stands.
        # Guests also ride the shared IP limiter so one address can't farm
        # extra slots by minting fresh UUIDs.
        user: dict[str, Any] | None
        guest_key: str | None = None
        try:
            user = self.require_user(conn)
        except APIError:
            guest_key = machi_ai_guest_key(self.headers.get("X-Machi-Guest-Id"))
            if not guest_key:
                raise
            if not rate_check(self._client_ip(), "ai_guest"):
                raise APIError("操作过于频繁，请稍后再试", 429, "rate_limited")
            user = None
        if user is not None:
            self._enforce_not_muted(user)
        # The usage ledger / conversation owner key: real user id or guest hash.
        subject_id = user["id"] if user else guest_key
        body = self.read_json()
        country = (str(body.get("country") or "").strip().lower()) or GUIDE_DEFAULT_COUNTRY
        country = _normalize_country_code(country) or GUIDE_DEFAULT_COUNTRY
        language = (str(body.get("language") or "zh-CN").strip()) or "zh-CN"
        message = str(body.get("message") or "").strip()
        if not message:
            return self.send_error_json(
                machi_ai_text(language, "请输入你的问题。", "質問を入力してください。", "Please enter your question."),
                400, "invalid_message",
            )
        if len(message) > MACHI_AI_MAX_INPUT_CHARS:
            return self.send_error_json(
                machi_ai_text(language, "消息太长了，请精简后再发送。", "メッセージが長すぎます。短くしてください。",
                              "Your message is too long — please shorten it."),
                400, "invalid_message",
            )

        usage_date = machi_ai_usage_date()
        is_member = bool(user) and has_active_membership(conn, user["id"])
        limit = machi_ai_daily_limit(user, is_member)
        # Specialized member-only abilities (resume polish / mock interview).
        # An unknown/empty ability falls back to general chat. A member-only
        # ability requested by a non-member returns an upgrade prompt BEFORE any
        # quota is touched or upstream call is made.
        ability = machi_ai_ability(body.get("ability"))
        if ability and ability["member_only"] and not is_member:
            return self._guide_ai_member_ability_response(language, ability)
        # Cheap, non-authoritative fast path: reject an obviously over-quota
        # caller before doing any retrieval work. This read alone is racy (N
        # concurrent requests all see the same stale count), so the real gate is
        # the atomic reservation just before the upstream call below.
        if machi_ai_usage_count(conn, subject_id, usage_date) >= limit:
            return self._guide_ai_quota_response(language, is_member, is_guest=user is None)

        # Resolve (but don't yet create) the conversation, and pull recent
        # history. Persisting is deferred until the AI call succeeds, so a hard
        # provider failure never leaves orphan rows or burns a quota slot.
        conv_id = str(body.get("conversationId") or body.get("conversation_id") or "").strip() or None
        conv_row = None
        if conv_id:
            conv_row = conn.execute(
                "SELECT * FROM guide_ai_conversations WHERE id = ? AND user_id = ? AND deleted_at = ''",
                (conv_id, subject_id),
            ).fetchone()
            if not conv_row:
                return self.send_error_json(
                    machi_ai_text(language, "对话不存在或已删除。", "会話が見つかりません。", "Conversation not found."),
                    404, "not_found",
                )

        history: list[dict[str, Any]] = []
        if conv_row is not None:
            hist_rows = conn.execute(
                "SELECT role, content FROM guide_ai_messages WHERE conversation_id = ? "
                "ORDER BY created_at DESC LIMIT ?",
                (conv_id, MACHI_AI_MAX_HISTORY_MESSAGES),
            ).fetchall()
            history = [dict(r) for r in reversed(hist_rows)]

        try:
            context_items = guide_ai_retrieve_context(
                conn, user_message=message, country=country, language=language,
                limit=MACHI_AI_MAX_CONTEXT_ITEMS,
            )
        except Exception:
            context_items = []

        messages = machi_ai_build_messages(
            user_message=message, language=language, history=history, context_items=context_items,
            ability=ability,
        )
        thinking = machi_ai_is_complex(message) or bool(ability and ability.get("force_thinking"))
        # Atomically claim a quota slot BEFORE spending money upstream. The
        # reservation increments and returns today's running total in one
        # statement, so concurrent requests get distinct totals and only those
        # landing within the cap proceed — closing the check-then-increment race
        # that let a burst exceed the free/member cap and burn real tokens. A
        # failed AI call refunds the slot below, preserving "quota is only ever
        # spent on a real answer".
        reserved = self._machi_ai_reserve_usage(conn, subject_id, usage_date, is_member)
        if reserved > limit:
            self._machi_ai_refund_usage(conn, subject_id, usage_date, is_member)
            return self._guide_ai_quota_response(language, is_member, is_guest=user is None)
        completion = None
        # 会员用 Pro 深度模型,免费用户用基础模型 —— 这是会员的核心价值之一。
        # 若 Pro 模型上游异常,下方 try/except 会优雅降级为 AI_UNAVAILABLE 并退还
        # 额度,不会影响会员正常使用其它功能。
        chat_model = MACHI_AI_PRO_MODEL if (is_member and MACHI_AI_PRO_MODEL) else MACHI_AI_MODEL
        try:
            completion = seed_llm.machi_ai_chat_completion(
                messages,
                model=chat_model,
                thinking=thinking,
                max_tokens=1600,
                timeout=MACHI_AI_TIMEOUT_SEC,
            )
        except Exception:
            # Never surface the provider's raw error — degrade to "unavailable".
            completion = None
        if not completion or not str(completion.get("content") or "").strip():
            # No answer was produced — refund the reserved slot so a provider
            # failure never costs the user a quota slot.
            self._machi_ai_refund_usage(conn, subject_id, usage_date, is_member)
            return self.send_json(
                self._error_envelope("AI_UNAVAILABLE", machi_ai_text(
                    language,
                    "Machi AI 暂时无法回答，请稍后再试。",
                    "Machi AI は現在応答できません。しばらくしてから再度お試しください。",
                    "Machi AI is temporarily unavailable. Please try again shortly.",
                )),
                503,
            )

        assistant_content = str(completion.get("content") or "").strip()
        usage = completion.get("usage") or {}
        # Public sources for the client: type/title/subtitle/route only.
        client_sources = [
            {"type": it["type"], "title": it["title"], "subtitle": it.get("subtitle") or "",
             "route": it.get("route") or {}}
            for it in context_items
        ]

        now = now_iso()
        if conv_row is None:
            conv_id = str(uuid.uuid4())
            conn.execute(
                "INSERT INTO guide_ai_conversations (id, user_id, title, country, language, "
                "last_message_preview, message_count, created_at, updated_at, deleted_at) "
                "VALUES (?, ?, ?, ?, ?, '', 0, ?, ?, '')",
                (conv_id, subject_id, _machi_ai_title_from_message(message), country, language, now, now),
            )
        # User turn.
        conn.execute(
            "INSERT INTO guide_ai_messages (id, conversation_id, user_id, role, content, source_count, "
            "sources_json, model_internal, finish_reason, prompt_tokens, completion_tokens, total_tokens, "
            "latency_ms, created_at) VALUES (?, ?, ?, 'user', ?, 0, '', '', '', 0, 0, 0, 0, ?)",
            (str(uuid.uuid4()), conv_id, subject_id, message, now),
        )
        # Assistant turn. model_internal is for diagnostics only; never returned.
        assistant_msg_id = str(uuid.uuid4())
        assistant_now = now_iso()
        conn.execute(
            "INSERT INTO guide_ai_messages (id, conversation_id, user_id, role, content, source_count, "
            "sources_json, model_internal, finish_reason, prompt_tokens, completion_tokens, total_tokens, "
            "latency_ms, created_at) VALUES (?, ?, ?, 'assistant', ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
            (assistant_msg_id, conv_id, subject_id, assistant_content, len(client_sources),
             json.dumps(client_sources, ensure_ascii=False), str(completion.get("model") or ""),
             str(completion.get("finish_reason") or ""), int(usage.get("prompt_tokens") or 0),
             int(usage.get("completion_tokens") or 0), int(usage.get("total_tokens") or 0),
             int(completion.get("latency_ms") or 0), assistant_now),
        )
        preview = " ".join(assistant_content.split())[:80]
        conn.execute(
            "UPDATE guide_ai_conversations SET last_message_preview = ?, "
            "message_count = message_count + 2, updated_at = ? WHERE id = ?",
            (preview, assistant_now, conv_id),
        )
        # The quota slot was reserved before the call; only the token tallies
        # remain to be recorded.
        self._machi_ai_record_usage_tokens(conn, subject_id, usage_date, usage)

        remaining = None if is_member else max(0, limit - reserved)
        self.send_json({
            "status": "ok",
            "conversationId": conv_id,
            "message": {
                "id": assistant_msg_id,
                "role": "assistant",
                "content": assistant_content,
                "createdAt": assistant_now,
                "sources": client_sources,
            },
            "usage": {
                "membershipActive": is_member,
                "remainingFreeUses": remaining,
                "upgradeSuggested": (not is_member) and remaining == 0,
            },
        })

    def api_guide_ai_conversation_delete(self, conn: sqlite3.Connection, conversation_id: str) -> None:
        user = self.require_user(conn)
        conversation_id = (conversation_id or "").strip()
        conv = conn.execute(
            "SELECT id FROM guide_ai_conversations WHERE id = ? AND user_id = ? AND deleted_at = ''",
            (conversation_id, user["id"]),
        ).fetchone()
        if not conv:
            return self.send_error_json("conversation not found", 404, "not_found")
        now = now_iso()
        conn.execute(
            "UPDATE guide_ai_conversations SET deleted_at = ?, updated_at = ? WHERE id = ? AND user_id = ?",
            (now, now, conversation_id, user["id"]),
        )
        self.send_json({"status": "ok"})

    def api_guide_ai_feedback(self, conn: sqlite3.Connection, message_id: str) -> None:
        user = self.require_user(conn)
        message_id = (message_id or "").strip()
        body = self.read_json()
        rating = str(body.get("rating") or "").strip().lower()
        if rating not in ("helpful", "not_helpful"):
            return self.send_error_json("invalid rating", 400, "invalid_body")
        reason = str(body.get("reason") or "").strip()[:500]
        # The message must exist and belong to this user.
        msg = conn.execute(
            "SELECT id FROM guide_ai_messages WHERE id = ? AND user_id = ?",
            (message_id, user["id"]),
        ).fetchone()
        if not msg:
            return self.send_error_json("message not found", 404, "not_found")
        conn.execute(
            "INSERT INTO guide_ai_feedback (id, user_id, message_id, rating, reason, created_at) "
            "VALUES (?, ?, ?, ?, ?, ?)",
            (str(uuid.uuid4()), user["id"], message_id, rating, reason, now_iso()),
        )
        self.send_json({"status": "ok", "rating": rating})

    # --- Per-user Guide progress (login required) ---------------------------
    def _guide_progress_summary(self, conn: sqlite3.Connection, user_id: str,
                                items: list[dict[str, Any]]) -> list[dict[str, Any]]:
        done_by_journey: dict[str, int] = {}
        for it in items:
            if it.get("status") == "done" and it.get("stepKey"):
                done_by_journey[it["journeyKey"]] = done_by_journey.get(it["journeyKey"], 0) + 1
        summaries: list[dict[str, Any]] = []
        for jkey, done in done_by_journey.items():
            total = conn.execute(
                "SELECT COUNT(*) AS c FROM guide_journey_steps WHERE journey_key = ? AND status = 'published'",
                (jkey,),
            ).fetchone()["c"]
            total = int(total)
            summaries.append({"journeyKey": jkey, "done": done, "total": total,
                              "percent": int(round(done * 100 / total)) if total else 0})
        return summaries

    def api_guide_progress(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        user = self.require_user(conn)
        rows = conn.execute(
            "SELECT * FROM guide_user_progress WHERE user_id = ? ORDER BY updated_at DESC", (user["id"],)
        ).fetchall()
        items = [serialize_guide_progress(r) for r in rows]
        self.send_json({"status": "ok", "items": items,
                        "summary": self._guide_progress_summary(conn, user["id"], items)})

    def api_guide_progress_update(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        body = self.read_json()
        journey_key = str(body.get("journeyKey") or "").strip()
        step_key = str(body.get("stepKey") or "").strip()
        status = str(body.get("status") or "in_progress").strip()
        if not journey_key:
            return self.send_error_json("journeyKey required", 400, "invalid_body")
        if status not in GUIDE_PROGRESS_STATUSES:
            return self.send_error_json("invalid status", 400, "invalid_body")
        now = now_iso()
        completed_at = now if status == "done" else None
        reminder_at = str(body.get("reminderAt") or "").strip() or None
        planned_date = _guide_date_value(body.get("plannedDate") or body.get("planned_date"))
        due_at = _guide_date_value(body.get("dueAt") or body.get("due_at"))
        priority = str(body.get("priority") or "normal").strip()[:40] or "normal"
        notify_enabled = 1 if _guide_bool_value(body.get("notifyEnabled") or body.get("notify_enabled")) else 0
        calendar_note = str(body.get("calendarNote") or body.get("calendar_note") or "").strip()[:1000]
        notes = str(body.get("notes") or "")[:2000]
        progress_cols = _table_columns(conn, "guide_user_progress")
        supports_planning_fields = all(
            col in progress_cols for col in ("planned_date", "due_at", "priority", "notify_enabled", "calendar_note")
        )
        existing = conn.execute(
            "SELECT id FROM guide_user_progress WHERE user_id = ? AND journey_key = ? AND step_key = ?",
            (user["id"], journey_key, step_key),
        ).fetchone()
        if existing:
            if supports_planning_fields:
                conn.execute(
                    "UPDATE guide_user_progress SET status = ?, completed_at = ?, "
                    "reminder_at = COALESCE(?, reminder_at), planned_date = COALESCE(?, planned_date), "
                    "due_at = COALESCE(?, due_at), priority = ?, notify_enabled = ?, calendar_note = ?, "
                    "notes = ?, updated_at = ? WHERE id = ?",
                    (status, completed_at, reminder_at, planned_date, due_at, priority, notify_enabled, calendar_note, notes, now, existing["id"]),
                )
            else:
                conn.execute(
                    "UPDATE guide_user_progress SET status = ?, completed_at = ?, "
                    "reminder_at = COALESCE(?, reminder_at), notes = ?, updated_at = ? WHERE id = ?",
                    (status, completed_at, reminder_at, notes, now, existing["id"]),
                )
        else:
            if supports_planning_fields:
                conn.execute(
                    "INSERT INTO guide_user_progress (id, user_id, journey_key, step_key, status, completed_at, reminder_at, "
                    "planned_date, due_at, priority, notify_enabled, calendar_note, notes, created_at, updated_at) "
                    "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
                    (str(uuid.uuid4()), user["id"], journey_key, step_key, status, completed_at, reminder_at,
                     planned_date, due_at, priority, notify_enabled, calendar_note, notes, now, now),
                )
            else:
                conn.execute(
                    "INSERT INTO guide_user_progress (id, user_id, journey_key, step_key, status, completed_at, reminder_at, notes, created_at, updated_at) "
                    "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
                    (str(uuid.uuid4()), user["id"], journey_key, step_key, status, completed_at, reminder_at, notes, now, now),
                )
        # Keep the plan todo (if any) in lockstep so there is one unified progress.
        self._guide_sync_progress_to_todo(
            conn, user["id"], journey_key, step_key, status, now,
            planned_date=planned_date, due_at=due_at, reminder_at=reminder_at, priority=priority,
        )
        rows = conn.execute(
            "SELECT * FROM guide_user_progress WHERE user_id = ? ORDER BY updated_at DESC", (user["id"],)
        ).fetchall()
        items = [serialize_guide_progress(r) for r in rows]
        self.send_json({"status": "ok", "items": items,
                        "summary": self._guide_progress_summary(conn, user["id"], items)})

    # --- Guide OS: server-first profile / plans / todos / calendar ------------
    def _guide_user_profile_row(self, conn: sqlite3.Connection, user_id: str):
        return conn.execute("SELECT * FROM guide_user_profiles WHERE user_id = ? LIMIT 1", (user_id,)).fetchone()

    def api_guide_profile(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        user = self.require_user(conn)
        self.send_json({"status": "ok", "profile": serialize_guide_profile(self._guide_user_profile_row(conn, user["id"]))})

    def api_guide_profile_update(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        body = self.read_json()
        now = now_iso()
        existing = self._guide_user_profile_row(conn, user["id"])
        # arrival_stage: absent key = "leave unchanged". iOS's reminder-settings
        # save (GuideProfileSetupView) posts a payload without arrivalStage, so
        # full-replace semantics would silently wipe the stage picked during
        # onboarding. An explicit value (even junk, coerced to '') still writes.
        if "arrivalStage" in body or "arrival_stage" in body:
            arrival_stage = _guide_arrival_stage_value(body.get("arrivalStage") or body.get("arrival_stage"))
        else:
            arrival_stage = _guide_arrival_stage_value(existing["arrival_stage"]) if existing else ""
        values = {
            "identity_type": str(body.get("identityType") or body.get("identity_type") or "").strip()[:80],
            "country": str(body.get("country") or "jp").strip().lower()[:20] or "jp",
            "city": str(body.get("city") or "").strip()[:120],
            "is_in_japan": 1 if _guide_bool_value(body.get("isInJapan") or body.get("is_in_japan")) else 0,
            "arrival_stage": arrival_stage,
            "visa_status": str(body.get("visaStatus") or body.get("visa_status") or "").strip()[:120],
            "visa_expires_at": _guide_date_value(body.get("visaExpiresAt") or body.get("visa_expires_at")),
            "japanese_level": str(body.get("japaneseLevel") or body.get("japanese_level") or "").strip()[:40],
            "target_japanese_level": str(body.get("targetJapaneseLevel") or body.get("targetLevel") or body.get("target_japanese_level") or "").strip()[:40],
            "graduation_date": _guide_date_value(body.get("graduationDate") or body.get("graduation_date")),
            "target_entry_term": str(body.get("targetEntryTerm") or body.get("target_entry_term") or "").strip()[:80],
            "target_industry": str(body.get("targetIndustry") or body.get("target_industry") or "").strip()[:120],
            "target_school_type": str(body.get("targetSchoolType") or body.get("target_school_type") or "").strip()[:80],
            "weekly_available_minutes": _guide_int(body.get("weeklyAvailableMinutes") or body.get("weekly_available_minutes"), 0, lo=0, hi=10080),
            "needs_materials": 1 if _guide_bool_value(body.get("needsMaterials") or body.get("needs_materials")) else 0,
            "needs_services": 1 if _guide_bool_value(body.get("needsServices") or body.get("needs_services")) else 0,
        }
        if existing:
            conn.execute(
                "UPDATE guide_user_profiles SET identity_type = ?, country = ?, city = ?, is_in_japan = ?, "
                "arrival_stage = ?, visa_status = ?, visa_expires_at = ?, japanese_level = ?, target_japanese_level = ?, "
                "graduation_date = ?, target_entry_term = ?, target_industry = ?, target_school_type = ?, "
                "weekly_available_minutes = ?, needs_materials = ?, needs_services = ?, updated_at = ? WHERE id = ?",
                (
                    values["identity_type"], values["country"], values["city"], values["is_in_japan"],
                    values["arrival_stage"],
                    values["visa_status"], values["visa_expires_at"], values["japanese_level"], values["target_japanese_level"],
                    values["graduation_date"], values["target_entry_term"], values["target_industry"], values["target_school_type"],
                    values["weekly_available_minutes"], values["needs_materials"], values["needs_services"], now, existing["id"],
                ),
            )
        else:
            conn.execute(
                "INSERT INTO guide_user_profiles (id, user_id, identity_type, country, city, is_in_japan, arrival_stage, visa_status, "
                "visa_expires_at, japanese_level, target_japanese_level, graduation_date, target_entry_term, target_industry, "
                "target_school_type, weekly_available_minutes, needs_materials, needs_services, created_at, updated_at) "
                "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
                (
                    str(uuid.uuid4()), user["id"], values["identity_type"], values["country"], values["city"], values["is_in_japan"],
                    values["arrival_stage"],
                    values["visa_status"], values["visa_expires_at"], values["japanese_level"], values["target_japanese_level"],
                    values["graduation_date"], values["target_entry_term"], values["target_industry"], values["target_school_type"],
                    values["weekly_available_minutes"], values["needs_materials"], values["needs_services"], now, now,
                ),
            )
        generated_count = self._guide_sync_profile_derived(conn, user["id"], values["visa_expires_at"], values["graduation_date"])
        self.send_json({
            "status": "ok",
            "profile": serialize_guide_profile(self._guide_user_profile_row(conn, user["id"])),
            "generatedTodoCount": generated_count,
        })

    def _guide_sync_profile_derived(self, conn: sqlite3.Connection, user_id: str,
                                    visa_expires_at: str | None, graduation_date: str | None) -> int:
        """Auto-derive deadline todos straight from the identity profile, so
        saving identity visibly produces something (the spec's value loop).
        Idempotent: clears prior derived rows, then re-creates from the current
        dates. The calendar + APNs reminders pick these up via due_at."""
        generated = 0
        try:
            conn.execute(
                "DELETE FROM guide_todos WHERE user_id = ? AND source_type = 'profile' AND source_id IN ('visa', 'graduation')",
                (user_id,),
            )
            if visa_expires_at:
                self._guide_todo_insert(
                    conn, user_id=user_id, source_type="profile", source_id="visa",
                    title="在留资格更新 / 在留卡期限", summary="在到期前预约入管、备齐材料办理在留更新，避免逾期。",
                    todo_type="visa_renewal", due_at=visa_expires_at,
                    reminder_at=_guide_date_minus(visa_expires_at, 60), priority="high",
                    product_slugs="work-visa-change-checklist", service_slugs="japanese-document-translation",
                )
                generated += 1
            if graduation_date:
                self._guide_todo_insert(
                    conn, user_id=user_id, source_type="profile", source_id="graduation",
                    title="毕业 / 入社时间线", summary="按毕业时间反推就活或升学的关键节点，提前准备材料。",
                    todo_type="career_timeline", due_at=graduation_date,
                    reminder_at=_guide_date_minus(graduation_date, 90), priority="normal",
                )
                generated += 1
        except Exception:
            return 0
        return generated

    def _guide_plan_summary(self, conn: sqlite3.Connection, plan_id: str) -> dict[str, Any]:
        rows = conn.execute("SELECT status FROM guide_todos WHERE plan_id = ?", (plan_id,)).fetchall()
        total = len(rows)
        done = sum(1 for r in rows if (r["status"] or "") == "done")
        percent = int(round(done * 100 / total)) if total else 0
        next_row = conn.execute(
            "SELECT * FROM guide_todos WHERE plan_id = ? AND status NOT IN ('done','skipped') "
            "ORDER BY COALESCE(planned_date, due_at, updated_at), created_at LIMIT 1",
            (plan_id,),
        ).fetchone()
        return {
            "todoTotal": total,
            "todoDone": done,
            "progressPercent": percent,
            "nextTodo": serialize_guide_todo(next_row) if next_row else None,
        }

    def _guide_update_plan_progress(self, conn: sqlite3.Connection, plan_id: str) -> None:
        if not plan_id:
            return
        summary = self._guide_plan_summary(conn, plan_id)
        next_todo = summary.get("nextTodo") or {}
        conn.execute(
            "UPDATE guide_plans SET progress_percent = ?, current_todo_id = ?, updated_at = ? WHERE id = ?",
            (int(summary.get("progressPercent") or 0), next_todo.get("id") or "", now_iso(), plan_id),
        )

    def _guide_plan_payload(self, conn: sqlite3.Connection, plan_row: sqlite3.Row | dict[str, Any] | None) -> dict[str, Any] | None:
        if not plan_row:
            return None
        return serialize_guide_plan(plan_row, self._guide_plan_summary(conn, dict(plan_row)["id"]))

    def _guide_ensure_todo_columns(self, conn: sqlite3.Connection) -> None:
        """Self-heal older production Guide todo tables before hot-path reads/writes.

        The boot migration normally handles this, but Guide endpoints should not
        500 if a production snapshot has a skipped migration record or an older
        table created before planned dates / recurrence / steps existed.
        """
        _ensure_columns(conn, "guide_todos", {
            "plan_id": "TEXT NOT NULL DEFAULT ''",
            "source_type": "TEXT NOT NULL DEFAULT ''",
            "source_id": "TEXT NOT NULL DEFAULT ''",
            "journey_key": "TEXT NOT NULL DEFAULT ''",
            "step_key": "TEXT NOT NULL DEFAULT ''",
            "summary": "TEXT NOT NULL DEFAULT ''",
            "todo_type": "TEXT NOT NULL DEFAULT 'guide_step'",
            "status": "TEXT NOT NULL DEFAULT 'not_started'",
            "priority": "TEXT NOT NULL DEFAULT 'normal'",
            "planned_date": "TEXT",
            "due_at": "TEXT",
            "reminder_at": "TEXT",
            "completed_at": "TEXT",
            "estimated_minutes": "INTEGER NOT NULL DEFAULT 0",
            "notes": "TEXT NOT NULL DEFAULT ''",
            "related_article_slugs": "TEXT NOT NULL DEFAULT ''",
            "related_product_slugs": "TEXT NOT NULL DEFAULT ''",
            "related_service_slugs": "TEXT NOT NULL DEFAULT ''",
            "recurrence": "TEXT NOT NULL DEFAULT ''",
            "steps": "TEXT NOT NULL DEFAULT '[]'",
            "list_name": "TEXT NOT NULL DEFAULT ''",
            "tags": "TEXT NOT NULL DEFAULT ''",
        })

    def _guide_os_recommendation_payload(
        self,
        conn: sqlite3.Connection,
        *,
        profile: sqlite3.Row | dict[str, Any] | None,
        todo_rows: list[sqlite3.Row] | list[dict[str, Any]],
        language: str = "zh-CN",
        limit: int = 4,
    ) -> dict[str, list[dict[str, Any]]]:
        product_slugs: list[str] = []
        service_slugs: list[str] = []

        def add(slugs: list[str], values: list[str] | tuple[str, ...]) -> None:
            for raw in values:
                slug = str(raw or "").strip()
                if slug and slug not in slugs:
                    slugs.append(slug)

        def infer(todo: dict[str, Any]) -> None:
            haystack = " ".join([
                str(todo.get("todo_type") or ""),
                str(todo.get("journey_key") or ""),
                str(todo.get("source_type") or ""),
                str(todo.get("title") or ""),
                str(todo.get("summary") or ""),
            ]).lower()
            if any(k in haystack for k in ("school_application", "grad_school", "research", "研究计划", "出愿", "大学院", "教授")):
                add(product_slugs, [
                    "graduate-school-application-full-pack", "research-plan-template-pack",
                    "professor-email-template-pack", "application-documents-checklist",
                    "graduate-school-interview-100",
                ])
                add(service_slugs, ["research-plan-review-service", "graduate-school-consultation", "research-plan-revision"])
            if any(k in haystack for k in ("company_es", "company_interview", "job", "career", "履历", "職務", "面试", "es", "志望")):
                add(product_slugs, [
                    "rirekisho-template-pack", "shokumukeirekisho-template-pack",
                    "self-pr-motivation-template", "interview-100-questions",
                ])
                add(service_slugs, [
                    "rirekisho-review-service", "shokumukeirekisho-review-service",
                    "es-motivation-revision", "japan-job-mock-interview",
                ])
            if any(k in haystack for k in ("jlpt", "n1", "n2", "n3", "n4", "n5", "日语", "日本語")):
                add(product_slugs, [
                    "jlpt-n5-n1-roadmap", "jlpt-n3-30-day-plan", "n2-grammar-pack",
                    "jlpt-n2-20-year-trend-analysis", "jlpt-n1-20-year-trend-analysis",
                ])
            if any(k in haystack for k in ("life_payment", "arrival", "housing", "rent", "bank", "mobile", "visa", "房租", "水电", "手机", "银行卡", "役所", "签证")):
                add(product_slugs, [
                    "bank-account-document-checklist", "mobile-plan-comparison",
                    "national-health-insurance-checklist", "work-visa-change-checklist",
                ])
                add(service_slugs, [
                    "housing-application-support", "city-hall-procedure-support",
                    "bank-account-support", "mobile-sim-support", "japanese-phone-call-proxy",
                    "delivery-utility-call", "japan-life-consultation",
                ])
            if any(k in haystack for k in ("language_school", "coe", "语言学校", "留学", "入境")):
                add(product_slugs, ["language-school-doc-checklist", "language-school-selection-guide", "coe-material-guide"])
                add(service_slugs, ["language-school-consultation", "language-school-application-consult", "japanese-document-translation"])

        for row in todo_rows:
            todo = dict(row)
            add(product_slugs, _guide_split_tags(todo.get("related_product_slugs")))
            add(service_slugs, _guide_split_tags(todo.get("related_service_slugs")))
            infer(todo)

        if profile:
            p = dict(profile)
            identity = str(p.get("identity_type") or "").lower()
            target = " ".join([str(p.get("target_school_type") or ""), str(p.get("target_industry") or ""), str(p.get("target_japanese_level") or "")]).lower()
            if any(k in identity + " " + target for k in ("language", "留学", "school", "student")):
                add(product_slugs, ["language-school-doc-checklist", "language-school-selection-guide", "jlpt-n5-n1-roadmap"])
                add(service_slugs, ["language-school-consultation"])
            if any(k in identity + " " + target for k in ("worker", "career", "company", "转职", "就职")):
                add(product_slugs, ["rirekisho-template-pack", "shokumukeirekisho-template-pack"])
                add(service_slugs, ["shokumukeirekisho-review-service", "japan-job-mock-interview"])
            if any(k in identity + " " + target for k in ("graduate", "大学院", "研究")):
                add(product_slugs, ["research-plan-template-pack", "graduate-school-application-full-pack"])
                add(service_slugs, ["research-plan-review-service", "graduate-school-consultation"])
            if bool(p.get("needs_materials")):
                add(product_slugs, ["application-documents-checklist", "jlpt-n5-n1-roadmap"])
            if bool(p.get("needs_services")):
                add(service_slugs, ["japan-life-consultation", "japanese-phone-call-proxy"])

        slugs = product_slugs + service_slugs
        if not slugs:
            rows = conn.execute(
                "SELECT * FROM guide_products WHERE country = 'jp' AND status IN ('published','coming_soon') "
                "ORDER BY is_service ASC, is_coming_soon ASC, is_featured DESC, sort_order LIMIT ?",
                (limit * 2,),
            ).fetchall()
        else:
            placeholders = ",".join("?" * len(slugs))
            rows = conn.execute(
                f"SELECT * FROM guide_products WHERE country = 'jp' AND status IN ('published','coming_soon') AND slug IN ({placeholders})",
                tuple(slugs),
            ).fetchall()
            order = {slug: idx for idx, slug in enumerate(slugs)}
            rows = sorted(rows, key=lambda r: order.get(r["slug"], 9999))

        products: list[dict[str, Any]] = []
        services: list[dict[str, Any]] = []
        for row in rows:
            payload = localize_guide_product_payload(serialize_guide_product(row), language)
            if bool(row["is_service"]):
                if len(services) < limit:
                    services.append(payload)
            elif len(products) < limit:
                products.append(payload)
        return {"recommendedProducts": products, "recommendedServices": services}

    def _guide_todo_insert(self, conn: sqlite3.Connection, *, user_id: str, plan_id: str = "", source_type: str = "",
                           source_id: str = "", journey_key: str = "", step_key: str = "", title: str,
                           summary: str = "", todo_type: str = "guide_step", priority: str = "normal",
                           planned_date: str | None = None, due_at: str | None = None, reminder_at: str | None = None,
                           estimated_minutes: int = 0, notes: str = "", article_slugs: str = "",
                           product_slugs: str = "", service_slugs: str = "", recurrence: str = "") -> str:
        now = now_iso()
        todo_id = str(uuid.uuid4())
        self._guide_ensure_todo_columns(conn)
        conn.execute(
            "INSERT INTO guide_todos (id, user_id, plan_id, source_type, source_id, journey_key, step_key, title, summary, "
            "todo_type, status, priority, planned_date, due_at, reminder_at, estimated_minutes, notes, "
            "related_article_slugs, related_product_slugs, related_service_slugs, recurrence, created_at, updated_at) "
            "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'not_started', ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
            (
                todo_id, user_id, plan_id, source_type, source_id, journey_key, step_key, title[:200], summary[:1000],
                todo_type, priority[:40], planned_date, due_at, reminder_at, int(estimated_minutes or 0), notes[:2000],
                article_slugs, product_slugs, service_slugs, recurrence[:20], now, now,
            ),
        )
        if reminder_at:
            self._guide_schedule_reminders(conn, user_id=user_id, todo_id=todo_id, plan_id=plan_id,
                                           title=title[:200], reminder_at=reminder_at, due_at=due_at or "",
                                           multi_tier=todo_type in _GUIDE_MULTI_TIER_TODO_TYPES)
        return todo_id

    def _guide_schedule_reminders(self, conn: sqlite3.Connection, *, user_id: str, todo_id: str,
                                  plan_id: str = "", title: str = "", reminder_at: str | None = None,
                                  due_at: str = "", multi_tier: bool = False) -> None:
        """Schedule reminders for a todo. The single guide_reminders row (UNIQUE
        per user+todo) holds the *next* upcoming tier; the dispatcher rolls it
        forward to T-3 then T-1 after each fire, so high-value deadlines get a
        T-7/T-3/T-1 ladder without breaking the unique constraint. (spec P1)"""
        if not user_id or not todo_id:
            return
        today = now_iso()[:10]
        tiers = _guide_reminder_tier_dates(due_at, reminder_at, multi_tier)
        if not tiers:
            self._guide_set_reminder_status(conn, user_id=user_id, todo_id=todo_id, status="cancelled")
            return
        # First not-yet-passed tier (else the last one, so a late add still pings).
        future = [d for d in tiers if d >= today]
        first = future[0] if future else tiers[-1]
        self._guide_upsert_reminder(conn, user_id=user_id, todo_id=todo_id, plan_id=plan_id,
                                    title=title, reminder_at=first, status="active")

    def _guide_set_reminder_status(self, conn: sqlite3.Connection, *, user_id: str, todo_id: str, status: str) -> None:
        """Bulk-update every reminder for a todo (e.g. all → 'completed' when the
        todo is done, 'cancelled' when its date is cleared)."""
        if not user_id or not todo_id:
            return
        conn.execute(
            "UPDATE guide_reminders SET status = ?, updated_at = ? WHERE user_id = ? AND todo_id = ? AND status = 'active'",
            (status[:40] or "active", now_iso(), user_id, todo_id),
        )

    def _guide_upsert_reminder(self, conn: sqlite3.Connection, *, user_id: str, todo_id: str,
                               plan_id: str = "", title: str = "", reminder_at: str | None = None,
                               status: str = "active") -> None:
        # Back-compat single-row helper (kept for any legacy callers).
        if not user_id or not todo_id:
            return
        now = now_iso()
        existing = conn.execute(
            "SELECT id FROM guide_reminders WHERE user_id = ? AND todo_id = ? LIMIT 1",
            (user_id, todo_id),
        ).fetchone()
        if existing:
            conn.execute(
                "UPDATE guide_reminders SET plan_id = ?, title = ?, reminder_at = ?, status = ?, updated_at = ? WHERE id = ?",
                (plan_id, title[:200], reminder_at, status[:40] or "active", now, existing["id"]),
            )
        else:
            conn.execute(
                "INSERT INTO guide_reminders (id, user_id, todo_id, plan_id, title, reminder_at, channel, status, created_at, updated_at) "
                "VALUES (?, ?, ?, ?, ?, ?, 'app', ?, ?, ?)",
                (str(uuid.uuid4()), user_id, todo_id, plan_id, title[:200], reminder_at, status[:40] or "active", now, now),
            )

    def _guide_create_journey_todos(self, conn: sqlite3.Connection, user_id: str, plan_id: str,
                                    journey_key: str, target_date: str | None = None) -> None:
        steps = conn.execute(
            "SELECT * FROM guide_journey_steps WHERE journey_key = ? AND country = 'jp' AND status = 'published' ORDER BY sort_order",
            (journey_key,),
        ).fetchall()
        base = _guide_today_date()
        for idx, step in enumerate(steps):
            planned = _guide_date_add(idx, base)
            self._guide_todo_insert(
                conn,
                user_id=user_id,
                plan_id=plan_id,
                source_type="journey_step",
                source_id=step["id"],
                journey_key=journey_key,
                step_key=step["step_key"],
                title=step["title"],
                summary=step["summary"] or "",
                todo_type="guide_step",
                priority="normal" if step["required"] else "low",
                planned_date=planned,
                due_at=planned if not target_date else None,
                estimated_minutes=int(step["estimated_minutes"] or 0),
                article_slugs=step["article_slugs"] or "",
                product_slugs=step["product_slugs"] or "",
            )

    def api_guide_plans(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        user = self.require_user(conn)
        rows = conn.execute(
            "SELECT * FROM guide_plans WHERE user_id = ? ORDER BY status = 'active' DESC, updated_at DESC",
            (user["id"],),
        ).fetchall()
        self.send_json({"status": "ok", "items": [self._guide_plan_payload(conn, r) for r in rows]})

    def api_guide_active_plan(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        user = self.require_user(conn)
        language = (query.get("language") or "zh-CN").strip() or "zh-CN"
        row = conn.execute(
            "SELECT * FROM guide_plans WHERE user_id = ? AND status = 'active' ORDER BY updated_at DESC LIMIT 1",
            (user["id"],),
        ).fetchone()
        todos = self._guide_todos_for_query(conn, user["id"], {"status": "open", "limit": "8"})
        profile = self._guide_user_profile_row(conn, user["id"])
        recommendations = self._guide_os_recommendation_payload(conn, profile=profile, todo_rows=todos, language=language)
        today = datetime.now(timezone.utc).date().isoformat()
        upcoming_to = _guide_date_add(7)
        identity, suggested_journeys, default_journey, next_actions = self._guide_personalization(conn, profile, todos, language)
        self.send_json({
            "status": "ok",
            "profile": serialize_guide_profile(profile),
            "plan": self._guide_plan_payload(conn, row),
            "retention": self._guide_retention(conn, user["id"]),
            "todayTodos": [serialize_guide_todo(r) for r in self._guide_todos_for_query(conn, user["id"], {"from": today, "to": today, "status": "open", "limit": "8"})],
            "upcomingTodos": [serialize_guide_todo(r) for r in self._guide_todos_for_query(conn, user["id"], {"from": today, "to": upcoming_to, "status": "open", "limit": "12"})],
            "openTodos": [serialize_guide_todo(r) for r in todos],
            "identityType": identity,
            "suggestedJourneys": suggested_journeys,
            "defaultJourneyKey": default_journey,
            "recommendedNextActions": next_actions,
            **recommendations,
        })

    def _guide_retention(self, conn: sqlite3.Connection, user_id: str) -> dict:
        """Lightweight retention signals (spec P1): how many todos were completed
        in the last 7 days, and the current consecutive-day completion streak."""
        today = _guide_today_date().date()
        week_floor = (today - timedelta(days=6)).isoformat()
        try:
            week_done = int(conn.execute(
                "SELECT COUNT(*) AS c FROM guide_todos WHERE user_id = ? AND status = 'done' "
                "AND completed_at IS NOT NULL AND substr(completed_at,1,10) >= ?",
                (user_id, week_floor),
            ).fetchone()["c"])
            rows = conn.execute(
                "SELECT DISTINCT substr(completed_at,1,10) AS d FROM guide_todos "
                "WHERE user_id = ? AND status = 'done' AND completed_at IS NOT NULL "
                "ORDER BY d DESC LIMIT 90",
                (user_id,),
            ).fetchall()
        except Exception:
            return {"weekDone": 0, "streakDays": 0}
        done_days = {r["d"] for r in rows if r["d"]}
        streak = 0
        cursor = today
        # Streak counts back from today; a completion today or yesterday keeps it alive.
        if today.isoformat() not in done_days and (today - timedelta(days=1)).isoformat() in done_days:
            cursor = today - timedelta(days=1)
        while cursor.isoformat() in done_days:
            streak += 1
            cursor = cursor - timedelta(days=1)
        return {"weekDone": week_done, "streakDays": streak}

    def _guide_personalization(self, conn: sqlite3.Connection, profile: sqlite3.Row | dict | None,
                               todo_rows: list, language: str) -> tuple[str, list[dict], str, list[dict]]:
        """Identity → ordered journeys + a default journey + next-action cards.
        Drives the spec's 'different identities see a different home'."""
        identity = ""
        if profile is not None:
            try:
                identity = (profile["identity_type"] or "").strip()
            except Exception:
                identity = (dict(profile).get("identity_type") or "").strip() if profile else ""
        try:
            jrows = conn.execute(
                "SELECT journey_key, title, subtitle, icon, color FROM guide_journeys "
                "WHERE country = 'jp' AND status = 'published'",
            ).fetchall()
        except Exception:
            jrows = []
        jmap = {r["journey_key"]: r for r in jrows}
        ordered = _guide_identity_journey_order(identity, list(jmap.keys()))
        suggested = [{
            "key": k, "title": jmap[k]["title"], "subtitle": jmap[k]["subtitle"],
            "icon": jmap[k]["icon"], "color": jmap[k]["color"],
        } for k in ordered if k in jmap]
        default_journey = _guide_identity_default_journey(identity, list(jmap.keys()))
        next_actions: list[dict] = []
        # Most urgent due todos first (overdue / soonest), so "下一步" leads with
        # real deadlines (在留到期、出愿截止…) instead of only journey suggestions.
        dated = [serialize_guide_todo(r) for r in todo_rows]
        dated = [t for t in dated if t.get("dueAt")]
        dated.sort(key=lambda t: t["dueAt"])
        for t in dated[:2]:
            next_actions.append({
                "kind": "todo", "title": t["title"], "todoId": t["id"],
                "todoType": t.get("todoType", ""), "dueAt": t.get("dueAt"),
            })
        if not next_actions and todo_rows:
            t0 = serialize_guide_todo(todo_rows[0])
            next_actions.append({"kind": "todo", "title": t0["title"], "todoId": t0["id"], "todoType": t0.get("todoType", "")})
        for s in suggested[: max(0, 4 - len(next_actions))]:
            next_actions.append({"kind": "journey", "journeyKey": s["key"], "title": s["title"], "subtitle": s["subtitle"]})
        return identity, suggested, default_journey, next_actions

    def api_guide_plan_start(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        body = self.read_json()
        journey_key = str(body.get("journeyKey") or body.get("sourceJourneyKey") or "").strip()
        # Spec P0: "生成我的计划" with no explicit journey picks the default for
        # the user's identity (e.g. 社会人转职 → job_hunting / 在留).
        explicit_custom = str(body.get("planType") or "").strip() == "custom" or bool(str(body.get("title") or "").strip())
        if not journey_key and not explicit_custom:
            profile = self._guide_user_profile_row(conn, user["id"])
            identity = ""
            if profile is not None:
                try:
                    identity = (profile["identity_type"] or "").strip()
                except Exception:
                    identity = ""
            if identity:
                try:
                    keys = [r["journey_key"] for r in conn.execute(
                        "SELECT journey_key FROM guide_journeys WHERE country = 'jp' AND status = 'published'").fetchall()]
                    if keys:
                        journey_key = _guide_identity_default_journey(identity, keys)
                except Exception:
                    pass
        plan_type = str(body.get("planType") or "").strip() or ("life" if journey_key in {"arrival", "housing", "visa"} else "guide")
        target_date = _guide_date_value(body.get("targetDate") or body.get("target_date"))
        if journey_key:
            existing = conn.execute(
                "SELECT * FROM guide_plans WHERE user_id = ? AND status = 'active' AND source_journey_key = ? LIMIT 1",
                (user["id"], journey_key),
            ).fetchone()
            if existing:
                return self.send_json({"status": "ok", "plan": self._guide_plan_payload(conn, existing),
                                       "todos": [serialize_guide_todo(r) for r in self._guide_todos_for_query(conn, user["id"], {"planId": existing["id"], "limit": "100"})]})
        journey = None
        if journey_key:
            journey = conn.execute(
                "SELECT * FROM guide_journeys WHERE journey_key = ? AND country = 'jp' AND status = 'published' LIMIT 1",
                (journey_key,),
            ).fetchone()
        title = str(body.get("title") or (journey["title"] if journey else "") or "我的日本计划").strip()[:200]
        subtitle = str(body.get("subtitle") or (journey["subtitle"] if journey else "") or "").strip()[:500]
        now = now_iso()
        plan_id = str(uuid.uuid4())
        conn.execute(
            "INSERT INTO guide_plans (id, user_id, plan_type, title, subtitle, status, target_date, started_at, "
            "progress_percent, current_todo_id, source_journey_key, created_at, updated_at) "
            "VALUES (?, ?, ?, ?, ?, 'active', ?, ?, 0, '', ?, ?, ?)",
            (plan_id, user["id"], plan_type[:60], title, subtitle, target_date, now, journey_key, now, now),
        )
        if journey_key:
            self._guide_create_journey_todos(conn, user["id"], plan_id, journey_key, target_date)
        self._guide_update_plan_progress(conn, plan_id)
        _guide_funnel_log("plan_started", user_id=user["id"], journeyKey=journey_key or "", planType=plan_type)
        row = conn.execute("SELECT * FROM guide_plans WHERE id = ?", (plan_id,)).fetchone()
        self.send_json({"status": "ok", "plan": self._guide_plan_payload(conn, row),
                        "todos": [serialize_guide_todo(r) for r in self._guide_todos_for_query(conn, user["id"], {"planId": plan_id, "limit": "100"})]})

    def api_guide_plan_update(self, conn: sqlite3.Connection, plan_id: str) -> None:
        user = self.require_user(conn)
        body = self.read_json()
        row = conn.execute("SELECT * FROM guide_plans WHERE id = ? AND user_id = ?", (plan_id, user["id"])).fetchone()
        if not row:
            return self.send_error_json("plan not found", 404, "not_found")
        updates: list[str] = []
        params: list[Any] = []
        for api_key, col, max_len in (
            ("title", "title", 200), ("subtitle", "subtitle", 500), ("status", "status", 40), ("planType", "plan_type", 60),
        ):
            if api_key in body:
                updates.append(f"{col} = ?")
                params.append(str(body.get(api_key) or "").strip()[:max_len])
        if "targetDate" in body:
            updates.append("target_date = ?")
            params.append(_guide_date_value(body.get("targetDate")))
        if updates:
            updates.append("updated_at = ?")
            params.append(now_iso())
            params.append(plan_id)
            conn.execute(f"UPDATE guide_plans SET {', '.join(updates)} WHERE id = ?", tuple(params))
        self._guide_update_plan_progress(conn, plan_id)
        self.send_json({"status": "ok", "plan": self._guide_plan_payload(conn, conn.execute("SELECT * FROM guide_plans WHERE id = ?", (plan_id,)).fetchone())})

    def api_guide_plan_reset(self, conn: sqlite3.Connection, plan_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM guide_plans WHERE id = ? AND user_id = ?", (plan_id, user["id"])).fetchone()
        if not row:
            return self.send_error_json("plan not found", 404, "not_found")
        now = now_iso()
        conn.execute("UPDATE guide_todos SET status = 'not_started', completed_at = NULL, updated_at = ? WHERE plan_id = ? AND user_id = ?", (now, plan_id, user["id"]))
        self._guide_update_plan_progress(conn, plan_id)
        self.send_json({"status": "ok", "plan": self._guide_plan_payload(conn, conn.execute("SELECT * FROM guide_plans WHERE id = ?", (plan_id,)).fetchone())})

    def api_guide_study_plan(self, conn: sqlite3.Connection) -> None:
        """Spec P0.2: a JLPT/日语 study plan built from study HABITS, not just a
        timeline. Input: targetLevel + examDate + dailyMinutes → recurring todos
        (每日词汇 / 每周语法 / 周末模考+错题复盘) plus registration & sprint
        milestones. Capped at ~15 todos so we never spawn hundreds."""
        user = self.require_user(conn)
        body = self.read_json()
        level = str(body.get("targetLevel") or body.get("level") or "N3").strip().upper()[:8] or "N3"
        exam_date = _guide_date_value(body.get("examDate") or body.get("exam_date"))
        daily = _guide_int(body.get("dailyMinutes"), 45, lo=10, hi=600)
        if not exam_date:
            return self.send_error_json("examDate required", 400, "invalid_body")
        try:
            exam = datetime.fromisoformat(exam_date[:10]).date()
        except ValueError:
            return self.send_error_json("invalid examDate", 400, "invalid_body")
        today = _guide_today_date().date()
        now = now_iso()
        # Reuse an existing active JLPT/study plan for this level if present.
        title = f"JLPT {level} 备考计划"
        existing = conn.execute(
            "SELECT * FROM guide_plans WHERE user_id = ? AND status = 'active' AND plan_type = 'study' AND title = ? LIMIT 1",
            (user["id"], title),
        ).fetchone()
        if existing:
            plan_id = existing["id"]
            conn.execute("UPDATE guide_plans SET target_date = ?, updated_at = ? WHERE id = ?", (exam_date, now, plan_id))
            # Clear previously generated study todos so a re-run is idempotent.
            self._guide_delete_todos_for_source(conn, user["id"], "study_plan", plan_id)
        else:
            plan_id = str(uuid.uuid4())
            conn.execute(
                "INSERT INTO guide_plans (id, user_id, plan_type, title, subtitle, status, target_date, started_at, "
                "progress_percent, current_todo_id, source_journey_key, created_at, updated_at) "
                "VALUES (?, ?, 'study', ?, ?, 'active', ?, ?, 0, '', 'jlpt', ?, ?)",
                (plan_id, user["id"], title, f"每天 {daily} 分钟 · 考试 {exam_date}", exam_date, now, now, now),
            )
        vocab_products = "jlpt-vocabulary-pack,jlpt-grammar-summary"
        mock_products = "jlpt-mock-exam-set,jlpt-grammar-summary"
        study_services = "jlpt-study-plan-service,jlpt-weakness-review-service"
        # Cap at 5 weeks of recurring tasks so the total stays in the spec's
        # 8-15 range (1 daily + 5*2 weekly + ≤3 milestones = ≤14).
        weeks = max(1, min(5, (exam - today).days // 7))
        next_monday = today + timedelta(days=((7 - today.weekday()) % 7) or 7)

        def add(title_, summary_, todo_type, planned, recurrence="", products="", services="", priority="normal", reminder=None):
            self._guide_todo_insert(
                conn, user_id=user["id"], plan_id=plan_id, source_type="study_plan", source_id=plan_id,
                journey_key="jlpt", title=title_, summary=summary_, todo_type=todo_type,
                planned_date=planned, due_at=planned, reminder_at=reminder, priority=priority,
                estimated_minutes=daily, recurrence=recurrence, product_slugs=products, service_slugs=services,
            )

        # Daily vocabulary habit (one recurring anchor todo).
        add(f"每日词汇打卡（{level}，{daily} 分/天）", "每天背新词 + 复习昨天的词，养成习惯。", "exam_study",
            (today + timedelta(days=1)).isoformat(), recurrence="daily", products=vocab_products, services=study_services, priority="high",
            reminder=(today + timedelta(days=1)).isoformat())
        # Per-week grammar + weekend mock (recurring weekly).
        for w in range(weeks):
            wk_mon = next_monday + timedelta(days=7 * w)
            add(f"第{w + 1}周·语法总结（{level}）", "整理本周语法点，做对应练习。", "exam_study",
                wk_mon.isoformat(), recurrence="weekly", products=vocab_products, services=study_services)
            wk_sat = wk_mon + timedelta(days=5)
            add(f"第{w + 1}周·周末模考 + 错题复盘", "限时做一套模考，复盘错题与薄弱项。", "exam_study",
                wk_sat.isoformat(), recurrence="weekly", products=mock_products, services=study_services, priority="high",
                reminder=wk_sat.isoformat())
        # Milestones.
        reg_deadline = (exam - timedelta(days=60))
        if reg_deadline > today:
            add("JLPT 报名截止提醒", "在官网完成报名缴费，名额有限尽早报。", "exam_registration",
                reg_deadline.isoformat(), products="", services="", priority="high", reminder=reg_deadline.isoformat())
        sprint = exam - timedelta(days=30)
        if sprint > today:
            add(f"考前 30 天冲刺（{level}）", "进入冲刺：高频词、真题套卷、限时训练。", "exam_study",
                sprint.isoformat(), products=mock_products, services=study_services, priority="high", reminder=sprint.isoformat())
        add(f"JLPT {level} 考试当天", "带好准考证与证件，提前到场。", "exam_registration",
            exam_date, products="", services="", priority="high", reminder=(exam - timedelta(days=1)).isoformat())

        self._guide_update_plan_progress(conn, plan_id)
        _guide_funnel_log("study_plan_created", user_id=user["id"], planType="study")
        plan_row = conn.execute("SELECT * FROM guide_plans WHERE id = ?", (plan_id,)).fetchone()
        self.send_json({"status": "ok", "plan": self._guide_plan_payload(conn, plan_row),
                        "todos": [serialize_guide_todo(r) for r in self._guide_todos_for_query(conn, user["id"], {"planId": plan_id, "limit": "100"})]})

    def _guide_todos_for_query(self, conn: sqlite3.Connection, user_id: str, query: dict[str, str]):
        self._guide_ensure_todo_columns(conn)
        where = ["user_id = ?"]
        params: list[Any] = [user_id]
        status = (query.get("status") or "").strip()
        if status == "open":
            where.append("status NOT IN ('done','skipped')")
        elif status:
            where.append("status = ?")
            params.append(status)
        plan_id = (query.get("planId") or query.get("plan_id") or "").strip()
        if plan_id:
            where.append("plan_id = ?")
            params.append(plan_id)
        todo_type = (query.get("type") or query.get("todoType") or "").strip()
        if todo_type:
            where.append("todo_type = ?")
            params.append(todo_type)
        list_name = (query.get("listName") or "").strip()
        if list_name:
            where.append("list_name = ?")
            params.append(list_name)
        tag = (query.get("tag") or "").strip()
        if tag:
            where.append("(',' || tags || ',') LIKE ?")
            params.append(f"%,{tag},%")
        date_from = _guide_date_value(query.get("from"))
        date_to = _guide_date_value(query.get("to"))
        if date_from:
            where.append("COALESCE(planned_date, due_at, reminder_at, created_at) >= ?")
            params.append(date_from)
        if date_to:
            where.append("COALESCE(planned_date, due_at, reminder_at, created_at) <= ?")
            params.append(date_to)
        limit = _guide_int(query.get("limit") or query.get("pageSize"), 50, lo=1, hi=200)
        sql = "SELECT * FROM guide_todos WHERE " + " AND ".join(where) + " ORDER BY status = 'done' ASC, COALESCE(planned_date, due_at, reminder_at, updated_at), created_at LIMIT ?"
        params.append(limit)
        return conn.execute(sql, tuple(params)).fetchall()

    def api_guide_todos(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        user = self.require_user(conn)
        rows = self._guide_todos_for_query(conn, user["id"], query)
        self.send_json({"status": "ok", "items": [serialize_guide_todo(r) for r in rows], "total": len(rows)})

    def api_guide_todo_create(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        body = self.read_json()
        raw = str(body.get("content") or body.get("text") or body.get("title") or "").strip()
        if not raw:
            return self.send_error_json("todo content required", 400, "invalid_body")
        title = str(body.get("title") or raw).strip()[:200]
        summary = str(body.get("summary") or "").strip()[:1000]
        notes = str(body.get("notes") or "").strip()[:2000]
        plan_id = str(body.get("planId") or body.get("plan_id") or "").strip()
        todo_type = str(body.get("todoType") or body.get("todo_type") or "manual").strip()[:60] or "manual"
        priority = str(body.get("priority") or "").strip()[:40]
        planned_date = _guide_date_value(body.get("plannedDate") or body.get("planned_date"))
        due_at = _guide_date_value(body.get("dueAt") or body.get("due_at"))
        reminder_at = _guide_date_value(body.get("reminderAt") or body.get("reminder_at"))
        inferred_date = _guide_quick_todo_date_from_text(" ".join([raw, summary, notes]))
        deadline_like = any(k in raw for k in ("截止", "到期", "缴费", "付款", "还款", "面试", "考试")) or any(
            k in raw.lower() for k in ("deadline", "due", "interview", "exam", "payment")
        )
        if inferred_date and not planned_date and not due_at:
            if deadline_like:
                due_at = inferred_date
            else:
                planned_date = inferred_date
        if not priority:
            priority = "high" if due_at or deadline_like else "normal"
        if due_at and not reminder_at:
            reminder_at = _guide_date_minus(due_at, 1)
        todo_id = self._guide_todo_insert(
            conn,
            user_id=user["id"],
            plan_id=plan_id,
            source_type="manual",
            source_id="",
            title=title,
            summary=summary,
            todo_type=todo_type,
            priority=priority,
            planned_date=planned_date,
            due_at=due_at,
            reminder_at=reminder_at,
            estimated_minutes=_guide_int(body.get("estimatedMinutes") or body.get("estimated_minutes"), 0, lo=0, hi=1440),
            notes=notes,
            recurrence=str(body.get("recurrence") or "").strip()[:20],
        )
        conn.execute(
            "UPDATE guide_todos SET list_name = ?, tags = ? WHERE id = ?",
            (
                str(body.get("listName") or "").strip()[:100],
                ",".join(_guide_split_tags(body.get("tags")))[:1000],
                todo_id,
            ),
        )
        if plan_id:
            self._guide_update_plan_progress(conn, plan_id)
        row = conn.execute("SELECT * FROM guide_todos WHERE id = ?", (todo_id,)).fetchone()
        self.send_json({"status": "ok", "todo": serialize_guide_todo(row)})

    def _guide_sync_todo_to_progress(self, conn: sqlite3.Connection, todo_row: Any) -> None:
        """Mirror a journey-step todo's status into guide_user_progress so the
        journey-detail checklist and the plan/todo system never disagree (one
        unified progress, no duplicate trackers). Best-effort."""
        try:
            d = dict(todo_row)
            jk = (d.get("journey_key") or "").strip()
            sk = (d.get("step_key") or "").strip()
            if not jk or not sk:
                return
            status = d.get("status") or "not_started"
            now = now_iso()
            completed_at = (d.get("completed_at") or now) if status == "done" else None
            existing = conn.execute(
                "SELECT id FROM guide_user_progress WHERE user_id = ? AND journey_key = ? AND step_key = ?",
                (d["user_id"], jk, sk),
            ).fetchone()
            if existing:
                conn.execute(
                    "UPDATE guide_user_progress SET status = ?, completed_at = ?, updated_at = ? WHERE id = ?",
                    (status, completed_at, now, existing["id"]),
                )
            else:
                progress_cols = _table_columns(conn, "guide_user_progress")
                if all(col in progress_cols for col in ("planned_date", "due_at", "priority", "notify_enabled", "calendar_note")):
                    conn.execute(
                        "INSERT INTO guide_user_progress (id, user_id, journey_key, step_key, status, completed_at, "
                        "reminder_at, planned_date, due_at, priority, notify_enabled, calendar_note, notes, created_at, updated_at) "
                        "VALUES (?, ?, ?, ?, ?, ?, NULL, NULL, NULL, 'normal', 0, '', '', ?, ?)",
                        (str(uuid.uuid4()), d["user_id"], jk, sk, status, completed_at, now, now),
                    )
                else:
                    conn.execute(
                        "INSERT INTO guide_user_progress (id, user_id, journey_key, step_key, status, completed_at, reminder_at, notes, created_at, updated_at) "
                        "VALUES (?, ?, ?, ?, ?, ?, NULL, '', ?, ?)",
                        (str(uuid.uuid4()), d["user_id"], jk, sk, status, completed_at, now, now),
                    )
        except Exception:
            pass

    def _guide_sync_progress_to_todo(self, conn: sqlite3.Connection, user_id: str,
                                     journey_key: str, step_key: str, status: str, now: str,
                                     planned_date: str | None = None, due_at: str | None = None,
                                     reminder_at: str | None = None, priority: str | None = None) -> None:
        """Reverse of the above: ticking a step on the journey detail completes
        the matching plan todo (and re-derives plan progress) when one exists.
        When a journey step is scheduled from the detail page, mirror dates too
        so the Todo calendar becomes the real operational surface."""
        try:
            if not journey_key or not step_key:
                return
            trow = conn.execute(
                "SELECT id, plan_id FROM guide_todos WHERE user_id = ? AND journey_key = ? AND step_key = ? "
                "ORDER BY updated_at DESC LIMIT 1",
                (user_id, journey_key, step_key),
            ).fetchone()
            if not trow:
                if not (planned_date or due_at or reminder_at or status == "done"):
                    return
                step = conn.execute(
                    "SELECT * FROM guide_journey_steps WHERE journey_key = ? AND step_key = ? "
                    "AND country = 'jp' AND status = 'published' ORDER BY sort_order LIMIT 1",
                    (journey_key, step_key),
                ).fetchone()
                if not step:
                    return
                todo_id = self._guide_todo_insert(
                    conn,
                    user_id=user_id,
                    plan_id="",
                    source_type="journey_step",
                    source_id=step["id"],
                    journey_key=journey_key,
                    step_key=step_key,
                    title=step["title"] or "Guide Todo",
                    summary=step["summary"] or "",
                    todo_type="guide_step",
                    priority=priority or "normal",
                    planned_date=planned_date,
                    due_at=due_at,
                    reminder_at=reminder_at,
                    estimated_minutes=int(step["estimated_minutes"] or 0),
                    article_slugs=step["article_slugs"] or "",
                    product_slugs=step["product_slugs"] or "",
                )
                trow = {"id": todo_id, "plan_id": ""}
            completed_at = now if status == "done" else None
            updates = ["status = ?", "completed_at = ?"]
            params: list[Any] = [status, completed_at]
            if planned_date is not None:
                updates.append("planned_date = ?")
                params.append(planned_date)
            if due_at is not None:
                updates.append("due_at = ?")
                params.append(due_at)
            if reminder_at is not None:
                updates.append("reminder_at = ?")
                params.append(reminder_at)
            if priority:
                updates.append("priority = ?")
                params.append(priority[:40])
            updates.append("updated_at = ?")
            params.extend([now, trow["id"]])
            conn.execute(f"UPDATE guide_todos SET {', '.join(updates)} WHERE id = ?", tuple(params))
            todo = conn.execute("SELECT * FROM guide_todos WHERE id = ?", (trow["id"],)).fetchone()
            if status == "done":
                self._guide_set_reminder_status(conn, user_id=user_id, todo_id=trow["id"], status="completed")
            elif todo and (reminder_at is not None or due_at is not None):
                if todo["reminder_at"]:
                    self._guide_schedule_reminders(
                        conn, user_id=user_id, todo_id=trow["id"], plan_id=todo["plan_id"] or "",
                        title=todo["title"] or "", reminder_at=todo["reminder_at"], due_at=todo["due_at"] or "",
                        multi_tier=(todo["todo_type"] or "") in _GUIDE_MULTI_TIER_TODO_TYPES,
                    )
                else:
                    self._guide_set_reminder_status(conn, user_id=user_id, todo_id=trow["id"], status="cancelled")
            if trow["plan_id"]:
                self._guide_update_plan_progress(conn, trow["plan_id"])
        except Exception:
            pass

    def _guide_spawn_recurrence(self, conn: sqlite3.Connection, row: Any) -> None:
        """Completing a daily/weekly/monthly recurring todo spawns its next
        occurrence (advanced by the interval, fresh status, no carried subtasks),
        idempotently. Keeps habit todos alive instead of vanishing on completion.
        Capped at +400 days so it can never run away."""
        try:
            d = dict(row)
            rec = (d.get("recurrence") or "").strip().lower()
            if rec not in ("daily", "weekly", "monthly", "yearly"):
                return
            base = (d.get("planned_date") or d.get("due_at") or "")[:10]
            if not base:
                return
            base_dt = datetime.strptime(base, "%Y-%m-%d").date()
            if rec == "daily":
                nxt = base_dt + timedelta(days=1)
            elif rec == "weekly":
                nxt = base_dt + timedelta(days=7)
            elif rec == "yearly":
                nxt = datetime(base_dt.year + 1, base_dt.month, min(base_dt.day, 28)).date()
            else:
                month = base_dt.month + 1
                year = base_dt.year + (1 if month > 12 else 0)
                month = month - 12 if month > 12 else month
                nxt = datetime(year, month, min(base_dt.day, 28)).date()
            if (nxt - _guide_today_date().date()).days > 400:
                return
            next_iso = nxt.isoformat()
            dup = conn.execute(
                "SELECT 1 FROM guide_todos WHERE user_id = ? AND title = ? "
                "AND substr(COALESCE(planned_date, due_at, ''), 1, 10) = ? AND status != 'done' LIMIT 1",
                (d.get("user_id"), d.get("title"), next_iso),
            ).fetchone()
            if dup:
                return
            reminder = None
            if d.get("reminder_at"):
                try:
                    lead = (base_dt - datetime.strptime(str(d["reminder_at"])[:10], "%Y-%m-%d").date()).days
                    reminder = _guide_date_minus(next_iso, lead)
                except Exception:
                    reminder = None
            self._guide_todo_insert(
                conn, user_id=d.get("user_id"), plan_id=d.get("plan_id") or "",
                source_type=d.get("source_type") or "", source_id=d.get("source_id") or "",
                journey_key=d.get("journey_key") or "", step_key=d.get("step_key") or "",
                title=d.get("title") or "", summary=d.get("summary") or "",
                todo_type=d.get("todo_type") or "guide_step", priority=d.get("priority") or "normal",
                planned_date=next_iso, due_at=next_iso, reminder_at=reminder,
                estimated_minutes=int(d.get("estimated_minutes") or 0), notes=d.get("notes") or "",
                article_slugs=d.get("related_article_slugs") or "",
                product_slugs=d.get("related_product_slugs") or "",
                service_slugs=d.get("related_service_slugs") or "",
                recurrence=rec,
            )
        except Exception:
            pass

    def api_guide_todo_update(self, conn: sqlite3.Connection, todo_id: str, complete: bool = False, reminder_only: bool = False) -> None:
        user = self.require_user(conn)
        body = self.read_json()
        self._guide_ensure_todo_columns(conn)
        row = conn.execute("SELECT * FROM guide_todos WHERE id = ? AND user_id = ?", (todo_id, user["id"])).fetchone()
        if not row:
            return self.send_error_json("todo not found", 404, "not_found")
        updates: list[str] = []
        params: list[Any] = []
        if complete:
            updates.extend(["status = ?", "completed_at = ?"])
            params.extend(["done", now_iso()])
        else:
            for api_key, col, max_len in (
                ("title", "title", 200), ("summary", "summary", 1000), ("status", "status", 40),
                ("priority", "priority", 40), ("notes", "notes", 2000), ("recurrence", "recurrence", 20),
                ("listName", "list_name", 100),
            ):
                if api_key in body and not reminder_only:
                    updates.append(f"{col} = ?")
                    params.append(str(body.get(api_key) or "").strip()[:max_len])
            for api_key, col in (("plannedDate", "planned_date"), ("dueAt", "due_at"), ("reminderAt", "reminder_at")):
                if api_key in body:
                    updates.append(f"{col} = ?")
                    params.append(_guide_date_value(body.get(api_key)))
            if "steps" in body and not reminder_only:
                updates.append("steps = ?")
                params.append(_guide_steps_to_json(body.get("steps")))
            if "tags" in body and not reminder_only:
                updates.append("tags = ?")
                params.append(",".join(_guide_split_tags(body.get("tags")))[:1000])
        if "status" in body and not complete and str(body.get("status") or "") == "done":
            updates.append("completed_at = ?")
            params.append(now_iso())
        if "status" in body and str(body.get("status") or "") != "done" and not complete:
            updates.append("completed_at = NULL")
        if not updates:
            return self.send_json({"status": "ok", "todo": serialize_guide_todo(row)})
        updates.append("updated_at = ?")
        params.append(now_iso())
        params.append(todo_id)
        conn.execute(f"UPDATE guide_todos SET {', '.join(updates)} WHERE id = ?", tuple(params))
        if row["plan_id"]:
            self._guide_update_plan_progress(conn, row["plan_id"])
        todo = conn.execute("SELECT * FROM guide_todos WHERE id = ?", (todo_id,)).fetchone()
        self._guide_sync_todo_to_progress(conn, todo)
        if complete or (not complete and str(body.get("status") or "") == "done"):
            _guide_funnel_log("todo_completed", user_id=user["id"], todoType=todo["todo_type"] if todo else "")
            lifehub.record_local_action(conn, user["id"], "guide_todo_done", target_kind="todo", target_id=todo_id, now=now_iso())
            self._guide_set_reminder_status(conn, user_id=user["id"], todo_id=todo_id, status="completed")
            # Daily/weekly/monthly habits: completing one spawns the next
            # occurrence so it reappears instead of vanishing for good.
            self._guide_spawn_recurrence(conn, todo)
        elif "reminderAt" in body:
            if todo["reminder_at"]:
                self._guide_schedule_reminders(
                    conn, user_id=user["id"], todo_id=todo_id, plan_id=todo["plan_id"] or "",
                    title=todo["title"] or "", reminder_at=todo["reminder_at"], due_at=todo["due_at"] or "",
                    multi_tier=(todo["todo_type"] or "") in _GUIDE_MULTI_TIER_TODO_TYPES,
                )
            else:
                self._guide_set_reminder_status(conn, user_id=user["id"], todo_id=todo_id, status="cancelled")
        self.send_json({"status": "ok", "todo": serialize_guide_todo(todo)})

    def api_guide_todo_delete(self, conn: sqlite3.Connection, todo_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute(
            "SELECT * FROM guide_todos WHERE id = ? AND user_id = ?",
            (todo_id, user["id"]),
        ).fetchone()
        if not row:
            return self.send_error_json("todo not found", 404, "not_found")
        conn.execute(
            "UPDATE guide_reminders SET status = 'cancelled', updated_at = ? "
            "WHERE user_id = ? AND todo_id = ?",
            (now_iso(), user["id"], todo_id),
        )
        conn.execute("DELETE FROM guide_calendar_items WHERE user_id = ? AND todo_id = ?", (user["id"], todo_id))
        conn.execute("DELETE FROM guide_todos WHERE id = ? AND user_id = ?", (todo_id, user["id"]))
        if row["plan_id"]:
            self._guide_update_plan_progress(conn, row["plan_id"])
        self.send_json({"status": "ok", "deletedId": todo_id})

    def api_guide_calendar(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        user = self.require_user(conn)
        rows = self._guide_todos_for_query(conn, user["id"], {"from": query.get("from", ""), "to": query.get("to", ""), "limit": query.get("limit", "200")})
        items = []
        for row in rows:
            todo = serialize_guide_todo(row)
            date = todo.get("plannedDate") or todo.get("dueAt") or todo.get("reminderAt")
            items.append({
                "id": todo["id"],
                "todoId": todo["id"],
                "title": todo["title"],
                "date": date,
                "startAt": todo.get("reminderAt") or todo.get("dueAt") or todo.get("plannedDate"),
                "endAt": None,
                "type": todo.get("todoType") or "todo",
                "status": todo.get("status") or "not_started",
                "planId": todo.get("planId") or "",
                "todo": todo,
            })
        where = ["user_id = ?", "(todo_id = '' OR todo_id IS NULL)", "status != 'deleted'"]
        params: list[Any] = [user["id"]]
        if query.get("from"):
            where.append("date >= ?")
            params.append(_guide_date_value(query.get("from")))
        if query.get("to"):
            where.append("date <= ?")
            params.append(_guide_date_value(query.get("to")))
        event_rows = conn.execute(
            "SELECT * FROM guide_calendar_items WHERE " + " AND ".join(where) + " ORDER BY date, start_at LIMIT ?",
            tuple(params + [_guide_int(query.get("limit"), 200, lo=1, hi=1000)]),
        ).fetchall()
        items.extend(serialize_guide_calendar_item(row) for row in event_rows)
        items.sort(key=lambda item: (str(item.get("date") or ""), str(item.get("startAt") or ""), str(item.get("title") or "")))
        self.send_json({"status": "ok", "items": items, "total": len(items)})

    def api_guide_calendar_event_create(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        body = self.read_json()
        title = str(body.get("title") or "").strip()[:200]
        date_value = _guide_date_value(body.get("date") or body.get("startAt"))
        if not title or not date_value:
            return self.send_error_json("title and date required", 400, "invalid_body")
        now = now_iso()
        item_id = str(uuid.uuid4())
        conn.execute(
            "INSERT INTO guide_calendar_items (id, user_id, todo_id, title, date, start_at, end_at, type, status, plan_id, "
            "notes, recurrence, reminder_at, all_day, created_at, updated_at) "
            "VALUES (?, ?, '', ?, ?, ?, ?, ?, 'active', ?, ?, ?, ?, ?, ?, ?)",
            (
                item_id, user["id"], title, date_value,
                str(body.get("startAt") or date_value).strip()[:40],
                str(body.get("endAt") or "").strip()[:40] or None,
                str(body.get("type") or "event").strip()[:40] or "event",
                str(body.get("planId") or "").strip()[:80],
                str(body.get("notes") or "").strip()[:4000],
                str(body.get("recurrence") or "").strip()[:40],
                _guide_date_value(body.get("reminderAt")),
                1 if _guide_bool_value(body.get("allDay"), True) else 0,
                now, now,
            ),
        )
        row = conn.execute("SELECT * FROM guide_calendar_items WHERE id = ?", (item_id,)).fetchone()
        self.send_json({"status": "ok", "event": serialize_guide_calendar_item(row)})

    def api_guide_calendar_event_update(self, conn: sqlite3.Connection, item_id: str) -> None:
        user = self.require_user(conn)
        body = self.read_json()
        row = conn.execute(
            "SELECT * FROM guide_calendar_items WHERE id = ? AND user_id = ? AND (todo_id = '' OR todo_id IS NULL)",
            (item_id, user["id"]),
        ).fetchone()
        if not row:
            return self.send_error_json("calendar event not found", 404, "not_found")
        updates: list[str] = []
        params: list[Any] = []
        for api_key, col, limit in (
            ("title", "title", 200), ("startAt", "start_at", 40), ("endAt", "end_at", 40),
            ("type", "type", 40), ("status", "status", 40), ("planId", "plan_id", 80),
            ("notes", "notes", 4000), ("recurrence", "recurrence", 40),
        ):
            if api_key in body:
                updates.append(f"{col} = ?")
                params.append(str(body.get(api_key) or "").strip()[:limit] or None)
        if "date" in body:
            updates.append("date = ?")
            params.append(_guide_date_value(body.get("date")))
        if "reminderAt" in body:
            updates.append("reminder_at = ?")
            params.append(_guide_date_value(body.get("reminderAt")))
        if "allDay" in body:
            updates.append("all_day = ?")
            params.append(1 if _guide_bool_value(body.get("allDay"), True) else 0)
        if updates:
            updates.append("updated_at = ?")
            params.extend([now_iso(), item_id])
            conn.execute(f"UPDATE guide_calendar_items SET {', '.join(updates)} WHERE id = ?", tuple(params))
        updated = conn.execute("SELECT * FROM guide_calendar_items WHERE id = ?", (item_id,)).fetchone()
        self.send_json({"status": "ok", "event": serialize_guide_calendar_item(updated)})

    def api_guide_calendar_event_delete(self, conn: sqlite3.Connection, item_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute(
            "SELECT id FROM guide_calendar_items WHERE id = ? AND user_id = ? AND (todo_id = '' OR todo_id IS NULL)",
            (item_id, user["id"]),
        ).fetchone()
        if not row:
            return self.send_error_json("calendar event not found", 404, "not_found")
        conn.execute("DELETE FROM guide_calendar_items WHERE id = ? AND user_id = ?", (item_id, user["id"]))
        self.send_json({"status": "ok", "deleted": item_id})

    def _guide_application_stages(self, conn: sqlite3.Connection, app_id: str) -> list[dict[str, Any]]:
        rows = conn.execute(
            "SELECT * FROM guide_application_stages WHERE application_id = ? ORDER BY occurred_at ASC, created_at ASC",
            (app_id,),
        ).fetchall()
        return [serialize_guide_application_stage(r) for r in rows]

    def _guide_record_application_stage(
        self, conn: sqlite3.Connection, user_id: str, app_id: str, stage: str, note: str = "", occurred_at: str | None = None
    ) -> None:
        clean_stage = stage.strip()[:60] or "saved"
        now = now_iso()
        conn.execute(
            "INSERT INTO guide_application_stages (id, application_id, user_id, stage, note, occurred_at, created_at) "
            "VALUES (?, ?, ?, ?, ?, ?, ?)",
            (str(uuid.uuid4()), app_id, user_id, clean_stage, note.strip()[:1000], occurred_at or now, now),
        )

    def _guide_generate_application_todos(self, conn: sqlite3.Connection, user_id: str, app: sqlite3.Row | dict[str, Any]) -> None:
        d = dict(app)
        app_id = str(d.get("id") or "")
        plan_id = str(d.get("plan_id") or "")
        app_type = str(d.get("type") or "school")
        career_track = str(d.get("career_track") or "")
        name = str(d.get("name") or "")
        deadline = _guide_date_value(d.get("deadline"))
        interview_at = _guide_date_value(d.get("interview_at"))
        result_at = _guide_date_value(d.get("result_at"))
        old_plan_ids = self._guide_delete_todos_for_source(conn, user_id, "application", app_id)
        is_jlpt = app_type in ("jlpt", "exam")
        todo_type = "school_application" if app_type == "school" else ("exam_registration" if is_jlpt else "company_es")
        deadline_label = "出愿截止" if app_type == "school" else ("考试日" if is_jlpt else "ES 截止")
        if deadline:
            if app_type == "school":
                products = "research-plan-template-pack,application-documents-checklist,professor-email-template-pack"
                services = "research-plan-review-service,graduate-school-consultation,research-plan-revision"
            elif is_jlpt:
                products = services = ""
            else:
                products = "rirekisho-template-pack,self-pr-motivation-template,shokumukeirekisho-template-pack"
                services = "rirekisho-review-service,shokumukeirekisho-review-service,es-motivation-revision"
            self._guide_todo_insert(
                conn, user_id=user_id, plan_id=plan_id, source_type="application", source_id=app_id,
                title=f"{name} {deadline_label}", summary=name, todo_type=todo_type, due_at=deadline,
                reminder_at=_guide_date_minus(deadline, 7), priority="high", product_slugs=products, service_slugs=services,
            )
            today_iso = now_iso()[:10]
            for offset, m_title, m_summary, m_type, m_products, m_services in _guide_application_milestones(conn, app_type, career_track):
                planned = _guide_date_minus(deadline, offset)
                if not planned:
                    continue
                self._guide_todo_insert(
                    conn, user_id=user_id, plan_id=plan_id, source_type="application", source_id=app_id,
                    title=f"{name} · T-{offset} {m_title}", summary=m_summary, todo_type=m_type,
                    planned_date=planned, due_at=planned, reminder_at=planned if planned >= today_iso else None,
                    priority="high" if offset <= 14 else "normal", product_slugs=m_products, service_slugs=m_services,
                )
        if interview_at:
            products = "graduate-school-interview-100,interview-100-questions" if app_type == "school" else "interview-100-questions,self-pr-motivation-template"
            services = "graduate-school-consultation,research-plan-review-service" if app_type == "school" else "japan-job-mock-interview,es-motivation-revision"
            self._guide_todo_insert(
                conn, user_id=user_id, plan_id=plan_id, source_type="application", source_id=app_id,
                title=f"{name} 面试", summary="准备面试问题、逆質問和复盘记录。",
                todo_type="school_interview" if app_type == "school" else "company_interview",
                due_at=interview_at, reminder_at=_guide_date_minus(interview_at, 2), priority="high",
                product_slugs=products, service_slugs=services,
            )
        if result_at:
            self._guide_todo_insert(
                conn, user_id=user_id, plan_id=plan_id, source_type="application", source_id=app_id,
                title=f"{name} 结果确认", summary="确认结果并决定下一步。",
                todo_type="application_result", due_at=result_at, reminder_at=_guide_date_minus(result_at, 1), priority="normal",
            )
        for affected_plan in old_plan_ids | ({plan_id} if plan_id else set()):
            self._guide_update_plan_progress(conn, affected_plan)

    def api_guide_application_create(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        body = self.read_json()
        app_type = str(body.get("type") or "school").strip()[:40]
        career_track = str(body.get("careerTrack") or body.get("career_track") or "").strip()[:40]
        name = str(body.get("name") or "").strip()[:200]
        if not name:
            return self.send_error_json("name required", 400, "invalid_body")
        now = now_iso()
        app_id = str(uuid.uuid4())
        stage = str(body.get("stage") or "saved").strip()[:60] or "saved"
        conn.execute(
            "INSERT INTO guide_applications (id, user_id, plan_id, type, career_track, name, department, position, deadline, interview_at, result_at, "
            "status, stage, website_url, interview_location, meeting_url, contact_name, contact_email, priority, favorite, tags, notes, created_at, updated_at) "
            "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'active', ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
            (
                app_id, user["id"], str(body.get("planId") or "").strip(), app_type, career_track, name,
                str(body.get("department") or "").strip()[:160], str(body.get("position") or "").strip()[:160],
                _guide_date_value(body.get("deadline")), _guide_date_value(body.get("interviewAt")), _guide_date_value(body.get("resultAt")),
                stage, str(body.get("websiteUrl") or "").strip()[:1000], str(body.get("interviewLocation") or "").strip()[:500],
                str(body.get("meetingUrl") or "").strip()[:1000], str(body.get("contactName") or "").strip()[:160],
                str(body.get("contactEmail") or "").strip()[:320], str(body.get("priority") or "normal").strip()[:40],
                1 if _guide_bool_value(body.get("favorite")) else 0, ",".join(_guide_split_tags(body.get("tags")))[:1000],
                str(body.get("notes") or "").strip()[:4000], now, now,
            ),
        )
        app = conn.execute("SELECT * FROM guide_applications WHERE id = ?", (app_id,)).fetchone()
        self._guide_record_application_stage(conn, user["id"], app_id, stage, "创建申请")
        self._guide_generate_application_todos(conn, user["id"], app)
        self.send_json({"status": "ok", "application": serialize_guide_application(app, self._guide_application_stages(conn, app_id))})

    def api_guide_application_update(self, conn: sqlite3.Connection, app_id: str) -> None:
        user = self.require_user(conn)
        body = self.read_json()
        row = conn.execute("SELECT * FROM guide_applications WHERE id = ? AND user_id = ?", (app_id, user["id"])).fetchone()
        if not row:
            return self.send_error_json("application not found", 404, "not_found")
        updates: list[str] = []
        params: list[Any] = []
        old_stage = str(row["stage"] or "saved")
        for api_key, col, max_len in (
            ("type", "type", 40), ("careerTrack", "career_track", 40), ("name", "name", 200),
            ("department", "department", 160), ("position", "position", 160), ("status", "status", 40),
            ("stage", "stage", 60), ("websiteUrl", "website_url", 1000),
            ("interviewLocation", "interview_location", 500), ("meetingUrl", "meeting_url", 1000),
            ("contactName", "contact_name", 160), ("contactEmail", "contact_email", 320),
            ("priority", "priority", 40), ("notes", "notes", 4000),
        ):
            if api_key in body:
                updates.append(f"{col} = ?")
                params.append(str(body.get(api_key) or "").strip()[:max_len])
        for api_key, col in (("deadline", "deadline"), ("interviewAt", "interview_at"), ("resultAt", "result_at")):
            if api_key in body:
                updates.append(f"{col} = ?")
                params.append(_guide_date_value(body.get(api_key)))
        if "favorite" in body:
            updates.append("favorite = ?")
            params.append(1 if _guide_bool_value(body.get("favorite")) else 0)
        if "tags" in body:
            updates.append("tags = ?")
            params.append(",".join(_guide_split_tags(body.get("tags")))[:1000])
        if "status" in body and str(body.get("status") or "") == "archived":
            updates.append("archived_at = ?")
            params.append(now_iso())
        if updates:
            updates.append("updated_at = ?")
            params.append(now_iso())
            params.append(app_id)
            conn.execute(f"UPDATE guide_applications SET {', '.join(updates)} WHERE id = ?", tuple(params))
        updated = conn.execute("SELECT * FROM guide_applications WHERE id = ?", (app_id,)).fetchone()
        new_stage = str(updated["stage"] or "saved")
        if new_stage != old_stage:
            self._guide_record_application_stage(conn, user["id"], app_id, new_stage, str(body.get("stageNote") or "").strip())
        if any(key in body for key in ("type", "careerTrack", "name", "deadline", "interviewAt", "resultAt")):
            self._guide_generate_application_todos(conn, user["id"], updated)
        self.send_json({"status": "ok", "application": serialize_guide_application(updated, self._guide_application_stages(conn, app_id))})

    def _guide_delete_todos_for_source(self, conn: sqlite3.Connection, user_id: str, source_type: str, source_id: str) -> set[str]:
        """Remove every auto-generated todo for a source (application / life item)
        and its reminders. The calendar is DERIVED from todos, so deleting the
        todos also clears the calendar — no separate calendar cleanup needed.
        Returns the affected plan ids so the caller can recompute progress."""
        rows = conn.execute(
            "SELECT id, plan_id FROM guide_todos WHERE user_id = ? AND source_type = ? AND source_id = ?",
            (user_id, source_type, source_id),
        ).fetchall()
        plan_ids = {(r["plan_id"] or "") for r in rows if (r["plan_id"] or "")}
        todo_ids = [r["id"] for r in rows]
        for tid in todo_ids:
            conn.execute("DELETE FROM guide_reminders WHERE user_id = ? AND todo_id = ?", (user_id, tid))
        conn.execute(
            "DELETE FROM guide_todos WHERE user_id = ? AND source_type = ? AND source_id = ?",
            (user_id, source_type, source_id),
        )
        return plan_ids

    def api_guide_applications_list(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        user = self.require_user(conn)
        where = ["user_id = ?"]
        params: list[Any] = [user["id"]]
        for key, col in (("status", "status"), ("stage", "stage"), ("type", "type"), ("priority", "priority")):
            value = str(query.get(key) or "").strip()
            if value:
                where.append(f"{col} = ?")
                params.append(value)
        keyword = str(query.get("q") or "").strip()
        if keyword:
            where.append("(name LIKE ? OR department LIKE ? OR position LIKE ? OR tags LIKE ?)")
            like = f"%{keyword}%"
            params.extend([like, like, like, like])
        rows = conn.execute(
            "SELECT * FROM guide_applications WHERE " + " AND ".join(where) + " ORDER BY favorite DESC, "
            "CASE WHEN deadline IS NULL OR deadline = '' THEN 1 ELSE 0 END, deadline ASC, updated_at DESC",
            tuple(params),
        ).fetchall()
        self.send_json({
            "status": "ok",
            "items": [serialize_guide_application(r, self._guide_application_stages(conn, r["id"])) for r in rows],
            "total": len(rows),
        })

    def api_guide_application_detail(self, conn: sqlite3.Connection, app_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM guide_applications WHERE id = ? AND user_id = ?", (app_id, user["id"])).fetchone()
        if not row:
            return self.send_error_json("application not found", 404, "not_found")
        todos = self._guide_todos_for_query(conn, user["id"], {"type": "", "limit": "200"})
        related = [serialize_guide_todo(t) for t in todos if (t["source_type"] or "") == "application" and (t["source_id"] or "") == app_id]
        self.send_json({
            "status": "ok",
            "application": serialize_guide_application(row, self._guide_application_stages(conn, app_id)),
            "todos": related,
        })

    def api_guide_application_delete(self, conn: sqlite3.Connection, app_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM guide_applications WHERE id = ? AND user_id = ?", (app_id, user["id"])).fetchone()
        if not row:
            return self.send_error_json("application not found", 404, "not_found")
        plan_ids = self._guide_delete_todos_for_source(conn, user["id"], "application", app_id)
        conn.execute("DELETE FROM guide_application_stages WHERE application_id = ? AND user_id = ?", (app_id, user["id"]))
        conn.execute("DELETE FROM guide_applications WHERE id = ? AND user_id = ?", (app_id, user["id"]))
        for plan_id in plan_ids:
            self._guide_update_plan_progress(conn, plan_id)
        self.send_json({"status": "ok", "deleted": app_id})

    def api_guide_life_presets(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        """Public catalog of life-bill presets with smart defaults (spec P1)."""
        language = (query.get("language") or "zh-CN").strip() or "zh-CN"
        items = [{
            "type": p["type"], "label": _guide_life_preset_label(p, language), "icon": p["icon"],
            "recurrence": p["recurrence"], "reminderDaysBefore": p["reminderDaysBefore"], "kind": p["kind"],
        } for p in GUIDE_LIFE_ITEM_PRESETS]
        self.send_json({"status": "ok", "items": items})

    def api_guide_life_item_create(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        body = self.read_json()
        title = str(body.get("title") or "").strip()[:200]
        item_type = str(body.get("type") or "").strip()[:80]
        if not title or not item_type:
            return self.send_error_json("title and type required", 400, "invalid_body")
        # Apply preset smart-defaults for known types when the client omits them.
        preset = _GUIDE_LIFE_PRESET_BY_TYPE.get(item_type)
        due_day = _guide_int(body.get("dueDay"), 0, lo=0, hi=31)
        due_at = _guide_date_value(body.get("dueAt")) or _guide_next_monthly_due(due_day)
        default_reminder = (preset or {}).get("reminderDaysBefore", 3)
        reminder_days = _guide_int(body.get("reminderDaysBefore"), default_reminder, lo=0, hi=365)
        reminder_at = _guide_date_minus(due_at, reminder_days)
        recurrence = str(body.get("recurrence") or (preset or {}).get("recurrence") or "monthly").strip()[:40]
        payment_method = str(body.get("paymentMethod") or "").strip()[:120]
        auto_debit = 1 if _guide_bool_value(body.get("autoDebit") or body.get("auto_debit")) else 0
        now = now_iso()
        item_id = str(uuid.uuid4())
        conn.execute(
            "INSERT INTO guide_life_items (id, user_id, type, title, provider, amount, currency, payment_method, auto_debit, due_day, due_at, recurrence, reminder_days_before, notes, active, created_at, updated_at) "
            "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 1, ?, ?)",
            (
                item_id, user["id"], item_type, title, str(body.get("provider") or "").strip()[:160],
                _guide_int(body.get("amount"), 0, lo=0), str(body.get("currency") or "JPY").strip()[:12] or "JPY",
                payment_method, auto_debit, due_day, due_at,
                recurrence, reminder_days,
                str(body.get("notes") or "").strip()[:2000], now, now,
            ),
        )
        if due_at:
            # Auto-debit (口座振替 / 信用卡) only needs a balance check; manual
            # methods (便利店 / 收信件 / 银行转账) need a "go pay before due" nudge.
            todo_title = f"{title} {'扣款日 · 确认余额' if auto_debit else '缴费截止'}"
            todo_summary = (
                "自动扣款，确认账户 / 信用卡余额充足，避免扣款失败。"
                if auto_debit else
                "记得在截止前完成缴费（便利店 / 银行 / 邮局），避免逾期。"
            )
            self._guide_todo_insert(conn, user_id=user["id"], source_type="life_item", source_id=item_id,
                                    title=todo_title, summary=todo_summary,
                                    todo_type="life_payment", due_at=due_at, reminder_at=reminder_at,
                                    priority="normal" if auto_debit else "high",
                                    recurrence=recurrence if recurrence in ("monthly", "yearly", "weekly") else "",
                                    product_slugs="bank-account-document-checklist,mobile-plan-comparison,work-visa-change-checklist",
                                    service_slugs="japan-life-consultation,japanese-phone-call-proxy,delivery-utility-call")
        item = conn.execute("SELECT * FROM guide_life_items WHERE id = ?", (item_id,)).fetchone()
        self.send_json({"status": "ok", "item": serialize_guide_life_item(item)})

