        self._guide_delete_todos_for_source(conn, user["id"], "contract", item_id)
        conn.execute("DELETE FROM guide_contracts WHERE id = ? AND user_id = ?", (item_id, user["id"]))
        self.send_json({"status": "ok", "deleted": item_id})

