        work = [serialize_guide_company_review(r) for r in conn.execute(
            "SELECT * FROM guide_company_reviews WHERE company_id = ? AND status IN ('approved','published') ORDER BY created_at DESC LIMIT 50",
            (row["id"],)).fetchall()]
