    def api_admin_guide_articles(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        self.require_admin(conn)
        page = _guide_int(query.get("page"), 1, lo=1)
        page_size = _guide_int(query.get("pageSize") or query.get("limit"), 50, lo=1, hi=100)
        where = ["country = ?"]
        params: list[Any] = [_normalize_country_code(query.get("country") or "jp")]
        for q_key, col in (("status", "status"), ("categoryKey", "category_key"), ("subCategoryKey", "sub_category_key")):
            val = (query.get(q_key) or "").strip()
            if val:
                where.append(f"{col} = ?")
                params.append(val)
        keyword = (query.get("keyword") or query.get("q") or "").strip()
        if keyword:
            kw = f"%{keyword}%"
            where.append("(title LIKE ? OR summary LIKE ? OR body LIKE ? OR slug LIKE ? OR tags LIKE ?)")
            params.extend([kw, kw, kw, kw, kw])
        clause = " AND ".join(where)
        order = {
            "published": "published_at DESC, updated_at DESC",
            "oldest": "updated_at ASC",
            "sort": "sort_order ASC, updated_at DESC",
        }.get((query.get("sort") or "updated").strip(), "updated_at DESC")
        rows = conn.execute(
            f"SELECT * FROM guide_articles WHERE {clause} ORDER BY {order} LIMIT ? OFFSET ?",
            [*params, page_size, (page - 1) * page_size],
        ).fetchall()
        total = conn.execute(f"SELECT COUNT(*) AS c FROM guide_articles WHERE {clause}", params).fetchone()["c"]
        country = params[0]
        stats = {
            "total": int(total),
            "published": int(conn.execute("SELECT COUNT(*) AS c FROM guide_articles WHERE country = ? AND status = 'published'", (country,)).fetchone()["c"]),
            "draft": int(conn.execute("SELECT COUNT(*) AS c FROM guide_articles WHERE country = ? AND status = 'draft'", (country,)).fetchone()["c"]),
            "hidden": int(conn.execute("SELECT COUNT(*) AS c FROM guide_articles WHERE country = ? AND status = 'hidden'", (country,)).fetchone()["c"]),
            "missingSeo": int(conn.execute(
                "SELECT COUNT(*) AS c FROM guide_articles WHERE country = ? AND (seo_title = '' OR seo_description = '')",
                (country,),
            ).fetchone()["c"]),
        }
        self.send_json({
            "status": "ok", "items": [serialize_guide_article(r, include_body=False) for r in rows],
            "page": page, "pageSize": page_size, "total": int(total), "stats": stats,
        })

    def api_admin_guide_stale_queue(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        """过期复核队列:列出 verified_at + stale_after_days 已过期(或即将过期)的已发布
        文章,按类别 + 过期天数排序。日期加减在 Python 里做,避免 PG/SQLite 方言差异。"""
        self.require_admin(conn)
        country = _normalize_country_code(query.get("country") or "jp")
        rows = conn.execute(
            "SELECT id, title, slug, category_key, sub_category_key, source_url, source_label, "
            "verified_at, stale_after_days, updated_at FROM guide_articles "
            "WHERE country = ? AND status = 'published' AND verified_at <> '' AND stale_after_days > 0",
            (country,),
        ).fetchall()
        today = datetime.now(timezone.utc).date()
        items: list[dict[str, Any]] = []
        for r in rows:
            d = dict(r)
            checked_dt = parse_iso(str(d.get("verified_at") or ""))
            if checked_dt is None:
                continue
            due = checked_dt.date() + timedelta(days=int(d.get("stale_after_days") or 0))
            overdue_days = (today - due).days  # >0 已过期,<=0 未到期
            if overdue_days < 0:
                continue  # 只列已过期的
            items.append({
                "id": d.get("id"), "title": d.get("title"), "slug": d.get("slug"),
                "categoryKey": d.get("category_key") or "", "subCategoryKey": d.get("sub_category_key") or "",
                "sourceUrl": d.get("source_url") or "", "sourceLabel": d.get("source_label") or "",
                "verifiedAt": d.get("verified_at") or "", "staleAfterDays": int(d.get("stale_after_days") or 0),
                "dueAt": due.isoformat(), "overdueDays": overdue_days,
            })
        # 过期最久的排最前;同过期天数按类别稳定排序。
        items.sort(key=lambda x: (-x["overdueDays"], x["categoryKey"], x["slug"]))
        self.send_json({"status": "ok", "country": country, "total": len(items), "items": items})

    def api_admin_guide_article_ai_draft(self, conn: sqlite3.Connection) -> None:
        self.require_admin(conn)
        data = self.read_json()
        topic = _clean_text(data.get("topic") or data.get("title"), 200)
        if not topic:
            raise APIError("请输入要生成的文章主题", 400, "empty_topic")
        country = _normalize_country_code(data.get("country") or "jp")
        language = _normalize_language_tag(data.get("language") or "zh-CN")
        category_key = _clean_text(data.get("categoryKey") or data.get("category_key") or "study_japan", 80)
        sub_category_key = _clean_text(data.get("subCategoryKey") or data.get("sub_category_key"), 80)
        audience = _clean_text(data.get("audience"), 300)
        source_hint = str(data.get("sourceHint") or data.get("sourceUrl") or "").strip()[:500]
        context_items: list[dict[str, Any]] = []
        try:
            context_items = guide_ai_retrieve_context(
                conn,
                user_message=" ".join(x for x in [topic, category_key, sub_category_key, audience] if x),
                country=country,
                language=language,
                limit=8,
            )
        except Exception:
            context_items = []
        draft = seed_llm.generate_guide_article_draft(
            topic=topic,
            category_key=category_key,
            sub_category_key=sub_category_key,
            audience=audience,
            language=language,
            country=country,
            source_hint=source_hint,
            context_lines=[str(item.get("modelLine") or item.get("title") or "") for item in context_items],
            provider=str(data.get("engine") or "auto"),
            model=str(data.get("mode") or data.get("model") or "think"),
        )
        if not draft:
            return self.send_json(
                self._error_envelope(
                    "AI_DRAFT_UNAVAILABLE",
                    "Machi AI 暂时无法生成文章草稿，请稍后重试，或先手动保存一篇草稿。",
                ),
                503,
            )
        # Server-side cleanup and DB-ready defaults. The draft is never published
        # automatically; admins review and explicitly save/publish.
        slug_base = self._guide_slugify(draft.get("slug") or draft.get("title") or topic, fallback=uuid.uuid4().hex[:10])
        slug = slug_base
        suffix = 2
        while conn.execute(
            "SELECT id FROM guide_articles WHERE country = ? AND slug = ? LIMIT 1",
            (country, slug),
        ).fetchone():
            slug = f"{slug_base}-{suffix}"
            suffix += 1
        now = now_iso()
        article = {
            "title": draft.get("title") or topic,
            "slug": slug,
            "status": "draft",
            "categoryKey": category_key,
            "subCategoryKey": sub_category_key,
            "summary": draft.get("summary") or "",
            "body": draft.get("body") or "",
            "seoTitle": draft.get("seoTitle") or draft.get("title") or topic,
            "seoDescription": draft.get("seoDescription") or draft.get("summary") or "",
            "coverImage": "",
            "tags": draft.get("tags") or [],
            "relatedArticleSlugs": [],
            "relatedProductSlugs": [],
            "authorName": "Machi 日本指南编辑部",
            "sortOrder": 0,
            "isFeatured": False,
            "isFree": True,
            "isPaid": False,
            "sourceLabel": draft.get("sourceLabel") or "",
            "sourceUrl": draft.get("sourceUrl") or "",
            "verifiedAt": now,
            "staleAfterDays": int(draft.get("staleAfterDays") or 180),
        }
        self.send_json({
            "status": "ok",
            "article": article,
            "qualityWarnings": draft.get("qualityWarnings") or [],
            "qualityNotes": draft.get("qualityNotes") or [],
            "context": [{"type": it.get("type"), "title": it.get("title"), "route": it.get("route")} for it in context_items],
        })

