    def api_admin_guide_review_action(self, conn: sqlite3.Connection, kind: str, review_id: str, action: str) -> None:
        self.require_admin(conn)
        table = "guide_interview_reviews" if kind == "interview" else "guide_company_reviews"
        row = conn.execute(f"SELECT id, company_id FROM {table} WHERE id = ?", (review_id,)).fetchone()
        if not row:
            raise APIError("评论不存在", 404, "guide_review_not_found")
        new_status = {"approve": "published", "reject": "rejected", "hide": "hidden"}.get(action)
        if not new_status:
            raise APIError("未知操作", 400, "invalid_action")
        conn.execute(f"UPDATE {table} SET status = ?, updated_at = ? WHERE id = ?", (new_status, now_iso(), review_id))
        # Keep the denormalised review_count on the company in sync.
        approved = conn.execute(
            "SELECT (SELECT COUNT(*) FROM guide_company_reviews WHERE company_id = ? AND status IN ('approved','published')) + "
            "(SELECT COUNT(*) FROM guide_interview_reviews WHERE company_id = ? AND status IN ('approved','published')) AS c",
            (row["company_id"], row["company_id"])).fetchone()["c"]
        interview_count = conn.execute(
            "SELECT COUNT(*) AS c FROM guide_interview_reviews WHERE company_id = ? AND status IN ('approved','published')",
            (row["company_id"],)).fetchone()["c"]
        conn.execute("UPDATE guide_companies SET review_count = ?, updated_at = ? WHERE id = ?",
                     (int(approved), now_iso(), row["company_id"]))
        conn.execute("UPDATE guide_companies SET interview_review_count = ?, updated_at = ? WHERE id = ?",
                     (int(interview_count), now_iso(), row["company_id"]))
        self.send_json({"status": "ok", "id": review_id, "reviewStatus": new_status})

    def api_admin_guide_update_correction(self, conn: sqlite3.Connection, correction_id: str) -> None:
        self.require_admin(conn)
        row = conn.execute("SELECT id FROM guide_correction_reports WHERE id = ?", (correction_id,)).fetchone()
        if not row:
            raise APIError("纠错记录不存在", 404, "guide_correction_not_found")
        data = self.read_json()
        status = _clean_text(data.get("status"), 40)
        if status not in {"pending", "reviewed", "applied", "rejected"}:
            raise APIError("状态不正确", 400, "invalid_correction_status")
        conn.execute("UPDATE guide_correction_reports SET status = ?, updated_at = ? WHERE id = ?", (status, now_iso(), correction_id))
        self.send_json({"status": "ok", "id": correction_id, "correctionStatus": status})

    def api_admin_guide_upload(self, conn: sqlite3.Connection) -> None:
        # Admin-only alias for the existing media upload pipeline. Keeping the
        # route under /api/admin/guide makes the Guide management API complete
        # without duplicating multipart/base64 parsing or media persistence.
        self.require_admin(conn)
        return self.api_upload_media(conn)

    def api_generated_listing_card(self, query: dict[str, str], *, image_format: str = "png", head_only: bool = False) -> None:
        listing_type = normalize_listing_type(query.get("type") or "secondhand")
        try:
            index = int(query.get("i") or 0)
        except (TypeError, ValueError):
            index = 0
        if image_format == "svg":
            body = generated_listing_card_svg(listing_type, index).encode("utf-8")
            content_type = "image/svg+xml; charset=utf-8"
        else:
            body = generated_listing_card_png(listing_type, index)
            content_type = "image/png"
        self.send_response(200)
        self.send_header("Content-Type", content_type)
        self.send_header("Content-Length", str(len(body)))
        self.send_header("Cache-Control", "public, max-age=31536000")
        self.send_header("X-Machi-Version", "1.0")
        self.send_header("X-KaiX-Version", "1.0")
        self.send_header("X-Request-Id", getattr(self, "_request_id", "") or "")
        self._set_cors()
        self._set_security_headers()
        self.end_headers()
        if not head_only:
            self.wfile.write(body)

    # ---- HTTP verbs ----

    def do_OPTIONS(self) -> None:
        self.send_response(204)
        self._set_cors()
        self.end_headers()

    def do_GET(self) -> None:
        path = self.path.split("?", 1)[0]
        if path in ("/healthz", "/readyz") or self.path.startswith("/api/"):
            self._dispatch("GET")
        elif self.path.startswith("/media/"):
            self._serve_media()
        else:
            self._serve_static()

    def do_HEAD(self) -> None:
        path = self.path.split("?", 1)[0]
        if path == "/healthz":
            self.send_response(200)
            self.send_header("Content-Type", "application/json")
            self.send_header("Content-Length", "0")
            self._set_cors()
            self.end_headers()
            return
        if path == "/readyz":
            try:
                with db() as conn:
                    conn.execute("SELECT 1").fetchone()
                self.send_response(200)
            except Exception:
                self.send_response(503)
            self.send_header("Content-Type", "application/json")
            self.send_header("Content-Length", "0")
            self._set_cors()
            self.end_headers()
            return
        if path in ("/api/generated/listing-card.png", "/api/generated/listing-card.svg"):
            parsed = urlparse(self.path)
            query = {k: v[0] if v else "" for k, v in parse_qs(parsed.query).items()}
            self._request_id = secrets.token_hex(8)
            self.api_generated_listing_card(query, image_format="svg" if path.endswith(".svg") else "png", head_only=True)
            return
        self.send_error(405)

    def do_POST(self) -> None:
        self._dispatch("POST")

    def do_PATCH(self) -> None:
        self._dispatch("PATCH")

    def do_PUT(self) -> None:
        self._dispatch("PUT")

    def do_DELETE(self) -> None:
        self._dispatch("DELETE")

    def _serve_static(self) -> None:
        relative = self.path.split("?", 1)[0].lstrip("/")
        candidate = (STATIC_DIR / (relative or "index.html")).resolve()
        try:
            candidate.relative_to(STATIC_DIR.resolve())
        except ValueError:
            self.send_error(404)
            return
        if not candidate.exists() or candidate.is_dir():
            self.send_error(404)
            return
        mime, _ = mimetypes.guess_type(candidate.name)
        data = candidate.read_bytes()
        self.send_response(200)
        self.send_header("Content-Type", mime or "application/octet-stream")
        self.send_header("Content-Length", str(len(data)))
        self._set_cors()
        self.end_headers()
        self.wfile.write(data)

    def _serve_media(self) -> None:
        relative = self.path.split("?", 1)[0].lstrip("/")
        candidate = (ROOT / relative).resolve()
        try:
            candidate.relative_to(MEDIA_DIR.resolve())
        except ValueError:
            self.send_error(404)
            return
        if not candidate.exists() or candidate.is_dir():
            self.send_error(404)
            return
        mime, _ = mimetypes.guess_type(candidate.name)
        data = candidate.read_bytes()
        self.send_response(200)
        self.send_header("Content-Type", mime or "application/octet-stream")
        self.send_header("Content-Length", str(len(data)))
        self.send_header("Cache-Control", "public, max-age=31536000")
        self._set_cors()
        self.end_headers()
        self.wfile.write(data)

    # ---- routing ----

    def _dispatch(self, method: str) -> None:
        parsed = urlparse(self.path)
        path = parsed.path
        query = {k: v[0] if v else "" for k, v in parse_qs(parsed.query).items()}
        self._pending_event_user_id = None
        self._session_user_id = None
        self._idem_capture = None
        # Stamp every request with a unique id for log correlation.
        self._request_id = secrets.token_hex(8)
        ip = self._client_ip()
        started = time.perf_counter()
        status_code = 200

        # Cheap health endpoints don't go through the DB lock or rate limits.
        # `/api/health` is an alias of `/healthz` for load balancers / uptime
        # checks that expect the API prefix.
        if path in ("/healthz", "/api/health") and method == "GET":
            self.send_json({
                "ok": True,
                "service": "machi-backend",
                "database": KAIX_DB_BACKEND,
                "ts": now_iso(),
            })
            ACCESS_LOG.info('%s "GET %s" 200 ip=%s', self._request_id, path, ip)
            return
        if path in ("/readyz", "/api/health/ready") and method == "GET":
            try:
                with db() as conn:
                    conn.execute("SELECT 1").fetchone()
                payload = {"ready": True, "database": KAIX_DB_BACKEND}
                pstats = _pg_pool_stats()
                if pstats is not None:
                    payload["pgPool"] = pstats
                self.send_json(payload)
                ACCESS_LOG.info('%s "GET %s" 200 ip=%s', self._request_id, path, ip)
            except Exception as exc:
                self.send_error_json(f"db: {exc}", 503, "not_ready")
                ACCESS_LOG.warning('%s "GET %s" 503 ip=%s err=%s', self._request_id, path, ip, exc)
            return
        # Capability handshake — public, no auth, no DB. Clients hit this on
        # launch to gate wallet/commerce UI against the actual backend version.
        if path == "/api/meta/client-config" and method == "GET":
            self.send_json(client_config_payload())
            ACCESS_LOG.info('%s "GET %s" 200 ip=%s', self._request_id, path, ip)
            return
        if path in ("/api/generated/listing-card.png", "/api/generated/listing-card.svg") and method == "GET":
            self.api_generated_listing_card(query, image_format="svg" if path.endswith(".svg") else "png")
            ACCESS_LOG.info('%s "GET %s" 200 ip=%s', self._request_id, path, ip)
            return

        # Rate limit before doing any real work.
        group = _rate_group_for(path, method)
        if not rate_check(ip, group):
            status_code = 429
            self.send_response(429)
            self.send_header("Content-Type", "application/json; charset=utf-8")
            self.send_header("Retry-After", "30")
            self._set_cors()
            self._set_security_headers()
            self.end_headers()
            self.wfile.write(json.dumps(self._error_envelope("rate_limited", "请求过于频繁，请稍后再试。"), ensure_ascii=False).encode("utf-8"))
            ACCESS_LOG.warning('%s "%s %s" 429 ip=%s group=%s', self._request_id, method, path, ip, group)
            return

        # Only serialize on the DB lock for actual writes. SQLite WAL
        # supports concurrent readers and the lock was previously the
        # main throughput ceiling. Taxonomy GET endpoints lazily seed
        # default rows on first use, so they intentionally join the write
        # path to avoid two first-time visitors racing on SQLite.
        need_write_lock = (
            method in ("POST", "PATCH", "PUT", "DELETE")
            or path == "/api/auth/google/callback"
            or (method == "GET" and path in {"/api/listing-taxonomy", "/api/admin/listing-taxonomy"})
        )
        lock_held = False
        response = None
        try:
            if need_write_lock:
                # Fail fast instead of hanging forever if the lock is wedged
                # or under sustained contention — a stuck holder can no
                # longer pile up connections and take the whole site down.
                if not DB_LOCK.acquire(timeout=DB_WRITE_LOCK_TIMEOUT_SEC):
                    raise APIError("服务器繁忙，请稍后再试", 503, "server_busy")
                lock_held = True
            try:
                with db() as conn:
                    advisory_lock_id = self._idempotency_advisory_lock(conn, method, path)
                    try:
                        # Generic idempotency: a repeated write carrying the
                        # same key replays the first successful response.
                        replay = self._idempotency_lookup(conn, method, path)
                        if replay is not None:
                            status_code = replay[0]
                            self._send_idempotent_replay(replay[0], replay[1])
                        else:
                            response = self._route(conn, method, path, query)
                            self._idempotency_store(conn, method, path)
                    finally:
                        self._idempotency_advisory_unlock(conn, advisory_lock_id)
            finally:
                if lock_held:
                    DB_LOCK.release()
            # The SSE handler defers the long-running stream until after
            # any lock has been released. If the route asked for an
            # event stream, run it now.
            if self._pending_event_user_id is not None:
                self._run_event_stream(self._pending_event_user_id)
                return
            if response is None:
                pass
        except APIError as exc:
            status_code = exc.status
            self.send_error_json(str(exc), exc.status, exc.code, getattr(exc, "detail", None))
        except sqlite3.IntegrityError as exc:
            status_code = 409
            self.send_error_json(str(exc), 409, "conflict")
        except (BrokenPipeError, ConnectionResetError):
            # The client (or the reverse proxy in front of us) closed the
            # connection mid-response — common on mobile / flaky networks and
            # when a user navigates away. Not a server fault: log it as 499
            # (nginx convention: client closed request) via the access log so
            # it does NOT hit ERR_LOG / trigger an error-alert email, and don't
            # try to write an error body to an already-dead socket.
            status_code = 499
            ACCESS_LOG.info('%s "%s %s" 499 ip=%s client-disconnect', self._request_id, method, path, ip)
        except Exception as exc:
            status_code = 500
            err_id = self._request_id
            # Log the full traceback to error log but only send a generic
            # message to the client so we don't leak stack traces.
            ERR_LOG.exception('%s "%s %s" 500 ip=%s', err_id, method, path, ip)
            self.send_error_json(
                f"server error (request {err_id})" if PRODUCTION else f"{type(exc).__name__}: {exc}",
                500,
                "server_error",
            )
        finally:
            duration_ms = (time.perf_counter() - started) * 1000
            ACCESS_LOG.info(
                '%s "%s %s" %d ip=%s ms=%.1f',
                self._request_id, method, path, status_code, ip, duration_ms,
            )
            # Surface slow endpoints (with pool saturation) without an APM.
            if KAIX_SLOW_REQUEST_MS and duration_ms >= KAIX_SLOW_REQUEST_MS:
                ERR_LOG.warning(
                    'SLOW %s "%s %s" %d ms=%.0f ip=%s%s',
                    self._request_id, method, path, status_code, duration_ms, ip, _pg_pool_stat_suffix(),
                )
            # Best-effort visitor analytics. We pass ONLY coarse access
            # metadata — never the Authorization header, cookies, request
            # body, query string, or any secret. `path` here is already the
            # query-stripped path. Enqueue is non-blocking; the background
            # writer does the (locked) insert + GeoIP off the request thread.
            try:
                if (VISITOR_LOG_ENABLED and method != "OPTIONS"
                        and not path.startswith("/api/events")
                        and not path.lower().endswith(_VISIT_SKIP_EXT)):
                    enqueue_visitor_log({
                        "created_at": now_iso(),
                        "ip": ip,
                        "ip_hash": hash_ip(ip),
                        "method": method,
                        "path": path,
                        "status": status_code,
                        "user_id": getattr(self, "_session_user_id", None),
                        "user_agent": (self.headers.get("User-Agent") or "")[:300],
                        "referer": (self.headers.get("Referer") or "")[:300],
                        # Security events bypass per-IP dedup so admins always
                        # see every login / register / reset attempt.
                        "force": path.startswith("/api/auth/"),
                    })
            except Exception:
                pass

    def _client_ip(self) -> str:
        # X-Forwarded-For hardening: the LEFTMOST entries are client-controllable
        # (a spoofer prepends fake IPs), so the old `split(",")[0]` let attackers
        # rotate their apparent IP and defeat login/captcha/rate throttles. Take
        # the (KAIX_TRUSTED_PROXY_HOPS)-th value from the RIGHT — the IP our own
        # trusted proxy actually observed — instead.
        xff = self.headers.get("X-Forwarded-For", "")
        if xff and KAIX_TRUSTED_PROXY_HOPS > 0:
            parts = [p.strip() for p in xff.split(",") if p.strip()]
            if parts:
                return parts[max(0, len(parts) - KAIX_TRUSTED_PROXY_HOPS)]
        return self.client_address[0] if self.client_address else "anon"

    def _route(self, conn: sqlite3.Connection, method: str, path: str, query: dict[str, str]) -> Any:
        # auth
        if path == "/api/auth/register" and method == "POST":
            return self.api_register(conn)
        if path == "/api/auth/login" and method == "POST":
            return self.api_login(conn)
        if path == "/api/auth/apple" and method == "POST":
            return self.api_apple_native(conn)
        if path in ("/api/miniapp/wechat/login", "/api/miniapp/v1/wechat/login") and method == "POST":
            return self.api_miniapp_wechat_login(conn)
        if path == "/api/auth/apple/link" and method == "POST":
            return self.api_apple_link(conn)
        if path == "/api/auth/apple/unlink" and method == "POST":
            return self.api_apple_unlink(conn)
        if path == "/api/auth/google/start" and method == "GET":
            return self.api_google_start(conn, query)
        if path == "/api/auth/google/callback" and method == "GET":
            return self.api_google_callback(conn, query)
        if path == "/api/auth/google/unlink" and method == "POST":
            return self.api_google_unlink(conn)
        if path == "/api/auth/logout" and method == "POST":
            return self.api_logout(conn)
        if path == "/api/auth/me" and method == "GET":
            return self.api_me(conn)
        if path == "/api/auth/session" and method == "GET":
            return self.api_session(conn)
        if path == "/api/auth/me" and method == "PATCH":
            return self.api_update_me(conn)
        if path == "/api/auth/me" and method == "DELETE":
            return self.api_delete_me(conn)
        if path == "/api/auth/check-username" and method == "GET":
            return self.api_check_username(conn, query)
        if path == "/api/auth/check-email" and method == "GET":
            return self.api_check_email(conn, query)
        # email verification + password recovery + 2-step login
        if path == "/api/auth/captcha" and method == "POST":
            return self.api_captcha(conn)
        if path in ("/api/auth/email/send-code", "/api/auth/send-verification-code") and method == "POST":
            return self.api_send_email_code(conn)
        if path == "/api/auth/verify-code" and method == "POST":
            return self.api_verify_code(conn)
        if path == "/api/auth/login/start" and method == "POST":
            return self.api_login_start(conn)
        if path == "/api/auth/login/verify" and method == "POST":
            return self.api_login_verify(conn)
        if path in ("/api/auth/change-password", "/api/account/change-password") and method == "POST":
            return self.api_change_password(conn)
        if path == "/api/account/verify-password" and method == "POST":
            return self.api_verify_password(conn)
        if path == "/api/account/change-email" and method == "POST":
            return self.api_change_email(conn)
        if path == "/api/account/region-language" and method == "PATCH":
            return self.api_update_me(conn)
        if path == "/api/auth/forgot-password" and method == "POST":
            return self.api_forgot_password(conn)
        if path == "/api/auth/reset-password" and method == "POST":
            return self.api_reset_password(conn)

        # bootstrap (single round-trip startup payload)
        if path == "/api/bootstrap" and method == "GET":
            return self.api_bootstrap(conn)

        # users
        if path == "/api/users/me" and method == "GET":
            return self.api_me(conn)
        if path == "/api/users/me" and method == "PATCH":
            return self.api_update_me(conn)
        if path.startswith("/api/users/"):
            parts = path[len("/api/users/"):].split("/")
            user_id = unquote(parts[0])
            rest = "/".join(parts[1:])
            if not rest and method == "GET":
                return self.api_user_detail(conn, user_id)
            if rest == "posts" and method == "GET":
                return self.api_user_posts(conn, user_id, query)
            if rest == "reposts" and method == "GET":
                return self.api_user_reposts(conn, user_id, query)
            if rest == "replies" and method == "GET":
                return self.api_user_replies(conn, user_id, query)
            if rest == "media" and method == "GET":
                return self.api_user_media(conn, user_id, query)
            if rest == "likes" and method == "GET":
                return self.api_user_likes(conn, user_id, query)
            if rest == "bookmarks" and method == "GET":
                return self.api_user_bookmarks(conn, user_id, query)
            if rest == "follow" and method == "POST":
                return self.api_follow(conn, user_id, True)
            if rest == "follow" and method == "DELETE":
                return self.api_follow(conn, user_id, False)
            if rest == "block" and method == "POST":
                return self.api_block(conn, user_id, True)
            if rest == "block" and method == "DELETE":
                return self.api_block(conn, user_id, False)
            if rest == "report" and method == "POST":
                return self.api_report(conn, "user", user_id)
            if rest == "followers" and method == "GET":
                return self.api_relationship(conn, user_id, "followers")
            if rest == "following" and method == "GET":
                return self.api_relationship(conn, user_id, "following")

        # feed
        if path == "/api/feed" and method == "GET":
            return self.api_feed(conn, query)

        # posts
        if path == "/api/posts" and method == "GET":
            return self.api_feed(conn, query)
        if path == "/api/posts" and method == "POST":
            return self.api_create_post(conn)
        if path.startswith("/api/posts/"):
            parts = path[len("/api/posts/"):].split("/")
            post_id = parts[0]
            rest = "/".join(parts[1:])
            if not rest and method == "GET":
                return self.api_post_detail(conn, post_id)
            if not rest and method == "PATCH":
                return self.api_edit_post(conn, post_id)
            if not rest and method == "DELETE":
                return self.api_delete_post(conn, post_id)
            if rest == "like" and method == "POST":
                return self.api_post_interaction(conn, post_id, "like", True)
            if rest == "like" and method == "DELETE":
                return self.api_post_interaction(conn, post_id, "like", False)
            if rest == "bookmark" and method == "POST":
                return self.api_post_interaction(conn, post_id, "bookmark", True)
            if rest == "bookmark" and method == "DELETE":
                return self.api_post_interaction(conn, post_id, "bookmark", False)
            if rest == "save" and method == "POST":
                return self.api_post_interaction(conn, post_id, "bookmark", True)
            if rest == "save" and method == "DELETE":
                return self.api_post_interaction(conn, post_id, "bookmark", False)
            # 不感兴趣 (negative feedback): records a 'dismiss' interaction that
            # feeds the recommender's negative-preference maps. Never bumps heat,
            # never notifies (see api_post_interaction).
            if rest == "dismiss" and method == "POST":
                return self.api_post_interaction(conn, post_id, "dismiss", True)
            if rest == "dismiss" and method == "DELETE":
                return self.api_post_interaction(conn, post_id, "dismiss", False)
            if rest == "join" and method == "POST":
                return self.api_meetup_join(conn, post_id, True)
            if rest == "join" and method == "DELETE":
                return self.api_meetup_join(conn, post_id, False)
            if rest == "participants" and method == "GET":
                return self.api_meetup_participants(conn, post_id)
            if rest == "repost" and method == "POST":
                return self.api_repost(conn, post_id, True)
            if rest == "repost" and method == "DELETE":
                return self.api_repost(conn, post_id, False)
            if rest == "poll/vote" and method == "POST":
                return self.api_vote_poll(conn, post_id)
            if rest == "view" and method == "POST":
                return self.api_view_post(conn, post_id)
            if rest == "report" and method == "POST":
                return self.api_report(conn, "post", post_id)
            if rest == "comments" and method == "GET":
                return self.api_list_comments(conn, post_id, query)
            if rest == "comments" and method == "POST":
                return self.api_create_comment(conn, post_id)

        # comments
        if path.startswith("/api/comments/"):
            parts = path[len("/api/comments/"):].split("/")
            comment_id = parts[0]
            rest = "/".join(parts[1:])
            if not rest and method == "DELETE":
                return self.api_delete_comment(conn, comment_id)
            if rest == "like" and method == "POST":
                return self.api_comment_like(conn, comment_id, True)
            if rest == "like" and method == "DELETE":
                return self.api_comment_like(conn, comment_id, False)
            if rest == "report" and method == "POST":
                return self.api_report(conn, "comment", comment_id)
            if rest == "accept" and method in ("POST", "DELETE"):
                return self.api_accept_answer(conn, comment_id, method == "POST")

        # Machi Reputation
        if path == "/api/reputation/me" and method == "GET":
            return self.api_reputation_me(conn)
        if path == "/api/reputation/logs/me" and method == "GET":
            return self.api_reputation_logs_me(conn, query)
        if path == "/api/reputation/badges" and method == "GET":
            return self.api_reputation_badges(conn)
        if path == "/api/reputation/rewards/me" and method == "GET":
            return self.api_reputation_rewards_me(conn)
        if path == "/api/reputation/levels" and method == "GET":
            return self.api_reputation_levels(conn)
        if path == "/api/reputation/privileges" and method == "GET":
            return self.api_reputation_privileges(conn)
        if path == "/api/reputation/events" and method == "POST":
            return self.api_reputation_event(conn)
        if path.startswith("/api/reputation/users/") and method == "GET":
            return self.api_reputation_user(conn, unquote(path[len("/api/reputation/users/"):]))
        if path == "/api/reputation/admin/adjust" and method == "POST":
            return self.api_reputation_admin_adjust(conn)
        if path == "/api/reputation/admin/grant-badge" and method == "POST":
            return self.api_reputation_admin_grant_badge(conn)
        if path == "/api/reputation/admin/revoke-badge" and method == "POST":
            return self.api_reputation_admin_revoke_badge(conn)
        if path == "/api/reputation/admin/freeze" and method == "POST":
            return self.api_reputation_admin_freeze(conn)
        if path == "/api/reputation/admin/unfreeze" and method == "POST":
            return self.api_reputation_admin_unfreeze(conn)
        if path == "/api/reputation/admin/users" and method == "GET":
            return self.api_reputation_admin_users(conn, query)
        if path == "/api/reputation/admin/risk" and method == "GET":
            return self.api_reputation_admin_risk(conn, query)
        if path == "/api/reputation/admin/events" and method == "GET":
            return self.api_reputation_admin_events(conn, query)
        if path == "/api/reputation/admin/reviews" and method == "GET":
            return self.api_reputation_admin_reviews(conn, query)

        # Merchant verification and operating console. Web and native clients
        # share this state; verification flags are only changed by admin review.
        if path in {"/api/business/profile", "/api/business/application", "/api/me/business"} and method == "GET":
            return self.api_business_profile(conn)
        if path in {"/api/business/profile", "/api/business/application", "/api/me/business"} and method in {"POST", "PATCH"}:
            return self.api_upsert_business_application(conn)
        if path.startswith("/api/business/documents/") and method == "DELETE":
            return self.api_delete_business_document(conn, unquote(path[len("/api/business/documents/"):]))
        if path in {"/api/business/dashboard", "/api/me/business/dashboard"} and method == "GET":
            return self.api_business_dashboard(conn)
        if path in {"/api/my/business/reviews", "/api/me/business/reviews", "/api/business/reviews"} and method == "GET":
            return self.api_my_business_reviews(conn, query)
        # Public merchant directory: verified businesses browsable by anyone.
        if path == "/api/businesses/directory" and method == "GET":
            return self.api_businesses_directory(conn, query)
        if path.startswith("/api/businesses/") and path.endswith("/public") and method == "GET":
            return self.api_business_public(conn, unquote(path[len("/api/businesses/"):-len("/public")]))

        # structured city listings (marketplace / rentals / jobs / services)
        if path == "/api/listing-taxonomy" and method == "GET":
            return self.api_listing_taxonomy(conn, query)
        if path == "/api/listings" and method == "GET":
            return self.api_listings(conn, query)
        if path == "/api/listings" and method == "POST":
            return self.api_create_listing(conn)
        if path == "/api/listing_publish_precheck" and method == "GET":
            return self.api_listing_publish_precheck(conn, query)
        if path in {"/api/my/listings", "/api/me/listings"} and method == "GET":
            next_query = dict(query)
            next_query["owner"] = "me"
            return self.api_listings(conn, next_query)
        if path in {"/api/my/saved-listings", "/api/me/saved-listings", "/api/my/favorites", "/api/me/favorites"} and method == "GET":
            return self.api_my_saved_listings(conn, query)
        if path in {"/api/my/topic-follows", "/api/me/topic-follows"} and method == "GET":
            return self.api_my_topic_follows(conn)
        if path in {"/api/my/workbench/summary", "/api/me/workbench/summary"} and method == "GET":
            return self.api_my_workbench_summary(conn)
        if path in {"/api/my/listing-inquiries", "/api/my/inquiries", "/api/me/listing-inquiries", "/api/me/inquiries"} and method == "GET":
            return self.api_my_listing_inquiries(conn, query)
        if path in {"/api/my/applications", "/api/me/applications"} and method == "GET":
            next_query = dict(query)
            next_query.setdefault("role", "sent")
            next_query["type"] = next_query.get("type") or "job,hiring"
            return self.api_my_listing_inquiries(conn, next_query)
        if path in {"/api/my/service-appointments", "/api/me/service-appointments", "/api/my/appointments", "/api/me/appointments"} and method == "GET":
            return self.api_my_service_appointments(conn, query)
        if path in {"/api/me/bookings", "/api/my/bookings"} and method == "GET":
            return self.api_my_bookings(conn, query)
        if path in {"/api/me/orders", "/api/my/orders"} and method == "GET":
            return self.api_my_orders(conn, query)
        if path == "/api/me/reputation" and method == "GET":
            return self.api_reputation_me(conn)
        if path.startswith("/api/member/resources/"):
            parts = path[len("/api/member/resources/"):].split("/")
            resource_id = unquote(parts[0])
            tail = "/".join(parts[1:])
            if tail == "download-url" and method == "POST":
                return self.api_member_resource_download_url(conn, resource_id)
        if path.startswith("/api/listing-inquiries/") and method == "PATCH":
            return self.api_update_listing_inquiry(conn, unquote(path.split("/")[3]))
        if path.startswith("/api/listing-inquiries/") and method == "DELETE":
            return self.api_delete_listing_inquiry(conn, unquote(path.split("/")[3]))
        if path.startswith("/api/listings/"):
            parts = path[len("/api/listings/"):].split("/")
            listing_id = unquote(parts[0])
            rest = "/".join(parts[1:])
            if not rest and method == "GET":
                return self.api_listing_detail(conn, listing_id)
            if not rest and method == "PATCH":
                return self.api_update_listing(conn, listing_id)
            if not rest and method == "DELETE":
                return self.api_delete_listing(conn, listing_id)
            if rest in {"favorite", "save"} and method == "POST":
                return self.api_listing_favorite(conn, listing_id, True)
            if rest in {"favorite", "save"} and method == "DELETE":
                return self.api_listing_favorite(conn, listing_id, False)
            if rest == "report" and method == "POST":
                return self.api_listing_report(conn, listing_id)
            if rest == "similar" and method == "GET":
                return self.api_listing_similar(conn, listing_id, query)
            if rest in {"inquiry", "contact", "apply", "application", "book-viewing", "viewing", "book-service", "booking"} and method == "POST":
                return self.api_listing_inquiry(conn, listing_id)
            if rest == "reviews" and method == "GET":
                return self.api_listing_reviews(conn, listing_id, query)
            if rest == "reviews" and method == "POST":
                return self.api_upsert_listing_review(conn, listing_id)
            if rest.startswith("reviews/"):
                review_parts = rest.split("/")
                review_id = unquote(review_parts[1]) if len(review_parts) > 1 else ""
                review_tail = review_parts[2:]
                if review_id and not review_tail and method == "DELETE":
                    return self.api_delete_listing_review(conn, listing_id, review_id)
                if review_id and review_tail == ["reply"] and method == "POST":
                    return self.api_reply_listing_review(conn, listing_id, review_id)
            # reservation calendar (no money)
            if rest == "slots" and method == "GET":
                return self.api_listing_slots(conn, listing_id, query)
            if rest == "slots" and method == "POST":
                return self.api_create_listing_slots(conn, listing_id)
            if rest == "reservations" and method == "GET":
                return self.api_listing_reservations(conn, listing_id, query)
            if rest.startswith("slots/"):
                slot_parts = rest.split("/")
                slot_id = unquote(slot_parts[1]) if len(slot_parts) > 1 else ""
                slot_tail = slot_parts[2:]
                if slot_id and not slot_tail and method == "DELETE":
                    return self.api_delete_listing_slot(conn, listing_id, slot_id)
                if slot_id and slot_tail == ["book"] and method == "POST":
                    return self.api_book_listing_slot(conn, listing_id, slot_id)

        # reservations (customer side)
        if path == "/api/my/reservations" and method == "GET":
            return self.api_my_reservations(conn, query)
        if path.startswith("/api/reservations/"):
            res_parts = path[len("/api/reservations/"):].split("/")
            res_id = unquote(res_parts[0])
            res_tail = res_parts[1:]
            if res_id and res_tail == ["cancel"] and method == "POST":
                return self.api_cancel_reservation(conn, res_id)

        # search
        if path == "/api/search" and method == "GET":
            return self.api_search(conn, query)
        if path == "/api/search/history" and method == "GET":
            return self.api_search_history(conn)
        if path == "/api/search/history" and method == "DELETE":
            return self.api_clear_search_history(conn)
        if path == "/api/trending" and method == "GET":
            return self.api_trending(conn)
        if path == "/api/trending/weekly-likes" and method == "GET":
            return self.api_trending_weekly_likes(conn, query)
        if path == "/api/explore/happening" and method == "GET":
            return self.api_explore_posts(conn, query, "happening")
        if path == "/api/explore/hot" and method == "GET":
            return self.api_explore_posts(conn, query, "hot")
        if path == "/api/explore/topics" and method == "GET":
            return self.api_explore_topics(conn, query)
        if path in {"/api/discover/hot", "/api/explore/hot-board"} and method == "GET":
            return self.api_discover_hot(conn, query)
        # Lightweight product funnel (B6 #6): guest or logged-in.
        if path == "/api/funnel" and method == "POST":
            return self.api_funnel(conn)
        if path == "/api/topics" and method == "GET":
            return self.api_topics(conn)
        # Topic-follow (B6 #7) must be matched before the generic topic GET below.
        if path.startswith("/api/topics/") and path.endswith("/follow") and method in ("POST", "DELETE"):
            tag = path[len("/api/topics/"):-len("/follow")]
            return self.api_topic_follow(conn, tag, method == "POST")
        if path.startswith("/api/topics/") and method == "GET":
            tag = unquote(path[len("/api/topics/"):])
            return self.api_topic(conn, tag, query)
        if path.startswith("/api/profile/") and method == "GET":
            username = unquote(path[len("/api/profile/"):]).strip().lstrip("@")
            return self.api_profile_by_username(conn, username)

        # notifications
        if path == "/api/notifications" and method == "GET":
            return self.api_notifications(conn, query)
        if path == "/api/notifications/read" and method == "POST":
            return self.api_mark_notifications(conn)
        if path.startswith("/api/notifications/") and method == "DELETE":
            return self.api_delete_notification(conn, path.split("/")[3])

        # saved-search alerts (N4)
        if path == "/api/saved_searches" and method == "GET":
            return self.api_saved_searches(conn)
        if path == "/api/saved_searches" and method == "POST":
            return self.api_create_saved_search(conn)
        if path.startswith("/api/saved_searches/") and method == "DELETE":
            return self.api_delete_saved_search(conn, unquote(path[len("/api/saved_searches/"):]))

