    # ---- membership + payments ----

    def _membership_benefits_payload(self, conn: sqlite3.Connection, plan_key: str | None = None) -> list[dict[str, Any]]:
        plan = get_plan(conn, plan_key or MEMBERSHIP_PLAN_KEY)
        if not plan:
            plans = active_membership_plans(conn)
            plan = plans[0] if plans else None
        return _plan_benefits(plan)

    def api_membership_plan(self, conn: sqlite3.Connection) -> None:
        """Public plan info (price + names) for the membership page. No
        auth required so the upsell can render for logged-out visitors."""
        # Global, identical for every visitor and changes only when an admin
        # edits a plan — cache briefly so the membership page (web + iOS both
        # hit this on load) doesn't re-query per request under load.
        cached = _cache_get("membership_plan")
        if cached is not None:
            return self.send_json(cached)
        plans = [serialize_plan(p) for p in active_membership_plans(conn)]
        default = next((p for p in plans if p.get("isDefault")), plans[0] if plans else None)
        payload = {
            "plan": default,
            "plans": plans,
            "items": plans,
            "requires_membership_content_types": sorted(REQUIRES_VERIFIED_MEMBERSHIP),
            "apple_product_id": (default or {}).get("appleProductId") or (default or {}).get("iosIapProductId") or APPLE_IAP_PRODUCT_ID,
            "available_providers": available_payment_providers(),
        }
        _cache_put("membership_plan", payload, 60)
        self.send_json(payload)

    def api_membership_benefits(self, conn: sqlite3.Connection) -> None:
        plan = get_plan(conn, MEMBERSHIP_PLAN_KEY)
        self.send_json({
            "benefits": self._membership_benefits_payload(conn),
            "plan": serialize_plan(plan) if plan else None,
            "disclaimer": "认证会员表示该账号已开通 Machi 认证权益，不代表 Machi 对其发布内容作出担保。",
            "requires_membership_content_types": sorted(REQUIRES_VERIFIED_MEMBERSHIP),
        })

    def api_membership_exclusive(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        status = get_user_membership_status(conn, user["id"])
        if not status["is_active"]:
            raise APIError("访问会员专属内容需要开通 Machi 认证会员。", 403, "MEMBERSHIP_REQUIRED")
        # The member shelf is the Guide member library (original editorial
        # material with lasting value) — the retired news pipeline used to
        # fill this slot. Clients only rely on id/title/summary.
        country = (str(user.get("country") or "jp").strip().lower() or "jp")
        rows = conn.execute(
            """
            SELECT * FROM guide_products
             WHERE country = ? AND status IN ('published','coming_soon')
               AND is_member_included = 1 AND is_service = 0
             ORDER BY is_coming_soon ASC, is_featured DESC, sort_order, updated_at DESC
             LIMIT 12
            """,
            (country,),
        ).fetchall()
        items = []
        for r in rows:
            payload = localize_guide_product_payload(serialize_guide_product(r), "zh-CN")
            payload["summary"] = payload.get("subtitle") or payload.get("summary") or ""
            items.append(payload)
        self.send_json({
            "membership": status,
            "items": items,
            "guides": [
                {"key": "housing", "title": "租房避坑合集", "description": "看房、初期费用、合同和搬家前后需要确认的事项。"},
                {"key": "work", "title": "工作招聘发布入口", "description": "会员可发布招聘、打工、引荐等高信任内容。"},
                {"key": "city", "title": "东京 / 大阪生活指南", "description": "编辑部整理的通勤、区役所、在留、交通和生活提醒。"},
            ],
        })

    def api_membership_orders(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        user = self.require_user(conn)
        limit = max(1, min(int(query.get("limit") or 30), 100))
        # Hide auto-closed abandoned orders — the user asked that unpaid orders
        # not linger. Pending (still completable), paid, and refunded stay.
        rows = conn.execute(
            "SELECT * FROM payment_orders WHERE user_id = ? AND status <> 'closed' ORDER BY created_at DESC LIMIT ?",
            (user["id"], limit),
        ).fetchall()
        self.send_json({"items": [serialize_order(dict(r)) for r in rows]})

    def api_membership_insights(self, conn: sqlite3.Connection) -> None:
        """Member-only basic analytics over the caller's own posts:
        totals (views / likes / bookmarks / reposts / comments) plus their
        top posts by heat. Gated to active verified members."""
        user = self.require_user(conn)
        if not has_active_membership(conn, user["id"]):
            raise APIError("查看内容数据需要开通 Machi 认证会员。", 403, "MEMBERSHIP_REQUIRED")
        uid = user["id"]
        agg = conn.execute(
            "SELECT COUNT(*) AS cnt, COALESCE(SUM(view_count), 0) AS views "
            "FROM posts WHERE author_id = ? AND deleted_at IS NULL",
            (uid,),
        ).fetchone()

        def _icount(kind: str) -> int:
            return int(conn.execute(
                "SELECT COUNT(*) AS c FROM interactions WHERE kind = ? AND target_id IN "
                "(SELECT id FROM posts WHERE author_id = ? AND deleted_at IS NULL)",
                (kind, uid),
            ).fetchone()["c"])

        total_comments = int(conn.execute(
            "SELECT COUNT(*) AS c FROM comments WHERE deleted_at IS NULL AND post_id IN "
            "(SELECT id FROM posts WHERE author_id = ? AND deleted_at IS NULL)",
            (uid,),
        ).fetchone()["c"])
        top_rows = list(conn.execute(
            f"SELECT p.* FROM posts p WHERE p.author_id = ? AND p.deleted_at IS NULL "
            f"ORDER BY {_heat_score_sql('p')} DESC, p.created_at DESC LIMIT 5",
            (uid,),
        ))
        top_posts = fetch_posts_with_extras(conn, [dict(r) for r in top_rows], uid)
        top = [{
            "id": p["id"],
            "content": (p.get("content") or "")[:80],
            "content_type": p.get("content_type"),
            "view_count": p.get("view_count", 0),
            "like_count": p.get("like_count", 0),
            "comment_count": p.get("comment_count", 0),
            "bookmark_count": p.get("bookmark_count", 0),
        } for p in top_posts]
        self.send_json({
            "totals": {
                "post_count": int(agg["cnt"]),
                "total_views": int(agg["views"]),
                "total_likes": _icount("like"),
                "total_bookmarks": _icount("bookmark"),
                "total_reposts": _icount("repost"),
                "total_comments": total_comments,
            },
            "top_posts": top,
        })

    def api_membership_me(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        status = get_user_membership_status(conn, user["id"])
        plan = get_plan(conn, status["plan_key"] or MEMBERSHIP_PLAN_KEY)
        fresh = dict(conn.execute("SELECT * FROM users WHERE id = ?", (user["id"],)).fetchone())
        self.send_json({
            "membership": status,
            "plan": serialize_plan(plan) if plan else None,
            "user": serialize_user_with_counts(conn, fresh),
        })

    def api_membership_listing_quota(self, conn: sqlite3.Connection) -> None:
        """Per-group monthly high-trust publishing quota for the current user, so
        the client can show "used / limit / remaining" before the paywall. The
        three quota GROUPS (租房 / 招聘 / 本地商家·服务) collapse their member types
        (e.g. job+hiring, local_service+discount) into one shared counter — same
        source of truth as require_membership_listing_publish (membership_listing
        _monthly_usage). Auth required."""
        user = self.require_user(conn)
        # One representative type per distinct quota group (dedupe the group sets).
        seen: set[frozenset[str]] = set()
        groups: list[dict[str, Any]] = []
        for rep in ("rental", "job", "local_service"):
            types = frozenset(listing_membership_quota_types(rep))
            if types in seen:
                continue
            seen.add(types)
            usage = membership_listing_monthly_usage(conn, user["id"], rep)
            limit = int(usage.get("limit") or 0)
            used = int(usage.get("used") or 0)
            remaining = usage.get("remaining")
            groups.append({
                "key": rep,
                "label": LISTING_MEMBERSHIP_GROUP_LABELS.get(rep, rep),
                "used": used,
                "limit": limit,
                # remaining is None when limit is unlimited (limit <= 0).
                "remaining": remaining if remaining is not None else None,
            })
        self.send_json({"groups": groups})

    def api_create_payment_order(self, conn: sqlite3.Connection) -> None:
        """Create a Web payment order. The amount is ALWAYS taken from the
        plan — a client-supplied amount is ignored. iOS does NOT use this
        path (it buys through Apple IAP and calls /apple/verify)."""
        user = self.require_user(conn)
        data = self.read_json()
        plan_key = (data.get("planKey") or data.get("plan_key") or MEMBERSHIP_PLAN_KEY).strip()
        provider = (data.get("provider") or "").strip()
        client_type = (data.get("clientType") or data.get("client_type") or "web").strip()
        if provider not in ("wechat_pay", "alipay", "stripe"):
            raise APIError("不支持的支付方式", 400, "invalid_provider")
        if not get_plan(conn, plan_key):
            raise APIError("会员计划不存在", 404, "plan_not_found")
        order = create_payment_order(conn, user["id"], plan_key, provider, client_type)
        out: dict[str, Any] = {
            "orderNo": order["order_no"],
            "provider": provider,
            "amount": round(int(order["amount_cents"]) / 100, 2),
            "currency": order["currency"],
            "expiresAt": order["expires_at"],
        }
        if provider == "wechat_pay":
            out.update(build_wechat_payment(conn, order))
        elif provider == "stripe":
            out.update(build_stripe_payment(conn, order))
        else:
            out.update(build_alipay_payment(conn, order))
        self.send_json(out)

    def api_membership_create_checkout(self, conn: sqlite3.Connection) -> None:
        """Stripe-only Web membership one-time purchase checkout.
        Request: {plan_key}. Response: {checkout_url}. iOS must not use this
        endpoint for membership; it verifies Apple IAP via /apple/verify."""
        user = self.require_user(conn)
        data = self.read_json()
        plan_key = (data.get("planKey") or data.get("plan_key") or MEMBERSHIP_PLAN_KEY).strip()
        if not get_plan(conn, plan_key):
            raise APIError("会员计划不存在", 404, "plan_not_found")
        order = create_payment_order(conn, user["id"], plan_key, "stripe", "web")
        payment = build_stripe_payment(conn, order)
        self.send_json({
            "checkout_url": payment.get("pay_url", ""),
            "checkoutUrl": payment.get("pay_url", ""),
            "order_no": order["order_no"],
            "orderNo": order["order_no"],
            "plan_key": plan_key,
            "planKey": plan_key,
            "amount": round(int(order["amount_cents"]) / 100, 2),
            "currency": order["currency"],
            **({"mock": True} if payment.get("mock") else {}),
        })

    def api_order_status(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        user = self.require_user(conn)
        order_no = (query.get("orderNo") or query.get("order_no") or "").strip()
        if not order_no:
            raise APIError("缺少订单号", 400, "missing_order_no")
        row = conn.execute("SELECT * FROM payment_orders WHERE order_no = ?", (order_no,)).fetchone()
        if not row:
            raise APIError("订单不存在", 404, "order_not_found")
        order = dict(row)
        # Users may only read their own orders (admins can read any).
        if order["user_id"] != user["id"] and (user.get("role") or "member") != "admin":
            raise APIError("无权查看该订单", 403, "forbidden")
        # Lazily close a still-pending order that has passed its TTL.
        if order["status"] == "pending" and _order_is_expired(order):
            conn.execute(
                "UPDATE payment_orders SET status = 'closed', closed_at = ?, updated_at = ? WHERE order_no = ? AND status = 'pending'",
                (now_iso(), now_iso(), order_no),
            )
            order = dict(conn.execute("SELECT * FROM payment_orders WHERE order_no = ?", (order_no,)).fetchone())
        status = get_user_membership_status(conn, order["user_id"])
        self.send_json({
            "orderNo": order_no,
            "status": order["status"],
            "membershipActive": status["is_active"],
            "currentPeriodEnd": status["current_period_end"],
        })

    def api_stripe_confirm(self, conn: sqlite3.Connection) -> None:
        """Confirm a Stripe payment when the user returns to the success
        page. The server retrieves the Checkout Session from Stripe (with
        the secret key) and settles the order if it's paid — so Stripe
        works with ONLY the secret key, no webhook required. Idempotent
        and amount-checked, same as the webhook path."""
        user = self.require_user(conn)
        data = self.read_json()
        session_id = (data.get("sessionId") or data.get("session_id") or "").strip()
        if not session_id:
            raise APIError("缺少会话ID", 400, "missing_session")
        session = stripe_retrieve_session(session_id)
        if not session:
            raise APIError("Stripe 会话核验失败", 502, "verification_failed")
        order_no = str(session.get("client_reference_id") or (session.get("metadata") or {}).get("order_no") or "")
        if not order_no:
            raise APIError("会话未关联订单", 400, "order_not_found")
        order = conn.execute("SELECT * FROM payment_orders WHERE order_no = ?", (order_no,)).fetchone()
        if not order or (dict(order)["user_id"] != user["id"] and (user.get("role") or "member") != "admin"):
            raise APIError("无权确认该订单", 403, "forbidden")
        if str(session.get("payment_status") or "") == "paid":
            try:
                mark_order_paid(conn, order_no, provider_trade_no=str(session.get("payment_intent") or ""),
                                expected_provider="stripe", paid_amount_cents=int(session.get("amount_total") or 0),
                                provider_subscription_id=str(session.get("subscription") or ""))
            except APIError as exc:
                ACCESS_LOG.warning("stripe confirm settle rejected order=%s code=%s", order_no, exc.code)
        status = get_user_membership_status(conn, user["id"])
        self.send_json({
            "orderNo": order_no,
            "status": "paid" if session.get("payment_status") == "paid" else "pending",
            "membershipActive": status["is_active"],
            "currentPeriodEnd": status["current_period_end"],
        })

    def api_stripe_reconcile(self, conn: sqlite3.Connection) -> None:
        """Recover any of the caller's paid-but-pending Stripe orders by
        matching recent Stripe Checkout Sessions to their pending orders.
        Safe + idempotent: only settles THIS user's pending stripe orders
        whose session is actually paid, and only by the exact amount. A
        no-op when there's nothing pending or Stripe isn't configured."""
        user = self.require_user(conn)
        pending = {
            r["order_no"]: int(r["amount_cents"])
            for r in conn.execute(
                "SELECT order_no, amount_cents FROM payment_orders "
                "WHERE user_id = ? AND payment_provider = 'stripe' AND status = 'pending'",
                (user["id"],),
            )
        }
        if pending and STRIPE_SECRET_KEY:
            for sess in stripe_list_recent_sessions():
                ref = str(sess.get("client_reference_id") or "")
                if ref in pending and str(sess.get("payment_status") or "") == "paid":
                    try:
                        mark_order_paid(conn, ref, provider_trade_no=str(sess.get("payment_intent") or ""),
                                        expected_provider="stripe", paid_amount_cents=int(sess.get("amount_total") or 0),
                                        provider_subscription_id=str(sess.get("subscription") or ""))
                    except APIError as exc:
                        ACCESS_LOG.warning("stripe reconcile settle rejected order=%s code=%s", ref, exc.code)
        status = get_user_membership_status(conn, user["id"])
        self.send_json({
            "membershipActive": status["is_active"],
            "currentPeriodEnd": status["current_period_end"],
            "status": status["status"],
        })

    def api_payment_webhook_wechat(self, conn: sqlite3.Connection) -> None:
        """WeChat Pay v3 settlement callback. Verifies + decrypts, checks
        the amount, settles idempotently. Never leaks internal errors."""
        raw = self.read_bytes()
        headers = {k.lower(): v for k, v in self.headers.items()}
        resource = verify_wechat_webhook(headers, raw)
        if resource is None:
            return self._webhook_fail("wechat", "signature/verify failed")
        out_trade_no = str(resource.get("out_trade_no") or "")
        trade_state = str(resource.get("trade_state") or "")
        transaction_id = str(resource.get("transaction_id") or "")
        amount_total = int((resource.get("amount") or {}).get("total") or 0)
        event_id = transaction_id or out_trade_no
        raw_resource = json.dumps(resource, ensure_ascii=False)
        if trade_state == "SUCCESS" and out_trade_no:
            process_payment_webhook(
                conn, "wechat_pay", trade_state, event_id, out_trade_no, raw_resource,
                lambda c: mark_order_paid(c, out_trade_no, provider_trade_no=transaction_id,
                                          expected_provider="wechat_pay", paid_amount_cents=amount_total),
            )
        else:
            record_payment_webhook(conn, "wechat_pay", trade_state, event_id, out_trade_no, raw_resource, True)
        self.send_json({"code": "SUCCESS", "message": "OK"})

    def api_payment_webhook_alipay(self, conn: sqlite3.Connection) -> None:
        """Alipay async notify (application/x-www-form-urlencoded)."""
        raw = self.read_bytes().decode("utf-8", "replace")
        form = {k: v[0] if v else "" for k, v in parse_qs(raw).items()}
        ok = verify_alipay_webhook(form)
        out_trade_no = str(form.get("out_trade_no") or "")
        trade_status = str(form.get("trade_status") or "")
        trade_no = str(form.get("trade_no") or "")
        # Alipay sends total_amount in yuan; convert to fen for the check.
        try:
            amount_cents = int(round(float(form.get("total_amount") or 0) * 100))
        except ValueError:
            amount_cents = 0
        body = b"failure"
        if ok:
            event_id = trade_no or out_trade_no
            if trade_status in ("TRADE_SUCCESS", "TRADE_FINISHED") and out_trade_no:
                process_payment_webhook(
                    conn, "alipay", trade_status, event_id, out_trade_no, raw[:8000],
                    lambda c: mark_order_paid(c, out_trade_no, provider_trade_no=trade_no,
                                              expected_provider="alipay", paid_amount_cents=amount_cents),
                )
            else:
                record_payment_webhook(conn, "alipay", trade_status, event_id, out_trade_no, raw[:8000], True)
            body = b"success"
        else:
            record_payment_webhook(conn, "alipay", trade_status, trade_no or out_trade_no, out_trade_no, raw[:8000], False)
        self.send_response(200)
        self.send_header("Content-Type", "text/plain; charset=utf-8")
        self.send_header("Content-Length", str(len(body)))
        self.end_headers()
        self.wfile.write(body)

    def api_payment_webhook_stripe(self, conn: sqlite3.Connection) -> None:
        """Stripe webhook. Verifies the Stripe-Signature (HMAC-SHA256),
        settles the order on checkout.session.completed, idempotent on the
        Stripe event id. Membership opens here, never on the redirect."""
        raw = self.read_bytes()
        headers = {k.lower(): v for k, v in self.headers.items()}
        event = verify_stripe_webhook(headers, raw)
        if event is None:
            return self._webhook_fail("stripe", "signature/verify failed")
        event_id = str(event.get("id") or "")
        event_type = str(event.get("type") or "")
        obj = (event.get("data") or {}).get("object") or {}
        if event_type == "checkout.session.completed":
            order_no = str(obj.get("client_reference_id") or (obj.get("metadata") or {}).get("order_no") or "")
            amount_total = int(obj.get("amount_total") or 0)
            payment_intent = str(obj.get("payment_intent") or "")
            subscription_id = str(obj.get("subscription") or "")
            kind = str((obj.get("metadata") or {}).get("kind") or "")
            raw_event = json.dumps(event, ensure_ascii=False)
            if order_no and str(obj.get("payment_status") or "") == "paid":
                def _settle_stripe(c: sqlite3.Connection) -> None:
                    if kind == "wallet_topup" or order_no.startswith("WT"):
                        # Machi Points top-up — credit points exactly once.
                        wallet_credit_topup(c, order_no, provider_trade_no=payment_intent, source_type="stripe")
                    elif order_no.startswith("GP"):
                        # Machi Guide product order (digital resource / paid service).
                        settle_guide_order(c, order_no, payment_intent, amount_total)
                    else:
                        mark_order_paid(c, order_no, provider_trade_no=payment_intent,
                                        expected_provider="stripe", paid_amount_cents=amount_total,
                                        provider_subscription_id=subscription_id)
                # Dedup-record + settle commit as one unit (process_payment_webhook).
                process_payment_webhook(conn, "stripe", event_type, event_id, order_no, raw_event, _settle_stripe)
            else:
                # Not an actionable paid checkout — just mark the event seen.
                record_payment_webhook(conn, "stripe", event_type, event_id, order_no, raw_event, True)
        # NOTE: the customer.subscription.{created,updated,deleted} branch was
        # removed — Machi membership is a NON-RENEWING one-time purchase (see the
        # MEMBERSHIP_* config), so Stripe never creates a subscription object and
        # these events can never fire. The dead branch also wrote a 'cancelled'
        # status that no read path expected. Refunds/chargebacks are handled by
        # the charge.refunded / charge.dispute.* branch below.
        elif event_type in {"invoice.paid", "invoice.payment_failed"}:
            sub_id = str(obj.get("subscription") or "")
            first = record_payment_webhook(conn, "stripe", event_type, event_id, sub_id,
                                           json.dumps(event, ensure_ascii=False), True)
            if first and sub_id and event_type == "invoice.payment_failed":
                membership = conn.execute(
                    "SELECT * FROM user_memberships WHERE provider_subscription_id = ? ORDER BY updated_at DESC LIMIT 1",
                    (sub_id,),
                ).fetchone()
                if membership:
                    conn.execute("UPDATE user_memberships SET status = 'past_due', updated_at = ? WHERE id = ?",
                                 (now_iso(), membership["id"]))
                    sync_user_membership_cache(conn, membership["user_id"])
        elif event_type in {"charge.refunded", "charge.dispute.created", "charge.dispute.funds_withdrawn"}:
            # Refund/chargeback. The charge (or dispute) carries the payment
            # intent we recorded as the WT order's provider_trade_no. Claw back
            # the granted points (never forcing the balance negative).
            payment_intent = str(obj.get("payment_intent") or "")
            first = record_payment_webhook(conn, "stripe", event_type, event_id, payment_intent,
                                           json.dumps(event, ensure_ascii=False), True)
            if first and payment_intent:
                # MS-6: resolve the refunded/disputed charge across ALL three
                # rails (wallet top-up, membership, guide product) — previously
                # only wallet top-ups were clawed back, so a refunded membership
                # or guide purchase silently kept its benefits.
                wt = conn.execute(
                    "SELECT order_no FROM wallet_topup_orders WHERE payment_provider = 'stripe' AND provider_trade_no = ? LIMIT 1",
                    (payment_intent,)).fetchone()
                po = conn.execute(
                    "SELECT order_no FROM payment_orders WHERE payment_provider = 'stripe' AND provider_trade_no = ? LIMIT 1",
                    (payment_intent,)).fetchone()
                gp = conn.execute(
                    "SELECT order_no FROM guide_orders WHERE payment_provider = 'stripe' AND provider_trade_no = ? LIMIT 1",
                    (payment_intent,)).fetchone()
                if wt:
                    entry = "chargeback_debit" if event_type != "charge.refunded" else "refund_debit"
                    wallet_refund_topup(conn, wt["order_no"], reason=event_type, entry_type=entry)
                if po:
                    refund_order(conn, po["order_no"])          # mark refunded + revoke membership
                if gp:
                    refund_guide_points_order(conn, gp["order_no"], reason=event_type)  # revoke entitlement
        else:
            # Record-but-ignore other event types (still 2xx so Stripe stops retrying).
            record_payment_webhook(conn, "stripe", event_type, event_id, "", "", True)
        self.send_json({"received": True})

    def _apple_notification_user_id(self, conn: sqlite3.Connection, transaction: dict[str, Any]) -> str:
        """Resolve the Machi user for an App Store Server Notification.

        New purchases include StoreKit's appAccountToken (we pass the Machi
        user UUID from iOS). Older purchases may not, so fall back to the
        original transaction id recorded during the client-side verify call.
        """
        app_account_token = str(transaction.get("appAccountToken") or "").strip()
        if app_account_token:
            row = conn.execute(
                "SELECT id FROM users WHERE lower(id) = lower(?) LIMIT 1",
                (app_account_token,),
            ).fetchone()
            if row:
                return row["id"]
        original_id = str(transaction.get("originalTransactionId") or "").strip()
        if original_id:
            membership = conn.execute(
                "SELECT user_id FROM user_memberships WHERE provider_subscription_id = ? "
                "ORDER BY updated_at DESC LIMIT 1",
                (original_id,),
            ).fetchone()
            if membership:
                return membership["user_id"]
            order = conn.execute(
                "SELECT user_id FROM payment_orders WHERE payment_provider = 'apple_iap' AND provider_user_id = ? "
                "ORDER BY paid_at DESC, created_at DESC LIMIT 1",
                (original_id,),
            ).fetchone()
            if order:
                return order["user_id"]
        return ""

    def api_payment_webhook_apple(self, conn: sqlite3.Connection) -> None:
        """App Store Server Notifications v2 callback.

        Configure App Store Connect production URL as:
          https://machicity.com/api/payments/webhook/apple

        The endpoint records every notification, verifies Apple's JWS in
        production, and syncs the membership expiry from signedTransactionInfo.
        """
        data = self.read_json()
        signed_payload = (data.get("signedPayload") or data.get("signed_payload") or "").strip()
        if not signed_payload:
            return self._webhook_fail("apple_iap", "missing signedPayload")
        notification, signature_valid = decode_apple_jws_payload(signed_payload, require_signature=PRODUCTION)
        if not notification:
            record_payment_webhook(conn, "apple_iap", "invalid", secrets.token_hex(12), "",
                                   signed_payload[:8000], False)
            return self._webhook_fail("apple_iap", "notification signature/parse failed")

        apple_data = notification.get("data") or {}
        bundle_id = str(apple_data.get("bundleId") or "").strip()
        if APPLE_IAP_BUNDLE_ID and bundle_id and bundle_id != APPLE_IAP_BUNDLE_ID:
            record_payment_webhook(conn, "apple_iap", str(notification.get("notificationType") or "bundle_mismatch"),
                                   str(notification.get("notificationUUID") or secrets.token_hex(12)), "",
                                   json.dumps(notification, ensure_ascii=False)[:8000], signature_valid)
            return self._webhook_fail("apple_iap", "bundle mismatch")
        # Sandbox notifications must never mutate production state: a sandbox
        # REFUND/REVOKE would match a real membership row whose
        # provider_subscription_id is empty and cancel it immediately. Recorded
        # for audit, answered 2xx so Apple stops retrying, processed no further.
        # (Non-production servers still process sandbox notifications — that is
        # what staging/QA test against.)
        apple_env = str(apple_data.get("environment") or "").strip().lower()
        if PRODUCTION and apple_env and apple_env != "production":
            record_payment_webhook(conn, "apple_iap",
                                   str(notification.get("notificationType") or "sandbox_ignored"),
                                   str(notification.get("notificationUUID") or secrets.token_hex(12)), "",
                                   json.dumps(notification, ensure_ascii=False)[:8000], signature_valid)
            return self.send_json({"received": True, "processed": False, "reason": "sandbox_environment"})

        signed_tx = str(apple_data.get("signedTransactionInfo") or "").strip()
        transaction = verify_apple_transaction(signed_tx) if signed_tx else None
        if not transaction:
            record_payment_webhook(conn, "apple_iap", str(notification.get("notificationType") or "missing_transaction"),
                                   str(notification.get("notificationUUID") or secrets.token_hex(12)), "",
                                   json.dumps(notification, ensure_ascii=False)[:8000], signature_valid)
            return self._webhook_fail("apple_iap", "transaction verify failed")

        notification_type = str(notification.get("notificationType") or "").strip() or "UNKNOWN"
        subtype = str(notification.get("subtype") or "").strip()
        event_type = f"{notification_type}:{subtype}" if subtype else notification_type
        event_id = str(notification.get("notificationUUID") or transaction.get("transactionId") or secrets.token_hex(12))
        product_id = str(transaction.get("productId") or "").strip()
        original_id = str(transaction.get("originalTransactionId") or "").strip()
        first = record_payment_webhook(
            conn,
            "apple_iap",
            event_type,
            event_id,
            original_id or str(transaction.get("transactionId") or ""),
            json.dumps({"notification": notification, "transaction": transaction}, ensure_ascii=False),
            signature_valid,
        )
        if not first:
            return self.send_json({"received": True, "duplicate": True})

        user_id = self._apple_notification_user_id(conn, transaction)
        if not user_id:
            # 2xx so Apple does not retry forever; the raw notification is
            # audit-logged above and will become resolvable after the user opens
            # the app and verifies/restores with appAccountToken.
            ACCESS_LOG.warning("apple_iap notification without resolvable user event=%s original=%s", event_type, original_id)
            return self.send_json({"received": True, "processed": False, "reason": "user_not_found"})

        plan = get_plan_by_apple_product(conn, product_id) or get_plan(conn, MEMBERSHIP_PLAN_KEY)
        plan_key = plan["plan_key"] if plan else MEMBERSHIP_PLAN_KEY
        expires_at = apple_payload_expiry_iso(transaction)
        revoked = bool(transaction.get("revocationDate"))
        terminal_types = {"EXPIRED", "GRACE_PERIOD_EXPIRED", "REFUND", "REVOKE"}
        if revoked or notification_type in {"REFUND", "REVOKE"}:
            # MS-6: a refunded Apple CONSUMABLE points top-up must claw the points
            # back (previously only membership was handled).
            tx_id = str(transaction.get("transactionId") or "")
            wt = conn.execute(
                "SELECT order_no FROM wallet_topup_orders WHERE payment_provider = 'apple_iap' "
                "AND provider_trade_no IN (?, ?) AND provider_trade_no <> '' LIMIT 1",
                (tx_id, original_id)).fetchone()
            if wt:
                wallet_refund_topup(conn, wt["order_no"], reason=event_type, entry_type="refund_debit")
                return self.send_json({"received": True, "processed": True, "status": "points_refunded"})
            row = _current_membership_row(conn, user_id)
            if row and ((not original_id) or row.get("provider_subscription_id") in ("", original_id)):
                cancel_membership(conn, user_id, immediate=True, source="ios_iap")
            return self.send_json({"received": True, "processed": True, "status": "revoked"})
        if notification_type in terminal_types and expires_at:
            expiry = _aware(parse_iso(expires_at))
            if expiry and expiry <= datetime.now(timezone.utc):
                sync_apple_membership_expiry(conn, user_id, plan_key, expires_at, original_id, product_id, event_type)
                return self.send_json({"received": True, "processed": True, "status": "expired"})
        if expires_at:
            status = sync_apple_membership_expiry(conn, user_id, plan_key, expires_at, original_id, product_id, event_type)
            return self.send_json({
                "received": True,
                "processed": True,
                "membershipActive": status["is_active"],
                "currentPeriodEnd": status["current_period_end"],
            })
        return self.send_json({"received": True, "processed": True})

    def api_apple_verify(self, conn: sqlite3.Connection) -> None:
        """Verify a StoreKit2 transaction and open/extend membership. The
        iOS client sends the signed transaction; the server is the only
        place a purchase is trusted. Idempotent on the transaction id so a
        restore / re-verify never double-extends."""
        user = self.require_user(conn)
        data = self.read_json()
        signed = (data.get("signedTransaction") or data.get("signed_transaction") or "").strip()
        product_id = (data.get("productId") or data.get("product_id") or APPLE_IAP_PRODUCT_ID).strip()
        # This endpoint grants MEMBERSHIP only. A product_id that doesn't map to a
        # membership plan (e.g. a Machi Points consumable, which shares the same
        # bundleId so the structural JWS check passes) MUST be rejected — the old
        # `or get_plan(MEMBERSHIP_PLAN_KEY)` fallback let a cheap points purchase be
        # replayed here for free membership. Points have their own verify endpoint.
        plan = get_plan_by_apple_product(conn, product_id)
        if not plan:
            raise APIError("该商品不是会员套餐", 400, "product_not_membership")
        plan_key = plan["plan_key"]
        txn_id = str(data.get("transactionId") or data.get("transaction_id") or "")
        orig_id = str(data.get("originalTransactionId") or data.get("original_transaction_id") or "")
        if not signed:
            raise APIError("缺少交易凭证", 400, "invalid_transaction")
        payload = verify_apple_transaction(signed, product_id)
        if not payload:
            raise APIError("交易验证失败", 400, "verification_failed")
        txn_id = txn_id or str(payload.get("transactionId") or "")
        orig_id = orig_id or str(payload.get("originalTransactionId") or "")
        app_account_token = str(payload.get("appAccountToken") or "").strip()
        if app_account_token and app_account_token.lower() != user["id"].lower():
            raise APIError("交易账号与当前账号不匹配", 403, "apple_account_token_mismatch")
        previous_status = get_user_membership_status(conn, user["id"])
        previous_until = previous_status.get("current_period_end") or ""
        # Sandbox / TestFlight / Xcode transactions still open membership (so
        # testers can exercise member features), but they are NOT money: no
        # "payment succeeded" email — merely opening the paywall in TestFlight
        # re-delivers old sandbox (auto-renew) transactions via
        # Transaction.updates and used to mail a purchase receipt per renewal —
        # and the order is tagged ios_sandbox so finance can filter it out.
        # The environment field is read from the (production: Apple-signed)
        # payload and is never used to GRANT anything, only to mute noise.
        txn_environment = str(payload.get("environment") or data.get("environment") or "").strip().lower()
        is_sandbox_txn = txn_environment in ("sandbox", "xcode")
        dedup_key = "apple:" + (txn_id or orig_id or signed[:40])
        existing = conn.execute(
            "SELECT status FROM payment_orders WHERE provider_trade_no = ? AND payment_provider = 'apple_iap'",
            (dedup_key,),
        ).fetchone()
        if not (existing and existing["status"] == "paid"):
            order = create_payment_order(conn, user["id"], plan_key, "apple_iap",
                                         "ios_sandbox" if is_sandbox_txn else "ios")
            mark_order_paid(conn, order["order_no"], provider_trade_no=dedup_key,
                            provider_user_id=orig_id, expected_provider="apple_iap",
                            provider_subscription_id=orig_id, provider_price_id=product_id,
                            notify_email=not is_sandbox_txn)
        expires_at = apple_payload_expiry_iso(payload)
        # Sandbox / Xcode transactions may carry a far-future (or auto-renew
        # accelerated) expiry; cap the membership they grant at 7 days so a
        # tester can never mint a long-lived membership from a non-money txn.
        # Production transactions are untouched. Cap only shortens, never extends.
        if is_sandbox_txn and expires_at:
            sandbox_ceiling = (datetime.now(timezone.utc) + timedelta(days=7)).isoformat()
            if expires_at > sandbox_ceiling:
                expires_at = sandbox_ceiling
        if expires_at:
            sync_apple_membership_expiry(conn, user["id"], plan_key, expires_at, orig_id, product_id,
                                         "apple_client_verify", minimum_until_iso=previous_until)
        status = get_user_membership_status(conn, user["id"])
        self.send_json({
            "membershipActive": status["is_active"],
            "currentPeriodEnd": status["current_period_end"],
            "status": status["status"],
            "membership_status": status["status"],
            "plan_key": status["plan_key"] or plan_key,
            "planKey": status["plan_key"] or plan_key,
            "expires_at": status["current_period_end"],
            "expiresAt": status["current_period_end"],
        })

    # ---- Machi Points wallet ----

    def _wallet_topup_availability(self, pack: dict[str, Any], platform: str, store: str) -> tuple[bool, str]:
        """Per-client purchasability of a top-up pack. iOS/Android can only buy
        what has the matching store product id; Web buys via Stripe. Returns
        (purchasable, disabled_reason)."""
        platform = (platform or "web").lower()
        store = (store or "").lower()
        if platform == "ios":
            ok = bool(pack.get("apple_product_id") or pack.get("ios_iap_product_id"))
            return (ok, "" if ok else "ios_product_unconfigured")
        if platform == "android":
            if store in ("global", "google", "googleplay", "play", ""):
                ok = bool(pack.get("google_product_id"))
                return (ok, "" if ok else "google_product_unconfigured")
            if store in ("huawei",):
                ok = bool(pack.get("huawei_product_id"))
                return (ok, "" if ok else "channel_not_available")
            # china / xiaomi / oppo / vivo … — no in-app billing wired yet.
            return (False, "channel_not_available")
        # web
        ok = stripe_configured()
        return (ok, "" if ok else "stripe_unconfigured")

    def _wallet_topup_products_payload(self, conn: sqlite3.Connection, platform: str, store: str) -> list[dict[str, Any]]:
        out: list[dict[str, Any]] = []
        for pack in list_topup_products(conn):
            serialized = serialize_wallet_topup_product(pack)
            purchasable, reason = self._wallet_topup_availability(pack, platform, store)
            serialized["purchasable"] = purchasable
            serialized["disabledReason"] = reason
            out.append(serialized)
        return out

    def api_wallet_me(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        """Wallet overview: balance + buyable top-up packs + recent ledger.
        Auto-creates a zero-balance account on first read."""
        user = self.require_user(conn)
        platform = (query.get("platform") or "web").strip().lower()
        store = (query.get("store") or "").strip().lower()
        wallet = get_wallet_snapshot(conn, user["id"])
        recent = conn.execute(
            "SELECT * FROM wallet_ledger_entries WHERE user_id = ? ORDER BY created_at DESC, id DESC LIMIT 10",
            (user["id"],),
        ).fetchall()
        self.send_json({
            "wallet": wallet,
            "topupProducts": self._wallet_topup_products_payload(conn, platform, store),
            "recentEntries": [serialize_wallet_ledger_entry(r) for r in recent],
            "pointsName": WALLET_POINTS_NAME,
            "disclaimer": WALLET_DISCLAIMER,
        })

    def api_wallet_ledger(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        user = self.require_user(conn)
        page = max(1, int(query.get("page") or 1))
        page_size = max(1, min(int(query.get("pageSize") or query.get("page_size") or 20), 100))
        offset = (page - 1) * page_size
        rows = conn.execute(
            "SELECT * FROM wallet_ledger_entries WHERE user_id = ? ORDER BY created_at DESC, id DESC LIMIT ? OFFSET ?",
            (user["id"], page_size + 1, offset),
        ).fetchall()
        has_more = len(rows) > page_size
        rows = rows[:page_size]
        self.send_json({
            "wallet": get_wallet_snapshot(conn, user["id"]),
            "entries": [serialize_wallet_ledger_entry(r) for r in rows],
            "page": page, "pageSize": page_size, "hasMore": has_more,
        })

    # ── 邀请裂变 (referral) ──────────────────────────────────────────────────

    def api_referral_me(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        """战绩页 data: this user's stable invite code + share URL + counts +
        recent invitees. Lazily mints the code on first read."""
        user = self.require_user(conn)
        summary = referral.referral_summary(
            conn, user["id"], share_base=REFERRAL_SHARE_BASE, now=now_iso()
        )
        self.send_json({"referral": summary})

    def api_referral_bind(self, conn: sqlite3.Connection) -> None:
        """Late-bind an invite for an already-registered user who clicked a link
        after signing up. Still capped by UNIQUE(invitee_id) — if they were ever
        bound (even to a different inviter) this is a no-op. No payout here."""
        user = self.require_user(conn)
        data = self.read_json()
        code = (data.get("referral_code") or data.get("code") or data.get("ref") or "").strip()
        if not code:
            raise APIError("缺少邀请码", 400, "missing_code")
        outcome = referral.bind_referral(conn, code, user["id"], self._client_ip(), now=now_iso())
        self.send_json({"bound": bool(outcome.get("bound")), "reason": outcome.get("reason") or ""})

    def api_admin_referrals(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        """Admin: the human-review queue of rejected referrals."""
        self.require_admin(conn)
        limit = max(1, min(int(query.get("limit") or 100), 500))
        offset = max(0, int(query.get("offset") or 0))
        items = referral.list_review_queue(conn, limit=limit, offset=offset)
        self.send_json({"referrals": items, "limit": limit, "offset": offset})

    def api_admin_referral_review(self, conn: sqlite3.Connection, referral_id: str) -> None:
        """Admin: approve (pay both sides) or reject a held referral."""
        self.require_admin(conn)
        data = self.read_json()
        action = (data.get("action") or "").strip().lower()
        if action not in ("approve", "reject"):
            raise APIError("action 必须是 approve 或 reject", 400, "bad_action")
        outcome = admin_review_referral_atomic(conn, referral_id, action)
        if not outcome.get("ok"):
            raise APIError("邀请记录不存在或无法处理", 404, outcome.get("reason") or "review_failed")
        self.send_json(outcome)

