    # ---- API implementations ----

    def api_check_username(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        raw = query.get("username") or query.get("handle") or ""
        handle = normalize_handle(raw)
        if not handle:
            self.send_json({"available": False, "message": "请输入用户名", "code": "missing_username"})
            return
        if not HANDLE_RE.match(handle):
            self.send_json({"available": False, "message": "用户名必须是 3-20 位字母、数字、下划线或点", "code": "invalid_handle"})
            return
        if handle in RESERVED_HANDLES:
            self.send_json({"available": False, "message": "这个用户名不可使用", "code": "reserved_handle"})
            return
        exists = conn.execute("SELECT 1 FROM users WHERE handle = ? AND deleted_at IS NULL", (handle,)).fetchone()
        self.send_json({
            "available": exists is None,
            "message": "这个用户名可以使用" if exists is None else "这个用户名已经被使用",
            "code": "available" if exists is None else "handle_taken",
        })

    def api_check_email(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        email = (query.get("email") or "").strip()
        if not email:
            self.send_json({"available": False, "message": "请输入邮箱", "code": "missing_email"})
            return
        if not is_valid_email(email):
            self.send_json({"available": False, "message": "邮箱格式不正确", "code": "invalid_email"})
            return
        exists = conn.execute(
            "SELECT 1 FROM users WHERE lower(email) = ? AND deleted_at IS NULL",
            (email.lower(),),
        ).fetchone()
        self.send_json({
            "available": exists is None,
            "message": "这个邮箱可以使用" if exists is None else "这个邮箱已经注册过",
            "code": "available" if exists is None else "email_taken",
        })

    def api_verify_code(self, conn: sqlite3.Connection) -> None:
        """Non-consuming code check for clients that want to validate an
        email-code before submitting registration/reset. Registration and
        reset still consume the code, so a preflight check cannot burn it."""
        data = self.read_json()
        purpose = (data.get("purpose") or "register").strip()
        email = (data.get("email") or data.get("new_email") or "").strip()
        code = (data.get("code") or "").strip()
        challenge_id = (data.get("challenge_id") or "").strip()
        secure_purposes = {"change_password", "change_email_old", "change_email_new"}
        user = self.require_user(conn) if purpose in secure_purposes else None
        if purpose not in ("register", "reset", *secure_purposes):
            raise APIError("不支持的验证码类型", 400, "invalid_purpose")
        if purpose in ("change_password", "change_email_old"):
            email = (user["email"] or "").strip()
        if not is_valid_email(email):
            raise APIError("请填写有效邮箱", 400, "invalid_email")
        if not code:
            raise APIError("请输入验证码", 400, "invalid_code")
        if challenge_id:
            row = conn.execute(
                "SELECT * FROM auth_codes WHERE id = ? AND purpose = ? AND consumed_at IS NULL",
                (challenge_id, purpose),
            ).fetchone()
        elif user:
            row = conn.execute(
                "SELECT * FROM auth_codes WHERE purpose = ? AND user_id = ? AND consumed_at IS NULL ORDER BY created_at DESC LIMIT 1",
                (purpose, user["id"]),
            ).fetchone()
        else:
            row = conn.execute(
                "SELECT * FROM auth_codes WHERE purpose = ? AND email = ? AND consumed_at IS NULL ORDER BY created_at DESC LIMIT 1",
                (purpose, email.lower()),
            ).fetchone()
        if not row:
            raise APIError("验证码无效或已过期", 400, "invalid_code")
        if user and row["user_id"] != user["id"]:
            raise APIError("验证码无效或已过期", 400, "invalid_code")
        expires = parse_iso(row["expires_at"])
        if expires and expires < datetime.now(timezone.utc):
            raise APIError("验证码已过期", 400, "code_expired")
        if int(row["attempts"] or 0) >= EMAIL_CODE_MAX_ATTEMPTS:
            raise APIError("尝试次数过多，请重新获取验证码", 429, "too_many_attempts")
        actual = hash_auth_code(code, row["email"], purpose)
        if not hmac.compare_digest(row["code_hash"], actual):
            conn.execute("UPDATE auth_codes SET attempts = attempts + 1 WHERE id = ?", (row["id"],))
            raise APIError("验证码不正确", 400, "invalid_code")
        self.send_json({"success": True, "ok": True, "message": "验证码有效"})

    def api_register(self, conn: sqlite3.Connection) -> None:
        data = self.read_json()
        handle = normalize_handle(data.get("handle") or data.get("username") or "")
        display_name = (data.get("display_name") or handle).strip()
        password = data.get("password") or ""
        email = (data.get("email") or "").strip()
        if not HANDLE_RE.match(handle):
            raise APIError("用户名必须是 3-20 位字母、数字、下划线或点", 400, "invalid_handle")
        existing_count = conn.execute("SELECT COUNT(*) AS c FROM users").fetchone()["c"]
        bootstrap_token = (data.get("bootstrap_token") or "").strip()
        bootstrap_allowed = (
            existing_count == 0
            and (not ADMIN_BOOTSTRAP_TOKEN or (bootstrap_token and hmac.compare_digest(bootstrap_token, ADMIN_BOOTSTRAP_TOKEN)))
        )
        if handle in RESERVED_HANDLES and not bootstrap_allowed:
            raise APIError("这个用户名不可使用", 400, "reserved_handle")
        # Single source of truth for password strength (>=8 chars + letters and
        # digits). Enforced on EVERY registration path — the legacy codeless path
        # previously only required >=6, weaker than the policy Web/iOS advertise.
        validate_password_strength(password)
        if len(password) > 256:
            raise APIError("密码过长", 400, "invalid_password")
        if not display_name:
            raise APIError("显示名称不能为空", 400, "invalid_display_name")
        if len(display_name) > 60:
            raise APIError("显示名称过长", 400, "invalid_display_name")
        if email and len(email) > 254:
            raise APIError("邮箱过长", 400, "invalid_email")
        if email and not is_valid_email(email):
            raise APIError("请填写有效邮箱", 400, "invalid_email")
        # Email verification gate. Enforced when KAIX_REQUIRE_EMAIL_VERIFICATION
        # is on, OR opportunistically whenever the client supplied a `code`
        # (so the hardened Web flow works even before the gate is flipped).
        # Older clients that send neither keep the legacy behaviour untouched.
        submitted_code = (data.get("code") or "").strip()
        require_code = REQUIRE_EMAIL_VERIFICATION or bool(submitted_code)
        if require_code:
            if not is_valid_email(email):
                raise APIError("请填写有效邮箱", 400, "invalid_email")
            consume_auth_code(conn, purpose="register", email=email, code=submitted_code)
        else:
            # Codeless (legacy) registration is otherwise a wide-open bot
            # path — gate it with a captcha. The email-code flow is already
            # covered: requesting the code consumed a captcha.
            self._enforce_captcha(conn, data, "register")
        if conn.execute("SELECT 1 FROM users WHERE handle = ?", (handle,)).fetchone():
            raise APIError("用户名已存在", 409, "handle_taken")
        if email and conn.execute("SELECT 1 FROM users WHERE lower(email) = ? AND deleted_at IS NULL", (email.lower(),)).fetchone():
            raise APIError("这个邮箱已经注册过", 409, "email_taken")
        country, province, city, region_code, city_label = _normalize_region_payload(data)
        settings_language = (data.get("language") or "").strip()
        if settings_language not in ("zh-Hans", "en", "ja"):
            settings_language = ""
        # Admin bootstrapping:
        # - If KAIX_ADMIN_BOOTSTRAP_TOKEN is set, the registration request
        #   must carry a matching `bootstrap_token` to be promoted to
        #   admin. This closes the historical TOCTOU window where an
        #   attacker could race the first legitimate registration to
        #   become admin on a fresh install.
        # - If the env var is empty, fall back to the legacy behaviour
        #   so existing dev / single-operator deploys keep working.
        if ADMIN_BOOTSTRAP_TOKEN:
            if bootstrap_token and hmac.compare_digest(bootstrap_token, ADMIN_BOOTSTRAP_TOKEN):
                role = "admin"
            else:
                role = "member"
        elif PRODUCTION:
            # No bootstrap token in production: never auto-promote the first
            # registrant to admin (closes the fresh-DB race). Set
            # KAIX_ADMIN_BOOTSTRAP_TOKEN or grant admin out-of-band.
            role = "member"
        else:
            role = "admin" if existing_count == 0 else "member"
        user_id = str(uuid.uuid4())
        conn.execute(
            """
            INSERT INTO users (id, handle, display_name, email, password_hash, bio, location,
                               avatar_symbol, avatar_color, avatar_url, cover_url, membership_tier,
                               is_verified, role, country, province, city, current_region_code,
                               recent_region_codes, joined_at, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, '', ?, 'person.fill', 'indigo', '', '', 'free', 0, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (user_id, handle, display_name, email, hash_password(password),
             city_label, role, country, province, city, region_code, region_code,
             now_iso(), now_iso(), now_iso()),
        )
        conn.execute("INSERT INTO settings (user_id, language, updated_at) VALUES (?, ?, ?)", (user_id, settings_language, now_iso()))
        reputation_ensure_user(conn, user_id)
        if email:
            reputation_apply_event(conn, user_id, "email_verified", target_kind="user", target_id=user_id, reviewed=True)
        if region_code or settings_language:
            reputation_apply_event(conn, user_id, "city_language_set", target_kind="user", target_id=user_id)
        # 邀请裂变: bind the invite (if any) as a *pending* referral — no payout
        # happens here (registration-time rewards are a bot magnet). A bad/blank/
        # self code is silently ignored so it never blocks sign-up.
        referral_code = (data.get("referral_code") or data.get("ref") or "").strip()
        if referral_code:
            try:
                referral.bind_referral(conn, referral_code, user_id, self._client_ip(), now=now_iso())
            except Exception:
                # Referral binding must never break registration.
                pass
        token = self._create_session(conn, user_id)
        user_row = dict(conn.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone())
        self._set_session_cookie(token)
        self.send_json({"token": token, "user": serialize_user_with_counts(conn, user_row)})

    def _resolve_login_user(self, conn: sqlite3.Connection, raw: str) -> sqlite3.Row | None:
        """Look up a login target by handle OR email. An identifier containing
        '@' that is a valid email is matched on lower(email); otherwise on the
        normalized handle. Returns the row or None — callers must keep error
        messages identical so neither field becomes an existence oracle."""
        raw = (raw or "").strip()
        if "@" in raw and is_valid_email(raw):
            return conn.execute(
                "SELECT * FROM users WHERE lower(email) = ? AND deleted_at IS NULL", (raw.lower(),)
            ).fetchone()
        handle = normalize_handle(raw)
        if not handle:
            return None
        return conn.execute(
            "SELECT * FROM users WHERE handle = ? AND deleted_at IS NULL", (handle,)
        ).fetchone()

    def api_login(self, conn: sqlite3.Connection) -> None:
        # Single-step password login. Kept for existing clients (e.g. the
        # iOS app). When KAIX_LOGIN_REQUIRE_CODE is enabled, this endpoint is
        # closed and callers must use the /api/auth/login/start + /verify
        # two-step (email-code) flow instead.
        if LOGIN_REQUIRE_CODE:
            raise APIError("请使用验证码登录", 403, "login_code_required")
        data = self.read_json()
        raw_identifier = (data.get("handle") or data.get("username") or "").strip()
        # Failure key: normalized handle, or the lowercased email for email logins.
        fail_key = raw_identifier.lower() if "@" in raw_identifier else normalize_handle(raw_identifier)
        # Captcha first: bots must solve an image before they get to probe
        # the password oracle at all. In adaptive mode this only bites
        # after repeated failures from this IP / against this identifier.
        self._enforce_captcha(conn, data, "login", handle=fail_key)
        # Hard lockout on top of the captcha: too many failures for this account
        # or IP in the window => refuse outright (blunts distributed stuffing).
        if login_locked_out(self._client_ip(), fail_key):
            raise APIError("尝试次数过多，请稍后再试", 429, "too_many_attempts")
        password = data.get("password") or ""
        row = self._resolve_login_user(conn, raw_identifier)
        if not row or not verify_password(password, row["password_hash"]):
            record_login_failure(self._client_ip(), fail_key)
            raise APIError("用户名/邮箱或密码不正确", 401, "invalid_credentials")
        clear_login_failures(self._client_ip(), fail_key)
        token = self._create_session(conn, row["id"])
        self._set_session_cookie(token)
        self.send_json({"token": token, "user": serialize_user_with_counts(conn, dict(row))})

    def _request_base_url(self) -> str:
        if PUBLIC_BASE_URL:
            return PUBLIC_BASE_URL
        proto = (self.headers.get("X-Forwarded-Proto") or "").split(",", 1)[0].strip()
        if not proto:
            proto = "https" if PRODUCTION else "http"
        host = (
            self.headers.get("X-Forwarded-Host")
            or self.headers.get("Host")
            or "localhost"
        ).split(",", 1)[0].strip()
        return f"{proto}://{host}"

    def _google_redirect_uri(self) -> str:
        if GOOGLE_OAUTH_REDIRECT_URI:
            return GOOGLE_OAUTH_REDIRECT_URI
        return f"{self._request_base_url()}/api/auth/google/callback"

    @staticmethod
    def _safe_web_redirect(raw: str | None, default: str = "/home") -> str:
        value = (raw or "").strip()
        if not value or not value.startswith("/") or value.startswith("//") or "://" in value:
            return default
        return value[:500]

    @staticmethod
    def _safe_ios_callback(raw: str | None) -> str:
        value = (raw or "").strip()
        if value.startswith("machi://auth/google"):
            return value[:300]
        return GOOGLE_IOS_CALLBACK_URL

    def _oauth_callback_location(self, client: str, token: str | None = None, redirect: str = "", error: str = "") -> str:
        if client == "ios":
            params = {"token": token or ""} if token else {"error": error or "oauth_failed"}
            return f"{self._safe_ios_callback(redirect)}?{urlencode(params)}"
        params: dict[str, str] = {"redirect": self._safe_web_redirect(redirect)}
        if error:
            params["error"] = error
        return f"/auth/google/callback?{urlencode(params)}"

    def _google_token(self, code: str, redirect_uri: str) -> dict[str, Any]:
        payload = urlencode({
            "code": code,
            "client_id": GOOGLE_CLIENT_ID,
            "client_secret": GOOGLE_CLIENT_SECRET,
            "redirect_uri": redirect_uri,
            "grant_type": "authorization_code",
        }).encode("utf-8")
        req = urllib.request.Request(
            GOOGLE_OAUTH_TOKEN_URL,
            data=payload,
            method="POST",
            headers={"Content-Type": "application/x-www-form-urlencoded", "Accept": "application/json"},
        )
        try:
            with urllib.request.urlopen(req, timeout=15) as resp:
                return json.loads(resp.read().decode("utf-8"))
        except urllib.error.HTTPError as exc:
            try:
                detail = exc.read().decode("utf-8")[:300]
            except Exception:
                detail = ""
            raise APIError(f"Google 授权交换失败：{detail or exc.reason}", 502, "google_token_failed")
        except Exception as exc:
            raise APIError(f"无法连接 Google 授权服务：{exc}", 502, "google_token_failed")

    def _google_userinfo(self, access_token: str) -> dict[str, Any]:
        req = urllib.request.Request(
            GOOGLE_OAUTH_USERINFO_URL,
            method="GET",
            headers={"Authorization": f"Bearer {access_token}", "Accept": "application/json"},
        )
        try:
            with urllib.request.urlopen(req, timeout=15) as resp:
                return json.loads(resp.read().decode("utf-8"))
        except urllib.error.HTTPError as exc:
            try:
                detail = exc.read().decode("utf-8")[:300]
            except Exception:
                detail = ""
            raise APIError(f"Google 账号信息读取失败：{detail or exc.reason}", 502, "google_profile_failed")
        except Exception as exc:
            raise APIError(f"无法读取 Google 账号信息：{exc}", 502, "google_profile_failed")

    @staticmethod
    def _google_handle_base(email: str, name: str) -> str:
        seed = (email.split("@", 1)[0] if "@" in email else "") or name or "google_user"
        base = re.sub(r"[^a-z0-9_.]+", "", seed.lower().replace(" ", ".")).strip("._")
        if len(base) < 3:
            base = f"{base or 'user'}_google"
        return base[:20].strip("._") or "google_user"

    def _unique_google_handle(self, conn: sqlite3.Connection, email: str, name: str) -> str:
        base = self._google_handle_base(email, name)
        candidate = base
        suffix = 0
        while True:
            exists = conn.execute("SELECT 1 FROM users WHERE handle = ?", (candidate,)).fetchone()
            if not exists and candidate not in RESERVED_HANDLES and HANDLE_RE.match(candidate):
                return candidate
            suffix += 1
            tail = f".{suffix}"
            candidate = f"{base[:20 - len(tail)]}{tail}".strip("._")
            if len(candidate) < 3:
                candidate = f"user{suffix}"

    def _upsert_google_user(self, conn: sqlite3.Connection, profile: dict[str, Any]) -> dict[str, Any]:
        google_sub = str(profile.get("sub") or "").strip()
        if not google_sub:
            raise APIError("Google 账号缺少唯一标识", 400, "google_profile_invalid")
        email_verified = bool(profile.get("email_verified"))
        # Use the Google-provided email for account *matching* even when the
        # `email_verified` claim is absent from the payload — Google only returns
        # an email it owns for the signed-in account, so it is safe to link to an
        # existing same-email account. Previously this was gated on
        # `email_verified`, so logins missing that claim fell through to creating
        # a brand-new duplicate account instead of re-using the bound one.
        email = str(profile.get("email") or "").strip().lower()
        name = (str(profile.get("name") or "").strip() or (email.split("@", 1)[0] if email else "Google 用户"))[:60]
        picture = str(profile.get("picture") or "").strip()

        row = conn.execute("SELECT * FROM users WHERE google_sub = ? AND deleted_at IS NULL", (google_sub,)).fetchone()
        if row:
            updates = {
                "email_verified": 1 if email_verified else int(row["email_verified"] or 0),
                "auth_provider": "google",
                "updated_at": now_iso(),
            }
            if email and not row["email"]:
                updates["email"] = email
            if picture and not row["avatar_url"]:
                updates["avatar_url"] = picture
            sets = ", ".join(f"{k} = ?" for k in updates)
            conn.execute(f"UPDATE users SET {sets} WHERE id = ?", [*updates.values(), row["id"]])
            return dict(conn.execute("SELECT * FROM users WHERE id = ?", (row["id"],)).fetchone())

        # SECURITY (account-takeover gate): only AUTO-LINK a Google identity to an
        # existing local account by email when the email is provider-VERIFIED. A
        # Workspace admin can mint an account with email_verified=false bearing a
        # victim's address; without this gate that login would seize the victim's
        # pre-existing account. Unverified -> fall through to a fresh account.
        if email and email_verified:
            existing = conn.execute("SELECT * FROM users WHERE lower(email) = ? AND deleted_at IS NULL", (email,)).fetchone()
            if existing:
                conn.execute(
                    """
                    UPDATE users
                       SET google_sub = ?, email_verified = 1, auth_provider = 'google',
                           avatar_url = CASE WHEN avatar_url = '' THEN ? ELSE avatar_url END,
                           updated_at = ?
                     WHERE id = ?
                    """,
                    (google_sub, picture, now_iso(), existing["id"]),
                )
                return dict(conn.execute("SELECT * FROM users WHERE id = ?", (existing["id"],)).fetchone())

        user_id = str(uuid.uuid4())
        handle = self._unique_google_handle(conn, email, name)
        country, province, city, region_code, city_label = ("jp", "tokyo", "tokyo", "jp.tokyo.tokyo", "东京")
        conn.execute(
            """
            INSERT INTO users (id, handle, display_name, email, password_hash, bio, location,
                               avatar_symbol, avatar_color, avatar_url, cover_url, membership_tier,
                               is_verified, role, country, province, city, current_region_code,
                               recent_region_codes, google_sub, auth_provider, email_verified,
                               joined_at, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, '', ?, 'person.fill', 'indigo', ?, '', 'free', 0, 'member',
                    ?, ?, ?, ?, ?, ?, 'google', ?, ?, ?, ?)
            """,
            (
                user_id, handle, name, email, hash_password(secrets.token_urlsafe(32)),
                city_label, picture, country, province, city, region_code, region_code,
                google_sub, 1 if email_verified else 0, now_iso(), now_iso(), now_iso(),
            ),
        )
        conn.execute("INSERT INTO settings (user_id, language, updated_at) VALUES (?, '', ?)", (user_id, now_iso()))
        return dict(conn.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone())

    def _upsert_wechat_user(
        self,
        conn: sqlite3.Connection,
        openid: str,
        unionid: str,
        nickname: str,
        avatar_url: str,
    ) -> dict[str, Any]:
        """Find-or-create the Machi account behind a verified WeChat identity.
        Mirrors `_upsert_apple_user`: match by openid binding, else by unionid
        binding (so the same person on the Web/App side links up when a unionid
        is available), else create a fresh account. openid is the stable key —
        we persist it in miniapp_openid_bindings, never the session_key."""
        openid = (openid or "").strip()
        unionid = (unionid or "").strip()
        if not openid:
            raise APIError("微信账号缺少唯一标识", 400, "wechat_profile_invalid")
        nickname = ((nickname or "").strip() or "微信用户")[:60]
        avatar_url = (avatar_url or "").strip()[:500]

        binding = conn.execute(
            "SELECT * FROM miniapp_openid_bindings WHERE platform = 'wechat' AND openid = ?",
            (openid,),
        ).fetchone()
        if not binding and unionid:
            binding = conn.execute(
                "SELECT * FROM miniapp_openid_bindings WHERE platform = 'wechat' AND unionid = ? AND unionid != ''",
                (unionid,),
            ).fetchone()
        if binding:
            user = conn.execute(
                "SELECT * FROM users WHERE id = ? AND deleted_at IS NULL", (binding["user_id"],)
            ).fetchone()
            if user:
                conn.execute(
                    "UPDATE miniapp_openid_bindings SET unionid = ?, openid = ?, last_login_at = ?, updated_at = ? WHERE id = ?",
                    (unionid or binding["unionid"], openid, now_iso(), now_iso(), binding["id"]),
                )
                return dict(user)
            # Orphaned binding (user was deleted) — drop it and fall through to recreate.
            conn.execute("DELETE FROM miniapp_openid_bindings WHERE id = ?", (binding["id"],))

        user_id = str(uuid.uuid4())
        handle = self._unique_google_handle(conn, "", nickname)
        country, province, city, region_code, city_label = ("jp", "tokyo", "tokyo", "jp.tokyo.tokyo", "东京")
        conn.execute(
            """
            INSERT INTO users (id, handle, display_name, email, password_hash, bio, location,
                               avatar_symbol, avatar_color, avatar_url, cover_url, membership_tier,
                               is_verified, role, country, province, city, current_region_code,
                               recent_region_codes, auth_provider, email_verified,
                               joined_at, created_at, updated_at)
            VALUES (?, ?, ?, '', ?, '', ?, 'person.fill', 'green', ?, '', 'free', 0, 'member',
                    ?, ?, ?, ?, ?, 'wechat', 0, ?, ?, ?)
            """,
            (
                user_id, handle, nickname, hash_password(secrets.token_urlsafe(32)),
                city_label, avatar_url, country, province, city, region_code, region_code,
                now_iso(), now_iso(), now_iso(),
            ),
        )
        conn.execute("INSERT INTO settings (user_id, language, updated_at) VALUES (?, '', ?)", (user_id, now_iso()))
        conn.execute(
            """
            INSERT INTO miniapp_openid_bindings (id, platform, openid, unionid, user_id, created_at, updated_at, last_login_at)
            VALUES (?, 'wechat', ?, ?, ?, ?, ?, ?)
            """,
            (str(uuid.uuid4()), openid, unionid, user_id, now_iso(), now_iso(), now_iso()),
        )
        return dict(conn.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone())

    def api_miniapp_wechat_login(self, conn: sqlite3.Connection) -> None:
        """WeChat Mini Program login. Body: {code, nickname?, avatarUrl?}.
        The code (from wx.login on the client) is exchanged server-side for a
        stable openid via sns/jscode2session, then we find-or-create the Machi
        account and issue the SAME bearer session as every other login path, so
        the mini-program shares accounts and data with Web/iOS/Android."""
        data = self.read_json()
        code = str(data.get("code") or data.get("js_code") or "").strip()
        nickname = str(data.get("nickname") or data.get("nickName") or "")
        avatar_url = str(data.get("avatarUrl") or data.get("avatar_url") or "")
        # The network call to WeChat must not hold the global DB lock.
        with _DBLockReleased():
            session = wechat_code2session(code)
        user = self._upsert_wechat_user(
            conn, session["openid"], session.get("unionid", ""), nickname, avatar_url
        )
        token = self._create_session(conn, user["id"])
        ACCESS_LOG.info("wechat mini-program sign-in user %s (%s)", user["handle"], user["id"])
        # No session cookie here: mini-program clients use the bearer token.
        self.send_json({"token": token, "user": serialize_user_with_counts(conn, user)})

    def _upsert_apple_user(self, conn: sqlite3.Connection, sub: str, email: str, name: str) -> dict[str, Any]:
        """Find-or-create the Machi account behind a verified Apple identity.
        Mirrors `_upsert_google_user`: match by apple_sub, else link a matching
        verified email, else create. Apple may omit email/name after the first
        sign-in, which is fine — apple_sub is the stable key."""
        sub = (sub or "").strip()
        if not sub:
            raise APIError("Apple 账号缺少唯一标识", 400, "apple_profile_invalid")
        email = (email or "").strip().lower()
        name = ((name or "").strip() or (email.split("@", 1)[0] if email else "") or "Apple 用户")[:60]

        row = conn.execute("SELECT * FROM users WHERE apple_sub = ? AND deleted_at IS NULL", (sub,)).fetchone()
        if row:
            if email and not row["email"]:
                conn.execute("UPDATE users SET email = ?, email_verified = 1, updated_at = ? WHERE id = ?",
                             (email, now_iso(), row["id"]))
            return dict(conn.execute("SELECT * FROM users WHERE id = ?", (row["id"],)).fetchone())

        if email:
            existing = conn.execute("SELECT * FROM users WHERE lower(email) = ? AND deleted_at IS NULL", (email,)).fetchone()
            if existing:
                conn.execute("UPDATE users SET apple_sub = ?, email_verified = 1, updated_at = ? WHERE id = ?",
                             (sub, now_iso(), existing["id"]))
                return dict(conn.execute("SELECT * FROM users WHERE id = ?", (existing["id"],)).fetchone())

        user_id = str(uuid.uuid4())
        handle = self._unique_google_handle(conn, email, name)
        country, province, city, region_code, city_label = ("jp", "tokyo", "tokyo", "jp.tokyo.tokyo", "东京")
        conn.execute(
            """
            INSERT INTO users (id, handle, display_name, email, password_hash, bio, location,
                               avatar_symbol, avatar_color, avatar_url, cover_url, membership_tier,
                               is_verified, role, country, province, city, current_region_code,
                               recent_region_codes, apple_sub, auth_provider, email_verified,
                               joined_at, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, '', ?, 'person.fill', 'indigo', '', '', 'free', 0, 'member',
                    ?, ?, ?, ?, ?, ?, 'apple', ?, ?, ?, ?)
            """,
            (
                user_id, handle, name, email, hash_password(secrets.token_urlsafe(32)),
                city_label, country, province, city, region_code, region_code,
                sub, 1 if email else 0, now_iso(), now_iso(), now_iso(),
            ),
        )
        conn.execute("INSERT INTO settings (user_id, language, updated_at) VALUES (?, '', ?)", (user_id, now_iso()))
        return dict(conn.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone())

    def api_apple_native(self, conn: sqlite3.Connection) -> None:
        """Native Sign in with Apple: verify the posted identity token, then
        find-or-create the account and issue the same session as every other
        login. The token is the trust anchor — `email`/`full_name` from the
        body are only used as display fallbacks on first sign-in."""
        data = self.read_json()
        identity_token = str(data.get("identity_token") or data.get("identityToken") or "").strip()
        if not identity_token:
            raise APIError("缺少 Apple 凭证", 400, "apple_token_invalid")
        nonce = str(data.get("nonce") or "").strip() or None
        try:
            with _DBLockReleased():
                claims = verify_apple_identity_token(identity_token, expected_nonce=nonce)
        except APIError:
            raise
        except urllib.error.URLError:
            raise APIError("无法连接 Apple 验证服务，请稍后重试", 503, "apple_verify_unavailable")
        sub = str(claims.get("sub") or "")
        email = str(claims.get("email") or data.get("email") or "")
        full_name = str(data.get("full_name") or data.get("fullName") or "")
        user = self._upsert_apple_user(conn, sub, email, full_name)
        token = self._create_session(conn, user["id"])
        self._set_session_cookie(token)
        ACCESS_LOG.info("apple sign-in user %s (%s)", user["handle"], user["id"])
        self.send_json({"token": token, "user": serialize_user_with_counts(conn, user)})

    def _link_apple_to_user(self, conn: sqlite3.Connection, user_id: str, sub: str) -> dict[str, Any]:
        """Attach a verified Apple identity to the ALREADY-authenticated account
        (mirrors `_link_google_to_user`). Never logs in as someone else."""
        sub = (sub or "").strip()
        if not sub:
            raise APIError("Apple 账号缺少唯一标识", 400, "apple_profile_invalid")
        user = conn.execute("SELECT * FROM users WHERE id = ? AND deleted_at IS NULL", (user_id,)).fetchone()
        if not user:
            raise APIError("请登录后再绑定 Apple", 401, "AUTH_REQUIRED")
        other = conn.execute(
            "SELECT id FROM users WHERE apple_sub = ? AND id != ? AND deleted_at IS NULL",
            (sub, user_id),
        ).fetchone()
        if other:
            raise APIError("该 Apple 账号已绑定到其他 Machi 账号", 409, "apple_already_linked")
        existing = (user["apple_sub"] or "").strip()
        if existing and existing != sub:
            raise APIError("当前账号已绑定了另一个 Apple 账号，请先解绑", 409, "already_linked_other")
        conn.execute("UPDATE users SET apple_sub = ?, updated_at = ? WHERE id = ?", (sub, now_iso(), user_id))
        write_security_log(
            conn, user_id, "apple_linked", {"apple_sub_hint": sub[:6]},
            ip=self._client_ip(), user_agent=self.headers.get("User-Agent") or "",
        )
        return dict(conn.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone())

    def api_apple_link(self, conn: sqlite3.Connection) -> None:
        """Bind a Sign in with Apple identity to the CURRENT logged-in account,
        so a user (e.g. an admin signed in by password/Google) can also sign in
        with Apple later. Requires an authenticated session."""
        user = self.require_user(conn)
        data = self.read_json()
        identity_token = str(data.get("identity_token") or data.get("identityToken") or "").strip()
        if not identity_token:
            raise APIError("缺少 Apple 凭证", 400, "apple_token_invalid")
        nonce = str(data.get("nonce") or "").strip() or None
        try:
            with _DBLockReleased():
                claims = verify_apple_identity_token(identity_token, expected_nonce=nonce)
        except APIError:
            raise
        except urllib.error.URLError:
            raise APIError("无法连接 Apple 验证服务，请稍后重试", 503, "apple_verify_unavailable")
        updated = self._link_apple_to_user(conn, user["id"], str(claims.get("sub") or ""))
        self.send_json({"status": "ok", "user": serialize_user_with_counts(conn, updated)})

    def _link_google_to_user(self, conn: sqlite3.Connection, user_id: str, profile: dict[str, Any]) -> dict[str, Any]:
        """Attach a verified Google identity to an ALREADY-authenticated account
        (the link target is bound at start time by an authed request and stored
        in oauth_states, so the unauthenticated browser callback can't retarget
        it). Never logs the user in as someone else."""
        google_sub = str(profile.get("sub") or "").strip()
        if not google_sub:
            raise APIError("Google 账号缺少唯一标识", 400, "google_profile_invalid")
        user = conn.execute("SELECT * FROM users WHERE id = ? AND deleted_at IS NULL", (user_id,)).fetchone()
        if not user:
            raise APIError("请登录后再绑定 Google", 401, "AUTH_REQUIRED")
        other = conn.execute(
            "SELECT id FROM users WHERE google_sub = ? AND id != ? AND deleted_at IS NULL",
            (google_sub, user_id),
        ).fetchone()
        if other:
            raise APIError("该 Google 账号已绑定到其他 Machi 账号", 409, "google_already_linked")
        existing_sub = (user["google_sub"] or "").strip()
        if existing_sub and existing_sub != google_sub:
            raise APIError("当前账号已绑定了另一个 Google 账号，请先解绑", 409, "already_linked_other")
        picture = str(profile.get("picture") or "").strip()
        updates: dict[str, Any] = {"google_sub": google_sub, "updated_at": now_iso()}
        if picture and not (user["avatar_url"] or "").strip():
            updates["avatar_url"] = picture
        sets = ", ".join(f"{k} = ?" for k in updates)
        conn.execute(f"UPDATE users SET {sets} WHERE id = ?", [*updates.values(), user_id])
        write_security_log(
            conn, user_id, "google_linked", {"google_sub_hint": google_sub[:6]},
            ip=self._client_ip(), user_agent=self.headers.get("User-Agent") or "",
        )
        return dict(conn.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone())

    def _oauth_link_location(self, client: str, redirect: str = "", ok: bool = False, error: str = "") -> str:
        """Where to send the browser after a LINK (bind) attempt — distinct from
        the login callback because there's no new session token to deliver."""
        if client == "ios":
            params = {"linked": "1"} if ok else {"error": error or "google_link_failed"}
            return f"{self._safe_ios_callback(redirect)}?{urlencode(params)}"
        target = self._safe_web_redirect(redirect, "/settings")
        sep = "&" if "?" in target else "?"
        params = {"google": "linked"} if ok else {"google_error": error or "google_link_failed"}
        return f"{target}{sep}{urlencode(params)}"

    def api_google_start(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        if not GOOGLE_CLIENT_ID or not GOOGLE_CLIENT_SECRET:
            raise APIError("Google 登录尚未配置", 503, "google_oauth_not_configured")
        client = (query.get("client") or "web").strip().lower()
        if client not in ("web", "ios"):
            client = "web"
        # intent=login → sign in / auto-register; intent=link → bind Google to
        # the CURRENT account (requires an active session, captured here).
        intent = (query.get("intent") or "login").strip().lower()
        if intent not in ("login", "link"):
            intent = "login"
        link_user_id = ""
        if intent == "link":
            link_user_id = self.require_user(conn)["id"]
        if client == "ios":
            redirect = self._safe_ios_callback(query.get("redirect"))
        else:
            redirect = self._safe_web_redirect(query.get("redirect"), "/settings" if intent == "link" else "/home")
        state = secrets.token_urlsafe(32)
        created_at = now_iso()
        expires_at = (datetime.now(timezone.utc) + timedelta(seconds=GOOGLE_OAUTH_STATE_TTL_SEC)).isoformat()
        conn.execute(
            "INSERT INTO oauth_states (state, provider, client, redirect, intent, link_user_id, created_at, expires_at, ip) "
            "VALUES (?, 'google', ?, ?, ?, ?, ?, ?, ?)",
            (state, client, redirect, intent, link_user_id, created_at, expires_at, self._client_ip()[:64]),
        )
        redirect_uri = self._google_redirect_uri()
        params = {
            "client_id": GOOGLE_CLIENT_ID,
            "redirect_uri": redirect_uri,
            "response_type": "code",
            "scope": "openid email profile",
            "state": state,
            "prompt": "select_account",
        }
        self.send_json({
            "authorization_url": f"{GOOGLE_OAUTH_AUTH_URL}?{urlencode(params)}",
            "url": f"{GOOGLE_OAUTH_AUTH_URL}?{urlencode(params)}",
            "state": state,
            "expires_in": GOOGLE_OAUTH_STATE_TTL_SEC,
        })

    def api_google_callback(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        state = (query.get("state") or "").strip()
        row = conn.execute("SELECT * FROM oauth_states WHERE state = ? AND provider = 'google'", (state,)).fetchone() if state else None
        if not row:
            return self.send_redirect(self._oauth_callback_location("web", error="invalid_state"))
        client = row["client"] or "web"
        redirect = row["redirect"] or ""
        keys = row.keys()
        intent = ((row["intent"] if "intent" in keys else "login") or "login")
        link_user_id = ((row["link_user_id"] if "link_user_id" in keys else "") or "")

        def _fail(code: str) -> None:
            if intent == "link":
                return self.send_redirect(self._oauth_link_location(client, redirect=redirect, error=code))
            return self.send_redirect(self._oauth_callback_location(client, redirect=redirect, error=code))

        expires = parse_iso(row["expires_at"])
        if row["consumed_at"] or (expires and expires < datetime.now(timezone.utc)):
            return _fail("state_expired")
        conn.execute("UPDATE oauth_states SET consumed_at = ? WHERE state = ?", (now_iso(), state))
        if query.get("error"):
            return _fail("google_denied")
        code = (query.get("code") or "").strip()
        if not code:
            return _fail("missing_code")
        redirect_uri = self._google_redirect_uri()
        try:
            with _DBLockReleased():
                token_data = self._google_token(code, redirect_uri)
                access_token = str(token_data.get("access_token") or "")
                if not access_token:
                    raise APIError("Google 未返回访问令牌", 502, "google_token_failed")
                profile = self._google_userinfo(access_token)
        except APIError as exc:
            return _fail(exc.code or ("google_link_failed" if intent == "link" else "oauth_failed"))
        if intent == "link":
            try:
                self._link_google_to_user(conn, link_user_id, profile)
            except APIError as exc:
                return self.send_redirect(self._oauth_link_location(client, redirect=redirect, error=exc.code or "google_link_failed"))
            return self.send_redirect(self._oauth_link_location(client, redirect=redirect, ok=True))
        user = self._upsert_google_user(conn, profile)
        token = self._create_session(conn, user["id"])
        if client == "web":
            self._set_session_cookie(token)
        self.send_redirect(self._oauth_callback_location(client, token=token, redirect=redirect))

    def api_google_unlink(self, conn: sqlite3.Connection) -> None:
        """Remove the Google identity from the current account. Blocked when it
        is the account's only viable way back in (a Google-created account with
        no verified email), so a user can never lock themselves out."""
        user = self.require_user(conn)
        if not (user["google_sub"] or "").strip():
            self.send_json({"ok": True, "user": serialize_user_with_counts(conn, user), "message": "当前账号未绑定 Google"})
            return
        auth_provider = (user["auth_provider"] or "password")
        email_ok = is_valid_email((user["email"] or "").strip()) and bool(user["email_verified"])
        if auth_provider != "password" and not email_ok:
            raise APIError(
                "该账号是通过 Google 创建的，请先绑定邮箱并设置登录密码，再解绑 Google，以免无法再次登录。",
                400, "google_unlink_no_fallback",
            )
        conn.execute(
            "UPDATE users SET google_sub = '', auth_provider = 'password', updated_at = ? WHERE id = ?",
            (now_iso(), user["id"]),
        )
        write_security_log(
            conn, user["id"], "google_unlinked", {},
            ip=self._client_ip(), user_agent=self.headers.get("User-Agent") or "",
        )
        fresh = dict(conn.execute("SELECT * FROM users WHERE id = ?", (user["id"],)).fetchone())
        self.send_json({"ok": True, "user": serialize_user_with_counts(conn, fresh), "message": "已解绑 Google 账号"})

    def api_apple_unlink(self, conn: sqlite3.Connection) -> None:
        """Remove the Apple identity from the current account. Blocked when it is
        the account's only viable way back in (an Apple-created account with no
        verified email and no linked Google), so a user can never lock themselves
        out. Mirrors `api_google_unlink`."""
        user = self.require_user(conn)
        if not (user["apple_sub"] or "").strip():
            self.send_json({"ok": True, "user": serialize_user_with_counts(conn, user), "message": "当前账号未绑定 Apple"})
            return
        auth_provider = (user["auth_provider"] or "password")
        email_ok = is_valid_email((user["email"] or "").strip()) and bool(user["email_verified"])
        has_google = bool((user["google_sub"] or "").strip())
        if auth_provider not in ("password",) and not email_ok and not has_google:
            raise APIError(
                "该账号是通过 Apple 创建的，请先绑定邮箱并设置登录密码，再解绑 Apple，以免无法再次登录。",
                400, "apple_unlink_no_fallback",
            )
        # Only fall back to password auth when Apple WAS the primary provider;
        # a Google/password account keeps its provider untouched.
        next_provider = "password" if auth_provider == "apple" else auth_provider
        conn.execute(
            "UPDATE users SET apple_sub = '', auth_provider = ?, updated_at = ? WHERE id = ?",
            (next_provider, now_iso(), user["id"]),
        )
        write_security_log(
            conn, user["id"], "apple_unlinked", {},
            ip=self._client_ip(), user_agent=self.headers.get("User-Agent") or "",
        )
        fresh = dict(conn.execute("SELECT * FROM users WHERE id = ?", (user["id"],)).fetchone())
        self.send_json({"ok": True, "user": serialize_user_with_counts(conn, fresh), "message": "已解绑 Apple 账号"})

    def _create_session(self, conn: sqlite3.Connection, user_id: str) -> str:
        token = secrets.token_urlsafe(32)
        expires_at = (datetime.now(timezone.utc) + timedelta(days=SESSION_TTL_DAYS)).isoformat()
        # Hard-cap untrusted header values so a hostile client can't
        # bloat the row to MB.
        device = (self.headers.get("X-Device-Name") or "")[:120]
        ua = (self.headers.get("User-Agent") or "")[:300]
        ip = (self._client_ip() or "")[:64]
        conn.execute(
            "INSERT INTO sessions (token, user_id, device_name, user_agent, ip, created_at, last_seen_at, expires_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?)",
            (token, user_id, device, ua, ip, now_iso(), now_iso(), expires_at),
        )
        return token

    def api_logout(self, conn: sqlite3.Connection) -> None:
        session = self.current_session(conn)
        if session:
            conn.execute("DELETE FROM sessions WHERE token = ?", (session["token"],))
        self._clear_session_cookie()
        self.send_json({"ok": True})

    # ---- email verification + password recovery + 2-step login ----

    @staticmethod
    def _norm_locale(value: Any) -> str:
        v = str(value or "").strip().lower()
        return v if v in ("zh", "en", "ja") else "zh"

    def api_captcha(self, conn: sqlite3.Connection) -> None:
        """Issue an image-captcha challenge for the requested scene
        ('login' or 'register'). `enabled: false` tells clients to hide
        the captcha row entirely, which keeps every app build working
        across enforcement rollouts/rollbacks — and lets the adaptive
        login mode flip the row on per-IP after repeated failures."""
        data = self.read_json()
        scene = (data.get("scene") or "register").strip()
        if not captcha_required_for(scene, ip=self._client_ip()):
            self.send_json({"enabled": False})
            return
        self.send_json({"enabled": True, **issue_captcha(conn, self._client_ip())})

    def _enforce_captcha(self, conn: sqlite3.Connection, data: dict[str, Any], scene: str, handle: str = "") -> None:
        if not captcha_required_for(scene, ip=self._client_ip(), handle=handle):
            return
        verify_captcha_or_raise(
            conn,
            captcha_id=str(data.get("captcha_id") or ""),
            answer=str(data.get("captcha_code") or data.get("captcha") or ""),
        )

    def api_send_email_code(self, conn: sqlite3.Connection) -> None:
        """Issue a verification code for sign-up (or self-serve reset). The
        response NEVER contains the code — only whether it was accepted and
        how long it lasts. Responds generically to avoid leaking which
        addresses already have accounts."""
        data = self.read_json()
        email = (data.get("email") or data.get("new_email") or "").strip()
        purpose = (data.get("purpose") or "register").strip()
        locale = self._norm_locale(data.get("locale"))
        secure_purposes = {"change_password", "change_email_old", "change_email_new"}
        if purpose not in ("register", "reset", *secure_purposes):
            raise APIError("不支持的验证码类型", 400, "invalid_purpose")
        # Anonymous purposes are the bot/email-bomb vector; the secure ones
        # already require a logged-in session, so no captcha there.
        if purpose in ("register", "reset"):
            self._enforce_captcha(conn, data, "register")
        user = self.require_user(conn) if purpose in secure_purposes else None
        user_id = user["id"] if user else None
        if purpose in ("change_password", "change_email_old"):
            email = (user["email"] or "").strip()
            if not is_valid_email(email):
                raise APIError("当前账号未绑定邮箱，请先使用密码验证", 400, "no_email_on_file")
        if purpose == "change_email_new":
            email = email.strip()
        if not is_valid_email(email):
            raise APIError("请填写有效邮箱", 400, "invalid_email")
        taken = conn.execute(
            "SELECT 1 FROM users WHERE lower(email) = ? AND deleted_at IS NULL", (email.lower(),)
        ).fetchone()
        if purpose == "change_email_new":
            if email.lower() == (user["email"] or "").strip().lower():
                raise APIError("新邮箱不能与当前邮箱相同", 400, "same_email")
            exists = conn.execute(
                "SELECT 1 FROM users WHERE lower(email) = ? AND id != ? AND deleted_at IS NULL",
                (email.lower(), user["id"]),
            ).fetchone()
            if exists:
                raise APIError("这个邮箱已经注册过", 409, "email_taken")
        if purpose == "register" and taken:
            # Pretend success — don't reveal that this address is registered.
            self.send_json({"ok": True, "expires_in": EMAIL_CODE_TTL_SEC})
            return
        if purpose == "reset" and not taken:
            self.send_json({"ok": True, "expires_in": EMAIL_CODE_TTL_SEC})
            return
        if purpose == "reset" and taken:
            urow = conn.execute("SELECT id FROM users WHERE lower(email) = ? AND deleted_at IS NULL", (email.lower(),)).fetchone()
            user_id = urow["id"] if urow else None
        try:
            result = issue_auth_code(conn, purpose=purpose, email=email, ip=self._client_ip(),
                                     user_id=user_id, locale=locale)
            if user and purpose in secure_purposes:
                write_security_log(
                    conn,
                    user["id"],
                    f"{purpose}_code_sent",
                    {"email_hint": mask_email(email)},
                    ip=self._client_ip(),
                    user_agent=self.headers.get("User-Agent") or "",
                )
        except APIError as exc:
            if exc.code == "code_cooldown":
                raise
            # Any other failure: respond generically.
            self.send_json({"ok": True, "expires_in": EMAIL_CODE_TTL_SEC})
            return
        self.send_json({
            "ok": True,
            "challenge_id": result.get("challenge_id"),
            "email_hint": mask_email(email),
            "expires_in": result["expires_in"],
        })

    def api_login_start(self, conn: sqlite3.Connection) -> None:
        """Step 1 of code login: verify the password, then email a one-time
        code. Accounts with no email on file fall back to a direct session
        (unless KAIX_LOGIN_REQUIRE_CODE forces a code)."""
        data = self.read_json()
        raw_identifier = (data.get("handle") or data.get("username") or "").strip()
        fail_key = raw_identifier.lower() if "@" in raw_identifier else normalize_handle(raw_identifier)
        self._enforce_captcha(conn, data, "login", handle=fail_key)
        email_in = (data.get("email") or "").strip()
        password = data.get("password") or ""
        locale = self._norm_locale(data.get("locale"))
        # The single identifier field may hold a handle or an email; resolve it.
        row = self._resolve_login_user(conn, raw_identifier)
        # Legacy clients that send a separate explicit email field still work.
        if not row and email_in:
            row = conn.execute("SELECT * FROM users WHERE lower(email) = ? AND deleted_at IS NULL", (email_in.lower(),)).fetchone()
        if not row or not verify_password(password, row["password_hash"]):
            record_login_failure(self._client_ip(), fail_key)
            raise APIError("用户名/邮箱或密码不正确", 401, "invalid_credentials")
        clear_login_failures(self._client_ip(), fail_key)
        user_email = (row["email"] or "").strip()
        if not is_valid_email(user_email):
            if LOGIN_REQUIRE_CODE:
                raise APIError("该账号未绑定邮箱，无法使用验证码登录", 400, "no_email_on_file")
            token = self._create_session(conn, row["id"])
            self._set_session_cookie(token)
            self.send_json({"requires_code": False, "token": token, "user": serialize_user_with_counts(conn, dict(row))})
            return
        result = issue_auth_code(conn, purpose="login", email=user_email, ip=self._client_ip(),
                                 user_id=row["id"], locale=locale)
        self.send_json({
            "requires_code": True,
            "challenge_id": result["challenge_id"],
            "email_hint": mask_email(user_email),
            "expires_in": result["expires_in"],
        })

    def api_login_verify(self, conn: sqlite3.Connection) -> None:
        """Step 2 of code login: exchange a valid code for a session."""
        data = self.read_json()
        challenge_id = (data.get("challenge_id") or "").strip()
        code = (data.get("code") or "").strip()
        if not challenge_id:
            raise APIError("登录会话无效，请重新登录", 400, "invalid_challenge")
        row = consume_auth_code(conn, purpose="login", challenge_id=challenge_id, code=code)
        user_id = row["user_id"]
        user = conn.execute("SELECT * FROM users WHERE id = ? AND deleted_at IS NULL", (user_id,)).fetchone() if user_id else None
        if not user:
            raise APIError("账号不存在", 404, "user_not_found")
        token = self._create_session(conn, user_id)
        self._set_session_cookie(token)
        self.send_json({"token": token, "user": serialize_user_with_counts(conn, dict(user))})

    def api_change_password(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        current_password = data.get("current_password") or data.get("old_password") or ""
        code = (data.get("code") or "").strip()
        challenge_id = (data.get("challenge_id") or "").strip()
        new_password = data.get("new_password") or data.get("password") or ""
        verified_by = ""
        if current_password:
            if not verify_password(current_password, user["password_hash"]):
                raise APIError("当前密码不正确", 400, "invalid_credentials")
            verified_by = "password"
        elif code:
            email = (user["email"] or "").strip()
            if not is_valid_email(email):
                raise APIError("当前账号未绑定邮箱，请使用当前密码验证", 400, "no_email_on_file")
            consume_auth_code(
                conn,
                purpose="change_password",
                email=email,
                code=code,
                challenge_id=challenge_id,
                user_id=user["id"],
            )
            verified_by = "email_code"
        else:
            raise APIError("请先完成安全验证", 400, "verification_required")
        validate_password_strength(new_password)
        if verify_password(new_password, user["password_hash"]):
            raise APIError("新密码不能与当前密码相同", 400, "password_reuse")
        conn.execute("UPDATE users SET password_hash = ?, updated_at = ? WHERE id = ?",
                     (hash_password(new_password), now_iso(), user["id"]))
        # Revoke every OTHER session; keep the caller logged in.
        current = self.current_session(conn)
        keep = current["token"] if current else ""
        conn.execute("DELETE FROM sessions WHERE user_id = ? AND token != ?", (user["id"], keep))
        write_security_log(
            conn,
            user["id"],
            "password_changed",
            {"verified_by": verified_by, "revoked_other_sessions": True},
            ip=self._client_ip(),
            user_agent=self.headers.get("User-Agent") or "",
        )
        ACCESS_LOG.info("user %s changed password", user["handle"])
        self.send_json({"ok": True, "message": "密码已更新，请使用新密码登录。"})

    def api_verify_password(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        password = data.get("password") or data.get("current_password") or ""
        if not verify_password(password, user["password_hash"]):
            write_security_log(
                conn,
                user["id"],
                "password_verify_failed",
                {},
                ip=self._client_ip(),
                user_agent=self.headers.get("User-Agent") or "",
            )
            raise APIError("当前密码不正确", 400, "invalid_credentials")
        write_security_log(
            conn,
            user["id"],
            "password_verified",
            {},
            ip=self._client_ip(),
            user_agent=self.headers.get("User-Agent") or "",
        )
        self.send_json({"ok": True, "message": "验证通过"})

    def api_change_email(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        current_password = data.get("current_password") or data.get("password") or ""
        old_code = (data.get("old_code") or data.get("current_code") or "").strip()
        old_challenge_id = (data.get("old_challenge_id") or data.get("current_challenge_id") or "").strip()
        new_email = (data.get("new_email") or data.get("email") or "").strip().lower()
        new_code = (data.get("new_code") or data.get("code") or "").strip()
        new_challenge_id = (data.get("new_challenge_id") or data.get("challenge_id") or "").strip()
        if not is_valid_email(new_email):
            raise APIError("请填写有效邮箱", 400, "invalid_email")
        current_email = (user["email"] or "").strip().lower()
        if new_email == current_email:
            raise APIError("新邮箱不能与当前邮箱相同", 400, "same_email")
        exists = conn.execute(
            "SELECT 1 FROM users WHERE lower(email) = ? AND id != ? AND deleted_at IS NULL",
            (new_email, user["id"]),
        ).fetchone()
        if exists:
            raise APIError("这个邮箱已经注册过", 409, "email_taken")
        verified_by = ""
        if current_password:
            if not verify_password(current_password, user["password_hash"]):
                raise APIError("当前密码不正确", 400, "invalid_credentials")
            verified_by = "password"
        elif old_code and is_valid_email(current_email):
            consume_auth_code(
                conn,
                purpose="change_email_old",
                email=current_email,
                code=old_code,
                challenge_id=old_challenge_id,
                user_id=user["id"],
            )
            verified_by = "current_email_code"
        else:
            raise APIError("请先完成当前账号安全验证", 400, "verification_required")
        consume_auth_code(
            conn,
            purpose="change_email_new",
            email=new_email,
            code=new_code,
            challenge_id=new_challenge_id,
            user_id=user["id"],
        )
        conn.execute("UPDATE users SET email = ?, updated_at = ? WHERE id = ?", (new_email, now_iso(), user["id"]))
        reputation_apply_event(conn, user["id"], "email_verified", target_kind="user", target_id=user["id"], reviewed=True)
        write_security_log(
            conn,
            user["id"],
            "email_changed",
            {"verified_by": verified_by, "old_email_hint": mask_email(current_email), "new_email_hint": mask_email(new_email)},
            ip=self._client_ip(),
            user_agent=self.headers.get("User-Agent") or "",
        )
        if is_valid_email(current_email):
            with _DBLockReleased():
                send_email(
                    current_email,
                    "Machi 绑定邮箱已更改",
                    f"你的 Machi 绑定邮箱已更改为 {mask_email(new_email)}。如果不是你本人操作，请立即修改密码并联系支持。",
                )
        fresh = dict(conn.execute("SELECT * FROM users WHERE id = ?", (user["id"],)).fetchone())
        self.send_json({"ok": True, "message": "邮箱已更新", "user": serialize_user_with_counts(conn, fresh)})

    def api_forgot_password(self, conn: sqlite3.Connection) -> None:
        """Send a reset code. Always responds success so an attacker can't
        use this endpoint to enumerate which emails have accounts."""
        data = self.read_json()
        self._enforce_captcha(conn, data, "register")
        email = (data.get("email") or "").strip()
        locale = self._norm_locale(data.get("locale"))
        if is_valid_email(email):
            row = conn.execute("SELECT * FROM users WHERE lower(email) = ? AND deleted_at IS NULL", (email.lower(),)).fetchone()
            if row:
                try:
                    issue_auth_code(conn, purpose="reset", email=row["email"], ip=self._client_ip(),
                                    user_id=row["id"], locale=locale)
                except APIError:
                    pass  # swallow cooldown / send errors — never leak existence
        self.send_json({"ok": True, "expires_in": EMAIL_CODE_TTL_SEC})

    def api_reset_password(self, conn: sqlite3.Connection) -> None:
        data = self.read_json()
        email = (data.get("email") or "").strip()
        code = (data.get("code") or "").strip()
        new_password = data.get("new_password") or data.get("password") or ""
        if not is_valid_email(email):
            raise APIError("请填写有效邮箱", 400, "invalid_email")
        validate_password_strength(new_password)
        row = conn.execute("SELECT * FROM users WHERE lower(email) = ? AND deleted_at IS NULL", (email.lower(),)).fetchone()
        if not row:
            # Generic error — same shape as a bad code, no enumeration.
            raise APIError("验证码无效或已过期", 400, "invalid_code")
        consume_auth_code(conn, purpose="reset", email=row["email"], code=code, user_id=row["id"])
        conn.execute("UPDATE users SET password_hash = ?, updated_at = ? WHERE id = ?",
                     (hash_password(new_password), now_iso(), row["id"]))
        # A password reset revokes ALL existing sessions.
        conn.execute("DELETE FROM sessions WHERE user_id = ?", (row["id"],))
        self._clear_session_cookie()
        ACCESS_LOG.info("password reset completed for user %s", row["handle"])
        self.send_json({"ok": True})

    def api_me(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        self.send_json({"user": serialize_user_with_counts(conn, user)})

    def api_session(self, conn: sqlite3.Connection) -> None:
        """Guest-friendly auth probe — ALWAYS 200, returns {authenticated, user}.

        The web bootstrap calls this on every page load (including /login), so an
        anonymous visitor no longer triggers a 401 in the browser console. The
        hard-gated /api/auth/me (401 for guests) stays as-is for clients that
        want a strict check; this endpoint only changes the bootstrap signal."""
        session = self.current_session(conn)
        user = None
        if session:
            row = conn.execute(
                "SELECT * FROM users WHERE id = ? AND deleted_at IS NULL",
                (session["user_id"],),
            ).fetchone()
            if row:
                user = serialize_user_with_counts(conn, dict(row))
        self.send_json({"authenticated": bool(user), "user": user})

    def api_update_me(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        updates: list[tuple[str, Any]] = []
        fields = ["display_name", "bio", "location", "avatar_symbol", "avatar_color", "avatar_url", "cover_url"]
        for field in fields:
            if field in data and data[field] is not None:
                updates.append((field, str(data[field])))
        # H4: screen the free-text profile fields (display name + bio) — these are
        # public UGC and were bypassing the content filter that posts/comments/DMs
        # already run.
        enforce_content_policy(*[v for f, v in updates if f in ("display_name", "bio")])
        if "email" in data and data["email"] is not None:
            raise APIError("修改绑定邮箱需要安全验证", 403, "verification_required")
        # Region (phase 1). `country/province/city` is the user's declared
        # profile region. `current_region_code` is the browsing city. Keep
        # them separate so editing a profile region does not unexpectedly
        # switch the home feed.
        for field in ("country", "province", "city"):
            if field in data and data[field] is not None:
                updates.append((field, str(data[field]).strip().lower()))
        if "app_language" in data and data["app_language"] is not None:
            app_language = str(data["app_language"] or "").strip()
            if app_language == "zh":
                app_language = "zh-Hans"
            if app_language and app_language not in {"zh-Hans", "en", "ja"}:
                raise APIError("无效的界面语言", 400, "invalid_language")
            updates.append(("app_language", app_language))
        if "content_language_preference" in data and data["content_language_preference"] is not None:
            content_language = str(data["content_language_preference"] or "").strip().lower()
            if content_language not in {"", "follow_app", "zh", "en", "ja", "ko", "fr", "es", "multi"}:
                raise APIError("无效的内容语言", 400, "invalid_content_language")
            updates.append(("content_language_preference", content_language))
        if "preferred_content_languages" in data and data["preferred_content_languages"] is not None:
            raw_preferred = data["preferred_content_languages"]
            values = raw_preferred if isinstance(raw_preferred, list) else str(raw_preferred).replace(",", "|").split("|")
            preferred: list[str] = []
            for value in values:
                clean = str(value or "").strip().lower()
                if clean and clean not in {"zh", "en", "ja", "ko", "fr", "es"}:
                    raise APIError("无效的备用内容语言", 400, "invalid_content_language")
                if clean and clean not in preferred:
                    preferred.append(clean)
            updates.append(("preferred_content_languages", "|".join(preferred)))
        if "current_region_code" in data:
            country_val  = str(data.get("country",  user.get("country",  ""))).strip().lower()
            province_val = str(data.get("province", user.get("province", ""))).strip().lower()
            city_val     = str(data.get("city",     user.get("city",     ""))).strip().lower()
            current_code = str(data.get("current_region_code", "")).strip().lower()
            if not current_code:
                current_code = _resolve_region_code(country_val, province_val, city_val)
            updates.append(("current_region_code", current_code))
            existing_recent = [code for code in (user.get("recent_region_codes", "") or "").split("|") if code]
            if current_code:
                recent = [current_code] + [code for code in existing_recent if code != current_code]
                updates.append(("recent_region_codes", "|".join(recent[:10])))
        if "recent_region_codes" in data and isinstance(data["recent_region_codes"], list):
            recent = []
            for code in data["recent_region_codes"]:
                clean = str(code).strip().lower()
                if clean and clean not in recent:
                    recent.append(clean)
            updates.append(("recent_region_codes", "|".join(recent[:10])))
        if "dm_privacy" in data and data["dm_privacy"] is not None:
            dm_privacy = str(data["dm_privacy"]).strip().lower()
            if dm_privacy not in {"everyone", "following", "none"}:
                raise APIError("无效的私信隐私设置", 400, "invalid_dm_privacy")
            updates.append(("dm_privacy", dm_privacy))
        if "handle" in data and data["handle"]:
            new_handle = normalize_handle(data["handle"])
            if not HANDLE_RE.match(new_handle):
                raise APIError("用户名必须是 3-20 位字母、数字、下划线或点", 400, "invalid_handle")
            if conn.execute("SELECT 1 FROM users WHERE handle = ? AND id != ?", (new_handle, user["id"])).fetchone():
                raise APIError("用户名已存在", 409, "handle_taken")
            updates.append(("handle", new_handle))
        if "password" in data and data["password"]:
            raise APIError("修改密码需要安全验证", 403, "verification_required")
        if updates:
            sets = ", ".join(f"{f} = ?" for f, _ in updates) + ", updated_at = ?"
            values = [v for _, v in updates] + [now_iso(), user["id"]]
            conn.execute(f"UPDATE users SET {sets} WHERE id = ?", values)
            updated_fields = {f for f, _ in updates}
            if updated_fields.intersection({"display_name", "bio", "avatar_symbol", "avatar_color", "avatar_url", "cover_url"}):
                reputation_apply_event(conn, user["id"], "profile_completed", target_kind="user", target_id=user["id"])
            if updated_fields.intersection({
                "country", "province", "city", "current_region_code", "recent_region_codes",
                "app_language", "content_language_preference", "preferred_content_languages",
            }):
                reputation_apply_event(conn, user["id"], "city_language_set", target_kind="user", target_id=user["id"])
        fresh = dict(conn.execute("SELECT * FROM users WHERE id = ?", (user["id"],)).fetchone())
        self.send_json({"user": serialize_user_with_counts(conn, fresh)})

    def api_delete_me(self, conn: sqlite3.Connection) -> None:
        # User-initiated account deletion (App Store 5.1.1(v) / GDPR): really
        # scrub PII, free the handle, hide content and drop sessions — not just
        # flag deleted_at. Shared with admin erase via anonymize_user_account.
        user = self.require_user(conn)
        anonymize_user_account(conn, user["id"])
        self._clear_session_cookie()
        ACCESS_LOG.warning("user %s self-deleted account (%s)", user["handle"], user["id"])
        self.send_json({"ok": True})

    def api_bootstrap(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        feed_rows = list(conn.execute(
            f"SELECT * FROM posts WHERE deleted_at IS NULL AND {_visible_status_sql('posts')} ORDER BY created_at DESC LIMIT 30"
        ))
        feed = fetch_posts_with_extras(conn, [dict(r) for r in feed_rows], user["id"])
        unread = conn.execute(
            "SELECT COUNT(*) AS c FROM notifications WHERE user_id = ? AND is_read = 0 AND deleted_at IS NULL",
            (user["id"],),
        ).fetchone()["c"]
        self.send_json({
            "user": serialize_user_with_counts(conn, user),
            "feed": feed,
            "unread_notifications": int(unread),
            "server_time": now_iso(),
        })

    def api_user_detail(self, conn: sqlite3.Connection, user_id: str) -> None:
        viewer = self.current_session(conn)
        row = conn.execute("SELECT * FROM users WHERE (id = ? OR handle = ?) AND deleted_at IS NULL", (user_id, user_id)).fetchone()
        if not row:
            raise APIError("用户不存在", 404, "user_not_found")
        target = dict(row)
        counts = user_social_counts(conn, target["id"])
        is_following = False
        is_blocked = False
        if viewer:
            is_following = bool(conn.execute(
                "SELECT 1 FROM follows WHERE follower_id = ? AND following_id = ?",
                (viewer["user_id"], target["id"]),
            ).fetchone())
            is_blocked = bool(conn.execute(
                "SELECT 1 FROM blocks WHERE blocker_id = ? AND blocked_id = ?",
                (viewer["user_id"], target["id"]),
            ).fetchone())
        viewer_id = viewer["user_id"] if viewer else None
        # Mutual = we follow them AND they follow us back (drives 私信 affordance).
        is_mutual = False
        if viewer and is_following:
            is_mutual = bool(conn.execute(
                "SELECT 1 FROM follows WHERE follower_id = ? AND following_id = ?",
                (target["id"], viewer["user_id"]),
            ).fetchone())
        payload = serialize_user(target)
        payload.update(counts)
        listing_counts = user_listing_counts(conn, target["id"])
        # Recent posts preview so the profile first screen can paint header +
        # counts + a few posts in this single call (tabs still page lazily).
        preview_rows = [dict(r) for r in conn.execute(
            """
            SELECT * FROM posts
             WHERE author_id = ? AND deleted_at IS NULL AND status IN ('published', 'active')
             ORDER BY created_at DESC LIMIT 6
            """,
            (target["id"],),
        )]
        posts_preview = fetch_posts_with_extras(conn, preview_rows, viewer_id)
        payload.update({
            "is_following": is_following,
            "is_blocked": is_blocked,
            "is_mutual": is_mutual,
            "isMutual": is_mutual,
            "listing_counts": listing_counts,
            "listingCounts": listing_counts,
            "posts_preview": posts_preview,
            "postsPreview": posts_preview,
        })
        self.send_json({"user": payload, "viewer": {"id": viewer_id} if viewer_id else None, "canInteract": bool(viewer_id), "can_interact": bool(viewer_id)})

    def _resolve_user_id_or_404(self, conn: sqlite3.Connection, user_id: str) -> str:
        row = conn.execute(
            "SELECT id FROM users WHERE (id = ? OR handle = ?) AND deleted_at IS NULL",
            (user_id, user_id),
        ).fetchone()
        if not row:
            raise APIError("用户不存在", 404, "user_not_found")
        return str(row["id"])

    def api_profile_by_username(self, conn: sqlite3.Connection, username: str) -> None:
        handle = normalize_handle(username)
        if not handle:
            raise APIError("用户不存在", 404, "user_not_found")
        return self.api_user_detail(conn, handle)

    def _user_posts_query(self, conn: sqlite3.Connection, user_id: str, query: dict[str, str], *, where: str = "") -> tuple[list[dict[str, Any]], str | None]:
        viewer = self.current_session(conn)
        viewer_id = viewer["user_id"] if viewer else None
        user_id = self._resolve_user_id_or_404(conn, user_id)
        limit = max(1, min(int(query.get("limit") or 30), 50))
        cursor = cursor_decode(query.get("cursor"))
        cursor_clause = ""
        params: list[Any] = [user_id]
        if cursor:
            cursor_clause = " AND (p.created_at, p.id) < (?, ?)"
            params.extend([cursor[0], cursor[1]])
        params.append(limit + 1)
        rows = list(conn.execute(
            f"""
            SELECT p.* FROM posts p
            WHERE p.author_id = ? AND p.deleted_at IS NULL AND {_visible_status_sql('p')}{where}{cursor_clause}
            ORDER BY p.created_at DESC, p.id DESC
            LIMIT ?
            """,
            params,
        ))
        next_cursor = None
        if len(rows) > limit:
            # Last row shown — not the probe row — so the strict `<`
            # predicate resumes at limit+1 without dropping a post.
            rows = rows[:limit]
            last = rows[-1]
            next_cursor = cursor_encode(last["created_at"], last["id"])
        posts = fetch_posts_with_extras(conn, [dict(r) for r in rows], viewer_id)
        return posts, next_cursor

    def api_user_posts(self, conn: sqlite3.Connection, user_id: str, query: dict[str, str]) -> None:
        posts, next_cursor = self._user_posts_query(conn, user_id, query)
        self.send_json({"items": posts, "next_cursor": next_cursor})

    def api_user_reposts(self, conn: sqlite3.Connection, user_id: str, query: dict[str, str]) -> None:
        viewer = self.current_session(conn)
        viewer_id = viewer["user_id"] if viewer else None
        user_id = self._resolve_user_id_or_404(conn, user_id)
        limit = max(1, min(int(query.get("limit") or 30), 50))

        created_rows = list(conn.execute(
            f"""
            SELECT p.* FROM posts p
            WHERE p.author_id = ? AND p.repost_of_id IS NOT NULL
              AND p.deleted_at IS NULL AND {_visible_status_sql('p')}
            ORDER BY p.created_at DESC, p.id DESC
            LIMIT ?
            """,
            (user_id, limit + 1),
        ))

        interaction_rows = list(conn.execute(
            f"""
            SELECT i.id AS interaction_id, i.created_at AS interaction_created_at, p.*
              FROM interactions i
              JOIN posts p ON p.id = i.target_id
             WHERE i.user_id = ? AND i.kind = 'repost'
               AND p.deleted_at IS NULL AND {_visible_status_sql('p')}
               AND NOT EXISTS (
                 SELECT 1 FROM posts rp
                  WHERE rp.author_id = ?
                    AND rp.repost_of_id = i.target_id
                    AND COALESCE(rp.content, '') = ''
                    AND rp.deleted_at IS NULL
                    AND {_visible_status_sql('rp')}
               )
             ORDER BY i.created_at DESC, i.id DESC
             LIMIT ?
            """,
            (user_id, user_id, limit + 1),
        ))

        post_rows: list[dict[str, Any]] = [dict(row) for row in created_rows]
        for row in interaction_rows:
            original = dict(row)
            created_at = original.get("interaction_created_at") or original.get("created_at") or now_iso()
            post_rows.append({
                "id": f"repost:{original.get('interaction_id') or original['id']}",
                "author_id": user_id,
                "content": "",
                "repost_of_id": original["id"],
                "view_count": 0,
                "report_count": 0,
                "status": "active",
                "deleted_at": None,
                "country": original.get("country", "") or "",
                "province": original.get("province", "") or "",
                "city": original.get("city", "") or "",
                "region_code": original.get("region_code", "") or "",
                "content_type": "dynamic",
                "attributes": "{}",
                "created_at": created_at,
                "updated_at": created_at,
            })

        post_rows.sort(key=lambda item: (str(item.get("created_at") or ""), str(item.get("id") or "")), reverse=True)
        post_rows = post_rows[:limit]
        posts = fetch_posts_with_extras(conn, post_rows, viewer_id)
        self.send_json({"items": posts, "next_cursor": None, "viewer": {"id": viewer_id} if viewer_id else None, "canInteract": bool(viewer_id), "can_interact": bool(viewer_id)})

    def api_user_replies(self, conn: sqlite3.Connection, user_id: str, query: dict[str, str]) -> None:
        user_id = self._resolve_user_id_or_404(conn, user_id)
        limit = max(1, min(int(query.get("limit") or 30), 50))
        rows = list(conn.execute(
            "SELECT * FROM comments WHERE author_id = ? AND deleted_at IS NULL ORDER BY created_at DESC LIMIT ?",
            (user_id, limit),
        ))
        viewer = self.current_session(conn)
        viewer_id = viewer["user_id"] if viewer else None
        post_ids = list({r["post_id"] for r in rows})
        posts_map: dict[str, dict[str, Any]] = {}
        if post_ids:
            placeholders = ",".join("?" * len(post_ids))
            post_rows = list(conn.execute(
                f"""
                SELECT * FROM posts p
                WHERE p.id IN ({placeholders})
                  AND p.deleted_at IS NULL
                  AND {_visible_status_sql('p')}
                """,
                post_ids,
            ))
            hydrated = fetch_posts_with_extras(conn, [dict(r) for r in post_rows], viewer_id)
            posts_map = {p["id"]: p for p in hydrated}
        comments = []
        for row in rows:
            entry = dict(row)
            comments.append({**serialize_comment(entry), "post": posts_map.get(entry["post_id"])})
        self.send_json({"items": comments, "next_cursor": None, "viewer": {"id": viewer_id} if viewer_id else None, "canInteract": bool(viewer_id), "can_interact": bool(viewer_id)})

    def api_user_media(self, conn: sqlite3.Connection, user_id: str, query: dict[str, str]) -> None:
        posts, next_cursor = self._user_posts_query(
            conn, user_id, query,
            where=" AND EXISTS (SELECT 1 FROM post_media pm WHERE pm.post_id = p.id)",
        )
        self.send_json({"items": posts, "next_cursor": next_cursor})

