    def api_listing_inquiry(self, conn: sqlite3.Connection, listing_id: str) -> None:
        user = self.require_user(conn)
        user_dict = dict(user)
        row = conn.execute("SELECT * FROM city_listings WHERE id = ? AND deleted_at IS NULL", (listing_id,)).fetchone()
        if not row:
            raise APIError("信息不存在", 404, "listing_not_found")
        if row["seller_user_id"] == user["id"]:
            raise APIError("不能咨询自己发布的信息", 400, "self_inquiry")
        if conn.execute(
            "SELECT 1 FROM blocks WHERE blocker_id = ? AND blocked_id = ? LIMIT 1",
            (row["seller_user_id"], user["id"]),
        ).fetchone():
            raise APIError("对方暂时无法接收你的咨询", 403, "blocked")
        data = self.read_json()
        message = str(data.get("message") or "").strip()[:1000]
        enforce_content_policy(message)  # H4: the inquiry seeds a real DM thread
        contact_value = str(data.get("contact_value") or "").strip()[:200]
        row_dict = dict(row)
        inquiry_kind = listing_inquiry_type(row_dict)
        # Structured intake: the type-specific forms (预约看房 / 申请职位 / 预约服务)
        # post details=[{label,value},…]. We keep it as JSON and echo it into the
        # seeded thread message so the poster sees a real brief, not "在吗".
        details: list[dict[str, str]] = []
        raw_details = data.get("details")
        if isinstance(raw_details, list):
            for entry in raw_details[:24]:
                if not isinstance(entry, dict):
                    continue
                label = str(entry.get("label") or "").strip()[:48]
                value = str(entry.get("value") or "").strip()[:600]
                if label and value:
                    details.append({"label": label, "value": value})
        action_word = listing_inquiry_action_word(inquiry_kind)
        success_title = listing_inquiry_success_title(inquiry_kind)
        title = (row["title"] or "城市信息").strip()
        if not message:
            message = f"我想{action_word}：{title}"
        seller_id = row["seller_user_id"]
        now = now_iso()
        dedupe_cutoff = (datetime.now(timezone.utc) - timedelta(seconds=60)).isoformat()
        source_platform = str(data.get("source_platform") or data.get("sourcePlatform") or self.headers.get("X-Client-Platform") or "web").strip()[:40]
        locale = str(data.get("locale") or data.get("language") or self.headers.get("Accept-Language") or "").strip()[:80]
        metadata = {
            "intake_schema_version": 2,
            "details": details,
            "applicant_snapshot": {
                "id": user_dict.get("id", ""),
                "handle": user_dict.get("handle", ""),
                "display_name": user_dict.get("display_name", "") or user_dict.get("name", ""),
            },
            "listing_snapshot": {
                "id": row["id"],
                "type": row["type"],
                "category": row["category"],
                "title": title,
                "price": row["price"],
                "currency": row["currency"],
                "city_slug": row["city_slug"],
            },
            "source_platform": source_platform,
            "locale": locale,
            "success_receipt_title": success_title,
        }
        success_message = f"{success_title}。你可以在工作台查看进度，也可以继续私信补充信息。"
        # Idempotency + atomicity (§7/§19): all of a contact's writes — inquiry,
        # thread seed message, seller notification and counters — run inside one
        # BEGIN IMMEDIATE transaction. SQLite serializes writers, so a double
        # click / client retry / burst of concurrent requests collapses to a
        # single record set instead of duplicates, and a mid-write failure rolls
        # back wholesale (no orphan inquiry without a thread, no lost records). A
        # genuine re-contact after the 60s window still creates a new record.
        conn.execute("BEGIN IMMEDIATE")
        try:
            dup = conn.execute(
                """
                SELECT id, conversation_id, type, status, metadata FROM listing_inquiries
                 WHERE listing_id = ? AND from_user_id = ? AND created_at >= ?
                 ORDER BY created_at DESC LIMIT 1
                """,
                (listing_id, user["id"], dedupe_cutoff),
            ).fetchone()
            if dup:
                conv_id = dup["conversation_id"] or self._conversation_for(conn, user["id"], seller_id)["id"]
                conn.execute("COMMIT")
                dup_meta: dict[str, Any] = {}
                try:
                    parsed = json.loads(dup["metadata"] or "{}")
                    if isinstance(parsed, dict):
                        dup_meta = parsed
                except (TypeError, ValueError):
                    dup_meta = {}
                self.send_json({
                    "ok": True, "message": success_message,
                    "conversation_id": conv_id, "conversationId": conv_id,
                    "inquiry_id": dup["id"], "inquiryId": dup["id"],
                    "type": dup["type"] or inquiry_kind,
                    "status": normalize_listing_inquiry_status(dup["status"], "submitted"),
                    "details": dup_meta.get("details") if isinstance(dup_meta.get("details"), list) else [],
                    "metadata": dup_meta,
                    "success_title": dup_meta.get("success_receipt_title") or success_title,
                    "successTitle": dup_meta.get("success_receipt_title") or success_title,
                    "deduplicated": True,
                    "data": {
                        "conversation_id": conv_id, "conversationId": conv_id,
                        "inquiry_id": dup["id"], "inquiryId": dup["id"],
                        "type": dup["type"] or inquiry_kind,
                        "status": normalize_listing_inquiry_status(dup["status"], "submitted"),
                        "details": dup_meta.get("details") if isinstance(dup_meta.get("details"), list) else [],
                        "metadata": dup_meta,
                        "deduplicated": True,
                    },
                })
                return
            # A contact opens (or reuses) a real buyer↔seller DM thread instead of
            # a write-only form, then records the high-intent inquiry against that
            # thread. The seed message carries the listing + form context so the
            # poster never lands in an empty inbox. See §5–§8 联系/预约/申请闭环.
            conv = self._conversation_for(conn, user["id"], seller_id)
            conv_id = conv["id"]
            inquiry_id = str(uuid.uuid4())
            conn.execute(
                """
                INSERT INTO listing_inquiries (
                    id, listing_id, sender_user_id, seller_user_id, from_user_id, to_user_id,
                    type, message, contact_value, conversation_id, metadata, status, created_at, updated_at
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'submitted', ?, ?)
                """,
                (
                    inquiry_id, listing_id, user["id"], seller_id, user["id"], seller_id,
                    inquiry_kind, message, contact_value, conv_id,
                    json.dumps({**metadata, "conversation_id": conv_id}, ensure_ascii=False), now, now,
                ),
            )
            conn.execute("UPDATE city_listings SET inquiry_count = inquiry_count + 1, updated_at = ? WHERE id = ?", (now, listing_id))
            # Seed the thread with a receipt-like brief. The DM is a continuation
            # channel; the inquiry record remains the source of truth in 工作台.
            seed_parts = [f"【Machi {success_title}】", f"{action_word}：{title}", f"状态：{listing_inquiry_status_message('submitted')}"]
            if row["price"] is not None:
                seed_parts.append(format_price_value(row["price"], row["currency"]))
            seed_parts.extend(f"{d['label']}：{d['value']}" for d in details)
            if contact_value:
                seed_parts.append(f"联系方式：{contact_value}")
            seed_parts.append(message)
            seed_parts.append("商家可在工作台的线索与预约中心处理；用户可在我的申请/预约/咨询中查看进度。")
            seed_content = "\n".join(p for p in seed_parts if p)[:1500]
            message_id = str(uuid.uuid4())
            conn.execute(
                "INSERT INTO messages (id, conversation_id, sender_id, content, created_at, is_read) VALUES (?, ?, ?, ?, ?, 0)",
                (message_id, conv_id, user["id"], seed_content, now),
            )
            conn.execute("UPDATE conversations SET updated_at = ? WHERE id = ?", (now, conv_id))
            # Seller bell notification deep-linking to the thread.
            conn.execute(
                """
                INSERT INTO notifications (id, user_id, actor_id, type, target_listing_id, target_conversation_id, content, created_at)
                VALUES (?, ?, ?, 'listing_inquiry', ?, ?, ?, ?)
                """,
                (str(uuid.uuid4()), seller_id, user["id"], listing_id, conv_id, title[:140], now),
            )
            conn.execute("COMMIT")
            # After COMMIT — a rolled-back inquiry must never push.
            server_apns.enqueue(seller_id, ntype="listing_inquiry", actor_id=user["id"],
                                content=title[:140], conversation_id=conv_id)
        except Exception:
            try:
                conn.execute("ROLLBACK")
            except Exception:
                pass
            raise
        # Realtime fanout + response happen after COMMIT so the write lock is not
        # held during network I/O.
        HUB.publish(seller_id, {"type": "message", "conversation_id": conv_id, "message_id": message_id})
        HUB.publish(seller_id, {"type": "notification", "kind": "listing_inquiry", "listing_id": listing_id, "conversation_id": conv_id})
        self.send_json({
            "ok": True,
            "message": success_message,
            "conversation_id": conv_id,
            "conversationId": conv_id,
            "inquiry_id": inquiry_id,
            "inquiryId": inquiry_id,
            "type": inquiry_kind,
            "status": "submitted",
            "details": details,
            "metadata": {**metadata, "conversation_id": conv_id},
            "success_title": success_title,
            "successTitle": success_title,
            "data": {
                "conversation_id": conv_id,
                "conversationId": conv_id,
                "inquiry_id": inquiry_id,
                "inquiryId": inquiry_id,
                "type": inquiry_kind,
                "status": "submitted",
                "details": details,
                "metadata": {**metadata, "conversation_id": conv_id},
                "success_title": success_title,
                "successTitle": success_title,
            },
        })

    def api_my_workbench_summary(self, conn: sqlite3.Connection) -> None:
        """Lightweight authed aggregate for the iOS 工作台 home — one round trip,
        all counts from real data, 0 (never null) for empty buckets."""
        user = self.require_user(conn)
        uid = user["id"]
        urow = dict(user)

        def _count(sql: str, params: tuple = ()) -> int:
            try:
                row = conn.execute(sql, params).fetchone()
                return int((row[0] if row else 0) or 0)
            except Exception:
                return 0

        # Listings by status + total views — single grouped scan.
        published = pending = offline = views = 0
        try:
            for r in conn.execute(
                "SELECT status, COUNT(*) AS c, COALESCE(SUM(view_count), 0) AS v "
                "FROM city_listings WHERE seller_user_id = ? AND deleted_at IS NULL GROUP BY status",
                (uid,),
            ):
                row = dict(r)
                st = row.get("status") or ""
                c = int(row.get("c") or 0)
                views += int(row.get("v") or 0)
                if st in ("published", "reserved"):
                    published += c
                elif st == "pending_review":
                    pending += c
                elif st != "draft":
                    offline += c  # closed / expired / hidden / sold / rented / rejected
        except Exception:
            pass

        # Inquiries received (to me), bucketed by type + new status — single scan.
        to_expr = "COALESCE(NULLIF(to_user_id, ''), seller_user_id)"
        from_expr = "COALESCE(NULLIF(from_user_id, ''), sender_user_id)"
        application_types = {"job_apply", "rental_application"}
        received = new_leads = applications = new_applications = bookings = new_bookings = consults = new_consults = 0
        try:
            for r in conn.execute(
                f"SELECT type AS t, status AS s, COUNT(*) AS c FROM listing_inquiries "
                f"WHERE {to_expr} = ? GROUP BY type, status",
                (uid,),
            ):
                row = dict(r)
                t = row.get("t") or ""
                s = row.get("s") or "new"
                c = int(row.get("c") or 0)
                is_new = (s == "new")
                received += c
                if is_new:
                    new_leads += c
                if t in application_types:
                    applications += c
                    new_applications += c if is_new else 0
                elif t.endswith("_booking") or t == "rental_viewing":
                    bookings += c
                    new_bookings += c if is_new else 0
                else:
                    consults += c
                    new_consults += c if is_new else 0
        except Exception:
            pass

        sent = _count(f"SELECT COUNT(*) FROM listing_inquiries WHERE {from_expr} = ?", (uid,))
        orders = _count("SELECT COUNT(*) FROM guide_orders WHERE user_id = ?", (uid,))
        followers = _count("SELECT COUNT(*) FROM follows WHERE following_id = ?", (uid,))
        following = _count("SELECT COUNT(*) FROM follows WHERE follower_id = ?", (uid,))
        posts = _count("SELECT COUNT(*) FROM posts WHERE author_id = ? AND deleted_at IS NULL", (uid,))

        self.send_json({
            "posts": posts,
            "followers": followers,
            "following": following,
            "publishedListings": published,
            "pendingReview": pending,
            "offlineListings": offline,
            "receivedInquiries": received,
            "newInquiries": new_consults,
            "sentInquiries": sent,
            "applications": applications,
            "newApplications": new_applications,
            "bookings": bookings,
            "newBookings": new_bookings,
            "consults": consults,
            "newConsults": new_consults,
            "orders": orders,
            "views": views,
            "newLeads": new_leads,
            "membershipActive": bool(urow.get("is_verified_member", 0)),
            "merchantVerified": bool(urow.get("merchant_verified", 0)),
        })

    def api_my_listing_inquiries(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        user = self.require_user(conn)
        role = (query.get("role") or "all").strip().lower()
        listing_type = (query.get("type") or query.get("listing_type") or "").strip()
        status = normalize_listing_inquiry_status(query.get("status"), "") if query.get("status") else ""
        clauses = ["l.deleted_at IS NULL"]
        params: list[Any] = []
        from_expr = "COALESCE(NULLIF(i.from_user_id, ''), i.sender_user_id)"
        to_expr = "COALESCE(NULLIF(i.to_user_id, ''), i.seller_user_id)"
        if role in {"sent", "from", "outbox"}:
            clauses.append(f"{from_expr} = ?")
            params.append(user["id"])
        elif role in {"received", "to", "inbox"}:
            clauses.append(f"{to_expr} = ?")
            params.append(user["id"])
        else:
            clauses.append(f"({from_expr} = ? OR {to_expr} = ?)")
            params.extend([user["id"], user["id"]])
        if listing_type:
            types = [normalize_listing_type(v) for v in listing_type.split(",") if v.strip()]
            types = [v for v in dict.fromkeys(types) if v in LISTING_TYPES]
            if types:
                clauses.append("l.type IN (%s)" % ",".join("?" * len(types)))
                params.extend(types)
        # Bucket routing (see INQUIRY_*_LISTING_TYPES). Keeps each record in a
        # single workbench entry; absent = legacy "everything" behaviour.
        bucket = (query.get("bucket") or "").strip().lower()
        reservation_types = INQUIRY_RESERVATION_LISTING_TYPES
        application_types = INQUIRY_APPLICATION_LISTING_TYPES
        if bucket == "reservation":
            clauses.append("l.type IN (%s)" % ",".join("?" * len(reservation_types)))
            params.extend(reservation_types)
        elif bucket == "application":
            clauses.append("l.type IN (%s)" % ",".join("?" * len(application_types)))
            params.extend(application_types)
        elif bucket == "consultation":
            excluded = (*reservation_types, *application_types)
            clauses.append("l.type NOT IN (%s)" % ",".join("?" * len(excluded)))
            params.extend(excluded)
        if status:
            clauses.append("i.status = ?")
            params.append(status)
        rows = list(conn.execute(
            f"""
            SELECT i.*
              FROM listing_inquiries i
              JOIN city_listings l ON l.id = i.listing_id
             WHERE {' AND '.join(clauses)}
             ORDER BY i.created_at DESC
             LIMIT 100
            """,
            params,
        ))
        items = fetch_listing_inquiries_with_extras(conn, [dict(r) for r in rows], user["id"])
        self.send_json({"ok": True, "items": items, "role": role, "data": {"items": items, "role": role}})

