    def api_admin_update_business(self, conn: sqlite3.Connection, business_id: str) -> None:
        admin = self.require_admin(conn)
        data = self.read_json()
        row = conn.execute("SELECT * FROM business_profiles WHERE id = ?", (business_id,)).fetchone()
        if not row:
            raise APIError("商家申请不存在", 404, "business_not_found")
        current = dict(row)
        status = _clean_text(data.get("verification_status") or data.get("status") or current["verification_status"], 40)
        allowed = {"draft", "pending", "needs_review", "verified", "rejected", "suspended"}
        if status not in allowed:
            raise APIError("商家审核状态不合法", 400, "invalid_business_status")
        incoming_note = _clean_text(data.get("review_note") or data.get("note"), 2000)
        # Reject / 补材料 must carry a reason — the merchant needs to know what
        # to fix, otherwise the status change is a dead end for them.
        if status in {"rejected", "needs_review"} and not incoming_note:
            raise APIError("拒绝或要求补材料时，请填写给商家的说明。", 400, "review_note_required")
        note = incoming_note or _clean_text(current.get("review_note"), 2000)
        now = now_iso()
        conn.execute(
            """
            UPDATE business_profiles
               SET verification_status = ?, review_note = ?, reviewed_at = ?,
                   reviewer_admin_id = ?, updated_at = ?
             WHERE id = ?
            """,
            (status, note, now, admin["id"], now, business_id),
        )
        verified = status == "verified"
        conn.execute(
            "UPDATE users SET is_merchant = ?, merchant_verified = ?, updated_at = ? WHERE id = ?",
            (1 if status != "draft" else 0, 1 if verified else 0, now, current["owner_user_id"]),
        )
        if verified:
            conn.execute(
                """
                UPDATE city_listings
                   SET verification_status = 'verified', updated_at = ?
                 WHERE business_id = ? AND deleted_at IS NULL
                """,
                (now, business_id),
            )
        conn.execute(
            """
            INSERT INTO business_review_logs (
                id, business_id, actor_user_id, action, from_status, to_status, note, metadata, created_at
            )
            VALUES (?, ?, ?, 'admin_review', ?, ?, ?, ?, ?)
            """,
            (
                str(uuid.uuid4()), business_id, admin["id"], current["verification_status"], status,
                note, json.dumps({"source": "admin"}, ensure_ascii=False), now,
            ),
        )
        fresh = dict(conn.execute("SELECT * FROM business_profiles WHERE id = ?", (business_id,)).fetchone())
        self.send_json({
            "business": self._serialize_business_profile(conn, fresh, include_private=True),
        })

    def _explore_region_clause(self, conn: sqlite3.Connection, query: dict[str, str], viewer_id: str | None, alias: str = "p") -> tuple[str, list[Any], dict[str, str]]:
        region_code = (query.get("region_code") or query.get("regionCode") or "").strip().lower()
        country = (query.get("country") or "").strip().lower()
        province = (query.get("province") or "").strip().lower()
        city = (query.get("city") or "").strip().lower()
        if not (region_code or country or province or city) and viewer_id:
            row = conn.execute(
                "SELECT country, province, city, current_region_code FROM users WHERE id = ?",
                (viewer_id,),
            ).fetchone()
            if row:
                region_code = (row["current_region_code"] or "").strip().lower()
                country = (row["country"] or "").strip().lower()
                province = (row["province"] or "").strip().lower()
                city = (row["city"] or "").strip().lower()
        filters: list[str] = []
        params: list[Any] = []
        exact_city = (query.get("exact") or "").strip() in {"1", "true", "yes"}
        if region_code:
            circle_codes = [region_code] if exact_city else metro_circle_region_codes(region_code)
            if len(circle_codes) > 1:
                filters.append(f"{alias}.region_code IN (%s)" % ",".join("?" * len(circle_codes)))
                params.extend(circle_codes)
            else:
                filters.append(f"{alias}.region_code = ?")
                params.append(region_code)
        else:
            circle_slugs = [] if exact_city else metro_circle_city_slugs(country, province, city)
            if country == "jp" and len(circle_slugs) > 1:
                filters.append(f"{alias}.country = ?")
                params.append(country)
                filters.append(f"{alias}.city IN (%s)" % ",".join("?" * len(circle_slugs)))
                params.extend(circle_slugs)
            else:
                if country:
                    filters.append(f"{alias}.country = ?")
                    params.append(country)
                if province:
                    filters.append(f"{alias}.province = ?")
                    params.append(province)
                if city:
                    filters.append(f"{alias}.city = ?")
                    params.append(city)
        clause = (" AND " + " AND ".join(filters)) if filters else ""
        return clause, params, {
            "region_code": region_code,
            "country": country,
            "province": province,
            "city": city,
            "region_codes": ",".join(circle_codes) if region_code and len(circle_codes) > 1 else "",
            "cities": ",".join(circle_slugs) if not region_code and len(circle_slugs) > 1 else "",
            "exact": "1" if exact_city else "0",
        }

    def _explore_ranked_posts(
        self,
        conn: sqlite3.Connection,
        query: dict[str, str],
        *,
        kind: str,
        days: int,
        limit: int,
        viewer_id: str | None,
        config: dict[str, Any],
    ) -> tuple[list[dict[str, Any]], bool, dict[str, str]]:
        region_clause, region_params, region_scope = self._explore_region_clause(conn, query, viewer_id)
        if not config.get("city_isolated"):
            region_clause = ""
            region_params = []
        score_config = dict(config)
        score_config["hot_days"] = days
        # 正在发生 (happening) and 热榜 (hot) are now genuinely different boards:
        # happening ranks by recency-of-activity (resurfaces posts being discussed
        # right now) and windows on that activity; hot ranks by accumulated,
        # weighted, decaying heat over its longer window. Both read denormalized
        # columns — no correlated subqueries.
        if kind == "happening":
            score_sql = _happening_score_sql("p", score_config)
            # Bare column (not COALESCE(NULLIF(...))): last_activity_at is now
            # always populated (INSERT init + migration backfill + reconcile
            # fallback to created_at), so filter+sort can ride idx_posts_last_activity.
            cutoff_expr = "p.last_activity_at"
        else:
            score_sql = _explore_heat_score_sql("p", score_config)
            cutoff_expr = "p.created_at"
        type_clause = " AND p.content_type NOT IN (%s)" % ",".join("?" * len(HIGH_INTENT_POST_TYPES))
        type_params = sorted(HIGH_INTENT_POST_TYPES)
        quality_clause = ""
        if config.get("exclude_reported"):
            # Report leverage, not a kill switch: a single stray report no longer
            # exiles an otherwise-loved post from the board. Hide it once reports
            # cross a small absolute floor (3) AND outweigh a tenth of its likes —
            # so a viral post with a few reports survives while a low-engagement
            # post with real complaints drops.
            quality_clause += " AND (COALESCE(p.report_count, 0) < 3 OR COALESCE(p.report_count, 0) * 10 < COALESCE(p.like_count, 0))"
        # Low-quality gate = "has real text OR has media". The has-media half was a
        # per-candidate `EXISTS (SELECT ... FROM post_media)` correlated subquery
        # baked into the ranking scan. Move it out: SQL no longer probes media at
        # all, and the media check runs as ONE batched query over the fetched
        # candidate ids (see _drop_textless_no_media below). Posts that clearly
        # have text (>=2 non-space chars) never need the probe, so we still keep a
        # DB-side fast path for them and only Python-filter the text-empty ones.
        exclude_low_quality = bool(config.get("exclude_low_quality"))
        blocked_ids: set[str] = set()
        if viewer_id:
            blocked_ids = {
                r["blocked_id"]
                for r in conn.execute("SELECT blocked_id FROM blocks WHERE blocker_id = ?", (viewer_id,))
            }

        def run_rank(cutoff: str | None, tag: str) -> list[dict[str, Any]]:
            cache_input = {
                "kind": kind,
                "tag": tag,
                "days": days,
                "limit": limit,
                "region": region_scope,
                "config": score_config,
                "quality": quality_clause,
            }
            cache_key = "explore:posts:" + hashlib.sha1(json.dumps(cache_input, sort_keys=True).encode("utf-8")).hexdigest()
            cached_rank = _cache_get(cache_key)
            if cached_rank is None:
                cutoff_clause = f" AND {cutoff_expr} >= ?" if cutoff else ""
                params: list[Any] = []
                if cutoff:
                    params.append(cutoff)
                params.extend(region_params)
                params.extend(type_params)
                # Over-fetch candidates so the per-author cap (applied below) can
                # drop a prolific author's surplus posts and still return a full
                # page. 4× limit is plenty of headroom for a 2-per-author cap.
                params.append(limit * 4)
                user_join = "JOIN users u ON u.id = p.author_id AND u.deleted_at IS NULL" if config.get("exclude_banned_users") else "JOIN users u ON u.id = p.author_id"
                # Candidate SELECTION order:
                #  - hot board: order by the precomputed, indexed hot_score
                #    (idx_posts_hot) so the DB does an index scan instead of
                #    sorting a live weighted expression over the whole window;
                #    then re-rank the bounded candidate set in Python by the
                #    admin-tuned config weights (explore_score).
                #  - happening board: no precomputed column captures its
                #    recency-of-activity semantics, so keep the in-SQL sort by
                #    the (subquery-free) score expression.
                if kind == "happening":
                    order_by = "explore_score DESC, p.created_at DESC"
                    reorder_in_python = False
                else:
                    order_by = "p.hot_score DESC, p.created_at DESC"
                    reorder_in_python = True
                ranked_rows = list(conn.execute(
                    f"""
                    SELECT p.id, {score_sql} AS explore_score
                      FROM posts p
                      {user_join}
                     WHERE p.deleted_at IS NULL
                       AND p.status IN ('published', 'active')
                       {cutoff_clause}
                       {region_clause}
                       {type_clause}
                       {quality_clause}
                     ORDER BY {order_by}
                     LIMIT ?
                    """,
                    params,
                ))
                cached_rank = [{"id": r["id"], "score": float(r["explore_score"] or 0)} for r in ranked_rows]
                # Re-rank the hot candidates by the config-weighted score so the
                # admin weights still decide final order within the index-selected
                # pool. Stable sort preserves the hot_score tiebreak for equal scores.
                if reorder_in_python:
                    cached_rank.sort(key=lambda item: item["score"], reverse=True)
                _cache_put(cache_key, cached_rank, ttl_seconds=30)
            if not cached_rank:
                return []
            ids = [str(item["id"]) for item in cached_rank]
            placeholders = ",".join("?" * len(ids))
            rows = list(conn.execute(f"SELECT * FROM posts WHERE id IN ({placeholders})", ids))
            row_by_id = {r["id"]: dict(r) for r in rows}
            score_by_id = {str(item["id"]): float(item.get("score") or 0) for item in cached_rank}
            # Low-quality media probe (moved out of the ranking scan): only the
            # candidates whose text is too short to pass on its own need a media
            # check. Resolve those with ONE batched post_media query instead of a
            # per-row correlated EXISTS in the hot-path SQL.
            media_ok: set[str] = set()
            if exclude_low_quality:
                textless = [
                    pid for pid in ids
                    if len((row_by_id.get(pid, {}).get("content") or "").strip()) < 2
                ]
                if textless:
                    tph = ",".join("?" * len(textless))
                    media_ok = {
                        r["post_id"]
                        for r in conn.execute(
                            f"SELECT DISTINCT post_id FROM post_media WHERE post_id IN ({tph})", textless
                        )
                    }
            ordered: list[dict[str, Any]] = []
            # Author diversity: no single author may occupy more than 2 slots on a
            # ranked board, so one prolific poster can't wall off the whole 热榜/
            # 正在发生 page. Applied in rank order so an author keeps their two
            # highest-ranked posts. Truncate to the requested page size at the end.
            author_seen: dict[str, int] = {}
            for post_id in ids:
                row = row_by_id.get(post_id)
                if not row or row.get("author_id") in blocked_ids:
                    continue
                # Drop text-empty posts that also have no media (the has-text-OR-
                # has-media low-quality gate, now enforced in memory).
                if exclude_low_quality and len((row.get("content") or "").strip()) < 2 and post_id not in media_ok:
                    continue
                author_id = row.get("author_id") or ""
                if author_id:
                    if author_seen.get(author_id, 0) >= EXPLORE_MAX_POSTS_PER_AUTHOR:
                        continue
                    author_seen[author_id] = author_seen.get(author_id, 0) + 1
                row["explore_score"] = score_by_id.get(post_id, 0)
                ordered.append(row)
                if len(ordered) >= limit:
                    break
            return ordered

        cutoff = (datetime.now(timezone.utc) - timedelta(days=days)).isoformat()
        ranked = run_rank(cutoff, "window")
        fallback_used = False
        if config.get("fallback_enabled") and len(ranked) < int(config.get("min_display") or 0):
            existing = {row["id"] for row in ranked}
            fallback = [row for row in run_rank(None, "fallback") if row["id"] not in existing]
            if fallback:
                ranked.extend(fallback[: max(0, limit - len(ranked))])
                fallback_used = True
        return ranked[:limit], fallback_used, region_scope

    def api_discover_hot(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        """Structured local trend board (热榜): ranked TOPICS with an explainable
        reason, scope (city/metro/national) and time window (2h/24h/7d). Server
        owns the heat (comment>like, repost/bookmark, recency decay, report
        downweight via _heat_score_sql) so iOS never hand-rolls a ranking.
        Cached per scope+window so the heavy aggregate runs at most once / 60s."""
        scope = (query.get("scope") or "city").strip().lower()
        if scope not in ("city", "metro", "prefecture", "national"):
            scope = "city"
        window = (query.get("window") or query.get("time_window") or "7d").strip().lower()
        hours_map = {"2h": 2, "24h": 24, "3d": 72, "7d": 168}
        if window not in hours_map:
            window = "7d"
        hours = hours_map[window]
        region_code = (query.get("region_code") or "").strip().lower()
        country = region_code.split(".")[0] if region_code else ""

        scope_clause = ""
        scope_params: list[Any] = []
        if scope == "national" and country:
            scope_clause = "AND p.country = ?"
            scope_params.append(country)
        elif scope == "metro" and region_code:
            codes = metro_circle_region_codes(region_code) or [region_code]
            scope_clause = "AND p.region_code IN (%s)" % ",".join("?" * len(codes))
            scope_params.extend(codes)
        elif scope == "prefecture" and region_code:
            # 都道府県 board: filter by province (the prefecture), all cities in it.
            parts = region_code.split(".")
            if len(parts) >= 2 and parts[1]:
                scope_clause = "AND p.country = ? AND p.province = ?"
                scope_params.extend([parts[0], parts[1]])
            else:
                scope_clause = "AND p.region_code = ?"
                scope_params.append(region_code)
        elif region_code:
            scope_clause = "AND p.region_code = ?"
            scope_params.append(region_code)

        # Drop bare location / generic filler tags so the board ranks real
        # discussion topics instead of "#东京" (the city you're already in).
        block_tags = sorted(HOT_BOARD_TAG_BLOCKLIST)
        block_clause = ("AND t.tag NOT IN (%s)" % ",".join("?" * len(block_tags))) if block_tags else ""

        cache_key = f"discover:hot:{scope}:{window}:{region_code or country or 'all'}"
        cached = _cache_get(cache_key)
        if cached is None:
            now = datetime.now(timezone.utc)
            cutoff = (now - timedelta(hours=hours)).isoformat()
            half = (now - timedelta(hours=hours / 2)).isoformat()
            # Subquery-free: sum the engagement-only hot_score_engaged (NOT
            # hot_score — its freshness "曝光分" would let a burst of brand-new posts
            # inflate a tag) + denormalized comment_count, and use last_activity_at
            # to keep a topic alive when an older post is being commented on now.
            # COUNT(DISTINCT p.author_id) is the secondary sort so a single author
            # spamming one tag can't out-rank a tag many people actually discuss.
            try:
                rows = list(conn.execute(
                    f"""
                    SELECT t.tag AS tag,
                           COUNT(DISTINCT p.id) AS related,
                           COUNT(DISTINCT p.author_id) AS authors,
                           CAST(SUM(COALESCE(p.hot_score_engaged, 0)) AS INTEGER) AS heat,
                           SUM(COALESCE(p.comment_count, 0)) AS comments,
                           SUM(CASE WHEN p.created_at >= ? THEN 1 ELSE 0 END) AS recent_new
                      FROM post_tags t
                      JOIN posts p ON p.id = t.post_id
                     WHERE p.deleted_at IS NULL AND p.status IN ('published', 'active')
                       AND (p.created_at >= ?
                            OR COALESCE(NULLIF(p.last_activity_at, ''), p.created_at) >= ?)
                       {scope_clause}
                       {block_clause}
                     GROUP BY t.tag
                     ORDER BY heat DESC, authors DESC
                     LIMIT 20
                    """,
                    [half, cutoff, cutoff] + scope_params + block_tags,
                ))
            except Exception as exc:
                ERR_LOG.warning("discover hot degraded error=%s", exc)
                rows = []
            # Fallback: an empty local board (e.g. a prefecture with no content yet)
            # should show the country-wide 热榜 rather than nothing.
            if not rows and scope != "national" and country:
                try:
                    rows = list(conn.execute(
                        f"""
                        SELECT t.tag AS tag,
                               COUNT(DISTINCT p.id) AS related,
                               COUNT(DISTINCT p.author_id) AS authors,
                               CAST(SUM(COALESCE(p.hot_score_engaged, 0)) AS INTEGER) AS heat,
                               SUM(COALESCE(p.comment_count, 0)) AS comments,
                               SUM(CASE WHEN p.created_at >= ? THEN 1 ELSE 0 END) AS recent_new
                          FROM post_tags t
                          JOIN posts p ON p.id = t.post_id
                         WHERE p.deleted_at IS NULL AND p.status IN ('published', 'active')
                           AND (p.created_at >= ?
                                OR COALESCE(NULLIF(p.last_activity_at, ''), p.created_at) >= ?)
                           AND p.country = ?
                           {block_clause}
                         GROUP BY t.tag
                         ORDER BY heat DESC, authors DESC
                         LIMIT 20
                        """,
                        [half, cutoff, cutoff, country] + block_tags,
                    ))
                    if rows:
                        scope = "national"
                except Exception:
                    pass
            scope_label = {"city": "本市", "metro": "都市圈", "prefecture": "都道府县", "national": "全国"}.get(scope, "本地")
            window_label = {"2h": "2 小时内", "24h": "24 小时内", "3d": "3 天内", "7d": "7 天内"}[window]
            # rankDelta / velocity from the previous snapshot (item B3.6). scope
            # may have been reassigned to 'national' by the fallback above, so key
            # the snapshot on the FINAL scope + the region we actually served. If
            # no prior snapshot exists for this exact board yet (first view of a
            # region), fall back to the national board's history so a delta is
            # still available rather than a flat 0.
            snap_region = region_code or country or "all"
            scope_key = _topic_snapshot_scope_key(scope, snap_region)
            prev = _previous_topic_ranks(conn, scope_key, window)
            if not prev:
                prev = _previous_topic_ranks(conn, _topic_snapshot_scope_key("national", country or "all"), window)
            items = []
            snapshot_rows: list[tuple[str, int, int]] = []  # (tag, rank, heat) for the read-time snapshot
            for rank, r in enumerate(rows, 1):
                row = dict(r)
                tag = row.get("tag") or ""
                if not tag:
                    continue
                related = int(row.get("related") or 0)
                heat_v = max(0, int(row.get("heat") or 0))
                comments = int(row.get("comments") or 0)
                recent_new = int(row.get("recent_new") or 0)
                older = max(0, related - recent_new)
                prev_entry = prev.get(tag)
                # Positive delta = climbed (previous rank number was larger). A
                # brand-new tag with no prior snapshot gets delta 0 (unknown, not
                # a fake surge).
                rank_delta = (prev_entry["rank"] - rank) if prev_entry else 0
                heat_gained = (heat_v - prev_entry["heat"]) if prev_entry else 0
                if recent_new >= 2 and recent_new >= older:
                    reason = f"新发布 {recent_new} 条"
                elif comments >= max(1, related):
                    reason = "评论增长快"
                else:
                    reason = f"{window_label} {heat_v} 热度"
                # Trend now folds in the real rank movement + heat velocity from
                # the snapshot, not just the new-vs-older post split: a tag that
                # climbed ranks OR gained heat since last snapshot reads "up".
                if rank_delta > 0 or (prev_entry and heat_gained > 0) or recent_new > older:
                    trend = "up"
                elif rank_delta < 0 or (prev_entry and heat_gained < 0) or older > recent_new:
                    trend = "down"
                else:
                    trend = "flat"
                items.append({
                    "id": f"topic:{tag}",
                    "kind": "topic",
                    "title": f"#{tag}",
                    "subtitle": f"{related} 条相关 · {scope_label}",
                    "reason": reason,
                    "scope": scope,
                    "scopeLabel": scope_label,
                    "timeWindow": window,
                    "rank": rank,
                    "rankDelta": rank_delta,
                    "heatDelta": heat_gained,
                    "trend": trend,
                    "heatScore": heat_v,
                    "relatedPosts": related,
                    "route": {"type": "topic", "id": tag},
                })
                snapshot_rows.append((tag, rank, heat_v))
            # Read-time snapshot for the exact board just served: this block runs
            # only on a cache MISS, so it's naturally throttled to ~once / 60s per
            # board — giving region-specific boards (which the refresher's
            # national pass doesn't cover) their own delta history without an
            # unbounded refresher cross-product. Best-effort; never blocks the
            # response.
            if snapshot_rows:
                try:
                    _captured = now_iso()
                    for _tag, _rank, _heat in snapshot_rows:
                        conn.execute(
                            'INSERT INTO topic_rank_snapshots (scope, "window", tag, "rank", heat, captured_at) '
                            "VALUES (?, ?, ?, ?, ?, ?)",
                            (scope_key, window, _tag, _rank, _heat, _captured),
                        )
                except Exception as exc:
                    ERR_LOG.warning("discover hot read snapshot failed error=%s", exc)
            cached = items
            _cache_put(cache_key, cached, ttl_seconds=60)
        self.send_json({"items": cached, "scope": scope, "timeWindow": window})

    def api_explore_posts(self, conn: sqlite3.Connection, query: dict[str, str], kind: str) -> None:
        viewer = self.current_session(conn)
        viewer_id = viewer["user_id"] if viewer else None
        limit = max(1, min(int(query.get("limit") or 20), 50))
        config = _explore_rank_config(conn)
        days = int(config["happening_days"] if kind == "happening" else config["hot_days"])
        ranked, fallback_used, region_scope = self._explore_ranked_posts(
            conn,
            query,
            kind=kind,
            days=days,
            limit=limit,
            viewer_id=viewer_id,
            config=config,
        )
        posts = fetch_posts_with_extras(conn, ranked, viewer_id)
        scores = {row["id"]: float(row.get("explore_score") or 0) for row in ranked}
        for post in posts:
            post["explore_hot_score"] = scores.get(post["id"], 0)
            post["exploreHotScore"] = post["explore_hot_score"]
        self.send_json({
            "items": posts,
            "posts": posts,
            "mode": kind,
            "days": days,
            "fallbackUsed": fallback_used,
            "fallback_used": fallback_used,
            "region": region_scope,
            "config": config,
            "viewer": {"id": viewer_id} if viewer_id else None,
            "canInteract": bool(viewer_id),
            "can_interact": bool(viewer_id),
        })

    def api_explore_topics(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        viewer = self.current_session(conn)
        viewer_id = viewer["user_id"] if viewer else None
        limit = max(1, min(int(query.get("limit") or 30), 80))
        config = _explore_rank_config(conn)
        days = int(config["topic_days"])
        region_clause, region_params, region_scope = self._explore_region_clause(conn, query, viewer_id)
        if not config.get("city_isolated"):
            region_clause = ""
            region_params = []
        score_config = dict(config)
        score_config["hot_days"] = days
        score_sql = _explore_heat_score_sql("p", score_config)
        quality_clause = ""
        if config.get("exclude_reported"):
            # Report leverage, not a kill switch: a single stray report no longer
            # exiles an otherwise-loved post from the board. Hide it once reports
            # cross a small absolute floor (3) AND outweigh a tenth of its likes —
            # so a viral post with a few reports survives while a low-engagement
            # post with real complaints drops.
            quality_clause += " AND (COALESCE(p.report_count, 0) < 3 OR COALESCE(p.report_count, 0) * 10 < COALESCE(p.like_count, 0))"
        if config.get("exclude_low_quality"):
            quality_clause += " AND (length(trim(COALESCE(p.content, ''))) >= 2 OR EXISTS (SELECT 1 FROM post_media pm WHERE pm.post_id = p.id))"

        def query_topics(cutoff: str | None, tag: str) -> list[dict[str, Any]]:
            cache_input = {"tag": tag, "days": days, "limit": limit, "region": region_scope, "config": score_config, "quality": quality_clause}
            cache_key = "explore:topics:" + hashlib.sha1(json.dumps(cache_input, sort_keys=True).encode("utf-8")).hexdigest()
            cached = _cache_get(cache_key)
            if cached is not None:
                return cached
            cutoff_clause = " AND p.created_at >= ?" if cutoff else ""
            params: list[Any] = []
            if cutoff:
                params.append(cutoff)
            params.extend(region_params)
            params.append(limit)
            user_join = "JOIN users u ON u.id = p.author_id AND u.deleted_at IS NULL" if config.get("exclude_banned_users") else "JOIN users u ON u.id = p.author_id"
            # COUNT(DISTINCT p.author_id) as a sort key (above raw post_count) so a
            # tag many DIFFERENT people post under out-ranks one author stuffing it.
            rows = list(conn.execute(
                f"""
                SELECT t.tag, COUNT(*) AS post_count,
                       COUNT(DISTINCT p.author_id) AS authors,
                       SUM({score_sql}) AS topic_heat
                  FROM post_tags t
                  JOIN posts p ON p.id = t.post_id
                  {user_join}
                 WHERE p.deleted_at IS NULL
                   AND p.status IN ('published', 'active')
                   {cutoff_clause}
                   {region_clause}
                   {quality_clause}
                 GROUP BY t.tag
                 ORDER BY topic_heat DESC, authors DESC, post_count DESC, t.tag ASC
                 LIMIT ?
                """,
                params,
            ))
            items = [
                {
                    "tag": r["tag"],
                    "post_count": int(r["post_count"] or 0),
                    "postCount": int(r["post_count"] or 0),
                    "heat": float(r["topic_heat"] or 0),
                    "topicHeat": float(r["topic_heat"] or 0),
                }
                for r in rows
            ]
            _cache_put(cache_key, items, ttl_seconds=60)
            return items

        cutoff = (datetime.now(timezone.utc) - timedelta(days=days)).isoformat()
        topics = query_topics(cutoff, "window")
        fallback_used = False
        if config.get("fallback_enabled") and len(topics) < int(config.get("min_display") or 0):
            seen = {item["tag"] for item in topics}
            extra = [item for item in query_topics(None, "fallback") if item["tag"] not in seen]
            if extra:
                topics.extend(extra[: max(0, limit - len(topics))])
                fallback_used = True
        self.send_json({
            "topics": topics[:limit],
            "items": topics[:limit],
            "days": days,
            "fallbackUsed": fallback_used,
            "fallback_used": fallback_used,
            "region": region_scope,
            "config": config,
            "viewer": {"id": viewer_id} if viewer_id else None,
            "canInteract": bool(viewer_id),
            "can_interact": bool(viewer_id),
        })

    def _recommend_interest_profile(self, conn: sqlite3.Connection, viewer_id: str) -> dict[str, Any]:
        """Build a lightweight interest profile from the viewer's last-90-day
        engagement: which content_types, topics and authors they like / bookmark
        / repost / comment on. Returns normalized weight maps + the set of posts
        they've already engaged with (so we don't re-surface them). All best
        effort — any failure yields an empty profile and the caller falls back to
        plain recency. This is a ranking signal, never an access control.

        Cached per viewer for KAIX_RECPROFILE_TTL_SEC: the two engagement scans
        are the most expensive part of a personalized first page, and a 10-minute
        -stale interest profile is indistinguishable to the user — so at scale a
        returning viewer's repeated home opens cost ~one query window, not two
        scans every time. The scans are also row-capped so a power user with a
        huge history can't make the profile build unbounded."""
        cache_key = f"recprofile:{viewer_id}"
        cached_profile = _cache_get(cache_key)
        if cached_profile is not None:
            return cached_profile
        since = (datetime.now(timezone.utc) - timedelta(days=90)).isoformat()
        types: dict[str, float] = {}
        topics: dict[str, float] = {}
        authors: dict[str, float] = {}
        seen: set[str] = set()
        # Negative-preference maps (item B3.2): posts the viewer explicitly
        # dismissed ("不感兴趣") push their author + tags down. Kept separate from
        # the positive maps so a tag the viewer both engaged with AND dismissed
        # nets out honestly instead of one silently overwriting the other.
        neg_topics: dict[str, float] = {}
        neg_authors: dict[str, float] = {}
        dismissed: set[str] = set()
        # Tag heat rides post_tags, which has no single-row-per-post shape — a
        # post can carry several tags. Aggregate them into one comma string per
        # post via a grouped subquery join so the profile scan stays one query
        # per source table (not N+1 tag lookups). Backend-branched: Postgres
        # STRING_AGG, SQLite GROUP_CONCAT.
        tags_agg = "STRING_AGG(pt.tag, ',')" if KAIX_DB_BACKEND == "postgres" else "GROUP_CONCAT(pt.tag)"
        tag_join = f"LEFT JOIN (SELECT pt.post_id AS post_id, {tags_agg} AS tags FROM post_tags pt GROUP BY pt.post_id) tg ON tg.post_id = p.id"

        def _absorb(content_type: str, topic_slugs: str, author_id: str, weight: float) -> None:
            if content_type:
                types[content_type] = types.get(content_type, 0.0) + weight
            for slug in (topic_slugs or "").split(","):
                slug = slug.strip()
                if slug:
                    topics[slug] = topics.get(slug, 0.0) + weight
            if author_id:
                authors[author_id] = authors.get(author_id, 0.0) + weight

        def _absorb_neg(topic_slugs: str, author_id: str, weight: float) -> None:
            # weight is the (positive) magnitude of the negative signal.
            for slug in (topic_slugs or "").split(","):
                slug = slug.strip()
                if slug:
                    neg_topics[slug] = neg_topics.get(slug, 0.0) + weight
            if author_id:
                neg_authors[author_id] = neg_authors.get(author_id, 0.0) + weight

        try:
            for r in conn.execute(
                f"""SELECT p.id AS pid, p.content_type AS ct, p.author_id AS aid, i.kind AS kind, tg.tags AS tags
                   FROM interactions i JOIN posts p ON p.id = i.target_id
                   {tag_join}
                   WHERE i.user_id = ? AND i.created_at >= ? AND p.deleted_at IS NULL
                     AND i.kind IN ('like', 'bookmark', 'repost', 'dismiss')
                   ORDER BY i.created_at DESC LIMIT 400""",
                (viewer_id, since),
            ):
                d = dict(r)
                kind = d.get("kind") or ""
                if kind == "dismiss":
                    # 不感兴趣 is a negative signal: don't count it as "seen &
                    # liked", record it as a demotion of that author + tags and a
                    # hard-drop id for _recommend_rank.
                    dismissed.add(d["pid"])
                    _absorb_neg(d.get("tags") or "", d.get("aid") or "", 1.5)
                    continue
                seen.add(d["pid"])
                # bookmarks/reposts signal stronger intent than a like.
                w = {"bookmark": 3.0, "repost": 2.5, "like": 1.0}.get(kind, 1.0)
                _absorb(d.get("ct") or "", d.get("tags") or "", d.get("aid") or "", w)
            for r in conn.execute(
                f"""SELECT p.id AS pid, p.content_type AS ct, p.author_id AS aid, tg.tags AS tags
                   FROM comments c JOIN posts p ON p.id = c.post_id
                   {tag_join}
                   WHERE c.author_id = ? AND c.created_at >= ? AND c.deleted_at IS NULL AND p.deleted_at IS NULL
                   ORDER BY c.created_at DESC LIMIT 200""",
                (viewer_id, since),
            ):
                d = dict(r)
                seen.add(d["pid"])
                _absorb(d.get("ct") or "", d.get("tags") or "", d.get("aid") or "", 2.0)
        except Exception:
            return {
                "types": {}, "topics": {}, "authors": {},
                "neg_topics": {}, "neg_authors": {},
                "seen": set(), "dismissed": set(), "active": False,
            }

        def _norm(m: dict[str, float]) -> dict[str, float]:
            top = max(m.values()) if m else 0.0
            return {k: v / top for k, v in m.items()} if top > 0 else {}
        profile = {
            "types": _norm(types),
            "topics": _norm(topics),
            "authors": _norm(authors),
            # Negative maps are normalized independently (own scale) so a single
            # dismiss can't swamp a rich positive profile; the ranker weights
            # them modestly (see _recommend_rank).
            "neg_topics": _norm(neg_topics),
            "neg_authors": _norm(neg_authors),
            "seen": seen,
            "dismissed": dismissed,
            "active": bool(types or topics or authors),
        }
        _cache_put(cache_key, profile, ttl_seconds=KAIX_RECPROFILE_TTL_SEC)
        return profile

    def _recommend_rank(
        self,
        rows: list[dict[str, Any]],
        profile: dict[str, Any],
        limit: int,
        mmr_config: dict[str, Any] | None = None,
    ) -> list[dict[str, Any]]:
        """Re-rank a recency-ordered candidate pool by interest match while
        keeping freshness and diversity. Pure function over the pool — does not
        hit the DB. Weights are deliberately gentle so a brand-new post still
        surfaces and the feed never collapses onto one author/type.

        Diversity: when `mmr_config` is provided and enabled, the ordering is
        produced by a Maximal Marginal Relevance re-rank (relevance vs. pairwise
        tag/author/type similarity — see `_mmr_rerank`) which absorbs the old
        same-author / same-type constraints as continuous penalties. When it's
        None or disabled, we fall back to the legacy hard rules (no 3 same-author
        in a row / ≤3 same content_type in a sliding window). Either way the hard
        constraints — dismiss hard-drop and the freshness floor — bracket the
        re-rank and never participate in the trade-off."""
        types = profile.get("types") or {}
        topics = profile.get("topics") or {}
        authors = profile.get("authors") or {}
        neg_topics = profile.get("neg_topics") or {}
        neg_authors = profile.get("neg_authors") or {}
        seen = profile.get("seen") or set()
        dismissed = profile.get("dismissed") or set()
        # Hard-drop dismissed posts up front (item B3.2): the viewer said 不感兴趣,
        # so it should never re-surface — a mere score penalty could still float
        # it back onto page 1 in a sparse pool. Removing them here also keeps the
        # freshness index (below) aligned with what actually gets ranked.
        if dismissed:
            rows = [r for r in rows if r.get("id") not in dismissed]
        n = len(rows)
        scored: list[tuple[float, int, dict[str, Any]]] = []
        for idx, row in enumerate(rows):
            # Freshness: linear by position in the recency-sorted pool (1.0 newest).
            freshness = 1.0 - (idx / n) if n > 1 else 1.0
            interest = 0.0
            ct = row.get("content_type") or ""
            if ct and ct in types:
                interest += 1.6 * types[ct]
            # Tags now come from a real join in the pool query (topic_slugs), so
            # the 1.4 topic weight finally fires instead of being dead.
            slugs = [s.strip() for s in (row.get("topic_slugs") or "").split(",") if s.strip()]
            if slugs:
                interest += 1.4 * (sum(topics.get(s, 0.0) for s in slugs) / len(slugs))
                # Dismiss-based tag aversion: subtract the average negative
                # affinity of this post's tags (gentle so it nudges, not exiles).
                interest -= 1.4 * (sum(neg_topics.get(s, 0.0) for s in slugs) / len(slugs))
            aid = row.get("author_id") or ""
            if aid and aid in authors:
                interest += 1.2 * authors[aid]
            if aid and aid in neg_authors:
                interest -= 1.2 * neg_authors[aid]
            score = 2.0 * freshness + interest
            if row.get("id") in seen:
                score -= 2.5  # already engaged: down-weight hard, don't exclude
            scored.append((score, idx, row))
        scored.sort(key=lambda t: (-t[0], t[1]))

        mmr_on = bool(mmr_config and mmr_config.get("enabled"))
        if mmr_on:
            # MMR diversity re-rank (BE2): trade relevance against pairwise
            # tag/author/type similarity over the WHOLE scored pool, then trim to
            # `limit`. This subsumes the old "no 3 same-author in a row / ≤3
            # same-type" hard rules — a run of near-identical posts is now
            # penalized continuously (by the w_tag/w_author/w_type similarity)
            # instead of via brittle window counters. Passing the full pool
            # (not just the top `limit`) is what gives MMR room to swap a
            # slightly-less-relevant but more diverse post onto the page.
            lam = float(mmr_config.get("lambda", 0.72))
            # Rerank a little past `limit` so the run-breaker below has spare rows
            # to pull forward when it defers a clustered one (bounded by pool).
            mmr_take = min(len(scored), limit + max(4, limit // 4))
            mmr_ranked = _mmr_rerank(
                [(s, row) for s, _, row in scored],
                mmr_take,
                lam,
                float(mmr_config.get("w_tag", 0.6)),
                float(mmr_config.get("w_author", 0.25)),
                float(mmr_config.get("w_type", 0.15)),
            )
            # Final hard safety net: MMR is a soft trade-off, so a large relevance
            # gap can still leave a dominant author's opening run intact at a
            # relevance-heavy λ. Enforce the no-同作者三连 / 同类型>3 invariant on top.
            ranked = _break_runs(mmr_ranked, limit)
        else:
            # Legacy diversity pass (fallback when MMR is disabled): avoid three
            # in a row from the same author AND more than three of the same
            # content_type in a sliding window of the last 3 — so the page
            # doesn't collapse into e.g. six rants back-to-back. Both defer (not
            # drop) the offending row so it re-enters later in the ordering.
            out: list[dict[str, Any]] = []
            recent_authors: list[str] = []
            recent_types: list[str] = []
            deferred: list[dict[str, Any]] = []
            for _, _, row in scored:
                aid = row.get("author_id") or ""
                ct = row.get("content_type") or ""
                if aid and recent_authors[-2:].count(aid) >= 2:
                    deferred.append(row)
                    continue
                if ct and recent_types[-3:].count(ct) >= 3:
                    deferred.append(row)
                    continue
                out.append(row)
                recent_authors.append(aid)
                recent_types.append(ct)
                if len(out) >= limit:
                    break
            # Overflow continuation: keep the same author/type windows honest when
            # topping up from the deferred queue so a run of same-type posts can't
            # sneak back in at the tail.
            if len(out) < limit:
                for row in deferred:
                    if len(out) >= limit:
                        break
                    aid = row.get("author_id") or ""
                    ct = row.get("content_type") or ""
                    if aid and recent_authors[-2:].count(aid) >= 2:
                        continue
                    if ct and recent_types[-3:].count(ct) >= 3:
                        continue
                    out.append(row)
                    recent_authors.append(aid)
                    recent_types.append(ct)
                # Last resort: if constraints still leave us short (tiny pool),
                # fill with whatever deferred rows remain so the page isn't
                # under-filled.
                if len(out) < limit:
                    already = {id(r) for r in out}
                    out.extend(r for r in deferred if id(r) not in already)
            ranked = out[:limit]

        # Freshness floor — guarantees newly-posted content is actually seen.
        # The interest score can let a strongly-matched older post outrank a
        # brand-new, zero-engagement one, so a fresh post could miss page 1
        # entirely. Reserve a small quota for the very newest pool rows (the pool
        # is recency-ordered, idx 0 = newest) and splice any that the ranking
        # dropped in right after the top personalized pick, where they're seen.
        fresh_quota = min(limit, max(2, limit // 6))
        ranked_ids = {r.get("id") for r in ranked}
        missing_fresh = [r for r in rows[:fresh_quota] if r.get("id") not in ranked_ids]
        if missing_fresh:
            keep = ranked[: max(1, limit - len(missing_fresh))]
            ranked = (keep[:1] + missing_fresh + keep[1:])[:limit]
        ranked = ranked[:limit]

        # Eval instrumentation (BE2): sample ~1% of rankings (or all when a debug
        # flag is set) and emit aggregate diversity metrics as a structured log
        # line — category/tag entropy, author Gini, mean intra-list
        # dissimilarity. Aggregate-only: never logs ids or any post content.
        # Best-effort; a metrics hiccup must never affect the served feed.
        try:
            if self._recommend_eval_sampled():
                m = _diversity_metrics(ranked)
                ACCESS_LOG.info(
                    "recommend_diversity mmr=%s limit=%s n=%s "
                    "type_entropy=%s tag_entropy=%s author_gini=%s ild=%s",
                    1 if mmr_on else 0, limit, len(ranked),
                    m["type_entropy"], m["tag_entropy"], m["author_gini"], m["ild"],
                )
        except Exception:
            pass
        return ranked

    def _recommend_eval_sampled(self) -> bool:
        """True when this ranking should emit an eval-metrics log line: always
        when the viewer sent an X-Machi-Debug header, else ~1% sampled. Isolated
        so it can't throw into the ranking path (headers may be absent on the
        synthetic requests used by tests)."""
        try:
            hdr = getattr(self, "headers", None)
            if hdr is not None and (hdr.get("X-Machi-Debug") or "").strip():
                return True
        except Exception:
            pass
        import random as _random
        return _random.random() < 0.01

    def _recommend_coldstart_mix(
        self,
        conn: sqlite3.Connection,
        recency_rows: list[dict[str, Any]],
        limit: int,
        viewer_id: str | None,
        region_clause: str,
        region_params: list[Any],
        type_clause: str,
        type_params: list[Any],
        blocked_clause: str,
        blocked_params: list[Any],
        dismissed: set[str] | None = None,
        mmr_config: dict[str, Any] | None = None,
    ) -> list[dict[str, Any]]:
        """Cold-start home page (item B3.3): a viewer with no interest profile
        gets an interleave of the hot top-10 and the recency top-10 instead of a
        flat recency wall — so their very first feed shows both what's *good* and
        what's *new*. Both inputs already exist (the recency pool is passed in;
        hot rides the precomputed, indexed hot_score), so this is one extra
        bounded query. Pure zip-with-dedup in memory; returns [] to signal the
        caller to fall back to plain recency (e.g. hot empty on a fresh DB).

        A cold-start viewer can still have 不感兴趣 dismisses (dismisses alone don't
        make a profile 'active'); honor them here too so a dismissed post never
        reappears via the hot/recency mix.

        When `mmr_config` is enabled the interleave is passed once through the MMR
        re-rank with the (smaller) cold-start λ, so even a first feed avoids
        clustering the same author/type/topic. Cold start has no relevance
        signal, so we feed MMR a synthetic descending relevance (interleave
        position) — that keeps the hot/recency ordering as the tie-breaker while
        MMR spreads out near-duplicates."""
        dismissed = dismissed or set()
        hot_rows: list[dict[str, Any]] = []
        try:
            hot_sql = (
                "SELECT p.* FROM posts p WHERE p.deleted_at IS NULL "
                "AND p.status IN ('published', 'active') AND COALESCE(p.hot_score, 0) > 0"
                + region_clause + type_clause + blocked_clause
                + " ORDER BY p.hot_score DESC, p.created_at DESC LIMIT ?"
            )
            # Over-fetch a little so dismiss filtering still leaves ~10 hot rows.
            hot_params = [*region_params, *type_params, *blocked_params, 20]
            hot_rows = [
                dict(r) for r in conn.execute(hot_sql, hot_params)
                if r["id"] not in dismissed
            ][:10]
        except Exception:
            hot_rows = []
        if not hot_rows:
            # Nothing has heat yet — let the caller serve plain recency.
            return []
        recency_top = [r for r in recency_rows if r.get("id") not in dismissed][:10]
        # Interleave hot / recency, skipping ids already placed so a post that is
        # both hot AND recent appears once (at its earlier slot).
        out: list[dict[str, Any]] = []
        seen_ids: set[str] = set()
        for i in range(max(len(hot_rows), len(recency_top))):
            for cand in (
                hot_rows[i] if i < len(hot_rows) else None,
                recency_top[i] if i < len(recency_top) else None,
            ):
                if cand is None:
                    continue
                cid = cand.get("id")
                if cid and cid not in seen_ids:
                    seen_ids.add(cid)
                    out.append(cand)
            if len(out) >= limit:
                break
        # Top up from the rest of the recency pool if the interleave ran short
        # (e.g. heavy overlap between hot and recent). Still skip dismissed.
        if len(out) < limit:
            for cand in recency_rows:
                cid = cand.get("id")
                if cid and cid not in seen_ids and cid not in dismissed:
                    seen_ids.add(cid)
                    out.append(cand)
                    if len(out) >= limit:
                        break
        out = out[:limit]
        if mmr_config and mmr_config.get("enabled") and len(out) > 1:
            # Synthetic relevance = interleave position (descending) so MMR keeps
            # the hot/recency order as its relevance signal, then diversifies.
            n_out = len(out)
            scored = [(float(n_out - i), row) for i, row in enumerate(out)]
            out = _mmr_rerank(
                scored,
                limit,
                float(mmr_config.get("lambda_coldstart", 0.6)),
                float(mmr_config.get("w_tag", 0.6)),
                float(mmr_config.get("w_author", 0.25)),
                float(mmr_config.get("w_type", 0.15)),
            )
        return out[:limit]

    def api_feed(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        viewer = self.current_session(conn)
        viewer_id = viewer["user_id"] if viewer else None
        viewer_payload = {"id": viewer_id} if viewer_id else None
        can_interact = bool(viewer_id)
        mode = (query.get("mode") or "recommend").strip().lower()
        if mode not in {"recommend", "plaza", "local", "following", "hot"}:
            mode = "recommend"
        limit = max(1, min(int(query.get("limit") or 20), 50))
        cursor = cursor_decode(query.get("cursor"))

        blocked_clause = ""
        blocked_params: list[Any] = []
        if viewer_id:
            blocked_clause = " AND p.author_id NOT IN (SELECT blocked_id FROM blocks WHERE blocker_id = ?)"
            blocked_params.append(viewer_id)

        type_clause = ""
        type_params: list[Any] = []
        raw_types = query.get("content_type") or query.get("content_types") or ""
        content_types = [normalize_content_type(v) for v in raw_types.split(",") if v.strip()]
        content_types = [v for v in dict.fromkeys(content_types) if v in CONTENT_TYPES]
        if mode == "plaza" and not content_types:
            content_types = [
                "dynamic", "local_info", "guide", "question", "rant",
                "meetup", "dining", "event", "warning",
            ]
        if content_types:
            type_clause = " AND p.content_type IN (%s)" % ",".join("?" * len(content_types))
            type_params.extend(content_types)
        else:
            # Keep the home/recommend/local feed a community timeline.
            # High-intent marketplace/rental/job rows now live in
            # city_listings; legacy typed posts are hidden from generic feeds
            # unless a channel explicitly asks for them.
            type_clause = " AND p.content_type NOT IN (%s)" % ",".join("?" * len(HIGH_INTENT_POST_TYPES))
            type_params.extend(sorted(HIGH_INTENT_POST_TYPES))

        region_clause = ""
        region_params: list[Any] = []
        req_region_code = (query.get("region_code") or "").strip().lower()
        req_country  = (query.get("country")  or "").strip().lower()
        req_province = (query.get("province") or "").strip().lower()
        req_city     = (query.get("city")     or "").strip().lower()

        if mode == "local" and not (req_region_code or req_city) and viewer:
            viewer_row = conn.execute(
                "SELECT country, province, city, current_region_code FROM users WHERE id = ?",
                (viewer["user_id"],),
            ).fetchone()
            if viewer_row:
                req_region_code = (viewer_row["current_region_code"] or "").lower()
                req_country  = (viewer_row["country"] or "").lower()
                req_province = (viewer_row["province"] or "").lower()
                req_city     = (viewer_row["city"] or "").lower()

        # 都市圈聚合:同城默认按生活圈(关东圈/关西圈…)合并,而不是单个城市。
        # 传 exact=1 可退回单城(用于明确只看某一城)。
        exact_city = (query.get("exact") or "").strip() in {"1", "true", "yes"}
        if req_region_code:
            circle_codes = [req_region_code] if exact_city else metro_circle_region_codes(req_region_code)
            if len(circle_codes) > 1:
                region_clause = " AND p.region_code IN (%s)" % ",".join("?" * len(circle_codes))
                region_params.extend(circle_codes)
            else:
                region_clause = " AND p.region_code = ?"
                region_params.append(req_region_code)
        elif req_country or req_city:
            circle_slugs = [] if exact_city else metro_circle_city_slugs(req_country, req_province, req_city)
            if req_country == "jp" and len(circle_slugs) > 1:
                # JP 城市:按整个都市圈的城市集合过滤(忽略单一 province/city)。
                clauses = ["p.country = ?", "p.city IN (%s)" % ",".join("?" * len(circle_slugs))]
                region_params.append(req_country)
                region_params.extend(circle_slugs)
                region_clause = " AND " + " AND ".join(clauses)
            else:
                clauses = []
                if req_country:
                    clauses.append("p.country = ?")
                    region_params.append(req_country)
                if req_province:
                    clauses.append("p.province = ?")
                    region_params.append(req_province)
                if req_city:
                    clauses.append("p.city = ?")
                    region_params.append(req_city)
                region_clause = " AND " + " AND ".join(clauses)

        if mode == "local" and not (req_region_code or req_city):
            raise APIError("city required", 400, "missing_region")

        # Guest traffic: identical filters → identical page. Serve from the
        # short-TTL cache so landing-page bursts cost one query per window.
        # Logged-in feeds carry per-viewer state (liked/bookmarked/blocked)
        # and never touch this path; cursor pages are long-tail, skip them.
        anon_cache_key = None
        if viewer_id is None and cursor is None and mode != "following":
            anon_cache_key = "feed:anon:" + ":".join([
                mode, str(limit), req_region_code, req_country, req_province,
                req_city, ",".join(content_types),
            ])
            cached_payload = _cache_get(anon_cache_key)
            if cached_payload is not None:
                self.send_json(cached_payload)
                return

        if mode == "following":
            if not viewer_id:
                raise APIError("请登录后继续", 401, "AUTH_REQUIRED")
            base = """
                SELECT p.* FROM posts p
                JOIN follows f ON f.following_id = p.author_id
                WHERE f.follower_id = ? AND p.deleted_at IS NULL
                  AND p.status IN ('published', 'active')
            """
            base_params: list[Any] = [viewer_id]
        elif mode == "local":
            base = f"""
                SELECT p.* FROM posts p
                WHERE p.deleted_at IS NULL
                  AND p.status IN ('published', 'active')
            """
            base_params = []
        elif mode == "hot":
            config = _explore_rank_config(conn)
            days = int(config["hot_days"])
            ranked, fallback_used, region_scope = self._explore_ranked_posts(
                conn,
                query,
                kind="hot",
                days=days,
                limit=limit,
                viewer_id=viewer_id,
                config=config,
            )
            posts = fetch_posts_with_extras(conn, ranked, viewer_id)
            scores = {row["id"]: float(row.get("explore_score") or 0) for row in ranked}
            for post in posts:
                post["explore_hot_score"] = scores.get(post["id"], 0)
                post["exploreHotScore"] = post["explore_hot_score"]
            payload = {
                "items": posts,
                "next_cursor": None,
                "mode": mode,
                "days": days,
                "fallbackUsed": fallback_used,
                "fallback_used": fallback_used,
                "region": region_scope,
                "viewer": viewer_payload,
                "canInteract": can_interact,
                "can_interact": can_interact,
            }
            if anon_cache_key is not None:
                _cache_put(anon_cache_key, payload, ttl_seconds=ANON_FEED_CACHE_TTL)
            self.send_json(payload)
            return
        else:
            base = """
                SELECT p.* FROM posts p
                WHERE p.deleted_at IS NULL
                  AND p.status IN ('published', 'active')
            """
            base_params = []

        cursor_clause = ""
        cursor_params: list[Any] = []
        if cursor:
            cursor_clause = " AND (p.created_at, p.id) < (?, ?)"
            cursor_params.extend([cursor[0], cursor[1]])

        # Personalized recommend: on the FIRST page for a logged-in viewer, pull a
        # larger recency pool and re-rank it by the viewer's interest profile.
        # Page 2+ continues by plain recency below the pool (cursor on the pool's
        # oldest row) so there are no duplicates and pagination stays simple. Any
        # cold-start / empty-profile case falls straight through to recency.
        personalize = (
            mode in ("recommend", "plaza")
            and viewer_id is not None
            and cursor is None
        )
        if personalize:
            pool_size = min(max(limit * 5, 60), 200)
            # Join each pool post's tags (comma-joined) as topic_slugs so the
            # interest ranker's 1.4 topic weight actually has data to score
            # against — without this the pool carried no tags and that branch was
            # dead. Backend-branched aggregate; grouped subquery keeps it one row
            # per post (no fan-out that would break the recency LIMIT).
            _tags_agg = "STRING_AGG(pt.tag, ',')" if KAIX_DB_BACKEND == "postgres" else "GROUP_CONCAT(pt.tag)"
            _pool_base = base.replace(
                "SELECT p.* FROM posts p",
                f"SELECT p.*, tg.tags AS topic_slugs FROM posts p "
                f"LEFT JOIN (SELECT pt.post_id AS post_id, {_tags_agg} AS tags "
                f"FROM post_tags pt GROUP BY pt.post_id) tg ON tg.post_id = p.id",
                1,
            )
            pool_sql = _pool_base + region_clause + type_clause + blocked_clause + " ORDER BY p.created_at DESC, p.id DESC LIMIT ?"
            pool_params = [*base_params, *region_params, *type_params, *blocked_params, pool_size + 1]
            pool_rows = [dict(r) for r in conn.execute(pool_sql, pool_params)]
            profile = self._recommend_interest_profile(conn, viewer_id)
            mmr_config = _recommend_mmr_config(conn)
            if profile.get("active") and len(pool_rows) > limit:
                has_more = len(pool_rows) > pool_size
                pool = pool_rows[:pool_size]
                ranked = self._recommend_rank(pool, profile, limit, mmr_config=mmr_config)
                next_cursor = None
                if has_more or len(pool) > limit:
                    # Resume below the recency pool to avoid re-showing pool posts.
                    tail = pool[-1]
                    next_cursor = cursor_encode(tail["created_at"], tail["id"])
                posts = fetch_posts_with_extras(conn, ranked, viewer_id)
                self.send_json({
                    "items": posts, "next_cursor": next_cursor, "mode": mode,
                    "personalized": True, "viewer": viewer_payload,
                    "canInteract": can_interact, "can_interact": can_interact,
                })
                return
            # Cold start (item B3.3): a viewer with no interest profile yet used
            # to get pure recency — a wall of whatever was posted last. Instead
            # interleave the explore hot top-N with the recency top-N so a
            # newcomer's first page mixes "what's good" with "what's new". Falls
            # through to plain recency if hot is empty (fresh install / tiny DB).
            if not profile.get("active") and pool_rows:
                mixed = self._recommend_coldstart_mix(
                    conn, pool_rows[:pool_size], limit, viewer_id,
                    region_clause, region_params, type_clause, type_params,
                    blocked_clause, blocked_params,
                    dismissed=profile.get("dismissed") or set(),
                    mmr_config=mmr_config,
                )
                if mixed:
                    tail = pool_rows[: pool_size][-1]
                    next_cursor = cursor_encode(tail["created_at"], tail["id"])
                    posts = fetch_posts_with_extras(conn, mixed, viewer_id)
                    self.send_json({
                        "items": posts, "next_cursor": next_cursor, "mode": mode,
                        "coldStart": True, "viewer": viewer_payload,
                        "canInteract": can_interact, "can_interact": can_interact,
                    })
                    return

        sql = base + region_clause + type_clause + blocked_clause + cursor_clause + " ORDER BY p.created_at DESC, p.id DESC LIMIT ?"
        params = [*base_params, *region_params, *type_params, *blocked_params, *cursor_params]
        params.append(limit + 1)
        rows = list(conn.execute(sql, params))

        next_cursor = None
        if len(rows) > limit:
            # Encode the LAST ROW SHOWN, not the probe row — the strict `<`
            # predicate resumes at limit+1 exactly. Encoding the probe row
            # silently dropped one post at every page seam.
            rows = rows[:limit]
            last = rows[-1]
            next_cursor = cursor_encode(last["created_at"], last["id"])
        posts = fetch_posts_with_extras(conn, [dict(r) for r in rows], viewer_id)
        payload = {"items": posts, "next_cursor": next_cursor, "mode": mode, "viewer": viewer_payload, "canInteract": can_interact, "can_interact": can_interact}
        if anon_cache_key is not None:
            _cache_put(anon_cache_key, payload, ttl_seconds=ANON_FEED_CACHE_TTL)
        self.send_json(payload)

    def api_create_post(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        self._enforce_not_muted(user)  # UGC-5
        data = self.read_json()
        content = (data.get("content") or "").strip()
        enforce_content_policy(content)  # H4: reject banned/scam/illegal text on create
        media_ids = data.get("media_ids") or []
        repost_of_id = data.get("repost_of_id")
        # Content type + typed attributes. Validated + truncated
        # server-side so a client can't push junk into untyped JSON
        # storage. Typed posts may be form-first and have very short
        # body text, so attributes count as content for emptiness.
        raw_content_type = data.get("content_type")
        content_type = normalize_content_type(raw_content_type)
        if content_type == "dynamic" and not str(raw_content_type or "").strip():
            content_type = infer_content_type_from_content(content, data.get("attributes")) or content_type
        # Machi Verified gate. High-trust types (招聘/租房/找室友/本地服务/
        # 商家/优惠/内推) require an active membership. Enforced here for
        # EVERY client — the apps only mirror it for UX; a raw API call
        # cannot bypass it. Ordinary content (dynamic/question/guide/二手/
        # 小组/美食/活动…) is untouched and stays free.
        require_verified_membership(conn, user["id"], content_type)
        # Daily publish cap. 0 == off (default) so ordinary posting is
        # never impeded; members get the higher ceiling when an operator
        # opts in via the env config.
        _daily_limit = MEMBERSHIP_DAILY_LIMIT_FREE
        if _daily_limit > 0 and has_active_membership(conn, user["id"]):
            _daily_limit = MEMBERSHIP_DAILY_LIMIT_VERIFIED or 0
        if _daily_limit > 0:
            _since = (datetime.now(timezone.utc) - timedelta(days=1)).isoformat()
            _today = conn.execute(
                "SELECT COUNT(*) AS c FROM posts WHERE author_id = ? AND created_at >= ? AND deleted_at IS NULL",
                (user["id"], _since),
            ).fetchone()["c"]
            if int(_today) >= _daily_limit:
                raise APIError("今日发布已达上限，开通 Machi 认证会员可提升额度。", 429, "daily_limit_reached")
        attributes   = normalize_post_attributes(content_type, data.get("attributes"))
        if content_type == "poll":
            poll_attrs = decode_post_attributes(attributes)
            if not str(poll_attrs.get("question") or "").strip() or len(poll_options_from_attributes(poll_attrs)) < 2:
                raise APIError("投票需要问题和至少两个选项", 400, "invalid_poll")
        if not content and not media_ids and not repost_of_id and not attributes:
            raise APIError("内容不能为空", 400, "empty_content")
        if len(content) > 2000:
            raise APIError("内容过长", 400, "content_too_long")
        valid_media: list[dict[str, Any]] = []
        image_count = 0
        video_count = 0
        for raw_media_id in media_ids[:10]:
            media_id = str(raw_media_id or "").strip()
            if not media_id:
                continue
            media_row = conn.execute(
                "SELECT * FROM media WHERE id = ? AND owner_id = ? AND deleted_at IS NULL",
                (media_id, user["id"]),
            ).fetchone()
            if not media_row:
                raise APIError("包含无权使用的媒体文件", 403, "media_forbidden")
            media_type = str(media_row["type"] or "image")
            if media_type == "video":
                video_count += 1
                if video_count > 1:
                    raise APIError("每个帖子最多上传 1 个视频", 400, "post_video_limit")
            elif media_type == "image":
                image_count += 1
                if image_count > 9:
                    raise APIError("每个帖子最多上传 9 张图片", 400, "post_image_limit")
            valid_media.append(dict(media_row))
        if image_count > 0 and video_count > 0:
            raise APIError("图片和视频不能混合发布，请选择 9 张图片或 1 个视频", 400, "post_media_mixed")
        # Region — client may pass any of (country, province, city) or
        # the resolved region_code. We canonicalise here so the row is
        # internally consistent and the index hits.
        country  = (data.get("country")  or user.get("country")  or "").strip().lower()
        province = (data.get("province") or user.get("province") or "").strip().lower()
        city     = (data.get("city")     or user.get("city")     or "").strip().lower()
        region_code = (data.get("region_code") or "").strip().lower()
        if not region_code:
            region_code = _resolve_region_code(country, province, city)
        elif not country:
            country, province, city = _parse_region_code(region_code)
        language = _normalize_language_tag(data.get("language") or user.get("app_language") or "")
        post_id = str(uuid.uuid4())
        created_ts = now_iso()
        # Initialize last_activity_at = created_at so the 正在发生 radar can filter
        # and sort on the bare column (no COALESCE/NULLIF, index-friendly). A live
        # post always carries a real activity timestamp; comments bump it forward.
        conn.execute(
            "INSERT INTO posts (id, author_id, content, repost_of_id, view_count, status, country, province, city, region_code, content_type, attributes, language, created_at, updated_at, last_activity_at) VALUES (?, ?, ?, ?, 1, 'active', ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
            (post_id, user["id"], content, repost_of_id, country, province, city, region_code, content_type, attributes, language, created_ts, created_ts, created_ts),
        )
        for tag in extract_tags(content):
            conn.execute("INSERT OR IGNORE INTO post_tags VALUES (?, ?)", (post_id, tag))
        explicit_tags = data.get("tags") or []
        for tag in explicit_tags:
            normalized = str(tag).strip().lstrip("#").lower()
            if normalized:
                conn.execute("INSERT OR IGNORE INTO post_tags VALUES (?, ?)", (post_id, normalized))
        for index, media_item in enumerate(valid_media):
            media_id = media_item["id"]
            media_type = media_item.get("type") or "image"
            processing_status = "pending" if media_type == "video" else "ready"
            conn.execute(
                """
                INSERT INTO post_media (
                    id, post_id, media_id, uploaded_file_id, media_type, sort_index, sort_order, is_cover,
                    duration_seconds, width, height, processing_status, created_at, updated_at
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    str(uuid.uuid4()), post_id, media_id, media_id, media_type, index, index,
                    1 if index == 0 else 0,
                    float(media_item.get("duration") or 0), int(media_item.get("width") or 0), int(media_item.get("height") or 0),
                    processing_status, now_iso(), now_iso(),
                ),
            )
            conn.execute(
                "UPDATE uploaded_files SET entity_type = 'post', entity_id = ?, updated_at = ? WHERE id = ? AND user_id = ?",
                (post_id, now_iso(), media_id, user["id"]),
            )
        if content_type not in HIGH_INTENT_POST_TYPES:
            reputation_apply_event(conn, user["id"], "first_post", target_kind="post", target_id=post_id)
            reputation_apply_event(
                conn,
                user["id"],
                reputation_rule_for_post_type(content_type),
                target_kind="post",
                target_id=post_id,
                metadata={"content_type": content_type},
            )
        # 邀请裂变: posting is the invitee's first *valuable* action — the moment
        # a pending referral qualifies and both sides are paid. Idempotent (only
        # a still-pending referral for THIS user advances; everyone else's lookup
        # is a cheap indexed miss), and self-contained inside its own money_atomic
        # so a payout failure can never roll back the already-committed post.
        try:
            qualify_referral_atomic(conn, user["id"])
        except Exception:
            pass
        # Track anyone already pinged for this post so @mentions don't double-notify.
        mention_skip: set[str] = set()
        if repost_of_id:
            original = conn.execute("SELECT author_id FROM posts WHERE id = ?", (repost_of_id,)).fetchone()
            if original and original["author_id"] != user["id"]:
                conn.execute(
                    "INSERT INTO notifications (id, user_id, actor_id, type, target_post_id, content, created_at) VALUES (?, ?, ?, 'repost', ?, ?, ?)",
                    (str(uuid.uuid4()), original["author_id"], user["id"], repost_of_id, content, now_iso()),
                )
                HUB.publish(original["author_id"], {"type": "notification", "kind": "repost"})
                server_apns.enqueue(original["author_id"], ntype="repost", actor_id=user["id"],
                                    content=content, post_id=repost_of_id)
                mention_skip.add(original["author_id"])
        # @mentions in the body (B6): notify each real @handle, excluding anyone
        # already pinged for this post (e.g. the repost target author).
        notify_mentions(conn, content, actor_id=user["id"], post_id=post_id,
                        already_notified=mention_skip)
        row = dict(conn.execute("SELECT * FROM posts WHERE id = ?", (post_id,)).fetchone())
        posts = fetch_posts_with_extras(conn, [row], user["id"])
        HUB.broadcast([user["id"]], {"type": "post_created", "post_id": post_id})
        # Drop derived caches so the new post shows up on hot / trending
        # without waiting for the 30s TTL.
        invalidate_public_ranking_caches()
        self.send_json({"post": posts[0]})

    def api_post_detail(self, conn: sqlite3.Connection, post_id: str) -> None:
        viewer = self.current_session(conn)
        row = conn.execute("SELECT * FROM posts WHERE id = ? AND deleted_at IS NULL", (post_id,)).fetchone()
        if not row:
            raise APIError("帖子不存在", 404, "post_not_found")
        row_dict_value = dict(row)
        viewer_id = viewer["user_id"] if viewer else None
        if row_dict_value.get("status") not in VISIBLE_POST_STATUSES and row_dict_value.get("author_id") != viewer_id:
            viewer_user = conn.execute("SELECT role FROM users WHERE id = ?", (viewer_id,)).fetchone() if viewer_id else None
            if not viewer_user or viewer_user["role"] != "admin":
                raise APIError("帖子不存在", 404, "post_not_found")
        posts = fetch_posts_with_extras(conn, [row_dict_value], viewer_id)
        self.send_json({"post": posts[0], "viewer": {"id": viewer_id} if viewer_id else None, "canInteract": bool(viewer_id), "can_interact": bool(viewer_id)})

    def api_edit_post(self, conn: sqlite3.Connection, post_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM posts WHERE id = ?", (post_id,)).fetchone()
        if not row:
            raise APIError("帖子不存在", 404, "post_not_found")
        if row["author_id"] != user["id"]:
            raise APIError("只能编辑自己的帖子", 403, "forbidden")
        data = self.read_json()
        if "content" in data:
            content = (data["content"] or "").strip()
            conn.execute("UPDATE posts SET content = ?, updated_at = ? WHERE id = ?", (content, now_iso(), post_id))
            conn.execute("DELETE FROM post_tags WHERE post_id = ?", (post_id,))
            for tag in extract_tags(content):
                conn.execute("INSERT OR IGNORE INTO post_tags VALUES (?, ?)", (post_id, tag))
        # Allow editing the typed attributes blob (e.g. mark a
        # secondhand listing as sold, change a job's salary range).
        # `content_type` is intentionally immutable post-creation —
        # changing it would invalidate every cached card.
        if "attributes" in data:
            current_type = (conn.execute("SELECT content_type FROM posts WHERE id = ?", (post_id,)).fetchone() or {})
            ct = current_type["content_type"] if current_type else "dynamic"
            attrs = normalize_post_attributes(ct, data["attributes"])
            conn.execute("UPDATE posts SET attributes = ?, updated_at = ? WHERE id = ?", (attrs, now_iso(), post_id))
        fresh = dict(conn.execute("SELECT * FROM posts WHERE id = ?", (post_id,)).fetchone())
        posts = fetch_posts_with_extras(conn, [fresh], user["id"])
        self.send_json({"post": posts[0]})

    def api_delete_post(self, conn: sqlite3.Connection, post_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT author_id FROM posts WHERE id = ?", (post_id,)).fetchone()
        if not row:
            raise APIError("帖子不存在", 404, "post_not_found")
        if row["author_id"] != user["id"]:
            raise APIError("只能删除自己的帖子", 403, "forbidden")
        conn.execute("UPDATE posts SET status = 'deleted', deleted_at = ?, updated_at = ? WHERE id = ?", (now_iso(), now_iso(), post_id))
        conn.execute(
            """
            UPDATE uploaded_files
               SET status = 'deleted', deleted_at = ?, updated_at = ?
             WHERE entity_type = 'post' AND entity_id = ? AND user_id = ? AND deleted_at IS NULL
            """,
            (now_iso(), now_iso(), post_id, user["id"]),
        )
        retire_reposts_of_deleted_post(conn, post_id)
        invalidate_public_ranking_caches()
        _cache_invalidate("feed:")
        self.send_json({"ok": True})

    def api_post_interaction(self, conn: sqlite3.Connection, post_id: str, kind: str, on: bool) -> None:
        user = self.require_user(conn)
        post = conn.execute("SELECT author_id, content_type FROM posts WHERE id = ? AND deleted_at IS NULL", (post_id,)).fetchone()
        if not post:
            raise APIError("帖子不存在", 404, "post_not_found")
        existing = conn.execute(
            "SELECT id FROM interactions WHERE target_id = ? AND user_id = ? AND kind = ?",
            (post_id, user["id"], kind),
        ).fetchone()
        # Self-interaction never counts toward heat (an author can't like/收藏/
        # repost their own post into the 热榜). The interactions row is still
        # written (so the client reflects the state), but the denormalized
        # counter — the ONLY thing ranking reads — is left untouched. Kept in
        # lock-step with reconcile_post_counters, which excludes the same rows,
        # so the 6h self-heal can't drift the count back up.
        is_self = post["author_id"] == user["id"]
        if on and not existing:
            # OR IGNORE + the UNIQUE(target_id,user_id,kind) index (migration 94)
            # makes the write idempotent and closes the check-then-insert race:
            # if two concurrent requests both pass `not existing`, only one row is
            # actually inserted. Bump the counter ONLY when we truly inserted
            # (rowcount == 1), so a raced duplicate can't double-count the heat.
            cur = conn.execute(
                "INSERT OR IGNORE INTO interactions (id, target_id, user_id, kind, created_at) VALUES (?, ?, ?, ?, ?)",
                (str(uuid.uuid4()), post_id, user["id"], kind, now_iso()),
            )
            if not is_self and (cur.rowcount or 0) > 0:
                bump_post_counter_for_kind(conn, post_id, kind, +1)
            if kind == "bookmark":
                reputation_apply_event(
                    conn,
                    user["id"],
                    "first_bookmark",
                    actor_user_id=user["id"],
                    target_kind="post",
                    target_id=post_id,
                )
            if kind == "like" and post["author_id"] != user["id"]:
                reputation_apply_event(
                    conn,
                    post["author_id"],
                    "content_liked",
                    actor_user_id=user["id"],
                    target_kind="post",
                    target_id=post_id,
                    metadata={"content_type": post["content_type"] or "dynamic"},
                )
                conn.execute(
                    "INSERT INTO notifications (id, user_id, actor_id, type, target_post_id, content, created_at) VALUES (?, ?, ?, 'like', ?, '', ?)",
                    (str(uuid.uuid4()), post["author_id"], user["id"], post_id, now_iso()),
                )
                HUB.publish(post["author_id"], {"type": "notification", "kind": "like", "post_id": post_id})
                server_apns.enqueue(post["author_id"], ntype="like", actor_id=user["id"], post_id=post_id)
            if kind == "bookmark" and post["author_id"] != user["id"]:
                reputation_apply_event(
                    conn,
                    post["author_id"],
                    "content_bookmarked",
                    actor_user_id=user["id"],
                    target_kind="post",
                    target_id=post_id,
                    metadata={"content_type": post["content_type"] or "dynamic"},
                )
        elif not on and existing:
            conn.execute("DELETE FROM interactions WHERE id = ?", (existing["id"],))
            if not is_self:
                bump_post_counter_for_kind(conn, post_id, kind, -1)
        # 不感兴趣 (dismiss) is a personal recommender signal, not heat: it maps to
        # no counter column (bump_post_counter_for_kind ignores it), doesn't
        # notify the author, and doesn't feed 热榜/正在发生. Its ONE side effect is
        # the viewer's own interest profile, so bust that cache immediately —
        # otherwise the demoted author/tags would keep surfacing for up to
        # KAIX_RECPROFILE_TTL_SEC after the user said "不感兴趣", which feels broken.
        if kind == "dismiss":
            _cache_invalidate(f"recprofile:{user['id']}")
        # No cache invalidation here: the 热榜/推荐 tolerate up to ~60s of
        # staleness and the hot_score refresher + 30s TTLs converge on their own.
        # A cache bust on every like/收藏 was pure write amplification against the
        # shared ranking caches (删帖 / admin下架 still invalidate — those must be
        # immediate).
        fresh = dict(conn.execute("SELECT * FROM posts WHERE id = ?", (post_id,)).fetchone())
        posts = fetch_posts_with_extras(conn, [fresh], user["id"])
        self.send_json({"post": posts[0]})

    def api_meetup_join(self, conn: sqlite3.Connection, post_id: str, on: bool) -> None:
        """RSVP to a 約局 (meetup / dining / event). Reuses the interactions table
        (kind='meetup_join'); enforces the post's people_limit capacity. Returns
        the refreshed post so the client gets the new going count + joined state."""
        user = self.require_user(conn)
        post = conn.execute("SELECT * FROM posts WHERE id = ? AND deleted_at IS NULL", (post_id,)).fetchone()
        if not post:
            raise APIError("帖子不存在", 404, "post_not_found")
        if (post["content_type"] or "") not in ("meetup", "dining", "event"):
            raise APIError("这条内容不支持报名", 400, "not_a_meetup")
        existing = conn.execute(
            "SELECT id FROM interactions WHERE target_id = ? AND user_id = ? AND kind = 'meetup_join'",
            (post_id, user["id"]),
        ).fetchone()
        if on and not existing:
            attrs = decode_post_attributes(post["attributes"])
            try:
                limit = int(attrs.get("people_limit") or attrs.get("capacity") or 0)
            except (TypeError, ValueError):
                limit = 0
            going = conn.execute(
                "SELECT COUNT(*) AS c FROM interactions WHERE target_id = ? AND kind = 'meetup_join'",
                (post_id,),
            ).fetchone()["c"]
            if limit > 0 and int(going) >= limit:
                raise APIError("名额已满", 409, "meetup_full")
            conn.execute(
                "INSERT INTO interactions (id, target_id, user_id, kind, created_at) VALUES (?, ?, ?, 'meetup_join', ?)",
                (str(uuid.uuid4()), post_id, user["id"], now_iso()),
            )
        elif not on and existing:
            conn.execute("DELETE FROM interactions WHERE id = ?", (existing["id"],))
        fresh = dict(conn.execute("SELECT * FROM posts WHERE id = ?", (post_id,)).fetchone())
        posts = fetch_posts_with_extras(conn, [fresh], user["id"])
        self.send_json({"post": posts[0]})

    def api_meetup_participants(self, conn: sqlite3.Connection, post_id: str) -> None:
        """The going-list for a 約局 — who's joined, for the host + attendees."""
        viewer = self.current_session(conn)
        rows = conn.execute(
            "SELECT user_id FROM interactions WHERE target_id = ? AND kind = 'meetup_join' ORDER BY created_at",
            (post_id,),
        ).fetchall()
        ids = [r["user_id"] for r in rows]
        users = []
        if ids:
            ph = ",".join("?" * len(ids))
            umap = {u["id"]: u for u in conn.execute(f"SELECT * FROM users WHERE id IN ({ph})", ids)}
            users = [serialize_user(dict(umap[i])) for i in ids if i in umap]
        self.send_json({"participants": users, "count": len(users)})

    def api_repost(self, conn: sqlite3.Connection, post_id: str, on: bool) -> None:
        user = self.require_user(conn)
        # Soft-deleted rows still exist, so look up without the deleted filter:
        # you can only repost a *live* post, but undoing a repost must keep
        # working even after the original was deleted (otherwise a lingering
        # repost can never be cleared).
        post = conn.execute("SELECT * FROM posts WHERE id = ?", (post_id,)).fetchone()
        if not post:
            raise APIError("帖子不存在", 404, "post_not_found")
        if on and (post["deleted_at"] or post["status"] not in ("published", "active")):
            raise APIError("帖子不存在", 404, "post_not_found")
        changed = False
        if on:
            try:
                conn.execute(
                    "INSERT INTO interactions (id, target_id, user_id, kind, created_at) VALUES (?, ?, ?, 'repost', ?)",
                    (str(uuid.uuid4()), post_id, user["id"], now_iso()),
                )
                changed = True
                bump_post_counter(conn, post_id, "repost_count", +1)
            except sqlite3.IntegrityError:
                pass
            existing_repost_post = conn.execute(
                """
                SELECT id FROM posts
                 WHERE author_id = ? AND repost_of_id = ?
                   AND COALESCE(content, '') = ''
                   AND deleted_at IS NULL
                 LIMIT 1
                """,
                (user["id"], post_id),
            ).fetchone()
            if not existing_repost_post:
                created = now_iso()
                conn.execute(
                    """
                    INSERT INTO posts (
                        id, author_id, content, repost_of_id, view_count, status,
                        country, province, city, region_code, content_type, attributes,
                        created_at, updated_at, last_activity_at
                    ) VALUES (?, ?, '', ?, 1, 'active', ?, ?, ?, ?, 'dynamic', '{}', ?, ?, ?)
                    """,
                    (
                        str(uuid.uuid4()), user["id"], post_id,
                        post["country"] or "", post["province"] or "", post["city"] or "", post["region_code"] or "",
                        created, created, created,
                    ),
                )
                changed = True
            if changed and post["author_id"] != user["id"]:
                conn.execute(
                    "INSERT INTO notifications (id, user_id, actor_id, type, target_post_id, content, created_at) VALUES (?, ?, ?, 'repost', ?, '', ?)",
                    (str(uuid.uuid4()), post["author_id"], user["id"], post_id, now_iso()),
                )
                HUB.publish(post["author_id"], {"type": "notification", "kind": "repost"})
                server_apns.enqueue(post["author_id"], ntype="repost", actor_id=user["id"], post_id=post_id)
        else:
            removed = conn.execute(
                "DELETE FROM interactions WHERE target_id = ? AND user_id = ? AND kind = 'repost'",
                (post_id, user["id"]),
            )
            if (removed.rowcount or 0) > 0:
                bump_post_counter(conn, post_id, "repost_count", -1)
            conn.execute(
                """
                UPDATE posts
                   SET status = 'deleted', deleted_at = ?, updated_at = ?
                 WHERE author_id = ? AND repost_of_id = ?
                   AND COALESCE(content, '') = ''
                   AND deleted_at IS NULL
                """,
                (now_iso(), now_iso(), user["id"], post_id),
            )
        _cache_invalidate("feed:")
        invalidate_public_ranking_caches()
        fresh = dict(conn.execute("SELECT * FROM posts WHERE id = ?", (post_id,)).fetchone())
        posts = fetch_posts_with_extras(conn, [fresh], user["id"])
        self.send_json({"post": posts[0]})

    def api_vote_poll(self, conn: sqlite3.Connection, post_id: str) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        try:
            option_index = int(data.get("option_index"))
        except (TypeError, ValueError):
            raise APIError("请选择投票选项", 400, "invalid_poll_vote")
        post = conn.execute("SELECT * FROM posts WHERE id = ? AND deleted_at IS NULL", (post_id,)).fetchone()
        if not post or post["content_type"] != "poll":
            raise APIError("投票不存在", 404, "poll_not_found")
        attrs = decode_post_attributes(post["attributes"])
        options = poll_options_from_attributes(attrs)
        if not options:
            raise APIError("投票选项异常", 400, "invalid_poll")
        if poll_is_closed(attrs.get("expires_at")):
            raise APIError("投票已截止", 400, "poll_closed")
        if option_index < 0 or option_index >= len(options):
            raise APIError("投票选项不存在", 400, "invalid_poll_vote")
        conn.execute(
            """
            INSERT INTO post_poll_votes (post_id, user_id, option_index, created_at)
            VALUES (?, ?, ?, ?)
            ON CONFLICT(post_id, user_id)
            DO UPDATE SET option_index = excluded.option_index, created_at = excluded.created_at
            """,
            (post_id, user["id"], option_index, now_iso()),
        )
        fresh = dict(conn.execute("SELECT * FROM posts WHERE id = ?", (post_id,)).fetchone())
        posts = fetch_posts_with_extras(conn, [fresh], user["id"])
        self.send_json({"post": posts[0]})

    def api_view_post(self, conn: sqlite3.Connection, post_id: str) -> None:
        # Throttle view bumps to once per (viewer, post, hour). The
        # previous behaviour let any client spam +1 forever, which
        # both inflated heat scores and gave authors a trivial way to
        # juice their own metrics.
        viewer = self.current_session(conn)
        key = f"view:{post_id}:{viewer['user_id'] if viewer else self._client_ip()}"
        if _cache_get(key) is None:
            conn.execute("UPDATE posts SET view_count = view_count + 1 WHERE id = ?", (post_id,))
            _cache_put(key, True, ttl_seconds=3600)
        self.send_json({"ok": True})

    def api_list_comments(self, conn: sqlite3.Connection, post_id: str, query: dict[str, str]) -> None:
        viewer = self.current_session(conn)
        viewer_id = viewer["user_id"] if viewer else None
        sort = query.get("sort") or "top"
        # H3: opt-in keyset pagination. No `limit` → unchanged full-set behavior
        # (honors top/new sort globally). With `limit`, paginate chronologically
        # (newest-first) with a real `next_cursor` for "load earlier".
        limit_raw = str(query.get("limit") or "").strip()
        page_limit: int | None = None
        if limit_raw:
            try:
                page_limit = max(1, min(int(limit_raw), 100))
            except ValueError:
                raise APIError("limit 无效", 400, "invalid_limit")
        next_cursor: str | None = None
        if page_limit is None:
            rows = list(conn.execute(
                "SELECT * FROM comments WHERE post_id = ? AND deleted_at IS NULL ORDER BY created_at DESC",
                (post_id,),
            ))
        else:
            clauses = ["post_id = ?", "deleted_at IS NULL"]
            cparams: list[Any] = [post_id]
            before = cursor_decode(query.get("cursor") or query.get("before"))
            if before:
                clauses.append("(created_at < ? OR (created_at = ? AND id < ?))")
                cparams.extend([before[0], before[0], before[1]])
            fetched = list(conn.execute(
                f"SELECT * FROM comments WHERE {' AND '.join(clauses)} "
                f"ORDER BY created_at DESC, id DESC LIMIT ?",
                [*cparams, page_limit + 1],
            ))
            has_more = len(fetched) > page_limit
            rows = fetched[:page_limit]
            if has_more and rows:
                oldest = rows[-1]
                next_cursor = cursor_encode(oldest["created_at"], oldest["id"])
        ids = [r["id"] for r in rows]
        like_counts: dict[str, int] = {}
        liked_set: set[str] = set()
        if ids:
            placeholders = ",".join("?" * len(ids))
            for row in conn.execute(
                f"SELECT target_id, COUNT(*) AS c FROM interactions WHERE kind='commentLike' AND target_id IN ({placeholders}) GROUP BY target_id",
                ids,
            ):
                like_counts[row["target_id"]] = row["c"]
            if viewer_id:
                for row in conn.execute(
                    f"SELECT target_id FROM interactions WHERE kind='commentLike' AND user_id=? AND target_id IN ({placeholders})",
                    [viewer_id] + ids,
                ):
                    liked_set.add(row["target_id"])
        author_ids = list({r["author_id"] for r in rows})
        author_map = fetch_users_by_ids(conn, author_ids)
        comments = [
            serialize_comment(
                dict(r),
                {
                    "like_count": like_counts.get(r["id"], 0),
                    "liked": r["id"] in liked_set,
                    "author": author_map.get(r["author_id"]),
                },
            )
            for r in rows
        ]
        if page_limit is None and sort == "top":
            comments.sort(key=lambda c: (c["like_count"], c["created_at"]), reverse=True)
        else:
            # paginated mode is chronological so the keyset cursor stays valid
            comments.sort(key=lambda c: c["created_at"], reverse=True)
        self.send_json({"items": comments, "next_cursor": next_cursor, "nextCursor": next_cursor})

    def api_create_comment(self, conn: sqlite3.Connection, post_id: str) -> None:
        user = self.require_user(conn)
        self._enforce_not_muted(user)  # UGC-5
        if not rate_check("comment:" + user["id"], "comment"):  # UGC-6
            raise APIError("评论过于频繁，请稍后再试", 429, "rate_limited")
        data = self.read_json()
        content = (data.get("content") or "").strip()
        if not content:
            raise APIError("评论不能为空", 400, "empty_comment")
        if len(content) > 2000:
            raise APIError("评论过长", 400, "comment_too_long")
        enforce_content_policy(content)  # H4: reject banned/scam/illegal text on create
        post = conn.execute("SELECT author_id, content_type FROM posts WHERE id = ? AND deleted_at IS NULL", (post_id,)).fetchone()
        if not post:
            raise APIError("帖子不存在", 404, "post_not_found")
        parent_comment_id = str(data.get("parent_comment_id") or "").strip()
        reply_to_user_id = str(data.get("reply_to_user_id") or "").strip()
        parent_comment: dict[str, Any] | None = None
        if parent_comment_id:
            parent_row = conn.execute(
                "SELECT id, author_id, parent_comment_id FROM comments WHERE id = ? AND post_id = ? AND deleted_at IS NULL",
                (parent_comment_id, post_id),
            ).fetchone()
            if not parent_row:
                raise APIError("要回复的评论不存在", 404, "parent_comment_not_found")
            parent_comment = dict(parent_row)
            if parent_comment.get("parent_comment_id"):
                root_row = conn.execute(
                    "SELECT id, author_id FROM comments WHERE id = ? AND post_id = ? AND deleted_at IS NULL",
                    (parent_comment["parent_comment_id"], post_id),
                ).fetchone()
                if root_row:
                    parent_comment_id = root_row["id"]
            if not reply_to_user_id:
                reply_to_user_id = parent_comment["author_id"]
            elif not conn.execute("SELECT 1 FROM users WHERE id = ? AND deleted_at IS NULL", (reply_to_user_id,)).fetchone():
                reply_to_user_id = parent_comment["author_id"]
        else:
            reply_to_user_id = ""
        comment_id = str(uuid.uuid4())
        now = now_iso()
        conn.execute(
            "INSERT INTO comments (id, post_id, author_id, content, parent_comment_id, reply_to_user_id, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?)",
            (comment_id, post_id, user["id"], content, parent_comment_id or None, reply_to_user_id or None, now, now),
        )
        bump_post_counter(conn, post_id, "comment_count", +1)
        # Mark the post active *now* so the 正在发生 radar resurfaces it even if it
        # was created days ago (recency-of-activity, not just recency-of-creation).
        conn.execute("UPDATE posts SET last_activity_at = ? WHERE id = ?", (now, post_id))
        if post["author_id"] != user["id"]:
            reputation_apply_event(
                conn,
                post["author_id"],
                "content_commented",
                actor_user_id=user["id"],
                target_kind="post",
                target_id=post_id,
                metadata={"content_type": post["content_type"] or "dynamic"},
            )
            if (post["content_type"] or "") == "question" and len(content) >= 10:
                reputation_apply_event(
                    conn,
                    user["id"],
                    "comment_on_question",
                    actor_user_id=user["id"],
                    target_kind="post",
                    target_id=post_id,
                )
        recipients: dict[str, str] = {}
        if parent_comment_id:
            if reply_to_user_id and reply_to_user_id != user["id"]:
                recipients[reply_to_user_id] = "reply"
            if parent_comment and parent_comment["author_id"] != user["id"]:
                recipients.setdefault(parent_comment["author_id"], "reply")
        if post["author_id"] != user["id"]:
            recipients.setdefault(post["author_id"], "comment")
        for recipient_id, ntype in recipients.items():
            conn.execute(
                "INSERT INTO notifications (id, user_id, actor_id, type, target_post_id, target_comment_id, content, created_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?)",
                (str(uuid.uuid4()), recipient_id, user["id"], ntype, post_id, comment_id, content[:140], now),
            )
            HUB.publish(recipient_id, {"type": "notification", "kind": ntype, "post_id": post_id, "comment_id": comment_id})
            server_apns.enqueue(recipient_id, ntype=ntype, actor_id=user["id"],
                                content=content[:140], post_id=post_id)
        # @mentions in the comment body (B6): notify each real @handle, skipping
        # anyone who already got a reply/comment notification for this comment.
        notify_mentions(conn, content, actor_id=user["id"], post_id=post_id,
                        comment_id=comment_id, already_notified=set(recipients.keys()), now=now)
        row = dict(conn.execute("SELECT * FROM comments WHERE id = ?", (comment_id,)).fetchone())
        comment = serialize_comment(row, {"author": serialize_user(user), "like_count": 0, "liked": False})
        self.send_json({"comment": comment})

    def api_delete_comment(self, conn: sqlite3.Connection, comment_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM comments WHERE id = ?", (comment_id,)).fetchone()
        if not row:
            raise APIError("评论不存在", 404, "comment_not_found")
        post = conn.execute("SELECT author_id FROM posts WHERE id = ?", (row["post_id"],)).fetchone()
        if row["author_id"] != user["id"] and (not post or post["author_id"] != user["id"]):
            raise APIError("无权删除", 403, "forbidden")
        # Compare-and-swap: only the writer whose UPDATE actually flips a live
        # comment to deleted (rowcount == 1) may decrement the counter. The old
        # check-then-act (read stale deleted_at, then unconditional UPDATE, then
        # decrement on the stale flag) let two concurrent deletes both pass the
        # `not row["deleted_at"]` guard and double-decrement comment_count. Mirrors
        # mark_order_paid's CAS.
        now = now_iso()
        cur = conn.execute(
            "UPDATE comments SET deleted_at = ?, updated_at = ? WHERE id = ? AND deleted_at IS NULL",
            (now, now, comment_id),
        )
        if cur.rowcount == 1:
            bump_post_counter(conn, row["post_id"], "comment_count", -1)
        self.send_json({"ok": True})

    def api_comment_like(self, conn: sqlite3.Connection, comment_id: str, on: bool) -> None:
        user = self.require_user(conn)
        existing = conn.execute(
            "SELECT id FROM interactions WHERE target_id = ? AND user_id = ? AND kind = 'commentLike'",
            (comment_id, user["id"]),
        ).fetchone()
        if on and not existing:
            conn.execute(
                "INSERT INTO interactions (id, target_id, user_id, kind, created_at) VALUES (?, ?, ?, 'commentLike', ?)",
                (str(uuid.uuid4()), comment_id, user["id"], now_iso()),
            )
        elif not on and existing:
            conn.execute("DELETE FROM interactions WHERE id = ?", (existing["id"],))
        self.send_json({"ok": True, "liked": on})

    def api_search(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        viewer = self.current_session(conn)
        viewer_id = viewer["user_id"] if viewer else None
        viewer_country = ""
        if viewer_id:
            viewer_row = conn.execute("SELECT country FROM users WHERE id = ?", (viewer_id,)).fetchone()
            viewer_country = (viewer_row["country"] if viewer_row else "") or ""
        q = (query.get("q") or "").strip()
        kind = query.get("kind") or "all"
        if not q:
            self.send_json({"posts": [], "listings": [], "users": [], "topics": [], "guide": [], "viewer": {"id": viewer_id} if viewer_id else None, "canInteract": bool(viewer_id), "can_interact": bool(viewer_id)})
            return
        if viewer_id:
            # Dedupe by (user, query) and cap per-user history so the table can't
            # grow a row on every keystroke-search forever (reads already GROUP BY
            # query; this stops the underlying row churn / unbounded retention).
            conn.execute("DELETE FROM search_history WHERE user_id = ? AND query = ?", (viewer_id, q))
            conn.execute(
                "INSERT INTO search_history (id, user_id, query, created_at) VALUES (?, ?, ?, ?)",
                (str(uuid.uuid4()), viewer_id, q, now_iso()),
            )
            conn.execute(
                "DELETE FROM search_history WHERE user_id = ? AND id NOT IN ("
                "SELECT id FROM search_history WHERE user_id = ? ORDER BY created_at DESC LIMIT 50)",
                (viewer_id, viewer_id),
            )
        like = f"%{q}%"
        posts: list[dict[str, Any]] = []
        listings: list[dict[str, Any]] = []
        users: list[dict[str, Any]] = []
        topics: list[dict[str, Any]] = []
        if kind in ("all", "post"):
            country_clause = "AND country = ?" if viewer_country else ""
            params: tuple[Any, ...] = (like, viewer_country) if viewer_country else (like,)
            # Match on content only. The old OR-chain also pattern-matched
            # country/province/city (slug codes a user never types),
            # content_type (q="ran" surfaced every "rant" post) and the raw
            # attributes JSON (matched on internal keys) — all noise, and the
            # multi-column OR forced a full-table scan on every search. A
            # single content predicate is wrong-match-free and uses the
            # pg_trgm GIN index (migration 40) on PostgreSQL.
            rows = list(conn.execute(
                f"""
                SELECT * FROM posts
                WHERE deleted_at IS NULL
                  AND status IN ('published', 'active')
                  AND content LIKE ?
                  {country_clause}
                ORDER BY created_at DESC LIMIT 30
                """,
                params,
            ))
            posts = fetch_posts_with_extras(conn, [dict(r) for r in rows], viewer_id)
        if kind in ("all", "listing", "listings", "secondhand", "rental", "job"):
            country_clause = "AND country_code = ?" if viewer_country else ""
            type_clause = ""
            type_params: list[Any] = []
            if kind in {"secondhand", "rental", "job"}:
                type_clause = "AND type = ?"
                type_params.append(kind)
            params = [like, like, like, like, *type_params]
            if viewer_country:
                params.append(viewer_country)
            rows = list(conn.execute(
                f"""
                SELECT * FROM city_listings
                WHERE deleted_at IS NULL
                  AND status IN ('published', 'reserved')
                  AND (title LIKE ? OR description LIKE ? OR location_text LIKE ? OR category LIKE ?)
                  {type_clause}
                  {country_clause}
                ORDER BY is_promoted DESC, updated_at DESC LIMIT 30
                """,
                params,
            ))
            listings = fetch_listings_with_extras(conn, [dict(r) for r in rows], viewer_id)
        if kind in ("all", "user"):
            country_clause = "AND country = ?" if viewer_country else ""
            params = (like, like, viewer_country) if viewer_country else (like, like)
            rows = list(conn.execute(
                f"SELECT * FROM users WHERE (handle LIKE ? OR display_name LIKE ?) AND deleted_at IS NULL {country_clause} LIMIT 30",
                params,
            ))
            users = [serialize_user(dict(r)) for r in rows]
        if kind in ("all", "topic"):
            country_clause = "AND p.country = ?" if viewer_country else ""
            params = (q.lower().lstrip("#") + "%", viewer_country) if viewer_country else (q.lower().lstrip("#") + "%",)
            rows = list(conn.execute(
                f"""
                SELECT tag, COUNT(*) AS post_count
                FROM post_tags t
                JOIN posts p ON p.id = t.post_id
                WHERE t.tag LIKE ? AND p.deleted_at IS NULL AND p.status IN ('published', 'active')
                  {country_clause}
                GROUP BY tag ORDER BY post_count DESC LIMIT 30
                """,
                params,
            ))
            topics = [{"tag": r["tag"], "post_count": int(r["post_count"])} for r in rows]
        guide: list[dict[str, Any]] = []
        if kind in ("all", "guide"):
            # Guide content (articles + products) so the unified search isn't blind
            # to the Guide library. Country-scoped (guide content currently = jp).
            gc = viewer_country or GUIDE_DEFAULT_COUNTRY
            for r in conn.execute(
                "SELECT id, slug, title, summary FROM guide_articles WHERE country = ? AND status = 'published' "
                "AND (title LIKE ? OR summary LIKE ?) ORDER BY is_featured DESC, updated_at DESC LIMIT 12",
                (gc, like, like),
            ):
                d = dict(r)
                guide.append({"kind": "article", "id": d["id"], "slug": d.get("slug") or "",
                              "title": d.get("title") or "", "subtitle": d.get("summary") or ""})
            for r in conn.execute(
                "SELECT id, slug, title, subtitle FROM guide_products WHERE country = ? "
                "AND status IN ('published','coming_soon') AND title LIKE ? "
                "ORDER BY is_featured DESC, sort_order ASC LIMIT 12",
                (gc, like),
            ):
                d = dict(r)
                guide.append({"kind": "product", "id": d["id"], "slug": d.get("slug") or "",
                              "title": d.get("title") or "", "subtitle": d.get("subtitle") or ""})
        self.send_json({"posts": posts, "listings": listings, "users": users, "topics": topics, "guide": guide, "viewer": {"id": viewer_id} if viewer_id else None, "canInteract": bool(viewer_id), "can_interact": bool(viewer_id)})

    def api_search_history(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        # GROUP BY (not DISTINCT) so we can ORDER BY the recency aggregate:
        # PostgreSQL rejects `SELECT DISTINCT query ... ORDER BY created_at`
        # because the ORDER BY column isn't in the select list. GROUP BY query
        # + ORDER BY MAX(created_at) dedupes and keeps most-recent-first, and
        # is valid on both SQLite and Postgres.
        rows = conn.execute(
            "SELECT query FROM search_history WHERE user_id = ? GROUP BY query ORDER BY MAX(created_at) DESC LIMIT 20",
            (user["id"],),
        )
        self.send_json({"items": [r["query"] for r in rows]})

    def api_clear_search_history(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        conn.execute("DELETE FROM search_history WHERE user_id = ?", (user["id"],))
        self.send_json({"ok": True})

    def api_trending(self, conn: sqlite3.Connection) -> None:
        viewer = self.current_session(conn)
        viewer_id = viewer["user_id"] if viewer else None
        viewer_country = ""
        if viewer_id:
            viewer_row = conn.execute("SELECT country FROM users WHERE id = ?", (viewer_id,)).fetchone()
            viewer_country = (viewer_row["country"] if viewer_row else "") or ""
        cache_scope = viewer_country or "all"
        # Heavy aggregation — cache per country for 30s so users who
        # registered in Japan only see Japan-side content in global
        # widgets too.
        cached_ids = _cache_get(f"trending:{cache_scope}:post_ids")
        cached_topics = _cache_get(f"trending:{cache_scope}:topics")
        cached_user_ids = _cache_get(f"trending:{cache_scope}:user_ids")
        if cached_ids is None:
            cutoff_24h = (datetime.now(timezone.utc) - timedelta(hours=24)).isoformat()
            country_clause = "AND p.country = ?" if viewer_country else ""
            params: tuple[Any, ...] = (cutoff_24h, viewer_country) if viewer_country else (cutoff_24h,)
            # Order by the precomputed, indexed hot_score (idx_posts_hot) instead
            # of a live heat expression — the most-hit global widget now resolves
            # to an index scan whose cost is independent of how many posts or
            # interactions exist. hot_score already bakes in recency decay; the
            # 24h window keeps "trending = right now" semantics.
            # Over-fetch (60) so the per-author cap can drop a prolific author's
            # surplus and still fill the 20-slot rail. p.author_id is selected so
            # the cap runs in memory without a second query.
            id_rows = list(conn.execute(
                f"""
                SELECT p.id, p.author_id AS author_id, p.hot_score AS heat
                FROM posts p
                WHERE p.deleted_at IS NULL
                  AND p.status IN ('published', 'active')
                  AND p.created_at >= ?
                  {country_clause}
                ORDER BY p.hot_score DESC LIMIT 60
                """,
                params,
            ))
            # Author diversity: no author holds more than EXPLORE_MAX_POSTS_PER_AUTHOR
            # slots on the trending rail, keeping their highest-ranked posts.
            cached_ids = []
            _author_seen: dict[str, int] = {}
            for r in id_rows:
                aid = r["author_id"] or ""
                if aid:
                    if _author_seen.get(aid, 0) >= EXPLORE_MAX_POSTS_PER_AUTHOR:
                        continue
                    _author_seen[aid] = _author_seen.get(aid, 0) + 1
                cached_ids.append(r["id"])
                if len(cached_ids) >= 20:
                    break
            _cache_put(f"trending:{cache_scope}:post_ids", cached_ids, ttl_seconds=30)
        if cached_topics is None:
            try:
                # 热搜 = what's hot *now*, not all time. Window the tags to the last
                # 7 days, rank by the summed engagement-only heat of their posts
                # (hot_score_engaged, NOT hot_score — its freshness 曝光分 would let a
                # burst of brand-new posts inflate a tag), drop generic/location
                # filler (#东京 etc.), tiebreak on how many DIFFERENT authors use the
                # tag (blocks single-author stuffing). Velocity now compares this
                # window's summed heat against the PREVIOUS equal-length window's
                # (from the snapshot, item B3.6) plus a comment-increment signal,
                # instead of the crude recent-half-vs-older-half split.
                now = datetime.now(timezone.utc)
                win_cutoff = (now - timedelta(days=7)).isoformat()
                half_cutoff = (now - timedelta(hours=84)).isoformat()  # 3.5 days
                country_clause = "AND p.country = ?" if viewer_country else ""
                block_tags = sorted(HOT_BOARD_TAG_BLOCKLIST)
                block_clause = ("AND t.tag NOT IN (%s)" % ",".join("?" * len(block_tags))) if block_tags else ""
                # Window filter unified with api_discover_hot: a post is in-window
                # if it was created OR last active (a fresh comment) inside the 7d
                # window — so a resurfaced older thread counts toward its tag's
                # heat, matching the 热榜 semantics instead of created_at only.
                tparams: list[Any] = [half_cutoff, win_cutoff, win_cutoff]
                if viewer_country:
                    tparams.append(viewer_country)
                tparams.extend(block_tags)
                # Previous 7d national snapshot for this scope → heat velocity.
                prev_trend = _previous_topic_ranks(
                    conn, _topic_snapshot_scope_key("national", viewer_country or "all"), "7d"
                )
                cached_topics = []
                for r in conn.execute(
                    f"""
                    SELECT t.tag AS tag,
                           COUNT(DISTINCT p.id) AS c,
                           COUNT(DISTINCT p.author_id) AS authors,
                           COALESCE(SUM(p.hot_score_engaged), 0) AS heat,
                           SUM(COALESCE(p.comment_count, 0)) AS comments,
                           SUM(CASE WHEN p.created_at >= ? THEN 1 ELSE 0 END) AS recent_new
                    FROM post_tags t
                    JOIN posts p ON p.id = t.post_id
                    WHERE p.deleted_at IS NULL AND p.status IN ('published', 'active')
                      AND (p.created_at >= ?
                           OR COALESCE(NULLIF(p.last_activity_at, ''), p.created_at) >= ?)
                      {country_clause}
                      {block_clause}
                    GROUP BY t.tag
                    ORDER BY heat DESC, authors DESC, c DESC
                    LIMIT 20
                    """,
                    tparams,
                ):
                    row = dict(r)
                    related = int(row.get("c") or 0)
                    recent_new = int(row.get("recent_new") or 0)
                    older = max(0, related - recent_new)
                    heat_v = int(row.get("heat") or 0)
                    comments = int(row.get("comments") or 0)
                    prev_entry = prev_trend.get(row["tag"])
                    heat_gained = (heat_v - prev_entry["heat"]) if prev_entry else 0
                    # Snapshot heat velocity is the primary signal; comment growth
                    # and the new-vs-older post split are the fallback when there's
                    # no prior snapshot yet (first 7d of a fresh deploy).
                    if (prev_entry and heat_gained > 0) or (not prev_entry and (recent_new > older or comments > related)):
                        trend = "up"
                    elif (prev_entry and heat_gained < 0) or (not prev_entry and older > recent_new):
                        trend = "down"
                    else:
                        trend = "flat"
                    cached_topics.append({
                        "tag": row["tag"],
                        "post_count": related,
                        "heat": heat_v,
                        "heatDelta": heat_gained,
                        "trend": trend,
                    })
                # Cold-start / sparse city: if the windowed board is empty, fall
                # back to the all-time top tags so the rail is never blank.
                if not cached_topics:
                    fb_params: list[Any] = []
                    if viewer_country:
                        fb_params.append(viewer_country)
                    fb_params.extend(block_tags)
                    cached_topics = [
                        {"tag": r["tag"], "post_count": int(r["c"]), "heat": 0, "trend": "flat"}
                        for r in conn.execute(
                            f"""
                            SELECT t.tag, COUNT(*) AS c
                            FROM post_tags t
                            JOIN posts p ON p.id = t.post_id
                            WHERE p.deleted_at IS NULL AND p.status IN ('published', 'active')
                              {country_clause}
                              {block_clause}
                            GROUP BY t.tag ORDER BY c DESC LIMIT 20
                            """,
                            fb_params,
                        )
                    ]
                _cache_put(f"trending:{cache_scope}:topics", cached_topics, ttl_seconds=60)
            except Exception as exc:
                ERR_LOG.warning("trending topics degraded error=%s", exc)
                cached_topics = []
        if cached_user_ids is None:
            try:
                if viewer_country:
                    cached_user_ids = [r["id"] for r in conn.execute(
                        "SELECT id FROM users WHERE deleted_at IS NULL AND country = ? ORDER BY is_verified DESC, joined_at LIMIT 12",
                        (viewer_country,),
                    )]
                else:
                    cached_user_ids = [r["id"] for r in conn.execute(
                        "SELECT id FROM users WHERE deleted_at IS NULL ORDER BY is_verified DESC, joined_at LIMIT 12"
                    )]
                _cache_put(f"trending:{cache_scope}:user_ids", cached_user_ids, ttl_seconds=60)
            except Exception as exc:
                ERR_LOG.warning("trending users degraded error=%s", exc)
                cached_user_ids = []
        if cached_ids:
            placeholders = ",".join("?" * len(cached_ids))
            post_rows = list(conn.execute(
                f"SELECT * FROM posts WHERE id IN ({placeholders})", cached_ids,
            ))
            # Preserve heat order.
            order = {pid: i for i, pid in enumerate(cached_ids)}
            post_rows.sort(key=lambda r: order.get(r["id"], 1_000_000))
            posts = fetch_posts_with_extras(conn, [dict(r) for r in post_rows], viewer_id)
        else:
            posts = []
        users: list[dict[str, Any]] = []
        if cached_user_ids:
            try:
                placeholders = ",".join("?" * len(cached_user_ids))
                user_rows = list(conn.execute(
                    f"SELECT * FROM users WHERE id IN ({placeholders})", cached_user_ids,
                ))
                users = [serialize_user(dict(u)) for u in user_rows]
            except Exception as exc:
                ERR_LOG.warning("trending user hydration degraded error=%s", exc)
        # Admin-configurable right rail: applied post-cache (settings read is
        # cheap) so the heavy aggregation stays cached while the admin can
        # toggle sections or pin specific people to feature.
        rail = _site_settings(conn)
        if rail.get("right_rail_show_trending", "1") == "0":
            cached_topics = []
        pinned = [h.strip().lstrip("@") for h in re.split(r"[,\s，、]+", rail.get("right_rail_pinned_handles", "") or "") if h.strip()]
        if pinned:
            featured: list[dict[str, Any]] = []
            seen: set[str] = set()
            for handle in pinned[:8]:
                if handle.lower() in seen:
                    continue
                row = conn.execute("SELECT * FROM users WHERE handle = ? AND deleted_at IS NULL", (handle,)).fetchone()
                if row:
                    featured.append(serialize_user(dict(row)))
                    seen.add(handle.lower())
            users = featured
        elif rail.get("right_rail_show_recommended", "1") == "0":
            users = []
        self.send_json({
            "posts": posts,
            "topics": cached_topics,
            "users": users,
            "viewer": {"id": viewer_id} if viewer_id else None,
            "canInteract": bool(viewer_id),
            "can_interact": bool(viewer_id),
        })

    def api_trending_weekly_likes(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        viewer = self.current_session(conn)
        viewer_id = viewer["user_id"] if viewer else None
        viewer_country = ""
        if viewer_id:
            viewer_row = conn.execute("SELECT country FROM users WHERE id = ?", (viewer_id,)).fetchone()
            viewer_country = (viewer_row["country"] if viewer_row else "") or ""
        limit = max(1, min(int(query.get("limit") or 10), 30))
        days = max(1, min(int(query.get("days") or 7), 30))
        cutoff = (datetime.now(timezone.utc) - timedelta(days=days)).isoformat()
        # Optional region scoping: region_code wins; else country/province/city;
        # else fall back to the viewer's own country so the list stays local.
        region_code = (query.get("region_code") or query.get("regionCode") or "").strip().lower()
        q_country = (query.get("country") or "").strip().lower()
        q_province = (query.get("province") or "").strip().lower()
        q_city = (query.get("city") or "").strip().lower()
        region_filters: list[str] = []
        region_params: list[Any] = []
        if region_code:
            region_filters.append("p.region_code = ?")
            region_params.append(region_code)
        elif q_country or q_province or q_city:
            if q_country:
                region_filters.append("p.country = ?")
                region_params.append(q_country)
            if q_province:
                region_filters.append("p.province = ?")
                region_params.append(q_province)
            if q_city:
                region_filters.append("p.city = ?")
                region_params.append(q_city)
        elif viewer_country:
            region_filters.append("p.country = ?")
            region_params.append(viewer_country)
        region_clause = ("AND " + " AND ".join(region_filters)) if region_filters else ""
        params: list[Any] = [cutoff, *region_params, limit]
        rows = list(conn.execute(
            f"""
            SELECT p.*, COUNT(*) AS weekly_like_count
            FROM posts p
            JOIN interactions i ON i.target_id = p.id AND i.kind = 'like' AND i.created_at >= ?
            WHERE p.deleted_at IS NULL
              AND p.status IN ('published', 'active')
              {region_clause}
            GROUP BY p.id
            ORDER BY weekly_like_count DESC, p.created_at DESC
            LIMIT ?
            """,
            params,
        ))
        posts = fetch_posts_with_extras(conn, [dict(r) for r in rows], viewer_id)
        like_counts = {r["id"]: int(r["weekly_like_count"] or 0) for r in rows}
        for post in posts:
            post["weekly_like_count"] = like_counts.get(post["id"], 0)
            post["weeklyLikes"] = post["weekly_like_count"]
        self.send_json({
            "items": posts,
            "posts": posts,
            "days": days,
            "metric": "weekly_likes",
            "viewer": {"id": viewer_id} if viewer_id else None,
            "canInteract": bool(viewer_id),
            "can_interact": bool(viewer_id),
        })

    def api_topics(self, conn: sqlite3.Connection) -> None:
        viewer = self.current_session(conn)
        viewer_id = viewer["user_id"] if viewer else None
        viewer_country = ""
        if viewer_id:
            viewer_row = conn.execute("SELECT country FROM users WHERE id = ?", (viewer_id,)).fetchone()
            viewer_country = (viewer_row["country"] if viewer_row else "") or ""
        country_clause = "AND p.country = ?" if viewer_country else ""
        params: tuple[Any, ...] = (viewer_country,) if viewer_country else ()
        # This full post_tags×posts GROUP BY used to run on EVERY call. Cache the
        # public aggregate per country for a short window (keyed only by country —
        # the only input that changes the result); viewer-specific fields below
        # stay live. Collapses the legacy /api/topics fan-out to one DB hit/window.
        cache_key = f"topics:{viewer_country or '*'}"
        topics = _cache_get(cache_key)
        if topics is None:
            topics = [
                {"tag": r["tag"], "post_count": int(r["c"])}
                for r in conn.execute(
                    f"""
                    SELECT t.tag, COUNT(*) AS c
                    FROM post_tags t
                    JOIN posts p ON p.id = t.post_id
                    WHERE p.deleted_at IS NULL AND p.status IN ('published', 'active')
                      {country_clause}
                    GROUP BY t.tag ORDER BY c DESC LIMIT 50
                    """,
                    params,
                )
            ]
            _cache_put(cache_key, topics, 60.0)
        self.send_json({
            "topics": topics,
            "items": topics,
            "viewer": {"id": viewer_id} if viewer_id else None,
            "canInteract": bool(viewer_id),
            "can_interact": bool(viewer_id),
        })

    def api_topic(self, conn: sqlite3.Connection, tag: str, query: dict[str, str]) -> None:
        viewer = self.current_session(conn)
        viewer_id = viewer["user_id"] if viewer else None
        tag_clean = tag.lstrip("#").lower()
        sort = query.get("sort") or "latest"
        order = f"{_heat_score_sql('p')} DESC, p.created_at DESC" if sort in ("hot", "high_heat") else "p.created_at DESC"
        rows = list(conn.execute(
            f"""
            SELECT p.* FROM posts p
            JOIN post_tags t ON t.post_id = p.id
            WHERE t.tag = ? AND p.deleted_at IS NULL AND p.status IN ('published', 'active')
            ORDER BY {order} LIMIT 50
            """,
            (tag_clean,),
        ))
        if not rows and tag_clean:
            # Safety net: a post can carry "#东京" in its body yet lack a
            # post_tags row (older seed/import paths that never ran extract_tags).
            # Only when the indexed lookup is empty, scan content for the exact
            # hashtag token — filtered through extract_tags so "#东京" never
            # matches "#东京塔" — so a topic that genuinely has posts is never
            # shown as empty. Read-only; the startup backfill repairs the index.
            candidates = conn.execute(
                f"""
                SELECT p.* FROM posts p
                WHERE p.content LIKE ? AND p.deleted_at IS NULL
                  AND p.status IN ('published', 'active')
                ORDER BY {order} LIMIT 200
                """,
                (f"%#{tag_clean}%",),
            ).fetchall()
            rows = [r for r in candidates if tag_clean in extract_tags(r["content"] or "")][:50]
        posts = fetch_posts_with_extras(conn, [dict(r) for r in rows], viewer_id)
        self.send_json({"tag": tag_clean, "items": posts, "viewer": {"id": viewer_id} if viewer_id else None, "canInteract": bool(viewer_id), "can_interact": bool(viewer_id)})

    def api_funnel(self, conn: sqlite3.Connection) -> None:
        """POST /api/funnel (B6 #6). Guest or logged-in. Records a whitelisted
        client funnel event as a structured ACCESS_LOG line — no table, no PII.
        Rate-limited by the generic 'write' bucket (see _rate_group_for)."""
        viewer = self.current_session(conn)
        user_id = viewer["user_id"] if viewer else ""
        data = self.read_json()
        event = str(data.get("event") or "").strip()
        if event not in FUNNEL_EVENTS:
            raise APIError("未知事件", 400, "invalid_event")
        entity_type = str(data.get("entityType") or data.get("entity_type") or "").strip()[:40]
        entity_id = str(data.get("entityId") or data.get("entity_id") or "").strip()[:64]
        _funnel_log(event, user_id=user_id, entity_type=entity_type, entity_id=entity_id)
        self.send_json({"ok": True})

    def api_topic_follow(self, conn: sqlite3.Connection, tag: str, on: bool) -> None:
        """POST/DELETE /api/topics/<tag>/follow (B6 #7). Follow / unfollow a
        hashtag; the follow_digest task folds followed topics into the daily
        summary. Tag is stored lowercased with any leading '#' stripped."""
        user = self.require_user(conn)
        tag_clean = unquote(tag or "").strip().lstrip("#").lower()[:80]
        if not tag_clean:
            raise APIError("话题不能为空", 400, "invalid_tag")
        if on:
            # UNIQUE(user_id, tag) makes this idempotent across both dialects.
            conn.execute(
                "INSERT OR IGNORE INTO topic_follows (user_id, tag, created_at) VALUES (?, ?, ?)",
                (user["id"], tag_clean, now_iso()),
            )
        else:
            conn.execute(
                "DELETE FROM topic_follows WHERE user_id = ? AND tag = ?",
                (user["id"], tag_clean),
            )
        self.send_json({"ok": True, "tag": tag_clean, "following": on})

    def api_my_topic_follows(self, conn: sqlite3.Connection) -> None:
        """GET /api/my/topic-follows (B6 #7): the caller's followed hashtags."""
        user = self.require_user(conn)
        rows = conn.execute(
            "SELECT tag FROM topic_follows WHERE user_id = ? ORDER BY created_at DESC LIMIT 500",
            (user["id"],),
        ).fetchall()
        self.send_json({"tags": [r["tag"] for r in rows]})

    def api_notifications(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        user = self.require_user(conn)
        kind = query.get("kind") or "all"
        clause = ""
        params: list[Any] = [user["id"]]
        if kind != "all":
            clause = " AND type = ?"
            params.append(kind)
        rows = list(conn.execute(
            f"SELECT * FROM notifications WHERE user_id = ? AND deleted_at IS NULL{clause} ORDER BY created_at DESC LIMIT 100",
            params,
        ))
        actor_ids = list({r["actor_id"] for r in rows})
        actor_map = fetch_users_by_ids(conn, actor_ids)
        items = [
            serialize_notification(dict(r), {"actor": actor_map.get(r["actor_id"])})
            for r in rows
        ]
        unread_row = conn.execute(
            f"SELECT COUNT(*) AS c FROM notifications WHERE user_id = ? AND deleted_at IS NULL AND is_read = 0{clause}",
            params,
        ).fetchone()
        unread = int(unread_row["c"] if unread_row else 0)
        self.send_json({"items": items, "unread_count": unread})

    def api_mark_notifications(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        is_read = 1 if data.get("is_read", True) else 0
        if data.get("all"):
            conn.execute(
                "UPDATE notifications SET is_read = ? WHERE user_id = ? AND deleted_at IS NULL",
                (is_read, user["id"]),
            )
        else:
            ids = data.get("ids") or []
            for nid in ids:
                conn.execute(
                    "UPDATE notifications SET is_read = ? WHERE id = ? AND user_id = ? AND deleted_at IS NULL",
                    (is_read, nid, user["id"]),
                )
        unread_row = conn.execute(
            "SELECT COUNT(*) AS c FROM notifications WHERE user_id = ? AND deleted_at IS NULL AND is_read = 0",
            (user["id"],),
        ).fetchone()
        self.send_json({"ok": True, "unread_count": int(unread_row["c"] if unread_row else 0)})

    def api_delete_notification(self, conn: sqlite3.Connection, notif_id: str) -> None:
        user = self.require_user(conn)
        conn.execute(
            "UPDATE notifications SET deleted_at = ? WHERE id = ? AND user_id = ?",
            (now_iso(), notif_id, user["id"]),
        )
        self.send_json({"ok": True})

    def _conversation_for(self, conn: sqlite3.Connection, user_id: str, peer_id: str) -> dict[str, Any]:
        a, b = sorted([user_id, peer_id])
        row = conn.execute(
            "SELECT * FROM conversations WHERE participant_a = ? AND participant_b = ?",
            (a, b),
        ).fetchone()
        if row:
            conv = dict(row)
            hidden_col = "hidden_for_a_at" if conv["participant_a"] == user_id else "hidden_for_b_at"
            if conv.get("deleted_at") or conv.get(hidden_col):
                conn.execute(
                    f"UPDATE conversations SET deleted_at = NULL, {hidden_col} = NULL, updated_at = ? WHERE id = ?",
                    (now_iso(), conv["id"]),
                )
                return dict(conn.execute("SELECT * FROM conversations WHERE id = ?", (conv["id"],)).fetchone())
            return conv
        conv_id = str(uuid.uuid4())
        now = now_iso()
        # user_id is always the caller who is opening this DM (marketplace inquiry
        # or api_create_conversation) — record it as the initiator so the daily
        # active-DM quota can count only conversations this user started, and set
        # a stable created_at (updated_at moves on every reply, so the quota
        # window must not key off it).
        conn.execute(
            "INSERT INTO conversations (id, participant_a, participant_b, initiator_id, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?)",
            (conv_id, a, b, user_id, now, now),
        )
        return dict(conn.execute("SELECT * FROM conversations WHERE id = ?", (conv_id,)).fetchone())

    def api_conversations(self, conn: sqlite3.Connection, query: dict[str, str] | None = None) -> None:
        user = self.require_user(conn)
        query = query or {}
        # Opt-in keyset pagination on (updated_at, id). No `limit` → unchanged
        # (entire inbox) so existing clients never regress.
        limit_raw = str(query.get("limit") or "").strip()
        page_limit: int | None = None
        if limit_raw:
            try:
                page_limit = max(1, min(int(limit_raw), 100))
            except ValueError:
                raise APIError("limit 无效", 400, "invalid_limit")
        next_cursor: str | None = None
        clauses = [
            "deleted_at IS NULL",
            "((participant_a = ? AND COALESCE(hidden_for_a_at, '') = '') "
            "OR (participant_b = ? AND COALESCE(hidden_for_b_at, '') = ''))",
        ]
        cparams: list[Any] = [user["id"], user["id"]]
        if page_limit is not None:
            before = cursor_decode(query.get("cursor") or query.get("before"))
            if before:
                clauses.append("(updated_at < ? OR (updated_at = ? AND id < ?))")
                cparams.extend([before[0], before[0], before[1]])
            fetched = list(conn.execute(
                f"SELECT * FROM conversations WHERE {' AND '.join(clauses)} "
                f"ORDER BY updated_at DESC, id DESC LIMIT ?",
                [*cparams, page_limit + 1],
            ))
            has_more = len(fetched) > page_limit
            rows = fetched[:page_limit]
            if has_more and rows:
                oldest = rows[-1]
                next_cursor = cursor_encode(oldest["updated_at"], oldest["id"])
        else:
            rows = list(conn.execute(
                f"SELECT * FROM conversations WHERE {' AND '.join(clauses)} ORDER BY updated_at DESC",
                cparams,
            ))
        if not rows:
            self.send_json({"items": [], "next_cursor": next_cursor, "nextCursor": next_cursor})
            return
        conv_ids = [r["id"] for r in rows]
        placeholders = ",".join("?" * len(conv_ids))
        peer_ids = [
            (r["participant_b"] if r["participant_a"] == user["id"] else r["participant_a"])
            for r in rows
        ]
        users_map = fetch_users_by_ids(conn, peer_ids)
        # Last message per conversation in one pass. Avoid SQLite-only
        # rowid so the query works identically on PostgreSQL.
        last_messages: dict[str, dict[str, Any]] = {}
        for row in conn.execute(
            f"""
            SELECT *
            FROM (
              SELECT m.*,
                     ROW_NUMBER() OVER (
                       PARTITION BY conversation_id
                       ORDER BY created_at DESC, id DESC
                     ) AS machi_rank
              FROM messages m
              WHERE deleted_at IS NULL AND conversation_id IN ({placeholders})
            ) ranked
            WHERE machi_rank = 1
            """,
            conv_ids,
        ):
            last_messages[row["conversation_id"]] = dict(row)
        # Unread counts per conversation, single aggregate query.
        unread_map: dict[str, int] = {pid: 0 for pid in conv_ids}
        for row in conn.execute(
            f"""
            SELECT conversation_id, COUNT(*) AS c
            FROM messages
            WHERE deleted_at IS NULL
              AND is_read = 0
              AND sender_id != ?
              AND conversation_id IN ({placeholders})
            GROUP BY conversation_id
            """,
            [user["id"], *conv_ids],
        ):
            unread_map[row["conversation_id"]] = int(row["c"])
        last_message_ids = [msg["id"] for msg in last_messages.values()]
        media_by_last: dict[str, list[dict[str, Any]]] = {}
        attachments_by_last: dict[str, list[dict[str, Any]]] = {}
        if last_message_ids:
            msg_placeholders = ",".join("?" * len(last_message_ids))
            for r in conn.execute(
                f"""SELECT mm.message_id, m.* FROM message_media mm
                    JOIN media m ON m.id = mm.media_id
                    WHERE mm.message_id IN ({msg_placeholders}) AND m.deleted_at IS NULL""",
                last_message_ids,
            ):
                media_by_last.setdefault(r["message_id"], []).append(serialize_media(dict(r)))
            for r in conn.execute(
                f"""
                SELECT
                  a.id, a.message_id, a.thread_id, a.uploaded_file_id, a.attachment_type,
                  a.thumbnail_file_id,
                  COALESCE(NULLIF(tf.cdn_url, ''), NULLIF(tf.public_url, '')) AS thumbnail_url,
                  tf.purpose AS thumbnail_purpose,
                  tf.object_key AS thumbnail_object_key,
                  COALESCE(NULLIF(a.duration_seconds, 0), f.duration, 0) AS duration_seconds,
                  a.file_name,
                  COALESCE(NULLIF(a.file_size, 0), f.file_size, 0) AS file_size,
                  COALESCE(NULLIF(a.content_type, ''), f.content_type, '') AS content_type,
                  a.visibility, a.status, a.created_at,
                  f.file_type, f.width, f.height, f.object_key
                FROM message_attachments a
                JOIN uploaded_files f ON f.id = a.uploaded_file_id
                LEFT JOIN uploaded_files tf ON tf.id = a.thumbnail_file_id AND tf.deleted_at IS NULL
                WHERE a.message_id IN ({msg_placeholders})
                  AND a.deleted_at IS NULL
                  AND a.status != 'deleted'
                  AND f.deleted_at IS NULL
                ORDER BY a.created_at ASC
                """,
                last_message_ids,
            ):
                item = serialize_message_attachment(dict(r))
                attachments_by_last.setdefault(item["message_id"], []).append(item)
        items = []
        for r in rows:
            peer_id = r["participant_b"] if r["participant_a"] == user["id"] else r["participant_a"]
            last = last_messages.get(r["id"])
            # A user's manual-unread flag surfaces the thread as unread even with
            # zero unread inbound messages (e.g. they flagged an empty thread).
            manual_flag = int(
                (r["manual_unread_a"] if r["participant_a"] == user["id"] else r["manual_unread_b"]) or 0
            )
            unread = unread_map.get(r["id"], 0)
            if manual_flag and unread < 1:
                unread = 1
            items.append(serialize_conversation(dict(r), {
                "peer": users_map.get(peer_id),
                "last_message": serialize_message(last, {
                    "media": media_by_last.get(last["id"], []),
                    "attachments": attachments_by_last.get(last["id"], []),
                }) if last else None,
                "unread_count": unread,
            }))
        self.send_json({"items": items, "next_cursor": next_cursor, "nextCursor": next_cursor})

    def api_create_conversation(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        peer_id = data.get("peer_id")
        if not peer_id or peer_id == user["id"]:
            raise APIError("无效的对话对象", 400, "invalid_peer")
        peer_row = conn.execute(
            "SELECT * FROM users WHERE (id = ? OR handle = ?) AND deleted_at IS NULL",
            (peer_id, peer_id),
        ).fetchone()
        if not peer_row:
            raise APIError("用户不存在", 404, "user_not_found")
        # The same handle-or-id check above means the lookup might also
        # resolve to the caller via handle. Block it explicitly so we
        # never open a self-DM through the handle path.
        if peer_row["id"] == user["id"]:
            raise APIError("无效的对话对象", 400, "invalid_peer")
        # Respect mutual blocks: neither side can DM if either blocked
        # the other.
        blocked = conn.execute(
            "SELECT 1 FROM blocks WHERE (blocker_id = ? AND blocked_id = ?) OR (blocker_id = ? AND blocked_id = ?)",
            (user["id"], peer_row["id"], peer_row["id"], user["id"]),
        ).fetchone()
        if blocked:
            raise APIError("无法与该用户对话", 403, "blocked")
        if not dm_privacy_allows(conn, user["id"], peer_row["id"]):
            raise APIError("对方设置了私信权限，暂时无法发起私信", 403, "dm_privacy_restricted")
        rep = reputation_ensure_user(conn, user["id"])
        controls = reputation_effective_limits(conn, rep, user)
        if _clamp_reputation_score(rep.get("reputation_score")) < 20 or _clamp_risk_score(rep.get("risk_score")) >= int(reputation_limit_map(conn).get("restrict_risk_threshold") or 81):
            raise APIError("当前账号信任状态暂不能主动私信陌生人。", 403, "REPUTATION_LIMITED")
        a, b = sorted([user["id"], peer_row["id"]])
        existing_conv = conn.execute(
            "SELECT 1 FROM conversations WHERE participant_a = ? AND participant_b = ?",
            (a, b),
        ).fetchone()
        if not existing_conv:
            since = _reputation_now_window(1)
            # Count only conversations THIS user actively started in the last 24h.
            # The old query keyed off (participant_a OR participant_b) + updated_at,
            # so a passive inbound DM, a reply, or a delete that bumped updated_at
            # all wrongly burned the sender's quota. initiator_id is written only
            # for the opener (see _conversation_for); use created_at so replies to
            # an existing thread never re-tick the window.
            today_opened = conn.execute(
                """
                SELECT COUNT(*) AS c
                  FROM conversations
                 WHERE initiator_id = ?
                   AND created_at >= ?
                """,
                (user["id"], since),
            ).fetchone()["c"]
            if int(today_opened or 0) >= int(controls["dm_daily_limit"] or 0):
                raise APIError("今日主动私信次数已达当前信任额度。", 429, "DM_LIMIT_REACHED")
        conv = self._conversation_for(conn, user["id"], peer_row["id"])
        self.send_json({"conversation": serialize_conversation(conv, {"peer": serialize_user(dict(peer_row))})})

    def api_mutual_message_friends(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        user = self.require_user(conn)
        q = str(query.get("q") or "").strip()
        try:
            limit = int(query.get("limit") or 50)
        except (TypeError, ValueError):
            limit = 50
        limit = max(1, min(limit, 100))
        params: list[Any] = [user["id"], user["id"], user["id"], user["id"]]
        search_clause = ""
        if q:
            like = f"%{q}%"
            search_clause = "AND (u.handle LIKE ? OR u.display_name LIKE ? OR COALESCE(u.bio, '') LIKE ?)"
            params.extend([like, like, like])
        params.append(limit)
        rows = list(conn.execute(
            f"""
            SELECT u.*
              FROM users u
             WHERE u.deleted_at IS NULL
               AND EXISTS (
                    SELECT 1
                      FROM follows mine
                     WHERE mine.follower_id = ?
                       AND mine.following_id = u.id
               )
               AND EXISTS (
                    SELECT 1
                      FROM follows back
                     WHERE back.follower_id = u.id
                       AND back.following_id = ?
               )
               AND NOT EXISTS (
                    SELECT 1 FROM blocks b
                     WHERE (b.blocker_id = ? AND b.blocked_id = u.id)
                        OR (b.blocker_id = u.id AND b.blocked_id = ?)
               )
               {search_clause}
             ORDER BY LOWER(COALESCE(u.display_name, '')) ASC,
                      LOWER(COALESCE(u.handle, '')) ASC,
                      u.id ASC
             LIMIT ?
            """,
            params,
        ))
        items = []
        seen_user_ids: set[str] = set()
        for r in rows:
            user_row = dict(r)
            uid = str(user_row.get("id") or "")
            if not uid or uid in seen_user_ids:
                continue
            seen_user_ids.add(uid)
            user_row["is_following"] = 1
            items.append(serialize_user(user_row))
        self.send_json({"items": items})

    def api_delete_conversation(self, conn: sqlite3.Connection, conv_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM conversations WHERE id = ?", (conv_id,)).fetchone()
        if not row or (row["participant_a"] != user["id"] and row["participant_b"] != user["id"]):
            raise APIError("无权操作", 403, "forbidden")
        now = now_iso()
        hidden_col = "hidden_for_a_at" if row["participant_a"] == user["id"] else "hidden_for_b_at"
        conn.execute(f"UPDATE conversations SET {hidden_col} = ?, updated_at = ? WHERE id = ?", (now, now, conv_id))
        self.send_json({"ok": True})

    def api_messages(self, conn: sqlite3.Connection, conv_id: str, query: dict[str, str]) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM conversations WHERE id = ? AND deleted_at IS NULL", (conv_id,)).fetchone()
        if not row or (row["participant_a"] != user["id"] and row["participant_b"] != user["id"]):
            raise APIError("无权操作", 403, "forbidden")
        hidden_col = "hidden_for_a_at" if row["participant_a"] == user["id"] else "hidden_for_b_at"
        if row[hidden_col]:
            raise APIError("会话已隐藏，请重新发起对话", 404, "conversation_hidden")
        filters = ["conversation_id = ?", "deleted_at IS NULL"]
        params: list[Any] = [conv_id]
        q = str(query.get("q") or query.get("query") or "").strip()
        if q:
            like = f"%{q}%"
            filters.append(
                """
                (
                    content LIKE ?
                    OR id IN (
                        SELECT a.message_id
                          FROM message_attachments a
                          JOIN uploaded_files f ON f.id = a.uploaded_file_id
                         WHERE a.deleted_at IS NULL
                           AND f.deleted_at IS NULL
                           AND (COALESCE(a.file_name, '') LIKE ? OR COALESCE(f.object_key, '') LIKE ?)
                    )
                )
                """
            )
            params.extend([like, like, like])
        day = str(query.get("date") or query.get("day") or "").strip()
        if day:
            try:
                day_start = datetime.fromisoformat(day[:10]).date().isoformat()
                day_end = (datetime.fromisoformat(day[:10]).date() + timedelta(days=1)).isoformat()
                filters.append("created_at >= ? AND created_at < ?")
                params.extend([day_start, day_end])
            except ValueError:
                raise APIError("日期格式无效", 400, "invalid_date")
        # H2: opt-in keyset pagination. With no `limit`, behavior is UNCHANGED
        # (full chronological history) so existing clients never regress. With
        # `limit`, return the newest page (optionally older than `cursor`) plus a
        # `next_cursor` the client passes back to load earlier messages.
        limit_raw = str(query.get("limit") or "").strip()
        page_limit: int | None = None
        if limit_raw:
            try:
                page_limit = max(1, min(int(limit_raw), 200))
            except ValueError:
                raise APIError("limit 无效", 400, "invalid_limit")
        next_cursor: str | None = None
        if page_limit is None:
            rows = list(conn.execute(
                f"SELECT * FROM messages WHERE {' AND '.join(filters)} ORDER BY created_at",
                params,
            ))
        else:
            page_filters = list(filters)
            page_params = list(params)
            before = cursor_decode(query.get("cursor") or query.get("before"))
            if before:
                page_filters.append("(created_at < ? OR (created_at = ? AND id < ?))")
                page_params.extend([before[0], before[0], before[1]])
            fetched = list(conn.execute(
                f"SELECT * FROM messages WHERE {' AND '.join(page_filters)} "
                f"ORDER BY created_at DESC, id DESC LIMIT ?",
                [*page_params, page_limit + 1],
            ))
            has_more = len(fetched) > page_limit
            page = fetched[:page_limit]
            if has_more and page:
                oldest = page[-1]
                next_cursor = cursor_encode(oldest["created_at"], oldest["id"])
            rows = list(reversed(page))  # ascending for the client
        message_ids = [r["id"] for r in rows]
        media_by_msg: dict[str, list[dict[str, Any]]] = {}
        if message_ids:
            placeholders = ",".join("?" * len(message_ids))
            for r in conn.execute(
                f"""SELECT mm.message_id, m.* FROM message_media mm
                    JOIN media m ON m.id = mm.media_id
                    WHERE mm.message_id IN ({placeholders}) AND m.deleted_at IS NULL""",
                message_ids,
            ):
                media_by_msg.setdefault(r["message_id"], []).append(serialize_media(dict(r)))
        attachments_by_msg: dict[str, list[dict[str, Any]]] = {}
        if message_ids:
            placeholders = ",".join("?" * len(message_ids))
            for r in conn.execute(
                f"""
                SELECT
                  a.id, a.message_id, a.thread_id, a.uploaded_file_id, a.attachment_type,
                  a.thumbnail_file_id,
                  COALESCE(NULLIF(tf.cdn_url, ''), NULLIF(tf.public_url, '')) AS thumbnail_url,
                  tf.purpose AS thumbnail_purpose,
                  tf.object_key AS thumbnail_object_key,
                  COALESCE(NULLIF(a.duration_seconds, 0), f.duration, 0) AS duration_seconds,
                  a.file_name,
                  COALESCE(NULLIF(a.file_size, 0), f.file_size, 0) AS file_size,
                  COALESCE(NULLIF(a.content_type, ''), f.content_type, '') AS content_type,
                  a.visibility, a.status, a.created_at,
                  f.file_type, f.width, f.height, f.object_key
                FROM message_attachments a
                JOIN uploaded_files f ON f.id = a.uploaded_file_id
                LEFT JOIN uploaded_files tf ON tf.id = a.thumbnail_file_id AND tf.deleted_at IS NULL
                WHERE a.message_id IN ({placeholders})
                  AND a.deleted_at IS NULL
                  AND a.status != 'deleted'
                  AND f.deleted_at IS NULL
                ORDER BY a.created_at ASC
                """,
                message_ids,
            ):
                item = serialize_message_attachment(dict(r))
                attachments_by_msg.setdefault(item["message_id"], []).append(item)
        items = [
            serialize_message(dict(r), {
                "media": media_by_msg.get(r["id"], []),
                "attachments": attachments_by_msg.get(r["id"], []),
            })
            for r in rows
        ]
        self.send_json({"items": items, "next_cursor": next_cursor, "nextCursor": next_cursor})

    def api_create_message(self, conn: sqlite3.Connection, conv_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM conversations WHERE id = ?", (conv_id,)).fetchone()
        if not row or (row["participant_a"] != user["id"] and row["participant_b"] != user["id"]):
            raise APIError("无权操作", 403, "forbidden")
        other_id = row["participant_b"] if row["participant_a"] == user["id"] else row["participant_a"]
        # H3: re-check mutual block on EVERY send. Block is enforced at
        # conversation creation, but if B blocks A *after* the thread already
        # exists, A could keep messaging B indefinitely (block fails its core
        # purpose for the most common harassment vector). Honor it on the send
        # path too — including inquiry threads; harassment doesn't respect type.
        if conn.execute(
            "SELECT 1 FROM blocks WHERE (blocker_id = ? AND blocked_id = ?) OR (blocker_id = ? AND blocked_id = ?) LIMIT 1",
            (user["id"], other_id, other_id, user["id"]),
        ).fetchone():
            raise APIError("已拉黑或被对方拉黑，无法发送消息", 403, "blocked")
        # Listing-inquiry threads are business conversations opened by the
        # contact flow — dm_privacy must not break buyer↔seller follow-ups.
        is_inquiry_thread = conn.execute(
            "SELECT 1 FROM listing_inquiries WHERE conversation_id = ? LIMIT 1",
            (conv_id,),
        ).fetchone() is not None
        if not is_inquiry_thread and not dm_privacy_allows(conn, user["id"], other_id):
            raise APIError("对方设置了私信权限，暂时无法发送私信", 403, "dm_privacy_restricted")
        data = self.read_json()
        content = (data.get("content") or "").strip()
        attachment_ids = list(dict.fromkeys([
            str(v or "").strip()
            for v in (data.get("attachment_ids") or data.get("attachmentIds") or [])
            if str(v or "").strip()
        ]))
        submitted_media_ids = list(dict.fromkeys([
            str(v or "").strip()
            for v in (data.get("media_ids") or data.get("mediaIds") or [])
            if str(v or "").strip()
        ]))
        if not content and not attachment_ids and not submitted_media_ids:
            raise APIError("消息不能为空", 400, "empty_message")
        enforce_content_policy(content)  # H4: reject banned/scam/illegal text in DMs
        legacy_media_rows: list[dict[str, Any]] = []
        attachment_rows: list[dict[str, Any]] = []
        attachment_lookup_ids = list(dict.fromkeys([*attachment_ids, *submitted_media_ids]))
        image_count = 0
        video_count = 0
        file_count = 0
        for file_id in attachment_lookup_ids:
            upload_row = conn.execute(
                """
                SELECT * FROM uploaded_files
                 WHERE id = ?
                   AND user_id = ?
                   AND deleted_at IS NULL
                   AND status IN ('uploaded','processing','ready')
                """,
                (file_id, user["id"]),
            ).fetchone()
            if upload_row and str(upload_row["purpose"] or "") in {"message_image", "message_video", "message_file"}:
                upload = dict(upload_row)
                try:
                    metadata = json.loads(upload.get("metadata") or "{}")
                except (TypeError, json.JSONDecodeError):
                    metadata = {}
                if str(metadata.get("thread_id") or metadata.get("threadId") or "") != conv_id:
                    raise APIError("附件不属于该会话", 403, "attachment_thread_mismatch")
                purpose = str(upload.get("purpose") or "")
                attachment_type = "image" if purpose == "message_image" else "video" if purpose == "message_video" else "file"
                thumbnail_file_id = str(
                    metadata.get("thumbnail_file_id")
                    or metadata.get("thumbnailFileId")
                    or metadata.get("poster_file_id")
                    or metadata.get("posterFileId")
                    or ""
                ).strip()
                if attachment_type == "image":
                    image_count += 1
                    if image_count > 9:
                        raise APIError("每条私信最多发送 9 张图片", 400, "message_image_limit")
                elif attachment_type == "video":
                    video_count += 1
                    if video_count > 1:
                        raise APIError("每条私信最多发送 1 个视频", 400, "message_video_limit")
                else:
                    file_count += 1
                    if file_count > 1:
                        raise APIError("每条私信最多发送 1 个附件文件", 400, "message_file_limit")
                upload["_attachment_type"] = attachment_type
                if attachment_type == "video" and thumbnail_file_id:
                    # Accept BOTH the new private DM poster purpose
                    # (message_video_thumbnail) and the legacy public
                    # video_thumbnail so older clients / existing rows still work.
                    thumbnail_ok = conn.execute(
                        """
                        SELECT 1 FROM uploaded_files
                         WHERE id = ?
                           AND user_id = ?
                           AND purpose IN ('video_thumbnail', 'message_video_thumbnail')
                           AND status = 'ready'
                           AND deleted_at IS NULL
                         LIMIT 1
                        """,
                        (thumbnail_file_id, user["id"]),
                    ).fetchone()
                    upload["_thumbnail_file_id"] = thumbnail_file_id if thumbnail_ok else ""
                else:
                    upload["_thumbnail_file_id"] = ""
                attachment_rows.append(upload)
                continue
            if file_id in submitted_media_ids:
                media_row = conn.execute(
                    "SELECT * FROM media WHERE id = ? AND owner_id = ? AND deleted_at IS NULL",
                    (file_id, user["id"]),
                ).fetchone()
                if media_row:
                    legacy_media_rows.append(dict(media_row))
                    continue
            raise APIError("包含无权使用的私信附件", 403, "attachment_forbidden")
        if image_count > 0 and video_count > 0:
            raise APIError("图片和视频不能混合发送，请选择 9 张图片或 1 个视频", 400, "message_media_mixed")
        message_id = str(uuid.uuid4())
        now = now_iso()
        conn.execute(
            "INSERT INTO messages (id, conversation_id, sender_id, content, created_at, is_read) VALUES (?, ?, ?, ?, ?, 0)",
            (message_id, conv_id, user["id"], content, now),
        )
        for media_row in legacy_media_rows:
            conn.execute("INSERT OR IGNORE INTO message_media VALUES (?, ?)", (message_id, media_row["id"]))
        for upload in attachment_rows:
            attachment_id = "att_" + uuid.uuid4().hex
            conn.execute(
                """
                INSERT INTO message_attachments (
                    id, message_id, thread_id, uploaded_file_id, attachment_type, thumbnail_file_id,
                    duration_seconds, file_name, file_size, content_type, visibility, status, created_at, updated_at
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'thread_members_only', 'ready', ?, ?)
                """,
                (
                    attachment_id, message_id, conv_id, upload["id"], upload["_attachment_type"],
                    upload.get("_thumbnail_file_id") or "",
                    float(upload.get("duration") or 0),
                    Path(upload.get("object_key") or "").name,
                    int(upload.get("file_size") or 0),
                    upload.get("content_type") or "",
                    now, now,
                ),
            )
            conn.execute(
                "UPDATE uploaded_files SET entity_type = 'message', entity_id = ?, updated_at = ? WHERE id = ?",
                (message_id, now, upload["id"]),
            )
            record_upload_audit(conn, user["id"], "message_attachment_link", file_id=upload["id"], status="ready", metadata={"messageId": message_id, "threadId": conv_id, "attachmentId": attachment_id})
        conn.execute(
            "UPDATE conversations SET updated_at = ?, deleted_at = NULL, hidden_for_a_at = NULL, hidden_for_b_at = NULL WHERE id = ?",
            (now, conv_id),
        )
        peer_id = row["participant_b"] if row["participant_a"] == user["id"] else row["participant_a"]
        HUB.publish(peer_id, {"type": "message", "conversation_id": conv_id, "message_id": message_id})
        # Push every DM (messenger semantics) — the bell row below stays
        # deduped per conversation, but pushes shouldn't be.
        server_apns.enqueue(peer_id, ntype="message", actor_id=user["id"],
                            content=(content.strip()[:140] if content.strip() else "[附件]"),
                            conversation_id=conv_id, message_id=message_id)
        # Surface the DM in the recipient's notification feed (bell + the
        # clients' system-banner pipeline). At most ONE unread 'message'
        # row per conversation, so a burst of messages can't flood it.
        if not conn.execute(
            "SELECT 1 FROM notifications WHERE user_id = ? AND type = 'message' AND target_conversation_id = ? AND is_read = 0 AND deleted_at IS NULL LIMIT 1",
            (peer_id, conv_id),
        ).fetchone():
            notif_preview = content.strip()[:140] if content.strip() else "[附件]"
            conn.execute(
                "INSERT INTO notifications (id, user_id, actor_id, type, target_conversation_id, content, created_at) VALUES (?, ?, ?, 'message', ?, ?, ?)",
                (str(uuid.uuid4()), peer_id, user["id"], conv_id, notif_preview, now),
            )
            HUB.publish(peer_id, {"type": "notification", "kind": "message", "conversation_id": conv_id})
        fresh = dict(conn.execute("SELECT * FROM messages WHERE id = ?", (message_id,)).fetchone())
        media_rows = [serialize_media(dict(r)) for r in conn.execute(
            "SELECT m.* FROM message_media mm JOIN media m ON m.id = mm.media_id WHERE mm.message_id = ?",
            (message_id,),
        )]
        attachment_items = [
            serialize_message_attachment(dict(r))
            for r in conn.execute(
                """
                SELECT
                  a.id, a.message_id, a.thread_id, a.uploaded_file_id, a.attachment_type,
                  a.thumbnail_file_id,
                  COALESCE(NULLIF(tf.cdn_url, ''), NULLIF(tf.public_url, '')) AS thumbnail_url,
                  tf.purpose AS thumbnail_purpose,
                  tf.object_key AS thumbnail_object_key,
                  COALESCE(NULLIF(a.duration_seconds, 0), f.duration, 0) AS duration_seconds,
                  a.file_name,
                  COALESCE(NULLIF(a.file_size, 0), f.file_size, 0) AS file_size,
                  COALESCE(NULLIF(a.content_type, ''), f.content_type, '') AS content_type,
                  a.visibility, a.status, a.created_at,
                  f.file_type, f.width, f.height, f.object_key
                FROM message_attachments a
                JOIN uploaded_files f ON f.id = a.uploaded_file_id
                LEFT JOIN uploaded_files tf ON tf.id = a.thumbnail_file_id AND tf.deleted_at IS NULL
                WHERE a.message_id = ?
                  AND a.deleted_at IS NULL
                  AND a.status != 'deleted'
                  AND f.deleted_at IS NULL
                ORDER BY a.created_at ASC
                """,
                (message_id,),
            )
        ]
        self.send_json({"message": serialize_message(fresh, {"media": media_rows, "attachments": attachment_items})})

    def api_delete_message(self, conn: sqlite3.Connection, msg_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM messages WHERE id = ?", (msg_id,)).fetchone()
        if not row or row["sender_id"] != user["id"]:
            raise APIError("无权操作", 403, "forbidden")
        now = now_iso()
        conn.execute("UPDATE messages SET deleted_at = ? WHERE id = ?", (now, msg_id))
        conn.execute(
            "UPDATE message_attachments SET status = 'deleted', deleted_at = ?, updated_at = ? WHERE message_id = ? AND deleted_at IS NULL",
            (now, now, msg_id),
        )
        self.send_json({"ok": True})

    def api_message_attachment_view_url(self, conn: sqlite3.Connection, msg_id: str, attachment_id: str, query: dict[str, str] | None = None) -> None:
        user = self.require_user(conn)
        # kind=poster signs the private video COVER (thumbnail_file_id) instead of
        # the video body. Authorization is identical (thread membership) — the
        # poster of a DM video is as private as the video itself.
        want_poster = str((query or {}).get("kind") or "").strip().lower() == "poster"
        row = conn.execute(
            """
            SELECT
              a.id AS attachment_id,
              a.message_id,
              a.thread_id,
              a.uploaded_file_id,
              a.thumbnail_file_id,
              a.status AS attachment_status,
              f.id AS file_id,
              f.user_id AS file_owner_id,
              f.bucket,
              f.object_key,
              f.content_type,
              f.status AS file_status,
              f.purpose,
              tf.id AS thumb_file_id,
              tf.status AS thumb_status,
              tf.purpose AS thumb_purpose,
              c.participant_a,
              c.participant_b
            FROM message_attachments a
            JOIN messages m ON m.id = a.message_id AND m.deleted_at IS NULL
            JOIN conversations c ON c.id = m.conversation_id AND c.deleted_at IS NULL
            JOIN uploaded_files f ON f.id = a.uploaded_file_id
            LEFT JOIN uploaded_files tf ON tf.id = a.thumbnail_file_id AND tf.deleted_at IS NULL
            WHERE a.id = ?
              AND a.message_id = ?
              AND a.deleted_at IS NULL
              AND a.status != 'deleted'
              AND f.deleted_at IS NULL
              AND f.status != 'deleted'
            LIMIT 1
            """,
            (attachment_id, msg_id),
        ).fetchone()
        if not row:
            raise APIError("附件不存在", 404, "attachment_not_found")
        d = dict(row)
        if d["participant_a"] != user["id"] and d["participant_b"] != user["id"] and user.get("role") != "admin":
            record_upload_audit(conn, user["id"], "message_attachment_view_denied", file_id=d["file_id"], status="failed", reason="thread_forbidden", metadata={"messageId": msg_id, "attachmentId": attachment_id, "kind": "poster" if want_poster else "body"})
            raise APIError("无权查看该附件", 403, "forbidden")
        if want_poster:
            target_file_id = str(d.get("thumb_file_id") or "")
            target_purpose = str(d.get("thumb_purpose") or "")
            target_status = str(d.get("thumb_status") or "")
            if not target_file_id or target_purpose != "message_video_thumbnail":
                # Not a private poster (legacy public cover or none) — nothing to sign.
                raise APIError("封面无需签名", 400, "poster_not_private")
        else:
            target_file_id = str(d.get("file_id") or "")
            target_purpose = str(d.get("purpose") or "")
            target_status = str(d.get("file_status") or "")
            if target_purpose not in {"message_image", "message_video", "message_file"}:
                raise APIError("附件类型不支持", 400, "invalid_attachment_purpose")
        if target_status not in {"uploaded", "processing", "ready"}:
            raise APIError("附件尚未可用", 409, "attachment_not_ready")
        expires = S3_PRIVATE_DOWNLOAD_EXPIRES_SECONDS
        url = self._private_download_url(target_file_id, expires)
        record_upload_audit(conn, user["id"], "message_attachment_view_url", file_id=target_file_id, status="ready", metadata={"messageId": msg_id, "threadId": d["thread_id"], "attachmentId": attachment_id, "kind": "poster" if want_poster else "body", "expires": expires})
        self.send_json({"ok": True, "data": {"url": url, "expiresIn": expires}, "url": url, "expiresIn": expires})

    def api_mark_conversation_read(self, conn: sqlite3.Connection, conv_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM conversations WHERE id = ? AND deleted_at IS NULL", (conv_id,)).fetchone()
        if not row or (row["participant_a"] != user["id"] and row["participant_b"] != user["id"]):
            raise APIError("无权操作", 403, "forbidden")
        data = self.read_json()
        is_read = bool(data.get("is_read", True))
        # Per-participant manual-unread flag lets a user mark a conversation
        # unread even when it has no inbound message to flip (the old code's
        # is_read=false branch silently no-op'd those). a/b follows participant_a.
        manual_col = "manual_unread_a" if row["participant_a"] == user["id"] else "manual_unread_b"
        if is_read:
            conn.execute(
                "UPDATE messages SET is_read = 1 WHERE conversation_id = ? AND sender_id != ?",
                (conv_id, user["id"]),
            )
            conn.execute(
                """
                UPDATE notifications
                   SET is_read = 1
                 WHERE user_id = ?
                   AND type = 'message'
                   AND target_conversation_id = ?
                   AND deleted_at IS NULL
                """,
                (user["id"], conv_id),
            )
            # Reading clears any manual-unread flag this user set earlier.
            conn.execute(
                f"UPDATE conversations SET {manual_col} = 0 WHERE id = ?", (conv_id,)
            )
        else:
            # Flag manual-unread for this participant regardless of whether an
            # inbound message exists — this is the whole point of the fix.
            conn.execute(
                f"UPDATE conversations SET {manual_col} = 1 WHERE id = ?", (conv_id,)
            )
            latest_inbound = conn.execute(
                """
                SELECT *
                  FROM messages
                 WHERE conversation_id = ?
                   AND sender_id != ?
                   AND deleted_at IS NULL
                 ORDER BY created_at DESC, id DESC
                 LIMIT 1
                """,
                (conv_id, user["id"]),
            ).fetchone()
            if latest_inbound:
                latest = dict(latest_inbound)
                now = now_iso()
                conn.execute("UPDATE messages SET is_read = 0 WHERE id = ?", (latest["id"],))
                existing = conn.execute(
                    """
                    SELECT id
                      FROM notifications
                     WHERE user_id = ?
                       AND type = 'message'
                       AND target_conversation_id = ?
                     ORDER BY created_at DESC, id DESC
                     LIMIT 1
                    """,
                    (user["id"], conv_id),
                ).fetchone()
                preview = (latest.get("content") or "").strip()[:140] or "[附件]"
                if existing:
                    conn.execute(
                        """
                        UPDATE notifications
                           SET is_read = 0,
                               deleted_at = NULL,
                               actor_id = ?,
                               content = ?,
                               created_at = ?
                         WHERE id = ? AND user_id = ?
                        """,
                        (latest["sender_id"], preview, now, existing["id"], user["id"]),
                    )
                else:
                    conn.execute(
                        """
                        INSERT INTO notifications (id, user_id, actor_id, type, target_conversation_id, content, created_at, is_read)
                        VALUES (?, ?, ?, 'message', ?, ?, ?, 0)
                        """,
                        (str(uuid.uuid4()), user["id"], latest["sender_id"], conv_id, preview, now),
                    )
        unread_row = conn.execute(
            "SELECT COUNT(*) AS c FROM notifications WHERE user_id = ? AND deleted_at IS NULL AND is_read = 0",
            (user["id"],),
        ).fetchone()
        # This conversation's own unread count so the client can reconcile the
        # thread's badge: inbound unread messages, floored at 1 when the user has
        # a manual-unread flag set (an empty/no-inbound thread still shows unread).
        conv_unread = int(conn.execute(
            "SELECT COUNT(*) AS c FROM messages WHERE conversation_id = ? AND deleted_at IS NULL "
            "AND is_read = 0 AND sender_id != ?",
            (conv_id, user["id"]),
        ).fetchone()["c"] or 0)
        manual_flag = int(conn.execute(
            f"SELECT {manual_col} AS f FROM conversations WHERE id = ?", (conv_id,)
        ).fetchone()["f"] or 0)
        if manual_flag and conv_unread < 1:
            conv_unread = 1
        self.send_json({
            "ok": True,
            "unread_count": int(unread_row["c"] if unread_row else 0),
            "unreadCount": conv_unread,
        })

    # ---- S3 / unified uploads ----

    def _private_download_url(self, file_id: str, expires: int) -> str:
        exp = int(time.time()) + expires
        token = _signed_local_download_token(file_id, exp)
        base = self._request_base_url()
        path = f"/api/uploads/download/{file_id}?token={token}"
        return f"{base}{path}" if base else path

    def _assert_upload_entity_permission(
        self,
        conn: sqlite3.Connection,
        user: dict[str, Any],
        *,
        purpose: str,
        entity_type: str,
        entity_id: str,
    ) -> None:
        spec = UPLOAD_PURPOSES[purpose]
        if spec.get("admin") and user.get("role") != "admin":
            record_upload_audit(conn, user["id"], "presign_denied", status="failed", reason="admin_required", metadata={"purpose": purpose})
            raise APIError("该文件只能由管理员上传", 403, "admin_required")
        if purpose == "business_verification_file" and (entity_type != "business" or not entity_id):
            record_upload_audit(
                conn,
                user["id"],
                "presign_denied",
                status="failed",
                reason="business_required",
                metadata={"purpose": purpose},
            )
            raise APIError("请先保存商家申请，再上传认证材料", 400, "business_required")
        rep = reputation_ensure_user(conn, user["id"])
        if int(rep.get("risk_score") or 0) >= 80:
            record_upload_audit(conn, user["id"], "presign_denied", status="failed", reason="high_risk_user", metadata={"purpose": purpose})
            raise APIError("账号风险过高，暂不能上传文件", 403, "upload_restricted")
        if purpose == "guide_attachment":
            self._assert_guide_attachment_entity_owner(conn, user["id"], entity_type, entity_id)
            return
        if entity_type == "post" and entity_id:
            row = conn.execute("SELECT author_id FROM posts WHERE id = ? AND deleted_at IS NULL", (entity_id,)).fetchone()
            if not row or row["author_id"] != user["id"]:
                raise APIError("无权给该帖子上传文件", 403, "forbidden")
        elif entity_type == "listing" and entity_id:
            row = conn.execute("SELECT seller_user_id FROM city_listings WHERE id = ? AND deleted_at IS NULL", (entity_id,)).fetchone()
            if not row or row["seller_user_id"] != user["id"]:
                raise APIError("无权给该信息上传文件", 403, "forbidden")
        elif entity_type == "business" and entity_id and user.get("role") != "admin":
            row = conn.execute("SELECT owner_user_id FROM business_profiles WHERE id = ?", (entity_id,)).fetchone()
            if not row or row["owner_user_id"] != user["id"]:
                raise APIError("无权给该商家上传文件", 403, "forbidden")
        elif entity_type in {"guide_article", "guide_product"} and entity_id and user.get("role") != "admin":
            raise APIError("Guide 文件只能由管理员上传", 403, "admin_required")

    def _assert_guide_attachment_entity_owner(self, conn: sqlite3.Connection, user_id: str, entity_type: str, entity_id: str) -> None:
        if not entity_type or not entity_id:
            raise APIError("请先保存 Guide 项目，再上传附件", 400, "guide_entity_required")
        table_by_type = {
            "guide_task": "guide_todos",
            "guide_application": "guide_applications",
            "guide_life_item": "guide_life_items",
            "guide_contract": "guide_contracts",
            "guide_document": "guide_documents",
            "guide_goal": "guide_plans",
            "guide_calendar_event": "guide_calendar_items",
        }
        table = table_by_type.get(entity_type)
        if not table:
            raise APIError("Guide 附件类型不合法", 400, "invalid_guide_attachment_entity")
        row = conn.execute(f"SELECT user_id FROM {table} WHERE id = ?", (entity_id,)).fetchone()
        if not row or row["user_id"] != user_id:
            raise APIError("无权给该 Guide 项目上传附件", 403, "forbidden")

    # Identity images (a profile/company avatar & cover) are single, low-abuse
    # assets — they must NOT share the bulk daily upload budget. Otherwise a
    # business account (e.g. a 星域 partner 公司账号) that rehosts hundreds of
    # listing photos on its daily sync exhausts the cap and then can't even
    # change its own avatar. So they get their own separate, generous daily
    # bucket keyed only on identity uploads.
    _IDENTITY_UPLOAD_PURPOSES = ("avatar", "profile_cover", "business_logo", "business_cover")

    def _is_business_uploader(self, conn: sqlite3.Connection, user_id: str) -> bool:
        """Partner seller 公司账号 + verified merchants + official accounts upload
        high volumes legitimately (listing photo sync), so they get a much higher
        daily upload ceiling — they are trusted business accounts, not abuse."""
        row = conn.execute(
            "SELECT COALESCE(is_merchant,0) AS m, COALESCE(merchant_verified,0) AS v, "
            "COALESCE(is_official,0) AS o FROM users WHERE id = ?",
            (user_id,),
        ).fetchone()
        if row and (int(row["m"]) or int(row["v"]) or int(row["o"])):
            return True
        return bool(conn.execute(
            "SELECT 1 FROM partners WHERE seller_user_id = ? LIMIT 1", (user_id,)
        ).fetchone())

    def _check_upload_quota(
        self,
        conn: sqlite3.Connection,
        user_id: str,
        *,
        purpose: str,
        entity_type: str,
        entity_id: str,
    ) -> None:
        since = (datetime.now(timezone.utc) - timedelta(days=1)).isoformat()
        if purpose in self._IDENTITY_UPLOAD_PURPOSES:
            # Count ONLY identity uploads — listing/post photos never block an
            # avatar/cover change. Generous but bounded (anti-abuse for storage).
            placeholders = ",".join(["?"] * len(self._IDENTITY_UPLOAD_PURPOSES))
            id_daily = conn.execute(
                f"SELECT COUNT(*) AS c FROM uploaded_files WHERE user_id = ? AND created_at >= ? "
                f"AND deleted_at IS NULL AND purpose IN ({placeholders})",
                (user_id, since, *self._IDENTITY_UPLOAD_PURPOSES),
            ).fetchone()["c"]
            if int(id_daily or 0) >= 40:
                raise APIError("今日上传次数已达上限", 429, "daily_upload_limit")
            return  # identity purposes carry no per-entity count limit
        # Bulk content (listing/post/message media): trusted business accounts get
        # a far higher ceiling so a legitimate high-volume seller is never blocked.
        cap = 5000 if self._is_business_uploader(conn, user_id) else 120
        daily = conn.execute(
            "SELECT COUNT(*) AS c FROM uploaded_files WHERE user_id = ? AND created_at >= ? AND deleted_at IS NULL",
            (user_id, since),
        ).fetchone()["c"]
        if int(daily or 0) >= cap:
            raise APIError("今日上传次数已达上限", 429, "daily_upload_limit")
        limit = int(UPLOAD_PURPOSES[purpose].get("count") or 0)
        if limit <= 0:
            return
        if not (entity_type and entity_id):
            return
        count = conn.execute(
            """
            SELECT COUNT(*) AS c FROM uploaded_files
             WHERE user_id = ? AND purpose = ? AND entity_type = ? AND entity_id = ?
               AND status NOT IN ('deleted','failed') AND deleted_at IS NULL
            """,
            (user_id, purpose, entity_type, entity_id),
        ).fetchone()["c"]
        if int(count or 0) >= limit:
            raise APIError("该内容的上传数量已达上限", 400, "upload_count_limit")

    def api_upload_presign(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        purpose = normalize_upload_purpose(data.get("purpose"))
        file_name = str(data.get("fileName") or data.get("file_name") or "")
        content_type = canonical_upload_mime(purpose, str(data.get("contentType") or data.get("content_type") or ""), file_name)
        try:
            file_size = int(data.get("fileSize") or data.get("file_size") or 0)
        except (TypeError, ValueError):
            raise APIError("文件大小不合法", 400, "invalid_file_size")
        if file_size <= 0:
            raise APIError("文件大小不能为空", 400, "invalid_file_size")
        max_bytes = min(int(UPLOAD_PURPOSES[purpose]["max"]), S3_UPLOAD_MAX_SIZE)
        if file_size > max_bytes:
            record_upload_audit(conn, user["id"], "presign_denied", status="failed", reason="file_too_large", metadata={"purpose": purpose, "fileSize": file_size})
            raise APIError("文件太大", 413, "file_too_large")
        entity_type = normalize_upload_entity_type(data.get("entityType") or data.get("entity_type"))
        entity_id = str(data.get("entityId") or data.get("entity_id") or "").strip()
        thread_id = str(data.get("threadId") or data.get("thread_id") or data.get("conversationId") or data.get("conversation_id") or "").strip()
        group_id = str(data.get("groupId") or data.get("group_id") or "").strip()
        raw_metadata = data.get("metadata") if isinstance(data.get("metadata"), dict) else {}
        duration_seconds = max(0.0, float(raw_metadata.get("durationSeconds") or raw_metadata.get("duration_seconds") or data.get("duration") or data.get("durationSeconds") or 0))
        max_duration_by_purpose = {
            "post_video": 5 * 60,
            "article_video": 10 * 60,
            "experience_video": 5 * 60,
            "group_post_video": 5 * 60,
            "message_video": 2 * 60,
            "secondhand_video": 5 * 60,
            "rental_video": 10 * 60,
            "job_video": 5 * 60,
            "service_video": 5 * 60,
            "discount_video": 5 * 60,
        }
        if purpose in max_duration_by_purpose and duration_seconds > max_duration_by_purpose[purpose]:
            raise APIError("视频时长超过限制", 400, "video_duration_too_long")
        if purpose in {"message_image", "message_video", "message_file", "message_video_thumbnail"}:
            if not thread_id:
                raise APIError("私信上传需要 threadId", 400, "missing_thread_id")
            thread = conn.execute("SELECT * FROM conversations WHERE id = ? AND deleted_at IS NULL", (thread_id,)).fetchone()
            if not thread or (thread["participant_a"] != user["id"] and thread["participant_b"] != user["id"]):
                record_upload_audit(conn, user["id"], "presign_denied", status="failed", reason="thread_forbidden", metadata={"purpose": purpose, "threadId": thread_id})
                raise APIError("无权在该会话上传附件", 403, "thread_forbidden")
            entity_type = "message"
        self._assert_upload_entity_permission(conn, user, purpose=purpose, entity_type=entity_type, entity_id=entity_id)
        self._check_upload_quota(conn, user["id"], purpose=purpose, entity_type=entity_type, entity_id=entity_id)

        upload_id = "upload_" + uuid.uuid4().hex
        file_id = "file_" + uuid.uuid4().hex
        object_key = upload_object_key(user["id"], purpose, entity_type, entity_id, content_type, thread_id=thread_id, group_id=group_id)
        is_private = upload_is_private(purpose)
        cdn_url = upload_public_url(object_key, purpose)
        s3_available = s3_ready_for_upload()
        if PRODUCTION and not s3_available:
            record_upload_audit(conn, user["id"], "presign_denied", status="failed", reason="s3_unavailable", metadata={"purpose": purpose})
            raise APIError("生产环境对象存储暂不可用", 503, "s3_unavailable")
        # Browser-to-S3 PUT is fragile unless bucket CORS is perfectly
        # configured. Native clients do not have CORS, and direct-to-S3 keeps
        # large photo/video traffic off the app server when many users upload
        # at once. Web can keep the same-origin relay by omitting directS3.
        direct_requested = str(
            data.get("directS3")
            or data.get("direct_s3")
            or data.get("direct_s3_upload")
            or ""
        ).strip().lower() in {"1", "true", "yes", "ios", "native"}
        direct_s3 = bool(direct_requested and s3_available and not is_private)
        if is_private and s3_available:
            private_media_key()
        if direct_s3:
            try:
                upload_url = _s3_presigned_url("PUT", object_key, content_type=content_type, expires=S3_PRESIGN_EXPIRES_SECONDS)
            except APIError:
                if PRODUCTION:
                    record_upload_audit(conn, user["id"], "presign_denied", status="failed", reason="s3_presign_failed", metadata={"purpose": purpose})
                    raise
                direct_s3 = False
                s3_available = False
        if not direct_s3:
            token = _local_upload_token(upload_id, user["id"], object_key)
            base = self._request_base_url()
            path = f"/api/uploads/local/{upload_id}?token={quote(token, safe='')}"
            upload_url = f"{base}{path}" if base else path
        bucket = AWS_S3_BUCKET if s3_available else "local-dev"
        metadata = {
            "source": "s3-encrypted-pending" if is_private and s3_available else ("s3" if s3_available else "local"),
            "fileName": file_name[:240],
            "originalFileName": file_name[:240],
            "thumbnail_url": upload_thumbnail_url(object_key, content_type, purpose),
            "thread_id": thread_id,
            "group_id": group_id,
            "duration_seconds": duration_seconds,
            "moderation_status": "needs_review" if purpose.endswith("_video") else "clear",
            "processing_status": "pending" if purpose.endswith("_video") else "ready",
            "variants": {} if is_private else {
                "original": cdn_url,
                "large": cdn_url,
                "medium": cdn_url,
                "thumbnail": upload_thumbnail_url(object_key, content_type, purpose) or cdn_url,
            },
        }
        if UPLOAD_PURPOSES[purpose].get("kind") == "video":
            thumbnail_file_id = str(
                raw_metadata.get("thumbnailFileId")
                or raw_metadata.get("thumbnail_file_id")
                or raw_metadata.get("posterFileId")
                or raw_metadata.get("poster_file_id")
                or ""
            ).strip()
            if thumbnail_file_id:
                # Accept the new private DM poster purpose
                # (message_video_thumbnail) as well as the legacy public
                # video_thumbnail — the message_video body uses this same finalize
                # path, so a DM video's private cover must pass validation here.
                thumbnail_row = conn.execute(
                    """
                    SELECT * FROM uploaded_files
                     WHERE id = ?
                       AND user_id = ?
                       AND purpose IN ('video_thumbnail', 'message_video_thumbnail')
                       AND status = 'ready'
                       AND deleted_at IS NULL
                     LIMIT 1
                    """,
                    (thumbnail_file_id, user["id"]),
                ).fetchone()
                if not thumbnail_row:
                    raise APIError("视频封面尚未上传完成，请重新选择视频。", 400, "invalid_video_thumbnail")
                metadata["thumbnail_file_id"] = thumbnail_file_id
                metadata["poster_file_id"] = thumbnail_file_id
                thumbnail_media = uploaded_file_as_media(thumbnail_row)
                # A private poster has no public URL (upload_public_url returns
                # "" for private purposes); only cache a poster_url/thumbnail_url
                # here when the cover is a legacy PUBLIC video_thumbnail. Private
                # covers get a signed URL at read time via the attachment view-url.
                thumbnail_url = media_card_image_url(thumbnail_media)
                if thumbnail_url:
                    metadata["thumbnail_url"] = thumbnail_url
                    metadata["poster_url"] = thumbnail_url
                    variants = metadata.get("variants") if isinstance(metadata.get("variants"), dict) else {}
                    variants["thumbnail"] = thumbnail_url
                    variants["poster"] = thumbnail_url
                    metadata["variants"] = variants
        now = now_iso()
        conn.execute(
            """
            INSERT INTO uploaded_files (
                id, upload_id, user_id, bucket, object_key, public_url, cdn_url, content_type,
                file_size, file_type, purpose, entity_type, entity_id, status, metadata, created_at, updated_at
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'pending', ?, ?, ?)
            """,
            (
                file_id, upload_id, user["id"], bucket, object_key, cdn_url, cdn_url, content_type,
                file_size, upload_file_type(content_type), purpose, entity_type, entity_id,
                json.dumps(metadata, ensure_ascii=False, sort_keys=True), now, now,
            ),
        )
        record_upload_audit(
            conn,
            user["id"],
            "presign",
            file_id=file_id,
            upload_id=upload_id,
            status="pending",
            metadata={
                "purpose": purpose,
                "entityType": entity_type,
                "entityId": entity_id,
                "s3": s3_available,
                "directS3": direct_s3,
                "encrypted": is_private and s3_available,
            },
        )
        self.send_json({
            "ok": True,
            "data": {
                "uploadId": upload_id,
                "uploadUrl": upload_url,
                "fileKey": object_key,
                "bucket": bucket,
                "publicUrl": cdn_url or None,
                "cdnUrl": cdn_url,
                "expiresIn": S3_PRESIGN_EXPIRES_SECONDS,
                "headers": {"Content-Type": content_type},
                "file": serialize_uploaded_file(conn.execute("SELECT * FROM uploaded_files WHERE id = ?", (file_id,)).fetchone()),
            },
        })

    def api_upload_local_put(self, conn: sqlite3.Connection, upload_id: str, query: dict[str, str]) -> None:
        row = conn.execute("SELECT * FROM uploaded_files WHERE upload_id = ? AND deleted_at IS NULL", (upload_id,)).fetchone()
        if not row:
            raise APIError("上传不存在", 404, "upload_not_found")
        d = dict(row)
        expected_token = _local_upload_token(upload_id, d.get("user_id") or "", d.get("object_key") or "")
        if not expected_token or not hmac.compare_digest(expected_token, query.get("token") or ""):
            raise APIError("上传地址已失效", 403, "invalid_upload_token")
        if d.get("status") not in {"pending", "failed"}:
            raise APIError("上传状态不允许覆盖", 409, "invalid_upload_state")
        length = int(self.headers.get("Content-Length", 0) or 0)
        if length <= 0:
            raise APIError("empty upload", 400, "invalid_payload")
        if length != int(d["file_size"] or 0) or length > min(S3_UPLOAD_MAX_SIZE, int(UPLOAD_PURPOSES[d["purpose"]]["max"])):
            conn.execute("UPDATE uploaded_files SET status = 'failed', updated_at = ? WHERE id = ?", (now_iso(), d["id"]))
            record_upload_audit(conn, d["user_id"], "put_failed", file_id=d["id"], upload_id=upload_id, status="failed", reason="file_size_mismatch")
            raise APIError("文件大小与签名不一致", 400, "file_size_mismatch")
        s3_backed = d.get("bucket") != "local-dev"
        private_s3 = s3_backed and upload_is_private(str(d.get("purpose") or ""))
        public_s3 = s3_backed and not private_s3
        checksum = ""
        etag = ""
        encryption: dict[str, Any] | None = None
        temp_name = ""
        try:
            with _DBLockReleased():
                if private_s3:
                    encryptor, iv = private_media_encryptor()
                    plain_sha = hashlib.sha256()
                    plain_md5 = hashlib.md5()
                    first_chunk = b""
                    remaining = length
                    with tempfile.NamedTemporaryFile(prefix="machi-private-", suffix=".enc", delete=False) as encrypted_file:
                        temp_name = encrypted_file.name
                        while remaining:
                            chunk = self.rfile.read(min(PRIVATE_MEDIA_CHUNK_SIZE, remaining))
                            if not chunk:
                                raise APIError("上传内容不完整", 400, "upload_truncated")
                            if not first_chunk:
                                first_chunk = chunk
                            remaining -= len(chunk)
                            plain_sha.update(chunk)
                            plain_md5.update(chunk)
                            encrypted_file.write(encryptor.update(chunk))
                        encrypted_file.write(encryptor.finalize())
                    validate_upload_magic(first_chunk, d["content_type"])
                    encryption = private_media_encryption_metadata(iv, encryptor.tag)
                    _s3_client().upload_file(
                        temp_name,
                        AWS_S3_BUCKET,
                        d["object_key"],
                        ExtraArgs={
                            "ContentType": "application/octet-stream",
                            "Metadata": {
                                "machi-private": "aes-256-gcm",
                                "machi-cipher-version": str(PRIVATE_MEDIA_CIPHER_VERSION),
                            },
                        },
                    )
                    head = _s3_head_object(d["object_key"])
                    if int(head.get("ContentLength") or -1) != length:
                        _s3_delete_object(d["object_key"])
                        raise APIError("私密媒体上传校验失败", 502, "private_media_upload_verify_failed")
                    checksum = plain_sha.hexdigest()
                    etag = plain_md5.hexdigest()
                elif public_s3:
                    plain_sha = hashlib.sha256()
                    plain_md5 = hashlib.md5()
                    first_chunk = b""
                    remaining = length
                    with tempfile.NamedTemporaryFile(prefix="machi-public-", suffix=".upload", delete=False) as upload_file:
                        temp_name = upload_file.name
                        while remaining:
                            chunk = self.rfile.read(min(PRIVATE_MEDIA_CHUNK_SIZE, remaining))
                            if not chunk:
                                raise APIError("上传内容不完整", 400, "upload_truncated")
                            if not first_chunk:
                                first_chunk = chunk
                            remaining -= len(chunk)
                            plain_sha.update(chunk)
                            plain_md5.update(chunk)
                            upload_file.write(chunk)
                    validate_upload_magic(first_chunk, d["content_type"])
                    _s3_client().upload_file(
                        temp_name,
                        AWS_S3_BUCKET,
                        d["object_key"],
                        ExtraArgs={"ContentType": d["content_type"]},
                    )
                    head = _s3_head_object(d["object_key"])
                    if int(head.get("ContentLength") or -1) != length:
                        _s3_delete_object(d["object_key"])
                        raise APIError("媒体上传校验失败", 502, "s3_upload_verify_failed")
                    checksum = plain_sha.hexdigest()
                    etag = plain_md5.hexdigest()
                else:
                    raw = self.rfile.read(length)
                    if len(raw) != length:
                        raise APIError("上传内容不完整", 400, "upload_truncated")
                    validate_upload_magic(raw, d["content_type"])
                    target = local_upload_path(d["object_key"])
                    target.parent.mkdir(parents=True, exist_ok=True)
                    target.write_bytes(raw)
                    checksum = hashlib.sha256(raw).hexdigest()
                    etag = hashlib.md5(raw).hexdigest()
        except APIError as exc:
            conn.execute("UPDATE uploaded_files SET status = 'failed', updated_at = ? WHERE id = ?", (now_iso(), d["id"]))
            record_upload_audit(conn, d["user_id"], "put_failed", file_id=d["id"], upload_id=upload_id, status="failed", reason=exc.code)
            raise
        except (BotoCoreError, ClientError, OSError) as exc:
            conn.execute("UPDATE uploaded_files SET status = 'failed', updated_at = ? WHERE id = ?", (now_iso(), d["id"]))
            reason = "private_media_store_failed" if private_s3 else "media_store_failed"
            message = "私密媒体存储失败" if private_s3 else "媒体存储失败"
            record_upload_audit(conn, d["user_id"], "put_failed", file_id=d["id"], upload_id=upload_id, status="failed", reason=reason)
            raise APIError(message, 502, reason) from exc
        finally:
            if temp_name:
                try:
                    Path(temp_name).unlink(missing_ok=True)
                except OSError:
                    pass
        # CSAM / known-bad media gate: now that the full content checksum is
        # known, reject and PURGE the just-stored object if its hash is on the
        # blocklist, before the upload is ever marked usable.
        if checksum and media_hash_blocked(conn, checksum):
            try:
                if s3_backed:
                    _s3_delete_object(d["object_key"])
                else:
                    local_upload_path(d["object_key"]).unlink(missing_ok=True)
            except Exception:
                pass
            conn.execute("UPDATE uploaded_files SET status = 'failed', updated_at = ? WHERE id = ?", (now_iso(), d["id"]))
            record_upload_audit(conn, d["user_id"], "put_blocked", file_id=d["id"], upload_id=upload_id, status="failed", reason="media_blocked")
            ERR_LOG.warning("blocked media upload by hash user=%s upload=%s", d["user_id"], upload_id)
            raise APIError("该文件无法上传", 422, "media_blocked")
        metadata = json.loads(d.get("metadata") or "{}")
        if encryption:
            metadata["source"] = "s3-encrypted"
            metadata["encryption"] = encryption
            metadata["encrypted_at"] = now_iso()
        conn.execute(
            "UPDATE uploaded_files SET status = 'uploaded', checksum = ?, etag = ?, metadata = ?, updated_at = ? WHERE id = ?",
            (checksum, etag, json.dumps(metadata, ensure_ascii=False, sort_keys=True), now_iso(), d["id"]),
        )
        record_upload_audit(
            conn,
            d["user_id"],
            "put",
            file_id=d["id"],
            upload_id=upload_id,
            status="uploaded",
            metadata={"bytes": length, "encrypted": bool(encryption)},
        )
        self.send_empty(200, {"ETag": etag})

    def api_upload_complete(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        upload_id = str(data.get("uploadId") or data.get("upload_id") or "").strip()
        file_key = str(data.get("fileKey") or data.get("file_key") or "").strip()
        row = conn.execute(
            "SELECT * FROM uploaded_files WHERE upload_id = ? AND user_id = ? AND deleted_at IS NULL",
            (upload_id, user["id"]),
        ).fetchone()
        if not row:
            raise APIError("上传不存在", 404, "upload_not_found")
        d = dict(row)
        if file_key and file_key != d["object_key"]:
            raise APIError("fileKey 不匹配", 400, "file_key_mismatch")
        if d["status"] not in {"pending", "uploaded", "processing", "ready", "failed"}:
            raise APIError("上传状态不正确", 409, "invalid_upload_state")
        head: dict[str, Any] = {}
        if d.get("bucket") != "local-dev":
            try:
                head = _s3_head_object(d["object_key"])
            except APIError as exc:
                record_upload_audit(conn, user["id"], "complete_failed", file_id=d["id"], upload_id=upload_id, status="failed", reason=exc.code, metadata={"objectKey": d["object_key"]})
                raise
            content_length = int(head.get("ContentLength") or 0)
            if content_length <= 0:
                raise APIError("S3 文件为空", 400, "s3_object_empty")
            if content_length != int(d["file_size"] or 0):
                raise APIError("S3 文件大小与签名不匹配", 400, "s3_size_mismatch")
            if not upload_is_private(str(d.get("purpose") or "")):
                try:
                    validate_upload_magic(_s3_read_prefix(d["object_key"]), d["content_type"])
                except APIError as exc:
                    _s3_delete_object(d["object_key"])
                    conn.execute(
                        "UPDATE uploaded_files SET status = 'failed', updated_at = ? WHERE id = ?",
                        (now_iso(), d["id"]),
                    )
                    record_upload_audit(
                        conn,
                        user["id"],
                        "complete_failed",
                        file_id=d["id"],
                        upload_id=upload_id,
                        status="failed",
                        reason=exc.code,
                        metadata={"objectKey": d["object_key"]},
                    )
                    raise
        elif not local_upload_path(d["object_key"]).exists():
            raise APIError("文件尚未上传完成", 400, "upload_not_found")
        width = max(0, int(data.get("width") or 0))
        height = max(0, int(data.get("height") or 0))
        duration = max(0.0, float(data.get("duration") or data.get("durationSeconds") or data.get("duration_seconds") or 0))
        etag = str(data.get("etag") or head.get("ETag") or d.get("etag") or "").strip().strip('"')
        metadata = json.loads(d.get("metadata") or "{}")
        metadata["thumbnail_url"] = metadata.get("thumbnail_url") or upload_thumbnail_url(d["object_key"], d["content_type"], d["purpose"])
        if thumbnail_eligible({**d, "status": "ready"}):
            metadata["thumbnail_status"] = "queued"
        metadata["completed_at"] = now_iso()
        if head:
            metadata["s3_head_checked_at"] = metadata["completed_at"]
        conn.execute(
            """
            UPDATE uploaded_files
               SET status = 'ready', width = ?, height = ?, duration = ?, etag = ?, metadata = ?, updated_at = ?
             WHERE id = ?
            """,
            (width, height, duration, etag, json.dumps(metadata, ensure_ascii=False, sort_keys=True), now_iso(), d["id"]),
        )
        fresh = dict(conn.execute("SELECT * FROM uploaded_files WHERE id = ?", (d["id"],)).fetchone())
        media = uploaded_file_as_media(fresh)
        conn.execute(
            """
            INSERT INTO media (id, owner_id, type, url, thumb_url, mime, width, height, duration, byte_size, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT(id) DO UPDATE SET
                url = excluded.url,
                thumb_url = excluded.thumb_url,
                mime = excluded.mime,
                width = excluded.width,
                height = excluded.height,
                duration = excluded.duration,
                byte_size = excluded.byte_size,
                deleted_at = NULL
            """,
            (
                media["id"], media["owner_id"], media["type"], media["url"], media["thumb_url"],
                media["mime"], media["width"], media["height"], media["duration"], media["byte_size"], media["created_at"],
            ),
        )
        if fresh["purpose"] in {"avatar", "profile_cover"}:
            field = "avatar_url" if fresh["purpose"] == "avatar" else "cover_url"
            conn.execute(f"UPDATE users SET {field} = ?, updated_at = ? WHERE id = ?", (media["url"], now_iso(), user["id"]))
        if thumbnail_eligible(fresh):
            enqueue_thumbnail(fresh["id"])
        record_upload_audit(conn, user["id"], "complete", file_id=fresh["id"], upload_id=upload_id, status="ready")
        self.send_json({"ok": True, "data": {"file": serialize_uploaded_file(fresh), "media": media}, "file": serialize_uploaded_file(fresh), "media": media})

    def _uploaded_file_for_user(self, conn: sqlite3.Connection, file_id: str, user: dict[str, Any]) -> dict[str, Any]:
        row = conn.execute("SELECT * FROM uploaded_files WHERE id = ? AND deleted_at IS NULL", (file_id,)).fetchone()
        if not row:
            raise APIError("文件不存在", 404, "file_not_found")
        d = dict(row)
        if d["user_id"] != user["id"] and user.get("role") != "admin":
            raise APIError("无权操作", 403, "forbidden")
        return d

    def api_upload_get(self, conn: sqlite3.Connection, file_id: str) -> None:
        user = self.require_user(conn)
        d = self._uploaded_file_for_user(conn, file_id, user)
        self.send_json({"ok": True, "data": {"file": serialize_uploaded_file(d)}, "file": serialize_uploaded_file(d)})

    def api_upload_private_view_url(self, conn: sqlite3.Connection, file_id: str) -> None:
        user = self.require_user(conn)
        d = self._uploaded_file_for_user(conn, file_id, user)
        if not upload_is_private(str(d.get("purpose") or "")):
            raise APIError("公开文件无需私密查看链接", 400, "private_upload_required")
        if str(d.get("status") or "") not in {"uploaded", "processing", "ready"}:
            raise APIError("文件尚未可用", 409, "file_not_ready")
        expires = S3_PRIVATE_DOWNLOAD_EXPIRES_SECONDS
        url = self._private_download_url(file_id, expires)
        record_upload_audit(
            conn,
            user["id"],
            "private_view_url",
            file_id=file_id,
            status="ready",
            metadata={"purpose": d.get("purpose") or "", "expires": expires},
        )
        self.send_json({
            "ok": True,
            "data": {"url": url, "expiresIn": expires},
            "url": url,
            "expiresIn": expires,
        })

    def api_upload_delete(self, conn: sqlite3.Connection, file_id: str) -> None:
        user = self.require_user(conn)
        d = self._uploaded_file_for_user(conn, file_id, user)
        linked = conn.execute(
            """
            SELECT
              (SELECT COUNT(*) FROM post_media WHERE media_id = ?) +
              (SELECT COUNT(*) FROM message_media WHERE media_id = ?) +
              (SELECT COUNT(*) FROM message_attachments WHERE uploaded_file_id = ? AND deleted_at IS NULL) +
              (SELECT COUNT(*) FROM listing_media WHERE uploaded_file_id = ? OR id = ?) AS c
            """,
            (file_id, file_id, file_id, file_id, file_id),
        ).fetchone()["c"]
        if int(linked or 0) > 0 and user.get("role") != "admin":
            raise APIError("文件已被内容使用，请先解除关联", 409, "file_in_use")
        now = now_iso()
        conn.execute("UPDATE uploaded_files SET status = 'deleted', deleted_at = ?, updated_at = ? WHERE id = ?", (now, now, file_id))
        conn.execute("UPDATE media SET deleted_at = ? WHERE id = ?", (now, file_id))
        record_upload_audit(conn, user["id"], "delete_mark", file_id=file_id, status="deleted")
        self.send_json({"ok": True, "status": "deleted"})

    def api_admin_uploads(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        self.require_admin(conn)
        limit = max(1, min(int(query.get("limit") or 100), 300))
        status = (query.get("status") or "").strip()
        purpose = (query.get("purpose") or "").strip()
        user_id = (query.get("userId") or query.get("user_id") or "").strip()
        q = (query.get("q") or "").strip()
        incomplete = (query.get("incomplete") or "").strip().lower() in {"1", "true", "yes"}
        large = (query.get("large") or "").strip().lower() in {"1", "true", "yes"}
        check_object = (query.get("checkObject") or query.get("check_object") or "").strip().lower() in {"1", "true", "yes"}
        clauses = ["1 = 1"]
        params: list[Any] = []
        if status:
            clauses.append("f.status = ?")
            params.append(status)
        if purpose:
            clauses.append("f.purpose = ?")
            params.append(purpose)
        if user_id:
            clauses.append("f.user_id = ?")
            params.append(user_id)
        if incomplete:
            clauses.append("f.status IN ('pending','uploaded','processing','failed')")
        if large:
            clauses.append("f.file_size >= ?")
            params.append(10 * 1024 * 1024)
        if q:
            like = f"%{q}%"
            clauses.append("(f.id LIKE ? OR f.upload_id LIKE ? OR f.object_key LIKE ? OR u.handle LIKE ? OR u.display_name LIKE ?)")
            params.extend([like, like, like, like, like])
        where_sql = " AND ".join(clauses)
        rows = conn.execute(
            f"""
            SELECT f.*, u.handle AS owner_handle, u.display_name AS owner_name
              FROM uploaded_files f
              LEFT JOIN users u ON u.id = f.user_id
             WHERE {where_sql}
             ORDER BY f.created_at DESC
             LIMIT ?
            """,
            [*params, limit],
        ).fetchall()
        total = conn.execute(
            f"SELECT COUNT(*) AS c FROM uploaded_files f LEFT JOIN users u ON u.id = f.user_id WHERE {where_sql}",
            params,
        ).fetchone()["c"]
        items = []
        for row in rows:
            item = serialize_uploaded_file(row)
            item["ownerHandle"] = row["owner_handle"] or ""
            item["ownerName"] = row["owner_name"] or ""
            if check_object:
                if row["bucket"] == "local-dev":
                    item["objectExists"] = local_upload_path(row["object_key"]).exists()
                elif row["status"] not in {"pending", "deleted"}:
                    try:
                        _s3_head_object(row["object_key"])
                        item["objectExists"] = True
                    except APIError:
                        item["objectExists"] = False
            items.append(item)
        self.send_json({"ok": True, "items": items, "total": int(total or 0)})

    def api_admin_update_upload(self, conn: sqlite3.Connection, file_id: str) -> None:
        admin = self.require_admin(conn)
        row = conn.execute("SELECT * FROM uploaded_files WHERE id = ?", (file_id,)).fetchone()
        if not row:
            raise APIError("文件不存在", 404, "file_not_found")
        data = self.read_json()
        updates: dict[str, Any] = {}
        try:
            current_metadata = json.loads(row["metadata"] or "{}")
        except json.JSONDecodeError:
            current_metadata = {}
        metadata = dict(current_metadata)
        action = str(data.get("action") or "").strip()
        if action == "restore":
            updates["status"] = "ready"
            updates["deleted_at"] = ""
            metadata["restored_at"] = now_iso()
        elif action in {"flag", "mark_abnormal"}:
            updates["status"] = "failed"
            metadata["flagged"] = True
            metadata["flag_reason"] = str(data.get("reason") or "admin_flagged")[:240]
            metadata["flagged_at"] = now_iso()
        if "status" in data:
            status = str(data.get("status") or "").strip()
            if status not in {"pending", "uploaded", "processing", "ready", "failed", "deleted"}:
                raise APIError("状态不合法", 400, "invalid_status")
            updates["status"] = status
            if status == "deleted":
                updates["deleted_at"] = now_iso()
            else:
                updates["deleted_at"] = ""
        if "metadata" in data and isinstance(data["metadata"], dict):
            metadata.update(data["metadata"])
        if metadata != current_metadata:
            updates["metadata"] = json.dumps(metadata, ensure_ascii=False, sort_keys=True)
        if not updates:
            return self.send_json({"ok": True, "file": serialize_uploaded_file(row)})
        updates["updated_at"] = now_iso()
        cols = ", ".join(f"{col} = ?" for col in updates)
        conn.execute(f"UPDATE uploaded_files SET {cols} WHERE id = ?", [*updates.values(), file_id])
        fresh = conn.execute("SELECT * FROM uploaded_files WHERE id = ?", (file_id,)).fetchone()
        record_upload_audit(conn, admin["id"], "admin_update", file_id=file_id, status=updates.get("status", ""), metadata={"fields": list(updates.keys())})
        self.send_json({"ok": True, "file": serialize_uploaded_file(fresh)})

    def api_admin_cleanup_temp_uploads(self, conn: sqlite3.Connection) -> None:
        admin = self.require_admin(conn)
        data = self.read_json()
        hours = max(1, min(int(data.get("hours") or 24), 720))
        hard_delete = bool(data.get("hardDelete"))
        cutoff = (datetime.now(timezone.utc) - timedelta(hours=hours)).isoformat()
        rows = conn.execute(
            """
            SELECT * FROM uploaded_files
             WHERE deleted_at IS NULL
               AND created_at < ?
               AND (status IN ('pending','failed') OR object_key LIKE 'temp/%')
             ORDER BY created_at ASC
             LIMIT 500
            """,
            (cutoff,),
        ).fetchall()
        now = now_iso()
        deleted_objects = 0
        for row in rows:
            d = dict(row)
            conn.execute(
                "UPDATE uploaded_files SET status = 'deleted', deleted_at = ?, updated_at = ? WHERE id = ?",
                (now, now, d["id"]),
            )
            if hard_delete and (d.get("object_key") or "").startswith("temp/"):
                if d.get("bucket") == "local-dev":
                    target = local_upload_path(d["object_key"])
                    if target.exists() and target.is_file():
                        try:
                            target.unlink()
                            deleted_objects += 1
                        except OSError:
                            pass
                elif _s3_delete_object(d["object_key"]):
                    deleted_objects += 1
            record_upload_audit(conn, admin["id"], "temp_cleanup", file_id=d["id"], upload_id=d.get("upload_id") or "", status="deleted", metadata={"hours": hours, "hardDelete": hard_delete})
        record_admin_action(conn, admin["id"], "uploads_cleanup_temp", target_kind="uploaded_files", target_id="bulk", metadata={"count": len(rows), "deletedObjects": deleted_objects, "hours": hours, "hardDelete": hard_delete})
        self.send_json({"ok": True, "count": len(rows), "deletedObjects": deleted_objects})

    def api_admin_delete_upload(self, conn: sqlite3.Connection, file_id: str) -> None:
        admin = self.require_admin(conn)
        if not conn.execute("SELECT id FROM uploaded_files WHERE id = ?", (file_id,)).fetchone():
            raise APIError("文件不存在", 404, "file_not_found")
        now = now_iso()
        conn.execute("UPDATE uploaded_files SET status = 'deleted', deleted_at = ?, updated_at = ? WHERE id = ?", (now, now, file_id))
        conn.execute("UPDATE media SET deleted_at = ? WHERE id = ?", (now, file_id))
        record_upload_audit(conn, admin["id"], "admin_delete_mark", file_id=file_id, status="deleted")
        self.send_json({"ok": True, "status": "deleted"})

    def _find_uploaded_file_by_url_or_id(self, conn: sqlite3.Connection, value: str) -> dict[str, Any] | None:
        raw = (value or "").strip()
        if not raw:
            return None
        row = conn.execute(
            """
            SELECT * FROM uploaded_files
             WHERE (id = ? OR cdn_url = ? OR public_url = ? OR object_key = ?)
               AND deleted_at IS NULL
               AND status IN ('uploaded','processing','ready')
             ORDER BY created_at DESC LIMIT 1
            """,
            (raw, raw, raw, raw.removeprefix("/media/")),
        ).fetchone()
        return dict(row) if row else None

    def api_guide_product_download_url(self, conn: sqlite3.Connection, product_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute("SELECT * FROM guide_products WHERE id = ? OR slug = ? LIMIT 1", (product_id, product_id)).fetchone()
        if not row:
            raise APIError("资料/服务不存在", 404, "guide_product_not_found")
        if row["status"] != "published" or bool(row["is_coming_soon"]):
            raise APIError("资料尚未发布", 404, "guide_product_not_available")
        if bool(row["is_service"]) or not bool(row["is_digital"]):
            raise APIError("该项目不是可下载资料", 400, "guide_product_not_downloadable")
        owned = conn.execute(
            "SELECT 1 FROM guide_orders WHERE user_id = ? AND product_id = ? AND status IN ('paid','fulfilled') LIMIT 1",
            (user["id"], row["id"]),
        ).fetchone() is not None
        # A points purchase (or any other path) grants a generic entitlement.
        if not owned and user_has_entitlement(conn, user["id"], _guide_product_resource_type(dict(row)), row["id"]):
            owned = True
        member_unlocked = bool(row["is_member_included"]) and not bool(row["is_service"]) and has_active_membership(conn, user["id"])
        if not (owned or member_unlocked or bool(row["is_free"])):
            record_upload_audit(conn, user["id"], "download_denied", status="failed", reason="not_entitled", metadata={"productId": row["id"]})
            raise APIError("未解锁该资料", 403, "not_entitled")
        file_ref = row["file_url"] or ""
        upload = self._find_uploaded_file_by_url_or_id(conn, file_ref)
        if not upload:
            files = conn.execute(
                """
                SELECT f.* FROM guide_product_files g
                JOIN uploaded_files f ON f.id = g.uploaded_file_id
                WHERE g.product_id = ?
                  AND f.deleted_at IS NULL
                  AND f.status IN ('uploaded','processing','ready')
                ORDER BY g.created_at DESC LIMIT 1
                """,
                (row["id"],),
            ).fetchone()
            upload = dict(files) if files else None
        if not upload:
            raise APIError("资料文件尚未配置", 404, "guide_file_not_found")
        if str(upload.get("purpose") or "") not in {"guide_product_file", "member_resource_file"}:
            raise APIError("资料文件类型不正确", 400, "invalid_guide_file")
        expires = S3_PRIVATE_DOWNLOAD_EXPIRES_SECONDS
        url = self._private_download_url(upload["id"], expires)
        record_upload_audit(conn, user["id"], "download_url", file_id=upload["id"], status="ready", metadata={"productId": row["id"], "expires": expires})
        self.send_json({"ok": True, "downloadUrl": url, "expiresIn": expires, "file": serialize_uploaded_file(upload)})

    def api_member_resource_download_url(self, conn: sqlite3.Connection, resource_id: str) -> None:
        user = self.require_user(conn)
        row = conn.execute(
            """
            SELECT * FROM guide_products
             WHERE (id = ? OR slug = ?)
               AND is_member_included = 1
               AND is_service = 0
               AND status = 'published'
             LIMIT 1
            """,
            (resource_id, resource_id),
        ).fetchone()
        if not row:
            raise APIError("会员资料不存在", 404, "member_resource_not_found")
        if not has_active_membership(conn, user["id"]):
            record_upload_audit(conn, user["id"], "member_download_denied", status="failed", reason="membership_required", metadata={"resourceId": row["id"]})
            raise APIError("下载会员资料需要有效会员", 403, "MEMBERSHIP_REQUIRED")
        upload = self._find_uploaded_file_by_url_or_id(conn, row["file_url"] or "")
        if not upload:
            files = conn.execute(
                """
                SELECT f.* FROM guide_product_files g
                JOIN uploaded_files f ON f.id = g.uploaded_file_id
                WHERE g.product_id = ?
                  AND f.deleted_at IS NULL
                  AND f.status IN ('uploaded','processing','ready')
                ORDER BY g.created_at DESC LIMIT 1
                """,
                (row["id"],),
            ).fetchone()
            upload = dict(files) if files else None
        if not upload:
            raise APIError("会员资料文件尚未配置", 404, "member_resource_file_not_found")
        if str(upload.get("purpose") or "") != "member_resource_file":
            raise APIError("会员资料文件类型不正确", 400, "invalid_member_resource_file")
        expires = S3_PRIVATE_DOWNLOAD_EXPIRES_SECONDS
        url = self._private_download_url(upload["id"], expires)
        record_upload_audit(conn, user["id"], "member_download_url", file_id=upload["id"], status="ready", metadata={"resourceId": row["id"], "expires": expires})
        self.send_json({"ok": True, "downloadUrl": url, "expiresIn": expires, "file": serialize_uploaded_file(upload)})

    def api_upload_signed_download(self, conn: sqlite3.Connection, file_id: str, query: dict[str, str]) -> None:
        if not _verify_local_download_token(file_id, query.get("token") or ""):
            raise APIError("下载链接已失效", 403, "invalid_download_token")
        row = conn.execute(
            "SELECT * FROM uploaded_files WHERE id = ? AND status IN ('uploaded','processing','ready') AND deleted_at IS NULL",
            (file_id,),
        ).fetchone()
        if not row:
            raise APIError("文件不存在", 404, "file_not_found")
        d = dict(row)
        if not upload_is_private(str(d.get("purpose") or "")):
            raise APIError("该下载地址仅用于私密媒体", 403, "private_download_required")
        download_path: Path | None = None
        remove_after = False
        try:
            if d.get("bucket") == "local-dev":
                download_path = local_upload_path(d["object_key"])
                if not download_path.exists() or download_path.is_dir():
                    raise APIError("文件不存在", 404, "file_not_found")
            else:
                try:
                    metadata = json.loads(d.get("metadata") or "{}")
                except (TypeError, json.JSONDecodeError):
                    metadata = {}
                decryptor = private_media_decryptor(metadata)
                from cryptography.exceptions import InvalidTag
                with _DBLockReleased():
                    try:
                        response = _s3_client().get_object(Bucket=AWS_S3_BUCKET, Key=d["object_key"])
                    except ClientError as exc:
                        code = str((getattr(exc, "response", {}) or {}).get("Error", {}).get("Code") or "")
                        if code in {"404", "NoSuchKey", "NotFound"}:
                            raise APIError("文件不存在", 404, "file_not_found") from exc
                        raise APIError("私密媒体读取失败", 502, "private_media_read_failed") from exc
                    except (BotoCoreError, NoCredentialsError) as exc:
                        raise APIError("私密媒体读取失败", 502, "private_media_read_failed") from exc
                    body = response["Body"]
                    with tempfile.NamedTemporaryFile(prefix="machi-private-download-", delete=False) as plain_file:
                        download_path = Path(plain_file.name)
                        remove_after = True
                        try:
                            while True:
                                chunk = body.read(PRIVATE_MEDIA_CHUNK_SIZE)
                                if not chunk:
                                    break
                                plain_file.write(decryptor.update(chunk))
                            plain_file.write(decryptor.finalize())
                        except InvalidTag as exc:
                            raise APIError("私密媒体完整性校验失败", 502, "private_media_integrity_failed") from exc
                        finally:
                            body.close()
                expected_size = int(d.get("file_size") or 0)
                actual_size = download_path.stat().st_size
                if expected_size and actual_size != expected_size:
                    raise APIError("私密媒体大小校验失败", 502, "private_media_size_mismatch")

            size = download_path.stat().st_size
            filename = Path(d["object_key"]).name.replace('"', "")
            content_type = d["content_type"] or "application/octet-stream"
            # Images/video/audio are meant to render inline (an <video> tag or
            # AVPlayer), not be force-downloaded. Other private files keep the
            # attachment disposition with a filename.
            is_inline_media = content_type.startswith(("image/", "video/", "audio/"))
            disposition = "inline" if is_inline_media else f'attachment; filename="{filename}"'

            # Parse a byte-range request. AVPlayer (and HTML <video>) stream
            # media by issuing Range requests; without 206 support the player
            # can't seek or progressively play, so message videos showed a
            # black frame. We always advertise Accept-Ranges and honor a single
            # range. (GCM ciphertext can't be seeked, so the object is already
            # fully decrypted to download_path above — we just serve a slice.)
            range_header = (self.headers.get("Range") or "").strip()
            start = 0
            end = size - 1
            is_range = False
            unsatisfiable = False
            if range_header.startswith("bytes=") and size > 0:
                spec = range_header[len("bytes="):].split(",")[0].strip()
                first, sep, last = spec.partition("-")
                if sep:
                    try:
                        if first.strip() == "":
                            # Suffix range: final N bytes.
                            suffix = int(last)
                            if suffix > 0:
                                start = max(0, size - suffix)
                                end = size - 1
                                is_range = True
                        else:
                            start = int(first)
                            end = int(last) if last.strip() else size - 1
                            if start >= size:
                                unsatisfiable = True
                            elif start <= end:
                                end = min(end, size - 1)
                                is_range = True
                    except ValueError:
                        is_range = False

            if unsatisfiable:
                self.send_response(416)
                self.send_header("Content-Range", f"bytes */{size}")
                self.send_header("Accept-Ranges", "bytes")
                self.send_header("Content-Length", "0")
                self._set_cors()
                self._set_security_headers()
                self.end_headers()
                return

            length = (end - start + 1) if is_range else size
            self.send_response(206 if is_range else 200)
            self.send_header("Content-Type", content_type)
            self.send_header("Content-Length", str(length))
            self.send_header("Accept-Ranges", "bytes")
            if is_range:
                self.send_header("Content-Range", f"bytes {start}-{end}/{size}")
            self.send_header("Cache-Control", "private, no-store")
            self.send_header("Content-Disposition", disposition)
            self._set_cors()
            self._set_security_headers()
            self.end_headers()
            try:
                with download_path.open("rb") as source:
                    if is_range:
                        source.seek(start)
                    remaining = length
                    while remaining > 0:
                        chunk = source.read(min(PRIVATE_MEDIA_CHUNK_SIZE, remaining))
                        if not chunk:
                            break
                        self.wfile.write(chunk)
                        remaining -= len(chunk)
            except (BrokenPipeError, ConnectionResetError):
                # The player closed the connection after probing a range — a
                # normal part of seeking, not an error worth surfacing.
                pass
        finally:
            if remove_after and download_path is not None:
                try:
                    download_path.unlink(missing_ok=True)
                except OSError:
                    pass

    def api_upload_media(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        ctype = self.headers.get("Content-Type", "")
        if "multipart/form-data" in ctype:
            self._upload_multipart(conn, user)
            return
        data = self.read_json()
        base64_payload = data.get("data") or ""
        declared_mime = (data.get("mime") or "").lower()
        if not base64_payload.startswith("data:"):
            raise APIError("invalid payload", 400, "invalid_payload")
        header, b64data = base64_payload.split(",", 1)
        if "base64" not in header:
            raise APIError("invalid payload", 400, "invalid_payload")
        try:
            raw = base64.b64decode(b64data, validate=True)
        except Exception as exc:
            raise APIError(f"decode failed: {exc}", 400, "invalid_payload")
        self._persist_media(conn, user, raw, declared_mime)

    def _upload_multipart(self, conn: sqlite3.Connection, user: dict[str, Any]) -> None:
        ctype = self.headers.get("Content-Type", "")
        boundary = None
        for part in ctype.split(";"):
            part = part.strip()
            if part.startswith("boundary="):
                boundary = part[len("boundary="):].strip('"')
                break
        if not boundary:
            raise APIError("missing boundary", 400, "invalid_payload")
        raw = self.read_bytes()
        # Parse exactly per RFC 7578. The body looks like:
        #   --boundary\r\n<headers>\r\n\r\n<part>\r\n--boundary\r\n<headers>...
        # ending with --boundary--\r\n. The previous implementation
        # used `body.rstrip(b"\r\n--")` which stripped by character set
        # and would corrupt any file whose final bytes were any
        # combination of \r \n -.
        delimiter = b"--" + boundary.encode()
        try:
            sections = raw.split(delimiter)
        except Exception:
            raise APIError("invalid multipart", 400, "invalid_payload")
        for section in sections:
            if not section or section.startswith(b"--"):
                # Either the leading empty chunk (before the first
                # delimiter) or the closing "--\r\n" marker.
                continue
            if section.startswith(b"\r\n"):
                section = section[2:]
            header_blob, sep, body = section.partition(b"\r\n\r\n")
            if not sep:
                continue
            headers_text = header_blob.decode("utf-8", errors="replace")
            if 'name="file"' not in headers_text:
                continue
            # Every part ends with the literal CRLF that precedes the
            # next delimiter. Strip exactly that — never use rstrip on
            # binary data.
            if body.endswith(b"\r\n"):
                body = body[:-2]
            mime_match = re.search(r"Content-Type:\s*([^\r\n]+)", headers_text)
            declared_mime = (mime_match.group(1).strip().lower() if mime_match else "")
            self._persist_media(conn, user, body, declared_mime)
            return
        raise APIError("no file part", 400, "invalid_payload")

    def _persist_media(
        self,
        conn: sqlite3.Connection,
        user: dict[str, Any],
        raw: bytes,
        declared_mime: str,
    ) -> None:
        if not raw:
            raise APIError("empty upload", 400, "invalid_payload")
        if len(raw) > MAX_UPLOAD_BYTES:
            raise APIError("file too large", 413, "too_large")
        sniffed = _sniff_mime(raw)
        if not sniffed:
            raise APIError("不支持的文件类型", 415, "unsupported_media")
        # Trust the bytes over the client-declared header. When the
        # declared mime is also in our allowlist and matches what we
        # sniffed, we use it for the canonical record. Otherwise fall
        # back to what the bytes say.
        mime = declared_mime if declared_mime in ALLOWED_MIME and declared_mime == sniffed else sniffed
        if mime not in ALLOWED_MIME:
            raise APIError("不支持的文件类型", 415, "unsupported_media")
        sha = hashlib.sha256(raw).hexdigest()
        if media_hash_blocked(conn, sha):
            ERR_LOG.warning("blocked media upload by hash user=%s", user["id"])
            raise APIError("该文件无法上传", 422, "media_blocked")
        ext = EXT_BY_MIME.get(mime, ".bin")
        media_id = "file_" + uuid.uuid4().hex
        object_key = f"legacy/{user['id']}/{media_id}{ext}"
        target = local_upload_path(object_key)
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_bytes(raw)
        kind = "image" if mime.startswith("image/") else "video" if mime.startswith("video/") else "file"
        url = upload_public_url(object_key)
        thumb_url = upload_thumbnail_url(object_key, mime) or url
        now = now_iso()
        metadata = {
            "source": "legacy_media_upload",
            "thumbnail_url": thumb_url,
            "variants": {"original": url, "large": url, "medium": url, "thumbnail": thumb_url},
        }
        conn.execute(
            """
            INSERT INTO uploaded_files (
                id, upload_id, user_id, bucket, object_key, public_url, cdn_url, content_type,
                file_size, file_type, purpose, entity_type, entity_id, status, checksum, etag,
                metadata, created_at, updated_at
            )
            VALUES (?, ?, ?, 'local-dev', ?, ?, ?, ?, ?, ?, 'post_image', '', '', 'ready', ?, ?, ?, ?, ?)
            """,
            (
                media_id, "legacy_" + uuid.uuid4().hex, user["id"], object_key, url, url, mime,
                len(raw), upload_file_type(mime), sha,
                hashlib.md5(raw).hexdigest(), json.dumps(metadata, ensure_ascii=False, sort_keys=True), now, now,
            ),
        )
        # Width/height/duration intentionally default to 0 — the client
        # used to send these but they were unverified. A future pass
        # can compute them server-side with Pillow/ffprobe.
        conn.execute(
            "INSERT INTO media (id, owner_id, type, url, thumb_url, mime, width, height, duration, byte_size, created_at) VALUES (?, ?, ?, ?, ?, ?, 0, 0, 0, ?, ?)",
            (media_id, user["id"], kind, url, thumb_url, mime, len(raw), now),
        )
        record_upload_audit(conn, user["id"], "legacy_upload", file_id=media_id, status="ready", metadata={"bytes": len(raw), "mime": mime})
        fresh = dict(conn.execute("SELECT * FROM media WHERE id = ?", (media_id,)).fetchone())
        self.send_json({"media": serialize_media(fresh)})

    # ── Partner import backends (星域东京 等专属后台) ───────────────────────────
    # Token-gated, scoped-to-self mini backends. require_partner authorises ONLY
    # that partner's own listings + contacts; it is never a site-admin grant.
    # The heavy logic lives in server_partners.py; these are thin handlers.
    _PARTNER_IMG_MAX = 15 * 1024 * 1024

    def require_partner(self, conn: sqlite3.Connection, key: str) -> dict[str, Any]:
        key = (key or "").strip().lower()
        token = (self.headers.get("X-Partner-Token") or "").strip()
        if not token:
            auth = self.headers.get("Authorization") or ""
            if auth.lower().startswith("bearer "):
                token = auth[7:].strip()
        partner = partners.authenticate_partner(conn, key, token) if token else None
        if not partner:
            raise APIError("访问口令无效或已失效", 401, "partner_auth")
        return partner

    def _ensure_partner_seller(self, conn: sqlite3.Connection, key: str, name: str, data: dict[str, Any]) -> str:
        explicit = str(data.get("seller_user_id") or "").strip()
        if explicit and conn.execute("SELECT 1 FROM users WHERE id = ? AND deleted_at IS NULL", (explicit,)).fetchone():
            return explicit
        handle = f"partner_{key}"
        if conn.execute("SELECT 1 FROM users WHERE handle = ?", (handle,)).fetchone():
            handle = f"{handle}_{uuid.uuid4().hex[:6]}"
        uid = str(uuid.uuid4())
        now = now_iso()
        conn.execute(
            """
            INSERT INTO users (id, handle, display_name, email, password_hash, bio, location,
                               avatar_symbol, avatar_color, avatar_url, cover_url, membership_tier,
                               is_verified, is_merchant, merchant_verified, role, country, province, city,
                               current_region_code, recent_region_codes, joined_at, created_at, updated_at)
            VALUES (?, ?, ?, '', ?, '', '', 'building.2.fill', 'teal', '', '', 'free', 1, 1, 1, 'member', 'jp', '', '', '', '', ?, ?, ?)
            """,
            (uid, handle, name or key, hash_password(uuid.uuid4().hex + uuid.uuid4().hex), now, now, now),
        )
        conn.execute("INSERT OR IGNORE INTO settings (user_id, updated_at) VALUES (?, ?)", (uid, now))
        return uid

    def _read_multipart_file(self) -> tuple[str, str, bytes]:
        ctype = self.headers.get("Content-Type", "")
        boundary = None
        for part in ctype.split(";"):
            part = part.strip()
            if part.startswith("boundary="):
                boundary = part[len("boundary="):].strip('"')
                break
        if not boundary:
            raise APIError("missing boundary", 400, "invalid_payload")
        raw = self.read_bytes()
        for section in raw.split(b"--" + boundary.encode()):
            if not section or section.startswith(b"--"):
                continue
            if section.startswith(b"\r\n"):
                section = section[2:]
            header_blob, sep, body = section.partition(b"\r\n\r\n")
            if not sep:
                continue
            headers_text = header_blob.decode("utf-8", errors="replace")
            if "filename=" not in headers_text:
                continue
            if body.endswith(b"\r\n"):
                body = body[:-2]
            fname_match = re.search(r'filename="([^"]*)"', headers_text)
            mime_match = re.search(r"Content-Type:\s*([^\r\n]+)", headers_text)
            filename = (fname_match.group(1).strip() if fname_match else "")
            mime = (mime_match.group(1).strip().lower() if mime_match else "")
            return filename, mime, body
        raise APIError("no file part", 400, "invalid_payload")

    def _partner_persist_image_bytes(self, conn, partner, raw, declared_mime, filename="", source_url=""):
        if not raw:
            raise APIError("空图片", 400, "invalid_payload")
        if len(raw) > self._PARTNER_IMG_MAX:
            raise APIError("图片过大(上限 15MB)", 413, "too_large")
        sniffed = _sniff_mime(raw)
        if not sniffed or not sniffed.startswith("image/"):
            raise APIError("不支持的图片类型", 415, "unsupported_media")
        mime = declared_mime if (declared_mime in ALLOWED_MIME and declared_mime == sniffed) else sniffed
        if mime not in ALLOWED_MIME:
            raise APIError("不支持的图片类型", 415, "unsupported_media")
        sha = hashlib.sha256(raw).hexdigest()
        if media_hash_blocked(conn, sha):
            raise APIError("该图片无法上传", 422, "media_blocked")
        ext = EXT_BY_MIME.get(mime, ".jpg")
        media_id = "file_" + uuid.uuid4().hex
        object_key = f"partners/{partner['partner_key']}/listings/{media_id}{ext}"
        s3_backed = s3_ready_for_upload()
        if PRODUCTION and not s3_backed:
            raise APIError("生产环境对象存储暂不可用", 503, "s3_unavailable")
        if s3_backed:
            try:
                _s3_client().put_object(
                    Bucket=AWS_S3_BUCKET,
                    Key=object_key,
                    Body=raw,
                    ContentType=mime,
                    CacheControl="public, max-age=31536000, immutable",
                    Metadata={"machi-source": "partner-import", "partner": str(partner["partner_key"])},
                )
                head = _s3_head_object(object_key)
                if int(head.get("ContentLength") or -1) != len(raw):
                    _s3_delete_object(object_key)
                    raise APIError("图片上传校验失败", 502, "partner_image_upload_verify_failed")
            except APIError:
                raise
            except (BotoCoreError, ClientError, OSError) as exc:
                raise APIError("图片存储失败", 502, "partner_image_store_failed") from exc
            url = upload_public_url(object_key)
        else:
            target = local_upload_path(object_key)
            target.parent.mkdir(parents=True, exist_ok=True)
            target.write_bytes(raw)
            url = f"/media/{object_key}"
        thumb = upload_thumbnail_url(object_key, mime) if s3_backed else url
        thumb = thumb or url
        owner = partner.get("seller_user_id") or ""
        now = now_iso()
        bucket = AWS_S3_BUCKET if s3_backed else "local-dev"
        # 来源 URL 派生一个确定性 upload_id(UNIQUE 索引),这样每天自动同步时
        # 已转存过的同一张图能被 _partner_hosted_by_source 命中复用,不重复下载。
        if source_url:
            upload_id = "partnersrc_" + hashlib.sha256(
                f"{partner['partner_key']}|{source_url}".encode("utf-8")).hexdigest()
        else:
            upload_id = "partner_" + uuid.uuid4().hex
        metadata = {
            "source": "partner_import_s3" if s3_backed else "partner_import_local",
            "partner": partner["partner_key"],
            "source_url": source_url,
            "thumbnail_url": thumb,
            "variants": {"original": url, "large": url, "medium": url, "thumbnail": thumb},
        }
        conn.execute(
            """
            INSERT INTO uploaded_files (
                id, upload_id, user_id, bucket, object_key, public_url, cdn_url, content_type,
                file_size, file_type, purpose, entity_type, entity_id, status, checksum, etag,
                metadata, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'rental_image', 'listing', '', 'ready', ?, ?, ?, ?, ?)
            """,
            (media_id, upload_id, owner, bucket, object_key, url, url, mime, len(raw),
             upload_file_type(mime), sha, hashlib.md5(raw).hexdigest(),
             json.dumps(metadata, ensure_ascii=False, sort_keys=True), now, now),
        )
        conn.execute(
            "INSERT INTO media (id, owner_id, type, url, thumb_url, mime, width, height, duration, byte_size, created_at) VALUES (?, ?, 'image', ?, ?, ?, 0, 0, 0, ?, ?)",
            (media_id, owner, url, thumb, mime, len(raw), now),
        )
        record_upload_audit(conn, owner, "partner_upload", file_id=media_id, status="ready", metadata={"bytes": len(raw), "mime": mime})
        return {"url": url, "thumbnail_url": thumb, "media_id": media_id, "filename": filename}

    def _partner_hosted_by_source(self, conn, partner, source_url):
        """已按来源 URL 转存过的图片直接复用,避免每日同步重复下载(6GB/晚)。"""
        if not source_url:
            return None
        upload_id = "partnersrc_" + hashlib.sha256(
            f"{partner['partner_key']}|{source_url}".encode("utf-8")).hexdigest()
        row = conn.execute(
            "SELECT public_url, cdn_url, metadata FROM uploaded_files WHERE upload_id = ? AND status = 'ready'",
            (upload_id,),
        ).fetchone()
        if not row:
            return None
        d = dict(row)
        url = d.get("cdn_url") or d.get("public_url") or ""
        if not url:
            return None
        thumb = url
        try:
            meta = json.loads(d.get("metadata") or "{}")
            thumb = meta.get("thumbnail_url") or url
        except Exception:
            pass
        return {"url": url, "thumbnail_url": thumb}

    def _partner_rehost_url(self, conn, partner, url):
        # 先看有没有转存过同一来源 URL 的图片,命中就复用(不重复下载)。
        cached = self._partner_hosted_by_source(conn, partner, url)
        if cached:
            return cached
        try:
            from urllib.request import Request, urlopen
            req = Request(url, headers={"User-Agent": "MachiPartnerImport/1.0"})
            with urlopen(req, timeout=15) as resp:
                rmime = (resp.headers.get("Content-Type") or "").split(";")[0].strip().lower()
                data = resp.read(self._PARTNER_IMG_MAX + 1)
            if len(data) > self._PARTNER_IMG_MAX:
                return None
            return self._partner_persist_image_bytes(conn, partner, data, rmime, source_url=url)
        except APIError as exc:
            if exc.code in {"s3_unavailable", "partner_image_store_failed", "partner_image_upload_verify_failed"}:
                raise
            ERR_LOG.warning("partner image rehost failed url=%s code=%s", str(url)[:120], exc.code)
            return None
        except Exception:
            ERR_LOG.warning("partner image rehost failed url=%s", str(url)[:120])
            return None

    def _partner_image_resolver(self, conn, partner, rehost):
        def resolve(mapped):
            items = []
            for u in mapped.get("image_urls", []):
                u = str(u or "").strip()
                if not u:
                    continue
                if u.startswith("/media/") or (u.startswith("http") and not rehost):
                    items.append({"url": u, "thumbnail_url": u})
                elif u.startswith("http"):
                    got = self._partner_rehost_url(conn, partner, u)
                    if got:
                        items.append(got)
            return items
        return resolve

    def _parse_partner_listing_query(self, query: dict[str, str], default_limit: int) -> dict[str, Any]:
        raw_limit = str(query.get("limit") or default_limit).strip().lower()
        if raw_limit in {"all", "unlimited", "none", "0", "-1"}:
            limit: int | None = None
        else:
            try:
                limit = max(1, min(int(raw_limit), 500))
            except Exception:
                limit = default_limit
        try:
            offset = max(0, int(query.get("offset") or 0))
        except Exception:
            offset = 0
        return {"q": str(query.get("q") or "").strip()[:120], "limit": limit, "offset": offset}

    def _partner_listings_page(self, conn, key, query: dict[str, str], *, default_limit: int):
        opts = self._parse_partner_listing_query(query, default_limit)
        page = partners.search_partner_listing_ids(conn, key, q=opts["q"], limit=opts["limit"], offset=opts["offset"])
        ids = page["ids"]
        listings = []
        if not ids:
            listings = []
        else:
            placeholders = ",".join("?" * len(ids))
            rows = [dict(r) for r in conn.execute(
                f"SELECT * FROM city_listings WHERE id IN ({placeholders}) AND deleted_at IS NULL", ids)]
            order = {lid: i for i, lid in enumerate(ids)}
            rows.sort(key=lambda r: order.get(r["id"], 10 ** 9))
            listings = fetch_listings_with_extras(conn, rows, None)
        return {
            "listings": listings,
            "total": page["total"],
            "limit": page["limit"],
            "offset": page["offset"],
            "q": page["q"],
            "hasMore": page["hasMore"],
        }

    def _partner_listings_payload(self, conn, key, limit):
        return self._partner_listings_page(conn, key, {"limit": str(limit)}, default_limit=limit)["listings"]

    # ---- partner-facing endpoints ----
    def api_partner_branding(self, conn: sqlite3.Connection, key: str) -> None:
        p = partners.get_partner(conn, key)
        if not p or p.get("status") != "active":
            raise APIError("后台不存在", 404, "not_found")
        self.send_json({"partner": partners.serialize_partner(p, public=True)})

    def api_partner_branding_save(self, conn: sqlite3.Connection, key: str) -> None:
        """Token-gated self-service: let the partner set their own 公司头像/logo
        (and light branding). The logo is mirrored onto the seller 公司账号's
        avatar via update_partner → sync_seller_avatar, which is the only way that
        non-loginable account's avatar can change. Partners upload the image bytes
        first via POST /uploads, then save the returned URL here."""
        partner = self.require_partner(conn, key)
        data = self.read_json()
        fields: dict[str, Any] = {}
        # Only branding-safe fields — never let a partner flip status/seller/etc.
        for f in ("logo_url", "intro", "brand_color", "accent_color", "website", "name_ja", "name_en"):
            if f in data and data[f] is not None:
                fields[f] = str(data[f])
        if not fields:
            raise APIError("没有可保存的内容", 400, "invalid")
        p = partners.update_partner(conn, partner["partner_key"], fields, now=now_iso())
        if not p:
            raise APIError("后台不存在", 404, "not_found")
        self.send_json({"partner": partners.serialize_partner(p)})

    def api_partner_session(self, conn: sqlite3.Connection, key: str) -> None:
        body = self.read_json()
        token = (self.headers.get("X-Partner-Token") or str(body.get("token") or "")).strip()
        partner = partners.authenticate_partner(conn, key, token)
        if not partner:
            raise APIError("访问口令无效", 401, "partner_auth")
        self.send_json({
            "partner": partners.serialize_partner(partner),
            "contacts": [partners.serialize_contact(c) for c in partners.list_partner_contacts(conn, key)],
            "templateColumns": [{"header": h, "hint": hint} for h, hint in partners.TEMPLATE_COLUMNS],
        })

    def api_partner_template(self, conn: sqlite3.Connection, key: str) -> None:
        self.require_partner(conn, key)
        self.send_json({
            "filename": f"{key}_listings_template.csv",
            "csv": partners.build_template_csv(),
            "columns": [{"header": h, "hint": hint} for h, hint in partners.TEMPLATE_COLUMNS],
        })

    def api_partner_contacts(self, conn: sqlite3.Connection, key: str, query: dict[str, str]) -> None:
        self.require_partner(conn, key)
        self.send_json({"contacts": [partners.serialize_contact(c) for c in partners.list_partner_contacts(conn, key)]})

    def api_partner_contact_create(self, conn: sqlite3.Connection, key: str) -> None:
        self.require_partner(conn, key)
        data = self.read_json()
        if not str(data.get("name") or "").strip():
            raise APIError("缺少联系人姓名", 400, "invalid")
        c = partners.create_partner_contact(conn, key, data, now=now_iso())
        self.send_json({"contact": partners.serialize_contact(c)}, 201)

    def api_partner_contact_update(self, conn: sqlite3.Connection, key: str, cid: str) -> None:
        self.require_partner(conn, key)
        data = self.read_json()
        c = partners.update_partner_contact(conn, key, cid, data, now=now_iso())
        if not c:
            raise APIError("联系人不存在", 404, "not_found")
        resynced = partners.resync_contact_snapshots(conn, key, cid, now=now_iso())
        self.send_json({"contact": partners.serialize_contact(c), "resynced": resynced})

    def api_partner_contact_delete(self, conn: sqlite3.Connection, key: str, cid: str) -> None:
        self.require_partner(conn, key)
        if not partners.delete_partner_contact(conn, key, cid, now=now_iso()):
            raise APIError("联系人不存在", 404, "not_found")
        self.send_json({"ok": True})

    def api_partner_upload(self, conn: sqlite3.Connection, key: str) -> None:
        partner = self.require_partner(conn, key)
        filename, mime, raw = self._read_multipart_file()
        media = self._partner_persist_image_bytes(conn, partner, raw, mime, filename)
        self.send_json({"url": media["url"], "thumbnailUrl": media["thumbnail_url"], "filename": filename})

    def api_partner_import_parse(self, conn: sqlite3.Connection, key: str) -> None:
        partner = self.require_partner(conn, key)
        filename, _mime, raw = self._read_multipart_file()
        try:
            parsed = partners.parse_spreadsheet(raw, filename)
        except Exception as exc:
            raise APIError(f"解析失败:{exc}", 400, "parse_failed")
        contacts = partners.list_partner_contacts(conn, key)
        by_id = {c["id"]: c for c in contacts}
        by_name = {str(c.get("name") or "").lower(): c for c in contacts}
        dflt = partners.default_contact(conn, key)
        images_by_row = parsed.get("images_by_row") or {}
        preview = []
        for idx, raw_row in enumerate(parsed["rows"][:partners.MAX_IMPORT_ROWS]):
            mapped = partners.map_row(raw_row, partner, contacts_by_id=by_id, contacts_by_name=by_name,
                                      default_contact_row=dflt, row_index=idx)
            for img in images_by_row.get(idx, []):
                try:
                    m = self._partner_persist_image_bytes(conn, partner, img["data"], "", img.get("filename", ""))
                    mapped["image_urls"].append(m["url"])
                except Exception:
                    mapped.setdefault("warnings", []).append("一张嵌入图片无法导入")
            c = mapped.get("contact") or None
            mapped["contact"] = ({"id": c.get("id", ""), "name": c.get("name", ""), "phone": c.get("phone", "")} if c else None)
            preview.append(mapped)
        self.send_json({
            "columns": parsed.get("headers", []),
            "rows": preview,
            "warnings": parsed.get("warnings", []),
            "rowCount": len(preview),
        })

    def api_partner_import_commit(self, conn: sqlite3.Connection, key: str) -> None:
        partner = self.require_partner(conn, key)
        body = self.read_json()
        rows = body.get("rows")
        if not isinstance(rows, list) or not rows:
            raise APIError("没有可导入的房源", 400, "empty")
        if len(rows) > partners.MAX_IMPORT_ROWS:
            raise APIError(f"单次最多导入 {partners.MAX_IMPORT_ROWS} 条", 400, "too_many")
        options = body.get("options") if isinstance(body.get("options"), dict) else {}
        rehost = bool(options.get("rehostUrls", True))
        contacts = partners.list_partner_contacts(conn, key)
        by_id = {c["id"]: c for c in contacts}
        dflt = partners.default_contact(conn, key)
        mapped = partners.sanitize_commit_rows(rows, partner, contacts_by_id=by_id, default_contact_row=dflt)
        resolver = self._partner_image_resolver(conn, partner, rehost)
        result = partners.import_partner_listings(
            conn, partner, mapped, now=now_iso(), image_resolver=resolver,
            region_resolver=lambda cs: region_code_for_city_slug(partner.get("default_country_code") or "jp", cs),
        )
        invalidate_public_ranking_caches()
        ACCESS_LOG.info("partner import key=%s created=%s updated=%s", key, result["created"], result["updated"])
        self.send_json({"ok": True, "result": result})

    def _partner_stareal_options(self, body: dict[str, Any]) -> dict[str, Any]:
        allowed = set(server_stareal.ALL_HOUSE_TYPES)
        raw_types = body.get("types") or body.get("houseTypes") or list(server_stareal.ALL_HOUSE_TYPES)
        if isinstance(raw_types, str):
            raw_types = [x.strip() for x in raw_types.split(",")]
        if not isinstance(raw_types, list):
            raw_types = list(server_stareal.ALL_HOUSE_TYPES)
        house_types: list[str] = []
        for item in raw_types:
            t = str(item or "").strip().lower()
            if t == "all":
                house_types = list(server_stareal.ALL_HOUSE_TYPES)
                break
            if t in allowed and t not in house_types:
                house_types.append(t)
        if not house_types:
            raise APIError("请选择要同步的房源范围", 400, "invalid_stareal_types")
        try:
            max_images = int(body.get("maxImages") or body.get("max_images") or partners.MAX_IMAGES_PER_LISTING)
        except Exception:
            max_images = partners.MAX_IMAGES_PER_LISTING
        max_images = max(1, min(max_images, partners.MAX_IMAGES_PER_LISTING))

        def bool_option(name: str, default: bool) -> bool:
            if name not in body:
                return default
            value = body.get(name)
            if isinstance(value, bool):
                return value
            return str(value).strip().lower() not in {"0", "false", "no", "off", "否"}

        try:
            crawl_sleep = float(body.get("crawlSleep") or body.get("sleep") or 0.35)
        except Exception:
            crawl_sleep = 0.35
        crawl_sleep = max(0.0, min(crawl_sleep, 2.0))
        return {
            "house_types": house_types,
            "max_images": max_images,
            "full_res": bool_option("fullRes", True),
            "rehost_urls": bool_option("rehostUrls", True),
            "crawl_sleep": crawl_sleep,
        }

    def _json_cell(self, value: Any, fallback: Any) -> Any:
        if value in (None, ""):
            return fallback
        if isinstance(value, (dict, list)):
            return value
        try:
            parsed = json.loads(str(value))
        except Exception:
            return fallback
        return parsed if isinstance(parsed, type(fallback)) else fallback

    def _partner_sync_job_payload(self, row: Any | None) -> dict[str, Any] | None:
        if not row:
            return None
        d = dict(row)
        summary = self._json_cell(d.get("summary_json"), {})
        result = self._json_cell(d.get("result_json"), {})
        warnings = self._json_cell(d.get("warnings_json"), [])
        options = self._json_cell(d.get("options_json"), {})
        return {
            "id": d.get("id") or "",
            "partnerKey": d.get("partner_key") or "",
            "source": d.get("source") or "",
            "status": d.get("status") or "",
            "stage": d.get("stage") or "",
            "message": d.get("message") or "",
            "progress": int(d.get("progress") or 0),
            "totalSteps": int(d.get("total_steps") or 0),
            "processedSteps": int(d.get("processed_steps") or 0),
            "fetched": int(d.get("fetched_count") or 0),
            "mapped": int(d.get("mapped_count") or 0),
            "imageCount": int(d.get("image_count") or 0),
            "missingImageCount": int(d.get("missing_image_count") or 0),
            "created": int(d.get("created_count") or 0),
            "updated": int(d.get("updated_count") or 0),
            "errors": int(d.get("error_count") or 0),
            "errorCode": d.get("error_code") or "",
            "errorMessage": d.get("error_message") or "",
            "options": options,
            "summary": summary,
            "result": result,
            "warnings": warnings,
            "startedAt": d.get("started_at") or "",
            "finishedAt": d.get("finished_at") or "",
            "createdAt": d.get("created_at") or "",
            "updatedAt": d.get("updated_at") or "",
        }

    def _partner_latest_sync_job(self, conn: sqlite3.Connection, key: str, *, running_only: bool = False) -> Any | None:
        if running_only:
            return conn.execute(
                "SELECT * FROM partner_sync_jobs WHERE partner_key = ? AND source = 'stareal' "
                "AND status IN ('queued','running') ORDER BY created_at DESC LIMIT 1",
                (key,),
            ).fetchone()
        return conn.execute(
            "SELECT * FROM partner_sync_jobs WHERE partner_key = ? AND source = 'stareal' "
            "ORDER BY created_at DESC LIMIT 1",
            (key,),
        ).fetchone()

    def _partner_sync_job_update(self, job_id: str, **fields: Any) -> None:
        if not fields:
            return
        fields["updated_at"] = now_iso()
        if "progress" in fields:
            fields["progress"] = max(0, min(100, int(fields.get("progress") or 0)))
        allowed = {
            "status", "stage", "message", "progress", "total_steps", "processed_steps",
            "fetched_count", "mapped_count", "image_count", "missing_image_count",
            "created_count", "updated_count", "error_count", "summary_json", "result_json",
            "warnings_json", "error_code", "error_message", "started_at", "finished_at",
            "updated_at",
        }
        clean = {k: v for k, v in fields.items() if k in allowed}
        if not clean:
            return
        assignments = ", ".join(f"{k} = ?" for k in clean)
        with DB_LOCK, db() as jconn:
            jconn.execute(
                f"UPDATE partner_sync_jobs SET {assignments} WHERE id = ?",
                [*clean.values(), job_id],
            )

    def _start_partner_stareal_sync_job(
        self,
        conn: sqlite3.Connection,
        partner: dict[str, Any],
        options: dict[str, Any],
        *,
        created_by_user_id: str = "",
        created_by_role: str = "",
    ) -> tuple[dict[str, Any], bool]:
        key = str(partner.get("partner_key") or "")
        existing = self._partner_latest_sync_job(conn, key, running_only=True)
        if existing:
            return self._partner_sync_job_payload(existing) or {}, False
        job_id = "psync_" + uuid.uuid4().hex
        now = now_iso()
        conn.execute(
            """
            INSERT INTO partner_sync_jobs (
                id, partner_key, source, status, stage, message, progress, options_json,
                created_by_user_id, created_by_role, created_at, updated_at
            )
            VALUES (?, ?, 'stareal', 'queued', 'queued', '等待开始同步', 1, ?, ?, ?, ?, ?)
            """,
            (
                job_id, key, json.dumps(options, ensure_ascii=False, sort_keys=True),
                created_by_user_id or "", created_by_role or "", now, now,
            ),
        )
        try:
            conn.commit()
        except Exception:
            pass
        row = conn.execute("SELECT * FROM partner_sync_jobs WHERE id = ?", (job_id,)).fetchone()
        thread = threading.Thread(
            target=self._run_partner_stareal_sync_job,
            args=(job_id,),
            daemon=True,
            name=f"stareal-sync-{key[:20]}",
        )
        thread.start()
        return self._partner_sync_job_payload(row) or {"id": job_id, "status": "queued", "progress": 1}, True

    def _run_partner_stareal_sync_job(self, job_id: str) -> None:
        stats = {"created": 0, "updated": 0, "errors": 0}
        try:
            self._partner_sync_job_update(
                job_id,
                status="running",
                stage="fetching",
                message="正在获取星域东京官网房源",
                progress=5,
                started_at=now_iso(),
            )
            with db() as rconn:
                job = rconn.execute("SELECT * FROM partner_sync_jobs WHERE id = ?", (job_id,)).fetchone()
                if not job:
                    return
                options = self._json_cell(job["options_json"], {})
                partner = partners.get_partner(rconn, job["partner_key"])
                if not partner:
                    raise APIError("合作商不存在", 404, "partner_not_found")
                partner = self._ensure_stareal_partner(partner)
                # 后台同步:开启详情抓取,把官网上每套房源的完整字段(经纬度/築年/
                # 階数/物件番号/设备设施等)一并拉全。
                payload = self._partner_stareal_rows(rconn, partner, options, with_detail=True)

            summary = payload["summary"]
            self._partner_sync_job_update(
                job_id,
                stage="importing",
                message="官网数据已获取，正在导入房源和照片",
                progress=40,
                total_steps=max(1, len(payload["rows"])),
                fetched_count=int(summary.get("fetched") or 0),
                mapped_count=int(summary.get("mapped") or 0),
                image_count=int(summary.get("imageCount") or 0),
                missing_image_count=int(summary.get("missingImageCount") or 0),
                summary_json=json.dumps(summary, ensure_ascii=False, sort_keys=True),
                warnings_json=json.dumps(payload["warnings"], ensure_ascii=False),
            )

            def on_progress(done: int, total: int, item: dict[str, Any]) -> None:
                status = item.get("status")
                if status == "created":
                    stats["created"] += 1
                elif status == "updated":
                    stats["updated"] += 1
                elif status == "error":
                    stats["errors"] += 1
                pct = 40 + int((max(0, done) / max(1, total)) * 55)
                self._partner_sync_job_update(
                    job_id,
                    progress=pct,
                    processed_steps=done,
                    total_steps=total,
                    created_count=stats["created"],
                    updated_count=stats["updated"],
                    error_count=stats["errors"],
                    message=f"正在导入 {done}/{total} 套房源",
                )

            with DB_LOCK, db() as wconn:
                partner = partners.get_partner(wconn, str(summary.get("partnerKey") or "") or job["partner_key"])
                if not partner:
                    partner = partners.get_partner(wconn, job["partner_key"])
                if not partner:
                    raise APIError("合作商不存在", 404, "partner_not_found")
                resolver = self._partner_image_resolver(wconn, partner, bool(options.get("rehost_urls", True)))
                result = partners.import_partner_listings(
                    wconn,
                    partner,
                    payload["rows"],
                    now=now_iso(),
                    image_resolver=resolver,
                    region_resolver=lambda cs: region_code_for_city_slug(partner.get("default_country_code") or "jp", cs),
                    progress_callback=on_progress,
                )
                invalidate_public_ranking_caches()

            self._partner_sync_job_update(
                job_id,
                status="succeeded",
                stage="done",
                message="同步完成",
                progress=100,
                processed_steps=max(1, len(payload["rows"])),
                total_steps=max(1, len(payload["rows"])),
                created_count=int(result.get("created") or 0),
                updated_count=int(result.get("updated") or 0),
                error_count=len(result.get("errors") or []),
                result_json=json.dumps(result, ensure_ascii=False, sort_keys=True),
                finished_at=now_iso(),
            )
            ACCESS_LOG.info(
                "partner stareal job done id=%s created=%s updated=%s",
                job_id, result.get("created"), result.get("updated"),
            )
        except Exception as exc:
            code = getattr(exc, "code", "stareal_sync_failed")
            message = str(exc) or "同步失败"
            ERR_LOG.exception("partner stareal job failed id=%s", job_id)
            self._partner_sync_job_update(
                job_id,
                status="failed",
                stage="failed",
                message=message[:500],
                error_code=code,
                error_message=message[:1000],
                finished_at=now_iso(),
            )

    def _require_stareal_partner(self, conn: sqlite3.Connection, key: str) -> dict[str, Any]:
        partner = self.require_partner(conn, key)
        return self._ensure_stareal_partner(partner)

    def _require_admin_stareal_partner(self, conn: sqlite3.Connection, key: str) -> dict[str, Any]:
        self.require_admin(conn)
        partner = partners.get_partner(conn, key)
        if not partner:
            raise APIError("不存在", 404, "not_found")
        return self._ensure_stareal_partner(partner)

    def _ensure_stareal_partner(self, partner: dict[str, Any]) -> dict[str, Any]:
        key = str(partner.get("partner_key") or "").strip().lower()
        if key not in server_stareal.AUTHORIZED_PARTNER_KEYS:
            raise APIError("该同步器仅限星域东京后台使用", 403, "stareal_partner_required")
        return partner

    def _compact_partner_row_contact(self, row: dict[str, Any]) -> None:
        c = row.get("contact") or None
        row["contact"] = (
            {"id": c.get("id", ""), "name": c.get("name", ""), "phone": c.get("phone", "")}
            if isinstance(c, dict)
            else None
        )

    def _partner_stareal_rows(self, conn: sqlite3.Connection, partner: dict[str, Any], options: dict[str, Any],
                              *, with_detail: bool = False) -> dict[str, Any]:
        try:
            raw_items = server_stareal.fetch_all_items(
                options["house_types"],
                sleep=options["crawl_sleep"],
                timeout=30.0,
                with_detail=with_detail,
            )
        except Exception as exc:
            raise APIError(f"星域东京官网获取失败:{exc}", 502, "stareal_fetch_failed")
        rows = server_stareal.map_all(
            raw_items,
            full_res=options["full_res"],
            default_city=partner.get("default_city_slug") or "tokyo",
            max_images=options["max_images"],
        )
        for idx, row in enumerate(rows):
            row["row_index"] = idx
        contacts = partners.list_partner_contacts(conn, partner["partner_key"])
        by_id = {c["id"]: c for c in contacts}
        dflt = partners.default_contact(conn, partner["partner_key"])
        mapped = partners.sanitize_commit_rows(rows, partner, contacts_by_id=by_id, default_contact_row=dflt)
        by_type: dict[str, int] = {}
        for entry in raw_items:
            t = str(entry.get("house_type") or "")
            by_type[t] = by_type.get(t, 0) + 1
        by_intent: dict[str, int] = {}
        image_count = 0
        missing_images = 0
        for row in mapped:
            intent = str(row.get("listing_intent") or "")
            by_intent[intent] = by_intent.get(intent, 0) + 1
            imgs = row.get("image_urls") or []
            image_count += len(imgs)
            if not imgs:
                missing_images += 1
        warnings = []
        if not dflt:
            warnings.append("未设置默认预约联系人,同步房源将不显示预约联系人")
        summary = {
            "source": "stareal.jp",
            "partnerKey": partner.get("partner_key") or "",
            "fetched": len(raw_items),
            "mapped": len(mapped),
            "imageCount": image_count,
            "missingImageCount": missing_images,
            "byType": by_type,
            "byIntent": by_intent,
            "maxImages": options["max_images"],
            "fullRes": options["full_res"],
        }
        return {"rows": mapped, "summary": summary, "warnings": warnings}

    def _partner_preview_rows(self, rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
        out = []
        for row in rows:
            item = dict(row)
            self._compact_partner_row_contact(item)
            out.append(item)
        return out

    def api_partner_stareal_preview(self, conn: sqlite3.Connection, key: str) -> None:
        partner = self._require_stareal_partner(conn, key)
        options = self._partner_stareal_options(self.read_json())
        payload = self._partner_stareal_rows(conn, partner, options)
        ACCESS_LOG.info(
            "partner stareal preview key=%s rows=%s images=%s",
            key, payload["summary"]["mapped"], payload["summary"]["imageCount"],
        )
        self.send_json({
            "rows": self._partner_preview_rows(payload["rows"]),
            "warnings": payload["warnings"],
            "rowCount": payload["summary"]["mapped"],
            "summary": payload["summary"],
        })

