    def api_waitlist(self, conn: sqlite3.Connection) -> None:
        """Android-launch waitlist from the public marketing site.

        Anonymous on purpose — marketing visitors are not signed in, so this
        reuses the feedback table with an empty user_id and a reserved
        category instead of requiring auth. The generic per-IP write bucket
        already throttles it; one row per email address."""
        data = self.read_json()
        email = str(data.get("email") or "").strip().lower()
        if not email or len(email) > 254 or not re.match(r"^[^\s@]+@[^\s@.]+(\.[^\s@.]+)+$", email):
            raise APIError("邮箱格式不正确", 400, "invalid_email")
        payload = {
            "email": email,
            "city": str(data.get("city") or "")[:80],
            "language": str(data.get("language") or "")[:40],
            "intent": str(data.get("intent") or "")[:80],
            "locale": str(data.get("locale") or "")[:8],
        }
        existing = conn.execute(
            "SELECT id FROM feedback WHERE category = 'android_waitlist' AND content LIKE ?",
            (f'%"email": "{email}"%',),
        ).fetchone()
        if existing is None:
            conn.execute(
                "INSERT INTO feedback (id, user_id, category, content, created_at) VALUES (?, ?, ?, ?, ?)",
                (str(uuid.uuid4()), "", "android_waitlist", json.dumps(payload, ensure_ascii=False), now_iso()),
            )
        self.send_json({"ok": True})

    def api_register_push_token(self, conn: sqlite3.Connection) -> None:
        """Bind this device's APNs token to the logged-in account. Called
        by iOS after the user grants notification permission. Re-binding a
        token that belonged to another account moves it (shared devices)."""
        user = self.require_user(conn)
        data = self.read_json()
        token = str(data.get("token") or "").strip()
        if not token:
            raise APIError("缺少推送 token", 400, "missing_token")
        server_apns.register_token(conn, user["id"], token, str(data.get("platform") or "ios"), now_iso())
        self.send_json({"ok": True, "apnsEnabled": server_apns.apns_configured()})

    def api_unregister_push_token(self, conn: sqlite3.Connection) -> None:
        """Drop a device token (logout / notification opt-out). No auth on
        purpose: logout clears the bearer before this fires, and the APNs
        token itself is an unguessable Apple-issued capability — exact
        knowledge of it IS the authorization to unbind it."""
        data = self.read_json()
        server_apns.unregister_token(conn, str(data.get("token") or ""))
        self.send_json({"ok": True})

    def api_devices(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        rows = list(conn.execute(
            "SELECT * FROM sessions WHERE user_id = ? ORDER BY last_seen_at DESC",
            (user["id"],),
        ))
        grouped: dict[str, dict[str, Any]] = {}
        for r in rows:
            family, platform = _normalize_device_family(r["device_name"], r["user_agent"])
            group_key = f"{family}|{platform}"
            existing = grouped.get(group_key)
            geo = resolve_geo(r["ip"]) if r["ip"] else dict(_GEO_EMPTY)
            entry = {
                "id": r["token"][-12:],
                "token": r["token"],
                "tokens": [r["token"][-12:]],
                "device_name": r["device_name"] or family,
                "device_label": family,
                "platform": platform,
                "user_agent": r["user_agent"],
                "ip": r["ip"],
                "country": geo.get("country", ""),
                "region": geo.get("region", ""),
                "city": geo.get("city", ""),
                "org": geo.get("org", ""),
                "geo_state": geo.get("state", ""),
                "created_at": r["created_at"],
                "last_seen_at": r["last_seen_at"],
                "expires_at": r["expires_at"],
                "session_count": 1,
            }
            if not existing:
                grouped[group_key] = entry
                continue
            existing["session_count"] += 1
            existing["tokens"].append(r["token"][-12:])
            if (r["last_seen_at"] or "") > (existing["last_seen_at"] or ""):
                existing.update({
                    "id": r["token"][-12:],
                    "token": r["token"],
                    "device_name": r["device_name"] or family,
                    "user_agent": r["user_agent"],
                    "ip": r["ip"],
                    "country": geo.get("country", ""),
                    "region": geo.get("region", ""),
                    "city": geo.get("city", ""),
                    "org": geo.get("org", ""),
                    "geo_state": geo.get("state", ""),
                    "last_seen_at": r["last_seen_at"],
                    "expires_at": r["expires_at"],
                })
            if (r["created_at"] or "") < (existing["created_at"] or ""):
                existing["created_at"] = r["created_at"]
        items = sorted(grouped.values(), key=lambda x: x.get("last_seen_at") or "", reverse=True)
        self.send_json({"items": items})

    def api_revoke_device(self, conn: sqlite3.Connection, device_token: str) -> None:
        user = self.require_user(conn)
        conn.execute("DELETE FROM sessions WHERE user_id = ? AND (token = ? OR substr(token, length(token)-11) = ?)",
                     (user["id"], device_token, device_token))
        self.send_json({"ok": True})

    def api_list_drafts(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        rows = conn.execute(
            "SELECT * FROM drafts WHERE user_id = ? ORDER BY updated_at DESC",
            (user["id"],),
        )
        items = []
        for r in rows:
            items.append({
                "id": r["id"],
                "content": r["content"],
                "media_ids": [m for m in (r["media_ids"] or "").split("|") if m],
                "tags": [t for t in (r["tags"] or "").split("|") if t],
                "country": r["country"] or "",
                "province": r["province"] or "",
                "city": r["city"] or "",
                "region_code": r["region_code"] or "",
                "content_type": r["content_type"] or "dynamic",
                "attributes": decode_post_attributes(r["attributes"]),
                "language": r["language"] or "",
                "updated_at": r["updated_at"],
            })
        self.send_json({"items": items})

    # Client draft ids are opaque tokens minted by the app (e.g. "draft-1", a
    # UUID, or a ULID). Accept the common safe alphabet; anything else is treated
    # as untrusted and replaced with a server UUID.
    _DRAFT_ID_RE = re.compile(r"^[A-Za-z0-9._:-]{1,128}$")

    def _resolve_draft_id(self, conn: sqlite3.Connection, user_id: str, raw_id: str) -> str:
        """Choose the row id for a draft save.

        - well-formed id that is free OR already owned by this user -> reuse it
          (this is what makes the save idempotent: re-saving "draft-1" updates the
          same row instead of spawning a duplicate);
        - malformed id, or an id owned by ANOTHER user -> mint a fresh UUID so we
          never clobber a foreign draft and never collide on the primary key.
        """
        if raw_id and self._DRAFT_ID_RE.match(raw_id):
            row = conn.execute("SELECT user_id FROM drafts WHERE id = ?", (raw_id,)).fetchone()
            if row is None or str(row["user_id"]) == str(user_id):
                return raw_id
        return str(uuid.uuid4())

    def api_save_draft(self, conn: sqlite3.Connection) -> None:
        user = self.require_user(conn)
        data = self.read_json()
        raw_id = str(data.get("id") or "").strip()
        # Idempotent upsert: honour a well-formed client-supplied draft id so the
        # SAME id round-trips (offline drafts, retried saves and cross-device sync
        # all converge on a single row). Only mint a fresh UUID when the id is
        # malformed or already belongs to ANOTHER user — we never overwrite a
        # foreign row and never PK-collide into a 500. The response always returns
        # the canonical id so the client can adopt it locally.
        draft_id = self._resolve_draft_id(conn, user["id"], raw_id)
        media_ids = "|".join(data.get("media_ids") or [])
        tags = "|".join(data.get("tags") or [])
        content_type = str(data.get("content_type") or "dynamic").strip() or "dynamic"
        attributes = normalize_post_attributes(content_type, data.get("attributes") or {})
        country = str(data.get("country") or "").strip().lower()
        province = str(data.get("province") or "").strip().lower()
        city = str(data.get("city") or "").strip().lower()
        region_code = str(data.get("region_code") or "").strip().lower()
        language = str(data.get("language") or "").strip()
        existing = conn.execute("SELECT id FROM drafts WHERE id = ? AND user_id = ?", (draft_id, user["id"])).fetchone()
        if existing:
            conn.execute(
                """
                UPDATE drafts
                   SET content = ?,
                       media_ids = ?,
                       tags = ?,
                       country = ?,
                       province = ?,
                       city = ?,
                       region_code = ?,
                       content_type = ?,
                       attributes = ?,
                       language = ?,
                       updated_at = ?
                 WHERE id = ?
                """,
                (
                    data.get("content") or "", media_ids, tags,
                    country, province, city, region_code,
                    content_type, attributes, language,
                    now_iso(), draft_id,
                ),
            )
        else:
            conn.execute(
                """
                INSERT INTO drafts (
                    id, user_id, content, media_ids, tags,
                    country, province, city, region_code,
                    content_type, attributes, language, updated_at
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    draft_id, user["id"], data.get("content") or "", media_ids, tags,
                    country, province, city, region_code,
                    content_type, attributes, language, now_iso(),
                ),
            )
        self.send_json({"id": draft_id})

    def api_delete_draft(self, conn: sqlite3.Connection, draft_id: str) -> None:
        user = self.require_user(conn)
        conn.execute("DELETE FROM drafts WHERE id = ? AND user_id = ?", (draft_id, user["id"]))
        self.send_json({"ok": True})

    # ---- regions ----------------------------------------------------------

    def api_regions_countries(self, conn: sqlite3.Connection) -> None:
        """Full country list. Cached forever in-process (the data is a
        Python literal — it doesn't change at runtime)."""
        self.send_json({"items": REGION_COUNTRIES})

    def api_regions_provinces(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        country = (query.get("country") or "").strip().lower()
        if not country:
            raise APIError("country required", 400, "missing_param")
        provinces = REGION_PROVINCES.get(country, [])
        spec = _country_lookup(country)
        self.send_json({
            "country": country,
            "has_provinces": bool(spec and spec.get("has_provinces")),
            "items": provinces,
        })

    def api_regions_cities(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        country = (query.get("country") or "").strip().lower()
        province = (query.get("province") or "").strip().lower() or None
        if not country:
            raise APIError("country required", 400, "missing_param")
        spec = _country_lookup(country)
        if spec and spec.get("has_provinces"):
            allowed = {p["code"] for p in REGION_PROVINCES.get(country, [])}
            if not province or province not in allowed:
                self.send_json({"country": country, "province": province or "", "items": []})
                return
        cities = _cities_for_parent(country, province)
        self.send_json({"country": country, "province": province or "", "items": cities})

    def api_regions_popular(self, conn: sqlite3.Connection) -> None:
        """Resolve POPULAR_CITIES into rich objects (so the client can
        render `🇨🇳 上海` without re-walking the tree)."""
        items: list[dict[str, Any]] = []
        for code in POPULAR_CITIES:
            country_code, province_code, city_code = _parse_region_code(code)
            country = _country_lookup(country_code) or {}
            province_name = ""
            if province_code:
                for p in REGION_PROVINCES.get(country_code, []):
                    if p["code"] == province_code:
                        province_name = p["name"]
                        break
            city_name = ""
            for c in _cities_for_parent(country_code, province_code):
                if c["code"] == city_code:
                    city_name = c["name"]
                    break
            if not city_name:
                continue
            items.append({
                "region_code":   code,
                "country_code":  country_code,
                "country_name":  country.get("name", ""),
                "country_emoji": country.get("emoji", ""),
                "province_code": province_code,
                "province_name": province_name,
                "city_code":     city_code,
                "city_name":     city_name,
            })
        self.send_json({"items": items})

    def api_regions_resolve(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        """Look a region_code up and return the same hydrated shape as
        the popular list — used by the App / Web when displaying a
        post's location chip."""
        code = (query.get("code") or "").strip()
        if not code:
            raise APIError("code required", 400, "missing_param")
        payload = _region_payload_for_code(code)
        if not payload:
            raise APIError("region not found", 404, "region_not_found")
        self.send_json(payload)

    def api_regions_detect(self, conn: sqlite3.Connection) -> None:
        """Best-effort coarse region detection for posting defaults.

        We return only Machi's normalized region object and a source marker;
        raw IP is never returned to the client.
        """
        source = "fallback"
        viewer = self.current_session(conn)
        if viewer:
            row = conn.execute("SELECT current_region_code, country, province, city FROM users WHERE id = ?", (viewer["user_id"],)).fetchone()
            if row:
                code = (row["current_region_code"] or "").strip().lower() or _resolve_region_code(row["country"], row["province"], row["city"])
                payload = _region_payload_for_code(code)
                if payload:
                    payload.update({"source": "account", "geo_state": ""})
                    return self.send_json(payload)
        geo = resolve_geo(self._client_ip())
        code = _detect_region_code_from_geo(geo)
        payload = _region_payload_for_code(code) or _region_payload_for_code("jp.tokyo.tokyo")
        if not payload:
            raise APIError("region detect failed", 500, "region_detect_failed")
        if geo.get("state") == "ok":
            source = "ip"
        payload.update({"source": source, "geo_state": geo.get("state", "")})
        self.send_json(payload)

    def api_events_token(self, conn: sqlite3.Connection) -> None:
        """Exchange the long-lived Bearer for a short-lived SSE token.
        EventSource cannot attach an Authorization header so the Web
        client previously had to put the Bearer in the URL (`?token=`),
        which leaked it through nginx access logs / Referer / browser
        history. The new flow mints a one-shot token bound to the user
        that expires in 5 minutes."""
        user = self.require_user(conn)
        token = _mint_sse_token(user["id"])
        self.send_json({"token": token, "expires_in": int(_SSE_TOKEN_TTL)})

    def api_events(self, conn: sqlite3.Connection) -> None:
        # Resolve the user from either a one-shot SSE token (preferred,
        # via ?token=) or — for backwards compatibility — the standard
        # Bearer header. The long-lived Bearer in the URL is the
        # leakage vector we want to retire so the SSE-token path is
        # the documented one.
        parsed = urlparse(self.path)
        qs = parse_qs(parsed.query)
        sse_token = (qs.get("token") or [""])[0].strip()
        user_id = _consume_sse_token(sse_token)
        if user_id is None:
            user = self.require_user(conn)
            user_id = user["id"]
        self._pending_event_user_id = user_id
        return None

    # ---- marketing site copy ---------------------------------------------

    def _serialize_marketing_copy(self, row: sqlite3.Row | dict[str, Any]) -> dict[str, Any]:
        d = dict(row)
        return {
            "id": d["id"],
            "page_key": d["page_key"],
            "locale": d["locale"],
            "title": d["title"],
            "body": d["body"],
            "status": d["status"],
            "sort_order": int(d["sort_order"] or 0),
            "created_at": d["created_at"],
            "updated_at": d["updated_at"],
        }

    def _clean_marketing_payload(self, data: dict[str, Any], *, partial: bool = False) -> dict[str, Any]:
        allowed_pages = {
            "home", "about", "features", "cities", "guide", "business", "safety", "download",
            "ads", "contact", "partners", "jobs-promotion", "housing-promotion",
            "updates", "faq", "safety-center", "privacy", "terms", "membership-terms",
            "service-terms", "refund-policy", "community-guidelines", "commercial-disclosure",
            "cookie-policy",
        }
        cleaned: dict[str, Any] = {}
        if "page_key" in data or not partial:
            page_key = str(data.get("page_key") or "").strip().lower()
            if page_key not in allowed_pages:
                raise APIError("页面不合法", 400, "invalid_page_key")
            cleaned["page_key"] = page_key
        if "locale" in data or not partial:
            locale = str(data.get("locale") or "zh").strip().lower()
            if locale not in ("zh", "en", "ja"):
                raise APIError("语言不合法", 400, "invalid_locale")
            cleaned["locale"] = locale
        if "title" in data or not partial:
            title = str(data.get("title") or "").strip()
            if not title:
                raise APIError("标题不能为空", 400, "invalid_title")
            cleaned["title"] = title[:160]
        if "body" in data or not partial:
            body = str(data.get("body") or "").strip()
            cleaned["body"] = body[:6000]
        if "status" in data or not partial:
            status = str(data.get("status") or "published").strip().lower()
            if status not in ("draft", "published"):
                raise APIError("状态不合法", 400, "invalid_status")
            cleaned["status"] = status
        if "sort_order" in data or not partial:
            try:
                cleaned["sort_order"] = max(0, min(int(data.get("sort_order") or 0), 9999))
            except (TypeError, ValueError):
                raise APIError("排序不合法", 400, "invalid_sort_order")
        return cleaned

    def api_marketing_copy(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        page_key = (query.get("page") or query.get("page_key") or "").strip().lower()
        locale = (query.get("locale") or "zh").strip().lower()
        if locale not in ("zh", "en", "ja"):
            locale = "zh"
        params: list[Any] = [locale]
        where = "WHERE status = 'published' AND locale = ?"
        if page_key:
            where += " AND page_key = ?"
            params.append(page_key)
        rows = list(conn.execute(
            f"SELECT * FROM marketing_copy {where} ORDER BY sort_order ASC, updated_at DESC LIMIT 50",
            params,
        ))
        self.send_json({"items": [self._serialize_marketing_copy(r) for r in rows]})

    def _clean_marketing_override_locale(self, value: Any) -> str:
        locale = str(value or "zh").strip().lower()
        if locale not in ("zh", "en", "ja"):
            raise APIError("语言不合法", 400, "invalid_locale")
        return locale

    def _clean_marketing_override_key(self, value: Any) -> str:
        key = str(value or "").strip()
        if len(key) > 180 or not re.match(r"^(home|pages\.[a-z0-9-]+)\.[A-Za-z0-9_.-]+$", key):
            raise APIError("文案字段不合法", 400, "invalid_copy_key")
        return key

    def _read_marketing_copy_overrides(self, conn: sqlite3.Connection, locale: str) -> dict[str, str]:
        try:
            rows = conn.execute(
                "SELECT copy_key, value FROM marketing_copy_overrides WHERE locale = ? ORDER BY copy_key ASC",
                (locale,),
            ).fetchall()
        except sqlite3.OperationalError:
            return {}
        return {str(row["copy_key"]): str(row["value"] or "") for row in rows}

    def api_marketing_copy_overrides(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        try:
            locale = self._clean_marketing_override_locale(query.get("locale") or "zh")
        except APIError:
            locale = "zh"
        self.send_json({"locale": locale, "overrides": self._read_marketing_copy_overrides(conn, locale)})

    def api_site_settings(self, conn: sqlite3.Connection) -> None:
        self.send_json({"settings": _site_settings(conn)})

    # ---- admin ------------------------------------------------------------
    #
    # Everything below requires the calling user to have `role = 'admin'`.
    # First-launched install: the first registered account is auto-promoted
    # to admin (see api_register). After that, only an existing admin can
    # mint another admin via PATCH /api/admin/users/:id { role: 'admin' }.

    def api_admin_stats(self, conn: sqlite3.Connection) -> None:
        self.require_admin(conn)
        def one(sql: str, *p: Any) -> int:
            row = conn.execute(sql, p).fetchone()
            return int((row[0] if row else 0) or 0)

        cutoff_24h = (datetime.now(timezone.utc) - timedelta(hours=24)).isoformat()
        cutoff_7d = (datetime.now(timezone.utc) - timedelta(days=7)).isoformat()
        stats = {
            "users_total":         one("SELECT COUNT(*) FROM users WHERE deleted_at IS NULL"),
            "users_24h":           one("SELECT COUNT(*) FROM users WHERE created_at > ?", cutoff_24h),
            "users_7d":            one("SELECT COUNT(*) FROM users WHERE created_at > ?", cutoff_7d),
            "posts_total":         one("SELECT COUNT(*) FROM posts WHERE deleted_at IS NULL"),
            "posts_active":        one("SELECT COUNT(*) FROM posts WHERE deleted_at IS NULL AND status IN ('published', 'active')"),
            "posts_under_review":  one("SELECT COUNT(*) FROM posts WHERE deleted_at IS NULL AND status = 'under_review'"),
            "posts_hidden":        one("SELECT COUNT(*) FROM posts WHERE deleted_at IS NULL AND status = 'hidden'"),
            "boosted_posts":       one("SELECT COUNT(*) FROM posts WHERE deleted_at IS NULL AND is_boosted = 1"),
            "posts_24h":           one("SELECT COUNT(*) FROM posts WHERE created_at > ?", cutoff_24h),
            "comments_total":      one("SELECT COUNT(*) FROM comments WHERE deleted_at IS NULL"),
            "comments_24h":        one("SELECT COUNT(*) FROM comments WHERE created_at > ?", cutoff_24h),
            "messages_total":      one("SELECT COUNT(*) FROM messages WHERE deleted_at IS NULL"),
            "messages_24h":        one("SELECT COUNT(*) FROM messages WHERE created_at > ?", cutoff_24h),
            "media_total":         one("SELECT COUNT(*) FROM media WHERE deleted_at IS NULL"),
            "active_sessions":     one("SELECT COUNT(*) FROM sessions WHERE expires_at > ?", now_iso()),
            "reports_open":        one("SELECT COUNT(*) FROM reports"),
            "feedback_total":      one("SELECT COUNT(*) FROM feedback"),
            # Revenue + moderation aggregates for the 后台运营看板 (#6 看订单/看收入).
            "listings_total":          one("SELECT COUNT(*) FROM city_listings WHERE deleted_at IS NULL"),
            "listings_pending_review": one("SELECT COUNT(*) FROM city_listings WHERE deleted_at IS NULL AND status = 'pending_review'"),
            "listing_reports_open":    one("SELECT COUNT(*) FROM listing_reports WHERE status = 'open'"),
            # ios_sandbox = Apple Sandbox/TestFlight settlements (test traffic,
            # not money) — excluded from paid-order and revenue aggregates.
            "orders_paid_total":       one("SELECT COUNT(*) FROM payment_orders WHERE status = 'paid' AND COALESCE(client_type, '') <> 'ios_sandbox'"),
            "orders_pending":          one("SELECT COUNT(*) FROM payment_orders WHERE status = 'pending'"),
            "revenue_cents_total":     one("SELECT COALESCE(SUM(amount_cents), 0) FROM payment_orders WHERE status = 'paid' AND COALESCE(client_type, '') <> 'ios_sandbox'"),
            "revenue_cents_24h":       one("SELECT COALESCE(SUM(amount_cents), 0) FROM payment_orders WHERE status = 'paid' AND COALESCE(client_type, '') <> 'ios_sandbox' AND paid_at > ?", cutoff_24h),
            "revenue_cents_7d":        one("SELECT COALESCE(SUM(amount_cents), 0) FROM payment_orders WHERE status = 'paid' AND COALESCE(client_type, '') <> 'ios_sandbox' AND paid_at > ?", cutoff_7d),
            "active_memberships":      one("SELECT COUNT(*) FROM user_memberships WHERE status = 'active'"),
            "db_size_bytes":       (DB_PATH.stat().st_size if DB_PATH.exists() else 0),
            # Walking media/ on every admin stats request can be tens
            # of seconds with many files — cache it for 5 minutes.
            "media_size_bytes":    _cached_media_size_bytes(),
            "server_time":         now_iso(),
            "server_env":          "production" if PRODUCTION else "development",
            "allowed_origins":     sorted(ALLOWED_ORIGINS),
        }
        self.send_json({"stats": stats})

    def api_admin_server_metrics(self, conn: sqlite3.Connection) -> None:
        self.require_admin(conn)
        self.send_json({"metrics": _server_metrics()})

    def api_admin_site_settings(self, conn: sqlite3.Connection) -> None:
        self.require_admin(conn)
        self.send_json({"settings": _site_settings(conn)})

    def api_admin_update_site_settings(self, conn: sqlite3.Connection) -> None:
        self.require_admin(conn)
        data = self.read_json()
        updates: dict[str, str] = {}
        for key in SITE_SETTING_KEYS:
            if key in data:
                updates[key] = str(data.get(key) or "").strip()
        settings = _upsert_site_settings(conn, updates)
        if any(key.startswith("explore_") for key in updates):
            invalidate_public_ranking_caches()
        self.send_json({"settings": settings})

    def api_admin_marketing_copy_overrides(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        self.require_admin(conn)
        locale = self._clean_marketing_override_locale(query.get("locale") or "zh")
        self.send_json({"locale": locale, "overrides": self._read_marketing_copy_overrides(conn, locale)})

    def api_admin_update_marketing_copy_overrides(self, conn: sqlite3.Connection) -> None:
        admin = self.require_admin(conn)
        data = self.read_json()
        locale = self._clean_marketing_override_locale(data.get("locale") or "zh")
        raw_values = data.get("values") if isinstance(data.get("values"), dict) else data.get("overrides")
        if not isinstance(raw_values, dict):
            raise APIError("文案内容不合法", 400, "invalid_overrides")
        timestamp = now_iso()
        changed = 0
        for raw_key, raw_value in raw_values.items():
            key = self._clean_marketing_override_key(raw_key)
            value = str(raw_value or "").strip()
            if value:
                conn.execute(
                    """
                    INSERT INTO marketing_copy_overrides (locale, copy_key, value, updated_at)
                    VALUES (?, ?, ?, ?)
                    ON CONFLICT(locale, copy_key)
                    DO UPDATE SET value = excluded.value, updated_at = excluded.updated_at
                    """,
                    (locale, key, value[:12000], timestamp),
                )
                changed += 1
            else:
                conn.execute("DELETE FROM marketing_copy_overrides WHERE locale = ? AND copy_key = ?", (locale, key))
                changed += 1
        ACCESS_LOG.info("admin %s updated marketing master copy locale=%s fields=%d", admin["handle"], locale, changed)
        self.send_json({"locale": locale, "overrides": self._read_marketing_copy_overrides(conn, locale)})

    def api_admin_visitors(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        """Admin-only access log: recent visits with IP + resolved region,
        plus rollup summaries. The full IP is intentionally returned here —
        this endpoint exists precisely so operators can see it — but it is
        gated behind require_admin and never exposed to ordinary users."""
        self.require_admin(conn)
        limit = max(1, min(int(query.get("limit") or 100), 500))
        days = max(1, min(int(query.get("days") or 7), 365))
        q = (query.get("q") or "").strip()
        cutoff = (datetime.now(timezone.utc) - timedelta(days=days)).isoformat()
        clauses = ["created_at > ?"]
        params: list[Any] = [cutoff]
        if q:
            like = f"%{q}%"
            clauses.append("(ip LIKE ? OR country LIKE ? OR region LIKE ? OR city LIKE ? OR path LIKE ?)")
            params.extend([like, like, like, like, like])
        where = "WHERE " + " AND ".join(clauses)
        rows = list(conn.execute(
            f"SELECT * FROM visitor_logs {where} ORDER BY created_at DESC LIMIT ?",
            [*params, limit],
        ))
        total = int(conn.execute(f"SELECT COUNT(*) FROM visitor_logs {where}", params).fetchone()[0])
        uniques = int(conn.execute(f"SELECT COUNT(DISTINCT ip_hash) FROM visitor_logs {where}", params).fetchone()[0])
        logged_in = int(conn.execute(f"SELECT COUNT(DISTINCT user_id) FROM visitor_logs {where} AND user_id IS NOT NULL", params).fetchone()[0])
        top_countries = [
            {"country": r["country"], "count": int(r["c"])}
            for r in conn.execute(
                f"SELECT country, COUNT(*) AS c FROM visitor_logs {where} AND country != '' GROUP BY country ORDER BY c DESC LIMIT 12",
                params,
            )
        ]
        top_cities = [
            {"city": r["city"], "country": r["country"], "count": int(r["c"])}
            for r in conn.execute(
                f"SELECT city, country, COUNT(*) AS c FROM visitor_logs {where} AND city != '' GROUP BY city, country ORDER BY c DESC LIMIT 12",
                params,
            )
        ]
        items = [
            {
                "id": r["id"],
                "created_at": r["created_at"],
                "ip": r["ip"],
                "method": r["method"],
                "path": r["path"],
                "status": int(r["status"] or 0),
                "user_id": r["user_id"],
                "user_agent": r["user_agent"],
                "referer": r["referer"],
                "country": r["country"],
                "region": r["region"],
                "city": r["city"],
                "org": r["org"],
            }
            for r in rows
        ]
        self.send_json({
            "items": items,
            "summary": {
                "total": total,
                "unique_visitors": uniques,
                "logged_in_users": logged_in,
                "days": days,
                "top_countries": top_countries,
                "top_cities": top_cities,
                "geoip": GEOIP_TRANSPORT,
            },
        })

    def api_admin_users(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        self.require_admin(conn)
        try:
            limit = max(1, min(int(query.get("limit") or 30), 100))
        except (TypeError, ValueError):
            limit = 30
        try:
            offset = max(0, int(query.get("offset") or 0))
        except (TypeError, ValueError):
            offset = 0
        q = (query.get("q") or "").strip()
        seed_only = (query.get("seed") or "").strip().lower() in ("1", "true", "yes")
        _ensure_content_pack_users_table(conn)
        where = ["1 = 1"]
        params: list[Any] = []
        if q:
            like = f"%{q}%"
            where.append("(u.handle LIKE ? OR u.display_name LIKE ? OR u.email LIKE ?)")
            params += [like, like, like]
        join = "JOIN content_pack_users cpu ON cpu.user_id = u.id" if seed_only else ""
        where_sql = " AND ".join(where)
        total = int(conn.execute(
            f"SELECT COUNT(*) FROM users u {join} WHERE {where_sql}", params
        ).fetchone()[0])
        rows = list(conn.execute(
            f"SELECT u.* FROM users u {join} WHERE {where_sql} ORDER BY u.created_at DESC LIMIT ? OFFSET ?",
            [*params, limit, offset],
        ))
        # Mark which rows are generated seed personas (for a badge + bulk-clear).
        ids = [r["id"] for r in rows]
        seed_ids: set[str] = set()
        if ids:
            placeholders = ",".join("?" * len(ids))
            seed_ids = {r[0] for r in conn.execute(
                f"SELECT user_id FROM content_pack_users WHERE user_id IN ({placeholders})", ids
            ).fetchall()}
        seed_total = int(conn.execute("SELECT COUNT(*) FROM content_pack_users").fetchone()[0])
        items = []
        for r in rows:
            d = dict(r)
            base = serialize_user(d)
            base["role"] = d.get("role", "member")
            base["deleted_at"] = d.get("deleted_at")
            base["isSeed"] = d["id"] in seed_ids
            base["follower_count"] = int(conn.execute(
                "SELECT COUNT(*) FROM follows WHERE following_id = ?", (d["id"],)
            ).fetchone()[0])
            base["post_count"] = int(conn.execute(
                "SELECT COUNT(*) FROM posts WHERE author_id = ? AND deleted_at IS NULL", (d["id"],)
            ).fetchone()[0])
            items.append(base)
        self.send_json({"items": items, "total": total, "limit": limit, "offset": offset, "seedTotal": seed_total})

    def api_admin_update_user(self, conn: sqlite3.Connection, user_id: str) -> None:
        admin = self.require_admin(conn)
        data = self.read_json()
        target = conn.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone()
        if not target:
            raise APIError("用户不存在", 404, "user_not_found")
        updates: list[tuple[str, Any]] = []
        if "is_verified" in data:
            updates.append(("is_verified", 1 if data["is_verified"] else 0))
        if "email" in data:
            email = str(data.get("email") or "").strip().lower()
            if email:
                if not is_valid_email(email):
                    raise APIError("邮箱格式不正确", 400, "invalid_email")
                dupe = conn.execute(
                    "SELECT id FROM users WHERE lower(email) = ? AND id != ?",
                    (email, user_id),
                ).fetchone()
                if dupe:
                    raise APIError("该邮箱已被其他账号使用", 400, "email_taken")
                # Admin-set address is trusted, so it is marked verified.
                updates.append(("email", email))
                updates.append(("email_verified", 1))
            else:
                updates.append(("email", ""))
                updates.append(("email_verified", 0))
        if "role" in data and data["role"] in ("member", "creator", "admin"):
            # Don't let an admin demote themselves and then strand the system.
            if data["role"] != "admin" and target["id"] == admin["id"]:
                raise APIError("不能修改自己的角色", 400, "invalid_role_change")
            updates.append(("role", data["role"]))
            if data["role"] == "admin":
                if "is_official" not in data:
                    updates.append(("is_official", 1))
                if "official_role" not in data and not (target["official_role"] or "").strip():
                    updates.append(("official_role", "admin"))
        if "is_official" in data:
            will_be_admin = (data.get("role") or target["role"]) == "admin"
            if will_be_admin and not data["is_official"]:
                raise APIError("管理员必须保留官方标识", 400, "invalid_official_change")
            updates.append(("is_official", 1 if data["is_official"] else 0))
        if "official_role" in data:
            official_role = str(data.get("official_role") or "").strip()[:40]
            updates.append(("official_role", official_role))
        if "membership_tier" in data:
            updates.append(("membership_tier", data["membership_tier"]))
        if "creator_badge" in data:
            updates.append(("creator_badge", str(data["creator_badge"])[:80]))
        if "custom_tags" in data:
            raw_tags = data["custom_tags"]
            if isinstance(raw_tags, str):
                raw_tags = [part for part in raw_tags.replace("，", ",").replace("|", ",").split(",")]
            tags = []
            for tag in (raw_tags or []):
                cleaned = str(tag).strip()[:20]
                if cleaned and cleaned not in tags:
                    tags.append(cleaned)
                if len(tags) >= 6:
                    break
            updates.append(("custom_tags", "|".join(tags)))
        if "is_merchant" in data:
            updates.append(("is_merchant", 1 if data["is_merchant"] else 0))
        if "merchant_verified" in data:
            updates.append(("merchant_verified", 1 if data["merchant_verified"] else 0))
        if updates:
            sets = ", ".join(f"{f} = ?" for f, _ in updates) + ", updated_at = ?"
            values = [v for _, v in updates] + [now_iso(), user_id]
            conn.execute(f"UPDATE users SET {sets} WHERE id = ?", values)
            ACCESS_LOG.info("admin %s updated user %s fields=%s", admin["handle"], target["handle"], [f for f, _ in updates])
        fresh = dict(conn.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone())
        self.send_json({"user": serialize_user_with_counts(conn, fresh)})

    def api_admin_delete_user(self, conn: sqlite3.Connection, user_id: str) -> None:
        admin = self.require_admin(conn)
        target = conn.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone()
        if not target:
            raise APIError("用户不存在", 404, "user_not_found")
        if target["id"] == admin["id"]:
            raise APIError("不能封禁自己", 400, "cannot_ban_self")
        conn.execute("UPDATE users SET deleted_at = ?, updated_at = ? WHERE id = ?",
                     (now_iso(), now_iso(), user_id))
        conn.execute("DELETE FROM sessions WHERE user_id = ?", (user_id,))
        ACCESS_LOG.warning("admin %s suspended user %s", admin["handle"], target["handle"])
        self.send_json({"ok": True})

    def api_admin_restore_user(self, conn: sqlite3.Connection, user_id: str) -> None:
        admin = self.require_admin(conn)
        target = conn.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone()
        if not target:
            raise APIError("用户不存在", 404, "user_not_found")
        conn.execute(
            "UPDATE users SET deleted_at = NULL, updated_at = ? WHERE id = ?",
            (now_iso(), user_id),
        )
        fresh = dict(conn.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone())
        ACCESS_LOG.warning("admin %s restored user %s", admin["handle"], target["handle"])
        self.send_json({"user": serialize_user_with_counts(conn, fresh)})

    def api_admin_set_user_password(self, conn: sqlite3.Connection, user_id: str) -> None:
        """Admin-set a user's password. The plaintext is never logged or
        echoed; we only persist the salted PBKDF2 hash and drop every live
        session so the change takes effect immediately everywhere."""
        admin = self.require_admin(conn)
        data = self.read_json()
        target = conn.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone()
        if not target:
            raise APIError("用户不存在", 404, "user_not_found")
        password = data.get("password")
        validate_password_strength(password)
        conn.execute(
            "UPDATE users SET password_hash = ?, updated_at = ? WHERE id = ?",
            (hash_password(password), now_iso(), user_id),
        )
        conn.execute("DELETE FROM sessions WHERE user_id = ?", (user_id,))
        ACCESS_LOG.warning("admin %s reset password for user %s", admin["handle"], target["handle"])
        self.send_json({"ok": True})

    def api_admin_erase_user(self, conn: sqlite3.Connection, user_id: str) -> None:
        """Permanently erase an account: scrub its PII, free the handle, make
        the password unusable, hide its content and drop sessions. Distinct
        from the recoverable ban (`api_admin_delete_user`) — this cannot be
        undone to the original identity. Backend-agnostic (no FK-cascade
        surgery), so it behaves identically on SQLite and Postgres."""
        admin = self.require_admin(conn)
        target = conn.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone()
        if not target:
            raise APIError("用户不存在", 404, "user_not_found")
        if target["id"] == admin["id"]:
            raise APIError("不能删除自己的账号", 400, "cannot_delete_self")
        if (target["role"] or "member") == "admin":
            raise APIError("不能删除管理员账号，请先取消其管理员权限", 400, "cannot_delete_admin")
        anonymize_user_account(conn, user_id)
        ACCESS_LOG.warning("admin %s erased user %s (%s)", admin["handle"], target["handle"], user_id)
        self.send_json({"ok": True, "erased": True})

    def api_admin_mute_user(self, conn: sqlite3.Connection, user_id: str) -> None:
        """UGC-5: timed mute/suspension (graduated enforcement between 'nothing'
        and a permanent ban). minutes>0 mutes, minutes<=0 unmutes."""
        admin = self.require_admin(conn)
        data = self.read_json()
        target = conn.execute("SELECT id, handle FROM users WHERE id = ? AND deleted_at IS NULL", (user_id,)).fetchone()
        if not target:
            raise APIError("用户不存在", 404, "user_not_found")
        if target["id"] == admin["id"]:
            raise APIError("不能禁言自己", 400, "cannot_mute_self")
        try:
            minutes = int(data.get("minutes") or 0)
        except (TypeError, ValueError):
            raise APIError("时长不合法", 400, "invalid_minutes")
        reason = str(data.get("reason") or "")[:200]
        if minutes <= 0:
            conn.execute("UPDATE users SET muted_until = '', mute_reason = '', updated_at = ? WHERE id = ?",
                         (now_iso(), user_id))
            action, until = "unmute_user", ""
        else:
            minutes = min(minutes, 60 * 24 * 365)
            until = (datetime.now(timezone.utc) + timedelta(minutes=minutes)).isoformat()
            conn.execute("UPDATE users SET muted_until = ?, mute_reason = ?, updated_at = ? WHERE id = ?",
                         (until, reason, now_iso(), user_id))
            action = "mute_user"
        ACCESS_LOG.warning("admin %s %s %s (%s min)", admin["handle"], action, target["handle"], minutes)
        self.send_json({"ok": True, "muted_until": until})

    def api_create_appeal(self, conn: sqlite3.Connection) -> None:
        """UGC-5: a user appeals a moderation action (mute / content removal / merchant rejection)."""
        user = self.require_user(conn)
        if not rate_check("report:" + user["id"], "report"):
            raise APIError("提交过于频繁，请稍后再试", 429, "rate_limited")
        data = self.read_json()
        message = str(data.get("message") or "").strip()[:2000]
        if not message:
            raise APIError("请填写申诉理由", 400, "empty_appeal")
        target_kind = str(data.get("target_kind") or "")[:40]
        target_id = str(data.get("target_id") or "")[:64]
        if conn.execute(
            "SELECT 1 FROM appeals WHERE user_id = ? AND target_kind = ? AND target_id = ? AND status = 'open' LIMIT 1",
            (user["id"], target_kind, target_id)).fetchone():
            self.send_json({"ok": True, "deduped": True})
            return
        conn.execute(
            "INSERT INTO appeals (id, user_id, target_kind, target_id, message, status, created_at) "
            "VALUES (?, ?, ?, ?, ?, 'open', ?)",
            (str(uuid.uuid4()), user["id"], target_kind, target_id, message, now_iso()))
        self.send_json({"ok": True})

    def api_admin_appeals(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        self.require_admin(conn)
        limit = max(1, min(int(query.get("limit") or 50), 200))
        status = (query.get("status") or "open").strip().lower()
        if status in ("open", "resolved"):
            rows = list(conn.execute("SELECT * FROM appeals WHERE status = ? ORDER BY created_at DESC LIMIT ?", (status, limit)))
        else:
            rows = list(conn.execute("SELECT * FROM appeals ORDER BY created_at DESC LIMIT ?", (limit,)))
        users = fetch_users_by_ids(conn, list({r["user_id"] for r in rows}))
        items = [{"id": d["id"], "user": users.get(d["user_id"]), "target_kind": d["target_kind"],
                  "target_id": d["target_id"], "message": d["message"], "status": d["status"],
                  "resolution": d["resolution"], "created_at": d["created_at"], "resolved_at": d["resolved_at"]}
                 for d in (dict(r) for r in rows)]
        self.send_json({"items": items})

    def api_admin_resolve_appeal(self, conn: sqlite3.Connection, appeal_id: str) -> None:
        admin = self.require_admin(conn)
        data = self.read_json()
        resolution = str(data.get("resolution") or "")[:500]
        decision = (data.get("decision") or "reviewed").strip().lower()
        row = conn.execute("SELECT id, user_id FROM appeals WHERE id = ?", (appeal_id,)).fetchone()
        if not row:
            raise APIError("申诉不存在", 404, "appeal_not_found")
        conn.execute("UPDATE appeals SET status = 'resolved', resolution = ?, handled_by = ?, resolved_at = ? WHERE id = ?",
                     (f"{decision}: {resolution}".strip(": "), admin["id"], now_iso(), appeal_id))
        if decision == "granted":
            conn.execute("UPDATE users SET muted_until = '', mute_reason = '', updated_at = ? WHERE id = ?",
                         (now_iso(), row["user_id"]))
        self.send_json({"ok": True})

    def api_admin_posts(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        self.require_admin(conn)
        limit = max(1, min(int(query.get("limit") or 50), 200))
        q = (query.get("q") or "").strip()
        status = (query.get("status") or "").strip()
        content_type = normalize_content_type(query.get("content_type")) if query.get("content_type") else ""
        region_code = (query.get("region_code") or "").strip().lower()
        country = (query.get("country") or "").strip().lower()
        city = (query.get("city") or "").strip().lower()
        clauses: list[str] = []
        params: list[Any] = []
        if q:
            like = f"%{q}%"
            clauses.append("(content LIKE ? OR country LIKE ? OR province LIKE ? OR city LIKE ? OR content_type LIKE ?)")
            params.extend([like, like, like, like, like])
        if status in POST_STATUSES:
            clauses.append("status = ?")
            params.append(status)
        if content_type:
            clauses.append("content_type = ?")
            params.append(content_type)
        if region_code:
            clauses.append("region_code = ?")
            params.append(region_code)
        else:
            if country:
                clauses.append("country = ?")
                params.append(country)
            if city:
                clauses.append("city = ?")
                params.append(city)
        where = ("WHERE " + " AND ".join(clauses)) if clauses else ""
        rows = list(conn.execute(
            f"SELECT * FROM posts {where} ORDER BY created_at DESC LIMIT ?",
            [*params, limit],
        ))
        items = fetch_posts_with_extras(conn, [dict(r) for r in rows], None)
        # Surface deleted_at for the admin UI.
        for item, row in zip(items, rows):
            item["deleted_at"] = row["deleted_at"]
        self.send_json({"items": items})

    def api_admin_update_post(self, conn: sqlite3.Connection, post_id: str) -> None:
        admin = self.require_admin(conn)
        row = conn.execute("SELECT * FROM posts WHERE id = ?", (post_id,)).fetchone()
        if not row:
            raise APIError("帖子不存在", 404, "post_not_found")
        data = self.read_json()
        updates: list[tuple[str, Any]] = []
        if "status" in data:
            status = str(data["status"]).strip()
            if status not in POST_STATUSES:
                raise APIError("状态不合法", 400, "invalid_status")
            updates.append(("status", status))
            if status == "deleted":
                updates.append(("deleted_at", now_iso()))
            else:
                updates.append(("deleted_at", None))
        if "is_boosted" in data:
            updates.append(("is_boosted", 1 if data["is_boosted"] else 0))
        if "boost_weight" in data:
            try:
                updates.append(("boost_weight", max(0, int(data["boost_weight"]))))
            except (TypeError, ValueError):
                raise APIError("加热权重不合法", 400, "invalid_boost_weight")
        if "boosted_until" in data:
            updates.append(("boosted_until", str(data["boosted_until"] or "")[:60]))
        if updates:
            sets = ", ".join(f"{f} = ?" for f, _ in updates) + ", updated_at = ?"
            values = [v for _, v in updates] + [now_iso(), post_id]
            conn.execute(f"UPDATE posts SET {sets} WHERE id = ?", values)
            if any(f == "status" and v in {"hidden", "deleted"} for f, v in updates) and row["status"] not in {"hidden", "deleted"}:
                # The original just left public view — retire its reposts so
                # they don't keep rendering the removed content in feeds.
                retire_reposts_of_deleted_post(conn, post_id)
                reputation_apply_event(
                    conn,
                    row["author_id"],
                    "content_removed",
                    admin_id=admin["id"],
                    target_kind="post",
                    target_id=post_id,
                    reason=str(data.get("reason") or "内容因违反规则被下架"),
                    metadata={"content_type": row["content_type"] or "dynamic"},
                    reviewed=True,
                )
            invalidate_public_ranking_caches()
            _cache_invalidate("feed:")
            ACCESS_LOG.info("admin %s updated post %s fields=%s", admin["handle"], post_id, [f for f, _ in updates])
        fresh = dict(conn.execute("SELECT * FROM posts WHERE id = ?", (post_id,)).fetchone())
        post = fetch_posts_with_extras(conn, [fresh], None)[0]
        post["deleted_at"] = fresh.get("deleted_at")
        self.send_json({"post": post})

    def api_admin_delete_post(self, conn: sqlite3.Connection, post_id: str) -> None:
        admin = self.require_admin(conn)
        row = conn.execute("SELECT author_id FROM posts WHERE id = ?", (post_id,)).fetchone()
        if not row:
            raise APIError("帖子不存在", 404, "post_not_found")
        conn.execute("UPDATE posts SET status = 'deleted', deleted_at = ?, updated_at = ? WHERE id = ?",
                     (now_iso(), now_iso(), post_id))
        retire_reposts_of_deleted_post(conn, post_id)
        reputation_apply_event(
            conn,
            row["author_id"],
            "content_removed",
            admin_id=admin["id"],
            target_kind="post",
            target_id=post_id,
            reason="管理员删除内容",
            reviewed=True,
        )
        invalidate_public_ranking_caches()
        _cache_invalidate("feed:")
        ACCESS_LOG.warning("admin %s removed post %s", admin["handle"], post_id)
        self.send_json({"ok": True})

    def api_admin_comments(self, conn: sqlite3.Connection, query: dict[str, str]) -> None:
        self.require_admin(conn)
        limit = max(1, min(int(query.get("limit") or 50), 200))
        rows = list(conn.execute(
            "SELECT * FROM comments ORDER BY created_at DESC LIMIT ?", (limit,),
        ))
