        authors = fetch_users_by_ids(conn, ids)
        items = [
            {**serialize_comment(dict(r), {"author": authors.get(r["author_id"]), "like_count": 0, "liked": False}),
             "deleted_at": r["deleted_at"]}
            for r in rows
        ]
